-- requires primary_target to be null on bilateral/multilateral atomics
-- (a target gate there deletes half the phenomenon). Local is correct.

BEGIN;

-- 1. friction_nodes: 198 rows (full local set minus Balkan).
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('afd_and_german_polarisation','AfD and German political polarisation','AfD und die politische Polarisierung Deutschlands','The domestic conflict in Germany over the Alternative für Deutschland (AfD) and the boundaries of its participation in political life. It covers the party''s electoral rise, its classification by the domestic-intelligence service (Verfassungsschutz), the "Brandmauer" or firewall by which other parties decline to cooperate with it, debates over a possible ban, and disputes over its access to office, state secrets and public institutions. The friction is internal to German politics.','Der innenpolitische Konflikt in Deutschland um die Alternative für Deutschland (AfD) und die Grenzen ihrer Teilhabe am politischen Leben. Er umfasst den Aufstieg der Partei bei Wahlen, ihre Einstufung durch den Verfassungsschutz, die „Brandmauer", mit der andere Parteien eine Zusammenarbeit ablehnen, Debatten über ein mögliches Verbot sowie Streit über ihren Zugang zu Ämtern, Staatsgeheimnissen und öffentlichen Institutionen. Die Friktion ist innenpolitisch deutsch.',ARRAY['EUROPE-GERMANY'],true,36,'The rise of the Alternative für Deutschland has become the central fault line of German domestic politics. The party''s strength in the polls and in regional parliaments runs up against the "Brandmauer", the refusal of the other parties to govern or legislate with it, the domestic-intelligence classification of parts of it as extremist, recurring debate over an outright ban, and moves to limit its access to office and to state secrets. Its congresses, leadership under Alice Weidel and Tino Chrupalla, and street mobilisations draw large counter-protests. Coverage is sharply split: parts of the conservative and sovereigntist press frame the firewall and the intelligence classification as the establishment excluding millions of voters, while the liberal mainstream frames the party as a threat to the constitutional order that the firewall exists to contain; Russian state outlets frame state measures against the party as evidence of German or EU censorship. Allegations of the party''s ties to Moscow surface here but the broader Russian-influence dimension belongs to the Russia-Europe theater.','Der Aufstieg der Alternative für Deutschland ist zur zentralen Bruchlinie der deutschen Innenpolitik geworden. Die Stärke der Partei in Umfragen und in Landesparlamenten stößt auf die „Brandmauer", die Weigerung der übrigen Parteien, mit ihr zu regieren oder Gesetze zu beschließen, auf die Einstufung von Teilen der Partei als extremistisch durch den Verfassungsschutz, auf wiederkehrende Debatten über ein Verbot und auf Bestrebungen, ihren Zugang zu Ämtern und Staatsgeheimnissen zu begrenzen. Ihre Parteitage, die Führung unter Alice Weidel und Tino Chrupalla sowie Straßenmobilisierungen ziehen große Gegenproteste nach sich. Die Berichterstattung ist tief gespalten: Teile der konservativen und souveränistischen Presse deuten Brandmauer und Geheimdiensteinstufung als Ausschluss von Millionen Wählern durch das Establishment, während der liberale Mainstream die Partei als Gefahr für die verfassungsmäßige Ordnung deutet, zu deren Eindämmung die Brandmauer bestehe; russische Staatsmedien rahmen staatliche Maßnahmen gegen die Partei als deutsche oder EU-Zensur. Vorwürfe über Verbindungen der Partei nach Moskau tauchen hier auf, doch die weitergehende russische Einflussdimension gehört in das Russland-Europa-Theater.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('alberta_separatism_us_ties','Alberta separatism and its United States contacts','Separatismus in Alberta und seine Kontakte in die USA','The secession movement in the Canadian province of Alberta and its contacts with the United States. It covers the petition and signature drive for an independence referendum, the provincial government''s decision to put a separation question to a vote, court challenges to the referendum, opposition from the federal government, other provinces, former prime ministers and First Nations treaty holders, and reported meetings between separatist organisers and American officials along with the resulting foreign-interference inquiries.','Die Sezessionsbewegung in der kanadischen Provinz Alberta und ihre Kontakte in die USA. Sie umfasst die Petitions- und Unterschriftenkampagne für ein Unabhängigkeitsreferendum, die Entscheidung der Provinzregierung, eine Abspaltungsfrage zur Abstimmung zu stellen, gerichtliche Anfechtungen des Referendums, den Widerstand der Bundesregierung, anderer Provinzen, früherer Premierminister und der Vertragspartner der First Nations sowie berichtete Treffen zwischen separatistischen Organisatoren und amerikanischen Amtsträgern und die daraus folgenden Untersuchungen zu ausländischer Einflussnahme.',ARRAY['AMERICAS-CANADA','AMERICAS-USA'],true,115,'Alberta holds most of Canada''s oil reserves, has no coastline, and depends on federal decisions over pipelines, environmental rules and fiscal transfers. A separatist organisation has gathered signatures to trigger a referendum on leaving Canada, and the provincial government has moved to put a separation question on a ballot; the courts have at points quashed the bid, and Elections Alberta has sought disclosure of the group''s finances following a dispute over access to the electors list. Opposition has come from the federal government, other provincial premiers, two former prime ministers and First Nations leaders who hold treaty rights across the province. What connects the movement to the wider theater is the reported contact between its organisers and officials of the US administration, which prompted federal statements on respecting Canadian sovereignty, accusations of treason from another premier, and inquiries into foreign interference that found no evidence of it.','Alberta verfügt über den Großteil der kanadischen Ölreserven, hat keine Küste und ist auf Bundesentscheidungen zu Pipelines, Umweltauflagen und Finanzausgleich angewiesen. Eine separatistische Organisation hat Unterschriften gesammelt, um ein Referendum über den Austritt aus Kanada auszulösen, und die Provinzregierung hat Schritte unternommen, eine Abspaltungsfrage auf einen Stimmzettel zu setzen; Gerichte haben den Vorstoß zeitweise gekippt, und Elections Alberta verlangte Offenlegung der Finanzen der Gruppe nach einem Streit über den Zugriff auf das Wählerverzeichnis. Widerstand kam von der Bundesregierung, anderen Provinzpremiers, zwei früheren Premierministern und Vertretern der First Nations, die provinzweit Vertragsrechte halten. Mit dem übergeordneten Schauplatz verbindet die Bewegung der berichtete Kontakt ihrer Organisatoren zu Amtsträgern der US-Regierung — er führte zu Erklärungen des Bundes zur Achtung der kanadischen Souveränität, zu Landesverratsvorwürfen eines anderen Premiers und zu Untersuchungen wegen ausländischer Einflussnahme, die keine Belege dafür fanden.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CANADA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_competition','Arctic energy and territorial competition',NULL,NULL,NULL,ARRAY['AMERICAS-USA','EUROPE-RUSSIA','AMERICAS-CANADA','EUROPE-NORDIC'],false,96,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_military_presence','Arctic military build-up and NATO expansion','Militärischer Aufbau in der Arktis und NATO-Erweiterung','The re-militarization of the High North: Russia''s rebuilt bases and Northern Fleet along the Kola Peninsula and Barents Sea, and NATO''s answer — enlarged by Finnish and Swedish accession — through exercises, reinforcement and new basing, increasingly shadowed by Sino-Russian cooperation. The contest is over who is the provocateur. Western and Nordic coverage frames the build-up as necessary deterrence; Russian and Chinese state media cast NATO expansion as the destabilizing militarization of a once-low-tension zone.','Die erneute Militarisierung des hohen Nordens: Russlands wiederaufgebaute Stützpunkte und Nordflotte entlang der Kola-Halbinsel und der Barentssee sowie die Antwort der durch den finnischen und schwedischen Beitritt vergrößerten NATO durch Übungen, Verstärkung und neue Stützpunkte, zunehmend begleitet von russisch-chinesischer Kooperation. Umstritten ist, wer der Provokateur ist. Westliche und nordische Berichterstattung sieht den Aufbau als notwendige Abschreckung; russische und chinesische Staatsmedien stellen die NATO-Erweiterung als destabilisierende Militarisierung einer einst spannungsarmen Zone dar.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','NON-STATE-NATO','NON-STATE-EU','ASIA-CHINA'],true,110,'The High North is re-militarizing. Russia has rebuilt Cold-War-era bases and its Northern Fleet along the Kola Peninsula and Barents Sea; NATO, enlarged by Finnish and Swedish accession, has answered with exercises such as Arctic Sentry, Cold Response and Nordic Response, reinforcement of its northern flank and new basing, increasingly shadowed by Sino-Russian cooperation. The contest is over who is the provocateur: Western and Nordic coverage frames the build-up as necessary deterrence against a growing Russian and Chinese threat, while Russian and Chinese state media reverse the causality, casting NATO expansion as the destabilizing militarization of a once-low-tension zone and an encirclement of Russia.','Der hohe Norden militarisiert sich erneut. Russland hat Stützpunkte aus dem Kalten Krieg und seine Nordflotte entlang der Kola-Halbinsel und der Barentssee wiederaufgebaut; die durch den finnischen und schwedischen Beitritt vergrößerte NATO hat mit Übungen wie Arctic Sentry, Cold Response und Nordic Response, der Verstärkung ihrer Nordflanke und neuen Stützpunkten geantwortet, zunehmend begleitet von russisch-chinesischer Kooperation. Umstritten ist, wer der Provokateur ist: westliche und nordische Berichterstattung sieht den Aufbau als notwendige Abschreckung gegen eine wachsende russische und chinesische Bedrohung, während russische und chinesische Staatsmedien die Kausalität umkehren und die NATO-Erweiterung als destabilisierende Militarisierung einer einst spannungsarmen Zone und Einkreisung Russlands darstellen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_resources_competition','Arctic resources competition and climate access','Wettbewerb um arktische Rohstoffe und Klimazugang','The race for Arctic hydrocarbons and critical minerals as retreating ice opens access — Russia''s Yamal gas and Vostok oil, Norway''s Barents fields, Alaska''s Willow project, Greenland''s rare earths — contested by Arctic states and China. It sets a development camp that treats extraction as a legitimate sovereign right against its own critics, who warn that the same warming which opens the region — record-low sea ice, thawing permafrost, black carbon — is a climate emergency that drilling and mining only deepen.','Das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe, während das zurückweichende Eis den Zugang öffnet — Russlands Jamal-Gas und Wostok-Öl, Norwegens Barents-Felder, Alaskas Willow-Projekt, Grönlands Seltene Erden — umkämpft von Arktis-Staaten und China. Es stellt ein Entwicklungslager, das die Förderung als legitimes souveränes Recht betrachtet, gegen dessen eigene Kritiker, die warnen, dass dieselbe Erwärmung, die die Region öffnet — Rekordtief beim Meereis, tauender Permafrost, Ruß — ein Klimanotstand ist, den Bohrungen und Bergbau nur vertiefen.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-GREENLAND','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU','EUROPE-NORDIC'],true,111,'As the ice retreats it exposes an estimated fortune in Arctic hydrocarbons and critical minerals — Russia''s Yamal gas and Vostok oil, Norway''s Barents fields, Alaska''s Willow project, Greenland''s rare earths — turning the region into a resource frontier contested by Arctic states and China alike. Two stances frame it: a development camp of Russian state and Western energy press that treats extraction as a legitimate, economically vital sovereign right, and its own critics, who warn that the same warming that opens access — record-low sea ice, thawing permafrost, black carbon — is a climate emergency that drilling, mining and shipping only compound. Because the outlets reporting the resource boom often sound the environmental alarm too, the split is one of framing rather than of camp.','Mit dem Rückzug des Eises tritt ein geschätztes Vermögen an arktischen Kohlenwasserstoffen und kritischen Rohstoffen zutage — Russlands Jamal-Gas und Wostok-Öl, Norwegens Barents-Felder, Alaskas Willow-Projekt, Grönlands Seltene Erden — und macht die Region zu einer Rohstoff-Grenze, um die Arktis-Staaten und China gleichermaßen konkurrieren. Zwei Haltungen rahmen dies: ein Entwicklungslager aus russischer Staats- und westlicher Energiepresse, das die Förderung als legitimes, wirtschaftlich wichtiges souveränes Recht betrachtet, und dessen eigene Kritiker, die warnen, dass dieselbe Erwärmung, die den Zugang öffnet — Rekordtief beim Meereis, tauender Permafrost, Ruß — ein Klimanotstand ist, den Bohrungen, Bergbau und Schifffahrt nur verschärfen. Da dieselben Medien Boom und Umweltalarm berichten, ist die Trennung eine der Rahmung, nicht des Lagers.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_shipping_routes','Arctic shipping routes and passage competition','Arktische Schifffahrtsrouten und Passagenwettbewerb','The competition over the sea routes that Arctic warming is opening — the Northern Sea Route along Russia''s coast, the Northwest Passage through Canada''s archipelago, and a future transpolar route — which could cut weeks off Asia-Europe voyages. Russia is developing the Northern Sea Route with nuclear icebreakers and the port of Sabetta, and China has folded it into a "Polar Silk Road". Coverage divides between an opportunity framing and a Western security framing that sees Russian control and Chinese encroachment as a strategic threat.','Der Wettbewerb um die Seewege, welche die arktische Erwärmung öffnet — die Nordostpassage entlang der russischen Küste, die Nordwestpassage durch den kanadischen Archipel und eine künftige transpolare Route — die Asien-Europa-Fahrten um Wochen verkürzen könnten. Russland entwickelt die Nordostpassage mit nuklearen Eisbrechern und dem Hafen Sabetta, und China hat sie in eine "polare Seidenstraße" eingebettet. Die Berichterstattung teilt sich zwischen einer Chancen-Rahmung und einer westlichen Sicherheits-Rahmung, welche die russische Kontrolle und chinesisches Vordringen als strategische Bedrohung sieht.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU'],true,108,'Warming is opening sea routes that could reshape global trade — the Northern Sea Route along Russia''s coast, the Northwest Passage through Canada''s archipelago, and a future transpolar route — cutting weeks off Asia-Europe voyages. Russia is developing the Northern Sea Route with a nuclear-icebreaker fleet and the port of Sabetta, and China has folded the corridor into a "Polar Silk Road". Coverage divides between an opportunity framing from Russian, Chinese and commercial press that presents the routes as a shared economic prospect to be developed, and a strategic-threat framing from Western security press that sees Russian control of the passage, Chinese encroachment and a sanctions-evading "shadow fleet" as risks requiring monitoring and freedom-of-navigation assertion.','Die Erwärmung öffnet Seewege, die den globalen Handel umgestalten könnten — die Nordostpassage entlang der russischen Küste, die Nordwestpassage durch den kanadischen Archipel und eine künftige transpolare Route — und verkürzt Asien-Europa-Fahrten um Wochen. Russland entwickelt die Nordostpassage mit einer Flotte nuklearer Eisbrecher und dem Hafen Sabetta, und China hat den Korridor in eine "polare Seidenstraße" eingebettet. Die Berichterstattung teilt sich zwischen einer Chancen-Rahmung aus russischer, chinesischer und kommerzieller Presse, welche die Routen als gemeinsame wirtschaftliche Perspektive zur Entwicklung präsentiert, und einer Bedrohungs-Rahmung aus westlicher Sicherheitspresse, welche die russische Kontrolle der Passage, chinesisches Vordringen und eine sanktionsumgehende "Schattenflotte" als überwachungsbedürftige Risiken sieht.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_theater','Arctic strategic competition','Strategischer Wettbewerb in der Arktis','The contest over the Arctic as retreating sea ice opens once-inaccessible waters, seabed and sea lanes to competition among the eight Arctic states and China. Four axes run through it: the militarization of the High North and NATO''s northern expansion, the race for Arctic hydrocarbons and critical minerals, control of the emerging shipping routes, and the confrontation over Greenland that has strained transatlantic relations. Coverage is sharply divided — Western outlets frame Russian and Chinese activity as encroachment requiring deterrence, while Moscow and Beijing frame NATO''s build-up and the US Greenland push as the destabilizing provocation.','Der Wettstreit um die Arktis, während das zurückweichende Meereis einst unzugängliche Gewässer, Meeresböden und Seewege dem Wettbewerb zwischen den acht Arktis-Staaten und China öffnet. Vier Achsen durchziehen ihn: die Militarisierung des hohen Nordens und die Nordausdehnung der NATO, das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe, die Kontrolle über die entstehenden Schifffahrtsrouten und die Konfrontation um Grönland, die die transatlantischen Beziehungen belastet hat. Die Berichterstattung ist tief gespalten — westliche Medien deuten russische und chinesische Aktivitäten als Vordringen, das Abschreckung erfordert, während Moskau und Peking den NATO-Aufbau und den US-Vorstoß in Grönland als destabilisierende Provokation darstellen.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU','EUROPE-GREENLAND'],true,28,'The Arctic is emerging as a distinct arena of great-power competition as retreating sea ice opens once-inaccessible waters, seabed and sea lanes. It draws in the eight Arctic states plus China as a self-declared "near-Arctic" power, along four axes: the militarization of the High North and NATO''s northern expansion; the race for Arctic hydrocarbons and critical minerals; control of the emerging shipping routes; and — dominating current coverage — the confrontation over Greenland, where a US push for control has ruptured transatlantic relations. Warming is both the enabler that opens access and a planetary alarm running beneath all four. Coverage is sharply contested: Western outlets frame Russian and Chinese activity as encroachment requiring deterrence, Moscow and Beijing frame NATO''s build-up as the destabilizing provocation, and the same US move on Greenland is read as strategic necessity, unacceptable coercion, or imperial hypocrisy depending on the outlet.','Die Arktis entwickelt sich zu einer eigenständigen Arena des Großmächte-Wettbewerbs, da das zurückweichende Meereis einst unzugängliche Gewässer, Meeresböden und Seewege öffnet. Sie zieht die acht Arktis-Staaten sowie China als selbsternannte "arktisnahe" Macht an — entlang vier Achsen: die Militarisierung des hohen Nordens und die Nordausdehnung der NATO; das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe; die Kontrolle über die entstehenden Schifffahrtsrouten; und — die aktuelle Berichterstattung dominierend — die Konfrontation um Grönland, wo ein US-Vorstoß zur Kontrolle die transatlantischen Beziehungen zerrüttet hat. Die Erwärmung ist zugleich Wegbereiter des Zugangs und planetarer Alarm unter allen vier Achsen. Die Berichterstattung ist stark umkämpft: westliche Medien deuten russische und chinesische Aktivitäten als Vordringen, das Abschreckung erfordert, Moskau und Peking deuten den NATO-Aufbau als destabilisierende Provokation, und derselbe US-Vorstoß in Grönland gilt je nach Medium als strategische Notwendigkeit, inakzeptabler Zwang oder imperiale Heuchelei.','theater',ARRAY['arctic_shipping_routes','arctic_military_presence','arctic_resources_competition','greenland_control'],ARRAY['northern_sea_route','hammerfest_melkoya_lng','norwegian_shelf_gas'],'regional','{"type": "Point", "coordinates": [15.6, 78.2]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('armenia_azerbaijan_settlement','Armenia-Azerbaijan conflict and peace settlement','Konflikt und Friedensregelung zwischen Armenien und Aserbaidschan','The conflict between Armenia and Azerbaijan and efforts to settle it. The dispute is centred on Nagorno-Karabakh, a territory internationally recognised as part of Azerbaijan and inhabited by ethnic Armenians until 2023, fought over in wars in 1988-1994, in 2020, and in 2023, after which Azerbaijan reestablished control and the region''s Armenian population left. Contested issues include a peace treaty, border delimitation, the status of detainees and prisoners, accountability and war-crimes claims, mutual territorial and constitutional claims, and the parallel normalisation between Armenia and Turkey, whose shared border has been closed since the 1990s. Border clashes and ceasefire violations have recurred.','Der Konflikt zwischen Armenien und Aserbaidschan und die Bemühungen um seine Beilegung. Der Streit dreht sich um Bergkarabach, ein völkerrechtlich als Teil Aserbaidschans anerkanntes und bis 2023 von ethnischen Armeniern bewohntes Gebiet, um das in Kriegen 1988-1994, 2020 und 2023 gekämpft wurde; danach stellte Aserbaidschan die Kontrolle wieder her, und die armenische Bevölkerung der Region ging fort. Umstritten sind ein Friedensvertrag, die Grenzziehung, der Status von Gefangenen und Inhaftierten, Fragen der Verantwortung und Kriegsverbrechensvorwürfe, gegenseitige territoriale und verfassungsrechtliche Ansprüche sowie die parallele Normalisierung zwischen Armenien und der Türkei, deren gemeinsame Grenze seit den 1990er Jahren geschlossen ist. Grenzgefechte und Verstöße gegen den Waffenstillstand traten wiederholt auf.',ARRAY['ASIA-CAUCASUS'],true,42,'The Armenia-Azerbaijan conflict is the region''s longest-running interstate dispute, centred on Nagorno-Karabakh, a territory internationally recognised as Azerbaijani and inhabited by ethnic Armenians. It was fought over in a first war in 1988-1994, a second war in 2020, and a 2023 Azerbaijani operation, after which Azerbaijan reestablished full control and the territory''s Armenian population departed. The two states have negotiated toward a peace treaty and the delimitation of their border, with outstanding issues including the return of prisoners and detainees, accountability and war-crimes allegations, mutual constitutional and territorial claims, and guarantees against renewed fighting. In parallel, Armenia and Turkey -- whose shared border has been closed since the 1990s -- have pursued normalisation, including talks on trade and reopening rail and road links. The situation spans a diplomatic track and a persistent risk of renewed border clashes.','Der Konflikt zwischen Armenien und Aserbaidschan ist der am längsten andauernde zwischenstaatliche Streit der Region und dreht sich um Bergkarabach, ein völkerrechtlich als aserbaidschanisch anerkanntes und von ethnischen Armeniern bewohntes Gebiet. Um es wurde in einem ersten Krieg 1988-1994, einem zweiten Krieg 2020 und einer aserbaidschanischen Operation 2023 gekämpft; danach stellte Aserbaidschan die vollständige Kontrolle wieder her, und die armenische Bevölkerung des Gebiets ging fort. Die beiden Staaten haben über einen Friedensvertrag und die Grenzziehung verhandelt, mit offenen Fragen wie der Rückkehr von Gefangenen und Inhaftierten, Verantwortungs- und Kriegsverbrechensvorwürfen, gegenseitigen verfassungsrechtlichen und territorialen Ansprüchen und Garantien gegen erneute Kämpfe. Parallel dazu haben Armenien und die Türkei -- deren gemeinsame Grenze seit den 1990er Jahren geschlossen ist -- eine Normalisierung verfolgt, einschließlich Gesprächen über Handel und die Wiedereröffnung von Bahn- und Straßenverbindungen. Die Lage umfasst einen diplomatischen Weg und ein anhaltendes Risiko erneuter Grenzgefechte.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('armenia_western_pivot','Armenia''s realignment away from Russia','Armeniens Abkehr von Russland','The contested question of Armenia''s external alignment, between the Russian-led Collective Security Treaty Organization (CSTO) and Eurasian Economic Union (EAEU) on one side and the European Union and the West on the other. It encompasses Armenia''s security arrangements, trade dependencies, steps toward EU association and accession, Russian economic measures affecting Armenian trade, and a domestic political contest fought along this axis.','Die umstrittene Frage von Armeniens außenpolitischer Ausrichtung zwischen der russisch geführten Organisation des Vertrags über kollektive Sicherheit (OVKS) und der Eurasischen Wirtschaftsunion (EAWU) einerseits und der Europäischen Union und dem Westen andererseits. Sie umfasst Armeniens Sicherheitsarrangements, Handelsabhängigkeiten, Schritte in Richtung EU-Assoziierung und -Beitritt, russische Wirtschaftsmaßnahmen mit Auswirkungen auf den armenischen Handel sowie einen innenpolitischen Streit entlang dieser Achse.',ARRAY['ASIA-CAUCASUS'],true,41,'Armenia''s external alignment is a central and contested question of the country''s politics. Armenia is a member of the Russian-led CSTO and Eurasian Economic Union and has depended on Russia for security and trade. Its defeats in the wars over Nagorno-Karabakh opened a debate over those arrangements and over closer relations with the European Union, including trade measures, an association and accession debate, and high-level European engagement. Armenian politics divides between forces favouring alignment with Russia and the Russian-led blocs and those favouring integration with the EU, and national elections have been contested on this axis. Russia has applied economic measures affecting Armenian exports and has publicly stated that an EU turn would carry economic consequences. The dispute involves security guarantees, trade dependence, energy and domestic political competition at once.','Armeniens außenpolitische Ausrichtung ist eine zentrale und umstrittene Frage der Politik des Landes. Armenien ist Mitglied der russisch geführten OVKS und der Eurasischen Wirtschaftsunion und war in Sicherheit und Handel von Russland abhängig. Seine Niederlagen in den Kriegen um Bergkarabach eröffneten eine Debatte über diese Arrangements und über engere Beziehungen zur Europäischen Union, einschließlich Handelsmaßnahmen, einer Assoziierungs- und Beitrittsdebatte und hochrangiger europäischer Kontakte. Die armenische Politik teilt sich zwischen Kräften, die eine Ausrichtung auf Russland und die russisch geführten Bündnisse befürworten, und solchen, die eine Integration in die EU befürworten; nationale Wahlen wurden entlang dieser Achse ausgetragen. Russland hat Wirtschaftsmaßnahmen ergriffen, die armenische Ausfuhren betreffen, und öffentlich erklärt, eine Wende zur EU habe wirtschaftliche Folgen. Der Streit betrifft zugleich Sicherheitsgarantien, Handelsabhängigkeit, Energie und den innenpolitischen Wettbewerb.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('aukus_alliance_reliability','AUKUS submarine programme and alliance reliability','AUKUS-U-Boot-Programm und Bündniszuverlässigkeit','The AUKUS submarine programme and the Australian debate over what it delivers. Under a revised arrangement Australia is to receive three second-hand US Virginia-class submarines rather than newly built boats; the Collins-class fleet is being downsized and has entered a life-of-type extension; a UK inquiry reported shortcomings in the programme, and an Australian former minister crowd-funded a separate inquiry. The US Navy has established Naval Support Activity Stirling in Western Australia for rotational US and UK submarines, and Australia has pledged $2.7bn towards its own shipyard. The dispute runs between Australia and its partners and within Australian politics rather than with China.','Das AUKUS-U-Boot-Programm und die australische Debatte über seinen Ertrag. Nach einer überarbeiteten Vereinbarung soll Australien drei gebrauchte US-U-Boote der Virginia-Klasse statt neu gebauter Boote erhalten; die Collins-Klasse wird verkleinert und hat eine Laufzeitverlängerung begonnen; eine britische Untersuchung stellte Mängel des Programms fest, und ein früherer australischer Minister finanzierte per Crowdfunding eine eigene Untersuchung. Die US-Marine hat in Westaustralien die Naval Support Activity Stirling für rotierende US- und britische U-Boote eingerichtet, und Australien hat 2,7 Milliarden für eine eigene Werft zugesagt. Der Streit verläuft zwischen Australien und seinen Partnern sowie innerhalb der australischen Politik, nicht mit China.',ARRAY['OCEANIA-AUSTRALIA'],true,3,'AUKUS is the theater''s outlier, and the reason this theater is not a simple Australia-China dyad: only 3 of 70 AUKUS headlines mention China at all. The pact was built to answer Beijing, but the argument in the coverage is with Washington and within Australia. The revision to three second-hand Virginia-class boats reframed the entire debate — "the impact of Australia only buying second-hand submarines", "Australia scraps new Virginia-class submarines in AUKUS shake-up" — while the Collins-class fleet shrinks into a "high-risk" life extension and the Coalition floats stealth bombers as a stopgap. This is an own-goal topic in the strict sense: the harshest critics are the Australian mainstream itself, from a former foreign minister calling it among the country''s worst foreign-policy decisions to an ex-minister crowd-funding his own inquiry. Publisher alignment cannot separate stance here, because the same outlets carry both the defence of the pact and its demolition; only the framing does. Chinese and Russian state media denounce it as bloc confrontation and proliferation, but they are barely present in the coverage.','AUKUS ist der Ausreißer des Schauplatzes und der Grund, warum dieser keine einfache Australien-China-Dyade ist: nur 3 von 70 AUKUS-Schlagzeilen erwähnen China überhaupt. Der Pakt wurde als Antwort auf Peking geschlossen, doch der Streit in der Berichterstattung wird mit Washington und innerhalb Australiens geführt. Die Umstellung auf drei gebrauchte Boote der Virginia-Klasse hat die ganze Debatte neu gerahmt — "die Folgen davon, dass Australien nur gebrauchte U-Boote kauft", "Australien streicht neue Virginia-Boote in AUKUS-Umbau" — während die Collins-Klasse in eine "hochriskante" Laufzeitverlängerung schrumpft und die Opposition Tarnkappenbomber als Übergangslösung ins Spiel bringt. Dies ist ein Eigentor-Thema im strengen Sinne: die schärfsten Kritiker sind die australischen Leitmedien selbst — von einem früheren Außenminister, der den Pakt zu den schlechtesten außenpolitischen Entscheidungen des Landes zählt, bis zu einem Ex-Minister, der seine eigene Untersuchung per Crowdfunding finanziert. Die Medienzugehörigkeit kann die Haltung hier nicht trennen, weil dieselben Medien Verteidigung und Demontage des Pakts tragen; nur die Rahmung tut es. Chinesische und russische Staatsmedien verurteilen ihn als Blockkonfrontation und Proliferation, sind in der Berichterstattung aber kaum präsent.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('australia_china_trade_leverage','Trade dependence and commodity leverage','Handelsabhängigkeit und Rohstoffhebel','The commercial relationship between Australia and China, in which market access and commodity supply function as mutual leverage. China''s state-owned iron ore buyer restricted Fortescue and BHP cargoes during pricing negotiations before a settlement adopting a Chinese price index; a 55% tariff on Australian beef took effect when an agreed quota threshold was reached; Australia ordered Chinese investors to divest stakes in rare-earth projects under its foreign investment rules, and the Darwin Port lease remains disputed. The 2020-21 restrictions on barley, wine, coal and lobster have largely been unwound.','Die Handelsbeziehung zwischen Australien und China, in der Marktzugang und Rohstoffversorgung als wechselseitiger Hebel wirken. Chinas staatlicher Eisenerzkäufer beschränkte während der Preisverhandlungen Ladungen von Fortescue und BHP, bevor eine Einigung einen chinesischen Preisindex übernahm; ein Zoll von 55 Prozent auf australisches Rindfleisch trat in Kraft, als eine vereinbarte Quotenschwelle erreicht war; Australien ordnete nach seinen Regeln zur Auslandsinvestitionsprüfung den Verkauf chinesischer Anteile an Seltene-Erden-Projekten an, und die Verpachtung des Hafens von Darwin bleibt strittig. Die Beschränkungen von 2020-21 für Gerste, Wein, Kohle und Hummer sind weitgehend aufgehoben.',ARRAY['ASIA-CHINA'],true,2,'The quiet axis, and the one most often described with a stale frame. The 2020-21 coercion campaign — barley, wine, coal, lobster — is essentially over: Treasury Wine posts its strongest China result in over a decade and Beijing has been issuing new beef licences. What replaced it is subtler and genuinely two-way. China''s state buyer can restrict Fortescue and BHP cargoes mid-negotiation, and a 55% beef tariff snaps in at a quota threshold; but Australia can force Chinese investors out of rare-earth projects, and its foreign minister can be found telling Beijing "we need your fuel to send you iron ore". Coverage divides on interpretation rather than fact: Australian and Western business press reads each lever as proof that concentration is a strategic vulnerability requiring diversification and screening, while Chinese state media report the same tariff as the routine operation of an agreed quota and point to record vehicle sales, solar cooperation and rising Australian opinion of China as the real trend.','Die leise Achse — und die, die am häufigsten mit einem veralteten Deutungsrahmen beschrieben wird. Die Zwangskampagne von 2020-21 gegen Gerste, Wein, Kohle und Hummer ist im Wesentlichen beendet: Treasury Wine meldet sein stärkstes China-Ergebnis seit über einem Jahrzehnt, und Peking erteilt neue Rindfleischlizenzen. An ihre Stelle ist etwas Feineres und tatsächlich Wechselseitiges getreten. Chinas staatlicher Käufer kann mitten in Verhandlungen Ladungen von Fortescue und BHP beschränken, und ein 55-Prozent-Rindfleischzoll greift bei Erreichen einer Quotenschwelle; doch Australien kann chinesische Investoren aus Seltene-Erden-Projekten drängen, und seine Außenministerin sagt Peking, man brauche dessen Treibstoff, um Eisenerz zu liefern. Die Berichterstattung unterscheidet sich in der Deutung, nicht im Faktum: die australische und westliche Wirtschaftspresse liest jeden Hebel als Beleg dafür, dass Konzentration eine strategische Verwundbarkeit ist, die Diversifizierung und Prüfung erfordert, während chinesische Staatsmedien denselben Zoll als routinemäßige Anwendung einer vereinbarten Quote darstellen und Rekordabsätze bei Fahrzeugen, Solarkooperation und eine steigende Meinung über China als den eigentlichen Trend anführen.','atomic',NULL,'{}','regional',NULL::jsonb,'OCEANIA-AUSTRALIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('australia_theater','Australia as a contested middle power','Australien als umkämpfte Mittelmacht','Australia''s strategic position between its largest trading partner and its principal security ally. Four axes run through it: the contest with China over the security and diplomatic alignment of the Pacific island states; a trade relationship in which iron ore, beef and critical minerals carry both dependence and leverage; the contested assessment of Chinese espionage and military reach; and the AUKUS submarine programme, whose revision has made alliance reliability a domestic Australian question. Coverage divides between Australian and Western outlets, Chinese state media, and — on AUKUS — Australian critics of the pact itself.','Australiens strategische Lage zwischen seinem größten Handelspartner und seinem wichtigsten Sicherheitsverbündeten. Vier Achsen durchziehen sie: der Wettstreit mit China um die sicherheitspolitische und diplomatische Ausrichtung der pazifischen Inselstaaten; eine Handelsbeziehung, in der Eisenerz, Rindfleisch und kritische Rohstoffe zugleich Abhängigkeit und Hebel bedeuten; die umstrittene Einschätzung chinesischer Spionage und militärischer Reichweite; und das AUKUS-U-Boot-Programm, dessen Überarbeitung die Zuverlässigkeit des Bündnisses zu einer innenpolitischen Frage Australiens gemacht hat. Die Berichterstattung teilt sich zwischen australischen und westlichen Medien, chinesischen Staatsmedien und — bei AUKUS — australischen Kritikern des Pakts selbst.',ARRAY['OCEANIA-AUSTRALIA','ASIA-CHINA','AMERICAS-USA','OCEANIA-MELANESIA','OCEANIA-POLYNESIA','OCEANIA-MICRONESIA','OCEANIA-PAPUANEWGUINEA'],true,13,'Australia is the test case of a middle power that buys from one great power and shelters under another. Its coverage is not a single dyad but four distinct contests. The Pacific is the live front: within hours of Canberra signing a mutual defence treaty with Fiji, Beijing test-fired a nuclear-capable ballistic missile into the South Pacific, and Vanuatu and Solomon Islands are openly weighing which partner to take. Trade is the quiet one: the 2020-21 barley-and-wine coercion episode has largely unwound, and the live story is quota mechanics and iron-ore pricing power, running in both directions. Threat assessment is the loudest rhetorically, where ASIO, Five Eyes and the Lowy Institute meet a Chinese rebuttal machine that calls the whole thing hype. And AUKUS is the outlier: 96% of its coverage never mentions China at all, because the argument is with Washington and within Australia — over second-hand submarines, a capability gap and whether the pact was ever a good bargain. The result is a theater where the sharpest criticism of Australian policy comes not from Beijing but from Australian outlets.','Australien ist der Prüfstein einer Mittelmacht, die von einer Großmacht kauft und sich bei einer anderen unterstellt. Seine Berichterstattung ist keine einzelne Dyade, sondern vier getrennte Auseinandersetzungen. Der Pazifik ist die aktive Front: Stunden nachdem Canberra einen Verteidigungsvertrag mit Fidschi unterzeichnet hatte, testete Peking eine atomwaffenfähige ballistische Rakete im Südpazifik, und Vanuatu und die Salomonen wägen offen ab, welchen Partner sie wählen. Der Handel ist die leise Achse: die Zwangsmaßnahmen gegen Gerste und Wein von 2020-21 sind weitgehend zurückgenommen, und die aktuelle Geschichte sind Quotenmechanik und Preismacht beim Eisenerz — in beide Richtungen. Die Bedrohungsanalyse ist rhetorisch am lautesten, wo ASIO, Five Eyes und das Lowy Institute auf einen chinesischen Widerlegungsapparat treffen, der das Ganze als Panikmache bezeichnet. Und AUKUS ist der Ausreißer: 96 Prozent dieser Berichterstattung erwähnen China überhaupt nicht, denn der Streit wird mit Washington und innerhalb Australiens geführt — über gebrauchte U-Boote, eine Fähigkeitslücke und die Frage, ob der Pakt je ein guter Handel war. So entsteht ein Schauplatz, an dem die schärfste Kritik an australischer Politik nicht aus Peking kommt, sondern aus australischen Medien.','theater',ARRAY['pacific_island_contest','australia_china_trade_leverage','aukus_alliance_reliability','china_threat_assessment'],ARRAY['pilbara_iron_belt','australian_lithium_belt','australian_wheat_belt'],'regional','{"type": "Point", "coordinates": [149.13, -35.28]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('balochistan_insurgency','Balochistan insurgency','Aufstand in Belutschistan','The separatist insurgency in Balochistan, Pakistan''s largest and least populous province. It covers attacks by the Baloch Liberation Army and allied groups on security forces, railways and infrastructure, Pakistani military operations in response, the detention and prosecution of Baloch political activists including Mahrang Baloch, and the province''s mineral and port development, including Gwadar. Pakistan attributes the attacks to Indian backing; India rejects the attribution.','Der separatistische Aufstand in Belutschistan, Pakistans größter und am dünnsten besiedelter Provinz. Erfasst werden Anschläge der Belutschischen Befreiungsarmee und verbündeter Gruppen auf Sicherheitskräfte, Eisenbahnen und Infrastruktur, pakistanische Militäroperationen als Reaktion darauf, die Inhaftierung und strafrechtliche Verfolgung belutschischer Aktivisten wie Mahrang Baloch sowie die Erschließung der Bodenschätze und Häfen der Provinz, einschließlich Gwadar. Pakistan schreibt die Anschläge indischer Unterstützung zu; Indien weist dies zurück.',ARRAY['ASIA-PAKISTAN'],true,64,'Balochistan produces the highest-casualty incidents inside Pakistan: coordinated attacks that killed well over a hundred people, a train bombing claimed by Baloch separatists, and military operations reported to have killed scores of fighters. Pakistani officials link the Baloch Liberation Army to Indian backing and have pressed the UN Security Council to designate it; Indian officials call the charge a deflection from internal failings, and Pakistani lawmakers have themselves described the province as approaching civil war. Alongside the violence runs a civil-rights dispute: the life sentence handed to activist Mahrang Baloch, and reported enforced disappearances. Foreign investment in the province''s minerals and in Gwadar port proceeds against this backdrop.','Belutschistan verzeichnet die opferreichsten Vorfälle innerhalb Pakistans: koordinierte Anschläge mit weit über hundert Toten, ein von belutschischen Separatisten reklamierter Anschlag auf einen Zug und Militäroperationen, bei denen Dutzende Kämpfer getötet worden sein sollen. Pakistanische Behörden bringen die Belutschische Befreiungsarmee mit indischer Unterstützung in Verbindung und drängten den UN-Sicherheitsrat, sie zu listen; indische Stellen nennen den Vorwurf eine Ablenkung von inneren Defiziten, und pakistanische Abgeordnete haben die Lage in der Provinz selbst als bürgerkriegsnah beschrieben. Neben der Gewalt verläuft ein bürgerrechtlicher Streit: die lebenslange Haftstrafe für die Aktivistin Mahrang Baloch und Berichte über Fälle des Verschwindenlassens. Ausländische Investitionen in die Bodenschätze der Provinz und in den Hafen von Gwadar laufen vor diesem Hintergrund weiter.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('baltic_security','Baltic states security and NATO guarantees',NULL,NULL,NULL,ARRAY['EUROPE-RUSSIA','EUROPE-BALTIC','AMERICAS-USA'],false,26,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('canada_sovereignty_pressure','Annexation rhetoric and Canadian sovereignty response','Annexionsrhetorik und kanadische Souveränitätsantwort','The dispute over Canadian sovereignty in relation to the United States. It covers public statements about annexation and Canada becoming a US state, the threat to withhold opening of the Gordie Howe International Bridge between Detroit and Windsor, the withdrawal of Canada''s invitation to the Board of Peace, demands relating to the Golden Dome missile-defence programme, and the Canadian response — including consumer boycotts, domestic-purchasing campaigns and statements on the post-war international order.','Der Streit um die kanadische Souveränität im Verhältnis zu den USA. Er umfasst öffentliche Äußerungen über eine Annexion und einen Beitritt Kanadas als US-Bundesstaat, die Drohung, die Eröffnung der Gordie-Howe-Brücke zwischen Detroit und Windsor zurückzuhalten, die Rücknahme der kanadischen Einladung zum Board of Peace, Forderungen im Zusammenhang mit dem Raketenabwehrprogramm Golden Dome sowie die kanadische Reaktion — darunter Verbraucherboykotte, Kampagnen für heimische Käufe und Äußerungen zur internationalen Nachkriegsordnung.',ARRAY['AMERICAS-USA'],true,114,'Alongside the tariff dispute runs a distinct argument about status. Public discussion of annexation and of Canada as a fifty-first state has been accompanied by concrete instruments: a threat to keep closed the Gordie Howe International Bridge, a crossing Canada financed, and the withdrawal of the Canadian prime minister''s invitation to the Board of Peace following a speech at Davos on the post-war order. Demands relating to cost-sharing for the Golden Dome missile-defence programme run alongside them. The Canadian response has been cross-party and has extended beyond government to consumer boycotts and domestic-purchasing campaigns, with polling showing the confrontation consolidating rather than dividing Canadian opinion. Coverage from Russian and Chinese state outlets treats the annexation discussion as a case of expansionism within the Americas rather than endorsing either side.','Neben dem Zollstreit verläuft eine eigene Auseinandersetzung über den Status. Öffentliche Debatten über eine Annexion und über Kanada als einundfünfzigsten Bundesstaat gingen mit konkreten Instrumenten einher: der Drohung, die Gordie-Howe-Brücke geschlossen zu halten — einen von Kanada finanzierten Übergang — und der Rücknahme der Einladung des kanadischen Premierministers zum Board of Peace nach einer Rede in Davos über die Nachkriegsordnung. Hinzu kommen Forderungen zur Kostenbeteiligung am Raketenabwehrprogramm Golden Dome. Die kanadische Reaktion war parteiübergreifend und reichte über die Regierung hinaus bis zu Verbraucherboykotten und Kampagnen für heimische Käufe; Umfragen zeigen, dass die Konfrontation die kanadische Öffentlichkeit eher zusammenführt als spaltet. Russische und chinesische Staatsmedien behandeln die Annexionsdebatte als Fall von Expansionismus in Amerika, ohne eine der beiden Seiten zu unterstützen.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CANADA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('caucasus_power_competition','External power competition over the South Caucasus','Wettbewerb externer Mächte um den Südkaukasus','Competition among external powers -- Russia, Turkey, Iran, Israel and the United States -- for influence in the South Caucasus. It runs through Azerbaijani energy resources and export routes (the state company SOCAR, the Southern Gas Corridor, Caspian hydrocarbons), security and defence ties, the dispute between Israel and Turkey around recognition of the Armenian Genocide, tensions between Russia and Azerbaijan, and competing connectivity axes such as the Zangezur route and the International North-South Transport Corridor.','Der Wettbewerb externer Mächte -- Russland, Türkei, Iran, Israel und die Vereinigten Staaten -- um Einfluss im Südkaukasus. Er verläuft über aserbaidschanische Energieressourcen und Exportrouten (die staatliche Gesellschaft SOCAR, den Südlichen Gaskorridor, kaspische Kohlenwasserstoffe), Sicherheits- und Verteidigungsbeziehungen, den Streit zwischen Israel und der Türkei um die Anerkennung des Völkermords an den Armeniern, Spannungen zwischen Russland und Aserbaidschan sowie konkurrierende Konnektivitätsachsen wie die Sangesur-Route und den Internationalen Nord-Süd-Transportkorridor.',ARRAY['ASIA-CAUCASUS'],true,45,'The South Caucasus lies at the meeting point of several external powers that compete for influence as the regional balance shifts. Azerbaijan''s energy resources -- managed through the state company SOCAR and exported via the Southern Gas Corridor -- underpin its relations with Europe and Turkey, and Caspian hydrocarbons draw wider interest. Israel and Azerbaijan maintain close security and energy ties, and recognition of the Armenian Genocide by outside states is a point of contention between Israel and Turkey and has drawn Azerbaijani objection. Relations between Russia and Azerbaijan have been strained by incidents including detentions of nationals and a strike on a SOCAR facility. Iran opposes external military presence near its northern border. Competing transport projects -- the Zangezur route and the Iran-Russia International North-South Transport Corridor -- add an economic dimension to the contest among Russia, Turkey, Iran, Israel and the United States.','Der Südkaukasus liegt am Schnittpunkt mehrerer externer Mächte, die um Einfluss konkurrieren, während sich das regionale Gleichgewicht verschiebt. Aserbaidschans Energieressourcen -- verwaltet über die staatliche Gesellschaft SOCAR und exportiert über den Südlichen Gaskorridor -- untermauern seine Beziehungen zu Europa und der Türkei, und kaspische Kohlenwasserstoffe wecken breiteres Interesse. Israel und Aserbaidschan unterhalten enge Sicherheits- und Energiebeziehungen, und die Anerkennung des Völkermords an den Armeniern durch außenstehende Staaten ist ein Streitpunkt zwischen Israel und der Türkei und hat aserbaidschanischen Widerspruch hervorgerufen. Die Beziehungen zwischen Russland und Aserbaidschan sind durch Vorfälle wie die Festnahme von Staatsbürgern und einen Angriff auf eine SOCAR-Anlage belastet. Der Iran lehnt eine externe Militärpräsenz nahe seiner Nordgrenze ab. Konkurrierende Verkehrsprojekte -- die Sangesur-Route und der iranisch-russische Internationale Nord-Süd-Transportkorridor -- fügen dem Wettstreit zwischen Russland, der Türkei, dem Iran, Israel und den Vereinigten Staaten eine wirtschaftliche Dimension hinzu.','atomic',NULL,ARRAY['btc_pipeline','shah_deniz_field','scp_pipeline','sangachal_terminal'],'regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('caucasus_theater','South Caucasus realignment','Neuordnung des Südkaukasus','The South Caucasus -- Armenia, Azerbaijan and Georgia -- at the intersection of Russian, Turkish, Iranian and Euro-Atlantic interests. The region carries several unresolved disputes: the Armenia-Azerbaijan conflict centred on Nagorno-Karabakh, the question of Armenia''s alignment between the Russian-led blocs and the European Union, the status of Georgia''s breakaway regions of Abkhazia and South Ossetia, transit corridors across the region, and competition among external powers over influence, energy routes and security ties. It has seen repeated wars, including the Nagorno-Karabakh wars and the 2008 Russia-Georgia war.','Der Südkaukasus -- Armenien, Aserbaidschan und Georgien -- an der Schnittstelle russischer, türkischer, iranischer und euro-atlantischer Interessen. Die Region trägt mehrere ungelöste Streitfragen: den auf Bergkarabach zentrierten Konflikt zwischen Armenien und Aserbaidschan, die Frage von Armeniens Ausrichtung zwischen den russisch geführten Bündnissen und der Europäischen Union, den Status der abtrünnigen georgischen Regionen Abchasien und Südossetien, Transitkorridore durch die Region sowie den Wettbewerb externer Mächte um Einfluss, Energierouten und Sicherheitsbeziehungen. Sie hat wiederholt Kriege erlebt, darunter die Kriege um Bergkarabach und den russisch-georgischen Krieg von 2008.',ARRAY['ASIA-CAUCASUS','EUROPE-RUSSIA','MIDEAST-TURKEY','MIDEAST-IRAN','MIDEAST-ISRAEL','AMERICAS-USA','NON-STATE-EU','NON-STATE-NATO'],true,12,'The South Caucasus is a small region bordered by Russia, Turkey and Iran and reached by the interests of the European Union and the United States. Its principal fault lines are long-standing. Armenia and Azerbaijan have fought over Nagorno-Karabakh in wars in 1988-1994, in 2020, and in 2023, after which Azerbaijan reestablished control of the territory and its Armenian population departed; the two states negotiate over a peace treaty and the delimitation of their border. Armenia''s alignment is disputed between its membership in the Russian-led CSTO and Eurasian Economic Union and closer ties with the EU. Georgia contests its own external orientation, including EU accession, a law on foreign-funded organisations, and election results, while Abkhazia and South Ossetia -- the subject of conflicts in the early 1990s and the 2008 Russia-Georgia war -- remain outside Tbilisi''s control and are backed by Russia. A proposed transit corridor across Armenia''s Syunik province, and competition among Russia, Turkey, Iran, Israel and the United States over energy, security and connectivity, run through the region.','Der Südkaukasus ist eine kleine Region, die an Russland, die Türkei und den Iran grenzt und in die die Interessen der Europäischen Union und der Vereinigten Staaten hineinreichen. Seine wichtigsten Bruchlinien sind langjährig. Armenien und Aserbaidschan haben in Kriegen 1988-1994, 2020 und 2023 um Bergkarabach gekämpft; danach stellte Aserbaidschan die Kontrolle über das Gebiet wieder her, und dessen armenische Bevölkerung verließ es. Die beiden Staaten verhandeln über einen Friedensvertrag und die Grenzziehung. Armeniens Ausrichtung ist umstritten zwischen seiner Mitgliedschaft in der russisch geführten OVKS und der Eurasischen Wirtschaftsunion und engeren Beziehungen zur EU. Georgien streitet über seine eigene außenpolitische Ausrichtung, darunter den EU-Beitritt, ein Gesetz über ausländisch finanzierte Organisationen und Wahlergebnisse, während Abchasien und Südossetien -- Gegenstand von Konflikten in den frühen 1990er Jahren und des russisch-georgischen Krieges von 2008 -- außerhalb der Kontrolle Tiflis'' bleiben und von Russland unterstützt werden. Ein geplanter Transitkorridor durch Armeniens Provinz Sjunik sowie der Wettbewerb zwischen Russland, der Türkei, dem Iran, Israel und den Vereinigten Staaten um Energie, Sicherheit und Konnektivität durchziehen die Region.','theater',ARRAY['armenia_western_pivot','armenia_azerbaijan_settlement','georgia_geopolitical_drift','zangezur_corridor','caucasus_power_competition'],ARRAY['btc_pipeline','shah_deniz_field','scp_pipeline','sangachal_terminal'],'regional','{"type": "Point", "coordinates": [46.75, 39.8]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('china_japan_economic_restrictions','Chinese economic and travel restrictions on Japan','Chinesische Wirtschafts- und Reisebeschränkungen gegenüber Japan','Chinese trade, travel and regulatory measures affecting Japan, including rare-earth and dual-use export licensing, travel advisories affecting Chinese tourism to Japan, import rules on Japanese seafood, and the detention of Japanese nationals in China.','Chinesische Handels-, Reise- und Regulierungsmaßnahmen mit Auswirkungen auf Japan, darunter Exportlizenzierung für Seltene Erden und Güter mit doppeltem Verwendungszweck, Reisewarnungen mit Auswirkungen auf den chinesischen Tourismus nach Japan, Importregeln für japanische Meeresfrüchte sowie die Festnahme japanischer Staatsbürger in China.',ARRAY['ASIA-CHINA'],true,73,'China supplies the large majority of the world''s processed rare-earth minerals, an input Japanese manufacturers depend on, and has historically been Japan''s largest source of inbound tourists. Both have become instruments in the bilateral relationship: Chinese export licensing on rare earths and related materials to Japan has tightened at points of diplomatic friction, Chinese authorities have issued travel advisories that preceded declines in tourist arrivals from China, and imports of Japanese seafood have at times been restricted. Japanese nationals, including company employees, have also been detained by Chinese authorities. Japanese and allied governments have responded by pursuing alternative mineral sources, including seabed extraction and recycling, and joint stockpiling arrangements with other countries.','China liefert den überwiegenden Teil der weltweit verarbeiteten Seltenen Erden, ein Vorprodukt, von dem japanische Hersteller abhängig sind, und war historisch die größte Quelle einreisender Touristen für Japan. Beides ist zu einem Instrument der bilateralen Beziehung geworden: Chinesische Exportlizenzierung für Seltene Erden und verwandte Materialien nach Japan wurde an Punkten diplomatischer Spannung verschärft, chinesische Behörden erließen Reisewarnungen, denen Rückgänge bei den Touristenankünften aus China folgten, und Importe japanischer Meeresfrüchte wurden zeitweise beschränkt. Auch japanische Staatsbürger, darunter Unternehmensmitarbeiter, wurden von chinesischen Behörden festgenommen. Japan und verbündete Regierungen reagierten mit der Suche nach alternativen Rohstoffquellen, darunter Tiefseeabbau und Recycling, sowie gemeinsamen Bevorratungsvereinbarungen mit anderen Ländern.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-JAPAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('china_threat_assessment','Espionage allegations and China threat assessment','Spionagevorwürfe und Einschätzung der chinesischen Bedrohung','The contested assessment of Chinese espionage and military reach in relation to Australia. Australian authorities have charged Chinese nationals with foreign interference in Canberra, a jury found an Australian expatriate had acted as a Chinese intelligence asset, and the Five Eyes alliance warned that Chinese services recruit targets through fake job advertisements on professional networks. The Lowy Institute assessed China''s capacity to strike targets in Australia as growing, and China conducted a nuclear-capable ballistic missile test into the South Pacific. Chinese officials and state media reject these assessments.','Die umstrittene Einschätzung chinesischer Spionage und militärischer Reichweite in Bezug auf Australien. Australische Behörden haben chinesische Staatsbürger wegen ausländischer Einflussnahme in Canberra angeklagt, ein Geschworenengericht befand, ein australischer Auswanderer habe als chinesischer Nachrichtendienstzuträger gehandelt, und das Five-Eyes-Bündnis warnte, chinesische Dienste würben Zielpersonen über gefälschte Stellenanzeigen in beruflichen Netzwerken an. Das Lowy Institute schätzte Chinas Fähigkeit zu Angriffen auf Ziele in Australien als wachsend ein, und China führte einen atomwaffenfähigen ballistischen Raketentest im Südpazifik durch. Chinesische Amtsträger und Staatsmedien weisen diese Einschätzungen zurück.',ARRAY['ASIA-CHINA'],true,4,'This axis is a contest over whether the threat is real, and it is unusually symmetrical: nearly every Australian claim has a same-week Chinese rebuttal. ASIO spars publicly with Beijing over foreign interference; two more Chinese nationals are charged over information-gathering in Canberra; a jury finds an Australian expatriate acted as a Chinese spy asset; Five Eyes warns that Chinese officers pose as recruiters on job platforms; the Lowy Institute concludes China''s ability to strike targets in Australia is "real and growing"; and a nuclear-capable missile lands in the South Pacific. Against each, Chinese state media return a mirror line — the espionage warning is a "crafted rhetorical trap" and "highly ironic" from an alliance built on surveillance, and the think-tank threat assessment is a grave strategic miscalculation. The two coalitions are fully disjoint, so publisher alone tells the stances apart; what the corpus cannot settle is which reading a reader should believe.','Diese Achse ist ein Streit darüber, ob die Bedrohung real ist, und sie verläuft ungewöhnlich symmetrisch: fast jede australische Behauptung findet in derselben Woche eine chinesische Erwiderung. Der Inlandsgeheimdienst ASIO streitet öffentlich mit Peking über ausländische Einflussnahme; zwei weitere chinesische Staatsbürger werden wegen Informationsbeschaffung in Canberra angeklagt; ein Geschworenengericht befindet, ein australischer Auswanderer habe als chinesischer Spionagehelfer gehandelt; Five Eyes warnt, chinesische Offiziere gäben sich auf Jobplattformen als Personalvermittler aus; das Lowy Institute schließt, Chinas Fähigkeit zu Angriffen auf Ziele in Australien sei "real und wachsend"; und eine atomwaffenfähige Rakete geht im Südpazifik nieder. Dagegen setzen chinesische Staatsmedien jeweils eine Spiegelaussage — die Spionagewarnung sei eine "rhetorische Falle" und "höchst ironisch" von einem auf Überwachung gebauten Bündnis, und die Bedrohungsanalyse der Denkfabrik ein schwerer strategischer Fehlschluss. Die beiden Lager sind vollständig getrennt, sodass allein das Medium die Haltungen unterscheidet; was der Korpus nicht klären kann, ist, welcher Lesart zu glauben ist.','atomic',NULL,'{}','regional',NULL::jsonb,'OCEANIA-AUSTRALIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_armed_groups_peace','Armed groups and the peace process','Bewaffnete Gruppen und der Friedensprozess','Negotiations with guerrilla groups and drug cartels under the "total peace" policy, and the armed and narcotics economy they operate in.','Verhandlungen mit Guerillagruppen und Drogenkartellen im Rahmen der Politik des "totalen Friedens" sowie die bewaffnete Ökonomie und Drogenwirtschaft, in der sie agieren.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'The "total peace" policy opened parallel negotiations with the ELN, FARC dissident factions and the Gulf Clan. A tribunal charged former FARC members with war crimes, and the largest cartel suspended talks after the understanding reached between the Colombian and US presidents. Coca cultivation and gold trafficking fund several of the groups involved.','Die Politik des "totalen Friedens" eröffnete parallele Verhandlungen mit der ELN, FARC-Dissidentengruppen und dem Clan del Golfo. Ein Tribunal klagte frühere FARC-Mitglieder wegen Kriegsverbrechen an, und das größte Kartell setzte die Gespräche aus, nachdem sich der kolumbianische und der US-Präsident verständigt hatten. Kokaanbau und Goldschmuggel finanzieren mehrere der beteiligten Gruppen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_political_transition','Presidential transition and institutional contest','Präsidentschaftswechsel und institutioneller Streit','The Colombian presidential succession, the contested result and the institutional disputes around it.','Die kolumbianische Präsidentschaftsnachfolge, das umstrittene Ergebnis und die damit verbundenen institutionellen Auseinandersetzungen.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'The presidential race concluded in a narrow runoff win for Abelardo de la Espriella over Iván Cepeda. The US president publicly endorsed the winner before the vote, and the outgoing president alleged foreign interference in the result. The losing camp pursued a legal challenge. Coverage divides between readings of the outcome as a security mandate and as a risk to institutional norms.','Das Präsidentschaftsrennen endete mit einem knappen Stichwahlsieg von Abelardo de la Espriella über Iván Cepeda. Der US-Präsident hatte den Sieger vor der Wahl öffentlich unterstützt, und der scheidende Präsident behauptete ausländische Einflussnahme auf das Ergebnis. Das unterlegene Lager ging juristisch dagegen vor. Die Berichterstattung teilt sich in Deutungen des Ausgangs als Sicherheitsmandat und als Risiko für institutionelle Normen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_theater','Colombia','Kolumbien','Colombia''s external alignment, its contested presidential transition, and the negotiations with armed groups and drug cartels.','Kolumbiens außenpolitische Ausrichtung, der umstrittene Präsidentschaftswechsel und die Verhandlungen mit bewaffneten Gruppen und Drogenkartellen.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'Relations with Washington moved from a threatened military operation and a formal Colombian complaint to a White House meeting within weeks, and the resulting understanding disrupted the government''s negotiations with armed groups. A presidential election then produced a winner endorsed by the US president, while the outgoing president alleged foreign interference in the vote. Colombia has no centroid of its own and is covered under AMERICAS-ANDEAN.','Die Beziehungen zu Washington entwickelten sich binnen Wochen von einer angedrohten Militäroperation und einer förmlichen kolumbianischen Beschwerde hin zu einem Treffen im Weißen Haus; die daraus folgende Verständigung störte die Verhandlungen der Regierung mit bewaffneten Gruppen. Eine Präsidentschaftswahl brachte anschließend einen vom US-Präsidenten unterstützten Sieger hervor, während der scheidende Präsident ausländische Einflussnahme auf die Wahl behauptete. Kolumbien hat keinen eigenen Zentroid und wird unter AMERICAS-ANDEAN geführt.','theater',ARRAY['colombia_us_alignment','colombia_political_transition','colombia_armed_groups_peace'],'{}','regional','{"type": "Point", "coordinates": [-74.1, 4.7]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_us_alignment','Alignment with Washington','Ausrichtung gegenüber Washington','Colombia''s relations with the United States, spanning coercive measures, tariffs, sanctions designations and negotiated rapprochement.','Kolumbiens Beziehungen zu den Vereinigten Staaten, von Zwangsmaßnahmen, Zöllen und Sanktionslistungen bis zur ausgehandelten Annäherung.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'In January the US president threatened a military operation against Colombia following a raid in Venezuela; Bogotá lodged a formal complaint. Within weeks the two presidents met at the White House. The episode combined tariff threats, visa measures and sanctions designations with a rapid diplomatic reversal, and the resulting understanding carried directly into Colombia''s talks with armed groups.','Im Januar drohte der US-Präsident nach einem Einsatz in Venezuela mit einer Militäroperation gegen Kolumbien; Bogotá legte förmlich Beschwerde ein. Wenige Wochen später trafen sich beide Präsidenten im Weißen Haus. Die Episode verband Zolldrohungen, Visamaßnahmen und Sanktionslistungen mit einer raschen diplomatischen Kehrtwende; die daraus folgende Verständigung wirkte unmittelbar auf Kolumbiens Gespräche mit bewaffneten Gruppen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_embargo_sanctions','US sanctions and blockade instruments','US-Sanktions- und Blockadeinstrumente','US economic and legal instruments applied to Cuba: the embargo and its executive orders, sanctions designations of Cuban state and military-run enterprises, secondary sanctions reaching foreign shippers and hotel operators, expropriation and compensation claims, and criminal charges against Cuban officials.','Wirtschaftliche und juristische Instrumente der USA gegenüber Kuba: das Embargo und seine Dekrete, Sanktionslistungen kubanischer Staats- und Militärunternehmen, Sekundärsanktionen gegen ausländische Reedereien und Hotelbetreiber, Enteignungs- und Entschädigungsklagen sowie Strafverfahren gegen kubanische Amtsträger.',ARRAY['AMERICAS-CUBA'],true,102,'The instrument set widened during this window from the long-standing embargo to an executive order targeting fuel supply, designations of the military conglomerate GAESA and the Moa nickel operation, withdrawal by foreign shipping and hotel groups under threat of secondary sanctions, a Supreme Court opening for expropriation claims, and an indictment of a former Cuban president.','Das Instrumentarium weitete sich in diesem Zeitraum vom langjährigen Embargo aus: ein Dekret gegen die Treibstoffversorgung, Listungen des Militärkonglomerats GAESA und des Nickelbetriebs Moa, Rückzug ausländischer Reederei- und Hotelgruppen unter Androhung von Sekundärsanktionen, eine Öffnung des Supreme Court für Enteignungsklagen und eine Anklage gegen einen früheren kubanischen Präsidenten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_energy_collapse','Energy and humanitarian collapse','Energie- und humanitärer Zusammenbruch','The failure of Cuba''s electricity supply and the shortages that follow from it: national and regional blackouts, exhaustion of fuel reserves, rationing, and the effects on hospitals, food, water, sanitation and transport.','Der Zusammenbruch der kubanischen Stromversorgung und die daraus folgenden Engpässe: landesweite und regionale Stromausfälle, erschöpfte Treibstoffreserven, Rationierung sowie die Auswirkungen auf Kliniken, Nahrung, Wasser, Abfallentsorgung und Verkehr.',ARRAY['AMERICAS-CUBA'],true,105,'Cuba''s grid failed repeatedly during this window, at times island-wide, after the government reported its fuel reserves exhausted. Reporting covers rationing plans, closed hotels and suspended flights, uncollected refuse in Havana, hospital supply failures, and United Nations warnings of humanitarian collapse. Whether the cause is the US fuel blockade or long-term under-investment is itself contested.','Kubas Stromnetz fiel in diesem Zeitraum wiederholt aus, zeitweise landesweit, nachdem die Regierung ihre Treibstoffreserven für erschöpft erklärt hatte. Berichtet wird über Rationierungspläne, geschlossene Hotels und gestrichene Flüge, nicht abgeholten Müll in Havanna, Versorgungsausfälle in Kliniken und Warnungen der Vereinten Nationen vor einem humanitären Zusammenbruch. Ob die Ursache die US-Treibstoffblockade oder jahrzehntelange Unterinvestition ist, ist selbst umstritten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_external_lifelines','External lifelines and patron competition','Äußere Rettungsleinen und Patronenkonkurrenz','External supply to Cuba and the competition around it: oil and fuel cargoes, food and medical shipments, credit and aid from Russia, China, Venezuela, Mexico, Canada and European states, and US pressure on third countries to withhold them.','Versorgung Kubas von außen und der Wettbewerb darum: Öl- und Treibstoffladungen, Nahrungsmittel- und Medizinlieferungen, Kredite und Hilfe aus Russland, China, Venezuela, Mexiko, Kanada und europäischen Staaten sowie US-Druck auf Drittstaaten, sie zurückzuhalten.',ARRAY['AMERICAS-CUBA'],true,106,'Russian tankers, a Chinese rice shipment, Mexican humanitarian cargoes and a suspended Pemex crude contract all feature in this window, alongside US measures aimed at the third parties supplying them. Shipping movements, diversions and arrivals were reported closely enough to function as a running indicator of the island''s position.','Russische Tanker, eine chinesische Reislieferung, mexikanische Hilfsfrachten und ein ausgesetzter Pemex-Rohölvertrag prägen diesen Zeitraum, daneben US-Maßnahmen gegen die liefernden Drittparteien. Schiffsbewegungen, Kursänderungen und Ankünfte wurden so genau verfolgt, dass sie als laufender Indikator für die Lage der Insel dienten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_migration_exodus','Migration and refugee pressures',NULL,NULL,NULL,ARRAY['AMERICAS-CUBA','AMERICAS-USA'],false,103,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_military_coercion','Military coercion and regime-change threat','Militärische Nötigung und Drohung eines Regimewechsels','The military dimension of US pressure on Cuba: naval and air deployments in the Caribbean, reconnaissance activity, the Guantánamo Bay base and contacts across it, US debate over authorisation for the use of force, and armed incidents around the island.','Die militärische Dimension des US-Drucks auf Kuba: Marine- und Luftverlegungen in der Karibik, Aufklärungstätigkeit, der Stützpunkt Guantánamo Bay und die Kontakte über ihn hinweg, die US-Debatte über eine Ermächtigung zum Einsatz von Gewalt sowie bewaffnete Zwischenfälle rund um die Insel.',ARRAY['AMERICAS-CUBA'],true,107,'This window covers a carrier deployment to the Caribbean, increased surveillance flights off the Cuban coast, a rare meeting between the US Southern Command chief and Cuban officers at the edge of Guantánamo Bay, a Defense Secretary visit to the base, Senate votes on war powers, and a fatal exchange involving an armed group on a US-registered speedboat.','Dieser Zeitraum umfasst die Verlegung eines Flugzeugträgers in die Karibik, verstärkte Aufklärungsflüge vor der kubanischen Küste, ein seltenes Treffen des Chefs des US-Südkommandos mit kubanischen Offizieren am Rand von Guantánamo Bay, einen Besuch des Verteidigungsministers auf dem Stützpunkt, Senatsabstimmungen über Kriegsvollmachten sowie einen tödlichen Zwischenfall mit einer bewaffneten Gruppe auf einem in den USA registrierten Schnellboot.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_regime_survival','Regime legitimacy and internal control','Legitimität des Regimes und innere Kontrolle','The Cuban government''s internal position: the Communist Party and state leadership, succession, treatment of dissent and political prisoners, protest and policing, and the scope and pace of economic reform.','Die innere Lage der kubanischen Regierung: die Kommunistische Partei und die Staatsführung, die Nachfolge, der Umgang mit Dissens und politischen Gefangenen, Proteste und Polizeieinsätze sowie Umfang und Tempo der Wirtschaftsreformen.',ARRAY['AMERICAS-CUBA'],true,104,'During this window the government announced its largest economic reform package since 1959, released more than two thousand prisoners, and faced rare street protests over blackouts that ended in arrests. Reporting also covers speculation about who follows the current leadership and the position of the private sector.','In diesem Zeitraum kündigte die Regierung ihr größtes Wirtschaftsreformpaket seit 1959 an, entließ mehr als zweitausend Gefangene und sah sich seltenen Straßenprotesten gegen Stromausfälle gegenüber, die mit Verhaftungen endeten. Berichtet wird auch über Spekulationen zur Nachfolge der Führung und über die Lage des Privatsektors.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_theater','Cuba under maximum pressure','Kuba unter Maximaldruck','The confrontation between the United States and Cuba, comprising the US sanctions and blockade instruments applied to the island, the energy and humanitarian crisis on it, the outside states supplying it, the threat of US military action, and the Cuban government''s internal position.','Die Konfrontation zwischen den Vereinigten Staaten und Kuba: die US-Sanktions- und Blockadeinstrumente gegen die Insel, die dortige Energie- und humanitäre Krise, die Staaten, die sie beliefern, die Drohung mit US-Militäraktionen und die innere Lage der kubanischen Regierung.',ARRAY['AMERICAS-CUBA','AMERICAS-USA'],true,NULL,'Coverage in this window is dominated by a US campaign to cut off Cuba''s fuel imports, the island-wide power failures and shortages that followed, and the resulting contest over supply between Washington and Havana''s outside partners. Alongside it run an escalating US military signal in the Caribbean and a legal campaign against the Cuban leadership.','Die Berichterstattung in diesem Zeitraum wird von einer US-Kampagne zur Unterbindung kubanischer Treibstoffimporte bestimmt, von den darauf folgenden landesweiten Stromausfällen und Engpässen sowie vom Ringen um Nachschub zwischen Washington und Havannas äußeren Partnern. Daneben laufen ein eskalierendes US-Militärsignal in der Karibik und ein juristisches Vorgehen gegen die kubanische Führung.','theater',ARRAY['cuba_embargo_sanctions','cuba_energy_collapse','cuba_external_lifelines','cuba_military_coercion','cuba_regime_survival'],'{}','regional','{"type": "Point", "coordinates": [-82.4, 23.1]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_intervention_forces','MONUSCO, AU and regional military deployments',NULL,NULL,NULL,ARRAY['AFRICA-DRC','AFRICA-RWANDA','AFRICA-UGANDA','AFRICA-BURUNDI'],false,85,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_minerals_competition','Cobalt and coltan extraction and supply competition','Kobalt- und Coltanabbau und Wettbewerb um Lieferketten','The Democratic Republic of the Congo holds the world''s largest cobalt reserves and a significant share of its coltan, tantalum and copper. Chinese companies built much of the existing refining and processing base; American-backed buyers have more recently acquired producers and sought stakes tied to a minerals arrangement with Kinshasa. Some of the deposits concerned lie in territory held by armed groups, and the state has used export controls to influence prices.','Die Demokratische Republik Kongo verfügt über die weltweit größten Kobaltreserven sowie über bedeutende Anteile an Coltan, Tantal und Kupfer. Chinesische Unternehmen bauten einen Großteil der bestehenden Raffinerie- und Verarbeitungsbasis auf; zuletzt erwarben US-gestützte Käufer Produzenten und strebten Beteiligungen im Rahmen einer Rohstoffvereinbarung mit Kinshasa an. Ein Teil der betroffenen Vorkommen liegt in Gebieten bewaffneter Gruppen, und der Staat nutzte Exportkontrollen, um Preise zu beeinflussen.',ARRAY['AFRICA-DRC'],true,84,'Two strands run together and are not separable in coverage: the contest between American and Chinese buyers for Congolese assets, and the human and environmental record of the extraction itself.','Zwei Stränge laufen zusammen und sind in der Berichterstattung nicht zu trennen: der Wettbewerb amerikanischer und chinesischer Käufer um kongolesische Werte und die menschliche und ökologische Bilanz der Förderung selbst.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_peace_process','Mediation and sanctions over eastern Congo','Vermittlung und Sanktionen im Ostkongo-Konflikt','Efforts to end the fighting in eastern Congo run through several external tracks at once: agreements associated with Washington, talks in Doha and Switzerland, a signed ceasefire-monitoring mechanism, and the United Nations mission that is being reconfigured to support it. Alongside them runs an enforcement track of financial designations and travel restrictions aimed at Rwandan military figures and at Congolese political figures accused of supporting the rebellion.','Die Bemühungen, die Kämpfe im Osten Kongos zu beenden, laufen über mehrere externe Stränge zugleich: mit Washington verbundene Vereinbarungen, Gespräche in Doha und in der Schweiz, ein unterzeichneter Mechanismus zur Waffenstillstandsüberwachung und die Mission der Vereinten Nationen, die darauf ausgerichtet wird. Daneben verläuft ein Durchsetzungsstrang aus Finanzlistungen und Reisebeschränkungen gegen ruandische Militärs und gegen kongolesische Politiker, denen Unterstützung des Aufstands vorgeworfen wird.',ARRAY['AFRICA-DRC'],true,83,'The largest single cluster here is the designation of the Rwandan army and of former president Joseph Kabila; the accords themselves generate far less coverage than the sanctions used to enforce them.','Das größte einzelne Cluster ist die Listung der ruandischen Armee und des früheren Präsidenten Joseph Kabila; die Abkommen selbst erzeugen deutlich weniger Berichterstattung als die Sanktionen zu ihrer Durchsetzung.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('east_china_sea_claims','East China Sea overlapping continental shelf claims',NULL,NULL,NULL,ARRAY['ASIA-JAPAN','ASIA-CHINA','ASIA-SOUTHKOREA'],false,69,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eastern_congo_armed_groups','Armed group proliferation and territorial control',NULL,NULL,NULL,ARRAY['AFRICA-DRC','AFRICA-RWANDA','AFRICA-UGANDA','AFRICA-BURUNDI'],false,82,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('essequibo_dispute','Essequibo territorial dispute with Guyana','Territorialstreit um Essequibo mit Guyana','The territorial dispute between Venezuela and Guyana over the Essequibo region (Guayana Esequiba), including proceedings before the International Court of Justice and the offshore Stabroek oil block.','Der Territorialstreit zwischen Venezuela und Guyana um die Region Essequibo (Guayana Esequiba), einschließlich der Verfahren vor dem Internationalen Gerichtshof und des Offshore-Ölblocks Stabroek.',ARRAY['AMERICAS-VENEZUELA','AMERICAS-ANDEAN','AMERICAS-CARIBBEAN'],true,101,'Venezuela claims the Essequibo region, roughly two-thirds of Guyana''s territory, on the basis of a boundary settlement it regards as invalid. The dispute gained weight after major offshore oil discoveries in the adjacent Stabroek block turned Guyana into a significant producer. Guyana has brought the matter before the International Court of Justice; Venezuela contests the court''s jurisdiction and argues for direct negotiation. Coverage volume is low and episodic, spiking around hearings, but the combination of contested territory and offshore reserves keeps the escalation potential high.','Venezuela beansprucht die Region Essequibo -- etwa zwei Drittel des Staatsgebiets von Guyana -- unter Berufung auf eine Grenzregelung, die es als ungültig ansieht. Der Streit gewann an Gewicht, nachdem große Offshore-Ölfunde im angrenzenden Stabroek-Block Guyana zu einem bedeutenden Förderland gemacht hatten. Guyana rief den Internationalen Gerichtshof an; Venezuela bestreitet dessen Zuständigkeit und fordert direkte Verhandlungen. Das Berichterstattungsvolumen ist gering und episodisch mit Spitzen um Anhörungen, doch die Kombination aus umstrittenem Gebiet und Offshore-Reserven hält das Eskalationspotenzial hoch.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_amhara_conflict','Amhara insurgency and border tensions',NULL,NULL,NULL,ARRAY['AFRICA-ETHIOPIA','AFRICA-ERITREA','NON-STATE-OROMIA-LIBERATION-FRONT'],false,75,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_regional_confrontation','Ethiopia''s confrontation with its neighbours','Äthiopiens Konfrontation mit seinen Nachbarn','Ethiopia faces simultaneous disputes on several fronts: the unravelling of the Pretoria settlement that ended the Tigray war, accusations of Eritrean troop movements across the northern border, a long-running disagreement with Egypt over control of the Nile dam, and Addis Ababa''s stated pursuit of sovereign access to the sea.','Äthiopien steht gleichzeitig an mehreren Fronten in Konflikten: dem Zerfall des Abkommens von Pretoria, das den Tigray-Krieg beendete, Vorwürfen eritreischer Truppenbewegungen über die Nordgrenze, einer langjährigen Auseinandersetzung mit Ägypten über die Kontrolle des Nilstaudamms und dem erklärten Streben Addis Abebas nach einem souveränen Zugang zum Meer.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT'],true,75,'Tigray and Eritrea are one fused story in the 2026 record, not two; the Egyptian dimension has shifted from water alone to regional alignment.','Tigray und Eritrea sind im Material von 2026 eine zusammenhängende Geschichte, nicht zwei; die ägyptische Dimension hat sich vom reinen Wasserstreit zur regionalen Bündnispolitik verlagert.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_somaliland_access','Ethiopian sea access and Red Sea port competition',NULL,NULL,NULL,ARRAY['AFRICA-ETHIOPIA','AFRICA-SOMALIA','MIDEAST-EGYPT','AFRICA-DJIBOUTI','AFRICA-ERITREA'],false,77,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_budget_sovereignty','EU budget, own resources and regulatory sovereignty','EU-Haushalt, Eigenmittel und regulatorische Souveränität','The dispute over the European Union''s budget and the reach of its regulation into member-state competences. It covers the multiannual financial framework and the Commission''s proposals for new own resources and taxes, the conditionality tying disbursement to rule-of-law compliance, the reform of the Common Agricultural Policy and cohesion funds, and the pushback against Green Deal measures such as the combustion-engine phase-out and permitting rules. The friction runs between Brussels and national capitals and among net contributors and recipients.','Die Auseinandersetzung um den Haushalt der Europäischen Union und die Reichweite ihrer Regulierung in die Zuständigkeiten der Mitgliedstaaten. Sie umfasst den mehrjährigen Finanzrahmen und die Vorschläge der Kommission für neue Eigenmittel und Abgaben, die Konditionalität, die Auszahlungen an die Einhaltung der Rechtsstaatlichkeit bindet, die Reform der Gemeinsamen Agrarpolitik und der Kohäsionsfonds sowie den Widerstand gegen Maßnahmen des Green Deal wie das Aus für den Verbrennungsmotor und Genehmigungsregeln. Die Friktion verläuft zwischen Brüssel und den nationalen Hauptstädten sowie zwischen Nettozahlern und Empfängern.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD'],true,35,'The European Union''s budget has become a proxy for a larger argument over how much money and authority should sit in Brussels. Negotiations over the next multiannual financial framework pit net contributors against recipients, while the Commission''s push for new own resources and EU-level taxes to avoid cuts meets resistance in national capitals. Layered onto it are the conditionality that ties funds to rule-of-law compliance, the contested reform of the Common Agricultural Policy and cohesion funds, and a backlash against Green Deal regulation, from the combustion-engine phase-out to permitting and reporting rules. Coverage divides between outlets that frame stronger central financing and regulation as necessary for a capable Union and those that frame it as overreach into national competences and taxpayers'' money; the agricultural and industrial dimensions bring farmers'' and business lobbies into the same divide.','Der Haushalt der Europäischen Union ist zum Stellvertreter einer größeren Auseinandersetzung darüber geworden, wie viel Geld und Autorität in Brüssel liegen sollen. Die Verhandlungen über den nächsten mehrjährigen Finanzrahmen stellen Nettozahler gegen Empfänger, während der Vorstoß der Kommission für neue Eigenmittel und Abgaben auf EU-Ebene, um Kürzungen zu vermeiden, in den nationalen Hauptstädten auf Widerstand stößt. Hinzu kommen die Konditionalität, die Mittel an die Einhaltung der Rechtsstaatlichkeit bindet, die umstrittene Reform der Gemeinsamen Agrarpolitik und der Kohäsionsfonds sowie ein Widerstand gegen die Green-Deal-Regulierung, vom Aus für den Verbrennungsmotor bis zu Genehmigungs- und Berichtspflichten. Die Berichterstattung teilt sich zwischen Medien, die eine stärkere zentrale Finanzierung und Regulierung als notwendig für eine handlungsfähige Union deuten, und solchen, die darin einen Übergriff in nationale Zuständigkeiten und in Steuergelder sehen; die agrar- und industriepolitische Dimension bringt Bauern- und Wirtschaftsverbände in dieselbe Spaltung.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_cohesion_theater','European political fragmentation','Politische Fragmentierung Europas','The contest over the European Union''s internal cohesion and the balance of authority between its institutions and its member states. It runs along several axes: rule-of-law and budget-conditionality disputes between Brussels and national governments; the division over migration and asylum policy; the realignment of Europe''s political right and the debate over cooperation with national-conservative parties; and domestic polarisation within Germany, France and Hungary. The friction is internal to the Union, distinct from its disputes with the United States, with Russia, or over Ukraine, which are covered in separate theaters.','Der Streit um den inneren Zusammenhalt der Europäischen Union und das Kräfteverhältnis zwischen ihren Institutionen und ihren Mitgliedstaaten. Er verläuft entlang mehrerer Achsen: Konflikte um Rechtsstaatlichkeit und die Konditionalität des Haushalts zwischen Brüssel und den nationalen Regierungen; die Spaltung über Migrations- und Asylpolitik; die Neuordnung der europäischen Rechten und die Debatte über die Zusammenarbeit mit nationalkonservativen Parteien; sowie die innenpolitische Polarisierung in Deutschland, Frankreich und Ungarn. Die Friktion ist unionsintern und damit getrennt von den Auseinandersetzungen mit den Vereinigten Staaten, mit Russland oder um die Ukraine, die in eigenen Theatern behandelt werden.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD','NON-STATE-EU'],true,9,'The European Union''s internal cohesion is contested on several fronts at once. Brussels and national governments clash over rule-of-law conditionality and the next multiannual budget; member states divide over migration and asylum, from Spain''s mass regularisation to Italy''s offshore processing in Albania to the delayed entry-exit border system; Europe''s political right is reordering itself, as the European People''s Party debates cooperation with the Conservatives and Reformists and Patriots for Europe groups and the long-standing "cordon sanitaire" is tested; and domestic politics polarise inside the largest member states, with the AfD in Germany, the Rassemblement National in France and a change of government in Hungary. Coverage is itself divided: national-conservative and sovereigntist outlets frame Brussels as overreaching and the exclusion of insurgent parties as anti-democratic, mainstream liberal outlets frame the same movements as a threat to the rule of law and EU unity, and Russian and Chinese state media amplify every rift as evidence of Western decline. The disputes are internal to the Union; its external frictions with Washington, Moscow and over Ukraine are treated elsewhere.','Der innere Zusammenhalt der Europäischen Union ist an mehreren Fronten zugleich umstritten. Brüssel und die nationalen Regierungen streiten über die Rechtsstaatlichkeits-Konditionalität und den nächsten mehrjährigen Haushalt; die Mitgliedstaaten sind in der Migrations- und Asylfrage gespalten, von Spaniens Massenregularisierung über Italiens ausgelagerte Verfahren in Albanien bis zum verzögerten Ein- und Ausreisesystem an den Grenzen; die europäische Rechte ordnet sich neu, während die Europäische Volkspartei über die Zusammenarbeit mit den Fraktionen der Konservativen und Reformer sowie der Patrioten für Europa debattiert und der langjährige „Cordon sanitaire" auf die Probe gestellt wird; und die Innenpolitik der größten Mitgliedstaaten polarisiert sich, mit der AfD in Deutschland, dem Rassemblement National in Frankreich und einem Regierungswechsel in Ungarn. Die Berichterstattung ist selbst geteilt: nationalkonservative und souveränistische Medien deuten Brüssel als übergriffig und den Ausschluss aufstrebender Parteien als undemokratisch, liberale Mainstream-Medien deuten dieselben Bewegungen als Gefahr für Rechtsstaat und EU-Einheit, und russische und chinesische Staatsmedien verstärken jeden Riss als Beleg westlichen Niedergangs. Die Konflikte sind unionsintern; die äußeren Friktionen mit Washington, Moskau und um die Ukraine werden andernorts behandelt.','theater',ARRAY['hungary_rule_of_law','eu_migration_burden_sharing','eu_budget_sovereignty','afd_and_german_polarisation','french_nationalist_challenge','eu_right_realignment'],'{}','global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_migration_burden_sharing','EU migration and asylum policy','Migrations- und Asylpolitik der EU','The division among EU member states and institutions over migration and asylum. It covers the implementation of the Pact on Migration and Asylum and its solidarity and burden-sharing rules, the contrast between restrictive measures and regularisation schemes across member states, the externalisation of asylum processing to third countries, the entry-exit and border systems, and disputes over returns, detention and the role of the courts. The friction is internal to the Union.','Die Spaltung zwischen EU-Mitgliedstaaten und Institutionen in der Migrations- und Asylpolitik. Sie umfasst die Umsetzung des Migrations- und Asylpakts mit seinen Solidaritäts- und Lastenteilungsregeln, den Gegensatz zwischen restriktiven Maßnahmen und Regularisierungsprogrammen in den Mitgliedstaaten, die Auslagerung von Asylverfahren in Drittstaaten, die Ein- und Ausreise- sowie Grenzsysteme und Streitfragen um Rückführungen, Inhaftierung und die Rolle der Gerichte. Die Friktion ist unionsintern.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD'],true,34,'Migration remains one of the most persistent lines of division inside the European Union. The Pact on Migration and Asylum and its solidarity mechanism set member states against one another over how much of the burden each must carry, while national approaches diverge sharply, from Spain''s mass regularisation of undocumented migrants to Italy''s offshore processing in Albania to tightened returns and border controls elsewhere. The rollout of the entry-exit border system, court rulings on detention and asylum, and the argument over externalisation to third countries add further friction between capitals, the Commission, the European Parliament and the judiciary. Coverage splits between outlets that treat generous or rights-based measures as legally required solidarity and those that treat restriction and externalisation as the necessary response to public pressure, with the European People''s Party and its critics openly at odds; each national episode is read through that divide.','Migration bleibt eine der beständigsten Trennlinien innerhalb der Europäischen Union. Der Migrations- und Asylpakt und sein Solidaritätsmechanismus stellen die Mitgliedstaaten gegeneinander in der Frage, wie viel Last jeder tragen muss, während die nationalen Ansätze weit auseinandergehen, von Spaniens Massenregularisierung von Migranten ohne Papiere über Italiens ausgelagerte Verfahren in Albanien bis zu verschärften Rückführungen und Grenzkontrollen andernorts. Die Einführung des Ein- und Ausreisesystems an den Grenzen, Gerichtsurteile zu Inhaftierung und Asyl sowie der Streit über die Auslagerung in Drittstaaten schaffen weitere Reibung zwischen den Hauptstädten, der Kommission, dem Europäischen Parlament und der Justiz. Die Berichterstattung teilt sich zwischen Medien, die großzügige oder rechtebasierte Maßnahmen als rechtlich gebotene Solidarität behandeln, und solchen, die Restriktion und Auslagerung als notwendige Antwort auf den öffentlichen Druck sehen, wobei die Europäische Volkspartei und ihre Kritiker offen im Streit liegen; jede nationale Episode wird durch diese Spaltung gelesen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_right_realignment','Realignment of Europe''s parliamentary right','Neuordnung der europäischen Rechten','The reordering of Europe''s political right and the debate over cooperation between mainstream and national-conservative parties. It covers the balance among the European Parliament''s groups, the European People''s Party (EPP), the European Conservatives and Reformists (ECR) and Patriots for Europe (PfE), the erosion of the "cordon sanitaire" by which centrist parties have declined to govern with national-populist parties, joint votes and coalitions that cross that line, and the cross-border coordination of sovereigntist movements. The friction is internal to European party politics.','Die Neuordnung der europäischen Rechten und die Debatte über die Zusammenarbeit zwischen Mainstream- und nationalkonservativen Parteien. Sie umfasst das Kräfteverhältnis zwischen den Fraktionen des Europäischen Parlaments, der Europäischen Volkspartei (EVP), den Europäischen Konservativen und Reformern (EKR) und den Patrioten für Europa (PfE), die Aufweichung des „Cordon sanitaire", mit dem zentristische Parteien eine Regierung mit nationalpopulistischen Parteien abgelehnt haben, gemeinsame Abstimmungen und Koalitionen über diese Linie hinweg sowie die grenzüberschreitende Koordinierung souveränistischer Bewegungen. Die Friktion ist innerhalb der europäischen Parteipolitik angesiedelt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD'],true,40,'Europe''s political right is realigning, and the question of who will cooperate with whom has become a defining fault line of Union politics. In the European Parliament the European People''s Party increasingly passes measures with the Conservatives and Reformists and the Patriots for Europe rather than with the centre-left, while national-conservative parties coordinate across borders and position for a larger share of power. Running beneath it is the "cordon sanitaire", the long-standing refusal of mainstream parties to govern with national-populist ones, which is being tested and in places abandoned. Coverage divides between outlets that frame the realignment as the belated normalisation of parties with millions of voters and a legitimate majority, and those that frame it as the mainstream right lending respectability to movements it once excluded and eroding a norm that protected liberal democracy; Russian and Chinese state media present the shift as the decline of the European centre. It is distinct from the domestic party contests in Germany, France and Hungary, which have their own nodes.','Die europäische Rechte ordnet sich neu, und die Frage, wer mit wem zusammenarbeitet, ist zu einer prägenden Bruchlinie der Unionspolitik geworden. Im Europäischen Parlament verabschiedet die Europäische Volkspartei zunehmend Maßnahmen mit den Konservativen und Reformern und den Patrioten für Europa statt mit der Mitte-Links-Seite, während sich nationalkonservative Parteien über Grenzen hinweg koordinieren und sich einen größeren Machtanteil sichern wollen. Darunter liegt der „Cordon sanitaire", die langjährige Weigerung der Mainstream-Parteien, mit nationalpopulistischen zu regieren, die nun auf die Probe gestellt und mancherorts aufgegeben wird. Die Berichterstattung teilt sich zwischen Medien, die die Neuordnung als überfällige Normalisierung von Parteien mit Millionen Wählern und legitimer Mehrheit deuten, und solchen, die darin sehen, wie die etablierte Rechte Bewegungen Ansehen verleiht, die sie einst ausschloss, und eine Norm aushöhlt, die die liberale Demokratie schützte; russische und chinesische Staatsmedien präsentieren den Wandel als Niedergang der europäischen Mitte. Sie ist von den nationalen Parteienkämpfen in Deutschland, Frankreich und Ungarn zu unterscheiden, die eigene Knoten haben.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_sovereignty_theater','European sovereignty movements',NULL,NULL,NULL,ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','NON-STATE-EU'],false,10,NULL,NULL,'theater',ARRAY['afd_and_german_polarisation','french_nationalist_challenge','post_brexit_realignment','italian_populist_government'],'{}','global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_defence_dependence','Defence burden-sharing and US security guarantees','Verteidigungslastenteilung und US-Sicherheitsgarantien','The transactional dispute over who pays for and who guarantees European security. Washington presses its European allies to raise defence spending toward higher NATO targets, threatens and moves to draw down American troops in Europe, and casts doubt over the credibility of the US security guarantee and nuclear umbrella. Europeans are caught between paying more to keep Washington engaged and preparing for an America that may no longer come to their defence.','Der transaktionale Streit darüber, wer die europäische Sicherheit bezahlt und garantiert. Washington drängt seine europäischen Verbündeten, die Verteidigungsausgaben auf höhere NATO-Ziele anzuheben, droht mit dem Abzug amerikanischer Truppen aus Europa und zieht die Glaubwürdigkeit der US-Sicherheitsgarantie und des nuklearen Schirms in Zweifel. Die Europäer stehen zwischen der Notwendigkeit, mehr zu zahlen, um Washington eingebunden zu halten, und der Vorbereitung auf ein Amerika, das ihnen womöglich nicht mehr zu Hilfe kommt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','NON-STATE-NATO'],true,31,'The transactional dispute at the heart of the alliance: who pays for and who guarantees European security. Washington presses its allies toward far higher NATO spending targets, threatens and begins to draw down American troops in Europe, and casts doubt over the credibility of the US security guarantee and nuclear umbrella. The result is an anxious Europe caught between paying more to keep America engaged and preparing for an ally that may no longer come to its defence. US conservative media frame it as overdue accountability for decades of European freeloading; Western and European mainstream media frame a fraying guarantee that leaves the continent dangerously exposed. (Its mirror image -- Europe''s own answer of rearmament and autonomy -- is tracked separately.)','Der transaktionale Streit im Kern des Bündnisses: wer die europäische Sicherheit bezahlt und wer sie garantiert. Washington drängt seine Verbündeten zu weit höheren NATO-Ausgabenzielen, droht mit dem Abzug amerikanischer Truppen aus Europa und beginnt damit, und zieht die Glaubwürdigkeit der US-Sicherheitsgarantie und des nuklearen Schirms in Zweifel. Das Ergebnis ist ein besorgtes Europa zwischen der Notwendigkeit, mehr zu zahlen, um Amerika eingebunden zu halten, und der Vorbereitung auf einen Verbündeten, der ihm womöglich nicht mehr zu Hilfe kommt. US-konservative Medien deuten dies als überfällige Rechenschaft für jahrzehntelanges europäisches Trittbrettfahren; westliche und europäische Mainstream-Medien als bröckelnde Garantie, die den Kontinent gefährlich entblößt.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_tech_sovereignty','Transatlantic tech regulation and digital sovereignty','Transatlantische Techregulierung und digitale Souveränität','The friction between European regulators and American technology power. The EU enforces the Digital Markets Act, Digital Services Act, GDPR and AI Act against US Big Tech through fines, antitrust probes and content rules; Washington pushes back in defence of its firms, threatening tariffs over "unfair" treatment; and Europe pursues digital sovereignty in parallel, weaning its cloud, software and defence data off American providers. It pits European rule-making and "sovereign cloud" ambitions against Silicon Valley''s dominance and US retaliation.','Die Reibung zwischen europäischen Regulierern und amerikanischer Technologiemacht. Die EU setzt den Digital Markets Act, den Digital Services Act, die DSGVO und den AI Act gegen die US-Techkonzerne durch — mit Bußgeldern, Kartellverfahren und Inhaltsregeln; Washington wehrt sich zur Verteidigung seiner Konzerne und droht mit Zöllen wegen „unfairer" Behandlung; und Europa verfolgt parallel die digitale Souveränität, indem es Cloud, Software und Verteidigungsdaten von amerikanischen Anbietern löst. Europäische Regelsetzung und „souveräne Cloud"-Ambitionen stehen gegen die Dominanz des Silicon Valley und US-Vergeltung.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC'],true,32,'The clash between European rule-making and American technological power. The EU wields the Digital Markets Act, Digital Services Act, GDPR and AI Act against US Big Tech through fines, antitrust probes and content and privacy rules; Washington pushes back in defence of its firms, threatening tariffs over what it calls discriminatory treatment; and Europe pursues digital sovereignty in parallel, trying to wean its cloud, software and even defence data off American providers. US conservative media frame the EU''s rules as protectionist harassment and censorship of American champions; European and Western mainstream media frame legitimate regulation and an overdue bid for digital sovereignty; and Russian and Chinese state media cast US tech dominance as a digital colonialism Europe is only now resisting.','Der Zusammenprall zwischen europäischer Regelsetzung und amerikanischer Technologiemacht. Die EU setzt den Digital Markets Act, den Digital Services Act, die DSGVO und den AI Act gegen die US-Techkonzerne ein -- mit Bußgeldern, Kartellverfahren sowie Inhalts- und Datenschutzregeln; Washington wehrt sich zur Verteidigung seiner Konzerne und droht mit Zöllen wegen angeblich diskriminierender Behandlung; und Europa verfolgt parallel die digitale Souveränität und versucht, Cloud, Software und selbst Verteidigungsdaten von amerikanischen Anbietern zu lösen. US-konservative Medien deuten die EU-Regeln als protektionistische Schikane und Zensur amerikanischer Konzerne; europäische und westliche Mainstream-Medien als legitime Regulierung und überfälliges Streben nach digitaler Souveränität; russische und chinesische Staatsmedien als digitalen Kolonialismus, dem sich Europa erst jetzt widersetzt.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_theater','Europe-US strategic tensions','Strategische Spannungen zwischen Europa und den USA','The widening rift between the United States and its European allies under a Washington that treats Europe more as a competitor than a partner. It runs along four axes: a tariff and trade confrontation; a dispute over defence burden-sharing and the credibility of the US security guarantee; Europe''s answering drive for strategic autonomy and rearmament; and a clash over technology regulation and digital sovereignty. Beneath them runs a deeper question of whether the transatlantic alliance that defined the post-war order still holds — a fracture Moscow and Beijing cover with schadenfreude.','Der wachsende Riss zwischen den USA und ihren europäischen Verbündeten unter einem Washington, das Europa eher als Konkurrenten denn als Partner behandelt. Er verläuft entlang vier Achsen: einer Zoll- und Handelskonfrontation; eines Streits über die Verteidigungslastenteilung und die Glaubwürdigkeit der US-Sicherheitsgarantie; Europas Gegenbewegung hin zu strategischer Autonomie und Aufrüstung; und eines Konflikts über Technologieregulierung und digitale Souveränität. Darunter liegt die tiefere Frage, ob das transatlantische Bündnis, das die Nachkriegsordnung prägte, noch trägt — ein Bruch, den Moskau und Peking mit Schadenfreude begleiten.',ARRAY['NON-STATE-EU','AMERICAS-USA','ASIA-CHINA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','NON-STATE-NATO'],true,8,'The transatlantic alliance that anchored the post-war order is under its sharpest strain in generations, as a Washington that treats Europe more as a competitor than a partner presses on four fronts at once: a tariff and trade war, blunt demands over defence burden-sharing paired with doubt over the US security guarantee, a confrontation over technology regulation, and -- provoked by all three -- Europe''s own drive for strategic autonomy. The through-line is a continent forced to ask whether it can still rely on America, and what it must build if it cannot. Coverage splits three ways: US conservative media frame the pressure as overdue discipline of a freeloading, over-regulating Europe; Western and European mainstream outlets frame it as the rupture of a vital partnership that Europe must answer with unity, autonomy and digital sovereignty; and Russian and Chinese state media read every quarrel as proof of Western hypocrisy and the arrival of a multipolar world.','Das transatlantische Bündnis, das die Nachkriegsordnung verankerte, steht unter der schärfsten Belastung seit Generationen, da ein Washington, das Europa eher als Konkurrenten denn als Partner behandelt, an vier Fronten zugleich drängt: einem Zoll- und Handelskrieg, harschen Forderungen zur Verteidigungslastenteilung bei gleichzeitigem Zweifel an der US-Sicherheitsgarantie, einer Konfrontation über Technologieregulierung und -- durch all das ausgelöst -- Europas eigenem Streben nach strategischer Autonomie. Der rote Faden ist ein Kontinent, der sich fragen muss, ob er sich noch auf Amerika verlassen kann und was er aufbauen muss, falls nicht. Die Berichterstattung teilt sich dreifach: US-konservative Medien deuten den Druck als überfällige Disziplinierung eines trittbrettfahrenden, überregulierenden Europas; westliche und europäische Mainstream-Medien als Bruch einer lebenswichtigen Partnerschaft, dem Europa mit Einigkeit, Autonomie und digitaler Souveränität begegnen müsse; russische und chinesische Staatsmedien lesen jeden Streit als Beweis westlicher Heuchelei und Anbruch einer multipolaren Welt.','theater',ARRAY['transatlantic_trade','europe_us_defence_dependence','eu_strategic_autonomy','europe_us_tech_sovereignty'],ARRAY['lane_transatlantic','lane_us_europe_lng','lane_us_europe_energy'],'global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_strategic_autonomy','European strategic autonomy and defence self-reliance','Europäische strategische Autonomie und verteidigungspolitische Eigenständigkeit','Europe''s drive to act as an independent strategic pole — to build the capacity to defend itself and decide for itself with less reliance on the United States. It spans the push for a European defence union, an "EU army" and a European nuclear deterrent, rearmament initiatives such as ReArm Europe and Readiness 2030, industrial sovereignty, and de-risking from dependence on both Washington and Beijing. The open question is whether Europe can and should emancipate itself, or whether strategic autonomy is an illusion without American power.','Europas Bestreben, als eigenständiger strategischer Pol zu handeln — die Fähigkeit aufzubauen, sich selbst zu verteidigen und selbst zu entscheiden, mit geringerer Abhängigkeit von den USA. Es umfasst den Vorstoß zu einer europäischen Verteidigungsunion, einer „EU-Armee" und einer europäischen nuklearen Abschreckung, Aufrüstungsinitiativen wie ReArm Europe und Readiness 2030, industrielle Souveränität und die Verringerung der Abhängigkeit von Washington wie von Peking. Offen ist, ob Europa sich emanzipieren kann und soll oder ob strategische Autonomie ohne amerikanische Macht eine Illusion bleibt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','ASIA-CHINA'],true,30,'Europe''s answer to the US retreat: the drive to act as an independent strategic pole able to defend itself and decide for itself. It spans the push for a European defence union, an "EU army" and even a European nuclear deterrent, rearmament initiatives such as ReArm Europe and Readiness 2030, industrial sovereignty and de-risking from dependence on both Washington and Beijing. The open question -- can Europe, and will it dare? -- divides coverage: US conservative and Atlanticist-hawk media dismiss strategic autonomy as a costly fantasy that duplicates and weakens NATO; Western and European mainstream media frame a historic awakening the continent must see through; and Russian and Chinese state media welcome it as the fracturing of US hegemony and the arrival of a multipolar order.','Europas Antwort auf den US-Rückzug: das Streben, als eigenständiger strategischer Pol zu handeln, der sich selbst verteidigen und selbst entscheiden kann. Es umfasst den Vorstoß zu einer europäischen Verteidigungsunion, einer „EU-Armee" und sogar einer europäischen nuklearen Abschreckung, Aufrüstungsinitiativen wie ReArm Europe und Readiness 2030, industrielle Souveränität und die Verringerung der Abhängigkeit von Washington wie von Peking. Die offene Frage -- kann Europa, und wird es wagen? -- spaltet die Berichterstattung: US-konservative und atlantisch-restriktive Medien tun die strategische Autonomie als teure Fantasie ab, die die NATO dupliziere und schwäche; westliche und europäische Mainstream-Medien sehen ein historisches Erwachen; russische und chinesische Staatsmedien begrüßen sie als Zerfall der US-Hegemonie.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('french_nationalist_challenge','French political instability and the national-populist challenge','Politische Instabilität Frankreichs und die nationalpopulistische Herausforderung','The instability of French national politics and the contest around the Rassemblement National (RN). It covers the sequence of minority governments, no-confidence votes and budget standoffs, the RN''s electoral advance and the legal cases affecting Marine Le Pen and the rise of Jordan Bardella, and the wider argument over sovereignty, the presidential system and the 2027 succession. The friction is internal to French politics.','Die Instabilität der französischen Innenpolitik und der Streit um das Rassemblement National (RN). Er umfasst die Abfolge von Minderheitsregierungen, Misstrauensvoten und Haushaltsblockaden, den Wahlerfolg des RN sowie die Gerichtsverfahren um Marine Le Pen und den Aufstieg von Jordan Bardella und die umfassendere Auseinandersetzung über Souveränität, das präsidiale System und die Nachfolge 2027. Die Friktion ist innenpolitisch französisch.',ARRAY['EUROPE-FRANCE'],true,37,'French politics has entered a phase of chronic instability, with successive minority governments surviving or falling on no-confidence votes and unable to pass budgets through a hung National Assembly. Running through it is the advance of the Rassemblement National: its polling lead, the judicial cases affecting Marine Le Pen and her eligibility, and the rise of Jordan Bardella as the party positions for the 2027 presidential election. Coverage divides between outlets that present the party''s progress and Le Pen''s legal troubles as the establishment and the courts obstructing a movement with genuine popular support, and those that present the same party as a challenge to republican norms and the governing gridlock as the cost of its rise; Russian state media frame French turmoil as evidence of a failing model. The dispute is internal to France; French positions in transatlantic and Ukraine matters are covered in the relevant theaters.','Die französische Politik ist in eine Phase chronischer Instabilität eingetreten, in der aufeinanderfolgende Minderheitsregierungen an Misstrauensvoten überleben oder scheitern und in einer Nationalversammlung ohne Mehrheit keine Haushalte verabschieden können. Sie wird durchzogen vom Vormarsch des Rassemblement National: seinem Vorsprung in Umfragen, den Gerichtsverfahren um Marine Le Pen und ihre Wählbarkeit sowie dem Aufstieg von Jordan Bardella, während sich die Partei für die Präsidentschaftswahl 2027 in Stellung bringt. Die Berichterstattung teilt sich zwischen Medien, die den Erfolg der Partei und Le Pens juristische Probleme als Behinderung einer Bewegung mit echtem Rückhalt durch Establishment und Justiz darstellen, und solchen, die dieselbe Partei als Herausforderung republikanischer Normen und den Regierungsstillstand als Preis ihres Aufstiegs deuten; russische Staatsmedien rahmen die französischen Turbulenzen als Beleg eines scheiternden Modells. Der Streit ist innerfranzösisch; französische Positionen in transatlantischen und Ukraine-Fragen werden in den jeweiligen Theatern behandelt.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
