  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('georgia_geopolitical_drift','Georgia''s external orientation and internal disputes','Georgiens außenpolitische Ausrichtung und innere Auseinandersetzungen','Disputes over Georgia''s external orientation and domestic politics. At issue are the country''s EU accession candidacy; a law requiring registration of organisations that receive foreign funding, and disagreement over its scope and comparability to laws in Russia and in Western states; contested election results and protests; and the status of Abkhazia and South Ossetia, which separated from Georgian control in conflicts in the early 1990s and the 2008 Russia-Georgia war and are backed by Russia. These issues divide the governing party, the opposition and EU institutions over the country''s direction.','Auseinandersetzungen über Georgiens außenpolitische Ausrichtung und Innenpolitik. Umstritten sind der EU-Beitrittskandidatenstatus des Landes; ein Gesetz, das die Registrierung von Organisationen mit ausländischer Finanzierung verlangt, sowie Meinungsverschiedenheiten über dessen Reichweite und Vergleichbarkeit mit Gesetzen in Russland und in westlichen Staaten; umstrittene Wahlergebnisse und Proteste; und der Status von Abchasien und Südossetien, die sich in Konflikten in den frühen 1990er Jahren und im russisch-georgischen Krieg 2008 der georgischen Kontrolle entzogen und von Russland unterstützt werden. Diese Fragen spalten die Regierungspartei, die Opposition und EU-Institutionen über die Richtung des Landes.',ARRAY['ASIA-CAUCASUS'],true,43,'Georgia, a state on Russia''s southern border, is the subject of recurring disputes over its external orientation and internal politics. It holds EU candidate status, and disagreements over progress toward accession are central. A law requiring organisations that receive foreign funding to register drew large protests and criticism from EU institutions; the government compares it to transparency laws in Western states, while opponents compare it to Russian legislation. Election results and the conduct of votes have been contested between the governing party and the opposition, at times accompanied by street protests and police response. Abkhazia and South Ossetia, which separated from Georgian control in conflicts in the early 1990s and again during the 2008 Russia-Georgia war, remain outside Tbilisi''s authority and are backed by Russia. The node is maintained as a standing placeholder for a region where tensions can escalate quickly.','Georgien, ein Staat an Russlands Südgrenze, ist Gegenstand wiederkehrender Auseinandersetzungen über seine außenpolitische Ausrichtung und seine Innenpolitik. Es besitzt den EU-Kandidatenstatus, und Meinungsverschiedenheiten über die Fortschritte beim Beitritt stehen im Zentrum. Ein Gesetz, das Organisationen mit ausländischer Finanzierung zur Registrierung verpflichtet, löste große Proteste und Kritik von EU-Institutionen aus; die Regierung vergleicht es mit Transparenzgesetzen in westlichen Staaten, während Gegner es mit russischer Gesetzgebung vergleichen. Wahlergebnisse und der Ablauf von Abstimmungen wurden zwischen der Regierungspartei und der Opposition bestritten, zeitweise begleitet von Straßenprotesten und Polizeieinsätzen. Abchasien und Südossetien, die sich in Konflikten in den frühen 1990er Jahren und erneut während des russisch-georgischen Krieges 2008 der georgischen Kontrolle entzogen, bleiben außerhalb der Autorität Tiflis'' und werden von Russland unterstützt. Der Knoten wird als dauerhafter Platzhalter für eine Region geführt, in der Spannungen schnell eskalieren können.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('great_lakes_theater','Eastern Congo conflict and mineral competition','Konflikt in Ostkongo und Konkurrenz um Rohstoffe','The eastern provinces of the Democratic Republic of the Congo have been contested for three decades by armed groups, the Congolese state and neighbouring governments. The current phase combines the M23 insurgency and its disputed external backing, an externally brokered mediation and sanctions track, and competition over the cobalt, coltan and copper deposits that sit in and around the same territory. The United States, China, Rwanda, Uganda, Burundi and the United Nations mission are all engaged.','Die östlichen Provinzen der Demokratischen Republik Kongo sind seit drei Jahrzehnten zwischen bewaffneten Gruppen, dem kongolesischen Staat und den Nachbarregierungen umkämpft. Die gegenwärtige Phase verbindet den M23-Aufstand und dessen umstrittene Unterstützung von außen, einen extern vermittelten Verhandlungs- und Sanktionsstrang sowie den Wettbewerb um die Kobalt-, Coltan- und Kupfervorkommen, die in und um dasselbe Gebiet liegen. Die Vereinigten Staaten, China, Ruanda, Uganda, Burundi und die Mission der Vereinten Nationen sind daran beteiligt.',ARRAY['AFRICA-DRC','AMERICAS-USA'],true,23,'Coverage in the first half of 2026 divides sharply: the M23 war de-escalated through the period while the mediation and sanctions track kept producing, and an Ebola outbreak came to dominate Congolese coverage overall without being part of this dispute.','Die Berichterstattung im ersten Halbjahr 2026 teilt sich deutlich: Der M23-Krieg deeskalierte im Verlauf, während der Vermittlungs- und Sanktionsstrang weiter Nachrichten produzierte; zugleich beherrschte ein Ebola-Ausbruch die Kongo-Berichterstattung insgesamt, ohne Teil dieses Konflikts zu sein.','theater',ARRAY['m23_conflict','drc_peace_process','drc_minerals_competition'],ARRAY['katanga_copper_belt','bisie_tin_mine'],'regional','{"type": "Point", "coordinates": [29.2, -1.68]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('greenland_control','Greenland strategic control and Arctic geopolitics','Strategische Kontrolle über Grönland und Arktis-Geopolitik','The confrontation over Greenland after Washington escalated a long-standing interest into an open push for control, backed by tariff threats against objecting European allies. The island''s Arctic bases, rare-earth minerals and opening sea lanes make it strategically pivotal, but the fight runs along a transatlantic axis — the United States against Denmark, the EU and NATO partners — with Greenlanders'' own claim to self-determination cutting across both. Framings range from a US strategic claim to a European defense of sovereignty to a pro-Kremlin reading that treats the episode as proof of Western imperialism and hypocrisy.','Die Konfrontation um Grönland, nachdem Washington ein langjähriges Interesse zu einem offenen Vorstoß zur Kontrolle eskaliert hat, untermauert durch Zolldrohungen gegen widersprechende europäische Verbündete. Die arktischen Stützpunkte der Insel, ihre Seltenen Erden und die sich öffnenden Seewege machen sie strategisch entscheidend, doch der Konflikt verläuft transatlantisch — die USA gegen Dänemark, die EU und NATO-Partner — mit dem grönländischen Anspruch auf Selbstbestimmung quer dazu. Die Deutungen reichen von einem strategischen US-Anspruch über eine europäische Verteidigung der Souveränität bis zu einer pro-Kreml-Lesart, die die Episode als Beweis westlicher Heuchelei und Imperialismus behandelt.',ARRAY['EUROPE-GREENLAND','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU','NON-STATE-NATO','EUROPE-RUSSIA'],true,109,'Greenland has become the sharpest flashpoint of Arctic geopolitics after Washington escalated a long-standing interest into an open push for control, backed by tariff threats against European allies who object. The island''s value is triple — Arctic military basing at Pituffik, rare-earth minerals, and the sea lanes opening off its coast — but the confrontation runs along a transatlantic axis: the United States against Denmark, the EU and NATO partners, with Greenlanders'' own voice for self-determination cutting across both. Four readings compete: a US strategic, manifest-destiny claim that is thinly held; a European defense of Danish sovereignty and international law; a Greenlandic insistence that only Greenlanders decide; and a pro-Kremlin and Chinese framing that treats the episode not as support for a US takeover but as proof of Western imperialism and hypocrisy, amplifying the rift it opens.','Grönland ist zum schärfsten Brennpunkt der arktischen Geopolitik geworden, nachdem Washington ein langjähriges Interesse zu einem offenen Vorstoß zur Kontrolle eskaliert hat, untermauert durch Zolldrohungen gegen widersprechende europäische Verbündete. Der Wert der Insel ist dreifach — arktische Militärstützpunkte in Pituffik, Seltene Erden und die vor ihrer Küste entstehenden Seewege — doch die Konfrontation verläuft transatlantisch: die USA gegen Dänemark, die EU und NATO-Partner, mit der grönländischen Stimme für Selbstbestimmung quer dazu. Vier Lesarten konkurrieren: ein dünn vertretener strategischer US-Machtanspruch; eine europäische Verteidigung dänischer Souveränität und des Völkerrechts; ein grönländisches Beharren darauf, dass nur Grönländer entscheiden; und eine pro-Kreml- und chinesische Rahmung, die die Episode nicht als Zustimmung zu einer US-Übernahme deutet, sondern als Beweis westlicher Heuchelei und Imperialismus.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
