INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('haiti_gang_control','Gang control of Port-au-Prince','Bandenkontrolle ueber Port-au-Prince','Armed gangs control most of the capital and are expanding into other departments: killings, kidnapping, sexual violence and mass displacement.','Bewaffnete Banden kontrollieren den Grossteil der Hauptstadt und dehnen sich in weitere Departements aus: Toetungen, Entfuehrungen, sexuelle Gewalt und Massenvertreibung.',ARRAY['AMERICAS-CARIBBEAN'],true,NULL,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CARIBBEAN')
