INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('haiti_international_mission','International stabilisation mission politics','Politik der internationalen Stabilisierungsmission','UN Security Council wrangling, mission funding and force generation, and the politics of who stabilises Haiti and on what mandate.','Ringen im UN-Sicherheitsrat, Missionsfinanzierung und Truppenstellung sowie die Politik darum, wer Haiti mit welchem Mandat stabilisiert.',ARRAY['AMERICAS-CARIBBEAN','AMERICAS-USA'],true,NULL,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CARIBBEAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('haiti_theater','Haiti state collapse','Haitis Staatszerfall','Gang control of the capital, mass displacement and the politics of international stabilisation.','Bandenherrschaft ueber die Hauptstadt, Massenvertreibung und die Politik internationaler Stabilisierung.',ARRAY['AMERICAS-CARIBBEAN','AMERICAS-USA'],true,NULL,NULL,NULL,'theater',ARRAY['haiti_gang_control','haiti_international_mission'],'{}','regional','{"type": "Point", "coordinates": [-72.3, 18.5]}'::jsonb,'AMERICAS-CARIBBEAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('himalayan_strategic_competition','Himalayan strategic competition and infrastructure',NULL,NULL,NULL,ARRAY['ASIA-INDIA','ASIA-CHINA','ASIA-HIMALAYA'],false,67,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('horn_africa_theater','Horn of Africa realignment','Neuordnung am Horn von Afrika','The Horn of Africa is being reordered by overlapping disputes: the contested international status of Somaliland, an unresolved confrontation between Ethiopia and its northern and downstream neighbours, and the uneven reconstruction of the Somali state. Outside powers -- Israel, Turkey, Egypt, the Gulf states, the United States and China -- are all party to at least one of them.','Das Horn von Afrika wird durch mehrere ineinandergreifende Konflikte neu geordnet: den umstrittenen völkerrechtlichen Status Somalilands, eine ungelöste Konfrontation zwischen Äthiopien und seinen nördlichen wie flussabwärts gelegenen Nachbarn und den ungleichmäßigen Wiederaufbau des somalischen Staates. Auswärtige Mächte -- Israel, die Türkei, Ägypten, die Golfstaaten, die USA und China -- sind an mindestens einem davon beteiligt.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL','MIDEAST-EGYPT','MIDEAST-TURKEY','AMERICAS-USA'],true,21,'Coverage in 2026 is dominated by the recognition of Somaliland and the reaction to it, with a renewed war risk in northern Ethiopia and a fragile Somali state as the two other persistent strands.','Die Berichterstattung des Jahres 2026 wird von der Anerkennung Somalilands und den Reaktionen darauf bestimmt; das erneute Kriegsrisiko im Norden Äthiopiens und ein fragiler somalischer Staat sind die beiden weiteren durchgehenden Stränge.','theater',ARRAY['somaliland_recognition_contest','ethiopia_regional_confrontation','somalia_state_security'],ARRAY['bab_el_mandeb','gerd_dam'],'regional','{"type": "Point", "coordinates": [45.3, 2.05]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('houthi_strikes_on_israel','Houthi strikes on Israel',NULL,NULL,NULL,ARRAY['MIDEAST-YEMEN','MIDEAST-ISRAEL','MIDEAST-IRAN'],true,18,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('hungary_rule_of_law','Hungary, rule of law and the EU','Ungarn, Rechtsstaatlichkeit und die EU','The dispute over rule of law, EU funds and institutional power centred on Hungary. It spans the conditionality mechanism under which the European Commission has withheld cohesion and recovery money over concerns about judicial independence, media pluralism, public procurement and civil society, and the domestic contest over those same institutions following the change of government that ended Viktor Orban''s tenure. Recurring flashpoints include frozen EU funds, Article 7 proceedings, the constitutional and presidential order, and Hungary''s use of its vote in the European Council.','Die Auseinandersetzung um Rechtsstaatlichkeit, EU-Mittel und institutionelle Macht mit Schwerpunkt Ungarn. Sie umfasst den Konditionalitätsmechanismus, unter dem die Europäische Kommission Kohäsions- und Aufbaugelder wegen Bedenken zu richterlicher Unabhängigkeit, Medienvielfalt, öffentlicher Auftragsvergabe und Zivilgesellschaft zurückgehalten hat, sowie den innenpolitischen Streit um eben diese Institutionen nach dem Regierungswechsel, der die Amtszeit von Viktor Orban beendete. Wiederkehrende Brennpunkte sind eingefrorene EU-Mittel, Verfahren nach Artikel 7, die verfassungs- und präsidialrechtliche Ordnung sowie Ungarns Nutzung seiner Stimme im Europäischen Rat.',ARRAY['EUROPE-VISEGRAD','NON-STATE-EU'],true,32,'Hungary has been the sharpest test of the European Union''s rule-of-law tools. For years the Commission withheld cohesion and recovery funds under the conditionality mechanism, citing judicial independence, media pluralism, public procurement and the treatment of civil society and academia, while Budapest countered that Brussels was punishing a democratically elected government and infringing national sovereignty. The change of government that ended Viktor Orban''s tenure reopened the same questions from the inside, as the new administration moves against institutions, foundations and appointments inherited from the previous era and contests the presidency and constitutional order. Coverage divides between outlets that treat the conditionality fight as a necessary defence of shared European standards and those that read it, and the domestic reckoning that followed, as political score-settling; Russian state media frame the episode as proof of Brussels'' coercion of member states. Hungary''s separate use of its European Council vote on Ukraine is covered in the Ukraine theater.','Ungarn war der schärfste Test für die Rechtsstaatlichkeits-Instrumente der Europäischen Union. Jahrelang hielt die Kommission unter dem Konditionalitätsmechanismus Kohäsions- und Aufbaumittel zurück und verwies auf richterliche Unabhängigkeit, Medienvielfalt, öffentliche Auftragsvergabe sowie den Umgang mit Zivilgesellschaft und Wissenschaft, während Budapest entgegnete, Brüssel bestrafe eine demokratisch gewählte Regierung und verletze die nationale Souveränität. Der Regierungswechsel, der die Amtszeit von Viktor Orban beendete, öffnete dieselben Fragen von innen, als die neue Regierung gegen Institutionen, Stiftungen und Personalentscheidungen der Vorgängerära vorgeht und die Präsidentschaft sowie die Verfassungsordnung in Frage stellt. Die Berichterstattung teilt sich zwischen Medien, die den Konditionalitätsstreit als notwendige Verteidigung gemeinsamer europäischer Standards deuten, und solchen, die ihn und die folgende innenpolitische Abrechnung als politische Vergeltung lesen; russische Staatsmedien rahmen die Episode als Beleg für Brüssels Zwang gegenüber den Mitgliedstaaten. Ungarns gesonderte Nutzung seiner Stimme im Europäischen Rat zur Ukraine wird im Ukraine-Theater behandelt.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
