  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('india_pakistan_militancy','Cross-border militancy and proxy accusations','Grenzüberschreitende Militanz und Stellvertretervorwürfe','Militant attacks on Indian soil and the dispute over responsibility for them. It covers the groups India names -- Lashkar-e-Taiba, Jaish-e-Mohammed and associated figures such as Hafiz Saeed and Masood Azhar -- Indian investigations and designations, the 2025 Pahalgam attack and the Indian military operation conducted in response, and Pakistan''s rejection of the allegations. India states that the groups operate from Pakistani territory with official tolerance; Pakistan states that the allegations are unsubstantiated.','Militante Anschläge auf indischem Boden und der Streit über die Verantwortung dafür. Erfasst werden die von Indien benannten Gruppen -- Lashkar-e-Taiba, Jaish-e-Mohammed und Personen wie Hafiz Saeed und Masood Azhar --, indische Ermittlungen und Listungen, der Anschlag von Pahalgam 2025 und die daraufhin durchgeführte indische Militäroperation sowie Pakistans Zurückweisung der Vorwürfe. Indien erklärt, die Gruppen operierten mit offizieller Duldung von pakistanischem Gebiet aus; Pakistan erklärt, die Vorwürfe seien unbelegt.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN'],true,63,'This is the accusation layer of the India-Pakistan relationship, and it is asymmetric in coverage: Indian outlets report it heavily, Pakistani outlets rarely. Indian investigators have charge-sheeted figures including Hafiz Saeed over the Pahalgam attack and traced equipment and handlers across the border; New Delhi presses for international designations and for Pakistan''s return to the FATF list. Operation Sindoor, the military response to Pahalgam, is marked in Indian coverage as a precedent for striking back, and its anniversary generates recurring commentary. Pakistan''s foreign ministry says India has never presented evidence and describes the allegations as a narrative built for political use.','Dies ist die Vorwurfsebene des indisch-pakistanischen Verhältnisses, und die Berichterstattung ist asymmetrisch: Indische Medien behandeln sie ausführlich, pakistanische selten. Indische Ermittler haben unter anderem gegen Hafiz Saeed wegen des Anschlags von Pahalgam Anklage erhoben und Ausrüstung sowie Hintermänner jenseits der Grenze nachverfolgt; Neu-Delhi drängt auf internationale Listungen und auf Pakistans Rückkehr auf die FATF-Liste. Die Operation Sindoor, die militärische Antwort auf Pahalgam, gilt in der indischen Berichterstattung als Präzedenzfall für Gegenschläge, und ihr Jahrestag erzeugt wiederkehrende Kommentare. Pakistans Außenministerium erklärt, Indien habe nie Beweise vorgelegt, und bezeichnet die Vorwürfe als politisch nutzbares Narrativ.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('india_pakistan_nuclear_balance','Nuclear deterrence balance and strategic stability',NULL,NULL,NULL,ARRAY['ASIA-INDIA','ASIA-PAKISTAN'],false,64,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('indus_water_sharing','Indus waters treaty dispute','Streit um den Indus-Wasservertrag','The dispute over the Indus Waters Treaty, the 1960 World Bank-brokered agreement allocating the Indus basin rivers between India and Pakistan. It covers India''s suspension of the treaty and Pakistan''s demands for its restoration, Indian projects on the Chenab and the other western rivers, proceedings before the Court of Arbitration and the Permanent Indus Commission, and Pakistan''s representations to the UN Security Council. India describes the treaty as outdated; Pakistan describes it as valid, binding and operative.','Der Streit um den Indus-Wasservertrag, das 1960 von der Weltbank vermittelte Abkommen zur Aufteilung der Flüsse des Indus-Beckens zwischen Indien und Pakistan. Erfasst werden Indiens Aussetzung des Vertrags und Pakistans Forderungen nach seiner Wiederherstellung, indische Projekte am Chenab und den übrigen westlichen Flüssen, Verfahren vor dem Schiedsgerichtshof und der Ständigen Induskommission sowie Pakistans Eingaben an den UN-Sicherheitsrat. Indien bezeichnet den Vertrag als überholt; Pakistan bezeichnet ihn als gültig, bindend und in Kraft.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN'],true,65,'Water is the live lever in the India-Pakistan relationship. India suspended participation in the Indus Waters Treaty and has fast-tracked projects on the western rivers; its foreign ministry describes its position as consistent and the treaty as belonging to another era. Pakistan, wholly downstream, treats the suspension as unlawful: its president and ministers have called for restoration on World Water Day and at the UN, its deputy prime minister has written to the Security Council, and a defence minister has framed the issue in terms of war. A Court of Arbitration has issued findings, including a pondage award that India rejects. The dispute is a small share of overall coverage but recurs steadily and rises whenever a project or ruling advances.','Wasser ist der aktive Hebel im indisch-pakistanischen Verhältnis. Indien hat seine Teilnahme am Indus-Wasservertrag ausgesetzt und Projekte an den westlichen Flüssen beschleunigt; sein Außenministerium bezeichnet die eigene Position als konsistent und den Vertrag als einer anderen Zeit zugehörig. Pakistan, vollständig flussabwärts gelegen, hält die Aussetzung für rechtswidrig: Präsident und Minister forderten am Weltwassertag und vor den UN die Wiederherstellung, der stellvertretende Ministerpräsident wandte sich schriftlich an den Sicherheitsrat, und ein Verteidigungsminister formulierte die Frage in Kriegsbegriffen. Ein Schiedsgerichtshof hat Entscheidungen getroffen, darunter einen Schiedsspruch zur Speicherhaltung, den Indien zurückweist. Der Streit macht einen kleinen Teil der Gesamtberichterstattung aus, kehrt aber stetig wieder und nimmt zu, sobald ein Projekt oder eine Entscheidung voranschreitet.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('inter_korean_relations','Inter-Korean relations','Innerkoreanische Beziehungen','The relationship between the two Korean states, conducted across the Demilitarized Zone and the Northern Limit Line. It covers the engagement instruments -- the 2018 inter-Korean military agreement and its no-fly zone, liaison and hotline channels, family reunions, the Kaesong industrial zone and Kumgang tourism -- and the incidents that interrupt them, including drone incursions, loudspeaker and leaflet campaigns, and disputes over jurisdiction along the armistice line. It also covers the constitutional question: North Korea has removed references to reunification from its constitution and defines South Korea as a separate state, while Seoul''s unification policy has moved toward a two-state framing of peaceful coexistence.','Das Verhältnis zwischen den beiden koreanischen Staaten, geführt über die entmilitarisierte Zone und die nördliche Grenzlinie. Erfasst werden die Instrumente der Annäherung -- das innerkoreanische Militärabkommen von 2018 samt Flugverbotszone, Verbindungsbüros und Direktleitungen, Familienzusammenführungen, die Industriezone Kaesong und der Tourismus am Kumgang -- sowie die Zwischenfälle, die sie unterbrechen, darunter Drohneneinflüge, Lautsprecher- und Flugblattaktionen und Streit über die Zuständigkeit entlang der Waffenstillstandslinie. Erfasst wird ebenso die Verfassungsfrage: Nordkorea hat Verweise auf die Wiedervereinigung aus seiner Verfassung entfernt und definiert Südkorea als eigenen Staat, während Seouls Wiedervereinigungspolitik sich einer Zwei-Staaten-Rahmung friedlicher Koexistenz zugewandt hat.',ARRAY['ASIA-NORKOREA','ASIA-SOUTHKOREA'],true,5,'The inter-Korean relationship is being redefined rather than negotiated. North Korea has removed reunification from its constitution, defined its territory against a South it describes as a separate and hostile state, and publicly dismissed Seoul''s diplomatic overtures. Seoul has moved in a parallel direction on paper -- its unification white paper now frames the goal as peaceful two-state coexistence -- while pursuing engagement in practice: restoring the 2018 military agreement and its no-fly zone, easing civilian access along the border, expressing regret over drone incursions into the North, and reading signals such as statements from Kim Yo-jong or a less hostile constitutional revision as possible openings. The result is an asymmetry in which one side maintains an engagement track that the other has formally closed. Both readings of that asymmetry -- that engagement can still reopen the track, and that Pyongyang has ended it structurally -- appear in the same South Korean and Western outlets, which is why they are distinguished here by their framing rather than by publisher.','Das innerkoreanische Verhältnis wird eher neu definiert als verhandelt. Nordkorea hat die Wiedervereinigung aus seiner Verfassung entfernt, sein Staatsgebiet gegen einen Süden abgegrenzt, den es als eigenen und feindlichen Staat bezeichnet, und Gesprächsangebote aus Seoul öffentlich zurückgewiesen. Seoul hat sich auf dem Papier in eine parallele Richtung bewegt -- sein Weißbuch zur Wiedervereinigung fasst das Ziel nun als friedliche Koexistenz zweier Staaten -- verfolgt in der Praxis jedoch Annäherung: Wiederherstellung des Militärabkommens von 2018 samt Flugverbotszone, Erleichterung des zivilen Zugangs entlang der Grenze, Bedauern über Drohneneinflüge in den Norden und die Deutung von Signalen wie Äußerungen von Kim Yo-jong oder einer weniger feindseligen Verfassungsrevision als mögliche Öffnungen. Das Ergebnis ist eine Asymmetrie, in der eine Seite einen Annäherungskurs aufrechterhält, den die andere förmlich geschlossen hat. Beide Lesarten dieser Asymmetrie -- dass Annäherung den Kanal wieder öffnen kann und dass Pjöngjang ihn strukturell beendet hat -- erscheinen in denselben südkoreanischen und westlichen Medien, weshalb sie hier über ihre Rahmung und nicht über das Medium unterschieden werden.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
