INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('israel_iran_strikes','Israel-Iran direct strikes',NULL,NULL,NULL,ARRAY['MIDEAST-ISRAEL','MIDEAST-IRAN','AMERICAS-USA'],true,8,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
