INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('italian_populist_government','Italian right-wing populism and EU tensions',NULL,NULL,NULL,ARRAY['EUROPE-SOUTH'],false,39,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('japan_china_memory_wars','Wartime history and historical memory','Kriegsgeschichte und historisches Gedenken','Disputes over the commemoration and interpretation of Japan''s wartime conduct in China, including visits and offerings to Yasukuni Shrine, the historical record of the Nanjing Massacre and other wartime events, the treatment of forced laborers and so-called "comfort women," and the restitution of cultural property removed from China during the war.','Streitfragen zum Gedenken an und zur Deutung von Japans Kriegsverhalten in China, darunter Besuche und Opfergaben am Yasukuni-Schrein, die historische Aufarbeitung des Massakers von Nanking und anderer Kriegsereignisse, der Umgang mit Zwangsarbeitern und sogenannten "Trostfrauen" sowie die Rückgabe von Kulturgütern, die während des Krieges aus China entfernt wurden.',ARRAY['ASIA-CHINA'],true,70,'Japan''s conduct during its wartime occupation of parts of China, including the 1937 Nanjing Massacre, the use of forced labor, and the coercion of women into wartime brothels, remains a subject of dispute between the two countries'' historical accounts. Visits or ritual offerings by Japanese officials to Yasukuni Shrine, which honors Japan''s war dead including convicted war criminals, routinely draw formal protest from China. Related disputes include denial or minimization of wartime events by some Japanese public figures, the restoration of wartime military rank titles, unexploded or abandoned wartime chemical weapons still being cleared in China, and calls for Japan to return cultural relics removed during the war. These disputes recur independently of the theater''s other dimensions and are raised by Chinese officials and state media at points of broader diplomatic friction.','Japans Verhalten während der Besetzung von Teilen Chinas im Krieg, darunter das Massaker von Nanking 1937, der Einsatz von Zwangsarbeitern und die Zwangsrekrutierung von Frauen für Kriegsbordelle, bleibt zwischen den historischen Darstellungen beider Länder umstritten. Besuche oder rituelle Opfergaben japanischer Regierungsvertreter am Yasukuni-Schrein, der Japans Kriegstote einschließlich verurteilter Kriegsverbrecher ehrt, lösen regelmäßig förmliche Proteste Chinas aus. Verwandte Streitfragen umfassen die Leugnung oder Verharmlosung von Kriegsereignissen durch einzelne japanische Persönlichkeiten des öffentlichen Lebens, die Wiedereinführung von Dienstgradbezeichnungen aus der Kriegszeit, in China noch zu beseitigende zurückgelassene Chemiewaffen aus der Kriegszeit sowie Forderungen an Japan, während des Krieges entfernte Kulturgüter zurückzugeben. Diese Streitfragen treten unabhängig von den anderen Dimensionen des Themenfelds wiederholt auf und werden von chinesischen Regierungsvertretern und Staatsmedien an Punkten breiterer diplomatischer Spannung aufgegriffen.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-JAPAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('japan_china_taiwan_question','Japan''s role in the Taiwan question','Japans Rolle in der Taiwan-Frage','Japan''s public statements and legal posture on a potential military contingency in the Taiwan Strait, and China''s diplomatic response to them. Covers debate over Japan''s invocation of collective self-defense doctrine in relation to Taiwan, Taiwan Strait transits by Japanese naval vessels, and diplomatic incidents -- including at each country''s embassy -- that followed public remarks on the subject.','Japans öffentliche Äußerungen und rechtliche Haltung zu einem möglichen militärischen Konflikt in der Taiwanstraße sowie Chinas diplomatische Reaktionen darauf. Umfasst die Debatte über Japans Berufung auf die Doktrin der kollektiven Selbstverteidigung im Zusammenhang mit Taiwan, Durchfahrten japanischer Marineschiffe durch die Taiwanstraße sowie diplomatische Zwischenfälle -- auch an den jeweiligen Botschaften beider Länder --, die auf öffentliche Äußerungen zu diesem Thema folgten.',ARRAY['ASIA-CHINA'],true,71,'Japan''s position on Taiwan sits close to the center of its relationship with China because Taiwan lies at the edge of Japan''s own southwestern island chain: a Taiwan Strait contingency would occur within reach of Japanese territory and shipping lanes. Japanese officials have at times described such a contingency as a matter engaging Japan''s own security, including under the country''s collective self-defense doctrine, and Japanese naval vessels have transited the Taiwan Strait. China regards Taiwan as an internal matter and treats foreign statements on it as bearing on its own sovereignty; Japanese remarks on the subject have prompted formal protests, demands for retraction, and diplomatic friction including incidents at each country''s embassy. The dispute is distinct from the wider Taiwan Strait confrontation between China, Taiwan and the United States: its terrain is the bilateral Japan-China relationship, triggered by and centered on Japan''s own statements and posture.','Japans Position zu Taiwan steht nahe am Zentrum seines Verhältnisses zu China, da Taiwan am Rand von Japans eigener südwestlicher Inselkette liegt: Ein Konflikt in der Taiwanstraße würde sich in Reichweite japanischen Territoriums und japanischer Schifffahrtswege abspielen. Japanische Regierungsvertreter haben einen solchen Konflikt zeitweise als Frage bezeichnet, die die eigene Sicherheit Japans berührt, auch im Rahmen der Doktrin der kollektiven Selbstverteidigung, und japanische Marineschiffe sind durch die Taiwanstraße gefahren. China betrachtet Taiwan als innere Angelegenheit und wertet ausländische Äußerungen dazu als seine eigene Souveränität berührend; japanische Aussagen zu diesem Thema haben förmliche Proteste, Rücknahmeforderungen und diplomatische Spannungen bis hin zu Zwischenfällen an den jeweiligen Botschaften beider Länder ausgelöst. Der Streit unterscheidet sich von der breiteren Konfrontation um die Taiwanstraße zwischen China, Taiwan und den USA: Sein Schauplatz ist die bilaterale japanisch-chinesische Beziehung, ausgelöst durch und zentriert auf Japans eigene Äußerungen und Haltung.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-JAPAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('japan_china_theater','Japan-China strategic rivalry','Japanisch-chinesische strategische Rivalität','Strategic competition between Japan and China spanning five dimensions: the Senkaku/Diaoyu Islands and adjacent East China Sea waters, Japan''s position on the Taiwan question, Japan''s defense posture and the constitutional constraints on it, Chinese trade and travel measures applied to Japan, and disputes over the interpretation of wartime history. Each dimension carries its own vocabulary and set of actors, and the five interact with each other over time.','Strategischer Wettbewerb zwischen Japan und China entlang fünf Dimensionen: die Senkaku/Diaoyu-Inseln und die angrenzenden Gewässer des Ostchinesischen Meeres, Japans Position in der Taiwan-Frage, Japans Verteidigungshaltung und die verfassungsrechtlichen Beschränkungen dafür, chinesische Handels- und Reisemaßnahmen gegenüber Japan sowie Streitfragen zur Deutung der Kriegsgeschichte. Jede Dimension hat ein eigenes Vokabular und eigene Akteure, und die fünf Dimensionen wirken im Zeitverlauf aufeinander ein.',ARRAY['ASIA-JAPAN','ASIA-CHINA'],true,19,'Japan and China are Northeast Asia''s two largest economies and have moved between periods of diplomatic engagement and acute friction since normalizing relations in 1972. Five distinct dimensions structure the relationship: a territorial dispute over the Senkaku/Diaoyu Islands and East China Sea maritime boundaries, patrolled by both countries'' coast guards; Japan''s statements and legal posture on a potential Taiwan Strait contingency, which China regards as bearing on its own sovereignty; Japan''s defense budget, equipment policy and constitutional debate, conducted against the backdrop of China''s military modernization; Chinese export licensing, travel advisories and import rules applied to Japanese trade and travel; and a set of disputes over the commemoration and interpretation of Japan''s wartime conduct in China, including Yasukuni Shrine, the Nanjing Massacre, and the treatment of forced laborers and so-called "comfort women." Coverage of each dimension draws on distinct vocabularies and institutional actors, and diplomatic friction in one dimension has historically coincided with renewed attention to the others.','Japan und China sind die beiden größten Volkswirtschaften Nordostasiens und bewegen sich seit der Normalisierung ihrer Beziehungen 1972 zwischen Phasen diplomatischer Annäherung und akuter Spannung. Fünf Dimensionen prägen das Verhältnis: ein Territorialstreit um die Senkaku/Diaoyu-Inseln und die Seegrenzen im Ostchinesischen Meer, patrouilliert von den Küstenwachen beider Länder; Japans Aussagen und rechtliche Haltung zu einem möglichen Konflikt in der Taiwanstraße, den China als seine eigene Souveränität betreffend ansieht; Japans Verteidigungshaushalt, Rüstungspolitik und Verfassungsdebatte vor dem Hintergrund der chinesischen Militärmodernisierung; chinesische Exportlizenzierung, Reisewarnungen und Importregeln gegenüber japanischem Handel und Reiseverkehr; sowie Streitfragen zum Gedenken an und zur Deutung von Japans Kriegsverhalten in China, darunter der Yasukuni-Schrein, das Massaker von Nanking sowie der Umgang mit Zwangsarbeitern und sogenannten "Trostfrauen". Die Berichterstattung zu jeder Dimension folgt eigenen Vokabularen und institutionellen Akteuren, und diplomatische Spannungen in einer Dimension gingen historisch häufig mit erneuter Aufmerksamkeit für die anderen einher.','theater',ARRAY['japan_china_taiwan_question','japan_defense_expansion','china_japan_economic_restrictions','senkaku_diaoyu_islands','japan_china_memory_wars'],ARRAY['taiwan_strait','bayan_obo_rare_earths','northwest_pacific_fishing_grounds'],'regional','{"type": "Point", "coordinates": [123.5, 25.75]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('japan_defense_expansion','Japan''s defense expansion and postwar military constraints','Japans Verteidigungsausbau und die Beschränkungen des Nachkriegsmilitärs','Japan''s defense budget, equipment policy and constitutional debate, considered in relation to China''s military modernization. Covers rising defense spending, development of counter-strike missile capability, changes to Japan''s arms export rules, and debate over Article 9 of Japan''s postwar constitution and its Self-Defense Forces.','Japans Verteidigungshaushalt, Rüstungspolitik und Verfassungsdebatte im Verhältnis zur chinesischen Militärmodernisierung. Umfasst steigende Verteidigungsausgaben, die Entwicklung von Gegenschlag-Raketenfähigkeiten, Änderungen an Japans Regeln für Rüstungsexporte sowie die Debatte über Artikel 9 der japanischen Nachkriegsverfassung und die Selbstverteidigungsstreitkräfte.',ARRAY['ASIA-CHINA'],true,72,'Japan''s postwar constitution renounces the use of force to settle international disputes and for decades constrained its military to a strictly defensive posture. Since the 2010s, Japan has raised its defense budget, developed long-range counter-strike missile capability, eased restrictions on defense equipment exports, and debated formal revision of Article 9 -- changes officials in Tokyo describe as a response to a more severe regional security environment, including Chinese naval and air activity near Japan''s southwestern islands. Chinese officials and state media describe the same changes as a departure from Japan''s postwar pacifist commitments and connect them to Japan''s wartime history. The debate involves Japan''s Self-Defense Forces, its defense budget process, and its security relationships with the United States and other partners.','Japans Nachkriegsverfassung verzichtet auf Gewaltanwendung zur Beilegung internationaler Streitigkeiten und beschränkte sein Militär über Jahrzehnte auf eine strikt defensive Ausrichtung. Seit den 2010er Jahren hat Japan seinen Verteidigungshaushalt erhöht, weitreichende Gegenschlag-Raketenfähigkeiten entwickelt, Beschränkungen bei Rüstungsexporten gelockert und eine förmliche Änderung von Artikel 9 debattiert -- Schritte, die Vertreter in Tokio als Reaktion auf ein verschärftes regionales Sicherheitsumfeld beschreiben, darunter chinesische Marine- und Luftaktivitäten nahe Japans südwestlichen Inseln. Chinesische Regierungsvertreter und Staatsmedien beschreiben dieselben Schritte als Abkehr von Japans pazifistischen Nachkriegsverpflichtungen und stellen sie in Bezug zu Japans Kriegsgeschichte. Die Debatte betrifft Japans Selbstverteidigungsstreitkräfte, den Verteidigungshaushaltsprozess sowie die Sicherheitsbeziehungen zu den USA und weiteren Partnern.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-JAPAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('kashmir_dispute','Kashmir dispute','Kaschmir-Konflikt','The territorial dispute over Kashmir, divided since 1947 between areas administered by India and by Pakistan and claimed in full by both. It covers the constitutional status of Jammu and Kashmir following the 2019 changes and the unrestored statehood that followed, the status of Gilgit-Baltistan and the areas Pakistan administers, exchanges over the territory at the United Nations and other international bodies, and unrest and security operations on both sides of the line of control.','Der Territorialstreit um Kaschmir, das seit 1947 zwischen indisch und pakistanisch verwalteten Gebieten geteilt ist und von beiden Seiten vollständig beansprucht wird. Er umfasst den Verfassungsstatus von Jammu und Kaschmir nach den Änderungen von 2019 und die seither nicht wiederhergestellte Eigenstaatlichkeit, den Status von Gilgit-Baltistan und der von Pakistan verwalteten Gebiete, den Austausch über das Gebiet vor den Vereinten Nationen und anderen internationalen Gremien sowie Unruhen und Sicherheitsoperationen auf beiden Seiten der Waffenstillstandslinie.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN'],true,62,'Kashmir remains the formal territorial dispute between India and Pakistan, though it now generates more diplomatic and constitutional coverage than military coverage. India treats the territory as an internal matter and rejects references to it by other states as unwarranted; Pakistan raises it at the UN Human Rights Council and other bodies as an unresolved dispute, and marks Kashmir Solidarity Day. Within Indian-administered Jammu and Kashmir, the restoration of statehood is contested in domestic politics. Within Pakistan-administered Kashmir, protests over refugee seats and other grievances have turned deadly. Coverage is heavily concentrated in Indian and Pakistani outlets, each reporting the other''s administration critically.','Kaschmir bleibt der formelle Territorialstreit zwischen Indien und Pakistan, erzeugt inzwischen aber mehr diplomatische und verfassungsrechtliche als militärische Berichterstattung. Indien behandelt das Gebiet als innere Angelegenheit und weist Äußerungen anderer Staaten dazu als unzulässig zurück; Pakistan bringt es vor dem UN-Menschenrechtsrat und anderen Gremien als ungelösten Streitfall vor und begeht den Kaschmir-Solidaritätstag. Im indisch verwalteten Jammu und Kaschmir ist die Wiederherstellung der Eigenstaatlichkeit innenpolitisch umstritten. Im pakistanisch verwalteten Kaschmir sind Proteste um Flüchtlingssitze und andere Beschwerden tödlich verlaufen. Die Berichterstattung konzentriert sich stark auf indische und pakistanische Medien, die jeweils die Verwaltung der Gegenseite kritisch darstellen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('korea_peninsula_deterrence','US-ROK alliance and peninsula deterrence','US-südkoreanisches Bündnis und Abschreckung auf der Halbinsel','The United States-South Korea alliance as a military instrument and as a relationship under renegotiation. It covers the combined force posture -- United States Forces Korea, the Combined Forces Command, basing at Camp Humphreys, Osan and Kunsan, and the THAAD battery at Seongju -- and the exercise cycle, including Freedom Shield and Ulchi. It also covers the terms of the alliance itself: the conditions-based transfer of wartime operational control, defence cost-sharing, extended deterrence and the Nuclear Consultative Group, and South Korea''s programme for nuclear-powered submarines and a more self-reliant defence.','Das Bündnis zwischen den Vereinigten Staaten und Südkorea als militärisches Instrument und als Beziehung, deren Bedingungen neu verhandelt werden. Erfasst werden die gemeinsame Streitkräfteaufstellung -- die US-Streitkräfte in Korea, das kombinierte Oberkommando, die Stationierung in Camp Humphreys, Osan und Kunsan sowie die THAAD-Batterie in Seongju -- und der Übungszyklus einschließlich Freedom Shield und Ulchi. Erfasst werden ebenso die Bündnisbedingungen selbst: die bedingungsgebundene Übertragung der Operationskontrolle im Kriegsfall, die Teilung der Verteidigungskosten, die erweiterte Abschreckung und die Nukleare Konsultativgruppe sowie Südkoreas Programm für atomgetriebene U-Boote und eine eigenständigere Verteidigung.',ARRAY['ASIA-SOUTHKOREA','AMERICAS-USA','ASIA-NORKOREA','ASIA-JAPAN'],true,2,'The alliance is doing two things at once. As a military instrument it sustains the deterrence posture against the North: a standing US troop presence, a combined command, an annual exercise cycle that Pyongyang answers with launches, and extended-deterrence commitments reaffirmed through the Nuclear Consultative Group. As a relationship it is being renegotiated. Seoul is working toward the conditions-based transfer of wartime operational control, pressing for indigenous nuclear-powered submarines, and framing a more self-reliant defence as complementary to rather than a substitute for the alliance; defence cost-sharing and episodes of friction between the two capitals recur. Coverage of the first strand is broadly supportive across Western, South Korean and Japanese outlets. Coverage of the second is critical from inside the same coalition, which is why the two are separated here rather than read off publisher alignment. Chinese state media run a third line: that Washington treats South Korea as an instrument for containing China. Russian and Chinese reporting of the exercises themselves is otherwise neutral.','Das Bündnis leistet zweierlei zugleich. Als militärisches Instrument trägt es das Abschreckungsdispositiv gegenüber dem Norden: eine dauerhafte US-Truppenpräsenz, ein kombiniertes Oberkommando, einen jährlichen Übungszyklus, den Pjöngjang mit Raketenstarts beantwortet, und Zusagen zur erweiterten Abschreckung, die über die Nukleare Konsultativgruppe bekräftigt werden. Als Beziehung wird es neu verhandelt. Seoul arbeitet auf die bedingungsgebundene Übertragung der Operationskontrolle im Kriegsfall hin, drängt auf eigene atomgetriebene U-Boote und stellt eine eigenständigere Verteidigung als Ergänzung und nicht als Ersatz für das Bündnis dar; die Teilung der Verteidigungskosten und Reibungen zwischen beiden Hauptstädten kehren wieder. Die Berichterstattung über den ersten Strang ist in westlichen, südkoreanischen und japanischen Medien weitgehend zustimmend. Die über den zweiten ist kritisch aus derselben Koalition heraus, weshalb beide hier getrennt und nicht über die Medienzugehörigkeit erschlossen werden. Chinesische Staatsmedien fahren eine dritte Linie: Washington behandle Südkorea als Instrument zur Eindämmung Chinas. Die russische und chinesische Berichterstattung über die Übungen selbst ist ansonsten neutral.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-SOUTHKOREA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('korea_reunification_identity','Korean reunification question and national identity',NULL,NULL,NULL,ARRAY['ASIA-NORKOREA','ASIA-SOUTHKOREA'],false,60,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('korea_theater','Korean Peninsula standoff','Konfrontation auf der koreanischen Halbinsel','The unresolved confrontation on the Korean Peninsula, where the Korean War was halted by an armistice rather than concluded by a peace treaty. Five axes run through it: North Korea''s nuclear and ballistic missile programme and the sanctions architecture built around it; the United States-South Korea alliance, with its exercises, command arrangements and extended-deterrence commitments; North Korea''s military alignment with Russia, including troop deployments to the war in Ukraine; China''s economic and diplomatic patronage of Pyongyang; and the inter-Korean relationship itself, which North Korea has redefined constitutionally as a relationship between separate states. Coverage divides by bloc: Western, South Korean and Japanese outlets report the Northern programme as a threat requiring containment, while Russian and Chinese state media present Pyongyang''s arrangements with Moscow and Beijing as lawful cooperation between sovereign states.','Die ungelöste Konfrontation auf der koreanischen Halbinsel, wo der Koreakrieg durch einen Waffenstillstand unterbrochen und nicht durch einen Friedensvertrag beendet wurde. Fünf Achsen durchziehen sie: Nordkoreas Nuklear- und Raketenprogramm und die darum errichtete Sanktionsarchitektur; das Bündnis zwischen den Vereinigten Staaten und Südkorea mit seinen Übungen, Kommandostrukturen und Zusagen zur erweiterten Abschreckung; Nordkoreas militärische Ausrichtung auf Russland einschließlich Truppenentsendungen in den Krieg in der Ukraine; Chinas wirtschaftliche und diplomatische Patronage über Pjöngjang; und die innerkoreanische Beziehung selbst, die Nordkorea verfassungsrechtlich als Verhältnis getrennter Staaten neu definiert hat. Die Berichterstattung teilt sich nach Blöcken: Westliche, südkoreanische und japanische Medien berichten über das nordkoreanische Programm als Bedrohung, die Eindämmung erfordert, während russische und chinesische Staatsmedien Pjöngjangs Arrangements mit Moskau und Peking als rechtmäßige Zusammenarbeit souveräner Staaten darstellen.',ARRAY['ASIA-NORKOREA','ASIA-SOUTHKOREA','AMERICAS-USA','ASIA-CHINA','ASIA-JAPAN','EUROPE-RUSSIA'],true,16,'The Korean Peninsula remains divided along an armistice line that has held without a peace treaty since 1953. The dominant axis is North Korea''s nuclear and ballistic missile programme: Pyongyang has declared itself a nuclear state, describes that status as irreversible, and continues launch testing and enrichment expansion against a United Nations sanctions regime that has not reversed it. Two external relationships now shape what pressure can achieve. Russia and North Korea have built a treaty-based military partnership under which North Korean troops have fought in Kursk and North Korean munitions have supplied the war in Ukraine, with the return flow -- cash, and possibly military and space technology -- the central question for observers. China has restored its own links to Pyongyang through a state visit, resumed flights and rail, and trade that sustains the North Korean economy. Facing them, the United States-South Korea alliance is simultaneously reaffirming extended deterrence and renegotiating its own terms: the transfer of wartime operational control, defence cost-sharing, and Seoul''s push for a more self-reliant defence including nuclear-powered submarines. The inter-Korean track itself has narrowed, with Seoul offering engagement while North Korea has removed reunification from its constitution and defined the South as a separate state.','Die koreanische Halbinsel bleibt entlang einer Waffenstillstandslinie geteilt, die seit 1953 ohne Friedensvertrag hält. Die dominierende Achse ist Nordkoreas Nuklear- und Raketenprogramm: Pjöngjang hat sich zum Atomstaat erklärt, bezeichnet diesen Status als unumkehrbar und setzt Starttests und den Ausbau der Anreicherung gegen ein Sanktionsregime der Vereinten Nationen fort, das dies nicht rückgängig gemacht hat. Zwei äußere Beziehungen bestimmen inzwischen, was Druck bewirken kann. Russland und Nordkorea haben eine vertraglich geregelte Militärpartnerschaft aufgebaut, in deren Rahmen nordkoreanische Truppen bei Kursk gekämpft und nordkoreanische Munition den Krieg in der Ukraine beliefert haben; der Rückfluss -- Geld und möglicherweise Militär- und Raumfahrttechnologie -- ist die zentrale Frage für Beobachter. China hat seine eigenen Verbindungen nach Pjöngjang durch einen Staatsbesuch, wieder aufgenommene Flüge und Bahnverbindungen sowie Handel wiederhergestellt, der die nordkoreanische Wirtschaft trägt. Ihnen gegenüber bekräftigt das Bündnis zwischen den Vereinigten Staaten und Südkorea die erweiterte Abschreckung und verhandelt zugleich seine eigenen Bedingungen neu: die Übertragung der Operationskontrolle im Kriegsfall, die Teilung der Verteidigungskosten und Seouls Streben nach eigenständigerer Verteidigung einschließlich atomgetriebener U-Boote. Der innerkoreanische Kanal selbst hat sich verengt: Seoul bietet Annäherung an, während Nordkorea die Wiedervereinigung aus seiner Verfassung entfernt und den Süden als eigenen Staat definiert hat.','theater',ARRAY['north_korea_missile_program','north_korea_china_patronage','north_korea_russia_alignment','inter_korean_relations','korea_peninsula_deterrence'],ARRAY['ulsan_industrial','kori_saeul_npp','samsung_pyeongtaek_hwaseong','sk_hynix_icheon','busan_port','incheon_pyeongtaek_lng'],'regional','{"type": "Point", "coordinates": [126.7, 37.95]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
