INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_us_trade_pressure','US tariff and sanctions pressure','US-Zoll- und Sanktionsdruck','United States tariffs, sanctions designations and trade-enforcement measures applied to South American states.','Zölle, Sanktionslistungen und handelspolitische Zwangsmaßnahmen der Vereinigten Staaten gegenüber südamerikanischen Staaten.',ARRAY['AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN'],true,106,'Washington has proposed or imposed tariffs on Brazilian goods and issued sanctions designations touching Brazilian and Colombian officials and networks. Affected governments respond through negotiation, retaliation or appeals to the domestic electorate, and the measures intersect with election cycles in the targeted states.','Washington hat Zölle auf brasilianische Waren vorgeschlagen oder verhängt und Sanktionslistungen gegen brasilianische und kolumbianische Amtsträger und Netzwerke ausgesprochen. Betroffene Regierungen reagieren mit Verhandlungen, Gegenmaßnahmen oder der Ansprache der eigenen Wählerschaft; die Maßnahmen überschneiden sich mit Wahlzyklen in den betroffenen Staaten.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('m23_conflict','M23 insurgency in eastern Congo','M23-Aufstand im Osten der DR Kongo','M23 is an armed movement operating in North and South Kivu, aligned since 2023 with the Alliance Fleuve Congo. It has held Goma and other eastern towns, and the Congolese government, the United Nations and Western states attribute its capability to support from Rwanda -- an attribution Kigali rejects. The node also covers the other armed groups active in the same provinces, including the Allied Democratic Forces and CODECO.','M23 ist eine bewaffnete Bewegung in Nord- und Süd-Kivu, seit 2023 mit der Alliance Fleuve Congo verbunden. Sie hielt Goma und weitere Städte im Osten; die kongolesische Regierung, die Vereinten Nationen und westliche Staaten führen ihre Schlagkraft auf Unterstützung aus Ruanda zurück -- eine Zuschreibung, die Kigali zurückweist. Erfasst sind auch die übrigen bewaffneten Gruppen in denselben Provinzen, darunter die Allied Democratic Forces und CODECO.',ARRAY['AFRICA-DRC'],true,82,'Kinetic coverage fell steadily across the first half of 2026, from heavy fighting and drone strikes early in the year to an M23 withdrawal and government forces retaking ground by May.','Die Berichterstattung über Kampfhandlungen ging im ersten Halbjahr 2026 stetig zurück -- von schweren Gefechten und Drohnenangriffen zu Jahresbeginn bis zum Rückzug der M23 und der Rückeroberung von Gebieten durch Regierungstruppen im Mai.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('mexico_cartel_war','Cartel war and state response','Kartellkrieg und staatliche Antwort','Major operations against CJNG and Sinaloa, cartel-leader captures and deaths, and the militarisation of Mexican internal security.','Großoperationen gegen CJNG und Sinaloa, Festnahmen und Tötungen von Kartellführern und die Militarisierung der inneren Sicherheit Mexikos.',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],true,NULL,'Mexico''s confrontation with its drug cartels centres on the Sinaloa Cartel and the Jalisco New Generation Cartel (CJNG), fought through militarised operations, high-profile leader captures and extraditions to the United States, and running violence that has not been durably reduced. The story carries a persistent own-goal dimension: indictments and arrests reaching into the state itself — a Sinaloa governor accused of cartel ties, a former state security chief in US custody — feed a narco-state critique of collusion, corruption and impunity that even sympathetic outlets advance. Coverage divides between a security-offensive reading that treats captures as progress, a friendly-critic reading that treats militarisation as a failing strategy compromised from within, and a Russian/Chinese framing that blames US drug demand and the southward flow of American guns.','Mexikos Auseinandersetzung mit seinen Drogenkartellen konzentriert sich auf das Sinaloa-Kartell und das Kartell Jalisco Nueva Generación (CJNG), ausgetragen durch militarisierte Operationen, aufsehenerregende Festnahmen von Anführern und Auslieferungen an die USA sowie anhaltende Gewalt, die nicht dauerhaft zurückgegangen ist. Die Geschichte trägt eine beständige Eigentor-Dimension: Anklagen und Festnahmen, die bis in den Staat selbst reichen — ein Sinaloa-Gouverneur, dem Kartellverbindungen vorgeworfen werden, ein früherer Sicherheitschef in US-Gewahrsam — nähren eine Narco-Staat-Kritik an Kollusion, Korruption und Straflosigkeit, die selbst wohlgesonnene Medien vertreten. Die Berichterstattung teilt sich zwischen einer Sicherheitsoffensiv-Lesart, die Festnahmen als Fortschritt wertet, einer wohlwollend-kritischen Lesart, die Militarisierung als von innen kompromittierte, scheiternde Strategie sieht, und einem russisch/chinesischen Framing, das die US-Drogennachfrage und den Zustrom amerikanischer Waffen nach Süden verantwortlich macht.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-MEXICO')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('mexico_theater','US-Mexico security and trade confrontation','Sicherheits- und Handelskonfrontation USA-Mexiko','Confrontation between the United States and Mexico across three fronts: the cartel war and Mexico''s security response, US intervention pressure against Mexico''s sovereignty, and tariff, border and migration leverage.','Konfrontation zwischen den USA und Mexiko an drei Fronten: der Kartellkrieg und Mexikos Sicherheitsantwort, US-Interventionsdruck gegenüber Mexikos Souveränität sowie Zoll-, Grenz- und Migrationsdruckmittel.',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],true,NULL,'The US-Mexico relationship has hardened into a confrontation across three fronts, driven by Washington''s use of security and economic pressure on its southern neighbour. On the ground, Mexico''s own war against the Sinaloa and Jalisco New Generation cartels — leader captures, army operations, and the corruption and collusion that shadow them — is the substrate. Over it the United States has layered coercive security pressure: covert CIA operations (including the deaths of officers in Chihuahua), indictments of Mexican officials, and threats of unilateral military action against cartels on Mexican soil. In parallel runs economic and border leverage — tariff threats, USMCA renegotiation, and demands on migration, deportation and border enforcement. President Sheinbaum''s government answers with a sovereignty red line of cooperation without subordination. Coverage splits sharply: US conservative outlets frame the pressure as justified leverage against a failed partner; Mexican and Hispanic-American media as a violation of sovereignty and dignity; Western mainstream and business press through scandal, diplomacy and market disruption; and Russian and Chinese state media as proof of American imperialism in its own backyard.','Die Beziehung zwischen den USA und Mexiko hat sich zu einer Konfrontation an drei Fronten verhärtet, getrieben von Washingtons Einsatz sicherheitspolitischen und wirtschaftlichen Drucks auf seinen südlichen Nachbarn. Am Boden bildet Mexikos eigener Krieg gegen die Kartelle von Sinaloa und Jalisco Nueva Generación — Festnahmen von Anführern, Armeeoperationen sowie die begleitende Korruption und Kollusion — das Substrat. Darüber haben die USA sicherheitspolitischen Zwang gelegt: verdeckte CIA-Operationen (darunter der Tod von Beamten in Chihuahua), Anklagen gegen mexikanische Amtsträger und Drohungen mit einseitigen Militäraktionen gegen Kartelle auf mexikanischem Boden. Parallel verläuft wirtschaftlicher und grenzpolitischer Druck — Zolldrohungen, USMCA-Neuverhandlung und Forderungen zu Migration, Abschiebung und Grenzsicherung. Die Regierung von Präsidentin Sheinbaum antwortet mit einer roten Souveränitätslinie: Kooperation ohne Unterordnung. Die Berichterstattung ist stark gespalten: US-konservative Medien deuten den Druck als gerechtfertigtes Druckmittel gegen einen gescheiterten Partner; mexikanische und hispanoamerikanische Medien als Verletzung von Souveränität und Würde; westliche Mainstream- und Wirtschaftspresse über Skandal, Diplomatie und Marktstörungen; und russische und chinesische Staatsmedien als Beweis amerikanischen Imperialismus im eigenen Hinterhof.','theater',ARRAY['mexico_cartel_war','us_mexico_military_pressure','us_mexico_trade_border'],ARRAY['manzanillo_mx_port','cantarell_field','ku_maloob_zaap_field'],'regional','{"type": "Point", "coordinates": [-99.1, 19.4]}'::jsonb,'AMERICAS-MEXICO')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('myanmar_china_influence','Chinese influence on border stability and conflicts',NULL,NULL,NULL,ARRAY['ASIA-SOUTHEAST','ASIA-CHINA'],false,73,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('myanmar_civil_conflict','Myanmar civil conflict','Bürgerkonflikt in Myanmar','Myanmar has been in political and armed conflict since the military removed the elected government in February 2021. The armed forces, organised politically around the Union Solidarity and Development Party, hold central power; a parallel National Unity Government, allied People''s Defence Forces and long-established ethnic armed organisations contest military control across much of the country. In elections held under military administration the military-aligned bloc won most seats, and former State Counsellor Aung San Suu Kyi remains in detention. Fighting includes airstrikes, ground offensives and clashes near the borders with Thailand, China and India. The border regions host large scam-compound and human-trafficking operations whose victims and proceeds cross the wider region, prompting Chinese prosecutions and cross-border enforcement. China, Russia, India and ASEAN states maintain varying degrees of engagement with the authorities in Naypyidaw.','Myanmar befindet sich seit der Absetzung der gewählten Regierung durch das Militär im Februar 2021 in einem politischen und bewaffneten Konflikt. Die Streitkräfte, politisch um die Union Solidarity and Development Party organisiert, halten die zentrale Macht; eine parallele Regierung der Nationalen Einheit, verbündete People''s Defence Forces und seit langem bestehende ethnische bewaffnete Organisationen stellen die militärische Kontrolle in weiten Teilen des Landes infrage. Bei unter Militärverwaltung abgehaltenen Wahlen gewann das militärnahe Lager die meisten Sitze; die frühere Staatsrätin Aung San Suu Kyi bleibt in Haft. Zu den Kampfhandlungen gehören Luftangriffe, Bodenoffensiven und Gefechte nahe den Grenzen zu Thailand, China und Indien. Die Grenzregionen beherbergen große Betrugszentren und Menschenhandelsoperationen, deren Opfer und Erlöse die weitere Region durchziehen und chinesische Strafverfolgung sowie grenzüberschreitende Einsätze nach sich ziehen. China, Russland, Indien und ASEAN-Staaten unterhalten unterschiedlich enge Beziehungen zu den Behörden in Naypyidaw.',ARRAY['ASIA-SOUTHEAST','ASIA-SOUTHASIA','ASIA-CHINA'],true,1,'Myanmar''s conflict is regionally contained and draws limited direct involvement from major powers. The military-aligned bloc took most seats in elections held under military administration, Aung San Suu Kyi remains detained, and fighting continues between the armed forces and both opposition and ethnic armed organisations, while the border regions host industrial-scale scam compounds and trafficking. Coverage splits along two lines: Chinese and Russian state media present the post-election government as a legitimate transition backed by cooperation and engagement; Western and Southeast Asian democratic press treat the vote as a staged legitimation of military rule and document airstrikes, detentions and civilian casualties. The scam economy is reported across both as a transnational security problem.','Der Konflikt in Myanmar ist regional begrenzt und zieht nur begrenzte direkte Beteiligung der Großmächte nach sich. Das militärnahe Lager gewann bei unter Militärverwaltung abgehaltenen Wahlen die meisten Sitze, Aung San Suu Kyi bleibt in Haft, und die Kämpfe zwischen den Streitkräften und sowohl der Opposition als auch ethnischen bewaffneten Organisationen dauern an, während die Grenzregionen Betrugszentren und Menschenhandel im industriellen Maßstab beherbergen. Die Berichterstattung teilt sich entlang zweier Linien: Chinesische und russische Staatsmedien stellen die Regierung nach der Wahl als legitimen Übergang dar, der durch Zusammenarbeit und Engagement gestützt wird; westliche und südostasiatische demokratische Medien werten die Wahl als inszenierte Legitimierung der Militärherrschaft und dokumentieren Luftangriffe, Inhaftierungen und zivile Opfer. Die Betrugswirtschaft wird von beiden Seiten als transnationales Sicherheitsproblem behandelt.','atomic',NULL,ARRAY['kachin_rare_earth_zone'],'regional','{"type": "Point", "coordinates": [95.5, 21.5]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
