  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('north_korea_china_patronage','China''s patronage of North Korea','Chinas Patronage über Nordkorea','China''s economic and diplomatic relationship with North Korea, and its effect on the sanctions regime. It covers head-of-state and foreign-ministry visits, the cross-border economy through Dandong, Sinuiju and the Yalu and Tumen crossings, restored transport links including Beijing-Pyongyang flights and rail service, the treaty of friendship and its commemorative infrastructure, and the trade that supplies the North Korean economy. China is a permanent member of the United Nations Security Council and a party to the sanctions resolutions on North Korea; enforcement of those resolutions at the Chinese border is a recurring subject.','Chinas wirtschaftliche und diplomatische Beziehung zu Nordkorea und deren Wirkung auf das Sanktionsregime. Erfasst werden Besuche auf Ebene der Staatsoberhäupter und Außenministerien, die grenzüberschreitende Wirtschaft über Dandong, Sinuiju und die Übergänge am Yalu und Tumen, wiederhergestellte Verkehrsverbindungen einschließlich Flügen und Bahnverkehr zwischen Peking und Pjöngjang, der Freundschaftsvertrag und seine Gedenkinfrastruktur sowie der Handel, der die nordkoreanische Wirtschaft versorgt. China ist ständiges Mitglied des Sicherheitsrats der Vereinten Nationen und Vertragspartei der Sanktionsresolutionen zu Nordkorea; die Durchsetzung dieser Resolutionen an der chinesischen Grenze ist ein wiederkehrendes Thema.',ARRAY['ASIA-NORKOREA','ASIA-CHINA'],true,4,'China is the variable that determines how much the pressure regime can actually deliver. It is a permanent member of the Security Council and a signatory to the sanctions resolutions on North Korea, and it is simultaneously the North Korean economy''s principal external support: trade across the Yalu, restored Beijing-Pyongyang flights and rail service after years of suspension, and a re-engagement at the highest level through a state visit and a foreign-ministry mission. The nuclear question was not visibly advanced by that re-engagement. Chinese state media present it as a traditional friendship entering a new era and as a contribution to regional stability. Western, South Korean and Japanese outlets that take a position read the same links as the decisive gap in enforcement -- a lifeline that keeps the economy alive and rebuilds Chinese leverage over Pyongyang as a card in Beijing''s own competition with Washington. Much of the non-Chinese coverage, however, simply reports the visits and the reopened links without arguing either case.','China ist die Variable, die bestimmt, wie viel das Druckregime tatsächlich bewirken kann. Es ist ständiges Mitglied des Sicherheitsrats und Unterzeichner der Sanktionsresolutionen zu Nordkorea und zugleich die wichtigste äußere Stütze der nordkoreanischen Wirtschaft: Handel über den Yalu, wieder aufgenommene Flüge und Bahnverbindungen zwischen Peking und Pjöngjang nach Jahren der Aussetzung und eine Wiederannäherung auf höchster Ebene durch einen Staatsbesuch und eine Mission des Außenministeriums. Die Nuklearfrage wurde durch diese Wiederannäherung sichtbar nicht vorangebracht. Chinesische Staatsmedien stellen sie als traditionelle Freundschaft dar, die in eine neue Ära eintritt, und als Beitrag zur regionalen Stabilität. Westliche, südkoreanische und japanische Medien, die Position beziehen, lesen dieselben Verbindungen als entscheidende Lücke in der Durchsetzung -- eine Lebensader, die die Wirtschaft am Leben hält und Pekings Einfluss auf Pjöngjang als Karte im eigenen Wettbewerb mit Washington wiederaufbaut. Ein großer Teil der nicht-chinesischen Berichterstattung meldet die Besuche und die wiedereröffneten Verbindungen jedoch schlicht, ohne für eine der beiden Lesarten zu argumentieren.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-NORKOREA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('north_korea_international_pressure','International sanctions and pressure regime on North Korea',NULL,NULL,NULL,ARRAY['ASIA-NORKOREA','AMERICAS-USA','ASIA-CHINA','ASIA-JAPAN','ASIA-SOUTHKOREA'],false,59,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('north_korea_missile_program','North Korean ballistic and nuclear missile programme','Nordkoreas ballistisches und nukleares Raketenprogramm','North Korea''s nuclear weapons and ballistic missile programme, and the international pressure regime built against it. It covers warhead and fissile-material production at sites such as Yongbyon and Kangson, the test infrastructure at Punggye-ri and Sohae, the Hwasong and Pukguksong families of ballistic and submarine-launched missiles, hypersonic and guided systems, and the launch testing that punctuates the calendar. It also covers the response: United Nations Security Council sanctions and their enforcement, denuclearisation diplomacy, and allied detection and interception. Pyongyang has written its nuclear status into law and rejects denuclearisation as a premise for talks.','Nordkoreas Nuklearwaffen- und Raketenprogramm sowie das dagegen errichtete internationale Druckregime. Erfasst werden die Produktion von Sprengköpfen und Spaltmaterial an Standorten wie Yongbyon und Kangson, die Testinfrastruktur in Punggye-ri und Sohae, die Raketenfamilien Hwasong und Pukguksong einschließlich U-Boot-gestützter Systeme, Hyperschall- und gelenkte Systeme sowie die Starttests, die den Kalender prägen. Erfasst wird ebenso die Reaktion: Sanktionen des Sicherheitsrats der Vereinten Nationen und ihre Durchsetzung, Denuklearisierungsdiplomatie sowie Aufklärung und Abfangfähigkeit der Verbündeten. Pjöngjang hat seinen Atomstatus gesetzlich verankert und lehnt Denuklearisierung als Voraussetzung für Gespräche ab.',ARRAY['ASIA-NORKOREA','ASIA-SOUTHKOREA','AMERICAS-USA','ASIA-JAPAN'],true,1,'This is the axis that sets the terms for everything else on the peninsula. North Korea has declared itself a nuclear state, written that status into its constitution and law, and says it is irreversible; assessments track expanding uranium-enrichment capacity, growing warhead estimates, and progress on intercontinental and submarine-launched delivery. Launch testing is frequent and often timed against allied exercises or regional events. The pressure architecture built to reverse the programme -- Security Council resolutions, sanctions enforcement, interdiction and denuclearisation diplomacy -- has not achieved that reversal, and its enforcement has weakened as Russia and China have moved closer to Pyongyang. Reporting divides sharply: Western, South Korean and Japanese outlets treat the programme as an expanding danger to be contained, while Russian and Chinese state press, when it takes a position at all, relays Pyongyang''s claim that the arsenal is a lawful sovereign deterrent and that containment has failed. Most of that bloc''s coverage is neutral reporting of launches rather than advocacy.','Dies ist die Achse, die die Bedingungen für alles Übrige auf der Halbinsel setzt. Nordkorea hat sich zum Atomstaat erklärt, diesen Status in Verfassung und Gesetz verankert und bezeichnet ihn als unumkehrbar; Einschätzungen verfolgen wachsende Urananreicherungskapazitäten, steigende Sprengkopfschätzungen und Fortschritte bei interkontinentalen und U-Boot-gestützten Trägersystemen. Starttests erfolgen häufig und oft mit zeitlichem Bezug zu Übungen der Verbündeten oder regionalen Ereignissen. Die Druckarchitektur, die das Programm umkehren sollte -- Resolutionen des Sicherheitsrats, Sanktionsdurchsetzung, Unterbindung und Denuklearisierungsdiplomatie -- hat diese Umkehr nicht erreicht, und ihre Durchsetzung ist schwächer geworden, seit Russland und China Pjöngjang näher gerückt sind. Die Berichterstattung teilt sich deutlich: Westliche, südkoreanische und japanische Medien behandeln das Programm als wachsende Gefahr, die eingedämmt werden muss, während die russische und chinesische Staatspresse, sofern sie überhaupt Position bezieht, Pjöngjangs Anspruch wiedergibt, das Arsenal sei ein rechtmäßiges souveränes Abschreckungsmittel und die Eindämmung gescheitert. Der Großteil dieser Berichterstattung besteht aus neutralen Meldungen über Raketenstarts, nicht aus Fürsprache.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-NORKOREA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('north_korea_russia_alignment','North Korea''s alignment with Russia','Nordkoreas Ausrichtung auf Russland','The military and political alignment between North Korea and Russia, extended through Belarus. It covers the treaty-based partnership and its implementation: North Korean troop deployments to Russian territory including Kursk, munitions and missile transfers supporting the war in Ukraine, ministerial, parliamentary and head-of-state visits in both directions, cross-border infrastructure such as the Khasan-Tumangang crossing and a road bridge, and the compensation flowing back to Pyongyang. Estimates of that return flow include payments and the transfer of military and space technology. North Korean casualties and prisoners of war taken in Ukraine are part of the same axis.','Die militärische und politische Ausrichtung zwischen Nordkorea und Russland, erweitert um Belarus. Erfasst werden die vertraglich geregelte Partnerschaft und ihre Umsetzung: Entsendungen nordkoreanischer Truppen auf russisches Gebiet einschließlich Kursk, Lieferungen von Munition und Raketen zur Unterstützung des Krieges in der Ukraine, Besuche von Ministern, Parlamentariern und Staatsoberhäuptern in beide Richtungen, grenzüberschreitende Infrastruktur wie der Übergang Chasan-Tumangang und eine Straßenbrücke sowie die Gegenleistungen an Pjöngjang. Schätzungen dieses Rückflusses umfassen Zahlungen sowie den Transfer von Militär- und Raumfahrttechnologie. Nordkoreanische Gefallene und in der Ukraine gemachte Kriegsgefangene gehören zur selben Achse.',ARRAY['ASIA-NORKOREA','EUROPE-RUSSIA','EUROPE-UKRAINE','EUROPE-BELARUS'],true,3,'North Korea has become a participant in a European war, and the relationship that made it one is the newest structural change on the peninsula. Under a treaty-based partnership, North Korean soldiers have fought on Russian territory in Kursk and North Korean munitions and missiles have supplied the war in Ukraine; Pyongyang has publicly honoured the dead with memorials and housing for their families, and its leadership has described ties with Moscow as a top priority. Belarus has joined the axis at the level of state visits. What Russia pays in return is the question that connects this node to the weapons programme: estimates cover cash running to billions, and suspicion centres on military and space technology that would accelerate North Korean capabilities. Russian and Belarusian state press present the arrangement as lawful cooperation between sovereign states under the same sanctions, with North Korean soldiers as heroes of a liberation. Western, South Korean, Japanese and Ukrainian outlets read it as a transaction -- troops and shells for cash and technology -- and foreground its costs, including casualty figures, prisoners of war, and a policy of self-destruction to avoid capture that Kim has praised publicly.','Nordkorea ist zur Kriegspartei in einem europäischen Krieg geworden, und die Beziehung, die dazu geführt hat, ist die jüngste strukturelle Veränderung auf der Halbinsel. Im Rahmen einer vertraglich geregelten Partnerschaft haben nordkoreanische Soldaten auf russischem Gebiet bei Kursk gekämpft, und nordkoreanische Munition und Raketen haben den Krieg in der Ukraine beliefert; Pjöngjang hat die Gefallenen öffentlich mit Denkmälern und Wohnungen für ihre Familien geehrt, und seine Führung bezeichnet die Beziehungen zu Moskau als oberste Priorität. Belarus ist der Achse auf der Ebene von Staatsbesuchen beigetreten. Was Russland im Gegenzug zahlt, ist die Frage, die diesen Knoten mit dem Waffenprogramm verbindet: Schätzungen reichen bis in den Milliardenbereich, und der Verdacht richtet sich auf Militär- und Raumfahrttechnologie, die nordkoreanische Fähigkeiten beschleunigen würde. Die russische und belarussische Staatspresse stellt das Arrangement als rechtmäßige Zusammenarbeit souveräner Staaten unter denselben Sanktionen dar, mit nordkoreanischen Soldaten als Helden einer Befreiung. Westliche, südkoreanische, japanische und ukrainische Medien lesen es als Geschäft -- Truppen und Granaten gegen Geld und Technologie -- und stellen die Kosten in den Vordergrund, darunter Verlustzahlen, Kriegsgefangene und eine von Kim öffentlich gelobte Praxis der Selbstsprengung zur Vermeidung der Gefangennahme.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-NORKOREA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('pacific_island_contest','Contest for alignment of Pacific island states','Wettstreit um die Ausrichtung pazifischer Inselstaaten','The competition between Australia and China over the security and diplomatic alignment of the Pacific island states. Australia has signed a mutual defence treaty with Fiji and a pact with Vanuatu barring foreign military bases; Solomon Islands, under a new prime minister, is reviewing the security pact it signed with Beijing; Nauru, which switched recognition to Beijing, has directed officials to observe the one-China principle. China supplies medical teams, infrastructure and policing assistance across the region. Recognition of Taiwan and access to seabed minerals run through the same contest.','Der Wettbewerb zwischen Australien und China um die sicherheitspolitische und diplomatische Ausrichtung der pazifischen Inselstaaten. Australien hat einen Verteidigungsvertrag mit Fidschi und einen Pakt mit Vanuatu zum Verbot ausländischer Militärbasen unterzeichnet; die Salomonen überprüfen unter einem neuen Premierminister den mit Peking geschlossenen Sicherheitspakt; Nauru, das seine Anerkennung nach Peking verlagert hat, wies Bedienstete an, das Ein-China-Prinzip zu beachten. China stellt medizinische Teams, Infrastruktur und Polizeihilfe in der Region bereit. Die Anerkennung Taiwans und der Zugang zu Meeresbodenmineralien durchziehen denselben Wettstreit.',ARRAY['OCEANIA-MELANESIA','OCEANIA-POLYNESIA','OCEANIA-MICRONESIA','OCEANIA-PAPUANEWGUINEA'],true,1,'This is the theater''s live front and its fastest-moving one. The sequence in July 2026 is the whole story compressed: Canberra signs a mutual defence treaty with Fiji, and within hours Beijing test-fires a nuclear-capable ballistic missile into the South Pacific that lands near Nauru and Tuvalu, prompting Pacific leaders to answer "don''t threaten us". Around it, Vanuatu signs a pact barring foreign military bases while warning Australia it will not be "dictated to", and a new Solomon Islands prime minister moves to review the secret pact his predecessor signed with Beijing. Coverage splits cleanly by publisher: Australian and Western outlets read the pacts as island states freely choosing transparency over Chinese basing, while Chinese state media present the same engagement as ordinary cooperation that "should not target any third party" and cast Australian reporting as hype from an exclusionary mindset. A third voice — the islands'' own insistence that they are neither camp''s to win — is audible but still thin in the corpus.','Dies ist die aktive und am schnellsten bewegte Front des Schauplatzes. Die Abfolge im Juli 2026 verdichtet die ganze Geschichte: Canberra unterzeichnet einen Verteidigungsvertrag mit Fidschi, und binnen Stunden testet Peking eine atomwaffenfähige ballistische Rakete im Südpazifik, die nahe Nauru und Tuvalu niedergeht — worauf pazifische Staatschefs mit "Droht uns nicht" antworten. Daneben unterzeichnet Vanuatu einen Pakt zum Verbot ausländischer Militärbasen und warnt Australien zugleich, es lasse sich nichts "diktieren", und ein neuer Premierminister der Salomonen leitet die Überprüfung des von seinem Vorgänger mit Peking geschlossenen Geheimpakts ein. Die Berichterstattung trennt sich klar nach Medium: australische und westliche Medien deuten die Pakte als freie Entscheidung der Inselstaaten für Transparenz statt chinesischer Stützpunkte, während chinesische Staatsmedien dasselbe Engagement als gewöhnliche Kooperation darstellen, die "kein Drittland ins Visier nehmen" solle, und australische Berichte als Panikmache eines ausgrenzenden Denkens abtun. Eine dritte Stimme — das Beharren der Inseln, keinem Lager zu gehören — ist hörbar, im Korpus aber noch dünn.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('pakistan_afghanistan_border','Pakistan-Afghanistan border conflict','Grenzkonflikt zwischen Pakistan und Afghanistan','Armed conflict along and across the Durand Line, the frontier between Pakistan and Afghanistan that Kabul has never formally recognised. Pakistan conducts air strikes on targets in Kabul, Kandahar, Nangarhar and the eastern provinces, stating that they hit Tehreek-e-Taliban sanctuaries; the Taliban government reports civilian casualties, including a strike on a Kabul hospital, and claims retaliatory strikes inside Pakistan. Ground clashes recur around border crossings and checkposts, and successive short ceasefires have lapsed.','Bewaffneter Konflikt entlang und über die Durand-Linie hinweg, die Grenze zwischen Pakistan und Afghanistan, die Kabul nie förmlich anerkannt hat. Pakistan fliegt Luftangriffe auf Ziele in Kabul, Kandahar, Nangarhar und den östlichen Provinzen und erklärt, diese träfen Rückzugsgebiete der Tehreek-e-Taliban; die Taliban-Regierung meldet zivile Opfer, darunter einen Angriff auf ein Krankenhaus in Kabul, und gibt Vergeltungsangriffe in Pakistan an. An Grenzübergängen und Kontrollposten kommt es wiederholt zu Bodengefechten, und aufeinanderfolgende kurze Waffenruhen sind gescheitert.',ARRAY['ASIA-PAKISTAN'],true,61,'The Pakistan-Afghanistan border is the most active conflict in this theater by coverage volume. Pakistan states that its strikes target Tehreek-e-Taliban fighters who cross from Afghan territory to attack Pakistani forces and civilians, and that it acted after demands for verifiable measures went unanswered. The Taliban government accuses Pakistan of war crimes and of killing civilians, reports several hundred dead in a strike on a Kabul hospital, and says Afghan forces have struck military positions inside Pakistan. Both defence ministries have used the language of open war. Third states including China and Türkiye have offered to broker a ceasefire, and India has condemned the strikes as an assault on Afghan sovereignty. Coverage peaks with each round of strikes and subsides between them.','Die pakistanisch-afghanische Grenze ist gemessen am Berichterstattungsvolumen der aktivste Konflikt dieses Schauplatzes. Pakistan erklärt, seine Angriffe zielten auf Kämpfer der Tehreek-e-Taliban, die von afghanischem Gebiet aus pakistanische Sicherheitskräfte und Zivilisten angreifen, und es habe gehandelt, nachdem Forderungen nach überprüfbaren Maßnahmen unbeantwortet blieben. Die Taliban-Regierung wirft Pakistan Kriegsverbrechen und die Tötung von Zivilisten vor, meldet mehrere Hundert Tote bei einem Angriff auf ein Krankenhaus in Kabul und gibt an, afghanische Kräfte hätten Militärstellungen in Pakistan getroffen. Beide Verteidigungsministerien haben von offenem Krieg gesprochen. Drittstaaten wie China und die Türkei boten Vermittlung an, und Indien verurteilte die Angriffe als Verletzung der afghanischen Souveränität. Die Berichterstattung erreicht mit jeder Angriffswelle Spitzenwerte und geht dazwischen zurück.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-AFGHANISTAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('panama_canal_theater','US-China confrontation over the Panama Canal','US-chinesische Konfrontation um den Panamakanal','Port seizures, Chinese retaliation threats and transit politics have made the canal a front line of hemispheric great-power competition.','Hafenuebernahmen, chinesische Vergeltungsdrohungen und Transitpolitik haben den Kanal zu einer Frontlinie des hemisphaerischen Grossmachtwettbewerbs gemacht.',ARRAY['AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA'],false,NULL,NULL,NULL,'theater',ARRAY['panama_ports_dispute','panama_canal_transit_security'],ARRAY['panama_canal','colon_port'],'regional','{"type": "Point", "coordinates": [-79.6, 9.0]}'::jsonb,'AMERICAS-CENTRAL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('panama_canal_transit_security','Canal transit security and neutrality','Transitsicherheit und Neutralitaet des Kanals','Ship-detention accusations, neutrality-treaty politics and the canal''s exposure to US-China escalation and drought-driven capacity limits.','Vorwuerfe von Schiffsfestsetzungen, Neutralitaetsvertragspolitik und die Anfaelligkeit des Kanals fuer US-chinesische Eskalation und duerrebedingte Kapazitaetsgrenzen.',ARRAY['AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA'],false,NULL,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CENTRAL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
