  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_airspace_incursions','Airspace incursions and NATO air-defence on the Eastern flank','Luftraumverletzungen und NATO-Luftverteidigung an der Ostflanke','Incidents of drones and aircraft entering NATO airspace along the eastern flank, and the alliance''s air-defence response: scrambles, intercepts, national airspace closures, and debate over Article 4 consultations and shoot-down authority. The same airspace is also the subject of Russian claims that NATO and Baltic states allow Ukrainian drone operations to transit or launch from their territory.','Vorfälle, bei denen Drohnen und Flugzeuge entlang der Ostflanke in den NATO-Luftraum eindringen, sowie die Luftverteidigungsreaktion des Bündnisses: Abfangeinsätze, Luftraumsperrungen einzelner Staaten sowie die Debatte über Artikel-4-Konsultationen und Abschussbefugnis. Derselbe Luftraum ist zugleich Gegenstand russischer Behauptungen, NATO- und baltische Staaten ließen ukrainische Drohnenoperationen von ihrem Gebiet aus starten oder durchqueren.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC','EUROPE-BALKANS-EAST'],true,NULL,'Western-mainstream and Baltic/Nordic coverage treats repeated incursions as deliberate Russian probing requiring a firm response, including shoot-down authority. Russian and allied state media invert the story, accusing NATO and Baltic states of enabling Ukrainian drone strikes and casting Russian countermeasures as legitimate self-defence. A smaller Western-European current warns that shoot-down authority over ambiguous contacts risks uncontrolled escalation, and that some incidents may be accidental.','Die westliche Mainstream- und baltisch-nordische Berichterstattung behandelt wiederholte Einbrüche als gezielte russische Tests, die eine entschlossene Antwort einschließlich Abschussbefugnis erfordern. Russische und verbündete Staatsmedien kehren die Erzählung um, werfen NATO- und baltischen Staaten vor, ukrainische Drohnenangriffe zu ermöglichen, und stellen russische Gegenmaßnahmen als legitime Selbstverteidigung dar. Eine kleinere westeuropäische Strömung warnt, dass Abschussbefugnis gegenüber mehrdeutigen Kontakten unkontrollierte Eskalation riskiert und manche Vorfälle unfallbedingt sein könnten.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_europe_theater','Russia-Europe confrontation','Russland-Europa-Konfrontation','The confrontation between Russia and European states and institutions outside the direct Ukraine battlefield: NATO military posture on the eastern flank, below-threshold gray-zone activity, contested airspace over NATO territory, and the sanctions regime imposed on Russia since 2022. Participants include Russia, NATO and EU member states along the eastern flank (Baltic, Nordic, Visegrad), Germany, France, the UK, and the United States.','Die Konfrontation zwischen Russland und europäischen Staaten und Institutionen außerhalb des unmittelbaren Kriegsschauplatzes in der Ukraine: militärische Präsenz der NATO an der Ostflanke, Aktivität unterhalb der Kriegsschwelle in der Grauzone, umstrittener Luftraum über NATO-Gebiet und das seit 2022 gegen Russland verhängte Sanktionsregime. Beteiligte sind Russland, NATO- und EU-Mitgliedstaaten entlang der Ostflanke (Baltikum, Norden, Visegrad-Staaten), Deutschland, Frankreich, das Vereinigte Königreich und die Vereinigten Staaten.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC','AMERICAS-USA','EUROPE-BALKANS-EAST'],true,7,'The theater spans four atomic frictions: NATO-Russia military deterrence, hybrid and gray-zone operations, airspace incursions, and the sanctions regime. Western-mainstream coverage treats these as complementary parts of one response to sustained Russian pressure. Russian and allied state media treat the same events as manufactured or self-inflicted, produced by NATO encirclement and Western economic self-harm rather than genuine Russian aggression. A third, smaller current within Western-European press is critical of aspects of the Western response itself -- threat inflation, over-attribution, escalation risk -- without endorsing the Russian counter-frame.','Das Theater umfasst vier atomare Reibungspunkte: militärische Abschreckung zwischen NATO und Russland, hybride Operationen in der Grauzone, Luftraumverletzungen und das Sanktionsregime. Die westliche Mainstream-Berichterstattung behandelt diese als sich ergänzende Teile einer Antwort auf anhaltenden russischen Druck. Russische und verbündete Staatsmedien behandeln dieselben Ereignisse als konstruiert oder selbstverschuldet, verursacht durch NATO-Einkreisung und westliche wirtschaftliche Selbstschädigung statt durch echte russische Aggression. Eine dritte, kleinere Strömung innerhalb der westeuropäischen Presse steht Teilen der westlichen Reaktion selbst kritisch gegenüber -- Bedrohungsinflation, Über-Attribution, Eskalationsrisiko --, ohne den russischen Gegenframe zu teilen.','theater',ARRAY['russia_nato_deterrence','russia_hybrid_warfare','russia_airspace_incursions','russia_sanctions_regime'],ARRAY['druzhba_pipeline_west','turkstream','danish_straits'],'regional','{"type": "Point", "coordinates": [20.5, 54.7]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_gas_leverage','Russian gas leverage and energy security',NULL,NULL,NULL,ARRAY['EUROPE-RUSSIA','NON-STATE-EU','AMERICAS-USA'],false,27,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_hybrid_warfare','Russian hybrid and gray-zone operations against Europe','Russische hybride Kriegsführung gegen Europa','Below-threshold gray-zone activity attributed to Russia in the Baltic and North Sea region and beyond: undersea cable and pipeline sabotage, GPS jamming and spoofing, shadow-fleet tanker operations evading sanctions, and espionage. Named incidents include the Nord Stream pipeline sabotage, the Eagle S cable-damage case, and the Druzhba pipeline.','Aktivität unterhalb der Kriegsschwelle in der Grauzone, die Russland im Ostsee- und Nordseeraum sowie darüber hinaus zugeschrieben wird: Sabotage an Unterseekabeln und Pipelines, GPS-Störung und Spoofing, Schattenflotten-Tankerbetrieb zur Sanktionsumgehung sowie Spionage. Zu den benannten Vorfällen zählen die Nord-Stream-Pipeline-Sabotage, der Eagle-S-Kabelschadensfall und die Druzhba-Pipeline.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC','EUROPE-BALKANS-EAST'],true,NULL,'Western-mainstream and Baltic/Nordic coverage treats the pattern of sabotage, jamming and shadow-fleet activity as a coordinated Russian gray-zone campaign requiring attribution and hardened defences. Russian and allied state media dismiss the same incidents as evidence-free Russophobia, casting shadow-fleet enforcement as maritime piracy. A smaller Western-European current cautions against over-attribution, noting some incidents may be accidents or unrelated criminality.','Die westliche Mainstream- und baltisch-nordische Berichterstattung behandelt das Muster aus Sabotage, Störung und Schattenflotten-Aktivität als koordinierte russische Grauzonen-Kampagne, die Attribution und gehärtete Abwehr erfordert. Russische und verbündete Staatsmedien weisen dieselben Vorfälle als beweisfreie Russophobie zurück und stellen die Durchsetzung gegen die Schattenflotte als Piraterie dar. Eine kleinere westeuropäische Strömung warnt vor Über-Attribution und weist darauf hin, dass manche Vorfälle Unfälle oder unabhängige Kriminalität sein könnten.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_nato_deterrence','NATO-Russia military deterrence on Eastern flank','NATO-Russland-Abschreckung an der Ostflanke','NATO military posture on its eastern flank facing Russia: enhanced Forward Presence brigades in the Baltic states, forward air policing near Kaliningrad and the Suwalki corridor, rearmament and rising defence budgets, reintroduced conscription in several states, and named exercises such as Steadfast Defender and Baltic Sentry.','Die militärische Präsenz der NATO an ihrer Ostflanke gegenüber Russland: verstärkte Vornepräsenz-Brigaden in den baltischen Staaten, vorwärtige Luftpolizei nahe Kaliningrad und dem Suwalki-Korridor, Aufrüstung und steigende Verteidigungsbudgets, wiedereingeführte Wehrpflicht in mehreren Staaten sowie benannte Übungen wie Steadfast Defender und Baltic Sentry.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC','AMERICAS-USA','EUROPE-BALKANS-EAST'],true,24,'Western-mainstream coverage treats the build-up as proportionate deterrence against a persistent Russian military threat. Russian and allied state media treat the same build-up as aggressive NATO encirclement driving escalation. A smaller Western-European current questions whether rearmament and war-economy drift have become disproportionate to the near-term threat.','Die westliche Mainstream-Berichterstattung behandelt den Ausbau als angemessene Abschreckung gegen eine anhaltende russische Bedrohung. Russische und verbündete Staatsmedien behandeln denselben Ausbau als aggressive NATO-Einkreisung, die Eskalation treibt. Eine kleinere westeuropäische Strömung stellt infrage, ob Aufrüstung und Kriegswirtschafts-Drift gegenüber der kurzfristigen Bedrohung unverhältnismäßig geworden sind.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_sanctions_economy','Sanctions regime and economic impact',NULL,NULL,NULL,ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-UK','NON-STATE-EU'],false,25,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('russia_sanctions_regime','Russia sanctions regime','Russland-Sanktionsregime','Sanctions architecture imposed on Russia following the 2022 invasion: G7 oil price cap, EU sanctions packages (now in the high teens), frozen Russian sovereign assets (~$300B held primarily by Euroclear), REPO Act provisions, secondary sanctions on third-country evaders, shadow-fleet enforcement, SDN designations of oligarchs and entities, and Russian counter-measures (currency controls, gold reserves, BRICS settlement).','Sanktionsarchitektur gegen Russland seit der Invasion 2022: G7-Oelpreisdeckel, EU-Sanktionspakete (jetzt im hohen zweistelligen Bereich), eingefrorenes russisches Staatsvermoegen (~300 Mrd. USD, hauptsaechlich bei Euroclear), REPO-Act-Bestimmungen, Sekundaersanktionen gegen Umgeher in Drittstaaten, Schatten-Flotten-Durchsetzung, SDN-Listungen von Oligarchen und Unternehmen sowie russische Gegenmassnahmen (Waehrungskontrollen, Goldreserven, BRICS-Abwicklung).',ARRAY['EUROPE-RUSSIA','NON-STATE-EU'],true,55,'Sanctions framing is the third major axis of the Ukraine war contest. Tighten-and-seize framing (Ukrainian + Western mainstream + Eastern European) treats sanctions as a necessary economic constraint on the Russian war machine, calls for closing evasion loopholes (especially via UAE / Turkey / Central Asia), supports outright seizure of frozen sovereign assets for Ukrainian reconstruction, and frames any sanctions relief as rewarding aggression. Sanctions-ineffective framing (Russian state + Global South + some Chinese state + Hungarian-aligned EU) argues that sanctions have hurt European economies more than the Russian, that the Russian economy has adapted, that frozen-asset seizure would destroy trust in the Western financial system, and that the package should be wound down as part of any peace deal.','Sanktions-Rahmung ist die dritte Hauptachse des Ukraine-Krieg-Wettstreits. Verschaerfen-und-Beschlagnahmen-Rahmung (ukrainisch + westlicher Mainstream + Osteuropa) behandelt Sanktionen als notwendige wirtschaftliche Beschraenkung der russischen Kriegsmaschine, fordert Schliessung von Umgehungsluecken (besonders ueber VAE / Tuerkei / Zentralasien), unterstuetzt direkte Beschlagnahme eingefrorenen Staatsvermoegens fuer ukrainischen Wiederaufbau und rahmt jede Sanktionserleichterung als Belohnung von Aggression. Sanktionen-wirkungslos-Rahmung (russische Staatsmedien + Global South + einige chinesische Staatsmedien + ungarisch-orientierte EU) argumentiert, Sanktionen haetten europaeische Wirtschaften staerker geschaedigt als die russische, die russische Wirtschaft habe sich angepasst, Beschlagnahme eingefrorenen Vermoegens wuerde Vertrauen in das westliche Finanzsystem zerstoeren und das Paket sollte als Teil eines Friedensdeals abgewickelt werden.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_france_rupture','Rupture with France','Bruch mit Frankreich','The breakdown of relations between France and the Sahel states: severed diplomatic ties, expelled or withdrawn diplomats, prosecutions of French nationals on security charges, and the colonial-legacy arguments advanced on both sides.','Der Zusammenbruch der Beziehungen zwischen Frankreich und den Sahelstaaten: abgebrochene diplomatische Beziehungen, ausgewiesene oder abgezogene Diplomaten, Strafverfahren gegen französische Staatsangehörige wegen Sicherheitsdelikten und die auf beiden Seiten vorgebrachten Argumente zum kolonialen Erbe.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],true,105,'Burkina Faso broke off diplomatic relations with France and Paris called the move hostile; France withdrew its diplomats. A French intelligence officer was sentenced to twenty years in Bamako for offences against state security, a charge Paris rejects. Niger''s leadership publicly blamed France for the jihadist assault on Niamey airport, and France advised its nationals to leave Mali.','Burkina Faso brach die diplomatischen Beziehungen zu Frankreich ab; Paris nannte den Schritt feindselig und zog seine Diplomaten ab. Ein französischer Nachrichtendienstoffizier wurde in Bamako wegen Straftaten gegen die Staatssicherheit zu zwanzig Jahren verurteilt -- ein Vorwurf, den Paris zurückweist. Nigers Führung machte Frankreich öffentlich für den dschihadistischen Angriff auf den Flughafen von Niamey verantwortlich, und Frankreich empfahl seinen Staatsangehörigen, Mali zu verlassen.','atomic',NULL,'{}','regional',NULL::jsonb,'AFRICA-SAHEL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_french_withdrawal','Post-French security vacuum and great power competition',NULL,NULL,NULL,ARRAY['AFRICA-SAHEL','EUROPE-FRANCE','AMERICAS-USA','EUROPE-RUSSIA'],false,79,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_jihadist_insurgency','Jihadist insurgency and territorial contest','Dschihadistischer Aufstand und territorialer Wettstreit','Operations by jihadist armed groups across the Sahel and the Lake Chad basin -- JNIM, Islamic State affiliates, Boko Haram and ISWAP -- and the counterinsurgency campaigns waged against them by national armies and their foreign partners, including the civilian toll of both.','Operationen dschihadistischer bewaffneter Gruppen in der Sahelzone und im Tschadseebecken -- JNIM, Ableger des Islamischen Staats, Boko Haram und ISWAP -- sowie die Aufstandsbekämpfung durch nationale Armeen und ihre ausländischen Partner, einschließlich der zivilen Opfer beider Seiten.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA','NON-STATE-JIHADISTS','NON-STATE-BOKO-HARAM'],true,101,'The largest node in the theater. In 2026 JNIM moved from rural control to pressure on capitals, blockading Bamako''s fuel supply and mounting coordinated raids on multiple cities; Islamic State claimed an assault on Niamey''s airport. In the Lake Chad basin, Boko Haram and ISWAP continued mass abductions and attacks on military positions. Rights monitors and Amnesty documented large civilian death tolls from army airstrikes on both sides of the Nigeria-Sahel divide.','Der größte Knoten des Theaters. 2026 ging JNIM von der Kontrolle ländlicher Räume zum Druck auf Hauptstädte über, blockierte Bamakos Treibstoffversorgung und führte koordinierte Angriffe auf mehrere Städte; der Islamische Staat reklamierte einen Angriff auf den Flughafen von Niamey. Im Tschadseebecken setzten Boko Haram und ISWAP Massenentführungen und Angriffe auf Militärstellungen fort. Menschenrechtsbeobachter und Amnesty dokumentierten hohe zivile Opferzahlen durch Luftangriffe der Armeen auf beiden Seiten der nigerianisch-sahelischen Grenze.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_junta_consolidation','Junta consolidation and sovereigntist realignment','Junta-Konsolidierung und souveränistische Neuausrichtung','How the military governments that took power in Mali, Burkina Faso, Niger and Guinea consolidate control -- party bans, media suspensions, treatment of international bodies and postponed transitions -- and the sovereigntist doctrine they advance to justify it.','Wie die Militärregierungen, die in Mali, Burkina Faso, Niger und Guinea die Macht übernahmen, ihre Kontrolle festigen -- Parteiverbote, Mediensperren, der Umgang mit internationalen Institutionen und verschobene Übergänge -- und die souveränistische Doktrin, mit der sie dies begründen.',ARRAY['AFRICA-SAHEL'],true,103,'Burkina Faso dissolved all political parties and Guinea dissolved forty, including the main opposition. Niger withdrew from the International Criminal Court, describing it as an instrument of neocolonial repression, and suspended French media outlets. The UN human-rights office in Burkina Faso closed after being suspended. Mali''s leadership assumed the defence portfolio directly after the minister was killed.','Burkina Faso löste sämtliche politischen Parteien auf, Guinea vierzig, darunter die wichtigste Opposition. Niger trat aus dem Internationalen Strafgerichtshof aus, den es als Instrument neokolonialer Repression bezeichnete, und suspendierte französische Medien. Das UN-Menschenrechtsbüro in Burkina Faso schloss nach seiner Suspendierung. Malis Führung übernahm das Verteidigungsressort direkt, nachdem der Minister getötet worden war.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_security_patron_contest','Contest for security patronage','Wettstreit um die Sicherheitspatronage','The competition to supply the Sahel states with security assistance after the departure of French and UN forces: Russia''s Africa Corps, Turkish drones and training, renewed United States engagement, and Moroccan offers of Atlantic access to the landlocked members of the Alliance of Sahel States.','Der Wettstreit um Sicherheitsunterstützung für die Sahelstaaten nach dem Abzug französischer und UN-Kräfte: Russlands Africa Corps, türkische Drohnen und Ausbildung, erneutes Engagement der Vereinigten Staaten sowie marokkanische Angebote eines Atlantikzugangs für die Binnenstaaten der Allianz der Sahelstaaten.',ARRAY['AFRICA-SAHEL'],true,104,'The smallest node in the theater by volume but a persistent one. Africa Corps confirmed its withdrawal from Kidal, took casualties in rebel attacks and was reported retreating under jihadist pressure, while Moscow said its forces would stay in Mali and had helped stop an attempted coup. Niger''s president was received in Ankara as Türkiye expanded its training and drone footprint.','Der volumenmäßig kleinste, aber beständige Knoten des Theaters. Das Africa Corps bestätigte seinen Rückzug aus Kidal, erlitt Verluste bei Rebellenangriffen und wich Berichten zufolge unter dschihadistischem Druck zurück, während Moskau erklärte, seine Kräfte blieben in Mali und hätten geholfen, einen Putschversuch zu stoppen. Nigers Präsident wurde in Ankara empfangen, während die Türkei ihre Ausbildungs- und Drohnenpräsenz ausweitete.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_theater','Sahel military transition zone','Militärische Übergangszone Sahel','The Sahel and Lake Chad basin as a single conflict zone: jihadist insurgency, Tuareg separatism in northern Mali, military governments consolidating power after successive coups, the competition to replace France as the region''s security patron, and the rupture of relations with Paris.','Die Sahelzone und das Tschadseebecken als zusammenhängende Konfliktzone: dschihadistischer Aufstand, Tuareg-Separatismus in Nordmali, Militärregierungen, die nach aufeinanderfolgenden Putschen ihre Macht festigen, der Wettstreit um Frankreichs Nachfolge als Sicherheitspatron der Region und der Bruch der Beziehungen zu Paris.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE','EUROPE-RUSSIA','AMERICAS-USA'],true,22,'Coverage in the first half of 2026 is dominated by a single sequence: a coordinated JNIM and Tuareg offensive that killed Mali''s defence minister, blockaded Bamako and took Kidal, while Russia''s Africa Corps withdrew from the town it had helped hold. Around it sit the Lake Chad war against Boko Haram and ISWAP, party dissolutions in Burkina Faso and Niger''s exit from the ICC, and Burkina Faso''s severing of diplomatic relations with France.','Die Berichterstattung im ersten Halbjahr 2026 wird von einer einzigen Abfolge bestimmt: eine koordinierte Offensive von JNIM und Tuareg-Verbänden, die Malis Verteidigungsminister tötete, Bamako blockierte und Kidal einnahm, während sich Russlands Africa Corps aus der Stadt zurückzog, die es hatte halten helfen. Daneben stehen der Krieg am Tschadsee gegen Boko Haram und ISWAP, Parteiauflösungen in Burkina Faso, Nigers Austritt aus dem Internationalen Strafgerichtshof und der Abbruch der diplomatischen Beziehungen Burkina Fasos zu Frankreich.','theater',ARRAY['sahel_jihadist_insurgency','sahel_tuareg_separatism','sahel_junta_consolidation','sahel_security_patron_contest','sahel_france_rupture'],ARRAY['niger_delta_basin'],'regional','{"type": "Point", "coordinates": [0.9, 14.4]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_tuareg_separatism','Tuareg separatism and the northern Mali question','Tuareg-Separatismus und die Frage Nordmalis','The unresolved status of northern Mali and the Tuareg-led armed movements that claim it, including their control of Kidal and their relations with both the central government and the jihadist groups operating in the same territory.','Der ungeklärte Status Nordmalis und die tuareg-geführten bewaffneten Bewegungen, die ihn beanspruchen -- einschließlich ihrer Kontrolle über Kidal und ihres Verhältnisses sowohl zur Zentralregierung als auch zu den im selben Gebiet operierenden dschihadistischen Gruppen.',ARRAY['AFRICA-SAHEL'],true,102,'Tuareg formations took full control of Kidal in 2026 after an arrangement under which Russian forces withdrew from the town, and declared that the government in Bamako would fall. They claimed coordinated attacks jointly with JNIM -- a tactical alignment between a secular separatist movement and an al-Qaeda affiliate that both Bamako and Moscow cite as grounds to treat the two as one.','Tuareg-Verbände übernahmen 2026 die vollständige Kontrolle über Kidal, nachdem sich russische Kräfte im Rahmen einer Vereinbarung aus der Stadt zurückgezogen hatten, und erklärten, die Regierung in Bamako werde fallen. Sie reklamierten koordinierte Angriffe gemeinsam mit JNIM -- eine taktische Annäherung zwischen einer säkularen Separatistenbewegung und einem al-Qaida-Ableger, die Bamako wie Moskau als Grund anführen, beide als eines zu behandeln.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
