  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('senkaku_diaoyu_islands','Senkaku/Diaoyu islands and East China Sea maritime friction','Senkaku/Diaoyu-Inseln und maritime Spannungen im Ostchinesischen Meer','The territorial dispute over the Senkaku Islands, administered by Japan and known in China as the Diaoyu Islands, and the surrounding waters of the East China Sea. Covers China Coast Guard patrols and vessel movements in and near Japan''s territorial waters and exclusive economic zone around the islands, and related maritime activity including survey vessels and undersea drilling structures.','Der Territorialstreit um die Senkaku-Inseln, die von Japan verwaltet werden und in China als Diaoyu-Inseln bekannt sind, sowie die umliegenden Gewässer des Ostchinesischen Meeres. Umfasst Patrouillen und Schiffsbewegungen der chinesischen Küstenwache in und nahe Japans Hoheitsgewässern und ausschließlicher Wirtschaftszone um die Inseln sowie damit verbundene maritime Aktivitäten wie Forschungsschiffe und Unterwasser-Bohrstrukturen.',ARRAY['ASIA-CHINA'],true,68,'The Senkaku Islands, a small uninhabited island group in the East China Sea, have been administered by Japan since 1972 and are also claimed by China, which calls them the Diaoyu Islands, and by Taiwan. China Coast Guard vessels regularly enter the contiguous zone and, at intervals, the territorial waters around the islands; Japan''s coast guard tracks these vessels and at times acts to expel them. The dispute also extends to the wider East China Sea, where the two countries'' exclusive economic zone claims overlap and where survey vessels, fishing activity and gas-field infrastructure near the median line have periodically drawn protest from Japan. The islands lie near Japan''s Yonaguni and Ishigaki islands, within the broader geography of the first island chain.','Die Senkaku-Inseln, eine kleine unbewohnte Inselgruppe im Ostchinesischen Meer, werden seit 1972 von Japan verwaltet und werden zugleich von China, das sie Diaoyu-Inseln nennt, sowie von Taiwan beansprucht. Schiffe der chinesischen Küstenwache fahren regelmäßig in die Anschlusszone und zeitweise in die Hoheitsgewässer um die Inseln ein; Japans Küstenwache verfolgt diese Schiffe und schreitet mitunter ein, um sie zu vertreiben. Der Streit erstreckt sich zudem auf das weitere Ostchinesische Meer, wo sich die Ansprüche beider Länder auf die ausschließliche Wirtschaftszone überschneiden und wo Forschungsschiffe, Fischereiaktivitäten und Gasfeld-Infrastruktur nahe der Mittellinie wiederholt Proteste Japans ausgelöst haben. Die Inseln liegen nahe den japanischen Inseln Yonaguni und Ishigaki, innerhalb der weiteren Geografie der Ersten Inselkette.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-JAPAN')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('slovakia_alignment','Slovakia sovereignty and realignment pressures',NULL,NULL,NULL,ARRAY['EUROPE-VISEGRAD','NON-STATE-EU','EUROPE-RUSSIA'],false,33,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('somalia_state_security','Somali state security and coastal control','Somalias Staatssicherheit und Kontrolle der Küste','The Somali federal government is contesting control of its territory and coastline simultaneously: an insurgency by al-Shabaab, a peacekeeping mission facing a funding crisis, disputed federal elections that have produced armed clashes in Mogadishu, and a resurgence of piracy off the eastern seaboard. Turkey, the United States, Egypt and Gulf states are all engaged.','Die somalische Bundesregierung ringt gleichzeitig um die Kontrolle über ihr Territorium und ihre Küste: ein Aufstand von al-Shabaab, eine Friedensmission in der Finanzierungskrise, umstrittene Bundeswahlen mit bewaffneten Zusammenstößen in Mogadischu und ein Wiederaufleben der Piraterie vor der Ostküste. Die Türkei, die USA, Ägypten und Golfstaaten sind engagiert.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY','AMERICAS-USA'],true,76,'Deliberately a broad slice: insurgency, the AU mission, the election crisis and piracy are one story about state capacity, not four separate ones.','Bewusst breit geschnitten: Aufstand, AU-Mission, Wahlkrise und Piraterie sind eine einzige Geschichte über staatliche Handlungsfähigkeit, nicht vier getrennte.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('somaliland_recognition_contest','Somaliland recognition contest','Der Streit um die Anerkennung Somalilands','Somaliland declared independence from Somalia in 1991 and has governed itself since without broad international recognition. Israel''s recognition and exchange of ambassadors, alongside discussions of port access, critical minerals and military basing, has made its status an active international dispute involving Somalia, the African Union, Arab and Muslim states, Turkey and the United States.','Somaliland erklärte 1991 seine Unabhängigkeit von Somalia und regiert sich seither selbst, ohne breite internationale Anerkennung. Israels Anerkennung und der Austausch von Botschaftern haben den Status -- zusammen mit Gesprächen über Hafenzugang, kritische Rohstoffe und Militärstützpunkte -- zu einem aktiven internationalen Konflikt gemacht, an dem Somalia, die Afrikanische Union, arabische und muslimische Staaten, die Türkei und die USA beteiligt sind.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL','AMERICAS-USA','MIDEAST-EGYPT','MIDEAST-TURKEY'],true,74,'The single largest strand of Horn coverage in 2026, and the one that pulls the most outside powers in.','Der mit Abstand größte Berichterstattungsstrang am Horn im Jahr 2026 -- und derjenige, der die meisten auswärtigen Mächte einbezieht.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('south_asia_theater','South Asia contested borders','Umstrittene Grenzen in Südasien','The contested borders of South Asia, where two nuclear-armed states and their neighbours dispute territory, water and responsibility for cross-border violence. Five fault lines run through it: the air campaign and border clashes between Pakistan and Afghanistan along the Durand Line; the Kashmir territorial dispute between India and Pakistan; the separatist insurgency in Balochistan; the Indus Waters Treaty, suspended by India and contested by Pakistan; and the militant attacks that each state attributes to the other. Pakistan is a party to four of the five.','Die umstrittenen Grenzen Südasiens, wo zwei Atommächte und ihre Nachbarn über Territorium, Wasser und die Verantwortung für grenzüberschreitende Gewalt streiten. Fünf Bruchlinien durchziehen die Region: die Luftangriffe und Grenzgefechte zwischen Pakistan und Afghanistan entlang der Durand-Linie; der Territorialstreit um Kaschmir zwischen Indien und Pakistan; der separatistische Aufstand in Belutschistan; der von Indien ausgesetzte und von Pakistan angefochtene Indus-Wasservertrag; sowie die militanten Anschläge, die jeder Staat dem anderen zuschreibt. Pakistan ist an vier der fünf Konflikte beteiligt.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN','ASIA-AFGHANISTAN'],true,17,'South Asia''s frictions are organised around Pakistan, which is a party to four of the theater''s five fault lines. The largest by volume is the conflict with Afghanistan: cross-border air strikes, clashes along the Durand Line, and short ceasefires that have repeatedly lapsed, with both governments describing the relationship in terms of open war. The India-Pakistan relationship is in a post-conflict phase a year after a ceasefire ended open hostilities; its live threads are the suspended Indus Waters Treaty, a recurring airspace ban, disputed responsibility for the Pahalgam attack, and sovereignty claims exchanged at the United Nations. Inside Pakistan, the Balochistan insurgency continues, with Islamabad attributing the attacks to Indian backing and India rejecting the charge. The India-China border, by contrast, has been quiet: talks on delimitation have resumed and Ladakh coverage has largely moved to domestic Indian politics.','Die Reibungspunkte Südasiens ordnen sich um Pakistan, das an vier der fünf Bruchlinien des Schauplatzes beteiligt ist. Am umfangreichsten ist der Konflikt mit Afghanistan: grenzüberschreitende Luftangriffe, Gefechte entlang der Durand-Linie und kurze Waffenruhen, die wiederholt scheiterten, wobei beide Regierungen das Verhältnis als offenen Krieg bezeichnen. Das indisch-pakistanische Verhältnis befindet sich ein Jahr nach einer Waffenruhe, die offene Feindseligkeiten beendete, in einer Nachkriegsphase; aktuelle Themen sind der ausgesetzte Indus-Wasservertrag, ein wiederholt verlängertes Überflugverbot, die umstrittene Verantwortung für den Anschlag von Pahalgam und vor den Vereinten Nationen ausgetauschte Souveränitätsansprüche. Innerhalb Pakistans dauert der Aufstand in Belutschistan an, wobei Islamabad die Anschläge indischer Unterstützung zuschreibt und Indien dies zurückweist. Die indisch-chinesische Grenze ist dagegen ruhig: Gespräche über den Grenzverlauf wurden wieder aufgenommen, und die Berichterstattung über Ladakh betrifft überwiegend die indische Innenpolitik.','theater',ARRAY['pakistan_afghanistan_border','kashmir_dispute','balochistan_insurgency','indus_water_sharing','india_pakistan_militancy'],ARRAY['tarbela_dam'],'regional','{"type": "Point", "coordinates": [71.5, 33.0]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('south_china_sea_claims','South China Sea territorial and maritime disputes','Territorial- und Seerechtskonflikte im Südchinesischen Meer','China, the Philippines, Vietnam, Malaysia, Brunei, Indonesia and Taiwan hold overlapping territorial and maritime claims in the South China Sea. China''s claim, drawn as the nine-dash line, covers most of the sea and overlaps exclusive economic zones claimed by the other parties. An arbitral tribunal constituted under the UN Convention on the Law of the Sea ruled in 2016 that the line has no legal basis; China does not recognise the ruling. Several claimants occupy features in the Spratly and Paracel groups, and some have built installations on them. Coast guard, naval, militia and fishing vessels operate in contested waters, and encounters occur around features including Scarborough Shoal, Second Thomas Shoal and Reed Bank. The United States and other states outside the dispute conduct naval and air operations in the sea and hold exercises with claimant states. China and ASEAN have negotiated a code of conduct for the sea since 2002. Roughly a third of global shipping transits the sea, and the seabed holds oil, gas and fishing grounds.','China, die Philippinen, Vietnam, Malaysia, Brunei, Indonesien und Taiwan erheben einander überlappende Territorial- und Seerechtsansprüche im Südchinesischen Meer. Chinas Anspruch, als Neun-Striche-Linie gezogen, umfasst den größten Teil des Meeres und überlappt die von den anderen Parteien beanspruchten ausschließlichen Wirtschaftszonen. Ein nach dem UN-Seerechtsübereinkommen gebildetes Schiedsgericht entschied 2016, dass die Linie keine Rechtsgrundlage hat; China erkennt den Schiedsspruch nicht an. Mehrere Anrainer besetzen Formationen der Spratly- und Paracel-Gruppen, einige haben dort Anlagen errichtet. Küstenwach-, Marine-, Milizen- und Fischereifahrzeuge operieren in umstrittenen Gewässern; Begegnungen ereignen sich unter anderem am Scarborough-Riff, am Second-Thomas-Riff und an der Reed Bank. Die USA und weitere nicht am Streit beteiligte Staaten führen Marine- und Lufteinsätze im Meer durch und halten Manöver mit Anrainerstaaten ab. China und die ASEAN verhandeln seit 2002 über einen Verhaltenskodex. Etwa ein Drittel des weltweiten Seehandels passiert das Meer; der Meeresboden birgt Öl-, Gas- und Fischereivorkommen.',ARRAY['ASIA-CHINA','ASIA-SOUTHEAST','AMERICAS-USA'],true,53,'Seven parties hold overlapping claims to the South China Sea, through which roughly a third of global shipping passes. China''s nine-dash line covers most of the sea and overlaps the exclusive economic zones of the other claimants; a 2016 arbitral tribunal under UNCLOS found the line has no legal basis, and China does not recognise that ruling. Claimants occupy and have built on features in the Spratly and Paracel groups, and coast guard, militia and naval vessels meet around Scarborough Shoal, Second Thomas Shoal and Reed Bank. The United States and other non-claimant states operate naval and air forces in the sea and exercise with claimant states, and China and ASEAN have negotiated a code of conduct since 2002. Coverage splits along two lines: Chinese state media present the claims as historic and lawful, the arbitral award as invalid, and coast guard activity as routine law enforcement against Philippine and American provocation; Western, Philippine, Japanese and Southeast Asian press treat the award as binding and Chinese conduct as coercion of smaller claimants, and support allied presence and a binding code of conduct.','Sieben Parteien erheben überlappende Ansprüche auf das Südchinesische Meer, durch das etwa ein Drittel des weltweiten Seehandels läuft. Chinas Neun-Striche-Linie umfasst den größten Teil des Meeres und überlappt die ausschließlichen Wirtschaftszonen der übrigen Anrainer; ein Schiedsgericht nach dem UN-Seerechtsübereinkommen befand 2016, die Linie habe keine Rechtsgrundlage -- China erkennt den Schiedsspruch nicht an. Anrainer besetzen und bebauen Formationen der Spratly- und Paracel-Gruppen; Küstenwach-, Milizen- und Marinefahrzeuge begegnen einander am Scarborough-Riff, am Second-Thomas-Riff und an der Reed Bank. Die USA und weitere nicht beteiligte Staaten operieren mit Marine und Luftwaffe im Meer und üben mit Anrainerstaaten; China und die ASEAN verhandeln seit 2002 über einen Verhaltenskodex. Die Berichterstattung teilt sich in zwei Linien: Chinesische Staatsmedien stellen die Ansprüche als historisch und rechtmäßig dar, den Schiedsspruch als ungültig und die Küstenwacheinsätze als routinemäßige Rechtsdurchsetzung gegen philippinische und amerikanische Provokation. Westliche, philippinische, japanische und südostasiatische Presse hält den Schiedsspruch für bindend, wertet Chinas Vorgehen als Nötigung kleinerer Anrainer und befürwortet alliierte Präsenz und einen verbindlichen Verhaltenskodex.','atomic',NULL,ARRAY['strait_of_malacca','port_of_singapore'],'regional','{"type": "Point", "coordinates": [114.0, 10.0]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('strait_of_hormuz_sovereignty','Strait of Hormuz and Persian Gulf maritime security',NULL,NULL,NULL,ARRAY['MIDEAST-IRAN'],true,3,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sudan_civil_war','Sudan civil war','Sudanesischer Buergerkrieg','The war between the Sudanese army (SAF) under General al-Burhan and the Rapid Support Forces (RSF) paramilitary under Hemedti, ignited 15 April 2023. Coverage clusters around three framings: legitimate-state counter-insurgency, humanitarian / genocide catastrophe (El Fasher, Darfur, Kordofan, hospital strikes, famine), and external-backer contest (UAE accused of arming the RSF, Egypt and Saudi Arabia backing the army).','Der Krieg zwischen der sudanesischen Armee (SAF) unter General al-Burhan und der paramilitaerischen Rapid Support Forces (RSF) unter Hemedti, ausgebrochen am 15. April 2023. Drei Rahmungen: legitime staatliche Aufstandsbekaempfung, humanitaere Katastrophe / Genozid (Al-Faschir, Darfur, Kordofan, Angriffe auf Krankenhaeuser, Hungersnot) und Konflikt um auslaendische Unterstuetzer (Vorwuerfe gegen die VAE wegen Bewaffnung der RSF, Aegypten und Saudi-Arabien hinter der Armee).',ARRAY['MIDEAST-SUDAN','MIDEAST-EGYPT','MIDEAST-GULF','MIDEAST-SAUDI'],true,40,'The Sudan war has produced the world''s largest current displacement crisis (~12M displaced) and a UN-evidenced genocide finding in El Fasher, yet remains underreported. Contest: pan-Arab Egyptian and Saudi outlets emphasise state legitimacy and Brotherhood/Islamist risk inside the army; UN, Western humanitarian and pan-Arab non-aligned outlets emphasise civilian casualties, drone strikes on hospitals, and famine; investigative international and Turkish/Iranian state media critique Gulf and Ethiopian arms flows to the RSF.','Der Sudan-Krieg hat die weltweit groesste aktuelle Vertreibungskrise (~12 Mio.) und einen UN-belegten Genozid-Befund in Al-Faschir hervorgebracht, bleibt aber unterberichtet. Kontest: panarabische aegyptische und saudische Medien betonen Staats-Legitimitaet und Bruderschaft-/Islamisten-Risiko in der Armee; UN, westliche humanitaere und panarabische nicht-ausgerichtete Medien betonen zivile Opfer, Drohnenangriffe auf Krankenhaeuser und Hungersnot; investigative internationale sowie tuerkische und iranische Staatsmedien kritisieren Waffenlieferungen aus dem Golf und Aethiopien an die RSF.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
