INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('syria_theater','Syria in post-Assad transition',NULL,NULL,NULL,ARRAY['MIDEAST-LEVANT','MIDEAST-TURKEY','MIDEAST-ISRAEL','MIDEAST-IRAN','AMERICAS-USA','EUROPE-RUSSIA'],true,3,NULL,NULL,'theater',ARRAY['syria_kurdish_question','syria_israeli_strikes','syria_counter_terror','syria_recognition_and_normalisation'],'{}','regional','{"type": "Point", "coordinates": [36.3, 33.5]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_international_recognition','International recognition and diplomatic status','Internationale Anerkennung und diplomatischer Status','Taiwan''s diplomatic status and its participation in international bodies. Covers its remaining formal diplomatic partners and changes among them; efforts by Beijing to reduce that number and to restrict the travel of Taiwanese officials, including overflight and transit clearances; Taiwan''s exclusion from the World Health Assembly, ICAO and other organisations, and the competing readings of United Nations General Assembly Resolution 2758; representative offices that operate in the absence of formal relations, and the disputes they have triggered; parliamentary visits to Taipei and the responses to them; and the terminology governments and international bodies use for the island.','Taiwans diplomatischer Status und seine Teilhabe an internationalen Gremien. Erfasst die verbliebenen formellen diplomatischen Partner und Veränderungen in deren Kreis; Bemühungen Pekings, diese Zahl zu verringern und Reisen taiwanischer Amtsträger einschließlich Überflug- und Transitgenehmigungen zu beschränken; Taiwans Ausschluss von der Weltgesundheitsversammlung, der ICAO und weiteren Organisationen sowie die konkurrierenden Lesarten der UN-Resolution 2758; Repräsentanzen, die ohne formelle Beziehungen arbeiten, und die dadurch ausgelösten Streitfälle; parlamentarische Besuche in Taipeh und die Reaktionen darauf; sowie die Begriffe, die Regierungen und internationale Gremien für die Insel verwenden.',ARRAY['ASIA-TAIWAN'],true,52,'Taiwan maintains formal diplomatic relations with a small and shrinking number of states, and unofficial relations through representative offices with many more. The contest over both spans pressure on the remaining partners and the periodic switches of recognition; the blocking of Taiwanese leaders'' travel through denied overflight and transit clearances, which has curtailed presidential trips; exclusion from the World Health Assembly and ICAO; and the argument over whether United Nations General Assembly Resolution 2758 settled the island''s status, which Beijing asserts and Taipei and several Western governments dispute. Individual bilateral disputes recur -- Lithuania''s representative office and the trade consequences that followed, an office opened with Somaliland, and the responses to parliamentary delegations visiting Taipei. Naming is itself contested: whether the island is called Taiwan, Chinese Taipei, the Taiwan region or the Republic of China signals a position rather than a neutral choice.','Taiwan unterhält formelle diplomatische Beziehungen zu einer kleinen und schrumpfenden Zahl von Staaten und inoffizielle Beziehungen über Repräsentanzen zu deutlich mehr. Der Wettstreit um beides umfasst den Druck auf die verbliebenen Partner und die zeitweiligen Anerkennungswechsel; die Blockade von Reisen taiwanischer Politiker durch verweigerte Überflug- und Transitgenehmigungen, die Präsidentenreisen beschnitten hat; den Ausschluss von der Weltgesundheitsversammlung und der ICAO; sowie den Streit darüber, ob die UN-Resolution 2758 den Status der Insel geklärt hat, was Peking behauptet und Taipeh sowie mehrere westliche Regierungen bestreiten. Einzelne bilaterale Streitfälle wiederholen sich, etwa Litauens Repräsentanz und die folgenden Handelskonsequenzen. Auch die Benennung ist umstritten und signalisiert eine Position.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_military_pressure','Military and grey-zone pressure around Taiwan','Militärischer und hybrider Druck rund um Taiwan','Chinese military and coast guard operations in the air and waters around Taiwan, and the responses of Taiwan and its security partners. Covers aircraft and naval movements across the Taiwan Strait median line and into Taiwan''s air defence identification zone, coast guard patrols that Beijing describes as law enforcement, aircraft carrier transits and large-scale exercises, alongside Taiwan''s combat readiness drills and the Strait transits conducted by the navies of the United States, Japan and other states. It also covers activity below the threshold of armed force: undersea cable damage, balloon overflights, sand dredging and cyber operations. Taiwan-held offshore islands, including Kinmen, Matsu, Penghu, the Pratas and Taiping, are recurring locations.','Chinesische Militär- und Küstenwachoperationen im Luftraum und in den Gewässern rund um Taiwan sowie die Reaktionen Taiwans und seiner Sicherheitspartner. Erfasst Flug- und Schiffsbewegungen über die Mittellinie der Taiwanstraße und in Taiwans Luftverteidigungszone, Küstenwachpatrouillen, die Peking als Rechtsdurchsetzung bezeichnet, Trägerdurchfahrten und große Manöver, daneben Taiwans Bereitschaftsübungen und die Durchfahrten der Marinen der USA, Japans und weiterer Staaten. Erfasst auch Aktivitäten unterhalb der Schwelle bewaffneter Gewalt: Beschädigung von Seekabeln, Ballonüberflüge, Sandbaggerei und Cyberoperationen. Von Taiwan gehaltene vorgelagerte Inseln, darunter Kinmen, Matsu, Penghu, die Pratas-Inseln und Taiping, sind wiederkehrende Schauplätze.',ARRAY['ASIA-TAIWAN'],true,49,'Military and sub-military activity around Taiwan, and the responses to it, run on two sides. On one: sorties across the median line and into the air defence identification zone, coast guard patrols to the island''s east that Beijing characterises as regularised law enforcement, aircraft carrier movements through the Strait, and exercises that rehearse blockade and landing operations. On the other: Taiwan''s combat readiness drills, its investment in drones and asymmetric systems, and the Taiwan Strait transits conducted by American, Japanese, Canadian, Australian and European vessels, each of which draws a Chinese response. A distinct strand runs below the threshold of armed force -- undersea cable breaks affecting outlying islands, balloons, sand dredging and cyber operations -- and is often the more consequential day to day. The same events carry opposite descriptions depending on the outlet: an incursion or a routine patrol, a provocation or a lawful response.','Die militärischen und untermilitärischen Aktivitäten rund um Taiwan und die Reaktionen darauf verlaufen auf zwei Seiten. Auf der einen: Einsätze über die Mittellinie und in die Luftverteidigungszone, Küstenwachpatrouillen östlich der Insel, die Peking als regularisierte Rechtsdurchsetzung bezeichnet, Trägerbewegungen durch die Meerenge und Manöver, die Blockade- und Landungsoperationen proben. Auf der anderen: Taiwans Bereitschaftsübungen, seine Investitionen in Drohnen und asymmetrische Systeme sowie die Durchfahrten amerikanischer, japanischer, kanadischer, australischer und europäischer Schiffe, auf die jeweils eine chinesische Reaktion folgt. Ein eigener Strang verläuft unterhalb der Schwelle bewaffneter Gewalt: Brüche von Seekabeln zu den vorgelagerten Inseln, Ballons, Sandbaggerei und Cyberoperationen. Dieselben Ereignisse werden je nach Medium gegensätzlich beschrieben.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_political_warfare','Political influence and united front activity','Politische Einflussnahme und Einheitsfrontarbeit','Political influence activity directed at Taiwan from the mainland, and the contest over it inside Taiwan. Covers united front work, including the party-to-party channel between the Chinese Communist Party and the Kuomintang and the mainland visits of Kuomintang delegations; economic incentives and preferential policies offered to Taiwanese citizens and firms; cross-strait forums and people-to-people exchanges; entry bans and commercial restrictions directed at people Beijing designates as supporters of independence; and reported espionage, cognitive-warfare and disinformation operations. Taiwan''s own party competition over China policy, including legislative disputes and recall campaigns, forms part of the same contest.','Vom Festland auf Taiwan gerichtete politische Einflussnahme und der Wettstreit darüber innerhalb Taiwans. Erfasst Einheitsfrontarbeit, darunter den Parteikanal zwischen der Kommunistischen Partei Chinas und der Kuomintang sowie die Festlandbesuche von Kuomintang-Delegationen; wirtschaftliche Anreize und Vorzugsregelungen für taiwanische Bürger und Unternehmen; Foren und zwischenmenschlichen Austausch über die Meerenge; Einreiseverbote und geschäftliche Beschränkungen gegen Personen, die Peking als Unterstützer der Unabhängigkeit einstuft; sowie berichtete Spionage-, Kognitions- und Desinformationsoperationen. Taiwans eigener Parteienwettstreit über die China-Politik, einschließlich parlamentarischer Auseinandersetzungen und Abwahlkampagnen, ist Teil desselben Wettstreits.',ARRAY['ASIA-TAIWAN'],true,51,'Alongside the military dimension runs a political one, conducted through party channels, money and information rather than ships and aircraft. Its most visible element is the relationship between the Chinese Communist Party and the Kuomintang: chairwoman Cheng Li-wun''s delegation visits to the mainland and her meeting with Xi Jinping, revived party-to-party think-tank forums, and the economic incentives announced around them. Alongside the courtship sits its opposite -- entry bans and commercial restrictions on people Beijing designates as independence supporters -- and a reported intelligence dimension, including espionage cases inside Taiwan''s military and disinformation and cognitive-warfare campaigns aimed at Taiwanese voters. The island''s own politics is the terrain: the governing party and the opposition disagree over how far to engage the mainland and how much to spend on defence, and each side''s position is amplified by different outlets. Reporting divides sharply on the same facts, with Chinese and Russian state media presenting exchanges as goodwill toward compatriots and Western, Japanese and regional outlets presenting the same activity as subversion.','Neben der militärischen verläuft eine politische Dimension, die über Parteikanäle, Geld und Information statt über Schiffe und Flugzeuge geführt wird. Ihr sichtbarstes Element ist das Verhältnis zwischen der Kommunistischen Partei Chinas und der Kuomintang: die Festlandbesuche der Vorsitzenden Cheng Li-wun und ihr Treffen mit Xi Jinping, wiederbelebte Think-Tank-Foren beider Parteien und die dabei angekündigten wirtschaftlichen Anreize. Neben dem Werben steht dessen Gegenteil -- Einreiseverbote und geschäftliche Beschränkungen gegen von Peking benannte Personen -- sowie eine berichtete nachrichtendienstliche Dimension, darunter Spionagefälle im taiwanischen Militär und Desinformationskampagnen. Taiwans eigene Politik ist das Terrain: Regierungspartei und Opposition sind uneins über das Maß der Annäherung und die Verteidigungsausgaben.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_semiconductor_dependence','Semiconductor strategic dependence and supply chain security',NULL,NULL,NULL,ARRAY['ASIA-TAIWAN','ASIA-CHINA','AMERICAS-USA','ASIA-JAPAN'],false,51,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_sovereignty','Taiwan sovereignty dispute',NULL,NULL,NULL,ARRAY['ASIA-CHINA','ASIA-TAIWAN','AMERICAS-USA'],false,49,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_strait_theater','Taiwan Strait confrontation','Konfrontation in der Taiwanstraße','The dispute over Taiwan''s political status and the military, diplomatic and economic contest surrounding it. Beijing claims the island as Chinese territory and has not renounced the use of force to take it; Taipei governs the island separately and rejects that claim. The contest spans Chinese military and coast guard activity around the island and the deterrence response to it; the scope and reliability of United States arms supply and security policy; political influence activity directed at Taiwan and the contest over it among the island''s parties; and Taiwan''s diplomatic recognition and participation in international organisations. The United States and Japan are parties to the security dimension without maintaining formal diplomatic relations with Taipei.','Der Streit über den politischen Status Taiwans und der militärische, diplomatische und wirtschaftliche Wettstreit darum. Peking beansprucht die Insel als chinesisches Territorium und hat dem Einsatz von Gewalt zu ihrer Einnahme nicht abgeschworen; Taipeh regiert die Insel getrennt und weist diesen Anspruch zurück. Der Wettstreit umfasst chinesische Militär- und Küstenwachaktivitäten rund um die Insel und die darauf gerichtete Abschreckung; Umfang und Verlässlichkeit der US-Waffenlieferungen und Sicherheitspolitik; die auf Taiwan gerichtete politische Einflussnahme und der Wettstreit darüber zwischen den Parteien der Insel; sowie Taiwans diplomatische Anerkennung und Teilhabe an internationalen Organisationen. Die USA und Japan sind Parteien der Sicherheitsdimension, ohne formelle diplomatische Beziehungen zu Taipeh zu unterhalten.',ARRAY['ASIA-TAIWAN','ASIA-CHINA','AMERICAS-USA'],true,14,'The Taiwan Strait is where the People''s Republic of China''s claim to Taiwan meets the island''s separate government and the security arrangements of the United States and Japan. Beijing holds that the island is part of China and has not renounced the use of force; Taipei governs it separately, and Washington maintains unofficial relations, supplies arms under the Taiwan Relations Act, and has long declined to state explicitly whether it would intervene militarily. The contest spans aircraft, naval and coast guard activity around the island together with the exercises and Strait transits conducted in response; the scale and dependability of American arms supply, alongside Taiwan''s own defence budget and conscription debates; political influence activity directed at the island, including the party-to-party channel between the Chinese Communist Party and the Kuomintang, economic inducements, and reported espionage and disinformation; and Taiwan''s shrinking set of formal diplomatic partners, its exclusion from bodies such as the World Health Assembly, and the restrictions placed on its officials'' travel. Coverage divides along predictable lines: Western, Japanese and regional outlets describe Chinese activity as coercion of a democracy, Chinese and Russian state media describe the same activity as lawful enforcement of sovereignty against foreign interference, and a distinct strand of Western reporting questions whether American commitments will hold.','In der Taiwanstraße trifft der Anspruch der Volksrepublik China auf Taiwan auf die eigenständige Regierung der Insel und die Sicherheitsarrangements der USA und Japans. Peking hält die Insel für einen Teil Chinas und hat dem Einsatz von Gewalt nicht abgeschworen; Taipeh regiert sie getrennt, und Washington unterhält inoffizielle Beziehungen, liefert Waffen nach dem Taiwan Relations Act und hat es lange vermieden, ausdrücklich zu erklären, ob es militärisch eingreifen würde. Der Wettstreit umfasst Luft-, See- und Küstenwachaktivitäten rund um die Insel samt der darauf folgenden Manöver und Durchfahrten; Umfang und Verlässlichkeit der amerikanischen Waffenlieferungen neben Taiwans eigenen Debatten über Verteidigungshaushalt und Wehrpflicht; die auf die Insel gerichtete politische Einflussnahme, darunter der Parteikanal zwischen der Kommunistischen Partei Chinas und der Kuomintang, wirtschaftliche Anreize sowie berichtete Spionage und Desinformation; und Taiwans schrumpfender Kreis formeller diplomatischer Partner, sein Ausschluss aus Gremien wie der Weltgesundheitsversammlung und die Beschränkungen für Reisen seiner Amtsträger. Die Berichterstattung teilt sich entlang erwartbarer Linien.','theater',ARRAY['taiwan_military_pressure','taiwan_us_security_commitment','taiwan_political_warfare','taiwan_international_recognition'],ARRAY['taiwan_strait','tsmc_hsinchu','tsmc_fab18_tainan','kaohsiung_port'],'regional','{"type": "Point", "coordinates": [119.6, 23.9]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('taiwan_us_security_commitment','US security commitment and arms supply','US-Sicherheitszusage und Waffenlieferungen','United States arms supply to Taiwan and the scope of American security policy toward the island, together with Taiwan''s own defence effort. Covers arms sales, congressional approvals, deliveries and the delivery backlog; the Taiwan Relations Act and the Six Assurances; and the long-standing American practice of not stating explicitly whether it would intervene militarily, which is discussed as strategic ambiguity. Also covers the treatment of Taiwan in wider United States-China negotiations, and Taiwan''s defence budget, conscription and asymmetric-warfare programmes, which are contested in Taiwan''s legislature and raised by Washington as a question of burden sharing.','US-Waffenlieferungen an Taiwan und der Umfang der amerikanischen Sicherheitspolitik gegenüber der Insel, zusammen mit Taiwans eigener Verteidigungsanstrengung. Erfasst Rüstungsverkäufe, Genehmigungen durch den Kongress, Lieferungen und den Lieferrückstand; den Taiwan Relations Act und die Sechs Zusicherungen; sowie die langjährige amerikanische Praxis, nicht ausdrücklich zu erklären, ob militärisch eingegriffen würde, die als strategische Ambiguität erörtert wird. Erfasst zudem die Behandlung Taiwans in den weiteren Verhandlungen zwischen den USA und China sowie Taiwans Verteidigungshaushalt, Wehrpflicht und asymmetrische Programme, die im taiwanischen Parlament umstritten sind und von Washington als Frage der Lastenteilung angesprochen werden.',ARRAY['ASIA-TAIWAN'],true,50,'Taiwan buys most of its major weapons from the United States, which supplies them under the Taiwan Relations Act while maintaining no formal diplomatic relations and declining to say explicitly whether it would defend the island. That relationship runs in both directions. On the American side: which packages are approved, delivered, reviewed or delayed; the size of the undelivered backlog; official statements on whether policy has changed; and the appearance of Taiwan on the agenda of United States-China summitry, where arms sales have been described as a negotiating asset. On the Taiwanese side: a defence budget and special-budget process contested between the governing party and the opposition, extended conscription, and a shift toward drones and other asymmetric systems, all of which Washington raises as burden sharing. Coverage splits three ways rather than two. Chinese and Russian state media treat the arms relationship as a breach of the one-China principle. Western and regional outlets are consistently supportive of Taiwan but divide between reporting the commitment as intact and questioning whether it will hold -- so the critical register here comes largely from the island''s own supporters.','Taiwan bezieht die meisten seiner schweren Waffen aus den USA, die sie nach dem Taiwan Relations Act liefern, ohne formelle diplomatische Beziehungen zu unterhalten und ohne ausdrücklich zu erklären, ob sie die Insel verteidigen würden. Diese Beziehung verläuft in beide Richtungen. Auf amerikanischer Seite: welche Pakete genehmigt, geliefert, überprüft oder verzögert werden; der Umfang des Lieferrückstands; offizielle Aussagen zu einer etwaigen Änderung der Politik; und das Auftauchen Taiwans auf der Tagesordnung der Gipfel zwischen den USA und China, bei denen Rüstungsverkäufe als Verhandlungsgut bezeichnet wurden. Auf taiwanischer Seite: ein zwischen Regierungspartei und Opposition umstrittener Verteidigungs- und Sonderhaushalt, die verlängerte Wehrpflicht und die Hinwendung zu Drohnen und anderen asymmetrischen Systemen. Die Berichterstattung teilt sich dreifach statt zweifach: Der kritische Ton stammt hier großenteils von den Unterstützern der Insel selbst.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('thailand_cambodia_border','Thailand–Cambodia border conflict','Grenzkonflikt zwischen Thailand und Kambodscha','Thailand and Cambodia contest their shared 817-kilometre land border and an overlapping maritime zone in the Gulf of Thailand. The land dispute centres on 11th-century Khmer temples and their surrounding ground -- Preah Vihear, awarded to Cambodia by the International Court of Justice in 1962 and again in 2013, and the Ta Moan and Ta Krabey complexes and the tri-border "Emerald Triangle", which remain undemarcated. Boundary work proceeds under a 2000 memorandum (MOU 43) through a Joint Boundary Committee; a separate 2001 memorandum (MOU 44) governs talks on the overlapping maritime claims area, where the island of Koh Kood and seabed oil and gas are at stake. Armed clashes along the frontier in 2025 killed soldiers and civilians and displaced tens of thousands before a ceasefire brokered with outside mediation. Since then the border crossings have been closed at times, both armies have traded accusations of truce violations and troop build-ups, and Cambodia has moved parts of the maritime question toward the UN Convention on the Law of the Sea. Malaysia, the Philippines as ASEAN chair, China and the United States have all been involved in de-escalation.','Thailand und Kambodscha streiten um ihre gemeinsame 817 Kilometer lange Landgrenze und eine überlappende Seezone im Golf von Thailand. Der Landstreit dreht sich um Khmer-Tempel aus dem 11. Jahrhundert und das umliegende Gebiet -- Preah Vihear, das der Internationale Gerichtshof 1962 und erneut 2013 Kambodscha zusprach, sowie die Anlagen Ta Moan und Ta Krabey und das Dreiländereck "Smaragddreieck", die unvermessen bleiben. Die Grenzarbeit läuft unter einem Memorandum von 2000 (MOU 43) über eine Gemeinsame Grenzkommission; ein separates Memorandum von 2001 (MOU 44) regelt Gespräche über das überlappende Seegebiet, in dem die Insel Koh Kood sowie Öl- und Gasvorkommen am Meeresboden umstritten sind. Bewaffnete Zusammenstöße entlang der Grenze im Jahr 2025 töteten Soldaten und Zivilisten und vertrieben Zehntausende, bevor unter externer Vermittlung eine Waffenruhe zustande kam. Seither waren die Grenzübergänge zeitweise geschlossen, beide Armeen warfen einander Verstöße gegen die Waffenruhe und Truppenaufmärsche vor, und Kambodscha verlagerte Teile der Seefrage zum UN-Seerechtsübereinkommen. Malaysia, die Philippinen als ASEAN-Vorsitz, China und die USA waren an der Deeskalation beteiligt.',ARRAY['ASIA-SOUTHEAST','ASIA-SOUTHASIA','ASIA-CHINA','ASIA-PACIFIC-THAILAND'],true,60,'Thailand and Cambodia dispute their shared land border -- centred on the 11th-century temples of Preah Vihear (awarded to Cambodia by the ICJ), Ta Moan and Ta Krabey and the undemarcated "Emerald Triangle" -- and an overlapping maritime zone in the Gulf of Thailand governed by the MOU 44 framework, where the island of Koh Kood and seabed oil and gas are at stake. Border clashes in 2025 caused deaths and mass displacement before an externally brokered ceasefire; since then crossings have periodically closed, both armies allege truce violations and build-ups, and Cambodia has pushed part of the maritime question toward UNCLOS. Coverage divides along national lines: Thai outlets frame the border and Koh Kood as inviolable Thai territory and Cambodia as the party breaching the boundary memoranda and provoking incidents; the Cambodian counter-claim -- that Thailand occupies Cambodian ground and that the ICJ ruling and demarcation favour Phnom Penh -- reaches the corpus mainly through international wire quotes, as no Cambodian outlets are present. Chinese state media cover the dispute as a showcase for their own mediation and ASEAN de-escalation rather than backing either territorial claim.','Thailand und Kambodscha streiten um ihre Landgrenze -- im Zentrum stehen die Tempel Preah Vihear (vom IGH Kambodscha zugesprochen), Ta Moan und Ta Krabey aus dem 11. Jahrhundert sowie das unvermessene "Smaragddreieck" -- und um eine überlappende Seezone im Golf von Thailand, die durch das MOU-44-Rahmenwerk geregelt wird und in der die Insel Koh Kood sowie Öl- und Gasvorkommen umstritten sind. Grenzgefechte 2025 forderten Tote und Massenvertreibung, bevor eine extern vermittelte Waffenruhe zustande kam; seither waren Übergänge zeitweise geschlossen, beide Armeen werfen einander Verstöße und Aufmärsche vor, und Kambodscha verlagerte einen Teil der Seefrage zum UN-Seerechtsübereinkommen. Die Berichterstattung teilt sich entlang nationaler Linien: Thailändische Medien stellen die Grenze und Koh Kood als unverletzliches thailändisches Gebiet dar und Kambodscha als jene Partei, die die Grenzmemoranden bricht und Zwischenfälle provoziert; die kambodschanische Gegenposition -- Thailand besetze kambodschanischen Boden, und IGH-Urteil wie Vermessung sprächen für Phnom Penh -- erreicht das Korpus vor allem über internationale Agenturzitate, da keine kambodschanischen Medien vertreten sind. Chinesische Staatsmedien behandeln den Streit als Bühne für die eigene Vermittlung und die ASEAN-Deeskalation, statt einen der Gebietsansprüche zu stützen.','atomic',NULL,'{}','regional','{"type": "Point", "coordinates": [104.68, 14.39]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('transatlantic_trade','Transatlantic trade disputes and tariffs','Transatlantische Handelskonflikte und Zölle','The tariff and trade confrontation between the United States and the European Union under a protectionist Washington: US duties on European steel, aluminium, cars and other goods, the threatened and imposed counter-tariffs from Brussels, and the fragile framework trade deal negotiated to contain them. It extends to digital-services taxes, subsidy and market-access disputes and the Airbus-Boeing legacy, with European unity repeatedly tested over whether to retaliate against Washington or accommodate it.','Die Zoll- und Handelskonfrontation zwischen den USA und der Europäischen Union unter einem protektionistischen Washington: US-Abgaben auf europäischen Stahl, Aluminium, Autos und andere Waren, die angedrohten und verhängten Gegenzölle aus Brüssel und das fragile Rahmen-Handelsabkommen, das sie eindämmen soll. Sie reicht bis zu Digitalsteuern, Subventions- und Marktzugangsstreitigkeiten und dem Airbus-Boeing-Erbe, wobei die europäische Einigkeit immer wieder auf die Probe gestellt wird — Vergeltung gegen Washington oder Entgegenkommen.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC'],true,29,'The economic front of the transatlantic rift. A protectionist Washington has imposed and threatened tariffs on European steel, aluminium, cars and other goods, drawing threatened counter-tariffs from Brussels and repeated brinkmanship around a fragile framework deal meant to contain the damage. It reaches into digital-services taxes, subsidy fights and market access, and repeatedly tests whether the EU can hold a united line -- retaliating hard or accommodating -- as member states weigh exposed export industries against the cost of a trade war. US conservative outlets frame the tariffs as a justified correction of an unfair European surplus; European and Western mainstream coverage frames them as economic coercion demanding a firm, united response.','Die wirtschaftliche Front des transatlantischen Risses. Ein protektionistisches Washington hat Zölle auf europäischen Stahl, Aluminium, Autos und andere Waren verhängt und angedroht, angedrohte Gegenzölle aus Brüssel provoziert und wiederholt an den Rand der Eskalation um ein fragiles Rahmenabkommen geführt, das den Schaden begrenzen soll. Sie reicht bis zu Digitalsteuern, Subventionsstreitigkeiten und Marktzugang und prüft immer wieder, ob die EU eine geschlossene Linie halten kann -- harte Vergeltung oder Entgegenkommen. US-konservative Medien deuten die Zölle als berechtigte Korrektur eines unfairen europäischen Überschusses; europäische und westliche Mainstream-Berichterstattung als wirtschaftlichen Zwang, der eine feste, geschlossene Antwort verlangt.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
