INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('turkey_mediator_role','Turkey as regional mediator',NULL,NULL,NULL,ARRAY['MIDEAST-TURKEY','MIDEAST-IRAN','MIDEAST-ISRAEL','MIDEAST-EGYPT','MIDEAST-GULF','MIDEAST-SAUDI','EUROPE-UKRAINE'],true,15,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('turkey_theater','Turkey as contested regional power',NULL,NULL,NULL,ARRAY['MIDEAST-TURKEY','MIDEAST-IRAN','MIDEAST-ISRAEL','EUROPE-RUSSIA','AMERICAS-USA','NON-STATE-NATO'],true,4,NULL,NULL,'theater',ARRAY['turkey_kurdish_question','turkey_iran_war_spillover','turkey_mediator_role','turkey_democratic_backsliding'],ARRAY['turkish_straits','btc_pipeline','turkstream'],'regional','{"type": "Point", "coordinates": [32.9, 39.9]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_battlefield','Battlefield operations and territorial control','Kampfhandlungen und territoriale Kontrolle','The ground war itself: the contest for the front line and the territory behind it. Russian offensives and Ukrainian defense and counter-attacks across Donbas, Zaporizhzhia and the border oblasts -- captured villages, fortified towns, force generation and the daily attrition that moves the map by metres. Each side reads the same advance as either liberation or aggression, and that contest over meaning sits on top of the physical one.','Der Bodenkrieg selbst: der Kampf um die Frontlinie und das Land dahinter. Russische Offensiven sowie ukrainische Verteidigung und Gegenangriffe im Donbass, in Saporischschja und den Grenzregionen -- eroberte Doerfer, befestigte Staedte, Truppenaufwuchs und die taegliche Zermuerbung, die die Karte um Meter verschiebt. Jede Seite liest denselben Vorstoss entweder als Befreiung oder als Aggression, und dieser Streit um die Bedeutung liegt ueber dem physischen.',ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'],true,20,'This is the war at its most literal: kilometres of front, fortified towns that change hands over months, and an attritional grind that consumes men and materiel faster than either side admits. Russia presses a slow, costly advance framed as the liberation of historically Russian land; Ukraine fights a defensive war of national survival, trading space for time and striking back where it can. The battlefield''s vocabulary -- Pokrovsk, Kupiansk, Avdiivka, the Kursk incursion, mobilisation and casualty figures -- is where the war''s cost is counted most directly. Because the same kilometre is "liberated" by one side and "occupied" by the other, the ground war is also a contest over narrative: whose advance is legitimate, whose losses are catastrophic, and whether the line can move at all. Nothing else in the theatre -- aid, diplomacy, strikes -- makes sense except in relation to what is happening here.','Dies ist der Krieg in seiner buchstaeblichsten Form: Kilometer Front, befestigte Staedte, die ueber Monate den Besitzer wechseln, und ein zermuerbender Abnutzungskampf, der Menschen und Material schneller verbraucht, als beide Seiten zugeben. Russland treibt einen langsamen, verlustreichen Vormarsch voran, gerahmt als Befreiung historisch russischen Landes; die Ukraine fuehrt einen defensiven Ueberlebenskrieg, tauscht Raum gegen Zeit und schlaegt zurueck, wo sie kann. Das Vokabular des Schlachtfelds -- Pokrowsk, Kupjansk, Awdijiwka, der Vorstoss bei Kursk, Mobilmachung und Verlustzahlen -- ist der Ort, an dem die Kosten des Krieges am unmittelbarsten gezaehlt werden. Weil derselbe Kilometer von der einen Seite "befreit" und von der anderen "besetzt" wird, ist der Bodenkrieg auch ein Streit ums Narrativ: wessen Vormarsch legitim ist, wessen Verluste katastrophal sind und ob sich die Linie ueberhaupt bewegen laesst. Nichts anderes im Kriegsschauplatz -- Hilfe, Diplomatie, Angriffe -- ergibt Sinn ausser im Verhaeltnis zu dem, was hier geschieht.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_infrastructure_war','The long-range war: strikes on energy, industry and infrastructure','Der Fernkrieg: Angriffe auf Energie, Industrie und Infrastruktur','The war fought past the front line, in both directions: Ukrainian long-range strikes on Russian refineries, fuel depots, export terminals, airbases and military industry; Russian missile and drone campaigns against Ukraine''s power system, fuel storage and cities; and the contested safety of the Zaporizhzhia nuclear plant. Energy and infrastructure are dual-use by nature -- each side presents its own strikes as military necessity and the other side''s as terror, and that contest over intent is part of the phenomenon itself.','Der Krieg jenseits der Frontlinie, in beide Richtungen: ukrainische Langstreckenangriffe auf russische Raffinerien, Treibstofflager, Exportterminals, Luftwaffenstuetzpunkte und Ruestungsindustrie; russische Raketen- und Drohnenkampagnen gegen das ukrainische Stromsystem, Treibstofflager und Staedte; dazu die umkaempfte Sicherheit des Kernkraftwerks Saporischschja. Energie und Infrastruktur sind ihrem Wesen nach dual-use -- jede Seite stellt eigene Angriffe als militaerische Notwendigkeit dar und die der Gegenseite als Terror; dieser Streit um die Absicht ist Teil des Phaenomens selbst.',ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'],true,5,'Since 2024 the war''s most distinctive strategic layer has moved off the front line and onto the energy map. Ukraine''s deep-strike campaign reaches refineries, depots and export terminals far inside Russia; Russia''s missile and drone campaign works through Ukraine''s grid, generation and fuel storage. Both campaigns hit systems that are irreducibly dual-use: the same refinery fuels tanks and tractors, the same grid powers arms plants and apartment blocks. Each side states a military-economic rationale for its own strikes -- degrading the enemy''s fuel supply, logistics and defence industry -- and frames the other''s as terror against civilians; adjudicating between those readings is the narratives'' job, not this node''s. The Zaporizhzhia plant sits at the centre as a standing nuclear-safety flashpoint, with the IAEA as the only institutional referee on site. The contest is fought as much over legitimacy as over megawatts.','Seit 2024 hat sich die praegendste strategische Ebene des Krieges von der Front auf die Energiekarte verlagert. Die ukrainische Tiefschlag-Kampagne erreicht Raffinerien, Lager und Exportterminals weit im russischen Hinterland; die russische Raketen- und Drohnenkampagne richtet sich gegen das ukrainische Stromnetz, die Erzeugung und die Treibstofflager. Beide Kampagnen treffen Systeme, die unaufloeslich dual-use sind: dieselbe Raffinerie betankt Panzer und Traktoren, dasselbe Netz versorgt Ruestungswerke und Wohnbloecke. Jede Seite nennt fuer die eigenen Angriffe eine militaerisch-oekonomische Begruendung -- Schwaechung von Treibstoffversorgung, Logistik und Ruestungsindustrie des Gegners -- und rahmt die der Gegenseite als Terror gegen Zivilisten; zwischen diesen Lesarten zu entscheiden ist Aufgabe der Narrative, nicht dieses Knotens. Das Kernkraftwerk Saporischschja steht im Zentrum als permanenter nuklearer Gefahrenherd, mit der IAEO als einzigem institutionellen Schiedsrichter vor Ort. Der Konflikt wird ebenso um Legitimitaet wie um Megawatt gefuehrt.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_official_corruption','Official corruption and reconstruction challenges','Amtliche Korruption und Herausforderungen des Wiederaufbaus','Governance under wartime stress: graft investigations, procurement scandals and the integrity of reconstruction and aid spending. Coverage splits three ways -- reform institutions proving they work, Western allies alarmed that high-level corruption threatens support, and adversary media casting the whole state as a kleptocracy stealing aid at scale.','Regieren unter Kriegsbelastung: Korruptionsermittlungen, Beschaffungsskandale und die Integritaet der Ausgaben fuer Wiederaufbau und Hilfe. Die Berichterstattung teilt sich in drei Richtungen -- Reforminstitutionen, die ihre Wirksamkeit beweisen, westliche Verbuendete, die alarmiert sind, dass Korruption auf hoher Ebene die Unterstuetzung gefaehrdet, und gegnerische Medien, die den gesamten Staat als Kleptokratie darstellen, die Hilfe in grossem Stil stiehlt.',ARRAY['EUROPE-UKRAINE'],true,23,'Corruption is the one Ukraine topic where the usual publisher coalitions break down. The country''s own anti-corruption architecture -- NABU, SAPO, the High Anti-Corruption Court -- is both a genuine reform success and a steady source of damaging headlines, because every prosecution is also proof that the graft was there. Supportive outlets can therefore read the same Yermak-circle or procurement scandal two ways at once: as institutions working, or as systemic rot that endangers the Western aid the war depends on. That is why this node runs a three-stance gradient rather than a simple pro/con split -- reform-in-progress, Western systemic alarm, and the adversary "Zelensky kleptocracy" frame that treats every story as evidence aid is being stolen wholesale. The stakes are concrete: corruption narratives feed directly into the aid debate, so a single high-profile scandal can move votes in Washington and Brussels as much as any battlefield setback.','Korruption ist das eine Ukraine-Thema, bei dem die ueblichen Publisher-Koalitionen zusammenbrechen. Die eigene Antikorruptionsarchitektur des Landes -- NABU, SAPO, der Hohe Antikorruptionsgerichtshof -- ist zugleich ein echter Reformerfolg und eine bestaendige Quelle schaedlicher Schlagzeilen, denn jede Strafverfolgung ist auch ein Beleg, dass die Korruption vorhanden war. Wohlwollende Medien koennen denselben Skandal im Jermak-Kreis oder bei der Beschaffung daher auf zweierlei Weise zugleich lesen: als funktionierende Institutionen oder als systemische Faeulnis, die die westliche Hilfe gefaehrdet, von der der Krieg abhaengt. Deshalb faehrt dieser Knoten einen Drei-Stufen-Gradienten statt einer einfachen Pro/Contra-Teilung -- Reform im Gange, westliche systemische Alarmierung und das gegnerische "Selenskyj-Kleptokratie"-Framing, das jede Geschichte als Beweis wertet, dass Hilfe in grossem Stil gestohlen wird. Die Einsaetze sind konkret: Korruptionsnarrative fliessen direkt in die Hilfsdebatte ein, sodass ein einziger prominenter Skandal in Washington und Bruessel ebenso Stimmen bewegen kann wie ein Rueckschlag auf dem Schlachtfeld.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_peace_negotiations','Peace negotiations and diplomatic initiatives','Friedensverhandlungen und diplomatische Initiativen','The diplomatic track: ceasefire proposals, security guarantees, territorial formulas and the shuttle diplomacy around them. Three incompatible end-states compete -- a Ukrainian restoration of 1991 borders, a Russian settlement that ratifies its annexations and Ukrainian neutrality, and a great-power push to freeze the line as it stands. The contest is over whose terms define "peace".','Die diplomatische Spur: Waffenstillstandsvorschlaege, Sicherheitsgarantien, territoriale Formeln und die Pendeldiplomatie darum herum. Drei unvereinbare Endzustaende konkurrieren -- eine ukrainische Wiederherstellung der Grenzen von 1991, eine russische Regelung, die seine Annexionen und die ukrainische Neutralitaet bestaetigt, und ein Grossmacht-Vorstoss, die Linie im heutigen Verlauf einzufrieren. Der Streit geht darum, wessen Bedingungen "Frieden" definieren.',ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA','AMERICAS-USA','NON-STATE-EU'],true,22,'Every settlement proposal encodes a theory of who is winning. Kyiv''s maximalist position -- full withdrawal, restored borders, accountability and NATO-backed guarantees -- treats negotiation as the codification of a Russian defeat that has not yet happened on the ground. Moscow''s terms invert this: recognised annexations, a neutral and "denazified" Ukraine, sanctions lifted -- the ratification of its war aims by other means. Between them sits a third track, pushed at various points by Washington and echoed by war-weary European and Global South voices, that would freeze the front roughly where it lies and defer the hardest questions. The vocabulary -- Istanbul, Anchorage, security guarantees, line of contact, territorial swaps -- shifts with each round of shuttle diplomacy, but the underlying deadlock is stable: no party will sign terms that concede what it still believes it can win or hold. Diplomacy here is less a path out of the war than another arena in which it is fought.','Jeder Regelungsvorschlag verschluesselt eine Theorie darueber, wer gewinnt. Kiews maximalistische Position -- vollstaendiger Abzug, wiederhergestellte Grenzen, Rechenschaft und NATO-gestuetzte Garantien -- behandelt Verhandlungen als Festschreibung einer russischen Niederlage, die am Boden noch nicht eingetreten ist. Moskaus Bedingungen kehren dies um: anerkannte Annexionen, eine neutrale und "entnazifizierte" Ukraine, aufgehobene Sanktionen -- die Bestaetigung seiner Kriegsziele mit anderen Mitteln. Dazwischen liegt eine dritte Spur, zeitweise von Washington vorangetrieben und von kriegsmueden europaeischen und Global-South-Stimmen aufgegriffen, die die Front etwa dort einfrieren wuerde, wo sie verlaeuft, und die haertesten Fragen vertagt. Das Vokabular -- Istanbul, Anchorage, Sicherheitsgarantien, Kontaktlinie, Gebietstausch -- verschiebt sich mit jeder Runde der Pendeldiplomatie, doch die zugrunde liegende Blockade ist stabil: keine Partei unterzeichnet Bedingungen, die preisgeben, was sie noch zu gewinnen oder zu halten glaubt. Diplomatie ist hier weniger ein Weg aus dem Krieg als eine weitere Arena, in der er gefuehrt wird.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-UKRAINE')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_proxy_war','Ukraine war and NATO proxy dynamics',NULL,NULL,NULL,ARRAY['AMERICAS-USA','EUROPE-RUSSIA','EUROPE-UKRAINE'],false,97,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ukraine_war_theater','Russia''s war in Ukraine','Russlands Krieg in der Ukraine','The Russia-Ukraine war (initiated 24 February 2022) and its surrounding contest of framings: battlefield operations, the campaign against energy and infrastructure on both sides, Western military and economic aid, peace negotiations, anti-corruption investigations of Ukrainian officials, and the sanctions regime on Russia. The scope of the war itself is contested vocabulary — Ukrainian/Western framing as full-scale invasion versus Russian framing as a limited special military operation. Coverage spans Ukrainian, Russian, Western mainstream, Eastern European, and Global South press with sharply divergent vocabularies for the same events.','Der russisch-ukrainische Krieg (begonnen am 24. Februar 2022) und sein umgebender Rahmungs-Wettstreit: Gefechtsoperationen, der beiderseitige Feldzug gegen Energie und Infrastruktur, westliche militaerische und wirtschaftliche Hilfe, Friedensverhandlungen, Anti-Korruptionsermittlungen gegen ukrainische Beamte und das Sanktionsregime gegen Russland. Der Umfang des Krieges selbst ist umkaempftes Vokabular — ukrainisch-westliche Rahmung als voll entfaltete Invasion gegenueber russischer Rahmung als begrenzte militaerische Spezialoperation. Berichterstattung umfasst ukrainische, russische, westliche, osteuropaeische und Global-South-Medien mit stark divergierenden Vokabularen fuer dieselben Ereignisse.',ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'],true,6,'Russia''s invasion of Ukraine, launched 24 February 2022, is the largest land war in Europe since 1945 and the organizing fact of the current European security order. Four axes of contest run through it: control of the front line itself, the scale and durability of Western military and economic backing, the terms on which — or whether — negotiations can end it, and whether Ukraine''s wartime governance holds up under the strain of corruption scandals. A fifth front runs through the energy system on both sides, targeting the fuel and power that sustain the other''s war effort. Coverage of the war is itself contested ground: the same events are described as full-scale invasion and national resistance in Kyiv and the West, and as a special military operation against NATO encroachment in Moscow.','Russlands am 24. Februar 2022 begonnene Invasion der Ukraine ist der groesste Landkrieg in Europa seit 1945 und die praegende Tatsache der gegenwaertigen europaeischen Sicherheitsordnung. Vier Streitachsen durchziehen ihn: die Kontrolle ueber die Front selbst, Ausmass und Durchhaltefaehigkeit der westlichen militaerischen und wirtschaftlichen Unterstuetzung, die Bedingungen, unter denen — oder ob ueberhaupt — Verhandlungen den Krieg beenden koennen, sowie die Frage, ob die ukrainische Kriegsfuehrung der Belastung durch Korruptionsskandale standhaelt. Eine fuenfte Front verlaeuft durch das Energiesystem beider Seiten und zielt auf Treibstoff und Strom, die die Kriegsanstrengung der jeweils anderen Seite aufrechterhalten. Die Berichterstattung ueber den Krieg ist selbst umkaempftes Terrain: dieselben Ereignisse werden in Kiew und im Westen als umfassende Invasion und nationaler Widerstand beschrieben, in Moskau als militaerische Spezialoperation gegen die NATO-Osterweiterung.','theater',ARRAY['ukraine_battlefield','western_aid_to_ukraine','ukraine_peace_negotiations','ukraine_official_corruption','ukraine_infrastructure_war'],ARRAY['ukrainian_grain_belt','odesa_port','novorossiysk_port','druzhba_pipeline_west','turkish_straits','zaporizhzhia_npp','kerch_strait','omsk_refinery','primorsk_ust_luga_terminals'],'regional','{"type": "Point", "coordinates": [37.8, 48.0]}'::jsonb,'EUROPE-UKRAINE')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_canada_theater','United States-Canada rupture','Bruch zwischen den USA und Kanada','The confrontation between the United States and Canada across trade, sovereignty and the internal cohesion of the Canadian federation. Three axes run through it: tariffs and the renegotiation of the trilateral trade agreement; rhetoric about annexation and statehood alongside disputes over jointly financed border infrastructure; and a secession movement in Alberta whose organisers have held contacts with American officials. The two economies are deeply integrated and the two states are treaty allies, which is what makes the dispute distinct from an ordinary trade conflict.','Die Konfrontation zwischen den USA und Kanada in den Bereichen Handel, Souveränität und innerer Zusammenhalt des kanadischen Bundesstaates. Drei Achsen durchziehen sie: Zölle und die Neuverhandlung des trilateralen Handelsabkommens; Rhetorik über Annexion und Staatlichkeit sowie Streit über gemeinsam finanzierte Grenzinfrastruktur; und eine Sezessionsbewegung in Alberta, deren Organisatoren Kontakte zu amerikanischen Amtsträgern unterhielten. Beide Volkswirtschaften sind eng verflochten und beide Staaten sind Bündnispartner — das unterscheidet den Streit von einem gewöhnlichen Handelskonflikt.',ARRAY['AMERICAS-CANADA','AMERICAS-USA'],true,112,'Canada and the United States share the world''s longest land border, a trilateral trade agreement, a joint air-defence command and roughly three-quarters of Canadian exports. That integration is the backdrop against which a tariff campaign, public discussion of annexation and statehood, a threat to withhold a jointly financed border crossing, and the withdrawal of a diplomatic invitation have moved the relationship onto contested ground. The Canadian response has run across party lines and has extended to consumer boycotts, domestic-procurement campaigns and trade openings toward India, China and Asian markets. A third axis is domestic: a referendum push in Alberta, a landlocked province holding most of Canada''s oil reserves, whose organisers have met American officials — drawing objections from the federal government, provincial premiers, First Nations treaty holders and the courts. Russian, Chinese and Iranian state media cover the dispute as evidence of Western fracture rather than taking either side.','Kanada und die USA teilen die längste Landgrenze der Welt, ein trilaterales Handelsabkommen, ein gemeinsames Luftverteidigungskommando und rund drei Viertel der kanadischen Ausfuhren. Vor diesem Hintergrund haben eine Zollkampagne, öffentliche Debatten über Annexion und Staatlichkeit, die Drohung, einen gemeinsam finanzierten Grenzübergang zurückzuhalten, und die Rücknahme einer diplomatischen Einladung die Beziehung auf strittiges Terrain verschoben. Die kanadische Reaktion verlief parteiübergreifend und reichte bis zu Verbraucherboykotten, Kampagnen für heimische Beschaffung und Handelsöffnungen nach Indien, China und Asien. Eine dritte Achse ist innenpolitisch: ein Referendumsvorstoß in Alberta, einer Binnenprovinz mit dem Großteil der kanadischen Ölreserven, deren Organisatoren amerikanische Amtsträger trafen — mit Einwänden der Bundesregierung, von Provinzpremiers, Vertragspartnern der First Nations und der Gerichte. Russische, chinesische und iranische Staatsmedien behandeln den Streit als Beleg westlicher Zerrissenheit, ohne Partei zu ergreifen.','theater',ARRAY['us_canada_trade_coercion','canada_sovereignty_pressure','alberta_separatism_us_ties'],ARRAY['athabasca_oil_sands','canadian_prairies_wheat','athabasca_basin_uranium'],'regional','{"type": "Point", "coordinates": [-75.7, 45.4]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_canada_trade_coercion','Tariffs, USMCA renegotiation and trade retaliation','Zölle, USMCA-Neuverhandlung und Handelsvergeltung','The tariff and trade-agreement dispute between the United States and Canada. It covers duties imposed and threatened on Canadian goods, the reopening of the trilateral trade agreement, sector-specific measures on steel, aluminium, softwood lumber, aircraft and vehicles, Canadian counter-tariffs and their extension, congressional votes on the tariff authority, and Canada''s parallel pursuit of trade agreements with India, China and Asian partners.','Der Zoll- und Handelsabkommensstreit zwischen den USA und Kanada. Er umfasst verhängte und angedrohte Abgaben auf kanadische Waren, die Wiedereröffnung des trilateralen Handelsabkommens, sektorspezifische Maßnahmen bei Stahl, Aluminium, Nadelholz, Flugzeugen und Fahrzeugen, kanadische Gegenzölle und deren Verlängerung, Abstimmungen im Kongress über die Zollbefugnis sowie Kanadas parallele Bemühungen um Handelsabkommen mit Indien, China und asiatischen Partnern.',ARRAY['AMERICAS-USA'],true,113,'Trade is the largest and most continuous strand of the US-Canada confrontation. Duties have been imposed or threatened across steel and aluminium, softwood lumber, vehicles and aircraft, with an aircraft decertification threat attached to a proposed fifty per cent rate. Canada has extended counter-measures and both governments have moved in and out of negotiation, while the trilateral agreement covering the three North American economies has been reopened for renegotiation, at points with Mexico and the United States meeting without Canada. The dispute has drawn opposition inside the United States as well, including a House vote to overturn the tariffs with cross-party support, and it has pushed Canada toward trade agreements with India, China and Asian markets — which has in turn drawn further tariff threats.','Der Handel ist der größte und durchgängigste Strang der Konfrontation zwischen den USA und Kanada. Abgaben wurden auf Stahl und Aluminium, Nadelholz, Fahrzeuge und Flugzeuge verhängt oder angedroht, verbunden mit der Drohung, kanadischen Flugzeugen die Zulassung zu entziehen, bei einem geplanten Satz von fünfzig Prozent. Kanada hat Gegenmaßnahmen verlängert, beide Regierungen traten wiederholt in Verhandlungen ein und aus, und das trilaterale Abkommen der drei nordamerikanischen Volkswirtschaften wurde zur Neuverhandlung geöffnet — zeitweise trafen sich Mexiko und die USA ohne Kanada. Der Streit stieß auch innerhalb der USA auf Widerstand, darunter ein Votum des Repräsentantenhauses zur Aufhebung der Zölle mit parteiübergreifender Unterstützung. Er hat Kanada zu Handelsabkommen mit Indien, China und asiatischen Märkten gedrängt, was wiederum weitere Zolldrohungen nach sich zog.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CANADA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_ai_primacy','Artificial intelligence primacy race','Wettlauf um die Vorherrschaft bei künstlicher Intelligenz','The competition between US and Chinese firms and governments for capability and market position in artificial intelligence: model performance and training cost, access to compute, competition for users in each other''s markets, defence blacklisting of Chinese technology companies and the litigation it draws, disputes over model access and distillation, restrictions on cross-border acquisition of AI developers, and an intergovernmental dialogue on artificial intelligence agreed between the two governments.','Der Wettbewerb zwischen US-amerikanischen und chinesischen Unternehmen und Regierungen um Leistungsfähigkeit und Marktposition bei künstlicher Intelligenz: Modellleistung und Trainingskosten, Zugang zu Rechenkapazität, Wettbewerb um Nutzer in den jeweiligen Märkten, die Aufnahme chinesischer Technologieunternehmen auf Verteidigungslisten und die daraus folgenden Klagen, Streit über Modellzugriff und Distillation, Beschränkungen für grenzüberschreitende Übernahmen von KI-Entwicklern sowie ein zwischen beiden Regierungen vereinbarter Dialog zur künstlichen Intelligenz.',ARRAY['AMERICAS-USA'],true,94,'Artificial intelligence is the strand where the capability gap has narrowed most visibly. Chinese models reached the frontier at lower training cost, Chinese firms began competing for users inside the US market, and both governments treated the field as strategic. The contest is conducted with every available commercial and regulatory instrument: the US Defense Department listed Chinese technology companies as supporting the Chinese military, drawing lawsuits from the firms named; a US AI developer accused a Chinese counterpart of obtaining illicit access to its models, and the Chinese firm restricted its employees from using the US developer''s tools in turn; Washington issued warnings over model distillation; and Beijing blocked a US acquisition of a Chinese AI developer and tightened rules on outbound investment. Alongside the rivalry the two governments agreed to open an intergovernmental dialogue on artificial intelligence. Coverage divides on disjoint lines: Western, allied and specialist outlets describe a close race in which both sides use hard tactics, while Chinese state media attribute Chinese progress to domestic research investment and characterise US accusations and blacklisting as attempts to suppress a competitor.','Künstliche Intelligenz ist der Strang, in dem sich der Leistungsabstand am sichtbarsten verringert hat. Chinesische Modelle erreichten die Spitze bei geringeren Trainingskosten, chinesische Firmen begannen im US-Markt um Nutzer zu werben, und beide Regierungen behandelten das Feld als strategisch. Der Wettstreit wird mit allen verfügbaren kommerziellen und regulatorischen Mitteln geführt: Das US-Verteidigungsministerium führte chinesische Technologieunternehmen als Unterstützer des chinesischen Militärs, was Klagen der genannten Firmen nach sich zog; ein US-KI-Entwickler warf einem chinesischen Wettbewerber unzulässigen Zugriff auf seine Modelle vor, woraufhin dieser seinen Mitarbeitern die Nutzung der Werkzeuge des US-Entwicklers untersagte; Washington warnte vor Modell-Distillation; und Peking blockierte eine US-Übernahme eines chinesischen KI-Entwicklers und verschärfte die Regeln für Auslandsinvestitionen. Parallel zur Rivalität vereinbarten beide Regierungen einen zwischenstaatlichen Dialog zur künstlichen Intelligenz. Die Berichterstattung verläuft entlang getrennter Linien: westliche, verbündete und Fachmedien beschreiben ein enges Rennen, in dem beide Seiten harte Mittel einsetzen, während chinesische Staatsmedien den chinesischen Fortschritt heimischer Forschungsinvestition zuschreiben und US-Vorwürfe und Listungen als Versuche der Unterdrückung eines Wettbewerbers darstellen.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-CHINA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_critical_minerals','Critical minerals leverage','Hebelwirkung kritischer Rohstoffe','Dependence on Chinese supply of rare earths and other critical minerals, and the measures taken around it: Chinese export licensing and export-control listings covering rare earths and processed magnet materials, US strategic stockpiling and Defense Department offtake arrangements, critical-minerals agreements between the United States and the European Union and Japan, and support for mining and processing capacity outside China. China holds a dominant share of global refining and magnet production, and a bilateral arrangement on rare-earth supply has been in effect during the period.','Die Abhängigkeit von chinesischen Lieferungen Seltener Erden und anderer kritischer Rohstoffe und die Maßnahmen darum herum: chinesische Exportlizenzierung und Exportkontrolllisten für Seltene Erden und verarbeitete Magnetwerkstoffe, strategische Reservehaltung der USA und Abnahmevereinbarungen des Verteidigungsministeriums, Rohstoffabkommen zwischen den Vereinigten Staaten und der Europäischen Union sowie Japan und die Förderung von Förder- und Verarbeitungskapazität außerhalb Chinas. China hält einen dominierenden Anteil an der weltweiten Raffination und Magnetproduktion; eine bilaterale Vereinbarung zur Versorgung mit Seltenen Erden war im Zeitraum in Kraft.',ARRAY['AMERICAS-USA'],true,93,'Critical minerals are the strand where the asymmetry runs the other way. China holds a dominant share of rare-earth mining, refining and magnet production, and has used export licensing as an instrument — including placing two US rare-earth producers on its own export-control list. A bilateral arrangement on rare-earth supply has been in effect, with its extension discussed at the Beijing summit, though Chinese curbs continued to bind in the meantime. The US response is industrial rather than regulatory: a multibillion-dollar strategic stockpile, Defense Department offtake and investment arrangements with non-Chinese producers, and critical-minerals agreements concluded with the European Union and Japan. Third countries with their own deposits, including Brazil, have declined to align exclusively with either side. Coverage divides on disjoint lines: Western, allied and industry outlets treat the dependence as a strategic vulnerability to be engineered away, while Chinese state media present export licensing as lawful regulation of dual-use materials and the allied minerals agreements as exclusive blocs that fragment global trade.','Bei kritischen Rohstoffen verläuft die Asymmetrie in die andere Richtung. China hält einen dominierenden Anteil an Förderung, Raffination und Magnetproduktion Seltener Erden und hat Exportlizenzierung als Instrument eingesetzt — unter anderem durch die Aufnahme zweier US-Produzenten Seltener Erden auf die eigene Exportkontrollliste. Eine bilaterale Vereinbarung zur Versorgung mit Seltenen Erden war in Kraft, ihre Verlängerung wurde beim Pekinger Gipfel erörtert, während chinesische Beschränkungen zwischenzeitlich weiter wirkten. Die US-Antwort ist industrieller statt regulatorischer Natur: eine milliardenschwere strategische Reserve, Abnahme- und Investitionsvereinbarungen des Verteidigungsministeriums mit nichtchinesischen Produzenten sowie Rohstoffabkommen mit der Europäischen Union und Japan. Drittstaaten mit eigenen Vorkommen, darunter Brasilien, haben eine ausschließliche Bindung an eine der beiden Seiten abgelehnt. Die Berichterstattung verläuft entlang getrennter Linien: westliche, verbündete und Industriemedien behandeln die Abhängigkeit als strategische Verwundbarkeit, die technisch zu überwinden ist, während chinesische Staatsmedien Exportlizenzierung als rechtmäßige Regulierung von Dual-Use-Material und die Rohstoffabkommen der Verbündeten als exklusive Blöcke darstellen, die den Welthandel fragmentieren.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-CHINA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_investment_screening','Foreign investment restrictions and capital controls',NULL,NULL,NULL,ARRAY['AMERICAS-USA','ASIA-CHINA'],false,92,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_summit_diplomacy','Summit diplomacy and relationship management','Gipfeldiplomatie und Beziehungsmanagement','Leader-level contact between Washington and Beijing and the management of the bilateral relationship around it: state visits and summit meetings, the accompanying business delegations, and the outcomes announced from them, including tariff adjustments, agricultural and aircraft purchases and dialogue channels. The agenda routinely extends beyond the dyad to third-party files such as Iran, Taiwan and North Korea, which are carried by their own theaters.','Kontakte auf Führungsebene zwischen Washington und Peking und das Management der bilateralen Beziehung darum herum: Staatsbesuche und Gipfeltreffen, die begleitenden Wirtschaftsdelegationen sowie die daraus verkündeten Ergebnisse, darunter Zollanpassungen, Agrar- und Flugzeugkäufe und Dialogkanäle. Die Tagesordnung reicht regelmäßig über die Dyade hinaus zu Drittthemen wie Iran, Taiwan und Nordkorea, die in eigenen Theatern geführt werden.',ARRAY['AMERICAS-USA'],true,89,'Leader-level diplomacy is the largest single strand of coverage in the US-China relationship. A state visit to Beijing brought the US president and a delegation of company chief executives to meetings with Xi Jinping, followed by a reciprocal invitation to Washington. The announced outcomes were economic: reciprocal tariff reductions, renewed import permits for US beef, soybean purchase commitments, an aircraft order, and agreement to open an intergovernmental dialogue on artificial intelligence. Other agenda items — Iran, Taiwan, North Korea — produced no announced agreement. Coverage of the same events divides sharply: Chinese state media present the meetings as a new chapter of major-power cooperation, Western and allied outlets split between reading them as a working stabilisation of the rivalry and as a thin return for a state visit, and Russian state media read them as evidence of relative American decline. A large share of Western reporting is descriptive rather than evaluative.','Diplomatie auf Führungsebene ist der größte einzelne Berichterstattungsstrang der Beziehung zwischen den USA und China. Ein Staatsbesuch in Peking führte den US-Präsidenten und eine Delegation von Unternehmenschefs zu Treffen mit Xi Jinping, gefolgt von einer Gegeneinladung nach Washington. Die verkündeten Ergebnisse waren wirtschaftlicher Natur: wechselseitige Zollsenkungen, erneuerte Einfuhrgenehmigungen für US-Rindfleisch, Zusagen zum Sojabohnenkauf, eine Flugzeugbestellung und die Vereinbarung, einen zwischenstaatlichen Dialog zur künstlichen Intelligenz aufzunehmen. Weitere Tagesordnungspunkte — Iran, Taiwan, Nordkorea — brachten keine verkündete Einigung. Die Berichterstattung über dieselben Ereignisse geht deutlich auseinander: chinesische Staatsmedien präsentieren die Treffen als neues Kapitel der Großmächtekooperation, westliche und verbündete Medien schwanken zwischen der Lesart einer funktionierenden Stabilisierung der Rivalität und der einer dünnen Ausbeute für einen Staatsbesuch, und russische Staatsmedien deuten sie als Beleg relativen amerikanischen Machtverlusts. Ein großer Teil der westlichen Berichterstattung ist beschreibend statt wertend.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-CHINA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_tech_restrictions','Export controls and semiconductor access','Exportkontrollen und Halbleiterzugang','Restrictions on the movement of advanced semiconductor technology between the United States and China: entity-list designations, licensing conditions attached to Nvidia and other US chip sales, controls on lithography equipment coordinated with allied governments, and enforcement against diversion and smuggling. Controls operate in both directions — US authorities license what may be exported, while Chinese authorities decide what may be imported and have withheld approval for chips the United States had cleared.','Beschränkungen für den Transfer fortgeschrittener Halbleitertechnologie zwischen den Vereinigten Staaten und China: Aufnahmen in die Entity List, Auflagen für Chipverkäufe von Nvidia und anderen US-Anbietern, mit verbündeten Regierungen abgestimmte Kontrollen für Lithografieanlagen sowie die Verfolgung von Umgehung und Schmuggel. Die Kontrollen wirken in beide Richtungen: US-Behörden lizenzieren, was ausgeführt werden darf, chinesische Behörden entscheiden über die Einfuhr und verweigerten die Freigabe für Chips, welche die Vereinigten Staaten bereits genehmigt hatten.',ARRAY['AMERICAS-USA'],true,90,'Export controls are the principal instrument through which the United States acts on the technology relationship, and their operation has become two-sided. Washington maintains entity-list designations and licensing conditions on advanced chip sales, coordinates lithography controls with allied governments, and enforces against diversion — including a prosecution over the diversion of billions of dollars of Nvidia chips and a settlement with a US equipment maker over unlawful exports. Beijing''s response has moved beyond objection: it has withheld approval for H200 imports that US authorities had cleared for export, conditioned approvals on its own terms, and pressed domestic substitution. Chinese firms have also acquired US chip tools through Southeast Asian intermediaries. Coverage divides on disjoint lines: Western, allied and specialist outlets treat the controls as protection of a lead with direct military relevance, while Chinese state media present them as suppression of legitimate development that disrupts global chip supply chains and is failing on its own terms.','Exportkontrollen sind das Hauptinstrument, mit dem die Vereinigten Staaten auf das Technologieverhältnis einwirken, und ihre Anwendung ist zweiseitig geworden. Washington unterhält Entity-List-Aufnahmen und Auflagen für den Verkauf von Spitzenchips, stimmt Lithografiekontrollen mit verbündeten Regierungen ab und verfolgt Umgehungen — darunter ein Strafverfahren wegen der Umleitung von Nvidia-Chips im Milliardenwert und ein Vergleich mit einem US-Anlagenbauer wegen unrechtmäßiger Ausfuhren. Pekings Reaktion geht über Protest hinaus: Es verweigerte die Freigabe für H200-Einfuhren, welche die US-Behörden zur Ausfuhr freigegeben hatten, knüpfte Genehmigungen an eigene Bedingungen und trieb die heimische Substitution voran. Chinesische Firmen beschafften US-Chipwerkzeuge zudem über südostasiatische Zwischenhändler. Die Berichterstattung verläuft entlang getrennter Linien: westliche, verbündete und Fachmedien behandeln die Kontrollen als Schutz eines militärisch unmittelbar relevanten Vorsprungs, während chinesische Staatsmedien sie als Unterdrückung legitimer Entwicklung darstellen, die globale Chip-Lieferketten stört und an den eigenen Zielen scheitert.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-CHINA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_theater','US-China economic and technological competition','Wirtschaftlicher und technologischer Wettbewerb USA-China','The bilateral economic and technological contest between the United States and China: tariffs and trade investigations, export controls on advanced semiconductors, the competition over artificial intelligence, dependence on Chinese critical-mineral supply, and the leader-level diplomacy conducted alongside them. Both governments hold and use restrictive instruments — Washington licenses access to advanced chips and design tools, Beijing licenses rare-earth exports and decides on market access and foreign acquisitions. The geographic flashpoints where the two also compete are carried by separate theaters.','Der bilaterale wirtschaftliche und technologische Wettstreit zwischen den Vereinigten Staaten und China: Zölle und Handelsuntersuchungen, Exportkontrollen für Spitzenhalbleiter, der Wettbewerb um künstliche Intelligenz, die Abhängigkeit von chinesischen kritischen Rohstoffen sowie die begleitende Diplomatie auf Führungsebene. Beide Regierungen verfügen über restriktive Instrumente und setzen sie ein: Washington lizenziert den Zugang zu Spitzenchips und Entwurfswerkzeugen, Peking lizenziert Exporte Seltener Erden und entscheidet über Marktzugang und ausländische Übernahmen. Die geografischen Brennpunkte, an denen beide ebenfalls konkurrieren, werden in eigenen Theatern geführt.',ARRAY['AMERICAS-USA','ASIA-CHINA'],true,25,'The United States and China are engaged in a bilateral contest conducted almost entirely through economic and technological instruments. Five strands run through it: tariffs and Section 301 investigations, with US tariff authority itself subject to domestic litigation; export controls on advanced semiconductors, design tools and lithography, coordinated with allied governments; a close race in artificial intelligence in which Chinese models have narrowed the capability gap and firms on both sides contest access, users and blacklisting; dependence on Chinese rare-earth mining, refining and magnet production, met with stockpiling and allied minerals agreements; and leader-level summitry that produced tariff reductions, restored agricultural and aircraft purchases, and an agreed dialogue on artificial intelligence. Restriction runs in both directions: Washington controls what may be exported, while Beijing has withheld approval for chips US authorities had cleared, listed US rare-earth producers under its own export controls, barred procurement from US firms, and blocked a US acquisition of a Chinese AI developer. Coverage divides on observable lines: Western and allied outlets treat the contest as one to be managed and won, Chinese state media present restriction as suppression of legitimate development and cooperation as the alternative, a self-critical Western strand argues the instruments are imposing costs at home, and Russian state media read the relationship as evidence of a multipolar order.','Die Vereinigten Staaten und China tragen einen bilateralen Wettstreit aus, der fast ausschließlich mit wirtschaftlichen und technologischen Instrumenten geführt wird. Fünf Stränge durchziehen ihn: Zölle und Section-301-Verfahren, wobei die US-Zollbefugnis selbst Gegenstand innerstaatlicher Gerichtsverfahren ist; Exportkontrollen für Spitzenhalbleiter, Entwurfswerkzeuge und Lithografie, abgestimmt mit verbündeten Regierungen; ein enges Rennen in der künstlichen Intelligenz, in dem chinesische Modelle den Leistungsabstand verringert haben und Firmen beider Seiten um Zugang, Nutzer und Listungen streiten; die Abhängigkeit von chinesischer Förderung, Raffination und Magnetproduktion Seltener Erden, der mit Reservehaltung und Rohstoffabkommen unter Verbündeten begegnet wird; sowie Gipfeldiplomatie, aus der Zollsenkungen, wieder aufgenommene Agrar- und Flugzeugkäufe und ein vereinbarter Dialog zur künstlichen Intelligenz hervorgingen. Beschränkungen wirken in beide Richtungen: Washington kontrolliert, was ausgeführt werden darf, während Peking die Einfuhr von Chips verweigerte, die US-Behörden freigegeben hatten, US-Produzenten Seltener Erden auf die eigene Exportkontrollliste setzte, die Beschaffung bei US-Firmen untersagte und eine US-Übernahme eines chinesischen KI-Entwicklers blockierte. Die Berichterstattung teilt sich entlang beobachtbarer Linien: westliche und verbündete Medien behandeln den Wettstreit als steuer- und gewinnbar, chinesische Staatsmedien deuten Beschränkungen als Unterdrückung legitimer Entwicklung und Kooperation als Alternative, ein selbstkritischer westlicher Strang sieht die Instrumente Kosten im Inland verursachen, und russische Staatsmedien lesen die Beziehung als Beleg einer multipolaren Ordnung.','theater',ARRAY['us_china_summit_diplomacy','us_china_trade_tariffs','us_china_tech_restrictions','us_china_ai_primacy','us_china_critical_minerals'],ARRAY['taiwan_strait','tsmc_hsinchu','strait_of_malacca','smic_shanghai'],'global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_china_trade_tariffs','Trade and tariff competition','Handels- und Zollwettbewerb','Tariffs, trade investigations and market-access disputes between the United States and China: Section 301 proceedings, tariff rates and their escalation or reduction, anti-dumping measures, agricultural access for US soybeans and beef, treatment of Chinese electric vehicles in the US market, and government procurement restrictions applied in both directions. US tariff authority has been subject to domestic litigation, and both governments have applied and withdrawn measures during the period.','Zölle, Handelsuntersuchungen und Streitigkeiten über Marktzugang zwischen den Vereinigten Staaten und China: Section-301-Verfahren, Zollsätze und deren Erhöhung oder Senkung, Antidumpingmaßnahmen, Marktzugang für US-Sojabohnen und -Rindfleisch, die Behandlung chinesischer Elektrofahrzeuge im US-Markt sowie Beschaffungsbeschränkungen der öffentlichen Hand in beide Richtungen. Die US-Zollbefugnis war Gegenstand innerstaatlicher Gerichtsverfahren; beide Regierungen haben im Zeitraum Maßnahmen ergriffen und wieder zurückgenommen.',ARRAY['AMERICAS-USA'],true,91,'The tariff relationship moved through escalation and partial de-escalation. The United States opened Section 301 investigations covering China and a number of other trading partners; a domestic court ruling narrowed the tariff authority those measures rest on; and the Beijing summit produced reciprocal reductions on some goods together with renewed agricultural access. China applied countermeasures of its own, barring government procurement from dozens of US companies and keeping retaliation in reserve. Disputes also run through specific sectors: Chinese electric vehicles and the question of their access to the US market, soybean and beef purchases, and tariff evasion through third countries. Coverage divides less evenly here than elsewhere in the dyad. Chinese state media frame the measures as unilateral coercion outside the multilateral system. Western coverage is predominantly skeptical of the campaign — arguing it has raised costs and uncertainty for US industry and farmers while strengthening Beijing''s position — and an argument that tariff pressure is producing results is comparatively rare in headline coverage.','Das Zollverhältnis durchlief Eskalation und teilweise Deeskalation. Die Vereinigten Staaten eröffneten Section-301-Untersuchungen gegen China und eine Reihe weiterer Handelspartner; ein innerstaatliches Gerichtsurteil beschnitt die Zollbefugnis, auf der diese Maßnahmen beruhen; und der Pekinger Gipfel brachte wechselseitige Senkungen für einige Waren sowie erneuerten Agrarmarktzugang. China ergriff eigene Gegenmaßnahmen, untersagte die öffentliche Beschaffung bei Dutzenden US-Unternehmen und hielt Vergeltung in Reserve. Streit besteht auch in einzelnen Sektoren: chinesische Elektrofahrzeuge und die Frage ihres Zugangs zum US-Markt, Sojabohnen- und Rindfleischkäufe sowie Zollumgehung über Drittstaaten. Die Berichterstattung ist hier weniger ausgewogen als sonst in der Dyade. Chinesische Staatsmedien deuten die Maßnahmen als unilateralen Zwang außerhalb des multilateralen Systems. Die westliche Berichterstattung steht der Kampagne überwiegend skeptisch gegenüber — sie habe Kosten und Unsicherheit für US-Industrie und Landwirte erhöht und zugleich Pekings Position gestärkt — während das Argument, Zolldruck bringe Ergebnisse, in der Schlagzeilenberichterstattung vergleichsweise selten vorkommt.','atomic',NULL,'{}','regional',NULL::jsonb,'ASIA-CHINA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_culture_wars','National culture war conflicts and polarisation',NULL,NULL,NULL,ARRAY['AMERICAS-USA'],false,89,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_domestic_theater','United States domestic governance conflict','Innenpolitischer Machtkonflikt in den USA','Conflicts over the powers, staffing and rules of United States federal institutions, and over how those institutions treat people inside the country. Covers the courts and executive authority, the central bank, election administration, immigration enforcement in the interior, federal personnel, the security of political figures, media regulation, and the investigation of elite networks. Foreign coverage treats these as indicators of American reliability and of the standards Washington applies abroad.','Konflikte über die Befugnisse, die Besetzung und die Regeln von US-Bundesinstitutionen sowie darüber, wie diese Institutionen Menschen im Inland behandeln. Umfasst Gerichte und Exekutivgewalt, die Notenbank, die Wahlorganisation, den Einwanderungsvollzug im Landesinneren, Bundespersonal, den Schutz politischer Amtsträger, die Medienaufsicht und die Aufklärung von Elitennetzwerken. Ausländische Berichterstattung sieht darin Indikatoren für die Verlässlichkeit der USA und für die Maßstäbe, die Washington im Ausland anlegt.',ARRAY['AMERICAS-USA'],true,24,'Eight distinct disputes run in parallel here. Interior immigration enforcement and the Epstein files generate the largest volume and the widest non-English coverage. The Supreme Court sits at the centre of several at once, having rejected the birthright-citizenship order and struck down the global tariff authority while upholding removal power elsewhere. A contested Federal Reserve succession, a rolling cycle of cabinet departures, a redistricting and ballot-rules fight ahead of the midterms, repeated security incidents around political figures, and regulatory pressure on broadcasters complete the set.','Acht eigenständige Auseinandersetzungen laufen hier parallel. Der Einwanderungsvollzug im Landesinneren und die Epstein-Akten erzeugen das größte Volumen und die breiteste fremdsprachige Berichterstattung. Der Supreme Court steht gleich in mehreren im Mittelpunkt: Er wies die Anordnung zum Geburtsortsprinzip zurück und kippte die globale Zollbefugnis, bestätigte andernorts aber die Entlassungsbefugnis. Eine umstrittene Fed-Nachfolge, eine fortlaufende Kette von Kabinettsabgängen, ein Streit um Wahlkreise und Stimmzettelregeln vor den Zwischenwahlen, wiederholte Sicherheitsvorfälle um politische Amtsträger und regulatorischer Druck auf Sender vervollständigen das Bild.','theater',ARRAY['us_electoral_legitimacy','us_judicial_constraint','us_executive_loyalty','us_fed_independence','us_interior_immigration_enforcement','us_epstein_elite_network','us_political_violence','us_press_freedom'],'{}','global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_electoral_legitimacy','Electoral legitimacy and the midterm contest','Wahllegitimität und der Midterm-Wettstreit','Disputes over how United States elections are administered: the drawing of congressional district boundaries, rules on mail and absentee balloting, voter identification and citizenship-verification requirements, maintenance of voter rolls, and the scope of the Voting Rights Act. Contested through state legislatures and the federal courts.','Auseinandersetzungen über die Organisation von Wahlen in den USA: der Zuschnitt von Kongresswahlkreisen, Regeln zur Brief- und Abwesenheitswahl, Ausweis- und Staatsbürgerschaftsnachweise, die Pflege der Wählerverzeichnisse und die Reichweite des Voting Rights Act. Ausgetragen über die Parlamente der Bundesstaaten und die Bundesgerichte.',ARRAY['AMERICAS-USA'],true,101,'A redistricting contest runs across Texas, Florida, California, Virginia, Utah and South Carolina, with both parties redrawing maps and litigating the results. A Supreme Court ruling narrowing the Voting Rights Act reopened map fights in several states. Federal judges blocked a Postal Service order restricting mail balloting; House Republicans advanced a proof-of-citizenship requirement. An FBI raid on an Ohio voting-rights organisation drew attention shortly before the midterms.','Ein Streit um Wahlkreiszuschnitte zieht sich durch Texas, Florida, Kalifornien, Virginia, Utah und South Carolina, wobei beide Parteien Karten neu zeichnen und die Ergebnisse beklagen. Ein Urteil des Supreme Court zur Einschränkung des Voting Rights Act ließ Kartenstreitigkeiten in mehreren Bundesstaaten neu aufleben. Bundesrichter stoppten eine Anordnung der Post zur Einschränkung der Briefwahl; die Republikaner im Repräsentantenhaus brachten eine Nachweispflicht der Staatsbürgerschaft voran.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_epstein_elite_network','Epstein files and elite networks','Epstein-Akten und Elitennetzwerke','The investigation and disclosure of records concerning Jeffrey Epstein and the people connected to him: Justice Department file releases, congressional depositions and contempt proceedings, civil litigation and settlements, and parallel inquiries opened by other governments. Centred on United States court and congressional process, with subjects in several countries.','Ermittlungen und Aktenfreigaben zu Jeffrey Epstein und den mit ihm verbundenen Personen: Freigaben des Justizministeriums, Vernehmungen und Missachtungsverfahren im Kongress, Zivilklagen und Vergleiche sowie parallele Untersuchungen anderer Regierungen. Zentriert auf US-Gerichts- und Kongressverfahren, mit Betroffenen in mehreren Ländern.',ARRAY['AMERICAS-USA'],true,106,'The Justice Department released successive batches of files and video. Bill and Hillary Clinton testified and later faced contempt resolutions; Ghislaine Maxwell invoked the Fifth Amendment before the House Oversight Committee; the attorney general was subpoenaed and subsequently removed. Consequences reached well beyond the United States: a British former ambassador left the Labour Party and the prime minister''s chief of staff resigned, a Goldman Sachs lawyer stepped down, French prosecutors searched premises linked to a former minister, and Norway and Poland opened inquiries.','Das Justizministerium gab nacheinander Aktenpakete und Videomaterial frei. Bill und Hillary Clinton sagten aus und sahen sich später Missachtungsanträgen gegenüber; Ghislaine Maxwell verweigerte vor dem Kontrollausschuss die Aussage; die Justizministerin wurde vorgeladen und anschließend abberufen. Die Folgen reichten weit über die USA hinaus: Ein früherer britischer Botschafter verließ die Labour-Partei und der Stabschef des Premierministers trat zurück, eine Anwältin von Goldman Sachs schied aus, französische Staatsanwälte durchsuchten Räume mit Bezug zu einem Ex-Minister, und Norwegen und Polen leiteten Untersuchungen ein.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_executive_loyalty','Cabinet turnover and executive loyalty','Kabinettsumbau und Loyalität in der Exekutive','Departures, dismissals and replacements among senior United States federal officials: cabinet secretaries, the attorney general, intelligence and law-enforcement leadership, inspectors general and federal prosecutors. Covers both the appointments process and the reasons given for removals.','Abgänge, Entlassungen und Neubesetzungen unter hohen US-Bundesbeamten: Kabinettsmitglieder, die Justizministerin, die Führung von Nachrichtendiensten und Strafverfolgung, Generalinspekteure und Bundesstaatsanwälte. Umfasst sowohl das Ernennungsverfahren als auch die genannten Gründe für Abberufungen.',ARRAY['AMERICAS-USA'],true,103,'The attorney general was removed after appearing before the House Oversight Committee on the Epstein files; the homeland security secretary departed following a fatal shooting by an officer in Minneapolis; the director of national intelligence resigned. The FBI dismissed agents who had worked on earlier investigations touching the president. Several posts were filled on a temporary basis pending Senate confirmation.','Die Justizministerin wurde nach ihrem Auftritt vor dem Kontrollausschuss des Repräsentantenhauses zu den Epstein-Akten abberufen; die Heimatschutzministerin schied nach tödlichen Schüssen eines Beamten in Minneapolis aus; die Koordinatorin der Nachrichtendienste trat zurück. Das FBI entließ Beamte, die an früheren Ermittlungen mit Bezug zum Präsidenten gearbeitet hatten. Mehrere Posten wurden bis zur Bestätigung durch den Senat kommissarisch besetzt.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_federal_state_authority','Federal versus state authority and governance',NULL,NULL,NULL,ARRAY['AMERICAS-USA'],false,87,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_fed_independence','Federal Reserve independence','Unabhängigkeit der US-Notenbank','The relationship between the United States executive and the Federal Reserve: nomination and confirmation of the chair and governors, the legal limits on removing them, and disputes over the central bank''s autonomy in setting policy. Distinct from routine monetary-policy coverage, which concerns rate decisions rather than institutional control.','Das Verhältnis zwischen der US-Exekutive und der Federal Reserve: Nominierung und Bestätigung des Vorsitzes und der Gouverneure, die rechtlichen Grenzen ihrer Abberufung und Streit über die Autonomie der Notenbank bei der Politikgestaltung. Abzugrenzen von der routinemäßigen Geldpolitik-Berichterstattung, die Zinsentscheidungen und nicht institutionelle Kontrolle betrifft.',ARRAY['AMERICAS-USA'],true,104,'Kevin Warsh was nominated to succeed Jerome Powell as chair and cleared the Senate committee stage. An attempt to remove governor Lisa Cook was blocked in court, and a Justice Department referral against Powell was later dropped. Powell served out his term, publicly warning that the institution was undergoing a stress test and that lost credibility would be difficult to restore.','Kevin Warsh wurde als Nachfolger von Jerome Powell für den Vorsitz nominiert und passierte die Ausschussstufe im Senat. Der Versuch, die Gouverneurin Lisa Cook abzuberufen, wurde gerichtlich gestoppt; eine Anzeige des Justizministeriums gegen Powell wurde später fallengelassen. Powell beendete seine Amtszeit und warnte öffentlich, die Institution durchlaufe einen Stresstest und verlorene Glaubwürdigkeit sei schwer wiederherzustellen.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_interior_immigration_enforcement','Interior immigration enforcement','Einwanderungsdurchsetzung im Landesinneren','Immigration enforcement conducted inside the United States rather than at the border: arrests and removals by Immigration and Customs Enforcement, detention facilities and conditions within them, judicial review of individual cases, and disputes between federal agencies and state or city governments over cooperation. Border, cartel and bilateral trade questions belong to the US-Mexico theater.','Einwanderungsvollzug innerhalb der USA statt an der Grenze: Festnahmen und Abschiebungen durch die Einwanderungsbehörde ICE, Hafteinrichtungen und die Bedingungen darin, gerichtliche Überprüfung von Einzelfällen sowie Streit zwischen Bundesbehörden und Bundesstaaten oder Städten über die Zusammenarbeit. Grenz-, Kartell- und bilaterale Handelsfragen gehören zum US-Mexiko-Feld.',ARRAY['AMERICAS-USA'],true,105,'Congress approved a large multi-year funding increase for the agency. Deaths in custody rose and a measles outbreak was recorded at a Texas facility; judges ordered individual releases, including of a five-year-old and an 86-year-old French national. Agents were deployed to airports during a partial government shutdown, and their planned presence at stadiums during the World Cup drew majority public opposition in polling. State and city governments clashed with federal authorities over cooperation, and a county charged an officer over a non-fatal shooting.','Der Kongress bewilligte eine große mehrjährige Mittelaufstockung für die Behörde. Todesfälle in Gewahrsam nahmen zu, in einer Einrichtung in Texas wurden Masern festgestellt; Richter ordneten Freilassungen an, darunter die eines Fünfjährigen und einer 86-jährigen Französin. Beamte wurden während eines teilweisen Regierungsstillstands an Flughäfen eingesetzt, ihre geplante Präsenz in Stadien während der WM stieß in Umfragen mehrheitlich auf Ablehnung. Bundesstaaten und Städte gerieten mit Bundesbehörden über die Zusammenarbeit aneinander.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_judicial_constraint','Federal courts and executive power','Bundesgerichte und die Macht der Exekutive','Litigation over the reach of United States executive authority and the rulings that decide it: emergency and merits decisions of the Supreme Court, injunctions issued by federal district judges, and appellate review. Covers both decisions constraining the executive and decisions expanding its discretion.','Rechtsstreitigkeiten über die Reichweite der US-Exekutivgewalt und die Urteile, die darüber entscheiden: Eil- und Hauptsacheentscheidungen des Supreme Court, einstweilige Verfügungen von Bundesbezirksrichtern und Berufungsverfahren. Umfasst sowohl Entscheidungen, die die Exekutive begrenzen, als auch solche, die ihren Ermessensspielraum erweitern.',ARRAY['AMERICAS-USA'],true,102,'The Court rejected an attempt to limit birthright citizenship and ruled the global tariff order an unlawful use of executive power, prompting a replacement 10% tariff. It blocked the removal of a Federal Reserve governor while upholding removal power over other agencies, and expanded immigration discretion in TPS and southern-border decisions. Lower courts blocked a mail-ballot order and the defunding of public broadcasters.','Das Gericht wies den Versuch zurück, das Geburtsortsprinzip einzuschränken, und erklärte die globale Zollanordnung für einen unrechtmäßigen Gebrauch der Exekutivgewalt, woraufhin ein pauschaler Zoll von 10 Prozent folgte. Es stoppte die Abberufung einer Fed-Vorständin, bestätigte aber die Entlassungsbefugnis gegenüber anderen Behörden und erweiterte das Ermessen bei TPS- und Grenzentscheidungen. Untergerichte stoppten eine Briefwahlanordnung und die Mittelstreichung für öffentliche Sender.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_mexico_military_pressure','US intervention pressure and Mexican sovereignty','US-Interventionsdruck und mexikanische Souveränität','Friction over US covert operations (CIA), proposals for military action against cartels on Mexican soil, indictments of Mexican officials, and disputes over political interference, set against Mexico''s sovereignty position.','Spannungen über verdeckte US-Operationen (CIA), Vorschläge für Militäraktionen gegen Kartelle auf mexikanischem Boden, Anklagen gegen mexikanische Amtsträger und Auseinandersetzungen über politische Einmischung, gegenüber Mexikos Souveränitätsposition.',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],true,NULL,'This axis covers US pressure on Mexico that reaches beyond trade into security and politics. Its dominant strands in current coverage are covert and paramilitary — the deaths of CIA officers during a counter-narcotics operation in Chihuahua, US indictments of sitting Mexican officials, and repeated threats of unilateral military strikes against cartels on Mexican soil — alongside a political-interference dispute, with Mexico City accusing Washington of meddling in its internal affairs and elections. Against all of it, President Sheinbaum invokes a sovereignty red line of cooperation without subordination and constitutional non-intervention. Readings compete: US conservative voices call intervention necessary against a partner that cannot deliver; Mexican and Hispanic-American media call it a sovereignty violation; Western mainstream press covers it as scandal and diplomatic strain; and Russian and Chinese state media cast it as Monroe-Doctrine imperialism in Washington''s backyard.','Diese Achse umfasst US-Druck auf Mexiko, der über den Handel hinaus in Sicherheit und Politik reicht. Ihre dominierenden Stränge in der aktuellen Berichterstattung sind verdeckt und paramilitärisch — der Tod von CIA-Beamten während einer Anti-Drogen-Operation in Chihuahua, US-Anklagen gegen amtierende mexikanische Amtsträger und wiederholte Drohungen mit einseitigen Militärschlägen gegen Kartelle auf mexikanischem Boden — neben einem Streit über politische Einmischung, bei dem Mexiko-Stadt Washington Einmischung in innere Angelegenheiten und Wahlen vorwirft. Dem allen setzt Präsidentin Sheinbaum eine rote Souveränitätslinie entgegen: Kooperation ohne Unterordnung und verfassungsmäßige Nichtintervention. Die Lesarten konkurrieren: US-konservative Stimmen halten die Intervention gegen einen Partner, der nicht liefern kann, für notwendig; mexikanische und hispanoamerikanische Medien nennen sie eine Souveränitätsverletzung; westliche Mainstream-Presse berichtet über Skandal und diplomatische Spannungen; und russische und chinesische Staatsmedien deuten sie als Monroe-Doktrin-Imperialismus in Washingtons Hinterhof.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-MEXICO')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_mexico_trade_border','Tariffs, border and migration leverage','Zölle, Grenze und Migration als Druckmittel','Tariff threats, border enforcement and migration policy as bargaining instruments in the US-Mexico relationship.','Zolldrohungen, Grenzsicherung und Migrationspolitik als Verhandlungsinstrumente in den Beziehungen zwischen USA und Mexiko.',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],true,NULL,'The economic and border front of the US-Mexico relationship treats tariffs, the USMCA/T-MEC trade pact, and migration and border enforcement as interlocking instruments of leverage. Washington has wielded tariff threats — on autos, steel and aluminium — and the renegotiation or non-renewal of USMCA to extract Mexican cooperation on migration, deportation, fentanyl and border security, including National Guard deployments and a screwworm-driven livestock-trade dispute. Mexico, its economy deeply integrated with that of the United States, answers with counter-measures and diversification toward the EU and other partners. Coverage divides between a US conservative reading of legitimate, results-producing leverage; a business and wire reading centred on supply-chain and market disruption; and a Mexican reading of economic coercion that breaches the trade pact and national dignity.','Die wirtschaftliche und grenzpolitische Front der Beziehung zwischen den USA und Mexiko behandelt Zölle, das Handelsabkommen USMCA/T-MEC sowie Migration und Grenzsicherung als ineinandergreifende Druckmittel. Washington hat Zolldrohungen — auf Autos, Stahl und Aluminium — sowie die Neuverhandlung oder Nichtverlängerung des USMCA eingesetzt, um Mexikos Kooperation bei Migration, Abschiebung, Fentanyl und Grenzsicherung zu erzwingen, einschließlich Entsendungen der Nationalgarde und eines durch den Schraubenwurm ausgelösten Streits um den Viehhandel. Mexiko, dessen Wirtschaft eng mit der der USA verflochten ist, antwortet mit Gegenmaßnahmen und Diversifizierung hin zur EU und anderen Partnern. Die Berichterstattung teilt sich zwischen einer US-konservativen Lesart legitimer, ergebnisorientierter Druckmittel; einer wirtschafts- und agenturgeprägten Lesart mit Fokus auf Lieferketten- und Marktstörungen; und einer mexikanischen Lesart wirtschaftlichen Zwangs, der das Handelsabkommen und die nationale Würde verletzt.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-MEXICO')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_political_violence','Political violence and protective security','Politische Gewalt und Personenschutz','Attacks, attempted attacks and threats directed at United States political figures and institutions, and the protective and judicial response: Secret Service operations, prosecutions of suspects, security arrangements for officials and judges, and disclosed plots against political events.','Angriffe, Angriffsversuche und Drohungen gegen politische Amtsträger und Institutionen in den USA sowie die Schutz- und Justizreaktion: Einsätze des Secret Service, Strafverfahren gegen Verdächtige, Sicherheitsvorkehrungen für Amtsträger und Richter sowie aufgedeckte Anschlagspläne auf politische Veranstaltungen.',ARRAY['AMERICAS-USA'],true,107,'Shots were fired at the White House Correspondents'' Dinner, from which the president was evacuated; a suspect was charged and pleaded not guilty, and officials later said the president was the likely target. A separate armed man was killed entering the Mar-a-Lago perimeter, gunfire was exchanged near the White House and near the vice-president''s motorcade, and the FBI reported foiling a drone-and-sniper plot against an event. A member of Congress was attacked at a town hall in Minneapolis, and a Supreme Court justice described heightened security and threats to the judiciary.','Beim Korrespondentendinner im Weißen Haus fielen Schüsse, der Präsident wurde evakuiert; ein Verdächtiger wurde angeklagt und bekannte sich nicht schuldig, Behörden nannten den Präsidenten später als wahrscheinliches Ziel. Ein bewaffneter Mann wurde beim Eindringen auf das Gelände von Mar-a-Lago erschossen, nahe dem Weißen Haus und dem Konvoi des Vizepräsidenten fielen Schüsse, und das FBI vereitelte nach eigenen Angaben einen Anschlagsplan mit Drohnen und Scharfschützen. Ein Kongressmitglied wurde bei einer Bürgerversammlung in Minneapolis angegriffen.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_press_freedom','Press freedom and broadcast regulation','Pressefreiheit und Rundfunkaufsicht','The relationship between United States federal authority and news organisations: Federal Communications Commission action on broadcast licences, funding decisions affecting public broadcasters, press access to government departments, defamation litigation brought against news outlets, and First Amendment rulings arising from these.','Das Verhältnis zwischen US-Bundesbehörden und Nachrichtenorganisationen: Maßnahmen der Rundfunkaufsicht FCC zu Sendelizenzen, Finanzierungsentscheidungen für öffentliche Sender, Pressezugang zu Ministerien, Verleumdungsklagen gegen Medien und die daraus folgenden Urteile zum Ersten Verfassungszusatz.',ARRAY['AMERICAS-USA'],true,108,'The FCC opened licence reviews at stations carrying a network programme after a presenter''s joke about the first lady, and the network''s lawyers accused the regulator of acting for political reasons. A federal judge blocked an order ending funding for NPR and PBS on First Amendment grounds. The Pentagon moved to restrict press access again after losing in court, a $10 billion defamation suit was refiled against a newspaper, and the Committee to Protect Journalists and foreign outlets recorded visa revocations affecting a Costa Rican newspaper''s executives.','Die FCC leitete Lizenzüberprüfungen bei Sendern ein, die ein Netzwerkprogramm ausstrahlen, nachdem ein Moderator einen Witz über die First Lady gemacht hatte; die Anwälte des Senders warfen der Aufsicht politisch motiviertes Handeln vor. Ein Bundesrichter stoppte unter Berufung auf den Ersten Verfassungszusatz die Streichung der Mittel für NPR und PBS. Das Pentagon schränkte den Pressezugang nach einer Niederlage vor Gericht erneut ein, eine Verleumdungsklage über 10 Milliarden Dollar gegen eine Zeitung wurde neu eingereicht.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_arms_control','Nuclear arms control and strategic stability','Nukleare Rüstungskontrolle und strategische Stabilität','The nuclear arms-control relationship between the United States and Russia: treaty limits on deployed warheads and delivery systems, verification and inspection arrangements, strategic-stability talks, missile-defence programmes and novel delivery systems that fall outside existing frameworks.','Das nukleare Rüstungskontrollverhältnis zwischen den Vereinigten Staaten und Russland: vertragliche Obergrenzen für stationierte Sprengköpfe und Trägersysteme, Verifikations- und Inspektionsregelungen, Gespräche über strategische Stabilität, Raketenabwehrprogramme sowie neuartige Trägersysteme außerhalb bestehender Rahmen.',ARRAY['AMERICAS-USA'],true,94,'New START expired on 4 February 2026, ending the last treaty limits on the two largest nuclear arsenals and with them the inspection and data-exchange regime. The UN called the lapse a grave moment and coverage widely anticipates an unconstrained arms race. Talks on a successor have not stopped -- proposals have been floated and reported as close to agreement more than once, and China has publicly urged the two to resume strategic-stability dialogue -- but nothing has been concluded. Moscow attributes the collapse to rejected proposals and to the Golden Dome missile-defence programme; Washington points to Russian systems built outside any treaty''s scope.','New START lief am 4. Februar 2026 aus und beendete die letzten vertraglichen Obergrenzen für die beiden größten Nukleararsenale und damit auch das Inspektions- und Datenaustauschregime. Die UN nannte dies einen ernsten Moment; die Berichterstattung erwartet überwiegend ein ungebremstes Wettrüsten. Gespräche über einen Nachfolger laufen weiter -- Vorschläge wurden mehrfach als kurz vor einer Einigung berichtet, und China forderte beide Seiten öffentlich zur Wiederaufnahme des Dialogs über strategische Stabilität auf -- abgeschlossen wurde nichts. Moskau führt den Zusammenbruch auf zurückgewiesene Vorschläge und das Raketenabwehrprogramm Golden Dome zurück; Washington verweist auf russische Systeme außerhalb jedes Vertragsrahmens.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_bilateral_channel','Bilateral channel and normalisation','Bilateraler Gesprächskanal und Normalisierung','The working mechanism of the US-Russia relationship: envoy missions, foreign-minister contacts, leader-level calls, summit formats and the state of diplomatic and military channels between Washington and Moscow. Covers the machinery of contact itself rather than the substance of the Ukraine negotiations, which has its own node.','Der Arbeitsmechanismus des Verhältnisses zwischen den USA und Russland: Missionen von Sondergesandten, Kontakte der Außenminister, Telefonate auf Führungsebene, Gipfelformate sowie der Zustand der diplomatischen und militärischen Kanäle zwischen Washington und Moskau. Erfasst wird das Kontaktgeschehen selbst, nicht der Inhalt der Ukraine-Verhandlungen, für den ein eigener Knoten besteht.',ARRAY['AMERICAS-USA'],true,93,'Contact is far denser than at any point since 2022. US envoys have travelled repeatedly to Moscow, the two militaries have re-established high-level communication, foreign ministers speak by phone, and leader-level calls have become routine enough to include congratulatory exchanges. Moscow presents this as overdue recognition of parity while simultaneously accusing Washington of stalling and issuing ultimatums -- the two Kremlin registers run side by side.

The most telling pattern here is where the coverage lives rather than what it says. Russian state media treat the bilateral relationship as a standing subject and produce continuous commentary on its condition; Western outlets cover the same meetings and calls almost entirely as Ukraine-war developments, with the relationship itself appearing only as context. The result is that Moscow generates a large body of explicit narrative about the relationship while the Western position on it has to be inferred from war reporting -- an asymmetry in framing, not in the underlying events, and one reason the Kremlin''s account of the relationship travels more easily than any competing one.','Die Kontaktdichte ist so hoch wie zu keinem Zeitpunkt seit 2022. US-Sondergesandte reisten mehrfach nach Moskau, beide Streitkräfte stellten die Kommunikation auf hoher Ebene wieder her, die Außenminister telefonieren, und Gespräche auf Führungsebene sind so alltäglich geworden, dass sie Glückwünsche einschließen. Moskau stellt dies als überfällige Anerkennung der Ebenbürtigkeit dar und wirft Washington zugleich Hinhalten und Ultimaten vor -- beide Register laufen nebeneinander.

Aufschlussreicher als der Inhalt ist, wo diese Berichterstattung stattfindet. Russische Staatsmedien behandeln das bilaterale Verhältnis als dauerhaften Gegenstand und kommentieren seinen Zustand fortlaufend; westliche Medien berichten über dieselben Treffen und Telefonate fast ausschließlich als Entwicklungen des Ukrainekriegs, das Verhältnis selbst erscheint nur als Kontext. So entsteht in Moskau ein großer Bestand ausdrücklicher Erzählungen über die Beziehung, während die westliche Position dazu aus der Kriegsberichterstattung erschlossen werden muss -- eine Asymmetrie der Rahmung, nicht der Ereignisse, und ein Grund, weshalb die Kreml-Darstellung des Verhältnisses leichter Verbreitung findet als konkurrierende.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_election_interference','Election interference and information warfare',NULL,NULL,NULL,ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],false,95,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_sanctions_leverage','Sanctions relief as leverage','Sanktionslockerung als Druckmittel','American sanctions on Russian energy and finance used as an adjustable instrument: waivers, general licences and exemptions issued, extended, allowed to lapse and reinstated, and the effect of those decisions on Russian export revenue, on third-country buyers, and on coordination with European partners. Distinct from European enforcement action against the shadow fleet, which sits in the Russia-Europe theater.','Amerikanische Sanktionen gegen russische Energie und Finanzwirtschaft als verstellbares Instrument: Ausnahmegenehmigungen, Generallizenzen und Befreiungen, die erteilt, verlängert, auslaufen gelassen und wieder in Kraft gesetzt werden, sowie deren Wirkung auf russische Exporteinnahmen, auf Käufer in Drittstaaten und auf die Abstimmung mit europäischen Partnern. Abzugrenzen von der europäischen Durchsetzung gegen die Schattenflotte, die im Theater Russland-Europa liegt.',ARRAY['AMERICAS-USA'],true,92,'Waiver policy has moved repeatedly through 2026. Washington eased restrictions on cargoes already at sea, granted and then extended a 30-day waiver covering Indian purchases, exempted Rosneft''s German operations and approved a Lukoil carve-out for Bulgaria, before letting waivers lapse and signalling further changes. Each move drew objections from Kyiv and from European and British partners, and congressional pressure for a new sanctions bill persists. Indian and other buyers have continued purchasing throughout, treating the waivers as confirmation the restrictions were unenforceable rather than as permission.','Die Ausnahmepolitik hat sich 2026 mehrfach geändert. Washington lockerte Beschränkungen für bereits auf See befindliche Ladungen, gewährte und verlängerte eine 30-Tage-Ausnahme für indische Käufe, befreite das Deutschlandgeschäft von Rosneft und genehmigte eine Lukoil-Ausnahme für Bulgarien, ließ Ausnahmen dann auslaufen und kündigte weitere Änderungen an. Jeder Schritt rief Einwände aus Kyjiw sowie von europäischen und britischen Partnern hervor; im Kongress hält der Druck für ein neues Sanktionsgesetz an. Indische und andere Käufer kauften durchgehend weiter.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_theater','US-Russia strategic relationship','Das strategische Verhältnis zwischen den USA und Russland','The bilateral relationship between the United States and Russia, treated as a subject in its own right: the diplomatic channel between Washington and Moscow, the American sanctions instruments applied to Russian energy and finance, and the nuclear arms-control framework the two states share. Distinct from the war in Ukraine, which is covered by its own theater, though the two intersect constantly.','Das bilaterale Verhältnis zwischen den Vereinigten Staaten und Russland als eigenständiger Gegenstand: der diplomatische Kanal zwischen Washington und Moskau, die amerikanischen Sanktionsinstrumente gegenüber russischer Energie und Finanzwirtschaft sowie der gemeinsame nukleare Rüstungskontrollrahmen. Abzugrenzen vom Krieg in der Ukraine, der ein eigenes Theater hat, auch wenn sich beide ständig überschneiden.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],true,26,'The relationship is in an unsettled thaw. Working contacts have been rebuilt -- envoy visits to Moscow, a resumed high-level military channel, repeated leader-level calls -- while Washington has repeatedly issued and withdrawn waivers on Russian oil, drawing objections from European and British partners still tightening enforcement. The last nuclear warhead limits lapsed with New START in February 2026, leaving the two arsenals unconstrained for the first time in decades. Coverage divides less along US-versus-Russia lines than over how much accommodation of Moscow is warranted, with Western outlets on both sides of that question and third-country buyers treating the whole framework as conditions to navigate.

Note where each camp does its arguing. Russian state media treat the bilateral relationship as a subject in itself and comment on it continuously; Western coverage engages the same events mainly through the war in Ukraine and through sanctions policy, seldom as bilateral commentary. Both camps are present across this theater, but they are not arguing on the same terrain.','Das Verhältnis befindet sich in einem ungefestigten Tauwetter. Arbeitskontakte wurden wieder aufgebaut -- Besuche von Sondergesandten in Moskau, ein wieder aufgenommener militärischer Kanal auf hoher Ebene, wiederholte Telefonate auf Führungsebene -- während Washington Ausnahmegenehmigungen für russisches Öl mehrfach erteilte und zurücknahm, was Einwände europäischer und britischer Partner hervorrief, die die Durchsetzung weiter verschärfen. Die letzten nuklearen Obergrenzen liefen im Februar 2026 mit New START aus; erstmals seit Jahrzehnten sind beide Arsenale unbegrenzt. Die Berichterstattung teilt sich weniger entlang der Linie USA gegen Russland als an der Frage, wie viel Entgegenkommen gegenüber Moskau gerechtfertigt ist.

Aufschlussreich ist, wo die jeweilige Seite ihre Argumente vorbringt. Russische Staatsmedien behandeln das bilaterale Verhältnis als eigenständigen Gegenstand und kommentieren es fortlaufend; westliche Berichterstattung nähert sich denselben Ereignissen vor allem über den Ukrainekrieg und über die Sanktionspolitik, selten als bilateraler Kommentar. Beide Lager sind in diesem Theater präsent, aber sie streiten nicht auf demselben Terrain.','theater',ARRAY['us_russia_sanctions_leverage','us_russia_bilateral_channel','us_russia_arms_control'],ARRAY['yamal_lng','west_siberian_basin','samotlor_field'],'global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_venezuela_relations','US coercion and military action','US-Zwangsmaßnahmen und Militäraktionen','US coercive and military action toward Venezuela: the operation that detained Maduro, continued military presence and maritime interdiction, counter-narcotics strikes on vessels and on the Tren de Aragua network, and statements proposing US annexation.','Militärisches und erzwingendes Vorgehen der USA gegenüber Venezuela: die Operation zur Festnahme Maduros, fortgesetzte Militärpräsenz und Seeblockaden, Anti-Drogen-Angriffe auf Schiffe und das Netzwerk Tren de Aragua sowie Äußerungen über eine Annexion durch die USA.',ARRAY['AMERICAS-VENEZUELA'],true,99,'A US military operation detained the sitting Venezuelan president, who now faces narcoterrorism proceedings in a New York court. Since then the United States has maintained a military presence in and around the country, seized tankers linked to Venezuelan crude, and carried out strikes on vessels alleged to carry narcotics as well as on the leadership of the Tren de Aragua network, in at least one case jointly with Venezuelan forces. Congressional war-powers resolutions seeking to limit the deployment were introduced and narrowly defeated. Statements from the US president proposing that Venezuela become part of the United States were publicly rejected by the interim administration. The lawfulness of the operation and of the maritime strikes remains disputed.','Eine US-Militäroperation nahm den amtierenden venezolanischen Präsidenten fest, der sich nun in New York wegen Narkoterrorismus vor Gericht verantworten muss. Seither halten die USA eine Militärpräsenz im und um das Land aufrecht, beschlagnahmten Tanker mit venezolanischem Rohöl und führten Angriffe auf mutmaßliche Drogenschiffe sowie auf die Führung des Netzwerks Tren de Aragua durch -- in mindestens einem Fall gemeinsam mit venezolanischen Kräften. Im Kongress eingebrachte Resolutionen zu den Kriegsvollmachten, die den Einsatz begrenzen sollten, scheiterten knapp. Äußerungen des US-Präsidenten, Venezuela solle Teil der USA werden, wies die Übergangsverwaltung öffentlich zurück. Die Rechtmäßigkeit der Operation und der Angriffe auf See bleibt umstritten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-VENEZUELA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('venezuela_political_transition','Venezuela post-intervention transition','Venezuelas Uebergang nach der Intervention','The political settlement after Maduro''s removal: the interim administration''s mandate and legitimacy, the timing and conduct of elections, the opposition''s position, and governance, wage and security measures.','Die politische Einigung nach Maduros Absetzung: Mandat und Legitimität der Übergangsverwaltung, Zeitpunkt und Durchführung von Wahlen, die Position der Opposition sowie Regierungs-, Lohn- und Sicherheitsmaßnahmen.',ARRAY['AMERICAS-VENEZUELA'],true,98,'Maduro''s vice-president took office as acting head of state under a negotiated arrangement reached with Washington, and remained in place after the initial appointment period lapsed. The administration has replaced military commanders, raised wages and pensions, and advanced economic reform, while the opposition led by María Corina Machado was left outside the settlement and continues to press for early elections and a return from exile. Detentions and releases of opposition figures, street protests and the absence of a fixed electoral timetable are the recurring flashpoints. Whether this represents a genuine transition or a continuation of the previous governing bloc under new management is the central contested question.','Maduros Vizepräsidentin übernahm im Rahmen einer mit Washington ausgehandelten Vereinbarung das Amt der geschäftsführenden Staatschefin und blieb auch nach Ablauf der ursprünglichen Amtszeit im Amt. Die Regierung tauschte Militärkommandeure aus, erhöhte Löhne und Renten und trieb Wirtschaftsreformen voran, während die Opposition unter María Corina Machado von der Einigung ausgeschlossen blieb und weiterhin auf vorgezogene Wahlen und eine Rückkehr aus dem Exil drängt. Festnahmen und Freilassungen von Oppositionellen, Straßenproteste und das Fehlen eines festen Wahlkalenders sind die wiederkehrenden Konfliktpunkte. Ob dies ein echter Übergang oder die Fortsetzung des bisherigen Regierungslagers unter neuer Führung ist, bleibt die zentrale strittige Frage.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-VENEZUELA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('venezuela_sanctions_oil','Oil restart and economic opening','Wiederanlauf der Ölförderung und wirtschaftliche Öffnung','The reopening of Venezuela''s oil sector: sanctions relief and licensing, the return of international operators, recovery in production and exports, hydrocarbon-law and contract reform, and sovereign debt restructuring.','Die Wiederöffnung des venezolanischen Ölsektors: Sanktionslockerungen und Lizenzvergabe, die Rückkehr internationaler Betreiber, die Erholung von Förderung und Exporten, die Reform des Kohlenwasserstoffrechts und der Verträge sowie die Umstrukturierung der Staatsschulden.',ARRAY['AMERICAS-VENEZUELA'],true,100,'Venezuela holds the world''s largest proven crude reserves, most of it heavy oil in the Orinoco belt, and years of sanctions had left the sector largely closed to Western operators. Sanctions relief reversed that: licences were issued, majors and independents negotiated returns, exports climbed to their highest level in years, and buyers in the United States, India and Europe re-entered the market. A revised hydrocarbon law, contract terms, arbitration exposure and unresolved debt claims determine how far the recovery can run. The economics are inseparable from the political settlement that produced them, and reporting divides over who ultimately benefits.','Venezuela verfügt über die größten nachgewiesenen Rohölreserven der Welt, überwiegend Schweröl im Orinoco-Gürtel; jahrelange Sanktionen hatten den Sektor für westliche Betreiber weitgehend verschlossen. Die Sanktionslockerung kehrte das um: Lizenzen wurden erteilt, Konzerne und unabhängige Förderer verhandelten über eine Rückkehr, die Exporte stiegen auf den höchsten Stand seit Jahren, und Abnehmer in den USA, Indien und Europa kehrten an den Markt zurück. Ein überarbeitetes Kohlenwasserstoffgesetz, Vertragsbedingungen, Schiedsverfahren und ungeklärte Schuldenansprüche bestimmen, wie weit die Erholung tragen kann. Die Wirtschaft ist untrennbar mit der politischen Einigung verbunden, aus der sie hervorging; die Berichterstattung ist uneins darüber, wer letztlich profitiert.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-VENEZUELA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('venezuela_theater','Venezuela after the US intervention','Venezuela nach der US-Intervention','Venezuela''s contested trajectory after the US operation that removed Nicolás Maduro: the mandate of the interim administration, the reopening of the oil sector, the legality of the intervention, and the unresolved Essequibo claim against Guyana.','Venezuelas umstrittener Weg nach der US-Operation, die Nicolás Maduro absetzte: das Mandat der Übergangsverwaltung, die Wiederöffnung des Ölsektors, die Rechtmäßigkeit der Intervention und der ungelöste Essequibo-Anspruch gegenüber Guyana.',ARRAY['AMERICAS-VENEZUELA','AMERICAS-USA','AMERICAS-ANDEAN','AMERICAS-BRAZIL'],true,NULL,'Venezuela concentrates several distinct disputes in a single country. A US military operation detained the sitting president and a negotiated interim administration took office, leaving open questions of mandate, election timing and the opposition''s role. In parallel, sanctions relief reopened the world''s largest proven crude reserves to international operators, drawing the majors back and lifting exports to multi-year highs. The intervention itself remains legally contested, including over war-powers authority and strikes on vessels at sea. Separately, Venezuela''s long-standing claim to the Essequibo region continues before the International Court of Justice. Coverage divides sharply between Western and Latin American outlets on one side and Russian, Chinese and Iranian state media on the other.','Venezuela bündelt mehrere unterschiedliche Konflikte in einem Land. Eine US-Militäroperation nahm den amtierenden Präsidenten fest, und eine ausgehandelte Übergangsverwaltung trat an -- offen bleiben Fragen des Mandats, des Wahltermins und der Rolle der Opposition. Parallel öffnete die Lockerung der Sanktionen die größten nachgewiesenen Rohölreserven der Welt wieder für internationale Betreiber, die Konzerne kehrten zurück und die Exporte erreichten Mehrjahreshöchststände. Die Intervention selbst bleibt rechtlich umstritten, auch hinsichtlich der Kriegsvollmachten und der Angriffe auf Schiffe. Davon getrennt liegt Venezuelas langjähriger Anspruch auf die Region Essequibo weiterhin beim Internationalen Gerichtshof. Die Berichterstattung teilt sich deutlich zwischen westlichen und lateinamerikanischen Medien einerseits und russischen, chinesischen und iranischen Staatsmedien andererseits.','theater',ARRAY['venezuela_political_transition','us_venezuela_relations','venezuela_sanctions_oil','essequibo_dispute'],ARRAY['orinoco_heavy_oil_belt','paraguana_refining_center','stabroek_block'],'regional','{"type": "Point", "coordinates": [-66.9, 10.5]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('west_bank_settlements','West Bank settlements',NULL,NULL,NULL,ARRAY['MIDEAST-ISRAEL','MIDEAST-PALESTINE'],true,6,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('western_aid_to_ukraine','Western military and economic aid to Ukraine','Westliche Militaer- und Wirtschaftshilfe fuer die Ukraine','The flow of Western military, financial and industrial support that keeps Ukraine in the fight -- weapons packages, air defense, artillery and ammunition, budget financing and the fight over frozen Russian assets. The contested question is not only how much to send but what it buys: a sustainable defense, or an open-ended commitment that deepens the West''s exposure.','Der Strom westlicher militaerischer, finanzieller und industrieller Unterstuetzung, der die Ukraine im Kampf haelt -- Waffenpakete, Luftverteidigung, Artillerie und Munition, Haushaltsfinanzierung und der Streit um eingefrorene russische Vermoegenswerte. Die umstrittene Frage ist nicht nur, wie viel geschickt wird, sondern was es erkauft: eine tragfaehige Verteidigung oder eine unbefristete Verpflichtung, die die Exponierung des Westens vertieft.',ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY'],true,21,'Ukraine cannot fight without external supply, which makes Western aid a front in its own right -- fought in the parliaments and treasuries of Washington, Brussels, Berlin, London and Paris as much as on the battlefield. Supporters frame aid as the cheapest possible investment in European security: sustaining a democracy under attack and degrading a strategic rival without a single NATO soldier. Critics -- from the American right to Global South commentators -- read the same flows as escalation, proxy waste and a subsidy to prolong an unwinnable war. The specifics matter: which systems (air-defense interceptors, long-range strike, F-16s), how they are financed (direct grants, loans, the disputed use of immobilised Russian central-bank assets), and whether European industry can backfill what American politics may withdraw. Aid is where the war''s staying power is ultimately decided -- and where Western unity is most visibly tested.','Die Ukraine kann ohne externen Nachschub nicht kaempfen, was die westliche Hilfe zu einer eigenen Front macht -- ausgetragen in den Parlamenten und Finanzministerien von Washington, Bruessel, Berlin, London und Paris ebenso wie auf dem Schlachtfeld. Befuerworter rahmen Hilfe als die billigstmoegliche Investition in europaeische Sicherheit: eine angegriffene Demokratie stuetzen und einen strategischen Rivalen schwaechen, ohne einen einzigen NATO-Soldaten. Kritiker -- von der amerikanischen Rechten bis zu Kommentatoren des Globalen Suedens -- lesen dieselben Stroeme als Eskalation, Stellvertreter-Verschwendung und Subvention zur Verlaengerung eines nicht zu gewinnenden Krieges. Die Einzelheiten zaehlen: welche Systeme (Abfangraketen der Luftverteidigung, Langstreckenschlag, F-16), wie sie finanziert werden (Direktzuschuesse, Kredite, die umstrittene Nutzung immobilisierter russischer Zentralbankvermoegen) und ob die europaeische Industrie auffuellen kann, was die amerikanische Politik moeglicherweise zurueckzieht. An der Hilfe entscheidet sich letztlich das Durchhaltevermoegen des Krieges -- und hier wird die westliche Einheit am sichtbarsten auf die Probe gestellt.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-UKRAINE')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('yemen_red_sea_theater','Yemen and the Red Sea front',NULL,NULL,NULL,ARRAY['MIDEAST-YEMEN','MIDEAST-SAUDI','MIDEAST-GULF','MIDEAST-EGYPT','MIDEAST-IRAN','MIDEAST-ISRAEL','AMERICAS-USA','EUROPE-UK'],true,5,NULL,NULL,'theater',ARRAY['red_sea_shipping_security','houthi_strikes_on_israel','saudi_houthi_war'],ARRAY['bab_el_mandeb','suez_canal'],'regional','{"type": "Point", "coordinates": [44.2, 15.35]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('zangezur_corridor','Zangezur corridor and regional connectivity','Sangesur-Korridor und regionale Konnektivität','A proposed transit route across Armenia''s Syunik province connecting the main territory of Azerbaijan with its Nakhchivan exclave, and potentially onward to Turkey, the Caspian and Central Asia; also referred to as the "Trump Route" or TRIPP. Contested issues include sovereignty and control over the section crossing Armenian territory, questions of extraterritoriality, the effect on Iran''s land border with Armenia, Russia''s role, and the balance between trade connectivity and security concerns.','Eine geplante Transitroute durch Armeniens Provinz Sjunik, die das Kernland Aserbaidschans mit seiner Exklave Nachitschewan und möglicherweise weiter mit der Türkei, dem Kaspischen Meer und Zentralasien verbindet; auch als "Trump-Route" oder TRIPP bezeichnet. Umstritten sind Souveränität und Kontrolle über den durch armenisches Gebiet führenden Abschnitt, Fragen der Extraterritorialität, die Auswirkung auf Irans Landgrenze zu Armenien, Russlands Rolle sowie das Gleichgewicht zwischen Handelskonnektivität und Sicherheitsbedenken.',ARRAY['ASIA-CAUCASUS','MIDEAST-TURKEY','MIDEAST-IRAN','EUROPE-RUSSIA','AMERICAS-USA'],true,44,'The Zangezur corridor is a proposed transport link that would cross Armenia''s southern Syunik province to connect the main territory of Azerbaijan with its Nakhchivan exclave, and, if extended, link Turkey with the Caspian and Central Asia. Proposals have included an arrangement referred to as the "Trump Route" or TRIPP, involving a United States operating role. The route is contested on several grounds: whether and how Armenia retains sovereignty and control over the section on its territory; Iran''s opposition to an arrangement that would cut its land border with Armenia; Russia''s role in monitoring or guaranteeing transit; and the trade-off between the economic benefits of connectivity and the security concerns of the states affected. As a physical link between the peace process and regional trade, the corridor draws together the interests of Armenia, Azerbaijan, Turkey, Iran, Russia and the United States in a single route.','Der Sangesur-Korridor ist eine geplante Verkehrsverbindung, die durch Armeniens südliche Provinz Sjunik verlaufen würde, um das Kernland Aserbaidschans mit seiner Exklave Nachitschewan zu verbinden und, sofern verlängert, die Türkei mit dem Kaspischen Meer und Zentralasien. Vorschläge umfassten eine als "Trump-Route" oder TRIPP bezeichnete Regelung mit einer US-amerikanischen Betreiberrolle. Die Route ist aus mehreren Gründen umstritten: ob und wie Armenien Souveränität und Kontrolle über den Abschnitt auf seinem Gebiet behält; Irans Ablehnung einer Regelung, die seine Landgrenze zu Armenien durchtrennen würde; Russlands Rolle bei der Überwachung oder Absicherung des Transits; und der Abwägung zwischen dem wirtschaftlichen Nutzen der Konnektivität und den Sicherheitsbedenken der betroffenen Staaten. Als physische Verbindung zwischen dem Friedensprozess und dem regionalen Handel bündelt der Korridor die Interessen Armeniens, Aserbaidschans, der Türkei, des Irans, Russlands und der Vereinigten Staaten in einer einzigen Route.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();

