-- 4. narratives_v2: 418 rows.
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('afd_democratic_defense','The AfD is a threat to the democratic order that must be contained','Die AfD ist eine Gefahr für die demokratische Ordnung, die eingedämmt werden muss','Democratic-defense framing (German and Western mainstream) treats the AfD as a radical or extremist force whose classification by the domestic-intelligence service, the "Brandmauer" against cooperation, scrutiny of its access to office and state secrets and a possible ban are legitimate defences of the constitutional order. Vocabulary: rechtsextrem, extremist, threat to democracy, firewall, Verfassungsschutz, ban.','Die Demokratie-Verteidigungs-Rahmung (deutscher und westlicher Mainstream) sieht die AfD als radikale oder extremistische Kraft, deren Einstufung durch den Verfassungsschutz, die „Brandmauer" gegen Zusammenarbeit, die Prüfung ihres Zugangs zu Ämtern und Staatsgeheimnissen und ein mögliches Verbot legitime Verteidigungen der verfassungsmäßigen Ordnung seien.',ARRAY['EUROPE-GERMANY'],ARRAY['rechtsextrem','far-right','extremist','extremism','threat to democracy','Bedrohung','Demokratie','firewall','Brandmauer','Verfassungsschutz','ban','Verbot','verfassungsfeindlich','wehrhafte Demokratie','hate','Hetze','isolate','ausgrenzen'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'afd_and_german_polarisation',1,'Defence of the democratic order','Verteidigung der demokratischen Ordnung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('afd_exclusion_undemocratic','Excluding a party millions vote for is itself undemocratic','Eine Partei auszuschließen, die Millionen wählen, ist selbst undemokratisch','Exclusion-critique framing (voiced by the party and by sympathetic commentary) holds that the firewall, the intelligence classification and moves toward a ban disenfranchise millions of voters, amount to establishment overreach and threaten free speech, and that the party should be treated as a normal democratic actor. Vocabulary: millions of voters, undemocratic, establishment, free speech, exclusion, censorship.','Die Ausschluss-Kritik-Rahmung (von der Partei und von wohlwollenden Kommentaren vertreten) sieht in Brandmauer, Geheimdiensteinstufung und Verbotsüberlegungen eine Entrechtung von Millionen Wählern, einen Übergriff des Establishments und eine Gefahr für die Meinungsfreiheit und fordert, die Partei als normalen demokratischen Akteur zu behandeln.',ARRAY['EUROPE-GERMANY'],ARRAY['millions of voters','Millionen Wähler','undemocratic','undemokratisch','free speech','Meinungsfreiheit','censorship','Zensur','witch hunt','stigmatis','disenfranchise','second-class','double standard','normal party'],true,ARRAY['Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal'],'afd_and_german_polarisation',2,'Exclusion as anti-democratic','Ausgrenzung als undemokratisch', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('afd_persecution_kremlin','Germany persecutes its opposition and silences dissent','Deutschland verfolgt seine Opposition und unterdrückt abweichende Meinungen','Counter-framing (Russian state press) presents German measures against the AfD as political persecution and censorship by a state that lectures others on democracy. Moscow favours direct dealing with national forces over Brussels-aligned establishments, so it amplifies the polarisation and the anti-establishment case — adversarial to the German mainstream rather than an endorsement of the party''s programme. Vocabulary: persecution, censorship, crackdown, hypocrisy.','Die Gegen-Rahmung (russische Staatspresse) stellt die deutschen Maßnahmen gegen die AfD als politische Verfolgung und Zensur eines Staates dar, der andere über Demokratie belehrt. Moskau bevorzugt den direkten Umgang mit nationalen Kräften gegenüber Brüssel-nahen Establishments und verstärkt daher die Polarisierung und die anti-etablierte Sichtweise — gegnerisch zum deutschen Mainstream, keine Zustimmung zum Programm der Partei.',ARRAY['EUROPE-RUSSIA'],ARRAY['persecution','censorship','crackdown','opposition','hypocrisy','dictatorship','silence','ban','repression'],true,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian'],'afd_and_german_polarisation',3,'Russian counter-framing','Russische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alberta_legitimate_grievance','A grievance the federation has not answered','Ein Anliegen, auf das der Bund keine Antwort hat','The separatist push reflects durable material grievances in a landlocked resource province: transfer payments that flow outward, federal environmental and pipeline decisions made without provincial consent, and a sense that the province''s economic weight buys it no say in Ottawa.','Der separatistische Vorstoß spiegelt dauerhafte materielle Beschwerden einer rohstoffreichen Binnenprovinz: Transferzahlungen, die abfließen, föderale Umwelt- und Pipelineentscheidungen ohne Zustimmung der Provinz und das Gefühl, dass das wirtschaftliche Gewicht der Provinz ihr in Ottawa kein Mitspracherecht verschafft.',ARRAY['AMERICAS-CANADA'],ARRAY['Western alienation','equalization','equalisation','resource revenue','landlocked','grievance','frustration','neglect','ignored','left behind','oil-rich','argues','defends','treaty rights','Benachteiligung','Ausgleichszahlung','vernachlässigt','colony','independence advocate','Ottawa''s','federal overreach'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','El País','France 24 (EN)','NDTV','Anadolu Agency','OilPrice','Mining.com','Western Standard'],'alberta_separatism_us_ties',1,'The grievance is real','Das Anliegen ist real',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alberta_unity_defence','A dangerous bluff, and an opening for outside pressure','Ein gefährliches Bluffspiel und ein Einfallstor für Druck von außen','The referendum push is treated as constitutionally doubtful and economically self-defeating, with courts, First Nations treaty holders and former prime ministers ranged against it. Contacts between separatist organisers and American officials raise a further objection: that a domestic constitutional question is being opened to an outside government with an interest in the outcome.','Der Referendumsvorstoß gilt als verfassungsrechtlich zweifelhaft und wirtschaftlich selbstschädigend — Gerichte, Vertragspartner der First Nations und frühere Premierminister stellen sich dagegen. Kontakte zwischen separatistischen Organisatoren und amerikanischen Amtsträgern werfen einen weiteren Einwand auf: dass eine innerstaatliche Verfassungsfrage einer auswärtigen Regierung geöffnet wird, die ein Interesse am Ausgang hat.',ARRAY['AMERICAS-CANADA'],ARRAY['treason','dangerous','bluff','Brexit','quash','injunction','unconstitutional','illegal','warns','unity','essential','best place','united Canada','deals blow','concern','probing','electors list','voter data','respect Canadian sovereignty','interference','opposition','defend Canadian','Landesverrat','Einheit','verfassungswidrig','Einmischung'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','El País','France 24 (EN)','NDTV','Anadolu Agency','OilPrice','Mining.com','Straits Times','La Nación','Clarín','Japan Times'],'alberta_separatism_us_ties',2,'A threat to the federation','Eine Gefahr für den Bund', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alberta_external_amplification','A fraying federation, watched from outside','Ein brüchiger Bundesstaat, von außen beobachtet','The secession debate is covered as a symptom of Western political decay, with the emphasis placed on the fracture itself and on the contrast between Canadian objections to outside interference and Canadian conduct elsewhere.','Die Sezessionsdebatte wird als Symptom westlichen politischen Verfalls dargestellt, mit Betonung auf dem Bruch selbst und auf dem Kontrast zwischen kanadischen Einwänden gegen Einmischung von außen und kanadischem Verhalten andernorts.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['decay','decline','crisis','hypocris','double standard','so-called','fracture','disintegrat','Verfall','Doppelmoral','Zerfall'],true,ARRAY['RT','TASS (EN)','Global Times','CGTN','People''s Daily','China Daily','Xinhua','Sputnik','Press TV'],'alberta_separatism_us_ties',3,'Symptom of Western decay','Symptom westlichen Verfalls', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_nato_deterrence','NATO must reinforce the Arctic to deter a growing Russian (and Chinese) threat','Die NATO muss die Arktis verstärken, um eine wachsende russische (und chinesische) Bedrohung abzuschrecken','Deterrence framing (Western/NATO/Nordic mainstream) holds that Russian rearmament in the High North and growing Sino-Russian Arctic cooperation require NATO reinforcement -- exercises, bases, icebreakers and readiness -- to defend allied territory and close a capability gap. Vocabulary: deter, defend the north, Russian threat, build-up, readiness, Arctic Sentry, Cold Response.','Die Abschreckungs-Rahmung (westlicher/NATO/nordischer Mainstream) sieht die russische Aufrüstung im hohen Norden und die wachsende russisch-chinesische Arktis-Kooperation als Grund für eine NATO-Verstärkung -- Übungen, Stützpunkte, Eisbrecher und Einsatzbereitschaft.',ARRAY['NON-STATE-NATO','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU'],ARRAY['deter','deterrence','defend the north','Russian threat','build-up','readiness','reinforce','vulnerability','capability gap','exercise','Arctic Sentry','Cold Response','high north','protect','Abschreckung','russische Bedrohung'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','Military Times','Defense News','ERR News','LRT English','Atlantic Council','Politico','Kyiv Post'],'arctic_military_presence',1,'NATO Arctic deterrence necessary','NATO-Abschreckung in der Arktis notwendig',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_nato_militarization','NATO is militarising the Arctic and provoking a dangerous new confrontation','Die NATO militarisiert die Arktis und provoziert eine gefährliche neue Konfrontation','Militarisation framing (Russian + Chinese state press) reverses the causality: NATO expansion, exercises and basing are the destabilising provocation that turns a zone of low tension into an arena of bloc confrontation and an arms race, encircling Russia. Vocabulary: militarisation, provocation, encirclement, destabilise, arms race, bloc confrontation.','Die Militarisierungs-Rahmung (russische und chinesische Staatspresse) kehrt die Kausalität um: NATO-Erweiterung, Übungen und Stützpunkte seien die destabilisierende Provokation, die eine Zone geringer Spannung in eine Arena der Blockkonfrontation und ein Wettrüsten verwandelt.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['militariz','militarisation','provocation','encirclement','encircl','destabiliz','arms race','bloc confrontation','aggressive','escalat','Cold War','buildup','Militarisierung','Provokation','Einkreisung','Wettrüsten'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Global Times','CGTN','China Daily','Xinhua','Press TV'],'arctic_military_presence',2,'NATO militarising the Arctic','NATO militarisiert die Arktis', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_resource_development','Arctic energy and minerals are a legitimate sovereign development opportunity','Arktische Energie und Rohstoffe sind eine legitime souveräne Entwicklungschance','Development framing (Russian state + Western energy/business press) treats Arctic hydrocarbons and critical minerals as a legitimate, economically vital resource to be developed -- new discoveries, investment, production and jobs -- as retreating ice opens access. Vocabulary: discovery, reserves, investment, production, energy security, billion barrels.','Die Entwicklungs-Rahmung (russische Staats- und westliche Wirtschaftspresse) sieht arktische Kohlenwasserstoffe und kritische Rohstoffe als legitime, wirtschaftlich wichtige Ressource -- neue Funde, Investitionen, Förderung und Arbeitsplätze -- während das zurückweichende Eis den Zugang öffnet.',ARRAY['EUROPE-RUSSIA','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','ASIA-CHINA'],ARRAY['discovery','reserves','investment','production','energy security','billion barrels','boom','extract','output','field','jobs','develop'],true,ARRAY['Bloomberg','OilPrice','Wall Street Journal','Financial Times','TASS (EN)','RT','RIA Novosti','Globe and Mail','CNBC'],'arctic_resources_competition',1,'Sovereign resource development','Souveräne Rohstoffentwicklung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_drilling_environmental_alarm','Arctic warming and resource extraction are an environmental and climate emergency','Arktische Erwärmung und Rohstoffförderung sind ein Umwelt- und Klimanotstand','Environmental-and-climate framing (Western/green press plus climate-science reporting) treats the Arctic as a warning system and a victim: record-low sea ice, accelerating melt and thawing permafrost are a planetary climate signal, while opening the ice to drilling, mining and shipping compounds the damage through oil-spill risk, black carbon and biodiversity loss. It is the pro-development camp''s own critics -- the same outlets that report the resource boom also sound the alarm -- so publisher alone cannot separate the stances; framing keywords do. Vocabulary: record low, warming, melting, thawing permafrost, fragile ecosystem, black carbon, pristine, ban drilling, reckless, climate.','Die Umwelt- und Klima-Rahmung (westliche/grüne Presse und Klimawissenschafts-Berichterstattung) sieht die Arktis als Warnsystem und Opfer: Rekordtief beim Meereis, beschleunigte Schmelze und tauender Permafrost sind ein planetares Klimasignal, während das Öffnen des Eises für Bohrungen, Bergbau und Schifffahrt den Schaden durch Ölpest-Risiko, Ruß und Biodiversitätsverlust vergrößert.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','AMERICAS-USA'],ARRAY['fragile','ecosystem','climate','environmental','pollution','black carbon','warming','melting','melt','thaw','permafrost','record low','sea ice','ice loss','pristine','biodiversity','ban drilling','reckless','oil spill','protect the Arctic','emissions','carbon','fragiles Ökosystem','Umwelt','Klimaschutz','Klima','Erwärmung','Ölpest','Meereis','Rekordtief','Permafrost'],true,ARRAY['The Guardian','BBC World','Deutsche Welle','Euronews','France 24 (EN)','New York Times','El País','Le Monde','The Independent','Reuters','Channel NewsAsia','Associated Press','NPR','Al Jazeera'],'arctic_resources_competition',2,'Warming & environmental emergency','Erwärmung & Umweltnotstand', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_route_opportunity','Melting ice opens Arctic sea routes as a shared economic opportunity','Das schmelzende Eis öffnet arktische Seewege als gemeinsame wirtschaftliche Chance','Opportunity framing (Russian + Chinese + commercial press) presents the Northern Sea Route, Northwest Passage and Polar Silk Road as shorter, developable trade corridors and a legitimate economic prospect, with icebreaker fleets and Arctic ports as investment. Vocabulary: shorter route, trade route, transit, Northern Sea Route, Polar Silk Road, cargo, icebreaker fleet.','Die Chancen-Rahmung (russische, chinesische und kommerzielle Presse) präsentiert die Nordostpassage, die Nordwestpassage und die polare Seidenstraße als kürzere, entwickelbare Handelskorridore und legitime Wirtschaftsperspektive -- mit Eisbrecherflotten und arktischen Häfen als Investition.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','EUROPE-NORDIC'],ARRAY['shorter route','trade route','transit','opportunity','cargo','shipping boom','Polar Silk Road','develop','commercial','icebreaker fleet','Seidenstraße','Handelsroute'],true,ARRAY['TASS (EN)','RT','RIA Novosti','CGTN','Global Times','China Daily','Xinhua','Bloomberg','OilPrice'],'arctic_shipping_routes',1,'Arctic routes as economic opportunity','Arktische Routen als wirtschaftliche Chance',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_route_strategic_threat','Russian and Chinese control of Arctic routes is a strategic threat','Die russische und chinesische Kontrolle arktischer Routen ist eine strategische Bedrohung','Strategic-threat framing (Western security press) treats Russian dominance of the Northern Sea Route and China''s Polar Silk Road ambitions as a chokepoint risk requiring monitoring, freedom-of-navigation assertion and sanctions -- including the "shadow fleet" and dual-use shipping. Vocabulary: control, chokepoint, dominance, Chinese encroachment, dual-use, shadow fleet, freedom of navigation.','Die Bedrohungs-Rahmung (westliche Sicherheitspresse) sieht die russische Dominanz über die Nordostpassage und Chinas Ambitionen der polaren Seidenstraße als Nadelöhr-Risiko, das Überwachung, die Durchsetzung der Navigationsfreiheit und Sanktionen erfordert -- einschließlich der "Schattenflotte".',ARRAY['NON-STATE-NATO','AMERICAS-USA','EUROPE-NORDIC','NON-STATE-EU'],ARRAY['control','chokepoint','dominance','Russian control','Chinese encroachment','dual-use','shadow fleet','monitor','contest','freedom of navigation','strategic threat','militariz','sanctions','Bedrohung','Schattenflotte'],true,ARRAY['Reuters','BBC World','Financial Times','Wall Street Journal','New York Times','Military Times','Defense News','France 24 (EN)','Deutsche Welle','Euronews','Atlantic Council'],'arctic_shipping_routes',2,'Russian/Chinese route control as threat','Russische/chinesische Routenkontrolle als Bedrohung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_western_security_consensus','The Arctic must be secured against Russian militarization and Sino-Russian encroachment','Die Arktis muss gegen russische Militarisierung und russisch-chinesisches Vordringen gesichert werden','Western security-consensus framing (NATO, Nordic and US mainstream plus Western business press) holds that the Arctic is becoming a zone of strategic vulnerability that must be secured: Russian rearmament in the High North and deepening Sino-Russian cooperation require NATO deterrence, resource and shipping-route access must be protected, and allied sovereignty defended. Vocabulary: deter, Russian threat, encroachment, defend the north, freedom of navigation, security.','Die westliche Sicherheitskonsens-Rahmung (NATO, nordischer und US-Mainstream sowie westliche Wirtschaftspresse) sieht die Arktis als eine Zone strategischer Verwundbarkeit, die gesichert werden muss: russische Aufrüstung im hohen Norden und vertiefte russisch-chinesische Kooperation erfordern NATO-Abschreckung, der Zugang zu Rohstoffen und Schifffahrtsrouten muss geschützt und die Souveränität der Verbündeten verteidigt werden.',ARRAY['NON-STATE-NATO','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU'],ARRAY['deter','deterrence','Russian threat','encroachment','defend','defend the north','security','build-up','freedom of navigation','reinforce','high north'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','Atlantic Council','Politico','Bloomberg','OilPrice','Globe and Mail','CNBC','Fox News'],'arctic_theater',1,'Western Arctic security consensus','Westlicher Sicherheitskonsens in der Arktis',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_russia_china_counter','NATO expansion and the US Greenland grab are the real provocation and Western hypocrisy','NATO-Erweiterung und der US-Griff nach Grönland sind die eigentliche Provokation und westliche Heuchelei','Russian and Chinese counter-framing (Russian state press and Chinese state media) reverses the Western account: NATO''s northern expansion is the destabilizing militarization of a once-low-tension zone and an encirclement of Russia, and the US push on Greenland is imperialist overreach that exposes Western hypocrisy -- not a threat Moscow or Beijing pose but a pretext. It is adversarial to the Western Arctic posture as a whole. Vocabulary: militarization, provocation, encirclement, imperialism, hypocrisy, pretext.','Die russische und chinesische Gegen-Rahmung (russische Staatspresse und chinesische Staatsmedien) kehrt die westliche Darstellung um: Die Nordausdehnung der NATO sei die destabilisierende Militarisierung einer einst spannungsarmen Zone und eine Einkreisung Russlands, und der US-Vorstoß in Grönland sei imperialistische Überheblichkeit, die westliche Heuchelei entlarvt -- keine Bedrohung durch Moskau oder Peking, sondern ein Vorwand.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['militariz','provocation','encirclement','imperialism','imperialist','hypocrisy','pretext','land grab','destabiliz','bloc confrontation','double standard'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'arctic_theater',2,'Russian & Chinese counter-framing','Russische & chinesische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_western_sovereignty_stewardship','Coercion and reckless exploitation of the Arctic must be resisted — for allied sovereignty and the climate','Zwang und rücksichtslose Ausbeutung der Arktis müssen abgewehrt werden — für die Souveränität der Verbündeten und das Klima','Western sovereignty-and-stewardship framing (European and Western mainstream plus green press) resists the Arctic being carved up by coercion or reckless exploitation: it defends Danish and allied sovereignty and international law against the US Greenland push, is wary of Russian control of the sea routes, and treats the warming Arctic as a fragile climate system that drilling, mining and militarization endanger. Distinct from the security-consensus card, it is critical rather than martial. Vocabulary: sovereignty, coercion, international law, not for sale, warming, black carbon, fragile, climate.','Die westliche Souveränitäts- und Stewardship-Rahmung (europäischer und westlicher Mainstream sowie grüne Presse) wehrt sich gegen eine Aufteilung der Arktis durch Zwang oder rücksichtslose Ausbeutung: sie verteidigt die dänische und verbündete Souveränität und das Völkerrecht gegen den US-Vorstoß in Grönland, ist misstrauisch gegenüber russischer Kontrolle der Seewege und betrachtet die sich erwärmende Arktis als fragiles Klimasystem, das Bohrungen, Bergbau und Militarisierung gefährden.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','EUROPE-GERMANY','EUROPE-FRANCE','AMERICAS-USA','AMERICAS-CANADA'],ARRAY['sovereignty','coercion','not for sale','international law','hands off','fragile','warming','black carbon','climate','environmental','self-determination','melting'],true,ARRAY['El País','Le Monde','The Independent','Channel NewsAsia','ANSA','EurActiv','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Al Jazeera','Anadolu Agency','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','BBC World','New York Times','Reuters','Associated Press'],'arctic_theater',3,'European sovereignty & environmental stewardship','Europäische Souveränität & Umweltverantwortung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aas_durable_peace','A historic peace is ending a 30-year conflict and normalizing the region','Ein historischer Frieden beendet einen 30-jährigen Konflikt und normalisiert die Region','Western and Turkish framing celebrates the Armenia-Azerbaijan settlement -- and the parallel Armenia-Turkey opening -- as a historic, US-brokered peace that ends decades of war, delimits the border, reopens trade and railways, and integrates the South Caucasus.','Die westliche und türkische Deutung feiert die Regelung zwischen Armenien und Aserbaidschan -- samt der parallelen Öffnung zwischen Armenien und der Türkei -- als historischen, von den USA vermittelten Frieden, der jahrzehntelangen Krieg beendet, die Grenze zieht, Handel und Bahnverbindungen öffnet und den Südkaukasus integriert.',ARRAY['ASIA-CAUCASUS'],ARRAY['peace deal','peace treaty','historic','normalization','normalisation','breakthrough','ends conflict','reconciliation','regional integration','signed','direct trade','reopen','Friedensabkommen','historisch','Normalisierung','Aussöhnung','мирный договор','историческое','нормализация','примирение'],true,ARRAY['Reuters','Euronews','Euronews.com','Associated Press','BBC World','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','ANSA','La Repubblica','El País','Novinite','The National','Daily Sabah','Anadolu Agency','TRT World','Express Tribune','Dawn'],'armenia_azerbaijan_settlement',1,'Historic peace and normalization','Historischer Frieden und Normalisierung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aas_contested_settlement','The settlement is a contested, externally shaped arrangement rather than a genuine peace','Die Regelung ist ein umstrittenes, von außen geformtes Arrangement statt eines echten Friedens','Critics reject the triumphant peace account from two directions: a pro-Armenian and human-rights framing sees a capitulation imposed on a defeated Armenia that leaves the 2023 exodus, prisoners of war and war-crimes accountability unaddressed; a Russian framing sees a Western- and Turkish-brokered arrangement that sidelines Moscow and its peacekeepers.','Kritiker weisen die triumphale Friedenserzählung aus zwei Richtungen zurück: eine proarmenische und menschenrechtliche Deutung sieht eine einem besiegten Armenien aufgezwungene Kapitulation, die den Exodus von 2023, Kriegsgefangene und die Ahndung von Kriegsverbrechen ungeklärt lässt; eine russische Deutung sieht ein westlich-türkisch vermitteltes Arrangement, das Moskau und seine Friedenstruppen an den Rand drängt.',ARRAY['ASIA-CAUCASUS'],ARRAY['ethnic cleansing','forced displacement','exodus','capitulation','dictated','imposed','prisoners of war','prisoner','war crimes','torture','Folter','unpunished','betrayed','betrayal','betray','trial','convicted','verurteilt','sidelined','hijack','peacekeepers','excludes Russia','ethnische Säuberung','Vertreibung','Kriegsverbrechen','Kriegsgefangene','Kapitulation','aufgezwungen','an den Rand','этническая чистка','военнопленные','капитуляция','навязанный','в обход России'],true,ARRAY['France 24 (EN)','France 24','Le Figaro','Le Monde','The Guardian','Deutsche Welle','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Haaretz','Carnegie Endowment','TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'armenia_azerbaijan_settlement',2,'Contested / imposed settlement','Umstrittene / aufgezwungene Regelung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('awp_european_choice','Armenia''s turn to Europe is a sovereign, democratic escape from Russian domination','Armeniens Hinwendung zu Europa ist ein souveräner, demokratischer Ausbruch aus russischer Vorherrschaft','Western/pro-European framing celebrates Armenia''s pivot as a hard-won, democratic choice: a sovereign state escaping a failed Russian security guarantee, winning elections against Moscow''s pressure, and charting a European future through EU trade, accession talks and the EPC summit.','Die westlich/proeuropäische Deutung feiert Armeniens Schwenk als hart erkämpfte demokratische Entscheidung: ein souveräner Staat, der einer gescheiterten russischen Sicherheitsgarantie entkommt, gegen Moskaus Druck Wahlen gewinnt und über EU-Handel, Beitrittsgespräche und den EPG-Gipfel eine europäische Zukunft ansteuert.',ARRAY['ASIA-CAUCASUS'],ARRAY['pivot to Europe','turn to Europe','away from Russia','break with Russia','sovereign choice','pro-Western','historic shift','escape Moscow','European future','defies Russia','Hinwendung nach Europa','Abkehr von Russland','souveräne Entscheidung','historischer Wandel','разворот на Запад','суверенный выбор','европейский выбор'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','Washington Post','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Tagesschau','ANSA','La Repubblica','El País','Le Figaro','Carnegie Endowment','Novinite','Kyiv Post','LRT English','The Economist','Sky News','ABC News','The Australian','The National'],'armenia_western_pivot',1,'Sovereign European choice','Souveräne europäische Entscheidung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('awp_russian_capture','Armenia is being dragged into an anti-Russian orbit by a Western-engineered capture','Armenien wird durch eine vom Westen inszenierte Vereinnahmung in eine antirussische Umlaufbahn gezogen','Russian state framing treats the pivot as a hostile Western operation: elections tainted by "collective West" interference, Pashinyan a Western puppet betraying an ally, Armenia headed for a "Ukraine scenario" and economic ruin once it forfeits EAEU and CSTO benefits.','Die russische Staatsdeutung sieht den Schwenk als feindliche Westoperation: durch Einmischung des "kollektiven Westens" verfälschte Wahlen, Paschinjan als westliche Marionette und Bündnisverräter, Armenien auf dem Weg in ein "Ukraine-Szenario" und den wirtschaftlichen Ruin, sobald es die Vorteile von EAWU und OVKS verspielt.',ARRAY['ASIA-CAUCASUS'],ARRAY['collective West','interference','foreign interference','rigged','irregularities','puppet','Ukraine scenario','economic ruin','freeloading','betrayal','pressure on opposition','Einmischung','Marionette','manipuliert','вмешательство','коллективный Запад','майдан','русофоб'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'armenia_western_pivot',3,'Western capture / betrayal of alliance','Westliche Vereinnahmung / Bündnisverrat', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aukus_strategic_necessity','AUKUS is essential to Australian deterrence and is progressing','AUKUS ist für die australische Abschreckung unerlässlich und kommt voran','The supportive Australian framing holds that the submarine pact remains the cornerstone of Australian deterrence and is delivering: a $2.7bn pledge to accelerate the shipyard, the US Navy standing up Naval Support Activity Stirling in Western Australia, AUKUS partners advancing SSN and underwater-drone programmes, savings identified in the revised arrangement, and senior figures publicly backing the plan. Vocabulary: backs, advance, milestone, pledge, accelerate, savings, deterrence, cornerstone, sovereign capability.','Die unterstützende australische Rahmung sieht den U-Boot-Pakt weiterhin als Eckpfeiler der australischen Abschreckung, der Ergebnisse liefert: eine Zusage von 2,7 Milliarden zur Beschleunigung der Werft, die Einrichtung der Naval Support Activity Stirling durch die US-Marine in Westaustralien, Fortschritte der AUKUS-Partner bei SSN- und Unterwasserdrohnen-Programmen, Einsparungen in der überarbeiteten Vereinbarung sowie führende Politiker, die sich öffentlich hinter den Plan stellen.',ARRAY['OCEANIA-AUSTRALIA','AMERICAS-USA','EUROPE-UK'],ARRAY['backs','back the','advance','advancing','milestone','pledge','pledges','accelerate','speed up','savings','deterrence','cornerstone','sovereign capability','strengthens','delivers','on track','progress','won''t sink','hits out at'],true,ARRAY['ABC News','Australian Broadcasting Corporation','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','France 24','France 24 (EN)','Wall Street Journal','New York Times','Janes','Defense News','War on the Rocks','Chatham House','Anadolu Agency','Times of India','Express Tribune','Bangkok Post','The Star','CSIS','Lowy Institute'],'aukus_alliance_reliability',1,'Australian supportive framing','Australische unterstützende Rahmung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aukus_capability_doubt','AUKUS is delivering less than promised and binds Australia to an unreliable partner','AUKUS liefert weniger als versprochen und bindet Australien an einen unzuverlässigen Partner','The critical Australian framing — carried by the same mainstream outlets — holds that the pact has been downgraded and politically strained: Australia will receive three second-hand submarines instead of new Virginia-class boats, a capability gap opens as the Collins-class fleet is downsized and enters a "high-risk" life extension, an inquiry has been warned of nuclear-disaster risk, an ex-minister crowd-funded his own inquiry, a former foreign minister called it among Australia''s worst foreign-policy decisions, and Labor is publicly split. Vocabulary: second-hand, used, downgrade, scrap, shake-up, mess, division, inquiry, risk, gap, delay, chaos, worst.','Die kritische australische Rahmung — getragen von denselben Leitmedien — sieht den Pakt als herabgestuft und politisch belastet: Australien erhält drei gebrauchte U-Boote statt neuer Virginia-Klasse-Boote, eine Fähigkeitslücke entsteht, während die Collins-Klasse verkleinert wird und in eine "hochriskante" Laufzeitverlängerung geht, eine Untersuchung wurde vor nuklearem Katastrophenrisiko gewarnt, ein Ex-Minister finanzierte seine eigene Untersuchung per Crowdfunding, ein früherer Außenminister nannte ihn eine der schlechtesten außenpolitischen Entscheidungen Australiens, und Labor ist offen gespalten.',ARRAY['OCEANIA-AUSTRALIA','AMERICAS-USA','EUROPE-UK'],ARRAY['second-hand','secondhand','used nuclear','only three','downgrade','downgrades','scraps','shake-up','mess','division','divided','want out','inquiry','risk','high-risk','gap','delay','blowout','chaos','worst','spats','explaining','stood up','quit','fears','frog in a sock','sinking feeling','heroic','crowd-funded'],true,ARRAY['ABC News','Australian Broadcasting Corporation','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','France 24','France 24 (EN)','Wall Street Journal','New York Times','Janes','Defense News','War on the Rocks','Chatham House','Anadolu Agency','Times of India','Express Tribune','Bangkok Post','The Star','CSIS','Lowy Institute'],'aukus_alliance_reliability',2,'Australian critical framing','Australische kritische Rahmung', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aukus_bloc_confrontation','AUKUS is bloc confrontation that spreads nuclear submarine technology and fuels an arms race','AUKUS ist Blockkonfrontation, die Nuklear-U-Boot-Technologie verbreitet und ein Wettrüsten anheizt','Chinese and Russian state framing treats the pact as a Cold War bloc project: an Anglosphere grouping that transfers naval nuclear propulsion to a non-nuclear-weapon state, strains the non-proliferation regime, and drives regional militarisation under the banner of deterrence. US basing steps in Western Australia are reported as evidence of the build-up rather than as reassurance. Vocabulary: bloc confrontation, Cold War mentality, arms race, proliferation, militarisation, Anglo-Saxon.','Die chinesische und russische staatliche Rahmung behandelt den Pakt als Blockprojekt des Kalten Krieges: eine angelsächsische Gruppierung, die nukleare Marineantriebstechnik an einen Nichtkernwaffenstaat weitergibt, das Nichtverbreitungsregime belastet und die Militarisierung der Region unter dem Vorwand der Abschreckung vorantreibt. US-Stützpunktschritte in Westaustralien werden als Beleg für den Aufbau dargestellt, nicht als Rückversicherung.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA','OCEANIA-AUSTRALIA'],ARRAY['bloc confrontation','Cold War','mentality','arms race','proliferation','militarisation','militarization','Anglo-Saxon','hegemony','provocation'],true,ARRAY['Global Times','CGTN','news.cgtn.com','China Daily','People''s Daily','Xinhua','TASS','TASS (EN)','tass.com','RT'],'aukus_alliance_reliability',3,'Chinese and Russian state framing','Chinesische und russische staatliche Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_derisking_necessity','Concentrated dependence on the Chinese market is a strategic vulnerability Australia must reduce','Die konzentrierte Abhängigkeit vom chinesischen Markt ist eine strategische Verwundbarkeit, die Australien verringern muss','Australian and Western business coverage reads Beijing''s commercial levers as strategic risk: the 55% tariff triggering at the beef quota threshold, the state buyer restricting Fortescue and BHP iron ore cargoes during price talks, and Chinese stakes in rare-earth projects forced into divestment. The conclusion drawn is that market concentration must be reduced through diversification, investment screening and alternative supply chains. Vocabulary: quota, tariff, restrictions, state buyer, divest, screening, diversify, supply chain, vulnerability.','Die australische und westliche Wirtschaftsberichterstattung deutet Pekings kommerzielle Hebel als strategisches Risiko: der 55-Prozent-Zoll bei Erreichen der Rindfleischquote, der staatliche Käufer, der während der Preisverhandlungen Eisenerzladungen von Fortescue und BHP beschränkt, sowie chinesische Anteile an Seltene-Erden-Projekten, die zum Verkauf gezwungen werden. Daraus wird gefolgert, dass die Marktkonzentration durch Diversifizierung, Investitionsprüfung und alternative Lieferketten verringert werden muss.',ARRAY['OCEANIA-AUSTRALIA','ASIA-CHINA'],ARRAY['quota','tariff','restriction','state buyer','divest','screening','diversify','supply chain','vulnerability','dependence','leverage','pricing dispute','forced sale','rare earth','critical mineral'],true,ARRAY['ABC News','Australian Broadcasting Corporation','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','Wall Street Journal','New York Times','Mining.com','S&P Global','OilPrice','CNBC','Channel NewsAsia'],'australia_china_trade_leverage',1,'Australian and Western de-risking framing','Australische und westliche Risikominderungs-Rahmung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_mutual_benefit','Australia-China trade is complementary and growing, and quota mechanics are routine rather than coercive','Der Handel zwischen Australien und China ist komplementär und wächst; Quotenmechanismen sind Routine, nicht Zwang','Chinese state framing presents the commercial relationship as large, complementary and expanding — record Chinese vehicle sales in Australia, solar and energy-transition cooperation, growing beef and agricultural exports, rising Australian public opinion of China. Tariff steps are presented as the routine operation of agreed quota thresholds administered by MOFCOM rather than pressure, with strategic-rivalry politics cast as the thing putting the relationship at risk. Vocabulary: mutual benefit, complementary, growing market, quota threshold, cooperation, win-win.','Die chinesische staatliche Rahmung stellt die Handelsbeziehung als groß, komplementär und wachsend dar — Rekordabsatz chinesischer Fahrzeuge in Australien, Zusammenarbeit bei Solar- und Energiewende, steigende Rindfleisch- und Agrarexporte, verbesserte australische Meinung über China. Zollschritte werden als routinemäßige Anwendung vereinbarter Quotenschwellen durch das Handelsministerium dargestellt, nicht als Druck; die Politik der strategischen Rivalität gilt als das eigentliche Risiko für die Beziehung.',ARRAY['ASIA-CHINA','OCEANIA-AUSTRALIA'],ARRAY['mutual benefit','complementary','growing market','quota','threshold','cooperation','win-win','record','success','opportunity','互利','合作'],true,ARRAY['Global Times','CGTN','news.cgtn.com','China Daily','People''s Daily','Xinhua'],'australia_china_trade_leverage',2,'Chinese state mutual-benefit framing','Chinesische staatliche Rahmung des gegenseitigen Nutzens', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('australia_western_consensus','Australia must reduce its exposure to China and deepen its alliances','Australien muss seine Abhängigkeit von China verringern und seine Bündnisse vertiefen','The Australian and Western mainstream reading treats Australia''s position as one requiring active management: Chinese commercial leverage over iron ore, beef and critical minerals is a vulnerability to be diversified away from; espionage and interference findings and China''s growing strike reach justify the assessments its agencies make; and the answer across the Pacific is more partnership — defence treaties with Fiji and Vanuatu, alongside AUKUS. Vocabulary: de-risk, diversify, counter, deterrence, partner of choice, screening, resilience.','Die australische und westliche Mainstream-Lesart sieht Australiens Lage als aktiv zu steuern: Chinas kommerzieller Hebel über Eisenerz, Rindfleisch und kritische Rohstoffe gilt als Verwundbarkeit, von der zu diversifizieren ist; Erkenntnisse über Spionage und Einflussnahme sowie Chinas wachsende Angriffsreichweite rechtfertigen die Einschätzungen der Sicherheitsbehörden; und die Antwort im Pazifik lautet mehr Partnerschaft — Verteidigungsverträge mit Fidschi und Vanuatu sowie AUKUS.',ARRAY['OCEANIA-AUSTRALIA','AMERICAS-USA','ASIA-CHINA'],ARRAY['de-risk','diversify','counter','deterrence','partner of choice','screening','resilience','vulnerability','security pact','defence pact','assessment'],true,ARRAY['ABC News','Australian Broadcasting Corporation','ABC Pacific','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','France 24','France 24 (EN)','Wall Street Journal','New York Times','Channel NewsAsia','The Hindu','Times of India','Janes','Defense News','Mining.com','S&P Global','OilPrice','CNBC','War on the Rocks','Chatham House','Anadolu Agency','Express Tribune','Bangkok Post','The Star','Jerusalem Post','Philippine Daily Inquirer','CSIS','Lowy Institute'],'australia_theater',1,'Australian and Western consensus','Australischer und westlicher Konsens',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('australia_china_counter','Australia is manufacturing a threat and importing a bloc confrontation it does not need','Australien konstruiert eine Bedrohung und importiert eine Blockkonfrontation, die es nicht braucht','Chinese state media — with Russian outlets on AUKUS — reject the premise across every axis: the trade relationship is complementary and growing, and quota-triggered tariffs are routine administration rather than pressure; the espionage and military-threat assessments are hype, a "crafted rhetorical trap" and a grave strategic miscalculation; Pacific cooperation is requested by sovereign governments and should not be constrained by any third party; and AUKUS is Cold War bloc-building that spreads naval nuclear technology. Vocabulary: hype, fabricated, mutual benefit, Cold War mentality, third party, bloc confrontation.','Chinesische Staatsmedien — bei AUKUS ergänzt durch russische — weisen die Prämisse auf allen Achsen zurück: die Handelsbeziehung sei komplementär und wachsend, quotenbedingte Zölle seien Routine statt Druck; die Einschätzungen zu Spionage und Militärbedrohung seien Panikmache, eine "rhetorische Falle" und ein schwerer strategischer Fehlschluss; die Kooperation im Pazifik erfolge auf Wunsch souveräner Regierungen und dürfe von keinem Dritten beschränkt werden; und AUKUS sei Blockbildung des Kalten Krieges, die nukleare Marinetechnik verbreite.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA','OCEANIA-AUSTRALIA'],ARRAY['hype','fabricated','mutual benefit','Cold War','mentality','third party','bloc confrontation','rhetorical trap','miscalculation','win-win','complementary'],true,ARRAY['Global Times','CGTN','news.cgtn.com','China Daily','People''s Daily','Xinhua','TASS','TASS (EN)','tass.com','RT'],'australia_theater',2,'Chinese and Russian state counter-framing','Chinesische und russische staatliche Gegenrahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('australia_alliance_scepticism','The alliance is delivering less than Australia was promised','Das Bündnis liefert weniger, als Australien versprochen wurde','A distinct critical reading inside the Australian and Western press questions not China policy but the alliance itself: AUKUS has been revised down to three second-hand US submarines, a capability gap opens as the Collins-class fleet is downsized, a UK inquiry found the investment had "already faltered", and senior Australian figures — including a former foreign minister — describe the pact as among the country''s worst foreign-policy decisions. The concern is reliability and cost rather than the existence of a China problem. Vocabulary: second-hand, downgrade, gap, inquiry, faltered, mess, division, explaining.','Eine eigenständige kritische Lesart in der australischen und westlichen Presse stellt nicht die China-Politik infrage, sondern das Bündnis selbst: AUKUS wurde auf drei gebrauchte US-U-Boote heruntergestuft, eine Fähigkeitslücke entsteht durch die Verkleinerung der Collins-Klasse, eine britische Untersuchung sah die Investition als "bereits ins Stocken geraten", und führende australische Persönlichkeiten — darunter ein früherer Außenminister — bezeichnen den Pakt als eine der schlechtesten außenpolitischen Entscheidungen des Landes. Es geht um Zuverlässigkeit und Kosten, nicht um die Existenz eines China-Problems.',ARRAY['OCEANIA-AUSTRALIA','AMERICAS-USA','EUROPE-UK'],ARRAY['second-hand','downgrade','gap','inquiry','faltered','mess','division','explaining','worst','risk','scraps','stopgap'],true,ARRAY['ABC News','Australian Broadcasting Corporation','ABC Pacific','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','France 24','France 24 (EN)','Wall Street Journal','New York Times','Channel NewsAsia','The Hindu','Times of India','Janes','Defense News','War on the Rocks','Chatham House','Anadolu Agency','Express Tribune','Bangkok Post','The Star','CSIS','Lowy Institute'],'australia_theater',3,'Australian alliance scepticism','Australische Bündnisskepsis', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('baloch_foreign_backed_insurgency','The attacks are externally sponsored terrorism, not a domestic grievance','Die Anschläge sind von außen gesteuerter Terrorismus, keine innenpolitische Beschwerde','State-security framing (Pakistani press) treats the violence in Balochistan as externally sponsored terrorism rather than an indigenous political movement: officials link Baloch Liberation Army attacks to Indian backing, security operations are reported as counter-terrorism with militant death tolls, and the province''s mineral and port development is presented as the answer the militants aim to prevent.','Die staatliche Sicherheitsdarstellung (pakistanische Presse) betrachtet die Gewalt in Belutschistan als von außen gesteuerten Terrorismus und nicht als einheimische politische Bewegung: Behörden bringen Anschläge der Belutschischen Befreiungsarmee mit indischer Unterstützung in Verbindung, Sicherheitsoperationen werden als Terrorbekämpfung mit Opferzahlen unter Militanten dargestellt, und die Erschließung der Bodenschätze und des Hafens der Provinz gilt als jene Antwort, die die Militanten verhindern wollen.',ARRAY['ASIA-PAKISTAN'],ARRAY['terrorist','militant','BLA','Indian-backed','proxy','security forces','operation','neutralis','designate','responsible','sponsor','Ghazab','terrorism','hostile','Terrorist','Militante','Terrorismus'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation'],'balochistan_insurgency',1,'Foreign-backed insurgency','Von außen unterstützter Aufstand',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('baloch_rights_repression','The state answers Baloch grievances with force and detention','Der Staat begegnet belutschischen Beschwerden mit Gewalt und Haft','Rights framing (Western mainstream and wire services) centres the treatment of Baloch civilians and activists rather than either government''s security case: the life sentence handed to activist Mahrang Baloch, enforced disappearances, restrictions on peaceful protest, and the argument that a province held by force will not be pacified by mining investment.','Die menschenrechtliche Darstellung (westliche Leitmedien und Nachrichtenagenturen) rückt den Umgang mit belutschischen Zivilisten und Aktivisten in den Mittelpunkt statt der Sicherheitsargumente einer Regierung: die lebenslange Haftstrafe für die Aktivistin Mahrang Baloch, Fälle von Verschwindenlassen, Einschränkungen friedlichen Protests und das Argument, dass eine mit Gewalt gehaltene Provinz nicht durch Bergbauinvestitionen befriedet wird.',ARRAY['ASIA-PAKISTAN'],ARRAY['Mahrang','activist','disappearance','rights','sentenced','protest','crackdown','detention','Aktivist','Verschwinden','Rechte'],true,ARRAY['Reuters','BBC World','Associated Press','Deutsche Welle','The Guardian','Al Jazeera','France 24','France 24 (EN)','Euronews'],'balochistan_insurgency',2,'Repression and disappearances','Repression und Verschwindenlassen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('baloch_pakistan_internal_failure','The insurgency is Pakistan''s own governance failure, not foreign subversion','Der Aufstand ist Pakistans eigenes Regierungsversagen, keine ausländische Unterwanderung','Internal-failure framing (Indian press) rejects the sponsorship charge and treats the insurgency as evidence of Pakistani state failure: allegations of Indian involvement are dismissed as deflection from internal failings, the province is described as approaching civil war, and the scale of the violence is presented as the consequence of decades of neglect and coercive administration.','Die Darstellung des inneren Versagens (indische Presse) weist den Vorwurf der Unterstützung zurück und betrachtet den Aufstand als Beleg für das Versagen des pakistanischen Staates: Vorwürfe indischer Beteiligung gelten als Ablenkung von inneren Defiziten, die Provinz wird als am Rande eines Bürgerkriegs beschrieben, und das Ausmaß der Gewalt gilt als Folge jahrzehntelanger Vernachlässigung und einer auf Zwang gestützten Verwaltung.',ARRAY['ASIA-INDIA'],ARRAY['internal failing','baseless','civil war','deflect','reject','failure','unrest','neglect','inneres Versagen','haltlos','Bürgerkrieg'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'balochistan_insurgency',3,'Pakistan''s internal failure','Pakistans inneres Versagen', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('casp_continental_dependence','Canada depends on American protection','Kanada ist auf amerikanischen Schutz angewiesen','Canada is a smaller power whose prosperity and security rest on American markets and American defence, and which is poorly placed to object when Washington sets the terms of the relationship or questions the border arrangements underpinning it.','Kanada sei eine kleinere Macht, deren Wohlstand und Sicherheit auf amerikanischen Märkten und amerikanischer Verteidigung beruhen und die schlecht aufgestellt sei, um zu widersprechen, wenn Washington die Bedingungen der Beziehung setzt oder die zugrunde liegenden Grenzarrangements infrage stellt.',ARRAY['AMERICAS-USA'],ARRAY['grateful','small power','biting the hand','protects','depend','weakness','Golden Dome','freeload','benchmark','shield','umbrella','dankbar','abhängig','Schutzschirm'],true,ARRAY['Fox News'],'canada_sovereignty_pressure',1,'Dependence is the reality','Abhängigkeit ist die Realität',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('casp_sovereignty_defence','Sovereignty under pressure','Souveränität unter Druck','Annexation and "51st state" rhetoric, the threat to withhold a jointly financed border crossing, and the withdrawn diplomatic invitation are treated as pressure on the sovereignty of an independent state, prompting a cross-party Canadian response and a public turn toward domestic purchasing and alternative trading partners.','Annexionsrhetorik und Reden vom „51. Bundesstaat", die Drohung, einen gemeinsam finanzierten Grenzübergang zurückzuhalten, und die zurückgezogene diplomatische Einladung werden als Druck auf die Souveränität eines unabhängigen Staates verstanden — mit einer parteiübergreifenden kanadischen Reaktion und einer öffentlichen Hinwendung zu heimischen Käufen und alternativen Handelspartnern.',ARRAY['AMERICAS-CANADA'],ARRAY['sovereignt','independen','annex','51st state','reject','rebuff','stand up','unity','respect','Souveränität','Annexion','zurückweis'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','Der Spiegel','El País','France 24 (EN)','France 24','Al Jazeera','NDTV','Anadolu Agency','Reforma','El Universal','Mexico News Daily','Straits Times','La Nación','Clarín','Japan Times'],'canada_sovereignty_pressure',2,'Sovereignty must hold','Souveränität muss bestehen', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('casp_imperial_overreach','Imperial overreach in its own hemisphere','Imperiale Überdehnung in der eigenen Hemisphäre','Talk of absorbing a neighbouring state is presented as proof that American expansionism operates on its own continent as readily as abroad, and as grounds to dismiss Washington''s claim to defend a rules-based order or to invoke external threats as justification.','Das Gerede von der Einverleibung eines Nachbarstaates wird als Beleg dafür präsentiert, dass amerikanischer Expansionismus auf dem eigenen Kontinent ebenso wirkt wie im Ausland — und als Grund, Washingtons Anspruch zurückzuweisen, eine regelbasierte Ordnung zu verteidigen oder äußere Bedrohungen als Rechtfertigung anzuführen.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['expansionis','imperial','annex','colonial','hypocris','double standard','so-called','rules-based','Expansionis','imperial','Doppelmoral'],true,ARRAY['RT','TASS (EN)','Global Times','CGTN','People''s Daily','China Daily','Xinhua','Sputnik','Press TV'],'canada_sovereignty_pressure',3,'Expansionism exposed','Expansionismus entlarvt', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cpc_western_engagement','Outside engagement brings beneficial partnership and integration to the region','Äußeres Engagement bringt der Region nützliche Partnerschaft und Integration','A Western, Turkish and Israeli framing presents outside engagement in the South Caucasus as beneficial partnership and integration: Azerbaijani energy exports to Europe through SOCAR and the Southern Gas Corridor, Israeli and Turkish security and economic ties, a growing US role, and -- as an expression of Western and Israeli moral engagement -- recognition of the Armenian Genocide.','Eine westliche, türkische und israelische Deutung stellt das äußere Engagement im Südkaukasus als nützliche Partnerschaft und Integration dar: aserbaidschanische Energieexporte nach Europa über SOCAR und den Südlichen Gaskorridor, israelische und türkische Sicherheits- und Wirtschaftsbeziehungen, eine wachsende US-Rolle und -- als Ausdruck westlichen und israelischen moralischen Engagements -- die Anerkennung des Völkermords an den Armeniern.',ARRAY['ASIA-CAUCASUS'],ARRAY['partnership','integration','ties','cooperation','energy security','strategic partnership','grand deal','moral','justice','SOCAR','Southern Gas Corridor','Partnerschaft','Integration','Zusammenarbeit','moralisch','партнерство','сотрудничество'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','ANSA','La Repubblica','El País','Novinite','OilPrice','Carnegie Endowment','NPR','Daily Sabah','Anadolu Agency','TRT World','Jerusalem Post','The Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS'],'caucasus_power_competition',1,'Beneficial external partnership','Nützliche externe Partnerschaft',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cpc_russia_iran_resistance','Outside penetration of the region is a hostile encirclement to be resisted','Das Eindringen von außen in die Region ist eine feindliche Einkreisung, der zu widerstehen ist','A Russian and Iranian framing casts outside engagement as hostile penetration: US, Turkish and Israeli inroads -- bases, energy and arms deals, and transport corridors -- threaten Russian and Iranian interests and regional stability and are to be resisted through their own partnerships, amid frictions such as the disputes between Russia and Azerbaijan.','Eine russische und iranische Deutung stellt das äußere Engagement als feindliches Eindringen dar: US-amerikanische, türkische und israelische Vorstöße -- Stützpunkte, Energie- und Rüstungsgeschäfte sowie Transportkorridore -- bedrohten russische und iranische Interessen und die regionale Stabilität und seien durch eigene Partnerschaften abzuwehren, inmitten von Reibungen wie den Streitigkeiten zwischen Russland und Aserbaidschan.',ARRAY['ASIA-CAUCASUS'],ARRAY['encirclement','penetration','inroads','threat to stability','red line','foreign base','resist','sphere of influence','espionage','Einkreisung','Vordringen','rote Linie','Bedrohung','угроза','вторжение','красная линия','сфера влияния','шпионаж'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian','IRNA','Press TV'],'caucasus_power_competition',2,'Hostile encirclement / resistance','Feindliche Einkreisung / Widerstand', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('caucasus_western_consensus','The South Caucasus is realigning westward -- peace, connectivity and a break from Russia','Der Südkaukasus richtet sich neu nach Westen aus -- Frieden, Konnektivität und ein Bruch mit Russland','Western, Turkish and Israeli coverage reads the South Caucasus as tilting decisively toward the West and a post-Russian order: Armenia''s European pivot, a US-brokered Armenia-Azerbaijan peace, opening trade corridors, and recognition of historic wrongs together mark a strategic realignment away from Moscow.','Die westliche, türkische und israelische Berichterstattung liest den Südkaukasus als klar nach Westen und zu einer nachrussischen Ordnung neigend: Armeniens europäischer Schwenk, ein von den USA vermittelter Frieden zwischen Armenien und Aserbaidschan, sich öffnende Handelskorridore und die Anerkennung historischen Unrechts markierten zusammen eine strategische Neuordnung weg von Moskau.',ARRAY['ASIA-CAUCASUS'],ARRAY['realignment','pivot','peace','connectivity','European','away from Russia','Neuordnung','Frieden','realignment'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','Washington Post','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Tagesschau','ANSA','La Repubblica','El País','Le Figaro','Carnegie Endowment','Novinite','Kyiv Post','LRT English','The Economist','The National','Daily Sabah','Anadolu Agency','TRT World','Jerusalem Post','The Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS'],'caucasus_theater',1,'Western/regional realignment consensus','Konsens westlicher/regionaler Neuordnung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('caucasus_russia_china_counter','The West is destabilizing Russia''s neighbourhood and dragging it into an anti-Russian orbit','Der Westen destabilisiert Russlands Nachbarschaft und zieht sie in eine antirussische Umlaufbahn','Russian and Chinese state media frame the same events as reckless Western expansionism: election interference, colour-revolution engineering and Turkish/US/Israeli penetration are destabilizing Russia''s traditional sphere and steering the Caucasus toward a "Ukraine scenario" of chaos and dependency.','Russische und chinesische Staatsmedien deuten dieselben Ereignisse als rücksichtslosen westlichen Expansionismus: Wahleinmischung, das Inszenieren von Farbrevolutionen und türkisch/US-amerikanisch/israelisches Vordringen destabilisierten Russlands traditionelle Sphäre und steuerten den Kaukasus in ein "Ukraine-Szenario" aus Chaos und Abhängigkeit.',ARRAY['ASIA-CAUCASUS'],ARRAY['interference','colour revolution','Ukraine scenario','encirclement','expansionism','destabiliz','Einmischung','Farbrevolution','вмешательство','дестабилизац'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian','CGTN','news.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua'],'caucasus_theater',2,'Russia/China counter-narrative','Gegenerzählung Russlands/Chinas', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cjer_economic_coercion','China is weaponizing trade, minerals and tourism to punish Japanese political speech','China instrumentalisiert Handel, Rohstoffe und Tourismus, um japanische politische Äußerungen zu bestrafen','Coercion framing (Japanese and Western press) reads China''s rare-earth and dual-use export controls, entity blacklists, travel advisories, the collapse in Chinese tourism and the detention of Japanese nationals as a coordinated economic punishment for a political statement -- a repeat of the 2010 rare-earth showdown -- and treats supply concentration in Chinese hands as a strategic vulnerability. The response it presents is diversification: seabed mining, recycling, and joint stockpiling with Canada, France and G7 partners to find non-Chinese sources. Vocabulary: coercion, squeeze, chokehold, throttling exports, blacklist, retaliation, de-risking, diversify, non-China sources.','Die Nötigungs-Rahmung (japanische und westliche Presse) deutet Chinas Exportkontrollen für Seltene Erden und Güter mit doppeltem Verwendungszweck, schwarze Listen für Unternehmen, Reisewarnungen, den Einbruch des chinesischen Tourismus und die Festnahme japanischer Staatsbürger als koordinierte wirtschaftliche Bestrafung einer politischen Äußerung -- eine Wiederholung des Seltene-Erden-Konflikts von 2010 -- und sieht in der Lieferkonzentration eine strategische Verwundbarkeit. Als Antwort erscheint Diversifizierung: Tiefseeabbau, Recycling und gemeinsame Vorratshaltung mit Kanada, Frankreich und G7-Partnern.',ARRAY['ASIA-JAPAN'],ARRAY['coercion','squeeze','chokehold','pressure','weaponiz','retaliation','punish','throttling','blacklist','curbs','showdown','de-risk','diversify','stockpiling','alternatives','non-China','Nötigung','Druck','Vergeltung'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','朝日新聞','Reuters','Bloomberg','Financial Times','Wall Street Journal','New York Times','The Economist','The Telegraph','The Guardian','Straits Times','Channel NewsAsia','Deutsche Welle','Mining.com','OilPrice','Wired','Al Jazeera','VN Express'],'china_japan_economic_restrictions',1,'Economic coercion','Wirtschaftliche Nötigung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cjer_lawful_regulation','China''s export controls are lawful regulation and Japan''s own conduct caused the downturn','Chinas Exportkontrollen sind rechtmäßige Regulierung, und Japans eigenes Verhalten hat den Einbruch verursacht','Lawful-regulation framing (Chinese state media) presents the export controls as ordinary licensing of dual-use items to military end-users, applied in accordance with Chinese law and international non-proliferation obligations and aimed at curbing Japan''s military build-up rather than at trade. It attributes the fall in tourism and business confidence to Japanese conduct -- an erosion of mutual trust caused by the prime minister''s remarks -- and casts detentions as ordinary law enforcement against violations of Chinese law, while presenting Japanese firms and G7 partners as unconvinced by Tokyo''s hardline stance. Vocabulary: in accordance with law, dual-use, military end-user, watch list, erosion of mutual trust, root cause, outlier.','Die Regulierungs-Rahmung (chinesische Staatsmedien) stellt die Exportkontrollen als gewöhnliche Lizenzierung von Gütern mit doppeltem Verwendungszweck für militärische Endnutzer dar -- angewandt nach chinesischem Recht und internationalen Nichtverbreitungspflichten und gerichtet auf die Eindämmung von Japans Aufrüstung, nicht auf den Handel. Den Rückgang von Tourismus und Geschäftsvertrauen führt sie auf japanisches Verhalten zurück: eine durch die Äußerungen der Regierungschefin verursachte Erosion des gegenseitigen Vertrauens. Festnahmen gelten als normale Strafverfolgung.',ARRAY['ASIA-CHINA'],ARRAY['in accordance with law','lawful','dual-use','military end-user','non-proliferation','international obligations','watch list','erosion of mutual trust','harms business','root cause','self-inflicted','outlier','curb','neo-militaris','in accordance with Chinese laws','rechtmäßig','Gesetz'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch'],'china_japan_economic_restrictions',2,'Lawful regulation claim','Anspruch rechtmäßiger Regulierung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('china_threat_substantiated','Chinese espionage and military reach against Australia are real and growing','Chinesische Spionage und militärische Reichweite gegenüber Australien sind real und wachsen','Australian and allied coverage treats the threat assessment as evidence-based: ASIO sparring with Beijing over foreign interference, prosecutions of Chinese nationals for interference in Canberra, a jury finding an Australian expat acted as a Chinese spy asset, Five Eyes warnings that Chinese services recruit through fake job ads on professional networks, and Lowy Institute analysis that China''s capacity to strike targets in Australia is "real and growing" — underlined by a nuclear-capable ballistic missile test into the South Pacific. Vocabulary: espionage, foreign interference, spy, Five Eyes, strike capacity, ballistic, assessment.','Die australische und verbündete Berichterstattung behandelt die Bedrohungsanalyse als faktenbasiert: der Streit des Inlandsgeheimdienstes ASIO mit Peking über ausländische Einflussnahme, Anklagen gegen chinesische Staatsbürger wegen Einflussnahme in Canberra, ein Geschworenenurteil, wonach ein australischer Auswanderer als chinesischer Spionagehelfer handelte, Warnungen der Five Eyes vor Anwerbung über gefälschte Stellenanzeigen sowie die Analyse des Lowy Institute, Chinas Fähigkeit zu Angriffen auf Ziele in Australien sei "real und wachsend" — unterstrichen durch einen atomwaffenfähigen Raketentest im Südpazifik.',ARRAY['OCEANIA-AUSTRALIA','ASIA-CHINA'],ARRAY['espionage','foreign interference','spy','spies','Five Eyes','strike capacity','ballistic','missile','assessment','warns','charged','recruit','real and growing'],true,ARRAY['ABC News','Australian Broadcasting Corporation','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','Wall Street Journal','New York Times','Jerusalem Post','Channel NewsAsia','Janes','Defense News','CSIS','Lowy Institute'],'china_threat_assessment',1,'Australian and allied threat-assessment framing','Australische und verbündete Bedrohungsanalyse-Rahmung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('china_threat_fabricated','The "China threat" is a fabricated narrative used to justify Australian alignment against Beijing','Die "China-Bedrohung" ist ein konstruiertes Narrativ zur Rechtfertigung der australischen Ausrichtung gegen Peking','Chinese state framing rejects the assessments as manufactured: the Five Eyes espionage warning is called a "crafted rhetorical trap" and "highly ironic" given the alliance''s own surveillance record, and Australian think-tank claims of a Chinese military threat are called a grave strategic miscalculation. The argument is that the threat narrative is hype that serves alignment politics and damages a functioning relationship. Vocabulary: fabricated, hype, rhetorical trap, ironic, miscalculation, smear, Cold War mentality.','Die chinesische staatliche Rahmung weist die Einschätzungen als konstruiert zurück: die Five-Eyes-Warnung vor Spionage wird als "rhetorische Falle" und angesichts der eigenen Überwachungspraxis des Bündnisses als "höchst ironisch" bezeichnet, und Behauptungen australischer Denkfabriken über eine chinesische Militärbedrohung gelten als schwerer strategischer Fehlschluss. Das Narrativ der Bedrohung sei Panikmache, die der Bündnispolitik diene und eine funktionierende Beziehung beschädige.',ARRAY['ASIA-CHINA','OCEANIA-AUSTRALIA'],ARRAY['fabricated','hype','rhetorical trap','ironic','miscalculation','smear','Cold War','mentality','refutes','rejects','slams','so-called','alleged','炒作'],true,ARRAY['Global Times','CGTN','news.cgtn.com','China Daily','People''s Daily','Xinhua'],'china_threat_assessment',2,'Chinese state rebuttal framing','Chinesische staatliche Gegendarstellungs-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_peace_negotiation_defense','Talks are how the war ends','Gespräche beenden den Krieg','The supportive reading holds that negotiated demobilisation, transitional justice and rural investment are the only instruments that have historically reduced Colombia''s armed conflict, and that suspending talks under external pressure forfeits the mechanism without offering a replacement.','Die unterstützende Lesart hält fest, dass ausgehandelte Demobilisierung, Übergangsjustiz und Investitionen im ländlichen Raum die einzigen Instrumente sind, die Kolumbiens bewaffneten Konflikt historisch verringert haben, und dass die Aussetzung der Gespräche unter äußerem Druck diesen Mechanismus preisgibt, ohne Ersatz zu bieten.',ARRAY['AMERICAS-ANDEAN'],ARRAY['paz total','proceso de paz','negociac','peace talks','peace process','desmoviliz','transitional justice','justicia transicional','diálogo','acuerdo','resume','reanuda','ceasefire','cese'],true,ARRAY['El País','Deutsche Welle','Al Jazeera','Anadolu Agency','UN News','The Guardian','France 24','France 24 (EN)','BBC World'],'colombia_armed_groups_peace',1,'Negotiation is the workable route','Verhandlung ist der gangbare Weg',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_peace_process_failure','Talks bought the cartels time','Gespräche verschafften den Kartellen Zeit','The critical reading holds that open-ended negotiations let guerrilla factions and cartels consolidate territory, recruit and expand coca and gold revenues while nominally at the table, and that violence rose over the period the policy was in force.','Die kritische Lesart hält fest, dass ergebnisoffene Verhandlungen es Guerillafraktionen und Kartellen erlaubten, Gebiete zu festigen, zu rekrutieren sowie Koka- und Goldeinnahmen auszuweiten, während sie nominell am Tisch saßen, und dass die Gewalt im Geltungszeitraum der Politik zunahm.',ARRAY['AMERICAS-ANDEAN'],ARRAY['violencia','fracaso','enseñorea','dispara','control territorial','reclutamiento','impunidad','failed','emboldened','expansión','suspend','war crimes','crímenes de guerra','extorsión'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae'],'colombia_armed_groups_peace',2,'Negotiation emboldened the groups','Verhandlungen bestärkten die Gruppen', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_transition_mandate','Voters chose a harder line','Die Wähler wählten eine härtere Linie','The sympathetic reading treats the result as a decisive verdict on the outgoing government''s security record: an electorate exhausted by cartel violence and stalled negotiations voted for confrontation with armed groups and closer working relations with Washington.','Die wohlwollende Lesart wertet das Ergebnis als deutliches Urteil über die Sicherheitsbilanz der scheidenden Regierung: Eine von Kartellgewalt und stockenden Verhandlungen erschöpfte Wählerschaft stimmte für die Konfrontation mit bewaffneten Gruppen und engere Arbeitsbeziehungen zu Washington.',ARRAY['AMERICAS-ANDEAN'],ARRAY['mandato','mano dura','seguridad','crackdown','mega-prison','megacárcel','crime','rightward','giro a la derecha','ciclo de Petro','tough on','respaldo','cartel','orden','autoridad'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae','Associated Press','Reuters','Bloomberg','Japan Times','Atlantic Council'],'colombia_political_transition',1,'A mandate for security','Ein Mandat für Sicherheit',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_transition_institutional_concern','The result strains the guardrails','Das Ergebnis belastet die Schutzmechanismen','The critical reading raises the endorsement of a candidate by a foreign head of state before the vote, the outgoing president''s allegation of foreign interference, and the losing camp''s legal challenge as pressures on Colombian institutional norms, independent of the winner''s programme.','Die kritische Lesart benennt die Unterstützung eines Kandidaten durch ein ausländisches Staatsoberhaupt vor der Wahl, den Vorwurf ausländischer Einflussnahme durch den scheidenden Präsidenten und die Klage des unterlegenen Lagers als Belastungen kolumbianischer institutioneller Normen -- unabhängig vom Programm des Siegers.',ARRAY['AMERICAS-ANDEAN'],ARRAY['institucional','institutional','democracia','democracy','injerencia','interference','fraude','impugna','legal challenge','norms','autoritari','riesgo','concern','fears','ultraderech','far-right','extrema derecha','estrema destra','no reconoce','non riconosce','threat to','amenaza para','backsliding'],true,ARRAY['El País','The Guardian','Deutsche Welle','France 24','France 24 (EN)','Le Monde','BBC World','New York Times','CNN','Euronews','La Repubblica','Al Jazeera','Anadolu Agency'],'colombia_political_transition',2,'Concern for institutional norms','Sorge um institutionelle Normen', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_hard_turn','The electorate chose confrontation','Die Wählerschaft wählte Konfrontation','One reading runs through every arena at once: voters rejected negotiation with armed groups, elected a government promising confrontation and closer alignment with Washington, and treated the outgoing security policy as the thing that failed.','Eine Lesart durchzieht alle Bereiche zugleich: Die Wähler lehnten Verhandlungen mit bewaffneten Gruppen ab, wählten eine Regierung, die Konfrontation und engere Anlehnung an Washington verspricht, und werteten die scheidende Sicherheitspolitik als das Gescheiterte.',ARRAY['AMERICAS-ANDEAN'],ARRAY['mandato','seguridad','mano dura','cartel','violencia','victoria','contundente'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae'],'colombia_theater',1,'A country turning hard','Ein Land im harten Kurswechsel',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_negotiated_path','Bargaining still works, at home and abroad','Verhandeln funktioniert weiter, innen wie außen','A second reading emphasises that both the confrontation with Washington and the conflict with armed groups were managed through bargaining rather than force: the military threat ended in a White House meeting, and negotiation remains the only instrument that has historically shrunk the armed conflict.','Eine zweite Lesart betont, dass sowohl die Konfrontation mit Washington als auch der Konflikt mit bewaffneten Gruppen durch Verhandlung statt Gewalt bearbeitet wurden: Die Militärdrohung endete in einem Treffen im Weißen Haus, und Verhandlung bleibt das einzige Instrument, das den bewaffneten Konflikt historisch verkleinert hat.',ARRAY['AMERICAS-ANDEAN'],ARRAY['détente','acuerdo','negociac','peace process','paz total','diálogo','meeting'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País','Al Jazeera','Anadolu Agency','UN News'],'colombia_theater',2,'The negotiated path holds','Der Verhandlungsweg trägt',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_external_pressure','Decisions shaped from outside','Von außen geformte Entscheidungen','Mainstream coverage across the arenas describes a state whose room for manoeuvre narrowed from outside: a threatened military operation, tariff and sanctions pressure, a foreign endorsement in a national election, and an understanding with Washington that reshaped domestic negotiations with armed groups.','Etablierte Berichterstattung beschreibt über alle Bereiche hinweg einen Staat, dessen Handlungsspielraum von außen verengt wurde: eine angedrohte Militäroperation, Zoll- und Sanktionsdruck, eine ausländische Wahlempfehlung im nationalen Wahlkampf und eine Verständigung mit Washington, die die inneren Verhandlungen mit bewaffneten Gruppen umformte.',ARRAY['AMERICAS-ANDEAN'],ARRAY['threat','amenaza','sovereignty','soberan','injerencia','interference','institutional','democracia','tariff','sanction'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País','La Repubblica','Al Jazeera','Anadolu Agency'],'colombia_theater',3,'Sovereignty under external pressure','Souveränität unter äußerem Druck', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_hegemonic_critique','The region as a sphere of influence','Die Region als Einflusssphäre','State and non-Western outlets read the same events as a single demonstration of US primacy in the hemisphere -- military threats, strikes in neighbouring Venezuela and open intervention in an allied democracy''s election -- rather than as separate bilateral disputes.','Staatliche und außerwestliche Medien lesen dieselben Ereignisse als eine einzige Demonstration US-amerikanischer Vormacht in der Hemisphäre -- Militärdrohungen, Angriffe im benachbarten Venezuela und offene Einmischung in die Wahl einer verbündeten Demokratie -- und nicht als getrennte bilaterale Streitfälle.',ARRAY['AMERICAS-USA'],ARRAY['hegemon','imperial','soberan','injerencia','domination','unilateral','sphere of influence'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','Al-Ahram'],'colombia_theater',4,'Hemispheric domination critique','Kritik hemisphärischer Vorherrschaft', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_rapprochement','The channel was repaired','Der Gesprächskanal wurde repariert','Coverage of the reversal treats the White House meeting as evidence that the relationship remains negotiable: threats gave way to an invitation, both governments claimed a working understanding, and cooperation on security and trade resumed.','Die Berichterstattung über die Kehrtwende wertet das Treffen im Weißen Haus als Beleg dafür, dass die Beziehung verhandelbar bleibt: Auf Drohungen folgte eine Einladung, beide Regierungen reklamierten eine Arbeitsverständigung, und die Zusammenarbeit bei Sicherheit und Handel wurde wieder aufgenommen.',ARRAY['AMERICAS-USA'],ARRAY['détente','detente','amends','meeting','reunión','encuentro','invit','pacto','acuerdo','visita','recibe','host','talks','deal'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País'],'colombia_us_alignment',1,'Negotiated rapprochement','Ausgehandelte Annäherung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_coercion','Threats replaced diplomacy','Drohungen ersetzten Diplomatie','The critical reading holds that an allied government was subjected to a threatened military operation, tariff pressure and sanctions designations over a policy dispute, and that Bogotá''s formal complaint marked a durable shift in what the relationship can be assumed to guarantee.','Die kritische Lesart hält fest, dass eine verbündete Regierung wegen eines politischen Streits mit einer angedrohten Militäroperation, Zolldruck und Sanktionslistungen überzogen wurde und dass Bogotás förmliche Beschwerde eine dauerhafte Verschiebung dessen markiert, was die Beziehung noch garantiert.',ARRAY['AMERICAS-USA'],ARRAY['threat','amenaza','military operation','operación militar','military action','tariff','arancel','sanction','sanción','sovereignty','soberan','complaint','queja','insult','slander'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País'],'colombia_us_alignment',2,'Coercion against a partner','Zwang gegen einen Partner', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_imperial_overreach','A sovereign state treated as a subordinate','Ein souveräner Staat als Untergebener behandelt','State and non-Western outlets present the episode as an assertion of hemispheric domination rather than a bilateral dispute: military threats against a sovereign government, coupled with strikes in neighbouring Venezuela, are framed as the working method of US regional primacy.','Staatliche und außerwestliche Medien stellen die Episode als Behauptung hemisphärischer Vorherrschaft dar und nicht als bilateralen Streit: Militärdrohungen gegen eine souveräne Regierung, verbunden mit Angriffen im benachbarten Venezuela, gelten als Arbeitsmethode US-amerikanischer Regionalvormacht.',ARRAY['AMERICAS-USA'],ARRAY['hegemon','imperial','sovereignty','soberan','interference','injerencia','domination','bullying','unilateral'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','Al Jazeera','Anadolu Agency','Al-Ahram'],'colombia_us_alignment',3,'Hegemonic imposition','Hegemoniale Anmaßung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_pressure_justified','The instruments are aimed at a government that rules without consent','Die Instrumente richten sich gegen eine Regierung, die ohne Zustimmung herrscht','Sanctions, designations and criminal charges target a one-party leadership implicated in trafficking and repression -- the pressure is aimed at a government, not at a people it does not represent.','Sanktionen, Listungen und Strafverfahren richten sich gegen eine Einparteienführung, die in Schmuggel und Repression verstrickt ist -- der Druck zielt auf eine Regierung, nicht auf ein Volk, das sie nicht vertritt.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],ARRAY['castrismo','Castroism','dictad','dictat','ditadura','Diktatur','communist rule','one-party','partido único','must go','teetering','autocrat','narcotráfico','drug trafficking','murder charges','accountab','rendición de cuentas','sin consentimiento'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_embargo_sanctions',1,'Aimed at the government','Gegen die Regierung gerichtet',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_sanctions_overreach','Extraterritorial sanctions are collective punishment','Extraterritoriale Sanktionen sind Kollektivstrafe','Secondary sanctions that force European shippers and hotel groups out and penalise third countries reach far beyond US jurisdiction, and the burden falls on ordinary Cubans rather than the government.','Sekundärsanktionen, die europäische Reedereien und Hotelgruppen zum Rückzug zwingen und Drittstaaten bestrafen, reichen weit über die US-Jurisdiktion hinaus -- und die Last tragen gewöhnliche Kubaner, nicht die Regierung.',ARRAY['NON-STATE-EU','AMERICAS-USA','AMERICAS-CUBA'],ARRAY['extraterritorial','overreach','collective punishment','castigo colectivo','Kollektivstrafe','secondary sanctions','third countries','terceros países','unilateral','einseitig','coercive','coerci','counterproductive','contraproducente','kontraproduktiv','condemn','verurteil','condena','economic bombing','chok','asfixia','asphyx','strangl','breaking point','völkerrechtswidrig'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_embargo_sanctions',2,'Extraterritorial overreach','Extraterritoriale Übergriffigkeit', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_economic_warfare','The blockade is economic warfare against a sovereign nation','Die Blockade ist Wirtschaftskrieg gegen eine souveräne Nation','Washington''s siege is an illegal act of economic aggression, condemned year after year by the UN General Assembly, designed to break a country that refuses to submit.','Washingtons Belagerung ist ein illegaler Akt wirtschaftlicher Aggression, Jahr für Jahr von der UN-Generalversammlung verurteilt, um ein Land zu brechen, das sich nicht unterwirft.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_embargo_sanctions',3,'Economic warfare','Wirtschaftskrieg', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_self_inflicted','Decades of mismanagement, not the blockade, emptied the grid','Jahrzehnte der Misswirtschaft, nicht die Blockade, haben das Netz geleert','A Soviet-era grid left unmaintained, a state-run economy that never generated hard currency and a refusal to reform are why the lights went out; external pressure only exposed a model that had already failed.','Ein nie instand gehaltenes Netz aus Sowjetzeiten, eine Staatswirtschaft ohne Devisen und die Verweigerung von Reformen sind der Grund für die Dunkelheit; äußerer Druck hat nur ein längst gescheitertes Modell offengelegt.',ARRAY['AMERICAS-CUBA'],ARRAY['mismanagement','Misswirtschaft','mala gestión','decades of','décadas','Soviet-era','ageing','aging','obsolet','envejec','decay','marode','veraltet','state-run','central planning','Planwirtschaft','self-inflicted','failed model','modelo fallido','fracas','failing','arruin','ineficien','castrismo','gescheitert'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_energy_collapse',1,'Self-inflicted collapse','Selbstverschuldeter Zusammenbruch',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_humanitarian_alarm','A humanitarian emergency is unfolding whoever is to blame','Eine humanitäre Notlage entfaltet sich, gleich wer schuld ist','Hospitals without power, uncollected refuse, malnutrition and UN warnings of collapse describe a civilian emergency that has outrun the argument about its causes.','Kliniken ohne Strom, nicht abgeholter Müll, Mangelernährung und UN-Warnungen vor einem Zusammenbruch beschreiben eine zivile Notlage, die den Streit über ihre Ursachen längst überholt hat.',ARRAY['NON-STATE-EU','AMERICAS-CUBA'],ARRAY['humanitarian','humanitär','humanitaria','emergency','emergenc','Notlage','children are dying','civilians','Zivilisten','civiles','hospital','malnutrition','malnutri','hunger','hambre','Hunger','UN warns','catastroph','catástrofe','Katastroph','suffering','Leid','sufrimiento','desperate','desesper','misery','agoniz','asfixia','chok','breaking point','penuria'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_energy_collapse',2,'Humanitarian emergency','Humanitäre Notlage', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_starvation_siege','Starvation by siege is a deliberate instrument of policy','Aushungern durch Belagerung ist ein bewusstes Instrument der Politik','Cutting a small island''s fuel until its hospitals go dark and its children go hungry is not a side effect but the objective -- collective punishment used to force political surrender.','Einer kleinen Insel den Treibstoff zu nehmen, bis ihre Kliniken dunkel werden und ihre Kinder hungern, ist keine Nebenwirkung, sondern das Ziel -- Kollektivstrafe zur Erzwingung politischer Kapitulation.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_energy_collapse',3,'Starvation as a weapon','Aushungern als Waffe', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_prop_up','Outside shipments prop up a government that would otherwise have to change','Lieferungen von außen stützen eine Regierung, die sich sonst ändern müsste','Russian and Venezuelan cargoes and third-country aid buy time for a leadership that has refused reform, blunting the only pressure that has ever moved it.','Russische und venezolanische Ladungen sowie Hilfe aus Drittstaaten verschaffen einer reformunwilligen Führung Zeit und stumpfen den einzigen Druck ab, der je etwas bewegt hat.',ARRAY['AMERICAS-CUBA','EUROPE-RUSSIA'],ARRAY['prop up','props up','apuntalar','stütz','undercut','circumvent','umgehen','evade','eludir','sanctions-busting','prolong','prolongar','verlängert','buy time','oxígeno','respiro','rescue','rescate','castrismo','dictad','ditadura'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_external_lifelines',1,'Propping up the government','Stützung der Regierung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_humanitarian_duty','Relief is a humanitarian obligation and third states should not be coerced','Hilfe ist eine humanitäre Pflicht, und Drittstaaten dürfen nicht genötigt werden','Mexico, Spain, Brazil and Canada are meeting an obligation to a population in crisis, and pressuring them to withhold fuel and food turns civilians into the instrument of a dispute between governments.','Mexiko, Spanien, Brasilien und Kanada erfüllen eine Pflicht gegenüber einer Bevölkerung in der Krise; sie zum Zurückhalten von Treibstoff und Nahrung zu drängen, macht Zivilisten zum Werkzeug eines Regierungsstreits.',ARRAY['AMERICAS-MEXICO','EUROPE-SOUTH','AMERICAS-CUBA'],ARRAY['humanitarian','obligation','must reach','blocked','hampers','dialogue','diplomatic path','sovereign right','solidarity','donate','relief effort','humanitär','Pflicht','Dialog','souverän','Solidarität','humanitaria','obligación','vía diplomática','diálogo','soberan','solidaridad','donar','debe llegar'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_external_lifelines',2,'Humanitarian obligation','Humanitäre Pflicht', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_solidarity','Solidarity with a besieged island against an illegal siege','Solidarität mit einer belagerten Insel gegen eine illegale Belagerung','Fuel, grain and credit sent in the face of US threats are acts of principled solidarity between sovereign states, and the attempt to stop them shows the siege was never about the Cuban people.','Treibstoff, Getreide und Kredite, die trotz US-Drohungen geschickt werden, sind Akte prinzipientreuer Solidarität zwischen souveränen Staaten; der Versuch, sie zu stoppen, zeigt, dass es bei der Belagerung nie um das kubanische Volk ging.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_external_lifelines',3,'Sovereign solidarity','Souveräne Solidarität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_credible_threat','A credible threat of force is what brought Havana to the table','Eine glaubwürdige Drohung mit Gewalt hat Havanna an den Tisch gebracht','Carrier deployments and reconnaissance flights are signalling, not war -- and the shift from refusal to negotiation followed them, as did Havana''s own escalatory plotting.','Trägerverlegungen und Aufklärungsflüge sind Signale, kein Krieg -- und der Wechsel von Verweigerung zu Verhandlung folgte auf sie, ebenso wie Havannas eigene Eskalationspläne.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],ARRAY['credible','glaubwürdig','all options','alle Optionen','military option','opción militar','deterren','Abschreckung','disuasión','brought to the table','teetering','provocation','Provokation','provocación','drone attack','plotting','threat to the US','amenaza para'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_military_coercion',1,'Credible deterrence','Glaubwürdige Abschreckung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_unlawful','Threatening to take an island is unlawful and reckless','Die Drohung, eine Insel zu nehmen, ist rechtswidrig und leichtsinnig','There is no congressional authorisation, no legal basis for seizing a sovereign state, and every historical precedent from the Bay of Pigs onward points to a costly failure.','Es gibt keine Ermächtigung des Kongresses, keine Rechtsgrundlage für die Inbesitznahme eines souveränen Staates, und jeder historische Präzedenzfall seit der Schweinebucht deutet auf ein teures Scheitern.',ARRAY['NON-STATE-EU','AMERICAS-USA','AMERICAS-CUBA'],ARRAY['unlawful','illegal','without authorisation','without authorization','war powers','no congressional','Bay of Pigs','quagmire','bloodbath','reckless','rechtswidrig','ohne Mandat','Kriegsvollmachten','Schweinebucht','leichtsinnig','Blutbad','ilegal','sin autorización','Bahía de Cochinos','baño de sangre','imprudente'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_military_coercion',2,'Unlawful and reckless','Rechtswidrig und leichtsinnig', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_imperial_aggression','Gunboat diplomacy against a small neighbour is imperial aggression','Kanonenbootpolitik gegen einen kleinen Nachbarn ist imperiale Aggression','Moving a carrier group into the Caribbean and openly discussing seizing an island revives the crudest form of hemispheric domination, whatever pretext is offered.','Eine Trägergruppe in die Karibik zu verlegen und offen über die Inbesitznahme einer Insel zu sprechen, belebt die roheste Form hemisphärischer Vorherrschaft -- unter welchem Vorwand auch immer.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_military_coercion',3,'Imperial aggression','Imperiale Aggression', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_repression_documented','One-party rule holds by arresting those who protest','Die Einparteienherrschaft hält sich, indem sie Protestierende verhaftet','Arrests after blackout protests, political prisoners used as bargaining chips and a party that permits no alternative describe control maintained by coercion, not consent.','Verhaftungen nach Protesten gegen Stromausfälle, politische Gefangene als Verhandlungsmasse und eine Partei, die keine Alternative zulässt, beschreiben Kontrolle durch Zwang, nicht durch Zustimmung.',ARRAY['AMERICAS-CUBA'],ARRAY['political prisoner','preso polític','presos polític','dissident','disidente','arrest','arrestan','detien','detenid','encarcel','jailed','crackdown','one-party','partido único','censorship','censur','repress','repres','bargaining chip','politische Gefangene','inhaftiert','verhaftet','Einparteien','Zensur','castrismo','dictad'],true,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_regime_survival',1,'Rule by repression','Herrschaft durch Repression',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_reform_under_siege','A real opening is under way but external pressure is throttling it','Eine echte Öffnung läuft, doch äußerer Druck erstickt sie','The largest economic liberalisation since 1959 and the release of thousands of prisoners are genuine movement -- and the pressure campaign gives hardliners the argument that opening invites attack.','Die größte wirtschaftliche Liberalisierung seit 1959 und die Freilassung Tausender Gefangener sind echte Bewegung -- und die Druckkampagne liefert Hardlinern das Argument, Öffnung lade Angriffe ein.',ARRAY['AMERICAS-CUBA'],ARRAY['reform','liberalis','liberaliz','opening','private sector','released','freed','pardon','largest package','genuine','Reform','Öffnung','Privatsektor','freigelassen','Begnadigung','reforma','apertura','excarcela','liberad','indulto','sector privado'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_regime_survival',2,'Reform throttled by pressure','Reform durch Druck erstickt', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_sovereign_resistance','A sovereign people is resisting an externally engineered regime change','Ein souveränes Volk widersteht einem von außen betriebenen Regimewechsel','What is called repression is a state defending itself against infiltration, sabotage and an openly declared campaign to remove its government -- self-determination is the issue, not dissent.','Was Repression genannt wird, ist ein Staat, der sich gegen Infiltration, Sabotage und eine offen erklärte Kampagne zum Sturz seiner Regierung verteidigt -- es geht um Selbstbestimmung, nicht um Dissens.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_regime_survival',3,'Sovereign resistance','Souveräner Widerstand', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_pressure_consensus','The government, not the blockade, is what has to change','Die Regierung, nicht die Blockade, muss sich ändern','A one-party leadership that jails its critics, has run its economy into the ground and refuses to give up power is the reason the island is in this position -- and the reason pressure keeps being applied.','Eine Einparteienführung, die ihre Kritiker einsperrt, die Wirtschaft ruiniert hat und die Macht nicht abgeben will, ist der Grund für die Lage der Insel -- und der Grund, warum weiter Druck ausgeübt wird.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],NULL,true,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily','UN News'],'cuba_theater',1,'The government is the problem','Die Regierung ist das Problem',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_western_critique','The pressure campaign has become a humanitarian and legal problem of its own','Die Druckkampagne ist selbst zu einem humanitären und rechtlichen Problem geworden','Extraterritorial sanctions on third countries, an island without electricity or medicine, and open talk of seizing a sovereign state have moved the campaign past what its own stated aims can justify.','Extraterritoriale Sanktionen gegen Drittstaaten, eine Insel ohne Strom und Medikamente und offenes Gerede über die Inbesitznahme eines souveränen Staates haben die Kampagne über das hinausgeführt, was ihre erklärten Ziele rechtfertigen.',ARRAY['NON-STATE-EU','AMERICAS-CUBA'],NULL,true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_theater',2,'Overreach and human cost','Übergriffigkeit und menschliche Kosten', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_anti_imperial','A siege to break a sovereign nation that refuses to submit','Eine Belagerung, um eine souveräne Nation zu brechen, die sich nicht unterwirft','Fuel cut off, warships offshore, a former head of state indicted and allies punished for sending aid -- this is coercion of a small country for refusing hemispheric obedience, and solidarity with it is a defence of sovereignty itself.','Abgeschnittener Treibstoff, Kriegsschiffe vor der Küste, ein angeklagter früherer Staatschef und für Hilfslieferungen bestrafte Verbündete -- das ist Nötigung eines kleinen Landes für verweigerten hemisphärischen Gehorsam, und Solidarität mit ihm verteidigt die Souveränität selbst.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_theater',3,'Siege and sovereignty','Belagerung und Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_as_development','Capital arriving at last','Kapital, das endlich ankommt','Demand for battery and data-centre metals is finally being converted into Congolese assets: a state mining champion under new leadership, a distressed cobalt producer rescued by an American buyer, exploration money flowing into lithium, copper exports to the United States multiplying, a reopened corridor to Zambian ports and a first domestic stock exchange. Export controls are treated here as a producer country learning to price what it owns.','Die Nachfrage nach Batterie- und Rechenzentrumsmetallen wird endlich in kongolesische Werte umgesetzt: ein staatlicher Bergbaukonzern unter neuer Führung, ein angeschlagener Kobaltproduzent durch einen amerikanischen Käufer gerettet, Explorationsgelder für Lithium, vervielfachte Kupferexporte in die USA, ein wieder geöffneter Korridor zu sambischen Häfen und eine erste eigene Börse. Exportkontrollen gelten hier als ein Förderland, das lernt, seinen Besitz zu bepreisen.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['deal','agreement','investment','invest','stake','boom','growth','exploration','approve','approved','takeover','acquisition','corridor','stock market','exports','reopen','investissement','croissance','exportations','Investition','Wachstum','Übernahme','Ausfuhren'],true,ARRAY['Mining.com','Bloomberg','Financial Times','S&P Global','OilPrice','News24','Reuters','The Australian','Egypt Today'],'drc_minerals_competition',1,'Investment and leverage','Investitionen und Verhandlungsmacht',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_human_cost','The price is paid at the pit','Bezahlt wird an der Grube','The same supply chain that supplies the energy transition also produces two hundred dead in a single coltan collapse, a town reporting bleeding children after a cobalt plant leak, and consumer brands that cannot demonstrate their metal did not finance an armed group. Buyers describe their own due diligence as failing: deposits offered to foreign investors sit inside contested territory, and the paperwork does not survive contact with the pit.','Dieselbe Lieferkette, die die Energiewende speist, produziert auch zweihundert Tote bei einem einzigen Coltan-Einsturz, eine Stadt mit blutenden Kindern nach einem Leck in einer Kobaltanlage und Markenhersteller, die nicht belegen können, dass ihr Metall keine bewaffnete Gruppe finanziert hat. Die Abnehmer bezeichnen ihre eigene Sorgfaltsprüfung als unzureichend: Vorkommen, die ausländischen Investoren angeboten werden, liegen in umkämpftem Gebiet, und die Papiere halten dem Vergleich mit der Grube nicht stand.',ARRAY['AFRICA-DRC'],ARRAY['toxic','sickened','poison','gas leak','waste','collapse','landslide','killed','dead','buried','child','children','artisanal','funds rebels','atrocities','war zone','de-risk','due diligence','human rights','exploitation','toxique','rejets','éboulement','glissement de terrain','morts','enfants','artisanale','droits humains','giftig','Einsturz','Erdrutsch','Tote','Kinderarbeit','Menschenrechte'],true,ARRAY['The Guardian','Wall Street Journal','Le Monde','France 24','France 24 (EN)','Deutsche Welle','Associated Press','BBC World','BBC','Al Jazeera','Folha de S.Paulo','Council on Foreign Relations','Globe and Mail','La Repubblica','Press TV','DR'],'drc_minerals_competition',2,'Human and environmental cost','Menschliche und ökologische Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_as_resource_capture','A takeover of an established position','Übernahme einer gewachsenen Position','Seen from the incumbent side, the American entry is not new investment but the displacement of partners who built the refining and processing base over two decades, achieved through political leverage rather than commercial performance. Deposits are being tied to security guarantees, state mining leadership replaced during negotiations, and a producer country pressed into an exclusive alignment while its own officials call the terms constitutionally doubtful.','Aus Sicht der etablierten Seite ist der amerikanische Einstieg keine neue Investition, sondern die Verdrängung von Partnern, die über zwei Jahrzehnte die Raffinerie- und Verarbeitungsbasis aufgebaut haben -- erreicht durch politischen Druck, nicht durch wirtschaftliche Leistung. Vorkommen werden an Sicherheitsgarantien geknüpft, die staatliche Bergbauführung während der Verhandlungen ausgetauscht und ein Förderland in eine exklusive Bindung gedrängt, während eigene Amtsträger die Bedingungen für verfassungsrechtlich zweifelhaft halten.',ARRAY['AFRICA-DRC','ASIA-CHINA'],ARRAY['grab','capture','seize','exclusive','displace','squeeze out','leverage','unconstitutional','flawed','sovereignty','neocolonial','neo-colonial','plunder','scramble','strings attached','inconstitutionnel','souveraineté','néocolonial','pillage','verfassungswidrig','Souveränität','neokolonial','Ausplünderung'],true,ARRAY['Daily Nation','Daily Maverick','CGTN','Global Times','China Daily','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti'],'drc_minerals_competition',3,'Displacement of incumbents','Verdrängung der Etablierten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_accords_are_working','The accords are the route out of the war','Die Abkommen sind der Weg aus dem Krieg','External mediation is producing things the battlefield never did: a signed monitoring mechanism, prisoners released, humanitarian access agreed within fixed deadlines, and a commitment from both sides to protect civilians. Kinshasa is explicitly betting on the Washington track to secure the east, and the monitoring mission is being rebuilt around supporting the ceasefire rather than fighting a war.','Die externe Vermittlung bringt hervor, was das Schlachtfeld nie erreicht hat: einen unterzeichneten Überwachungsmechanismus, freigelassene Gefangene, humanitären Zugang mit festen Fristen und die Zusage beider Seiten, Zivilisten zu schützen. Kinshasa setzt ausdrücklich auf den Washingtoner Weg, um den Osten zu sichern, und die Beobachtermission wird darauf ausgerichtet, den Waffenstillstand zu stützen statt Krieg zu führen.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['signed','commit','commitment','progress','monitoring','release','released','prisoners','facilitate','de-escalate','breakthrough','mechanism','secure','chance','advance','prepares to support','deploy','signé','engagement','progrès','libérer','libération','faciliter','désescalade','sécuriser','compte sur','unterzeichnet','Fortschritt','Freilassung','Deeskalation','Chance'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Reuters','Associated Press','Swissinfo','news.un.org','UN News','Al Jazeera','Anadolu Agency','Deutsche Welle','The Standard','Daily Nation','ANSA'],'drc_peace_process',1,'Mediation is delivering','Vermittlung zeigt Wirkung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_accords_stalling','Signed, stalled, and unenforced','Unterzeichnet, blockiert, nicht durchgesetzt','The documents exist and the fighting continues. Peace deals are described by Kinshasa''s own spokesman as blocked by the conduct of the Rwandan president; the two sides trade accusations over a ceasefire neither observes; attacks continue while talks sit in Switzerland. Sanctions arrive after violations rather than preventing them, which makes the accords a record of intentions rather than a constraint on behaviour.','Die Dokumente existieren, die Kämpfe gehen weiter. Friedensabkommen werden vom Sprecher Kinshasas selbst als blockiert durch das Verhalten des ruandischen Präsidenten beschrieben; beide Seiten werfen einander Verstöße gegen einen Waffenstillstand vor, den keine Seite einhält; Angriffe dauern an, während in der Schweiz verhandelt wird. Sanktionen folgen den Verstößen, statt sie zu verhindern -- die Abkommen sind damit eher ein Protokoll von Absichten als eine Schranke für das Handeln.',ARRAY['AFRICA-DRC'],ARRAY['stalled','stalling','stagnate','stagnant','no progress','violation','violating','violated','accuses','accusations','breach','collapse','fragile','delay','delayed','persists','stagnent','bloqué','s''enlise','n''avance pas','violation','accuse','accusations','retard','ins Stocken','blockiert','Verstoß','Verzögerung','wirft vor'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','Deutsche Welle','Washington Post','Financial Times','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','The Standard','Daily Nation','Janes'],'drc_peace_process',2,'The process is not holding','Der Prozess trägt nicht', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_mediation_as_interference','Peacemaking with a price tag','Friedensstiftung mit Preisschild','The mediation is read here as leverage rather than diplomacy: a settlement brokered by the same power that is negotiating access to Congolese deposits, with sanctions used as the instrument of pressure and African sovereignty as the cost. On this account the accords are less a peace framework than the political wrapper around a resource arrangement, and the states applying the pressure are parties to the outcome rather than neutral arbiters.','Die Vermittlung wird hier als Druckmittel gelesen, nicht als Diplomatie: eine Regelung, vermittelt von derselben Macht, die zugleich über den Zugang zu kongolesischen Vorkommen verhandelt, mit Sanktionen als Druckinstrument und afrikanischer Souveränität als Preis. In dieser Lesart sind die Abkommen weniger ein Friedensrahmen als die politische Verpackung einer Rohstoffvereinbarung, und die Druck ausübenden Staaten sind Partei, nicht neutrale Schiedsrichter.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['interference','meddling','neocolonial','neo-colonial','imperial','exploitation','resource grab','unilateral','pressure','hegemony','so-called','double standard','ingérence','néocolonial','impérial','pression','unilatéral','Einmischung','neokolonial','Druck','Doppelmoral'],false,ARRAY['RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','CGTN','Global Times','China Daily'],'drc_peace_process',3,'Pressure dressed as mediation','Druck im Gewand der Vermittlung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_sanctions_as_enforcement','Designations as the only real leverage','Listungen als einziges echtes Druckmittel','With no force willing to impose the accords on the ground, financial and travel designations have become the instrument that carries actual cost: the Rwandan army and its senior commanders listed, visa restrictions placed on Rwandan officials, and a former Congolese president designated over his support for the rebellion. Analysts read the move against Kigali as the sharpest turn in the conflict''s external handling to date.','Da keine Truppe bereit ist, die Abkommen vor Ort durchzusetzen, sind Finanz- und Reisebeschränkungen zum einzigen Instrument mit realen Kosten geworden: die ruandische Armee und ihre ranghohen Kommandeure gelistet, Visasperren gegen ruandische Amtsträger, und ein früherer kongolesischer Präsident wegen seiner Unterstützung der Rebellion benannt. Beobachter werten das Vorgehen gegen Kigali als die schärfste Wende im äußeren Umgang mit diesem Konflikt bislang.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['sanction','sanctions','sanctioned','designat','visa restriction','listed','penalt','asset freeze','sanctionne','sanctionné','sanctions','restrictions de visa','Sanktionen','sanktioniert','Einreiseverbot'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','Financial Times','Al Jazeera','Daily Nation','Punch Newspapers'],'drc_peace_process',3,'Enforcement by designation','Durchsetzung durch Listung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_sanctions_rejected','The designated parties reject the designations','Die Gelisteten weisen die Listungen zurück','Those named in the measures dispute both their basis and their effect. Kigali presents the designations as insults that will not alter Rwandan defence policy, and the former Congolese president describes his own listing as unjustified. On this reading the sanctions are an external actor taking sides in a regional dispute it does not fully understand, rather than a neutral enforcement of an agreement.','Die Benannten bestreiten sowohl die Grundlage als auch die Wirkung der Maßnahmen. Kigali stellt die Listungen als Beleidigungen dar, die an Ruandas Verteidigungspolitik nichts ändern, und der frühere kongolesische Präsident nennt seine eigene Listung ungerechtfertigt. In dieser Lesart ergreift ein externer Akteur Partei in einem regionalen Streit, den er nicht vollständig überblickt, statt ein Abkommen neutral durchzusetzen.',ARRAY['AFRICA-DRC'],ARRAY['denies','denied','denounces','denounced','rejects','rejected','unjustified','unfounded','hits back','insults','sovereignty','internal affairs','dément','rejette','dénonce','injustifié','souveraineté','weist zurück','bestreitet','ungerechtfertigt','Souveränität'],true,ARRAY['The Standard','Anadolu Agency','Al-Ahram','Mail & Guardian','News24','TRT World','Daily Sabah','RT','TASS','TASS (EN)','Sputnik'],'drc_peace_process',4,'The designations are rejected','Die Listungen werden zurückgewiesen', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_essequibo_venezuelan_claim','Essequibo is historically Venezuelan territory','Essequibo ist historisch venezolanisches Gebiet','The Guayana Esequiba is Venezuelan by historical right; the World Court has no jurisdiction and Guyana''s unilateral oil auctions in disputed waters are the real provocation.','Die Guayana Esequiba ist historisch venezolanisch; das Weltgericht ist nicht zuständig, und Guyanas einseitige Ölauktionen in umstrittenen Gewässern sind die eigentliche Provokation.',ARRAY['AMERICAS-VENEZUELA','EUROPE-RUSSIA','ASIA-CHINA'],NULL,true,ARRAY['El Mundo','El País','La Nación','O Estado de S. Paulo','Clarín','Straits Times','TASS (EN)','TASS','RT','CGTN','China Daily','Global Times','Press TV'],'essequibo_dispute',1,'Venezuelan sovereign claim','Venezolanischer Souveränitätsanspruch',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_essequibo_guyana_sovereignty','Venezuela''s claim is an oil-driven threat to Guyana','Venezuelas Anspruch ist eine öl-getriebene Bedrohung Guyanas','The border was settled long ago; Venezuela''s revived claim over Guyana''s Stabroek oil is coercion against a small neighbour, and the World Court''s jurisdiction must be upheld.','Die Grenze wurde vor langer Zeit festgelegt; Venezuelas wiederbelebter Anspruch auf Guyanas Stabroek-Öl ist Zwang gegen einen kleinen Nachbarn, und die Zuständigkeit des Weltgerichts muss gewahrt bleiben.',ARRAY['AMERICAS-USA','NON-STATE-EU','AMERICAS-CARIBBEAN'],NULL,true,ARRAY['Reuters','Associated Press','BBC World','CNN','The Guardian','France 24 (EN)','Bloomberg','Financial Times'],'essequibo_dispute',2,'Guyana sovereignty & rule of law','Guyanas Souveränität & Rechtsstaatlichkeit', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_partnership_normalisation','Tensions overstated, partnership continues','Überzeichnete Spannungen, fortgesetzte Partnerschaft','Reports of an imminent northern war are exaggerated and often denied by the parties themselves; flights and administration are being restored, and Ethiopia remains a functioning partner for investment, infrastructure and trade regardless of the diplomatic noise around it.','Berichte über einen unmittelbar bevorstehenden Krieg im Norden sind übertrieben und werden von den Beteiligten selbst dementiert. Flugverbindungen und Verwaltung werden wiederhergestellt, und Äthiopien bleibt ungeachtet des diplomatischen Lärms ein funktionierender Partner für Investitionen, Infrastruktur und Handel.',ARRAY['AFRICA-HORN','ASIA-CHINA'],ARRAY['denies','untrue','resume','restore','cooperation','investment','partnership','development','dementiert','Zusammenarbeit','Wiederaufnahme'],false,ARRAY['CGTN','China Daily','Global Times','RT','TASS (EN)','Xinhua','ANSA'],'ethiopia_regional_confrontation',1,'Tensions are overstated','Die Spannungen sind überzeichnet',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_renewed_war_alarm','A second northern war in the making','Ein zweiter Krieg im Norden bahnt sich an','The Pretoria settlement is unravelling: the Tigrayan party has restored its pre-war administration, drones are striking again, Eritrean troops are accused of crossing the border, and an election that excluded Tigray has removed the last political off-ramp.','Das Abkommen von Pretoria zerfällt: Die tigrayische Partei hat ihre Vorkriegsverwaltung wiederhergestellt, es fliegen wieder Drohnenangriffe, eritreischen Truppen wird ein Grenzübertritt vorgeworfen, und eine Wahl unter Ausschluss Tigrays hat den letzten politischen Ausweg beseitigt.',ARRAY['AFRICA-HORN'],ARRAY['brink','war','fears','renewed','clashes','drone','atrocities','massacre','accountability','excluded','withdrawal','incursion','Krieg','Eskalation','Gräueltaten','Rechenschaft'],true,ARRAY['Reuters','BBC World','BBC','AFP','AFP Fact Check','Deutsche Welle','France 24','France 24 (EN)','The Economist','Associated Press','The Guardian','Le Monde','Atlantic Council','Daily Nation','News24','UN News','Bloomberg','CNN','Al Jazeera','Anadolu Agency','TRT World','Japan Times','Straits Times','The Standard'],'ethiopia_regional_confrontation',2,'Alarm at a returning war','Alarm vor einem wiederkehrenden Krieg', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_regional_revisionism','A revisionist power destabilising the region','Eine revisionistische Macht destabilisiert die Region','Addis Ababa''s pursuit of a seaport and its unilateral control of the Nile dam are expansionist demands on its neighbours'' sovereignty, and the deepening Egyptian partnerships with Eritrea, Djibouti and Somalia are a legitimate defensive response to them.','Addis Abebas Streben nach einem Seehafen und seine einseitige Kontrolle über den Nilstaudamm sind expansionistische Ansprüche gegenüber der Souveränität seiner Nachbarn. Die vertieften ägyptischen Partnerschaften mit Eritrea, Dschibuti und Somalia sind eine legitime Antwort darauf.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT'],ARRAY['expansionist','sovereignty','water','dam','GERD','Nile','isolate','parallel entities','littoral','Souveränität','Nil','Staudamm','expansionistisch'],true,ARRAY['Al-Ahram','Egypt Today','The National'],'ethiopia_regional_confrontation',3,'Ethiopia is the destabiliser','Äthiopien ist der Destabilisator', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('budget_more_europe','A capable Union needs stronger common financing','Eine handlungsfähige Union braucht eine stärkere gemeinsame Finanzierung','Integration framing (the Commission and pro-integration mainstream) holds that new own resources and a larger budget are needed for competitiveness, defence and shared priorities, that rule-of-law conditionality is legitimate, and that reform of cohesion and agricultural spending should serve common European goals. Vocabulary: own resources, common, invest, competitiveness, ambitious, more Europe.','Die Integrations-Rahmung (Kommission und integrationsfreundlicher Mainstream) sieht neue Eigenmittel und einen größeren Haushalt als notwendig für Wettbewerbsfähigkeit, Verteidigung und gemeinsame Prioritäten, die Rechtsstaats-Konditionalität als legitim und die Reform der Kohäsions- und Agrarausgaben als Dienst an gemeinsamen europäischen Zielen.',ARRAY['NON-STATE-EU'],ARRAY['own resources','Eigenmittel','larger budget','bigger budget','more ambitious','ambitious budget','backs larger','defend the budget','safeguards','biodiversity','green spending','new own resources','joint borrowing','Eurobond','common debt','gemeinsame Schulden','größeren Haushalt','competitiveness','invest','defence fund'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'eu_budget_sovereignty',1,'Stronger common financing','Stärkere gemeinsame Finanzierung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('budget_national_sovereignty','Brussels wants more money and power at the expense of nations and taxpayers','Brüssel will mehr Geld und Macht auf Kosten der Nationen und Steuerzahler','Sovereignty framing (net-contributor governments, centre-right and sovereigntist voices, farm and business lobbies) holds that the proposed budget is unaffordable, that new EU taxes and own resources are a power grab into national competences and taxpayers'' money, and that Green Deal and agricultural rules are overreach to be resisted. Vocabulary: net contributor, unaffordable, taxpayer, cut, overreach, red tape, reject.','Die Souveränitäts-Rahmung (Nettozahler-Regierungen, Mitte-rechts- und souveränistische Stimmen, Agrar- und Wirtschaftsverbände) sieht den vorgeschlagenen Haushalt als unbezahlbar, neue EU-Steuern und Eigenmittel als Griff nach nationalen Zuständigkeiten und Steuergeldern und Green-Deal- und Agrarregeln als abzuwehrende Übergriffe.',ARRAY['EUROPE-GERMANY','EUROPE-SOUTH','EUROPE-VISEGRAD'],ARRAY['net contributor','Nettozahler','too high','unaffordable','unbezahlbar','taxpayer','Steuerzahler','cut','Kürzung','overreach','power grab','red tape','Bürokratie','reject','ablehnen','burden','rebate','sovereignty','no-go','frugal'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate','Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal'],'eu_budget_sovereignty',2,'National sovereignty and taxpayers','Nationale Souveränität und Steuerzahler', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('budget_eu_decline_kremlin','The EU is fiscally overstretched and in decline','Die EU ist finanziell überfordert und im Niedergang','Rift-exploitation framing (Russian state press) presents the budget disputes as proof that the EU is broke, overstretched by rearmament and Ukraine, and fracturing between paymasters and dependants, amplifying the division rather than taking a side. Vocabulary: broke, insolvent, overstretched, decline, disunity, paymaster.','Die Riss-Ausnutzungs-Rahmung (russische Staatspresse) deutet die Haushaltsstreitigkeiten als Beleg, dass die EU pleite, durch Aufrüstung und Ukraine überfordert und zwischen Zahlmeistern und Empfängern zerrissen sei, und verstärkt die Spaltung, ohne Partei zu ergreifen.',ARRAY['EUROPE-RUSSIA'],ARRAY['broke','insolvent','overstretched','decline','disunity','paymaster','collapse','bankrupt','crisis'],false,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian'],'eu_budget_sovereignty',3,'Russian rift-exploitation','Russische Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eu_cohesion_hold','European cohesion and the rule of law must hold against centrifugal forces','Europäischer Zusammenhalt und Rechtsstaatlichkeit müssen den Fliehkräften standhalten','Pro-cohesion framing (Western mainstream and pro-integration press) treats the Union''s shared rules as worth defending: rule-of-law conditionality and anti-corruption standards, a democratic order guarded against the radical right, solidarity on migration and budget, and a firewall against normalising forces hostile to the European project. It reads the disputes as tests the Union must pass to hold together. Vocabulary: rule of law, solidarity, firewall, democracy, standards.','Die Zusammenhalts-Rahmung (westlicher Mainstream und integrationsfreundliche Presse) sieht die gemeinsamen Regeln der Union als verteidigenswert: Rechtsstaats-Konditionalität und Antikorruptionsstandards, eine gegen die radikale Rechte geschützte demokratische Ordnung, Solidarität bei Migration und Haushalt und eine Brandmauer gegen die Normalisierung projektfeindlicher Kräfte. Sie deutet die Konflikte als Prüfungen, die die Union bestehen muss.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD'],ARRAY['rule of law','Rechtsstaatlichkeit','solidarity','Solidarität','firewall','Brandmauer','democracy','Demokratie','far-right','rechtsextrem','standards','cohesion','Zusammenhalt'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'eu_cohesion_theater',1,'European cohesion must hold','Europäischer Zusammenhalt muss halten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eu_sovereigntist_revolt','Nations and voters are resisting an overreaching Brussels','Nationen und Wähler wehren sich gegen ein übergriffiges Brüssel','Sovereigntist framing (national-conservative governments and sympathetic voices across member states) holds that Brussels overreaches into national competences, budgets and identity, that mainstream parties wrongly exclude movements millions vote for, and that member states should reclaim control over migration, money and the rule of their own institutions. It runs from within the Union, not against its existence. Vocabulary: sovereignty, overreach, net contributor, will of voters, national control.','Die souveränistische Rahmung (nationalkonservative Regierungen und wohlwollende Stimmen in den Mitgliedstaaten) sieht Brüssel als übergriffig gegenüber nationalen Zuständigkeiten, Haushalten und Identität, den Ausschluss von Bewegungen, die Millionen wählen, als falsch und fordert, dass die Mitgliedstaaten die Kontrolle über Migration, Geld und ihre Institutionen zurückgewinnen. Sie wirkt aus der Union heraus, nicht gegen deren Bestand.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-SOUTH','EUROPE-VISEGRAD'],ARRAY['sovereignty','Souveränität','overreach','Bevormundung','net contributor','Nettozahler','will of the people','Millionen Wähler','national control','unaffordable','establishment','crackdown','Grenzen schützen'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate','Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal','CNews','Europe 1','Le Journal du Dimanche'],'eu_cohesion_theater',2,'National sovereignty and control','Nationale Souveränität und Kontrolle', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eu_fracture_rift_exploitation','Brussels overreach vindicates a Europe of sovereign nations','Brüsseler Übergriffigkeit bestätigt ein Europa souveräner Nationen','Counter-framing (Russian and Chinese state media) reads every internal European dispute as evidence that Brussels coerces its members and that a Europe of sovereign nations dealing bilaterally would serve them better. Moscow and Beijing prefer direct relations with national capitals over the EU''s supranational authority, so they amplify the sovereigntist case and every sign of division — adversarial to Brussels and to European cohesion as a whole, not a genuine party in the internal disputes they magnify. Vocabulary: coercion, sovereignty, decline, hypocrisy, division.','Die Gegen-Rahmung (russische und chinesische Staatsmedien) liest jeden inneren europäischen Streit als Beleg, dass Brüssel seine Mitglieder zwingt und dass ein Europa souveräner, bilateral handelnder Nationen ihnen besser diente. Moskau und Peking bevorzugen direkte Beziehungen zu den nationalen Hauptstädten gegenüber der supranationalen Autorität der EU und verstärken daher die souveränistische Sichtweise und jedes Zeichen der Spaltung — gegnerisch zu Brüssel und zur europäischen Kohäsion insgesamt, keine echte Partei in den vergrößerten Konflikten.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['coercion','decline','hypocrisy','chaos','collapse','crisis','disunity','persecution','failing'],true,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian','CGTN','China Daily','Global Times','Xinhua'],'eu_cohesion_theater',3,'Russian & Chinese counter-framing','Russische & chinesische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('migration_solidarity_rights','Migration requires European solidarity and respect for rights and law','Migration erfordert europäische Solidarität und die Achtung von Rechten und Recht','Solidarity-and-rights framing (Western mainstream and pro-integration voices) holds that asylum is a legal obligation, that the Pact''s burden-sharing must be honoured, that detention and pushbacks that courts find unlawful are unacceptable, and that regularisation and integration are legitimate answers. Vocabulary: solidarity, human rights, asylum right, unlawful, integration, shared responsibility.','Die Solidaritäts- und Rechte-Rahmung (westlicher Mainstream und integrationsfreundliche Stimmen) sieht Asyl als rechtliche Pflicht, die Lastenteilung des Pakts als einzuhaltende Verpflichtung, gerichtlich für rechtswidrig erklärte Inhaftierung und Zurückweisung als inakzeptabel und Regularisierung und Integration als legitime Antworten.',ARRAY['NON-STATE-EU'],ARRAY['solidarity','Solidarität','solidarité','human rights','Menschenrechte','asylum right','Asylrecht','unlawful','illegal ruling','ruled illegal','rechtswidrig','integration','shared responsibility','humanitarian','welcome','court','protect refugees'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'eu_migration_burden_sharing',1,'Solidarity and rights','Solidarität und Rechte',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('migration_national_control','Member states must control borders and curb irregular migration','Mitgliedstaaten müssen Grenzen kontrollieren und irreguläre Migration eindämmen','Control framing (national governments and centre-right and sovereigntist voices) holds that irregular migration must be curbed through tougher borders, faster returns, offshore processing and restriction, that generous regularisation sets the wrong incentives, and that member states, not Brussels, should decide. Vocabulary: control, crackdown, returns, irregular, offshore, restrict, pull factor.','Die Kontroll-Rahmung (nationale Regierungen sowie Mitte-rechts- und souveränistische Stimmen) sieht irreguläre Migration durch härtere Grenzen, schnellere Rückführungen, ausgelagerte Verfahren und Restriktion einzudämmen, großzügige Regularisierung als falschen Anreiz und die Entscheidung bei den Mitgliedstaaten, nicht bei Brüssel.',ARRAY['EUROPE-SOUTH','EUROPE-GERMANY','NON-STATE-EU'],ARRAY['control','Kontrolle','crackdown','tougher','deport','Abschiebung','irregular','illegal migration','offshore','remigration','pull factor','restrict','clampdown','overwhelmed','Grenzen schützen','secure border','return hub','tougher asylum'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate','Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal'],'eu_migration_burden_sharing',2,'National border control','Nationale Grenzkontrolle', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('migration_eu_failure_kremlin','EU migration policy is chaos and a failure of the European project','Die EU-Migrationspolitik ist Chaos und ein Scheitern des europäischen Projekts','Counter-framing (Russian state press) presents EU migration as chaos, division and the failure of a hypocritical Europe — often measured against Russia''s own large migrant and refugee inflows and integration strains — amplifying the disputes between member states as evidence of decline rather than taking a side on asylum policy. Vocabulary: chaos, crisis, failure, hypocrisy, collapse.','Die Gegen-Rahmung (russische Staatspresse) stellt die EU-Migration als Chaos, Spaltung und Scheitern eines heuchlerischen Europas dar — oft gemessen an Russlands eigenen großen Migranten- und Flüchtlingszuströmen und Integrationsproblemen — und verstärkt die Streitigkeiten zwischen den Mitgliedstaaten als Zeichen des Niedergangs, ohne in der Asylpolitik Partei zu ergreifen.',ARRAY['EUROPE-RUSSIA'],ARRAY['chaos','crisis','invasion','failure','hypocrisy','collapse','uncontrolled','flood','decline'],true,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian'],'eu_migration_burden_sharing',3,'Russian counter-framing','Russische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('realignment_firewall_defense','The mainstream must not normalise the radical right','Der Mainstream darf die radikale Rechte nicht normalisieren','Firewall-defense framing (centre-left, greens and pro-cordon voices) holds that mainstream parties, above all the EPP, must not legitimise or govern with national-conservative and radical-right forces, that the cordon sanitaire protects liberal democracy, and that its erosion is dangerous. Vocabulary: firewall, cordon sanitaire, normalisation, far-right, taboo, must not, legitimise.','Die Brandmauer-Verteidigungs-Rahmung (Mitte-links, Grüne und Befürworter des Cordon sanitaire) sieht, dass Mainstream-Parteien, allen voran die EVP, nationalkonservative und rechtsradikale Kräfte nicht legitimieren oder mit ihnen regieren dürfen, dass der Cordon sanitaire die liberale Demokratie schützt und seine Aufweichung gefährlich ist.',ARRAY['NON-STATE-EU','EUROPE-GERMANY'],ARRAY['firewall','Brandmauer','cordon sanitaire','normalis','normalisierung','far-right','rechtsextrem','taboo','Tabu','must not','legitimis','legitimieren','dangerous','erosion','pact with','shift right','Dammbruch'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'eu_right_realignment',1,'Defence of the cordon sanitaire','Verteidigung des Cordon sanitaire',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('realignment_new_majority','The right has a democratic mandate to govern and to cooperate','Die Rechte hat ein demokratisches Mandat zu regieren und zusammenzuarbeiten','Realignment framing (centre-right and national-conservative voices) holds that parties representing a large share of voters have a democratic mandate, that cooperation across the old cordon is legitimate and overdue, and that a new centre-right-to-national-conservative majority is a normal democratic outcome. Vocabulary: mandate, majority, legitimate, voters, normalise cooperation, new majority, represent.','Die Neuordnungs-Rahmung (Mitte-rechts- und nationalkonservative Stimmen) sieht Parteien, die einen großen Wähleranteil vertreten, mit einem demokratischen Mandat, die Zusammenarbeit über den alten Cordon hinweg als legitim und überfällig und eine neue Mehrheit von der Mitte-rechten bis zur nationalkonservativen Seite als normales demokratisches Ergebnis.',ARRAY['NON-STATE-EU','EUROPE-SOUTH'],ARRAY['democratic mandate','mandate to govern','legitimate majority','listen to voters','represent the voters','new majority','overdue','normal coalition partner'],true,ARRAY['Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal'],'eu_right_realignment',2,'A new democratic majority','Eine neue demokratische Mehrheit', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('realignment_center_decline_kremlin','Europe''s liberal centre is collapsing','Europas liberale Mitte bricht zusammen','Counter-framing (Russian and Chinese state media) presents the realignment as the collapse of a discredited European liberal centre and the vindication of forces opposed to Brussels and to Ukraine support. Moscow and Beijing favour a Europe of sovereign nations dealing bilaterally over Brussels'' supranational authority, so they amplify the shift as Western decline rather than endorsing a specific party. Vocabulary: collapse, decline, discredited, liberal elite.','Die Gegen-Rahmung (russische und chinesische Staatsmedien) deutet die Neuordnung als Zusammenbruch einer diskreditierten europäischen liberalen Mitte und als Bestätigung der Kräfte gegen Brüssel und gegen die Ukraine-Unterstützung. Moskau und Peking bevorzugen ein Europa souveräner, bilateral handelnder Nationen gegenüber der supranationalen Autorität Brüssels und verstärken daher den Wandel als westlichen Niedergang, ohne eine bestimmte Partei zu unterstützen.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['collapse','decline','discredited','liberal elite','sweeping','end of an era','crumbling','rejected','establishment fails'],false,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian','CGTN','China Daily','Global Times','Xinhua'],'eu_right_realignment',3,'Russian & Chinese counter-framing','Russische & chinesische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_europe_must_pay','Europe has freeloaded on US protection for decades and must finally pay its share','Europa hat sich jahrzehntelang auf US-Schutz verlassen und muss endlich seinen Anteil zahlen','America-First framing (US conservative press) holds that European allies have underspent on defence for decades while sheltering under the US umbrella, and that Washington is right to demand they hit higher NATO spending targets or forfeit American protection. Troop drawdowns and blunt pressure are framed as overdue accountability. Vocabulary: freeload, fair share, pay up, 5 percent, deadbeat, burden, or else.','Die America-First-Rahmung (US-konservative Presse) sieht in den europäischen Verbündeten jahrzehntelange Trittbrettfahrer unter dem US-Schirm und hält es für richtig, dass Washington höhere NATO-Ausgabenziele fordert -- oder den amerikanischen Schutz entzieht. Truppenabzüge und harter Druck gelten als überfällige Rechenschaft.',ARRAY['AMERICAS-USA'],ARRAY['freeload','fair share','pay up','5 percent','deadbeat','burden','or else','delinquent','pull out','Trittbrettfahrer','fairer Anteil'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_defence_dependence',1,'Europe must pay its share','Europa muss seinen Anteil zahlen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_unreliable_america','A wavering America is an unreliable protector, forcing an alarmed Europe to scramble','Ein schwankendes Amerika ist ein unzuverlässiger Beschützer und zwingt ein alarmiertes Europa zum Handeln','Western mainstream framing treats the fraying US security guarantee -- troop drawdowns, doubts over Article 5, transactional pressure -- as a strategic shock that leaves Europe dangerously exposed. Allies scramble to reassure Washington and raise spending to keep it engaged, while asking whether America will still come to their defence. Vocabulary: unreliable, abandon, exposed, reassure, Article 5, credibility, nervous, scramble.','Der westliche Mainstream deutet die bröckelnde US-Sicherheitsgarantie -- Truppenabzüge, Zweifel an Artikel 5, transaktionalen Druck -- als strategischen Schock, der Europa gefährlich entblößt. Die Verbündeten bemühen sich, Washington zu beschwichtigen und die Ausgaben zu erhöhen, und fragen zugleich, ob Amerika noch zu ihrer Verteidigung käme.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['unreliable','abandon','exposed','reassure','Article 5','credibility','nervous','scramble','guarantee','umbrella','unzuverlässig','Abzug','Artikel 5'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini'],'europe_us_defence_dependence',2,'America the unreliable protector','Amerika als unzuverlässiger Beschützer', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_nato_racket','NATO is a crumbling Cold-War racket through which the US bleeds Europe','Die NATO ist ein zerfallendes Relikt des Kalten Krieges, mit dem die USA Europa ausbluten','Rift-exploitation framing (Russian and Chinese state media) casts the burden-sharing rows as proof that NATO is an obsolete Cold-War racket: Washington extracts money and arms sales from dependent Europeans while the alliance''s internal quarrels reveal its decay. Adversarial to the alliance as a whole, amplified with schadenfreude, not support for either party. Vocabulary: racket, obsolete, Cold War relic, extort, arms sales, decay, disunity, crumbling.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) stellt die Lastenstreitigkeiten als Beweis dar, dass die NATO ein überholtes Relikt des Kalten Krieges sei: Washington presse Geld und Waffenkäufe aus abhängigen Europäern heraus, während die internen Querelen den Verfall des Bündnisses offenbarten.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['racket','obsolete','Cold War relic','extort','arms sales','decay','disunity','crumbling','vassal','proxy','Relikt','ausbluten','überholt'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_defence_dependence',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_eu_overreach','EU tech rules are protectionist harassment of successful American companies','Die EU-Techregeln sind protektionistische Schikane erfolgreicher amerikanischer Unternehmen','America-First framing (US conservative press) casts the DMA, DSA and antitrust fines as protectionist, anti-innovation harassment designed to shake down US technology champions and censor American speech, justifying tariff retaliation to defend them. Vocabulary: shakedown, protectionist, harassment, censorship, anti-innovation, discriminatory, retaliate, defend our companies.','Die America-First-Rahmung (US-konservative Presse) deutet DMA, DSA und Kartellstrafen als protektionistische, innovationsfeindliche Schikane, die US-Techkonzerne abkassieren und amerikanische Meinungsäußerung zensieren solle -- und rechtfertigt Zoll-Vergeltung zu ihrer Verteidigung.',ARRAY['AMERICAS-USA'],ARRAY['shakedown','protectionist','harassment','censorship','anti-innovation','discriminatory','retaliate','defend our','targeting American','Schikane','Zensur','abkassieren'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_tech_sovereignty',1,'EU regulatory overreach','EU-Regulierungsübergriff',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_digital_sovereignty','Europe must rein in US Big Tech and reclaim its digital sovereignty','Europa muss die US-Techkonzerne bändigen und seine digitale Souveränität zurückgewinnen','Western and European mainstream framing treats EU enforcement against US Big Tech -- DMA/DSA fines, antitrust probes, content and privacy rules -- as legitimate rule-of-law that Europe must uphold, and pairs it with a drive for digital sovereignty: sovereign cloud, Gaia-X and weaning public and defence systems off American providers. Vocabulary: digital sovereignty, rein in, enforce, rule of law, sovereign cloud, dependence, gatekeeper, level playing field.','Der westliche und europäische Mainstream sieht in der EU-Durchsetzung gegen die US-Techkonzerne -- DMA/DSA-Strafen, Kartellverfahren, Inhalts- und Datenschutzregeln -- legitime Rechtsstaatlichkeit, die Europa wahren müsse, und verbindet sie mit dem Streben nach digitaler Souveränität: souveräne Cloud, Gaia-X und die Loslösung öffentlicher und militärischer Systeme von amerikanischen Anbietern.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['digital sovereignty','rein in','enforce','rule of law','sovereign cloud','dependence','gatekeeper','level playing field','regulate','Big Tech','digitale Souveränität','Kartell'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','Ars Technica','TechCrunch'],'europe_us_tech_sovereignty',2,'European digital sovereignty','Europäische digitale Souveränität', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_digital_colonialism','US tech dominance is a digital colonialism Europe is only now waking up to','Die US-Techdominanz ist ein digitaler Kolonialismus, aus dem Europa erst jetzt erwacht','Rift-exploitation framing (Russian and Chinese state media) casts American technological dominance over Europe as digital colonialism and mass surveillance, presenting the EU-US tech clash as belated European recognition of its subjugation to Silicon Valley -- while stressing Washington''s hypocrisy on "free" markets. Adversarial to US tech hegemony, not an endorsement of EU regulation as such. Vocabulary: digital colonialism, surveillance, hegemony, subjugation, hypocrisy, control, dependence, monopoly.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) deutet die amerikanische Technologiedominanz über Europa als digitalen Kolonialismus und Massenüberwachung und stellt den EU-US-Techkonflikt als verspätetes europäisches Erkennen seiner Unterwerfung unter das Silicon Valley dar -- unter Betonung der Heuchelei Washingtons in Sachen „freier" Märkte.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['digital colonialism','surveillance','hegemony','subjugation','hypocrisy','control','dependence','monopoly','Silicon Valley','Kolonialismus','Überwachung','Hegemonie'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_tech_sovereignty',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_america_first','America First: a freeloading, over-regulating Europe must pay, open up and submit','America First: Ein trittbrettfahrendes, überregulierendes Europa muss zahlen, sich öffnen und fügen','America-First framing (US conservative press) runs across the whole theater: Europe has exploited US trade openness, freeloaded on US defence, and harasses American tech champions -- so tariffs, blunt burden-sharing pressure and retaliation over EU tech rules are justified tools to force fair terms and put America first. Europe is a partner to be disciplined, not indulged. Vocabulary: freeload, fair share, unfair, shakedown, America First, pay up, reciprocal.','Die America-First-Rahmung (US-konservative Presse) durchzieht das gesamte Theater: Europa habe die US-Handelsoffenheit ausgenutzt, sich beim US-Schutz als Trittbrettfahrer verhalten und schikaniere amerikanische Techkonzerne -- daher seien Zölle, harter Lastenteilungsdruck und Vergeltung gegen EU-Techregeln berechtigte Mittel, um faire Bedingungen zu erzwingen und Amerika an die erste Stelle zu setzen.',ARRAY['AMERICAS-USA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','extended deterrence','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','fair share','freeload','unfair','America First','rip off','reciprocal','pay up','delinquent','level playing field'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_theater',1,'America First','America First',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_transatlantic_rupture','A vital alliance is rupturing, forcing an alarmed Europe to defend itself and its interests','Ein lebenswichtiges Bündnis zerbricht und zwingt ein alarmiertes Europa, sich und seine Interessen zu verteidigen','Western and European mainstream framing treats the Trump-era pressure -- tariffs, burden-sharing threats, wavering security guarantees, tech confrontation -- as the rupture of a decades-old partnership that leaves Europe exposed and coerced. The response it champions is unity, countermeasures, strategic autonomy and digital sovereignty: an alarmed continent forced to decide and defend for itself. Vocabulary: rupture, coercion, unreliable, autonomy, sovereignty, unity, defend, wake-up call.','Der westliche und europäische Mainstream deutet den Druck der Trump-Ära -- Zölle, Lastenteilungsdrohungen, schwankende Sicherheitsgarantien, Techkonfrontation -- als Bruch einer jahrzehntealten Partnerschaft, der Europa entblößt und unter Zwang setzt. Die befürwortete Antwort ist Einigkeit, Gegenmaßnahmen, strategische Autonomie und digitale Souveränität.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','extended deterrence','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','countermeasure','unity','autonomy','reassure','unreliable'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini','Ars Technica','TechCrunch'],'europe_us_theater',2,'Transatlantic rupture & European response','Transatlantischer Bruch & europäische Antwort', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_western_disunity','The transatlantic split exposes Western hypocrisy and the arrival of a multipolar world','Der transatlantische Bruch entlarvt westliche Heuchelei und den Anbruch einer multipolaren Welt','Rift-exploitation framing (Russian and Chinese state media) reads every transatlantic quarrel -- tariffs, burden rows, the "EU army", tech fights -- not as taking sides but as proof that the US treats Europe as milkable vassals, that Western unity and values are hypocrisy, and that American hegemony is giving way to a multipolar order. Adversarial to the West as a bloc, amplified with schadenfreude. Vocabulary: vassal, hypocrisy, multipolar, end of hegemony, disunity, decline of the West, humiliation.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) liest jeden transatlantischen Streit -- Zölle, Lastenstreitigkeiten, „EU-Armee", Techkonflikte -- nicht als Parteinahme, sondern als Beweis, dass die USA Europa als auszunehmende Vasallen behandeln, westliche Einigkeit und Werte Heuchelei seien und die amerikanische Hegemonie einer multipolaren Ordnung weiche.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','vassal','hypocrisy','multipolar','humiliation','submission','end of hegemony'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_theater',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_illusion','European strategic autonomy is a costly fantasy that only weakens NATO','Europäische strategische Autonomie ist eine teure Fantasie, die nur die NATO schwächt','Skeptical framing (US conservative and Atlanticist-hawk press) mocks "strategic autonomy" and the "EU army" as a bureaucratic fantasy: Europe cannot defend itself, duplicates NATO, and should simply spend more inside the alliance rather than build rival structures that divide the West. Vocabulary: fantasy, pipe dream, duplication, cannot defend, paper army, undermine NATO, talk not troops.','Die skeptische Rahmung (US-konservative und atlantisch-restriktive Presse) verspottet „strategische Autonomie" und die „EU-Armee" als bürokratische Fantasie: Europa könne sich nicht selbst verteidigen, dupliziere die NATO und solle lieber innerhalb des Bündnisses mehr ausgeben, statt rivalisierende Strukturen aufzubauen, die den Westen spalten.',ARRAY['AMERICAS-USA'],ARRAY['fantasy','pipe dream','duplication','cannot defend','paper army','undermine NATO','illusion','talk not troops','Fantasie','Illusion','Papierarmee'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'eu_strategic_autonomy',1,'Autonomy is an illusion','Autonomie ist eine Illusion',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_european_awakening','Europe is finally awakening to strategic autonomy and must build its own defence','Europa erwacht endlich zur strategischen Autonomie und muss seine eigene Verteidigung aufbauen','Western mainstream framing treats the US retreat as the catalyst for a historic European awakening: the continent must build genuine strategic autonomy -- a defence union, industrial base, even a European deterrent -- through initiatives like ReArm Europe, to decide and defend for itself and de-risk from dependence on Washington. Broadly sympathetic to the project while debating its feasibility. Vocabulary: awakening, strategic autonomy, defence union, ReArm, sovereignty, self-reliance, wake-up call, emancipate.','Der westliche Mainstream deutet den US-Rückzug als Katalysator für ein historisches europäisches Erwachen: Der Kontinent müsse echte strategische Autonomie aufbauen -- eine Verteidigungsunion, eine industrielle Basis, sogar eine europäische Abschreckung -- über Initiativen wie ReArm Europe, um selbst zu entscheiden und sich zu verteidigen.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['awakening','strategic autonomy','defence union','ReArm','sovereignty','self-reliance','wake-up call','emancipate','rearm','deterrent','Erwachen','Autonomie','Verteidigungsunion'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini'],'eu_strategic_autonomy',2,'European strategic awakening','Europäisches strategisches Erwachen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_multipolar_welcome','European autonomy means the end of US hegemony and a welcome multipolar world','Europäische Autonomie bedeutet das Ende der US-Hegemonie und eine willkommene multipolare Welt','Rift-exploitation framing (Russian and Chinese state media) welcomes European "strategic autonomy" not out of solidarity but as the fracturing of the US-led bloc: proof that American hegemony is ending, that Europe should break free of its Atlantic vassalage, and that a multipolar order is arriving. It cheers the transatlantic split while doubting Europe will dare follow through. Vocabulary: multipolar, end of hegemony, vassalage, break free, Atlanticism dead, sovereignty, emancipation.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) begrüßt die europäische „strategische Autonomie" nicht aus Solidarität, sondern als Zerfall des US-geführten Blocks: als Beweis, dass die amerikanische Hegemonie ende, Europa sich aus atlantischer Vasallität lösen solle und eine multipolare Ordnung heraufziehe.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['multipolar','end of hegemony','vassalage','break free','Atlanticism','emancipation','sovereignty','declining America','Hegemonie','multipolar','Vasallität'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'eu_strategic_autonomy',3,'Multipolar rift-exploitation','Multipolare Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('france_republican_defense','The rule of law and republican norms must apply to the RN','Rechtsstaat und republikanische Normen müssen auch für das RN gelten','Republican-defense framing (French and Western mainstream) treats the Rassemblement National as a challenge to republican norms and the embezzlement case and any resulting ineligibility as the ordinary application of the law, and views the governing instability as the price of the party''s rise. Vocabulary: far-right, rule of law, embezzlement, convicted, republican, ineligibility.','Die republikanische Verteidigungs-Rahmung (französischer und westlicher Mainstream) sieht das Rassemblement National als Herausforderung republikanischer Normen und den Veruntreuungsprozess sowie eine mögliche Unwählbarkeit als normale Anwendung des Rechts und deutet die Regierungsinstabilität als Preis des Aufstiegs der Partei.',ARRAY['EUROPE-FRANCE'],ARRAY['far-right','extrême droite','estrema destra','rechtsextrem','rule of law','état de droit','embezzlement','détournement','convicted','condamn','ineligibility','inéligibilité','republican','républicain','threat','justice','trial'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'french_nationalist_challenge',1,'Republican norms and rule of law','Republikanische Normen und Rechtsstaat',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('france_popular_will','The establishment and the courts are blocking the popular will','Establishment und Justiz blockieren den Volkswillen','Popular-will framing (voiced by the party and sympathetic commentary) holds that the judicial cases against Marine Le Pen and the marginalisation of the movement are an establishment and judicial effort to deny voters the leader they prefer ahead of 2027. Vocabulary: will of the people, establishment, witch hunt, judicial coup, denial of democracy.','Die Volkswillen-Rahmung (von der Partei und wohlwollenden Kommentaren vertreten) sieht in den Gerichtsverfahren gegen Marine Le Pen und der Marginalisierung der Bewegung den Versuch von Establishment und Justiz, den Wählern die bevorzugte Anführerin vor 2027 zu verwehren.',ARRAY['EUROPE-FRANCE'],ARRAY['will of the people','volonté populaire','popular will','establishment','witch hunt','acharnement','judicial coup','déni de démocratie','anti-democratic','muzzle','museler','disqualify','ban Le Pen','barred','deny voters','front-runner','favourite','persecution','exclu'],true,ARRAY['Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal','CNews','Europe 1','Le Journal du Dimanche'],'french_nationalist_challenge',2,'Popular will vs the establishment','Volkswille gegen das Establishment', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('france_decline_kremlin','France''s model is failing amid chaos and instability','Frankreichs Modell scheitert in Chaos und Instabilität','Counter-framing (Russian state press) presents French turmoil, government collapses and unrest as proof of a failing Western model and elite disconnect. Moscow prefers dealing with sovereign national leaderships over Brussels-aligned elites, so it amplifies the instability and the anti-establishment case rather than endorsing any French party. Vocabulary: chaos, collapse, crisis, decline.','Die Gegen-Rahmung (russische Staatspresse) deutet die französischen Turbulenzen, Regierungsstürze und Unruhen als Beleg eines scheiternden westlichen Modells und abgehobener Eliten. Moskau bevorzugt den Umgang mit souveränen nationalen Führungen gegenüber Brüssel-nahen Eliten und verstärkt daher die Instabilität und die anti-etablierte Sichtweise, ohne eine französische Partei zu unterstützen.',ARRAY['EUROPE-RUSSIA'],ARRAY['chaos','collapse','crisis','decline','ungovernable','turmoil','failing','elite'],true,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian'],'french_nationalist_challenge',3,'Russian counter-framing','Russische Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('israel_dismantle_hamas','Israel: war is non-negotiable until Hamas is dismantled and hostages freed','Israel: der Krieg ist nicht verhandelbar, bis die Hamas zerschlagen und die Geiseln befreit sind','Israeli sources frame the Gaza war as a non-negotiable response to October 7 with two operational goals: dismantling Hamas as a military and governing entity, and returning all hostages. Civilian casualties are attributed to Hamas use of human shields and the tunnel network beneath civilian infrastructure. The vocabulary is "Hamas terror", "October 7 worst attack on Jews since the Holocaust", "hostages", "tunnels beneath hospitals", "human shields", "complete victory", "the day after Hamas". Prescription: continue military operations until Hamas military and governing capability is eliminated, hostage deals only on Israeli terms, no Palestinian Authority return to Gaza without reform.','Israelische Quellen rahmen den Gaza-Krieg als nicht verhandelbare Antwort auf den 7. Oktober mit zwei Zielen: Zerschlagung der Hamas als militaerische und herrschende Einheit und Rueckkehr aller Geiseln. Zivile Opfer werden der Nutzung menschlicher Schutzschilde durch die Hamas und dem Tunnelsystem unter ziviler Infrastruktur zugeschrieben. Vokabular: "Hamas-Terror", "7. Oktober schlimmster Angriff auf Juden seit dem Holocaust", "Geiseln", "Tunnel unter Krankenhaeusern", "menschliche Schutzschilde", "vollstaendiger Sieg", "der Tag danach". Vorschrift: militaerische Operationen bis zur Beseitigung der militaerischen und herrschenden Kapazitaet der Hamas fortsetzen, Geiseldeals nur zu israelischen Bedingungen, keine Rueckkehr der Palaestinensischen Autonomiebehoerde nach Gaza ohne Reform.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['Hamas terror','October 7','7 October','hostages','human shields','tunnels','Sinwar','dismantle Hamas','complete victory','Israeli right to defend','Iron Sword','Gaza tunnels','Hamas hospitals'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Fox News','Arutz Sheva','Ynetnews'],'gaza_war',1,'Dismantle Hamas, free hostages','Hamas zerschlagen, Geiseln befreien',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('gaza_humanitarian_catastrophe','Pan-Arab / pro-Palestinian: Israel''s Gaza campaign is humanitarian catastrophe and genocide','Panarabisch / propalaestinensisch: Israels Gaza-Feldzug ist humanitaere Katastrophe und Genozid','Pan-Arab outlets, Press TV, TRT, and pro-Palestinian commentary frame the Gaza war as a humanitarian catastrophe and, in many cases, a genocide. Evidence cited: civilian death toll exceeding 40,000 with majority women and children, near-total displacement of the population, induced famine via aid blockade, systematic destruction of hospitals, universities, mosques, churches, and water/sanitation infrastructure, the ICJ genocide case brought by South Africa, ICC arrest warrants for Netanyahu and Gallant. The vocabulary is "genocide", "famine", "starvation as a weapon", "Rafah massacre", "Khan Younis massacre", "hospital strikes", "aid convoy targeting", "ICJ genocide ruling", "displaced", "open-air prison". Prescription: immediate and unconditional ceasefire, full humanitarian access, accountability via international law, end US military aid to Israel.','Panarabische Medien, Press TV, TRT und propalaestinensische Kommentatoren rahmen den Gaza-Krieg als humanitaere Katastrophe und vielfach als Genozid. Argumente: zivile Todeszahl ueber 40.000, mehrheitlich Frauen und Kinder, fast vollstaendige Vertreibung der Bevoelkerung, herbeigefuehrte Hungersnot durch Hilfsblockade, systematische Zerstoerung von Krankenhaeusern, Universitaeten, Moscheen, Kirchen und Wasser-/Sanitaerinfrastruktur, IGH-Genozidklage Suedafrikas, IStGH-Haftbefehle gegen Netanjahu und Gallant. Vokabular: "Genozid", "Hungersnot", "Aushungern als Waffe", "Massaker von Rafah", "Massaker von Khan Younis", "Angriffe auf Krankenhaeuser", "Beschuss von Hilfslieferungen", "IGH-Genozidurteil", "Vertriebene", "Freiluft-Gefaengnis". Vorschrift: sofortiger und bedingungsloser Waffenstillstand, vollstaendiger humanitaerer Zugang, Rechenschaft per Voelkerrecht, Ende der US-Militaerhilfe an Israel.',ARRAY['MIDEAST-PALESTINE','MIDEAST-LEVANT','MIDEAST-IRAN','MIDEAST-EGYPT','MIDEAST-GULF'],ARRAY['genocide','famine','starvation','Rafah massacre','Khan Younis massacre','hospital strike','aid convoy','displaced','open-air prison','war crimes','collective punishment','ICJ','ICC','Netanyahu warrant','starvation as weapon','siege of Gaza','UNRWA','aid blocked','humanitarian catastrophe'],true,ARRAY['Al Jazeera','Press TV','TRT World','Anadolu Agency','Daily Sabah','Al-Ahram','Arab News','Fars News','IRNA','Al Arabiya','Khaleej Times','Gulf News','Al Mayadeen','Middle East Eye','Egypt Today'],'gaza_war',2,'Humanitarian catastrophe and genocide','Humanitaere Katastrophe und Genozid', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ggd_european_aspiration','Georgians want a European future their government is betraying','Georgier wollen eine europäische Zukunft, die ihre Regierung verrät','Western framing backs Georgia''s pro-European majority against a Georgian Dream government sliding toward Moscow: a Russian-style foreign-agent law, EU-accession freeze, contested elections and street protests met with a crackdown mark a democratic backsliding away from the European path.','Die westliche Deutung stellt sich hinter Georgiens proeuropäische Mehrheit gegen eine Regierung des Georgischen Traums, die Richtung Moskau abdriftet: ein Agentengesetz nach russischem Vorbild, eingefrorener EU-Beitritt, umstrittene Wahlen und niedergeschlagene Straßenproteste markieren einen demokratischen Rückschritt weg vom europäischen Weg.',ARRAY['ASIA-CAUCASUS'],ARRAY['pro-European','pro-EU','protests','democracy','foreign agent','backsliding','crackdown','European path','candidate status','betray','proeuropäisch','Proteste','Rückschritt','Agentengesetz','проевропейск','протесты','иностранных агентов'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Politico','Novinite','iROZHLAS'],'georgia_geopolitical_drift',1,'European aspiration betrayed','Verratene europäische Perspektive',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ggd_sovereignty_stability','Tbilisi is resisting a Western-orchestrated colour revolution and defending its sovereignty','Tiflis widersteht einer vom Westen orchestrierten Farbrevolution und verteidigt seine Souveränität','Russian state framing praises the Georgian government for resisting a Western-funded "colour revolution": the foreign-agent law is legitimate self-defense against NGO subversion, the protests are an externally engineered Maidan, and Tbilisi is defending sovereignty and stability against EU coercion.','Die russische Staatsdeutung lobt die georgische Regierung für den Widerstand gegen eine westlich finanzierte "Farbrevolution": das Agentengesetz sei legitime Selbstverteidigung gegen NGO-Unterwanderung, die Proteste ein von außen inszenierter Maidan, und Tiflis verteidige Souveränität und Stabilität gegen EU-Zwang.',ARRAY['ASIA-CAUCASUS'],ARRAY['colour revolution','color revolution','Maidan','sovereignty','stability','Western-funded','NGO','subversion','coercion','interference','Farbrevolution','Souveränität','Einmischung','цветная революция','майдан','суверенитет','вмешательство'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'georgia_geopolitical_drift',2,'Anti-Western sovereignty defense','Antiwestliche Souveränitätsverteidigung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_engagement_working','Outside engagement is starting to bite','Auswärtiges Engagement beginnt zu wirken','After years in which external actors declared concern and did little, the instruments finally have teeth: a monitoring mechanism signed in Switzerland, prisoners released and humanitarian corridors agreed, financial designations placed on a neighbouring army and on a former head of state, and capital moving into Congolese mining assets rather than around them. Engagement of this kind is treated as the one lever that has moved anything.','Nach Jahren, in denen äußere Akteure Besorgnis erklärten und wenig taten, haben die Instrumente endlich Wirkung: ein in der Schweiz unterzeichneter Überwachungsmechanismus, freigelassene Gefangene und vereinbarte humanitäre Korridore, Finanzlistungen gegen eine Nachbararmee und einen früheren Staatschef, und Kapital, das in kongolesische Bergbauwerte fließt statt an ihnen vorbei. Ein solches Engagement gilt als der einzige Hebel, der überhaupt etwas bewegt hat.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['signed','agreement','progress','release','investment','stake','sanctions','designat','monitoring','corridor','accord','signé','progrès','investissement','Abkommen','Fortschritt','Investition'],true,ARRAY['Mining.com','Bloomberg','S&P Global','OilPrice','The Australian','Egypt Today','France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC','BBC World','Deutsche Welle','Washington Post','Financial Times','Al Jazeera','Swissinfo','ANSA','news.un.org','UN News','News24','Daily Nation','Punch Newspapers'],'great_lakes_theater',1,'Engagement is delivering','Engagement zeigt Wirkung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_proxy_war_and_its_costs','A cross-border war paid for by civilians','Ein grenzüberschreitender Krieg, den Zivilisten bezahlen','The dominant international reading treats the fighting in the east as one system rather than several problems: an insurgency sustained from across a border, a mediation track that is signed but not observed, and an extraction economy that runs through the same contested ground. What connects them is who absorbs the cost -- populations detained in captured towns, displaced across borders, killed by strikes meant for combatants, or buried in a collapsed mine on territory the armed group controls.','Die vorherrschende internationale Lesart behandelt die Kämpfe im Osten als ein System, nicht als mehrere Probleme: ein von jenseits der Grenze getragener Aufstand, ein Vermittlungsweg, der unterzeichnet, aber nicht eingehalten wird, und eine Rohstoffwirtschaft, die durch dasselbe umkämpfte Gebiet läuft. Verbunden sind sie durch die Frage, wer die Kosten trägt -- Menschen, die in eroberten Städten festgehalten, über Grenzen vertrieben, von Angriffen auf Kombattanten getötet oder in einer eingestürzten Mine im Gebiet der bewaffneten Gruppe verschüttet werden.',ARRAY['AFRICA-DRC'],ARRAY['civilians','displaced','killed','abuse','atrocities','backing','proxy','stalled','violation','toxic','collapse','civils','déplacés','atrocités','soutien','éboulement','Zivilisten','Vertriebene','Unterstützung','Gräueltaten'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC','BBC World','Deutsche Welle','Washington Post','Financial Times','The Economist','Al Jazeera','Daily Sabah','TRT World','Punch Newspapers','Swissinfo','ANSA','La Repubblica','Der Spiegel','Folha de S.Paulo','Globe and Mail','Wall Street Journal','Council on Foreign Relations','Janes','DR','news.un.org','UN News'],'great_lakes_theater',2,'Proxy war and human cost','Stellvertreterkrieg und menschliche Kosten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_scepticism_of_outside_fixes','African scepticism about externally designed fixes','Afrikanische Skepsis gegenüber extern entworfenen Lösungen','Regional and African coverage is markedly cooler about solutions drafted elsewhere. The accords are reported as documents both sides accuse each other of breaking, the designations as measures the targeted governments simply reject, and the minerals arrangement as terms a neighbouring energy minister publicly contests and a Congolese figure calls constitutionally doubtful. The common thread is a question about who wrote the terms and who carries the consequences.','Die regionale und afrikanische Berichterstattung ist deutlich kühler gegenüber Lösungen, die anderswo entworfen wurden. Die Abkommen erscheinen als Dokumente, deren Bruch sich beide Seiten gegenseitig vorwerfen, die Listungen als Maßnahmen, die die betroffenen Regierungen schlicht zurückweisen, und die Rohstoffvereinbarung als Konditionen, die ein Energieminister des Nachbarlands öffentlich bestreitet und ein kongolesischer Akteur für verfassungsrechtlich zweifelhaft hält. Verbindend ist die Frage, wer die Bedingungen geschrieben hat und wer die Folgen trägt.',ARRAY['AFRICA-DRC'],ARRAY['rejects','denounces','unjustified','unconstitutional','flawed','clashes with','sovereignty','accusations','trade accusations','souveraineté','injustifié','Souveränität','ungerechtfertigt'],true,ARRAY['The Standard','Daily Nation','Daily Maverick','Mail & Guardian','News24','Al-Ahram'],'great_lakes_theater',3,'Scepticism about outside terms','Skepsis gegenüber fremden Bedingungen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_us_strategic_claim','US control of Greenland is a strategic and national-security necessity','Die US-Kontrolle über Grönland ist eine strategische und sicherheitspolitische Notwendigkeit','US-manifest-destiny framing (Trump-aligned American press) holds that acquiring or controlling Greenland is a core national-security interest -- for Arctic bases, rare-earth minerals and sea lanes -- justified by Russian and Chinese encroachment, and that Washington should secure it "one way or the other". Genuine advocacy is thin relative to overall coverage. Vocabulary: core national security, strategic necessity, acquire Greenland, Arctic security, deal on the table.','Die Manifest-Destiny-Rahmung (Trump-nahe US-Presse) sieht die Übernahme oder Kontrolle Grönlands als zentrales nationales Sicherheitsinteresse -- für arktische Stützpunkte, Seltene Erden und Seewege -- gerechtfertigt durch russisches und chinesisches Vordringen.',ARRAY['AMERICAS-USA'],ARRAY['core national security','national security interest','strategic necessity','acquire Greenland','buy Greenland','get Greenland','take Greenland','one way or the other','won''t rule out','will not rule out','deal on the table','Arctic security','American Greenland','national sicherheit','Grönland kaufen','Grönland erwerben'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','The National Interest','Newsmax'],'greenland_control',1,'US strategic claim (manifest destiny)','US-Machtanspruch (Manifest Destiny)',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_sovereignty_defense','Coercion over Greenland is unacceptable; Danish/European sovereignty must be defended','Zwang gegen Grönland ist inakzeptabel; die dänische/europäische Souveränität muss verteidigt werden','Sovereignty-defense framing (Western mainstream) treats US pressure on Greenland as an unacceptable coercion of an ally, a violation of territorial integrity and international law, and a test of European unity -- met with condemnation, protests, counter-tariffs and troop deployments. It defends Denmark''s and the EU''s position against Washington. Vocabulary: hands off, not for sale, sovereignty, coercion, condemn, retaliate, allies, international law.','Die Souveränitäts-Rahmung (westlicher Mainstream) sieht den US-Druck auf Grönland als inakzeptablen Zwang gegen einen Verbündeten, als Verletzung der territorialen Integrität und des Völkerrechts und als Test der europäischen Einigkeit -- beantwortet mit Verurteilung, Protesten und Gegenzöllen.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','EUROPE-GERMANY','EUROPE-FRANCE','AMERICAS-USA','AMERICAS-CANADA'],ARRAY['hands off','not for sale','sovereignty','territorial integrity','coercion','coerce','condemn','pushback','unacceptable','retaliate','counter-tariff','allies','international law','defend Greenland','rally','protest','red line','Souveränität','unverkäuflich','Hände weg','Völkerrecht','Vergeltung','Verbündete','inakzeptabel'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','Washington Post','New York Times','ABC News','NPR','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','CNN'],'greenland_control',2,'European/Danish sovereignty defense','Verteidigung europäischer/dänischer Souveränität', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_self_determination','Greenland''s future is for Greenlanders to decide -- not Washington or Copenhagen','Über Grönlands Zukunft entscheiden die Grönländer -- nicht Washington oder Kopenhagen','Self-determination framing (Greenlandic/Nordic voices) centres Greenland''s own agency: the island is not for sale, its people decide their future, and the crisis accelerates the independence debate vis-à-vis both Denmark and the United States. Distinct from EU sovereignty-defense, which speaks for Denmark/Brussels. Vocabulary: self-determination, Greenlanders decide, our future, not for sale, independence, Inuit, referendum.','Die Selbstbestimmungs-Rahmung (grönländische/nordische Stimmen) stellt Grönlands eigene Handlungsmacht in den Mittelpunkt: die Insel ist nicht verkäuflich, ihr Volk entscheidet über seine Zukunft, und die Krise beschleunigt die Unabhängigkeitsdebatte gegenüber Dänemark und den USA.',ARRAY['EUROPE-GREENLAND','EUROPE-NORDIC'],ARRAY['self-determination','Greenlanders decide','our future','our country','right to decide','independence','Inuit','referendum','Naleraq','Egede','decide our','Selbstbestimmung','Unabhängigkeit','Grönländer'],true,ARRAY['Reuters','BBC World','Deutsche Welle','France 24 (EN)','Euronews','Associated Press','The Guardian','ERR News','LRT English','Anadolu Agency','Al Jazeera'],'greenland_control',3,'Greenlandic self-determination','Grönländische Selbstbestimmung',0,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_western_hypocrisy','US imperialism over Greenland exposes Western hypocrisy and disunity','Der US-Imperialismus um Grönland entlarvt westliche Heuchelei und Uneinigkeit','Rift-exploitation framing (Russian state press + Chinese state media) frames the episode not as support for a US takeover but as proof of Western hypocrisy and imperialism: Washington behaves as a 21st-century coloniser toward an ally, the "Russian/Chinese threat" to Greenland is a manufactured pretext (which even Western officials deny), and the transatlantic rift it opens is amplified with schadenfreude. It is adversarial to the US and to Western cohesion, NOT an endorsement of annexation. Vocabulary: imperialism, land grab, double standard, manufactured threat, northern outpost, ups ante, colonialism.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) deutet die Episode nicht als Zustimmung zu einer US-Übernahme, sondern als Beweis westlicher Heuchelei und Imperialismus: Washington verhält sich wie ein Kolonialherr des 21. Jahrhunderts, die "russisch-chinesische Bedrohung" Grönlands sei ein Vorwand, und der transatlantische Riss wird mit Schadenfreude verstärkt. Gegnerisch zu den USA und zur westlichen Geschlossenheit -- keine Zustimmung zur Annexion.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['imperialism','imperialist','land grab','takeover','double standard','hypocrisy','pretext','manufactured threat','inflating','so-called threat','colonial','colonialism','northern outpost','ups ante','21st century','coloniser'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'greenland_control',4,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_gulf_aggression_response','US-Israel-Saudi-UAE: Iranian and Houthi strikes are state-sponsored aggression','US-Israel-Saudi-VAE: iranische und Huthi-Schlaege sind staatlich gesponserte Aggression','The US-Israel-Saudi-UAE coalition describes the Iranian and Houthi strikes on Gulf states and US presence as "state-sponsored aggression" against sovereign nations. The 2019 Aramco strike, the 2022 UAE attacks, the 2025-2026 strikes on Saudi pipelines, UAE air-defence systems, and US bases are framed as Iran-directed acts of war that demand accountability. US service members killed at Tower 22, at Al Udeid, at Al Asad — each death is framed as an unacceptable cost requiring proportionate response. Saudi Arabia and the UAE are framed as victims of Iranian terror — sovereign Arab states attacked on their own territory by Iranian-backed forces. Houthi attacks on Saudi airspace and oil infrastructure are framed not as Yemeni civil war but as Iranian regional projection through proxy. The narrative explicitly rejects the asymmetric-deterrence framing as moral equivalence: hosting US bases is not complicity, and US-Israeli operations against Iran do not justify Iranian retaliation against third parties. The narrative prescribes: military retaliation against Iranian and Houthi leadership and capability, sustained sanctions on Iranian missile and drone programs, FTO designation of the Houthi movement, and integrated Gulf-Israeli air-defence cooperation as a force multiplier.','Die US-Israel-Saudi-VAE-Koalition beschreibt die iranischen und Huthi-Schlaege auf Golfstaaten und US-Praesenz als "staatlich gesponserte Aggression" gegen souveraene Nationen. Der Aramco-Angriff 2019, die VAE-Angriffe 2022, die Schlaege 2025-2026 auf saudische Pipelines, VAE-Luftabwehrsysteme und US-Basen werden als iranisch gesteuerte Kriegsakte gerahmt, die Rechenschaft erfordern. US-Soldaten, getoetet bei Tower 22, Al Udeid, Al Asad — jeder Tod ist ein inakzeptabler Preis, der verhaeltnismaessige Antwort erfordert. Saudi-Arabien und die VAE werden als Opfer iranischen Terrors gerahmt. Huthi-Angriffe auf saudischen Luftraum und Oel-Infrastruktur gelten nicht als jemenitischer Buergerkrieg, sondern als iranische regionale Projektion durch Stellvertreter. Das Narrativ lehnt die asymmetrische-Abschreckungs-Rahmung als moralische Aequivalenz ab: das Beherbergen von US-Basen ist keine Komplizenschaft, und US-israelische Operationen gegen Iran rechtfertigen keine iranische Vergeltung gegen Dritte. Verschreibung: militaerische Vergeltung gegen iranische und Huthi-Fuehrung und -Faehigkeit, anhaltende Sanktionen auf iranische Raketen- und Drohnenprogramme, FTO-Designierung der Huthi-Bewegung, und integrierte Golf-israelische Luftabwehrkooperation als Kraftmultiplikator.',ARRAY['AMERICAS-USA','MIDEAST-ISRAEL','MIDEAST-SAUDI'],ARRAY['state-sponsored aggression','state-sponsored attack','Iranian aggression','Iranian state-sponsored','attack on sovereign nation','attack on sovereign Arab','sovereign Arab states attacked','US service members killed','service members killed','Tower 22','Al Udeid','Al Asad','attack on US base','attack on US embassy','unacceptable cost','demands response','demands accountability','proportionate response','must be held accountable','Iranian terror','Iran-backed terror','Iranian regional projection','projection through proxy','integrated air defence','Saudi-Israeli cooperation','FTO designation Houthi','Houthi terror','Houthi aggression','Aramco strike','attacks on Saudi infrastructure','attacks on UAE'],true,ARRAY['Fox News','Wall Street Journal','WSJ','New York Post','CNN','New York Times','The New York Times','Washington Post','The Washington Post','Bloomberg','NPR','MSNBC','Associated Press','Reuters','Jerusalem Post','The Jerusalem Post','Times of Israel','Haaretz','i24NEWS','JNS','Israel Hayom','Ynet','Arab News','Saudi Gazette','Al Arabiya','Al Arabiya English','Asharq Al-Awsat','The National','Khaleej Times','Gulf News','WAM','Kyiv Post'],'gulf_attacks_on_arab_states',1,'State-sponsored aggression','Staatlich gesponserte Aggression', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_gulf_resistance_solidarity','Iran-aligned: Axis of Resistance as legitimate liberation movement','Iran-ausgerichtet: Achse des Widerstands als legitime Befreiungsbewegung','Iran and its regional partners describe the network of allied armed groups as the "Axis of Resistance" — a legitimate "liberation" movement against Israeli "occupation" of Palestinian and Lebanese territory and against Western "imperial" presence in the region. Hezbollah is framed as Lebanon''s defender against Israeli aggression and the only force that liberated southern Lebanon from Israeli occupation in 2000. Hamas is framed as the legitimate Palestinian resistance to occupation and the Gaza siege. The Houthis are framed as defenders of Yemen against Saudi and UAE aggression and as actors in solidarity with Palestinians under Israeli "genocide". The IRGC Quds Force, Iraqi PMF, and Syrian-aligned militias are framed as defenders of regional sovereignty against US "foreign occupation" — including the 28,500 US troops in Iraq and Syria and the 5,500 in Lebanon-region naval presence. Iranian state framing positions the support of these groups as a "moral duty" of solidarity with oppressed Muslims and as Iran''s contribution to regional self-determination. Western and Israeli operations against the network — assassinations of commanders, drone strikes, the 2025-2026 escalation — are framed as "state terrorism" and "war crimes" against legitimate political-military actors. The narrative prescribes: continued material support to the network, refusal of any framework that designates these groups as terrorist, and political-diplomatic pressure for international recognition of Palestinian and Lebanese resistance rights.','Iran und seine regionalen Partner beschreiben das Netzwerk verbuendeter bewaffneter Gruppen als "Achse des Widerstands" — eine legitime "Befreiungs"-Bewegung gegen israelische "Besatzung" palaestinensischen und libanesischen Territoriums und gegen westliche "imperiale" Praesenz in der Region. Hisbollah wird als Verteidigerin Libanons gegen israelische Aggression gerahmt, als einzige Kraft, die den Suedlibanon 2000 von israelischer Besatzung befreite. Hamas wird als legitimer palaestinensischer Widerstand gegen Besatzung und Gaza-Belagerung gerahmt. Die Huthis werden als Verteidiger Jemens gegen saudische und emiratische Aggression sowie als Solidaritaets-Akteure mit Palaestinensern unter israelischem "Genozid" gerahmt. Die IRGC-Quds-Truppe, irakische PMF und syrisch-ausgerichtete Milizen gelten als Verteidiger regionaler Souveraenitaet gegen US-"Fremdbesatzung". Iranische Rahmensetzung positioniert die Unterstuetzung dieser Gruppen als "moralische Pflicht" der Solidaritaet mit unterdrueckten Muslimen. Westliche und israelische Operationen — Attentate auf Kommandeure, Drohnenschlaege, die Eskalation 2025-2026 — werden als "Staatsterrorismus" und "Kriegsverbrechen" gegen legitime politisch-militaerische Akteure gerahmt. Verschreibung: fortgesetzte materielle Unterstuetzung des Netzwerks, Ablehnung jedes Rahmens, der diese Gruppen als terroristisch designiert, und politisch-diplomatischer Druck fuer internationale Anerkennung palaestinensischer und libanesischer Widerstandsrechte.',ARRAY['MIDEAST-IRAN','MIDEAST-LEVANT','MIDEAST-PALESTINE','MIDEAST-YEMEN'],ARRAY['assassinated','asymmetric calculus','asymmetric deterrence','asymmetric response','asymmetric retaliation','asymmetric warfare','Axis of Resistance','cannot match conventional','complicit Gulf states','complicit states','cost imposition','crimes against humanity','eye for an eye','foreign occupation','Hamas resistance','Hezbollah resistance','higher cost','host states','Houthi solidarity','imperial presence','imposing costs','Israeli aggression','Israeli occupation','Israeli state terrorism','launch points','legitimate liberation','legitimate resistance','legitimate response','legitimate retaliation','liberation movement','liberation struggle','martyr','martyrdom','martyred','moral duty','Nasrallah martyred','occupation forces','occupying power','oppressed Muslims','oppressed peoples','Palestine solidarity','proportionate response','proportionate to aggression','punishing Saudi participation','response to aggression','Sinwar martyred','Soleimani martyred','solidarity with Palestine','solidarity with Palestinians','staging ground','state-sponsored terrorism','state terrorism','targeted killing illegal','US base as legitimate target','US bases are targets','war crimes','Western imperial','Western imperialism','will be answered','Yemeni resistance','Yemen solidarity with Palestine'],true,ARRAY['Press TV','IRNA','Fars News','Fars News Agency','Tasnim News','Mehr News','Al Manar','Al Mayadeen','Middle East Eye'],'gulf_attacks_on_arab_states',3,'Resistance solidarity',NULL,2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_new_partnerships','New partnerships remaking the Horn','Neue Partnerschaften ordnen das Horn neu','A long-frozen map is finally moving: recognition, basing agreements and minerals deals are creating relationships that the old insistence on inherited borders had blocked for decades.','Eine lange eingefrorene Landkarte kommt in Bewegung: Anerkennung, Stützpunktabkommen und Rohstoffverträge schaffen Beziehungen, die das alte Beharren auf ererbten Grenzen jahrzehntelang verhindert hatte.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL'],ARRAY['recognition','historic','partnership','agreement','minerals','Anerkennung','Partnerschaft'],true,ARRAY['Jerusalem Post','Times of Israel','i24NEWS','Haaretz','News24'],'horn_africa_theater',1,'Realignment as opportunity','Neuordnung als Chance',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_regional_stabilisers','Regional partners rebuilding state capacity','Regionale Partner bauen Staatlichkeit wieder auf','Turkish, Gulf and East African engagement is doing the unglamorous work of reconstituting functioning states in the Horn -- training armies, drilling for energy, reopening borders and trade.','Türkisches, arabisches und ostafrikanisches Engagement leistet die unspektakuläre Arbeit, funktionierende Staaten am Horn wiederherzustellen: Armeen ausbilden, Energie erschließen, Grenzen und Handel wieder öffnen.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY','MIDEAST-EGYPT'],ARRAY['transformation','renewal','institutions','cooperation','partnership','training','trade','Wiederaufbau','Partnerschaft'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Egypt Today','Al-Ahram','ANSA'],'horn_africa_theater',2,'Stabilisation through partnership','Stabilisierung durch Partnerschaft',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_western_alarm','Western alarm at fragmentation and famine','Westliche Alarmrufe über Zerfall und Hungersnot','Reporting from Western outlets and UN agencies converges on deterioration: a northern Ethiopian war restarting, famine returning as aid collapses, piracy back at sea, and diplomatic recognition being auctioned for bases and minerals.','Berichte westlicher Medien und von UN-Organisationen laufen auf eine Verschlechterung hinaus: ein wieder aufflammender Krieg im Norden Äthiopiens, eine mit dem Wegbrechen der Hilfe zurückkehrende Hungersnot, erneute Piraterie und diplomatische Anerkennung, die gegen Stützpunkte und Rohstoffe versteigert wird.',ARRAY['AFRICA-HORN'],ARRAY['brink','fears','famine','hunger','clashes','piracy','drone','atrocities','civilian','Krieg','Hungersnot','Piraterie'],true,ARRAY['Reuters','BBC World','BBC','AFP','AFP Fact Check','Deutsche Welle','The Guardian','Financial Times','Le Monde','UN News','The Economist','Associated Press','France 24','France 24 (EN)','Die Zeit','Der Standard','IISS','Kurier','The Telegraph','Der Spiegel','Bloomberg','CNN','Atlantic Council','Japan Times','Straits Times','DR','Military Times','Defense News'],'horn_africa_theater',3,'Alarm at deterioration','Alarm über die Verschlechterung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_sovereignty_bloc','Sovereignty and non-interference','Souveränität und Nichteinmischung','Arab and Turkish coverage frames the realignment as a set of violations: inherited borders must hold, an outside power cannot confer statehood on a secessionist region, and upstream control of shared water is a standing threat to downstream states.','Arabische und türkische Berichterstattung deutet die Neuordnung als eine Reihe von Verstößen: Ererbte Grenzen müssen halten, eine fremde Macht kann einer sezessionistischen Region keine Staatlichkeit verleihen, und die Kontrolle über gemeinsame Wasserressourcen am Oberlauf bleibt eine Dauerbedrohung für die Anrainer flussabwärts.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT','MIDEAST-TURKEY'],ARRAY['sovereignty','territorial integrity','illegal','null and void','condemn','reject','water','dam','Souveränität','verurteilen'],true,ARRAY['Al Jazeera','Al Arabiya','Arab News','Dawn','The National'],'horn_africa_theater',4,'Borders and sovereignty violated','Verletzte Grenzen und Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_russian_iranian_counter','Russian and Iranian counter-framing','Russische und iranische Gegendarstellung','Russian and Iranian state media read the Horn primarily as a theatre of American and Israeli overreach -- airstrikes, blocked peacekeeping funding and coastal basing -- rather than as a set of local disputes.','Russische und iranische Staatsmedien lesen das Horn vorrangig als Schauplatz amerikanischer und israelischer Übergriffigkeit -- Luftangriffe, blockierte Mittel für Friedensmissionen, Stützpunkte an der Küste -- und nicht als eine Reihe lokaler Konflikte.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['airstrike','intervention','base','imperial','blockade','foreign','Luftangriff','Einmischung'],true,ARRAY['RT','Press TV','TASS (EN)','Sputnik'],'horn_africa_theater',5,'Blame external intervention','Die Einmischung von außen ist schuld', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('houthi_resistance_strikes_legitimate','Houthi missile and drone strikes on Israel are legitimate axis-of-resistance action','Houthi-Raketen und -Drohnenangriffe auf Israel sind legitime Widerstandsachsen-Aktion','Resistance-axis framing: Houthi missile and drone attacks on Israel are legitimate solidarity action with Gaza, coordinated with Iran and Hezbollah under a single axis-of-resistance command, deepening Israeli vulnerability and establishing a new deterrence equation. The vocabulary: "solidarity strikes", "axis command", "new deterrence equation", "Yemeni right to retaliate", "Israeli vulnerability". Prescription: integrated axis operations until Gaza ceasefire; develop Houthi missile and drone capabilities further.','Widerstandsachsen-Rahmung: Houthi-Raketen und -Drohnen-Angriffe auf Israel sind legitime Solidaritaets-Aktion mit Gaza, koordiniert mit Iran und Hisbollah unter einem einheitlichen Widerstandsachsen-Kommando, vertiefen israelische Verwundbarkeit und etablieren eine neue Abschreckungsgleichung. Vokabular: "Solidaritaetsschlaege", "Achsen-Kommando", "neue Abschreckungsgleichung", "jemenitisches Vergeltungsrecht", "israelische Verwundbarkeit". Vorschrift: integrierte Achsen-Operationen bis zum Gaza-Waffenstillstand.',ARRAY['MIDEAST-YEMEN','MIDEAST-IRAN'],ARRAY['solidarity strikes','axis command','new deterrence equation','Yemeni right','Israeli vulnerability'],true,ARRAY['Press TV','Fars News','IRNA','Al Mayadeen','Al Jazeera','TRT World','Anadolu Agency','Daily Sabah','CGTN','TASS (EN)'],'houthi_strikes_on_israel',1,'Solidarity strikes on Israel are legitimate','Solidaritaetsschlaege gegen Israel sind legitim',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('houthi_iranian_proxy_aggression','Houthi strikes are Iranian-orchestrated proxy aggression requiring kinetic answer','Houthi-Schlaege sind iranisch orchestrierte Stellvertreter-Aggression mit kinetischer Antwort','Israeli, pro-Israel, and Saudi-aligned framing: Houthi strikes are Iranian-orchestrated proxy aggression demanding kinetic response on Yemeni soil (Hodeidah port, Sanaa airport, Houthi leadership) plus expanded regional partnerships (Somaliland base, deeper Gulf cooperation) to interdict Iranian weapons pipelines. The vocabulary: "Iranian-orchestrated", "proxy aggression", "Hodeidah port", "Sanaa airport", "Somaliland base", "weapons interdiction", "kinetic answer". Prescription: continue Israeli strikes on Yemeni targets, build Somaliland-Eilat air-defense partnership, sanction Iranian transit nodes.','Israelische, pro-israelische und saudisch-orientierte Rahmung: Houthi-Schlaege sind iranisch orchestrierte Stellvertreter-Aggression mit kinetischer Antwort auf jemenitischem Boden (Hafen Hodeida, Flughafen Sanaa, Houthi-Fuehrung) plus erweiterten regionalen Partnerschaften (Somaliland-Basis, tiefere Golf-Kooperation) zur Unterbindung iranischer Waffenpipelines. Vokabular: "iranisch orchestriert", "Stellvertreter-Aggression", "Hafen Hodeida", "Flughafen Sanaa", "Somaliland-Basis", "Waffen-Unterbindung", "kinetische Antwort". Vorschrift: israelische Schlaege auf jemenitische Ziele fortsetzen.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA','MIDEAST-SAUDI'],ARRAY['Iranian-orchestrated','proxy aggression','Hodeidah port','Sanaa airport','Somaliland base','weapons interdiction','kinetic answer'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Fox News','Arutz Sheva','Haaretz','Al-Ahram','Al Arabiya','Arab News'],'houthi_strikes_on_israel',2,'Iranian proxy aggression on Israel','Iranische Stellvertreter-Aggression gegen Israel', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hungary_eu_standards','Rule of law and EU standards must be upheld in Hungary','Rechtsstaatlichkeit und EU-Standards müssen in Ungarn gelten','Standards-defense framing (Western mainstream) holds that judicial independence, media freedom, anti-corruption and the conditionality mechanism are non-negotiable European commitments, that the frozen funds were a justified response to backsliding, and that the post-transition clean-up of captured institutions is democratic renewal. Vocabulary: rule of law, conditionality, corruption, media freedom, democratic renewal.','Die Standards-Rahmung (westlicher Mainstream) sieht richterliche Unabhängigkeit, Medienfreiheit, Korruptionsbekämpfung und den Konditionalitätsmechanismus als nicht verhandelbare europäische Verpflichtungen, die eingefrorenen Mittel als gerechtfertigte Antwort auf den Abbau des Rechtsstaats und die Aufarbeitung vereinnahmter Institutionen nach dem Machtwechsel als demokratische Erneuerung.',ARRAY['NON-STATE-EU','EUROPE-VISEGRAD'],ARRAY['rule of law','Rechtsstaatlichkeit','état de droit','stato di diritto','conditionality','Konditionalität','judicial independence','media freedom','Pressefreiheit','corruption','Korruption','anti-corruption','backsliding','democratic renewal','frozen funds','eingefrorene','recovery plan','transparency','Transparenz','new government','neue Regierung','Regierungswechsel','election','Neuwahl','oust','abgesetzt','transition','Aufarbeitung','clean-up'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate'],'hungary_rule_of_law',1,'EU rule-of-law standards','EU-Rechtsstaatsstandards',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hungary_sovereignty_interference','Brussels interferes in a sovereign nation''s democracy','Brüssel mischt sich in die Demokratie eines souveränen Landes ein','Sovereignty framing (national-conservative sympathisers and the ousted camp''s own voice) holds that the conditionality fight was Brussels punishing a democratically elected government and infringing national sovereignty, and reads the domestic reckoning that followed the change of government as political revenge against opponents. Vocabulary: sovereignty, interference, Brussels overreach, double standard, political persecution, revenge.','Die Souveränitäts-Rahmung (nationalkonservative Sympathisanten und die Stimme des abgewählten Lagers) sieht im Konditionalitätsstreit eine Bestrafung einer demokratisch gewählten Regierung durch Brüssel und einen Eingriff in die nationale Souveränität und deutet die innenpolitische Abrechnung nach dem Regierungswechsel als politische Rache an Gegnern.',ARRAY['EUROPE-VISEGRAD'],ARRAY['sovereignty','Souveränität','souveraineté','interference','Einmischung','ingérence','Brussels overreach','Bevormundung','blackmail','Erpressung','double standard','doppelte Standards','witch hunt','Hexenjagd','political persecution','politische Verfolgung','revenge','Rache','purge','settle scores','national identity','will of voters'],true,ARRAY['Reuters','BBC World','The Guardian','Financial Times','Associated Press','AFP','Euronews','Deutsche Welle','France 24 (EN)','France 24','CNN','New York Times','Politico','Der Spiegel','Süddeutsche Zeitung','Die Zeit','Tagesschau','Le Monde','La Repubblica','El País','ANSA','EurActiv','Sky News','Handelsblatt','Frankfurter Allgemeine','Le Figaro','Corriere della Sera','El Mundo','The Telegraph','Wall Street Journal','Bloomberg','Die Presse','Der Standard','Kurier','eKathimerini','WELT','Cicero','Le Point','El Debate','Junge Freiheit','NIUS','Tichys Einblick','Valeurs Actuelles','Causeur','Boulevard Voltaire','Il Giornale','Libero','La Verità','OKdiario','Libertad Digital','Brussels Signal'],'hungary_rule_of_law',2,'National sovereignty vs Brussels','Nationale Souveränität gegen Brüssel', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hungary_brussels_coercion','Brussels overreaches against a sovereign nation','Brüssel greift nach einem souveränen Land über','Counter-framing (Russian state press, and the sovereignty case generally) holds that the conditionality fight and the funds freeze were Brussels overreaching against a democratically elected government and infringing national sovereignty. Moscow favours direct dealings with national capitals over Brussels'' supranational authority, so it amplifies the sovereigntist critique and every sign of EU heavy-handedness — aligned against Brussels rather than endorsing a specific Hungarian faction. Vocabulary: coercion, overreach, sovereignty, interference, diktat.','Die Gegen-Rahmung (russische Staatspresse und die souveränistische Sichtweise allgemein) sieht im Konditionalitätsstreit und im Einfrieren der Mittel einen Übergriff Brüssels gegen eine demokratisch gewählte Regierung und eine Verletzung der nationalen Souveränität. Moskau bevorzugt direkte Beziehungen zu den nationalen Hauptstädten gegenüber der supranationalen Autorität Brüssels und verstärkt daher die souveränistische Kritik und jedes Zeichen von Brüsseler Härte — gegen Brüssel gerichtet, ohne eine ungarische Seite zu unterstützen.',ARRAY['EUROPE-RUSSIA'],ARRAY['coercion','diktat','interfere','вмешательств','overreach','sovereignty','суверенитет','voting rights','лишени права','frozen funds','заморож','double standard','Bevormundung','Erpressung durch Brüssel'],true,ARRAY['RT','TASS (EN)','TASS','Lenta.ru','Gazeta.ru','Izvestia','RIA Novosti','BelTA Russian'],'hungary_rule_of_law',3,'Russian counter-framing','Russische Gegen-Rahmung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('militancy_pakistan_sponsorship','Pakistan shelters and directs the groups that attack India','Pakistan beherbergt und steuert die Gruppen, die Indien angreifen','Sponsorship framing (Indian press) holds that Lashkar-e-Taiba, Jaish-e-Mohammed and allied groups operate from Pakistani soil with official tolerance or direction: investigators trace the Pahalgam attack to handlers across the border, designated figures remain at liberty, and Operation Sindoor is presented as a proportionate response that established a precedent for striking back.','Die Unterstützungs-Darstellung (indische Presse) besagt, dass Lashkar-e-Taiba, Jaish-e-Mohammed und verbündete Gruppen mit offizieller Duldung oder Steuerung von pakistanischem Boden aus operieren: Ermittler führen den Anschlag von Pahalgam auf Hintermänner jenseits der Grenze zurück, gelistete Personen bleiben auf freiem Fuß, und die Operation Sindoor gilt als verhältnismäßige Antwort, die einen Präzedenzfall für Gegenschläge geschaffen hat.',ARRAY['ASIA-INDIA'],ARRAY['sponsor','shelter','harbour','handler','terror','Lashkar','Sindoor','proxy','FATF','designat','Unterstützung','beherbergt'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'india_pakistan_militancy',1,'Pakistani sponsorship of militancy','Pakistanische Unterstützung von Militanz',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('militancy_indian_pretext','India weaponises unproven allegations to justify pressure and strikes','Indien instrumentalisiert unbewiesene Vorwürfe, um Druck und Angriffe zu rechtfertigen','Pretext framing (Pakistani press) holds that India has never substantiated its allegations over the Pahalgam attack, that the accusations serve domestic politics and a campaign to isolate Pakistan diplomatically, and that Pakistan is itself a principal victim of militant violence rather than its author.','Die Vorwand-Darstellung (pakistanische Presse) besagt, dass Indien seine Vorwürfe zum Anschlag von Pahalgam nie belegt hat, dass die Anschuldigungen der Innenpolitik und einer Kampagne zur diplomatischen Isolierung Pakistans dienen und dass Pakistan selbst ein Hauptopfer militanter Gewalt ist und nicht deren Urheber.',ARRAY['ASIA-PAKISTAN'],ARRAY['false flag','propaganda','unsubstantiated','failed to substantiate','weaponisation','baseless','narrative','reject','isolation','haltlos','Vorwand'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation'],'india_pakistan_militancy',2,'Indian accusations as pretext','Indische Vorwürfe als Vorwand', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('indus_treaty_obsolete','The 1960 treaty no longer fits India''s needs and its terms are being revisited','Der Vertrag von 1960 entspricht nicht mehr Indiens Bedarf und wird überprüft','Treaty-revision framing (Indian press) holds that the Indus Waters Treaty was negotiated under conditions that no longer apply, that India''s position is consistent and lawful, and that a state which sponsors cross-border militancy cannot expect the water arrangement to continue unchanged; projects on the western rivers are presented as within India''s entitlement.','Die Vertragsrevisions-Darstellung (indische Presse) besagt, dass der Indus-Wasservertrag unter Bedingungen ausgehandelt wurde, die nicht mehr gelten, dass Indiens Position konsistent und rechtmäßig ist und dass ein Staat, der grenzüberschreitende Militanz unterstützt, keine unveränderte Fortführung der Wasserregelung erwarten kann; Projekte an den westlichen Flüssen gelten als von Indiens Anspruch gedeckt.',ARRAY['ASIA-INDIA'],ARRAY['outdated','obsolete','consistent','abeyance','renegotiat','rightful','entitle','review','fast-track','überholt','Anspruch'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'indus_water_sharing',1,'Treaty outdated; India''s rightful use','Vertrag überholt; Indiens rechtmäßige Nutzung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('indus_water_weaponisation','Suspending the treaty is coercion against a downstream population','Die Aussetzung des Vertrags ist Zwang gegen eine flussabwärts lebende Bevölkerung','Water-coercion framing (Pakistani press and sympathetic outlets) holds that the treaty remains valid, binding and operative, that no party may suspend it unilaterally, and that restricting or re-timing flows on which a downstream population depends for agriculture and drinking water is an act of coercion; the case is pressed at the UN Security Council and through arbitration.','Die Wasserzwang-Darstellung (pakistanische Presse und wohlwollende Medien) besagt, dass der Vertrag gültig, bindend und in Kraft bleibt, dass keine Partei ihn einseitig aussetzen darf und dass die Beschränkung oder zeitliche Steuerung von Wassermengen, von denen eine flussabwärts lebende Bevölkerung für Landwirtschaft und Trinkwasser abhängt, ein Zwangsakt ist; der Fall wird vor dem UN-Sicherheitsrat und durch Schiedsverfahren verfolgt.',ARRAY['ASIA-PAKISTAN'],ARRAY['weaponisation','water aggression','binding','restore','valid','unilateral','lifeline','arbitration','UNSC','Instrumentalisierung','bindend'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation','Anadolu Agency','Arab News','Al Jazeera','TRT World'],'indus_water_sharing',2,'Weaponisation of water','Instrumentalisierung des Wassers', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('inter_korean_engagement','Engagement can lower tension and reopen the inter-Korean track','Annäherung kann Spannungen senken und den innerkoreanischen Kanal wieder öffnen','Engagement framing (Seoul''s government position as carried by South Korean and Western outlets) holds that the track can be reopened through unilateral de-escalation and offers: restoring the 2018 inter-Korean military agreement and its no-fly zone, easing civilian access along the border, expressing regret over drone incursions, resuming exchanges, and reading signals such as Kim Yo-jong''s statements or a less hostile constitutional revision as openings.','Die Annäherungsrahmung (die Position der Regierung in Seoul, transportiert von südkoreanischen und westlichen Medien) hält den Kanal für wieder zu öffnen -- durch einseitige Deeskalation und Angebote: Wiederherstellung des innerkoreanischen Militärabkommens von 2018 samt Flugverbotszone, Erleichterung des zivilen Zugangs entlang der Grenze, Bedauern über Drohneneinflüge, Wiederaufnahme des Austauschs und die Deutung von Signalen wie Äußerungen von Kim Yo-jong oder einer weniger feindseligen Verfassungsrevision als Öffnungen.',ARRAY['ASIA-SOUTHKOREA'],ARRAY['coexistence','dialogue','talks','restore','improve','exchange','no-fly zone','regret','ease','hope','trust','peaceful','revive','reinstate','wise','less hostility','engagement','Annäherung','Dialog','Gespräche'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','Euronews','Financial Times','Bloomberg','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Sky News','NPR','ABC News','Channel NewsAsia','CNA','Straits Times','The Straits Times','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Times','Nikkei Asia','Al Jazeera','Brookings','Carnegie Endowment','Beyond Parallel'],'inter_korean_relations',1,'Engagement can reopen the track','Annäherung kann den Kanal öffnen',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pyongyang_closed_the_door','Pyongyang has formally closed the inter-Korean track','Pjöngjang hat den innerkoreanischen Kanal förmlich geschlossen','Closure framing (South Korean and Western outlets covering the same relationship) holds that the North has structurally ended the inter-Korean project rather than merely paused it: reunification references were deleted from the constitution, the South is defined as a separate and hostile state, Seoul''s diplomacy offers are publicly dismissed, and Seoul''s own unification white paper has pivoted to "two-state" coexistence. On this reading the engagement track has no counterpart.','Die Abschlussrahmung (südkoreanische und westliche Medien, die dieselbe Beziehung abdecken) hält das innerkoreanische Projekt für strukturell beendet und nicht nur ausgesetzt: Verweise auf die Wiedervereinigung wurden aus der Verfassung gestrichen, der Süden wird als eigener und feindlicher Staat definiert, Gesprächsangebote aus Seoul werden öffentlich zurückgewiesen, und Seouls eigenes Weißbuch zur Wiedervereinigung ist auf eine Koexistenz zweier Staaten umgeschwenkt. In dieser Lesart fehlt dem Annäherungskurs das Gegenüber.',ARRAY['ASIA-NORKOREA'],ARRAY['drops','dropped','drop','removes','removed','two-state','two state','hostile','separate state','dismiss','reject','no interest','constitution','territory','abandons','niente riunificazione','abandonne','streicht','feindlich'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','Euronews','Financial Times','Bloomberg','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Sky News','NPR','ABC News','Channel NewsAsia','CNA','Straits Times','The Straits Times','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Times','Nikkei Asia','Al Jazeera','Le Monde','El Mundo','Der Spiegel','Corriere della Sera'],'inter_korean_relations',2,'The track is structurally closed','Der Kanal ist strukturell geschlossen', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_iran_nuclear_threat','Western coalition: Iran nuclear as existential threat','Westliche Koalition: Iran-Atomprogramm als Existenzbedrohung','The Israel-US-Saudi coalition describes Iran''s enrichment program as an "existential threat" that warrants "preemptive" military action if necessary. Iranian advances at Natanz and Fordow — 60% enrichment levels, advanced IR-6 / IR-9 centrifuge cascades, reduced "breakout time" estimates — are framed as evidence of intent to "weaponize". The Israeli position rests on the "Begin doctrine" (no hostile regional power may acquire nuclear weapons) and the broader principle of "prevention not deterrence". The US position escalates from "maximum pressure" sanctions and naval deployments to direct strikes on Iranian assets where the breakout window narrows. The narrative prescribes denial of capability through sanctions, sabotage (Stuxnet legacy, Mossad operations against scientists, plant accidents), and where necessary preemptive military strikes on enrichment facilities; explicitly rejects diplomatic frameworks that grant Iran any continuing enrichment capability.','Die israelisch-amerikanisch-saudische Koalition beschreibt Irans Anreicherungsprogramm als "Existenzbedrohung", die noetigenfalls "praeventives" militaerisches Handeln rechtfertigt. Iranische Fortschritte in Natanz und Fordow gelten als Beweis fuer Waffenabsicht. Die israelische Position stuetzt sich auf die "Begin-Doktrin" und das Prinzip der "Praevention statt Abschreckung". Die US-Position eskaliert von "maximalem Druck" bis zu direkten Schlaegen, wenn das Breakout-Fenster schrumpft. Verschreibung: Faehigkeitsverweigerung durch Sanktionen, Sabotage und noetigenfalls praeventive Schlaege; explizite Ablehnung diplomatischer Rahmen, die Iran fortgesetzte Anreicherungsfaehigkeit zugestehen.',ARRAY['AMERICAS-USA','MIDEAST-ISRAEL','MIDEAST-SAUDI'],ARRAY['existential threat','preemptive strike','prevention not deterrence','Begin doctrine','all options on table','maximum pressure','denial of capability','denuclearization','rollback','weapons program','nuclear weapon program','nuclear weapons capability','nuclear ambition','nuclear ambitions','breakout time','breakout window','breakout capability','weapons-grade','clandestine enrichment','Stuxnet','military option','Natanz strike','extract Iran','extract enriched uranium','remove enriched uranium','remove uranium','precondition to ending war','crushing','crushing Iran','eliminate','eliminate Iran','destroy Iran','destroy Iran nuclear','enrichment halt','halt enrichment','stop funding proxies','stop Iran','Iran threat','Witkoff','Iran 11 bombs','enrichment compromise','oppose enrichment compromise','tear up'],true,ARRAY['Fox News','Wall Street Journal','WSJ','New York Post','CNN','New York Times','The New York Times','Washington Post','The Washington Post','Bloomberg','NPR','MSNBC','Jerusalem Post','The Jerusalem Post','Times of Israel','Haaretz','i24NEWS','JNS','Israel Hayom','Ynet','Kyiv Post'],'iran_nuclear_program',1,'Existential threat','Existenzbedrohung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_nuclear_sovereign_right','Iran: nuclear program as sovereign right and deterrence hedge','Iran: Atomprogramm als souveraenes Recht und Abschreckungsabsicherung','Iran describes its nuclear program in a framework of sovereign right and lawful deterrence. Enrichment activity at Natanz and Fordow is characterised as a "peaceful civilian nuclear program" and an exercise of Iran''s rights as an "NPT signatory" under "Article IV". The supreme leader''s standing "fatwa against nuclear weapons" is invoked as the religious-juridical foundation — nuclear weapons are forbidden under Iranian Islamic doctrine, and the program is therefore civilian by definition. Progressive non-compliance with JCPOA limits is framed as legitimate response to the "American withdrawal" of 2018 and the "snapback" of sanctions; "we honored the deal" is the standing claim. The Israeli campaign of "sabotage", "assassinations of scientists", and plant accidents is termed "aggression" and "state terrorism". American "maximum pressure" is "collective punishment" of the Iranian people; deeper enrichment is the proportionate "deterrence hedge" against credible US-Israeli threats, with Iraq and Libya as cautionary cases of regimes that abandoned deterrence and were destroyed. The narrative prescribes continued enrichment as leverage, demands sanctions relief and US security guarantee as preconditions for any new agreement, and rejects all frameworks that would deny Iran the right to a complete nuclear fuel cycle.','Iran beschreibt sein Atomprogramm im Rahmen souveraenen Rechts und rechtmaessiger Abschreckung. Anreicherung in Natanz und Fordow gilt als "friedliches ziviles Nuklearprogramm" und Wahrnehmung iranischer Rechte als "NPT-Unterzeichnerstaat" unter "Artikel IV". Die fortbestehende "Fatwa des Obersten Fuehrers gegen Nuklearwaffen" wird als religioes-juristische Grundlage angefuehrt. Die schrittweise Abkehr von JCPOA-Grenzen ist legitime Antwort auf den "amerikanischen Ausstieg" 2018; "wir haben das Abkommen eingehalten" ist die stehende Behauptung. Israelische Sabotage und Attentate auf Wissenschaftler werden als "Aggression" und "Staatsterrorismus" bezeichnet. Amerikanischer "maximaler Druck" ist "kollektive Bestrafung"; tiefere Anreicherung ist die verhaeltnismaessige "Abschreckungsabsicherung". Verschreibung: fortgesetzte Anreicherung als Hebel, Sanktionserleichterung und US-Sicherheitsgarantie als Vorbedingungen, Ablehnung jedes Rahmens, der Iran den vollstaendigen Brennstoffkreislauf verweigert.',ARRAY['MIDEAST-IRAN'],ARRAY['peaceful civilian nuclear program','NPT Article IV','sovereign enrichment','Khamenei fatwa','fatwa against nuclear weapons','we honored the deal','American withdrawal','JCPOA betrayed','maximum pressure failure','collective punishment','deterrence hedge','Israeli aggression','state terrorism','Iraq Libya cautionary','peaceful nuclear','peaceful nuclear energy','peaceful nuclear technology','right to enrich','enrichment rights','inalienable right','rights enshrined in NPT','nuclear logic','religious beliefs','big lie','big lies','civilian atomic','civilian nuclear','Israeli sabotage','attacks on Iran','attacks on nuclear','US-Israeli attacks','language of force','rejects language','Israeli arsenal','nuclear-weapon-free Middle East','fair nuclear deal','fair nuclear talks','rejection of nuclear weapons','nuclear self-sufficiency','reparations','nuclear ambiguity','demands reparations'],true,ARRAY['Press TV','IRNA','Fars News','Fars News Agency','Tasnim News','Mehr News','Al Manar','Al Mayadeen'],'iran_nuclear_program',2,'Sovereign right','Souveraenes Recht',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_iran_proxy_network_threat','Western coalition: Iran proxy network as terror infrastructure','Westliche Koalition: iranisches Stellvertreternetz als Terror-Infrastruktur','The Israel-US-Saudi coalition describes the Iran-aligned regional armed-group network as an Iranian-directed "terror infrastructure". "Hezbollah" in Lebanon, "Hamas" in Gaza, the "Houthis" in Yemen, "Iraqi PMF" militias, "IRGC" Quds Force operations across the region — all are framed as proxies that Iran arms, funds, trains, and directs for power projection and attacks on allied states. Israeli operations in Gaza, the West Bank, southern Lebanon, and Syria are presented as "counterterrorism" and the legitimate exercise of "self-defence". Civilian casualties are attributed to groups using "human shields" in tunnels embedded under schools, hospitals, and residential blocks. US counter-Houthi air operations in the Red Sea and counter-PMF strikes in Iraq and Syria are framed identically. Saudi and UAE positioning has hardened markedly since the Houthi attacks on Saudi oil infrastructure and UAE air defences in 2025-2026. The narrative prescribes: sustained kinetic counterterrorism operations including assassinations of senior commanders (Soleimani, Mughniyeh, Nasrallah, Sinwar, Haniyeh, Khademi); foreign-terrorist-organisation designations; sanctions on the Iranian funding network and its banking facilitators; and rejection of any negotiation framework that legitimises these groups as political actors.','Die israelisch-amerikanisch-saudische Koalition beschreibt das iranisch ausgerichtete regionale Bewaffneten-Netz als iranisch gesteuerte "Terror-Infrastruktur". "Hisbollah" im Libanon, "Hamas" in Gaza, die "Huthis" im Jemen, "irakische PMF"-Milizen, Operationen der "IRGC"-Quds-Truppe — alle gerahmt als Stellvertreter, die Iran bewaffnet, finanziert, ausbildet und steuert. Israelische Operationen in Gaza, Westjordanland, Suedlibanon und Syrien gelten als "Terrorbekaempfung" und legitime "Selbstverteidigung". Zivile Opfer werden Gruppen zugeschrieben, die "menschliche Schutzschilde" in Tunneln unter Schulen, Krankenhaeusern und Wohnhaeusern nutzen. US-Operationen gegen Huthis im Roten Meer und gegen PMF-Stellungen in Irak und Syrien werden identisch gerahmt. Die saudische und emiratische Positionierung hat sich nach Huthi-Angriffen auf saudische Oel-Infrastruktur und VAE-Luftabwehr 2025-2026 deutlich verhaertet. Verschreibung: anhaltende kinetische Terrorbekaempfung einschliesslich Attentate auf Kommandeure (Soleimani, Mughniyeh, Nasrallah, Sinwar, Haniyeh, Khademi), FTO-Designierung der bewaffneten Gruppen, Sanktionen gegen das iranische Finanzierungsnetzwerk und Ablehnung jedes Verhandlungsrahmens, der diese Gruppen als politische Akteure legitimiert.',ARRAY['AMERICAS-USA','MIDEAST-ISRAEL','MIDEAST-SAUDI'],ARRAY['terror infrastructure','Iran proxy network','Iran-backed','Iran-aligned','human shields','self-defence','right to self-defence','right to defend','counterterrorism','tunnel network','tunnel infrastructure','FTO designation','foreign terrorist organisation','terror financing','Iranian funding','eliminated','commander eliminated','commander killed','targeted killing','assassinated','assassination','crippled','degraded','dismantle','destroy Hezbollah','destroy Hamas','October 7','Oct 7','Hamas attack','Hamas atrocity','Iran-backed Houthi','Houthi attack','Houthi missile','Soleimani','Mughniyeh','Nasrallah','Sinwar','Haniyeh','Khademi'],true,ARRAY['Fox News','Wall Street Journal','WSJ','New York Post','CNN','New York Times','The New York Times','Washington Post','The Washington Post','Bloomberg','NPR','MSNBC','Associated Press','Jerusalem Post','The Jerusalem Post','Times of Israel','Haaretz','i24NEWS','JNS','Israel Hayom','Ynet','Arab News','Saudi Gazette','Al Arabiya','Al Arabiya English','Asharq Al-Awsat','The National','Khaleej Times','Gulf News','WAM','Kyiv Post'],'iran_proxy_network',1,'Terror infrastructure','Terror-Infrastruktur', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_axis_of_resistance','Iran-aligned: Axis of Resistance as legitimate liberation movement','Iran-ausgerichtet: Achse des Widerstands als legitime Befreiungsbewegung','Iran and its regional partners describe the network of allied armed groups as the "Axis of Resistance" — a legitimate "liberation" movement against Israeli "occupation" of Palestinian and Lebanese territory and against Western "imperial" presence in the region. Hezbollah is framed as Lebanon''s defender against Israeli aggression and the only force that liberated southern Lebanon from Israeli occupation in 2000. Hamas is framed as the legitimate Palestinian resistance to occupation and the Gaza siege. The Houthis are framed as defenders of Yemen against Saudi and UAE aggression and as actors in solidarity with Palestinians under Israeli "genocide". The IRGC Quds Force, Iraqi PMF, and Syrian-aligned militias are framed as defenders of regional sovereignty against US "foreign occupation" — including the 28,500 US troops in Iraq and Syria and the 5,500 in Lebanon-region naval presence. Iranian state framing positions the support of these groups as a "moral duty" of solidarity with oppressed Muslims and as Iran''s contribution to regional self-determination. Western and Israeli operations against the network — assassinations of commanders, drone strikes, the 2025-2026 escalation — are framed as "state terrorism" and "war crimes" against legitimate political-military actors. The narrative prescribes: continued material support to the network, refusal of any framework that designates these groups as terrorist, and political-diplomatic pressure for international recognition of Palestinian and Lebanese resistance rights.','Iran und seine regionalen Partner beschreiben das Netzwerk verbuendeter bewaffneter Gruppen als "Achse des Widerstands" — eine legitime "Befreiungs"-Bewegung gegen israelische "Besatzung" palaestinensischen und libanesischen Territoriums und gegen westliche "imperiale" Praesenz in der Region. Hisbollah wird als Verteidigerin Libanons gegen israelische Aggression gerahmt, als einzige Kraft, die den Suedlibanon 2000 von israelischer Besatzung befreite. Hamas wird als legitimer palaestinensischer Widerstand gegen Besatzung und Gaza-Belagerung gerahmt. Die Huthis werden als Verteidiger Jemens gegen saudische und emiratische Aggression sowie als Solidaritaets-Akteure mit Palaestinensern unter israelischem "Genozid" gerahmt. Die IRGC-Quds-Truppe, irakische PMF und syrisch-ausgerichtete Milizen gelten als Verteidiger regionaler Souveraenitaet gegen US-"Fremdbesatzung". Iranische Rahmensetzung positioniert die Unterstuetzung dieser Gruppen als "moralische Pflicht" der Solidaritaet mit unterdrueckten Muslimen. Westliche und israelische Operationen — Attentate auf Kommandeure, Drohnenschlaege, die Eskalation 2025-2026 — werden als "Staatsterrorismus" und "Kriegsverbrechen" gegen legitime politisch-militaerische Akteure gerahmt. Verschreibung: fortgesetzte materielle Unterstuetzung des Netzwerks, Ablehnung jedes Rahmens, der diese Gruppen als terroristisch designiert, und politisch-diplomatischer Druck fuer internationale Anerkennung palaestinensischer und libanesischer Widerstandsrechte.',ARRAY['MIDEAST-IRAN','MIDEAST-LEVANT','MIDEAST-PALESTINE','MIDEAST-YEMEN'],ARRAY['assassinated','asymmetric calculus','asymmetric deterrence','asymmetric response','asymmetric retaliation','asymmetric warfare','Axis of Resistance','cannot match conventional','complicit Gulf states','complicit states','cost imposition','crimes against humanity','eye for an eye','foreign occupation','Hamas resistance','Hezbollah resistance','higher cost','host states','Houthi solidarity','imperial presence','imposing costs','Israeli aggression','Israeli occupation','Israeli state terrorism','launch points','legitimate liberation','legitimate resistance','legitimate response','legitimate retaliation','liberation movement','liberation struggle','martyr','martyrdom','martyred','moral duty','Nasrallah martyred','occupation forces','occupying power','oppressed Muslims','oppressed peoples','Palestine solidarity','proportionate response','proportionate to aggression','punishing Saudi participation','response to aggression','Sinwar martyred','Soleimani martyred','solidarity with Palestine','solidarity with Palestinians','staging ground','state-sponsored terrorism','state terrorism','targeted killing illegal','US base as legitimate target','US bases are targets','war crimes','Western imperial','Western imperialism','will be answered','Yemeni resistance','Yemen solidarity with Palestine'],true,ARRAY['Press TV','IRNA','Fars News','Fars News Agency','Tasnim News','Mehr News','Al Manar','Al Mayadeen','Middle East Eye'],'iran_proxy_network',2,'Legitimate resistance','Legitimer Widerstand',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_iran_regime_change_doctrine','Western coalition: the Iranian regime is illegitimate and replaceable','Westliche Koalition: das iranische Regime ist illegitim und ersetzbar','The Israel-US-Saudi coalition describes the Islamic Republic of Iran as an illegitimate, brutal "regime" — the loaded word "regime" rather than "government" is itself the diagnostic — that "oppresses its own people", supports "terror infrastructure" abroad, and pursues nuclear weapons. The narrative holds that "the Iranian people deserve freedom" and that the regime is propped up only by repression of the women, students and ethnic minorities who would otherwise replace it. The 2022-2023 "Mahsa Amini" protests and the "Women Life Freedom" movement are framed as proof that the regime has lost its people. The diaspora opposition — "Reza Pahlavi" and the monarchist movement, "Maryam Rajavi" and the "Mojahedin-e Khalq" (MEK), "Iran International" television — are presented as legitimate alternative leadership-in-waiting. Sanctions, designation of the IRGC as a foreign terrorist organisation, and material and rhetorical support for the opposition are framed as solidarity with the Iranian people against their oppressors. The 2025 and 2026 Israeli and American strikes on Iranian leadership — including the killing of "Supreme Leader Khamenei" and "Ali Larijani" — are framed as a "decapitation" that opens space for "democratic transition" and the "fall of the Islamic Republic". The narrative explicitly does not endorse occupation or regime imposition — the prescribed model is that the Iranian people, freed from the regime''s grip, will choose their own future. The narrative prescribes: maximum-pressure sanctions, support to opposition voices and broadcasting, diplomatic isolation of the regime, kinetic operations against regime apparatus where opportunity arises, and rejection of any framework that legitimises the current government as a normal interlocutor.','Die israelisch-amerikanisch-saudische Koalition beschreibt die Islamische Republik Iran als illegitimes, brutales "Regime" — das geladene Wort "Regime" statt "Regierung" ist selbst das Diagnostikum — das "sein eigenes Volk unterdrueckt", "Terror-Infrastruktur" im Ausland unterstuetzt und Nuklearwaffen anstrebt. Das Narrativ haelt fest, dass "das iranische Volk Freiheit verdient" und dass das Regime nur durch Unterdrueckung jener Frauen, Studenten und ethnischen Minderheiten gestuetzt wird, die es sonst ersetzen wuerden. Die Mahsa-Amini-Proteste 2022-2023 und die "Women Life Freedom"-Bewegung gelten als Beweis, dass das Regime sein Volk verloren hat. Die Diaspora-Opposition — "Reza Pahlavi" und die Monarchisten-Bewegung, "Maryam Rajavi" und die "Mojahedin-e Khalq" (MEK), Iran International TV — werden als legitime alternative Fuehrung im Wartestand praesentiert. Sanktionen, FTO-Designierung der IRGC und Unterstuetzung der Opposition gelten als Solidaritaet mit dem iranischen Volk. Die israelisch-amerikanischen Schlaege 2025 und 2026 auf die iranische Fuehrung — einschliesslich der Toetung des "Obersten Fuehrers Khamenei" und "Ali Larijanis" — werden als "Enthauptung" gerahmt, die Raum fuer "demokratischen Uebergang" und "Fall der Islamischen Republik" oeffnet. Das Narrativ befuerwortet ausdruecklich keine Besatzung oder aufgezwungene Regierung — das vorgeschriebene Modell ist, dass das iranische Volk, befreit vom Regime, seine eigene Zukunft waehlen wird. Verschreibung: maximaler Sanktionsdruck, Unterstuetzung von Oppositionsstimmen und -sendungen, diplomatische Isolation, kinetische Operationen gegen Regimeapparat wo Gelegenheit besteht, Ablehnung jedes Rahmens, der die gegenwaertige Regierung als normalen Gespraechspartner legitimiert.',ARRAY['AMERICAS-USA','MIDEAST-ISRAEL','MIDEAST-SAUDI'],ARRAY['the regime','Iranian regime','Tehran regime','mullah regime','tyrannical regime','brutal regime','oppressive regime','Islamic Republic','regime change','topple','overthrow','fall of the regime','fall of the Islamic Republic','collapse of the regime','democratic transition','post-regime Iran','free Iran','liberate Iran','free the Iranian people','Iranian people deserve freedom','people vs the regime','Iranian opposition','opposition leaders','opposition figures','oppressed by the regime','morality police','hijab protest','protests in Iran crushed','crackdown on protesters','monarchist','monarchist opposition','decapitation strike','regime decapitated','regime collapse imminent'],true,ARRAY['Jerusalem Post','The Jerusalem Post','Times of Israel','Haaretz','i24NEWS','JNS','Israel Hayom','Ynet','Fox News','Wall Street Journal','WSJ','New York Post','CNN','New York Times','The New York Times','Washington Post','The Washington Post','Bloomberg','NPR','MSNBC','Associated Press','Arab News','Saudi Gazette','Al Arabiya','Al Arabiya English','Asharq Al-Awsat','Kyiv Post'],'iran_theater',1,'Regime is illegitimate','Regime ist illegitim', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_sovereign_existence','Iran: Islamic Republic as sovereign state under permanent foreign assault','Iran: Islamische Republik als souveraener Staat unter permanentem fremden Angriff','Iran describes its political system in a framework of "religious democracy" — the "Islamic Republic" established by "Imam Khomeini" in 1979, headed by the "Supreme Leader" under the doctrine of "Velayat-e Faqih" (Guardianship of the Jurist). Western and Israeli pressure across all phases — sanctions, support for opposition, broadcasting, military action — is framed as a single 45-year imperial "regime change" campaign disguised under successive pretexts (nuclear, terrorism, human rights). The diaspora opposition is delegitimised: the "MEK" / "Mojahedin-e Khalq" is termed "Munafiqin" (the hypocrites) and "foreign-backed terrorists" responsible for thousands of Iranian deaths; the "Pahlavi pretender" Reza Pahlavi is framed as an irrelevant son of an overthrown dictator; "Iran International" is framed as Saudi-funded propaganda. The 2022-2023 protests are framed as "foreign-instigated unrest" stoked by hostile media — "rioters" rather than "protesters" — though the underlying social grievances are sometimes acknowledged. The 2025 and 2026 Israeli and American strikes on Iranian leadership are framed as "war crimes" and "state terrorism" against a sovereign government; the "martyrdom" of "Imam Khamenei" and Larijani is framed as elevating them rather than ending their authority, and as binding the Iranian nation in unity against the aggressor. Resilience framing dominates: "we will not bow", "stronger after every blow", "national unity in the face of aggression". The narrative prescribes: continued sovereignty without external concessions, military preparedness for further aggression, sustained orderly succession (the Assembly of Experts process), continued material and rhetorical pressure on Western and Israeli legitimacy, and rejection of any negotiating framework that treats the Islamic Republic as a temporary or replaceable government.','Iran beschreibt sein politisches System im Rahmen "religioeser Demokratie" — die 1979 von "Imam Khomeini" errichtete "Islamische Republik", gefuehrt vom "Obersten Fuehrer" unter der Doktrin "Velayat-e Faqih". Westlicher und israelischer Druck in allen Phasen — Sanktionen, Oppositionsunterstuetzung, Sendungen, militaerische Aktion — wird als einzige 45-jaehrige imperiale "Regimewechsel"-Kampagne unter verschiedenen Vorwaenden (nuklear, Terrorismus, Menschenrechte) gerahmt. Die Diaspora-Opposition wird delegitimiert: die "MEK"/"Mojahedin-e Khalq" gelten als "Munafiqin" (Heuchler) und "fremdfinanzierte Terroristen", verantwortlich fuer Tausende iranischer Tote; der "Pahlavi-Praetendent" Reza Pahlavi gilt als irrelevanter Sohn eines gestuerzten Diktators; "Iran International" als saudisch finanzierte Propaganda. Die Proteste 2022-2023 gelten als "fremdgeschuerte Unruhen" — "Randalierer" statt "Demonstranten" — wenngleich die unterliegenden sozialen Beschwerden manchmal anerkannt werden. Die israelisch-amerikanischen Schlaege 2025-2026 auf die iranische Fuehrung gelten als "Kriegsverbrechen" und "Staatsterrorismus" gegen eine souveraene Regierung; das "Martyrium" von "Imam Khamenei" und Larijani erhebe sie statt ihre Autoritaet zu beenden und binde die iranische Nation in Einheit gegen den Aggressor. Resilienz dominiert: "wir beugen uns nicht", "staerker nach jedem Schlag", "nationale Einheit im Angesicht der Aggression". Verschreibung: anhaltende Souveraenitaet ohne externe Zugestaendnisse, militaerische Bereitschaft fuer weitere Aggression, geordnete Nachfolge (Expertenversammlungs-Prozess), fortgesetzter materieller und rhetorischer Druck auf westliche und israelische Legitimitaet, Ablehnung jedes Verhandlungsrahmens, der die Islamische Republik als temporaere oder ersetzbare Regierung behandelt.',ARRAY['MIDEAST-IRAN'],ARRAY['Islamic Republic','religious democracy','Imam Khomeini','Imam Khamenei','Supreme Leader','Ayatollah Khamenei','Ayatollah','Velayat-e Faqih','Guardian Jurist','Pasdaran','Sepah','Munafiqin','foreign-backed terrorists','MEK terrorist','MEK terror','Pahlavi pretender','son of the Shah','Saudi-funded propaganda','Iran International propaganda','regime change war','imperial regime change','foreign interference','foreign meddling','foreign-instigated','foreign-instigated unrest','rioters','Western-backed rioters','fitnah','sedition','color revolution','colour revolution','martyred','martyrdom','Sayyed','Khamenei martyred','Imam Khamenei martyred','Larijani martyred','state terrorism','Israeli state terrorism','war crimes against Iran','crimes against humanity Iran','we will not bow','will not bow','will not surrender','stronger after every blow','national unity','nation unites','orderly succession','Assembly of Experts'],true,ARRAY['Press TV','IRNA','Fars News','Fars News Agency','Tasnim News','Mehr News','Al Manar','Al Mayadeen'],'iran_theater',2,'Sovereign state under assault','Souveraener Staat unter Angriff',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eu_diplomatic_preservation_norm','EU/E3 diplomatic engagement on Iran','EU/E3 diplomatische Iran-Strategie','The European Union and the E3 (France, Germany, United Kingdom) frame their Iran posture around preserving diplomatic channels while applying calibrated pressure on enrichment and proliferation. The vocabulary is "JCPOA preservation", "Vienna talks", "snapback mechanism", "IAEA safeguards", "diplomatic off-ramp", "engage rather than isolate", "return to compliance", and "calibrated pressure". The narrative explicitly registers concern about enrichment escalation, ballistic-missile transfers, and IAEA cooperation, but rejects unilateral military strikes as the answer — preferring sustained diplomacy under multilateral institutions. Prescription: keep talks alive, threaten snapback as leverage rather than execution, and position the EU as the indispensable convening power between Washington and Tehran.','Die Europaeische Union und die E3 (Frankreich, Deutschland, Grossbritannien) gestalten ihre Iran-Politik um den Erhalt diplomatischer Kanaele bei gleichzeitig kalibriertem Druck auf Anreicherung und Proliferation. Das Vokabular: "JCPOA-Erhalt", "Wiener Gespraeche", "Snapback-Mechanismus", "IAEA-Sicherheitsmassnahmen", "diplomatische Ausfahrt", "engagieren statt isolieren", "Rueckkehr zur Einhaltung", "kalibrierter Druck". Das Narrativ benennt explizit Anreicherungs-Eskalation, Raketentransfers und IAEA-Kooperation als Probleme, lehnt jedoch unilateraere Militaerschlaege als Antwort ab und bevorzugt nachhaltige Diplomatie ueber multilaterale Institutionen. Vorschrift: Gespraeche am Leben erhalten, Snapback als Druckmittel statt als Vollzug einsetzen und die EU als unverzichtbare Vermittlerin zwischen Washington und Teheran positionieren.',ARRAY['NON-STATE-EU','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-UK'],ARRAY['preserve diplomacy','diplomatic off-ramp','multilateral framework','engage rather than isolate','de-escalation','return to negotiations','snapback','JCPOA-plus','Vienna talks','Normandy Format','two-state solution','strategic ambiguity','international law','EU as convener','dialogue','must stop','must be resolved','resolved through dialogue','return to diplomacy','striving for return to diplomacy','firmness and dialogue','dialogue with US','Kaja Kallas','EU foreign affairs','EU foreign affairs chief','Tajani','Parolin','Vatican','Pope Leo','Meloni','EU eyeing','no to escalation','EU-US relations','preserve the deal','support every initiative','oppose military action','resume talks','restore JCPOA','talks','Iran talks','nuclear talks','Iran nuclear talks','US-Iran nuclear talks','negotiations','negotiating','mediates','Oman mediates','critical stage','reach a deal','no deal','without a deal','deal or','nuclear deal','Iran nuclear deal','stand-off','deal deadline','failed deals','continue talks','resume talks','scheduled for','ceasefire','fragile ceasefire','ceasefire deal','Iran ceasefire','mediation','mediation efforts','mediator','mediating','stop the war','end the war','stop Iran war','end Iran war','vote to stop','Senate vote to stop','Macron urges','Macron pushes','Macron calls','Macron presses','urges restraint','calls for restraint','calls for ceasefire','urges Trump','urges Iran','diplomatic effort','diplomatic push','diplomatic relation','diplomatic relations','diplomatic channel','Vatican','Pope','Pope Leo','Kallas warns','Kallas urges','Kallas eyes','Kallas says','Borrell','von der Leyen','EU naval mission','civilisational erasure','fund people not bombs','movement against war','against war in Iran','deal can be done','deal with Iran','Iran deal','fragile','distracts from','cessez-le-feu','tregua','trêve','négociation','negociation','négocier','diplomatie','diplomatique','plaide','urge','appelle','dialogue avec','le dialogue','au dialogue','du dialogue','Waffenruhe','Waffenstillstand','Verhandlung','Verhandlungen','Verhandlungstisch','Diplomatie','diplomatisch','diplomatische','Friedensgespräch','Friedensgespraech','Friedensgespraeche','mahnt','fordert','draengt','drangt','drängt','tregua','cessate il fuoco','negoziato','negoziati','trattativa','trattative','diplomatico','diplomatica','mediazione','alto el fuego','alto-el-fuego','negociación','negociaciones','diplomático','diplomática','mediación','mediador'],true,ARRAY['BBC','BBC World','The Guardian','Financial Times','The Independent','The Times','Le Monde','Le Figaro','France 24','France 24 (EN)','RFI','Liberation','FAZ','Frankfurter Allgemeine Zeitung','Suddeutsche Zeitung','Deutsche Welle','DW','Der Spiegel','Spiegel','Tagesspiegel','Handelsblatt','ANSA','La Repubblica','Corriere della Sera','La Stampa','Il Sole 24 Ore','El Pais','El País','El Mundo','ABC España','La Vanguardia','Euronews','Politico Europe','Politico EU','Euractiv','EUobserver'],'iran_theater',3,'Engage and criticise','Engagieren und kritisieren',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('multipolar_systemic_alternative','Multipolar sovereignty backing for Iran','Multipolare Souveraenitaetsdeckung fuer Iran','China, Russia, the DPRK, and Global South commentary frame the Iran confrontation as US-Israeli "hegemony" and "interference" against a sovereign state. The argument: enrichment is a legitimate "sovereign right" under hostile sanctions and standing military threat from Israel; the actual escalator is American-Israeli pressure, not Iranian conduct. The vocabulary is "sovereignty", "unilateralism", "collective punishment via sanctions", "diktat", "imperialism", "BRICS solidarity", "Global South", and "dollar de-dependence". The narrative is not Iranian self-defence (that lives in iran_sovereign_existence) — it is the external multipolar voice that legitimises Iran''s position by framing Western pressure as systemic aggression. Prescription: Russia-China-Iran-DPRK alignment as counterweight, BRICS+ expansion, sanctions relief through multipolar institutions, and rejection of Washington''s right to set the terms.','China, Russland, die DVRK und Kommentatoren des Globalen Suedens rahmen die Iran-Konfrontation als US-israelische "Hegemonie" und "Einmischung" gegen einen souveraenen Staat. Die Argumentation: Anreicherung ist ein legitimes "souveraenes Recht" unter feindlichen Sanktionen und permanenter israelischer Militaerdrohung; der eigentliche Eskalator ist amerikanisch-israelischer Druck, nicht iranisches Verhalten. Das Vokabular: "Souveraenitaet", "Unilateralismus", "Kollektivstrafe durch Sanktionen", "Diktat", "Imperialismus", "BRICS-Solidaritaet", "Globaler Sueden", "Dollar-Entkopplung". Das Narrativ ist keine iranische Selbstverteidigung (diese lebt in iran_sovereign_existence) — es ist die externe multipolare Stimme, die Irans Position durch die Rahmung westlichen Drucks als systemische Aggression legitimiert. Vorschrift: Russland-China-Iran-DVRK-Allianz als Gegengewicht, BRICS+-Erweiterung, Sanktionsentlastung durch multipolare Institutionen, Zurueckweisung von Washingtons Anspruch, die Bedingungen zu setzen.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA','MIDEAST-IRAN','ASIA-NORKOREA'],ARRAY['US hegemony','Western hegemony','unilateralism','imperialism','Cold War mentality','collective punishment','foreign occupation','multipolar','multipolar world','multipolar order','BRICS','Global South','sovereign right','inalienable right','anti-sanctions','dollar de-dependence','dollar hegemony','US dollar hegemony','de-dollarisation','de-dollarization','encirclement','US bases','US bases in Middle East','US bases in region','imperial overreach','imperial pressure','double standards','second-class nation','economic terrorism'],true,ARRAY['RT','RT News','TASS','TASS (EN)','Sputnik','RIA Novosti','Xinhua','Global Times','China Daily','CGTN','Al Jazeera','Al Jazeera English','TeleSUR','Granma','Express Tribune','The Express Tribune','Dawn'],'iran_theater',4,'Sovereignty principle','Souveraenitaetsprinzip',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('israel_preemptive_strike_doctrine','Israel: preemptive and reactive strikes against an existential nuclear-bound enemy','Israel: praeventive und reaktive Schlaege gegen einen existenziellen, nuklear strebenden Gegner','Israeli sources frame direct exchanges with Iran as preemptive and reactive self-defense against an enemy openly committed to Israel''s destruction and pursuing nuclear weapons capability. The Begin Doctrine (strike a nuclear adversary before it can strike you) is the operational principle. Targets are presented as legitimate military: IRGC command, air defense, missile production, nuclear-related sites. Iranian missile/drone waves are framed as failed Iranian aggression neutralized by Iron Dome / Arrow / David''s Sling and US/UK/French/Jordanian air defense cooperation. The vocabulary is "Begin Doctrine", "preemption", "existential nuclear threat", "deterrence restoration", "Iron Dome", "Arrow 3", "regional defense coalition", "Iran''s axis cut down". Prescription: continue degrading Iranian nuclear, IRGC, and proxy capabilities; reject diplomatic engagement that leaves Iran a nuclear threshold state.','Israelische Quellen rahmen direkte Schlagabtausche mit dem Iran als praeventive und reaktive Selbstverteidigung gegen einen Gegner, der offen Israels Zerstoerung anstrebt und Nuklearwaffenfaehigkeit verfolgt. Die Begin-Doktrin (einen nuklearen Gegner zuerst treffen) ist das operative Prinzip. Ziele gelten als legitim militaerisch: IRGC-Kommando, Luftabwehr, Raketenproduktion, nuklear-nahe Anlagen. Iranische Raketen-/Drohnen-Wellen werden als gescheiterte iranische Aggression dargestellt, neutralisiert durch Iron Dome, Arrow und David''s Sling sowie US-/UK-/franzoesische und jordanische Luftabwehr-Kooperation. Vokabular: "Begin-Doktrin", "Praevention", "existenzielle nukleare Bedrohung", "Wiederherstellung der Abschreckung", "Iron Dome", "Arrow 3", "regionale Verteidigungskoalition". Vorschrift: iranische Nuklear-, IRGC- und Stellvertreter-Kapazitaeten weiter abbauen; diplomatische Loesungen ablehnen, die den Iran als Nuklear-Schwellenstaat belassen.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['Begin Doctrine','preemption','existential nuclear threat','Iron Dome','Arrow 3','David''s Sling','regional defense coalition','IRGC neutralized','Iranian missiles intercepted','deterrence restored','nuclear threat eliminated'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Fox News','Arutz Sheva','Ynetnews'],'israel_iran_strikes',1,'Preemptive defense against Iran','Praeventive Verteidigung gegen Iran',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_legitimate_retaliation_doctrine','Iran-aligned: Iranian retaliation is legitimate state self-defense under the UN Charter','Iran-orientiert: iranische Vergeltung ist legitime staatliche Selbstverteidigung gemaess der UN-Charta','Iranian and aligned outlets (Press TV, Fars, IRNA, Al Mayadeen, RT, CGTN, TRT World) frame Iranian missile and drone strikes on Israel as legitimate state self-defense under Article 51 of the UN Charter, responding to Israeli aggression (consulate strike in Damascus, assassinations of IRGC and Hezbollah leadership on Iranian and allied soil, strikes on Iranian air defenses and nuclear-related sites). Operation True Promise is celebrated as the first direct Iranian strike on Israel that established a new deterrence equation. The vocabulary is "Operation True Promise", "Article 51", "legitimate retaliation", "deterrence restored", "Zionist regime", "axis of resistance", "Israeli aggression", "consulate attack", "martyrs of the IRGC". Prescription: maintain the new strike-for-strike equation; continue building axis-of-resistance coordination; develop nuclear deterrence capability if necessary.','Iranische und verbuendete Medien (Press TV, Fars, IRNA, Al Mayadeen, RT, CGTN, TRT World) rahmen iranische Raketen- und Drohnenangriffe auf Israel als legitime staatliche Selbstverteidigung gemaess Artikel 51 der UN-Charta — als Antwort auf israelische Aggression (Konsulatsschlag in Damaskus, Liquidierung von IRGC- und Hisbollah-Fuehrung auf iranischem und verbuendetem Boden, Schlaege gegen iranische Luftabwehr und nuklear-nahe Anlagen). "Operation Wahres Versprechen" gilt als erster direkter iranischer Schlag gegen Israel, der eine neue Abschreckungsgleichung etablierte. Vokabular: "Operation Wahres Versprechen", "Artikel 51", "legitime Vergeltung", "wiederhergestellte Abschreckung", "zionistisches Regime", "Achse des Widerstands", "israelische Aggression", "Konsulatsangriff", "Maertyrer des IRGC". Vorschrift: die neue Schlag-gegen-Schlag-Gleichung aufrechterhalten; den Aufbau einer Achsen-Koordination fortsetzen; nukleare Abschreckungs-Kapazitaet bei Bedarf entwickeln.',ARRAY['MIDEAST-IRAN','MIDEAST-LEVANT'],ARRAY['Operation True Promise','Article 51','legitimate retaliation','Zionist regime','axis of resistance','Israeli aggression','consulate attack','IRGC martyrs','deterrence','new equation','strike for strike','Iranian self-defense'],true,ARRAY['Press TV','Fars News','IRNA','Al Mayadeen','Al Jazeera','RT','TASS (EN)','CGTN','TRT World','Anadolu Agency'],'israel_iran_strikes',2,'Iran''s legitimate state self-defense','Legitime staatliche Selbstverteidigung Irans', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('israel_self_defense_north','Israel: push Hezbollah north of the Litani; restore northern security','Israel: Hisbollah nordwaerts vom Litani zurueckdraengen, Sicherheit im Norden wiederherstellen','Israeli sources frame the northern border conflict as a self-defense theater triggered by Hezbollah''s October 8 "support front" and rocket fire that displaced ~60,000 Israelis from the Galilee. Operational goal: restore UN Resolution 1701 by force, push Hezbollah north of the Litani, eliminate its precision-guided missile arsenal and senior command. Beirut strikes on Hezbollah leadership (including Nasrallah) are presented as legitimate decapitation operations. The vocabulary is "Hezbollah aggression", "northern displaced", "Litani", "1701 enforcement", "precision-guided missile project", "deterrence restored", "decapitation strike". Prescription: continue military pressure until Hezbollah accepts withdrawal from the border zone; reject any diplomatic settlement that leaves Hezbollah''s arsenal in place.','Israelische Quellen rahmen den Nordgrenzkonflikt als Selbstverteidigungs-Front, ausgeloest durch die Hisbollah-"Unterstuetzungsfront" vom 8. Oktober und Raketenbeschuss, der rund 60.000 Israelis aus Galilaea vertrieb. Operatives Ziel: Umsetzung der UN-Resolution 1701 mit Gewalt, Hisbollah nordwaerts des Litani, Beseitigung des Praezisions-Raketenarsenals und der Fuehrung. Schlaege gegen die Hisbollah-Fuehrung in Beirut (darunter Nasrallah) gelten als legitime Enthauptungs-Operationen. Vokabular: "Hisbollah-Aggression", "Vertriebene im Norden", "Litani", "Durchsetzung der 1701", "Praezisions-Raketenprogramm", "wiederhergestellte Abschreckung", "Enthauptungsschlag". Vorschrift: militaerischen Druck fortsetzen, bis die Hisbollah den Rueckzug aus der Grenzzone akzeptiert; jede diplomatische Loesung ablehnen, die ihr Arsenal belaesst.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['Hezbollah aggression','northern displaced','Litani','1701','UNSCR 1701','precision-guided','decapitation','Nasrallah eliminated','Galilee','northern Israel','rocket fire','deterrence'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Fox News','Arutz Sheva','Ynetnews'],'israel_lebanon_border',1,'Restore northern security','Sicherheit im Norden wiederherstellen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hezbollah_resistance_north','Hezbollah and aligned: northern front as legitimate solidarity resistance','Hisbollah und verbuendet: Nordfront als legitimer Solidaritaets-Widerstand','Hezbollah-aligned outlets (Al Mayadeen, Press TV, Al-Akhbar) and pan-Arab commentary frame the northern front as legitimate solidarity resistance with Gaza. Hezbollah''s rocket fire is presented as proportionate pressure on the IDF to ease Gaza operations; Israeli strikes on Beirut suburbs are framed as collective punishment of Lebanon and assassinations of resistance leadership. The vocabulary is "support front", "solidarity with Gaza", "Israeli aggression on Lebanon", "Beirut massacre", "Dahieh", "martyrs of the resistance", "victory of the resistance". Prescription: continue military pressure on Israel until Gaza ceasefire; reject Lebanese state cooperation with Israeli security demands; preserve Hezbollah as the de facto deterrent against Israel.','Hisbollah-nahe Medien (Al Mayadeen, Press TV, Al-Akhbar) und panarabische Stimmen rahmen die Nordfront als legitimen Solidaritaets-Widerstand mit Gaza. Hisbollah-Raketenbeschuss gilt als verhaeltnismaessiger Druck auf die IDF zur Entlastung Gazas; israelische Schlaege auf Beiruter Vororte gelten als Kollektivstrafe gegen den Libanon und Liquidierungen der Widerstandsfuehrung. Vokabular: "Unterstuetzungsfront", "Solidaritaet mit Gaza", "israelische Aggression gegen den Libanon", "Massaker in Beirut", "Dahieh", "Maertyrer des Widerstands", "Sieg des Widerstands". Vorschrift: militaerischen Druck auf Israel fortsetzen, bis ein Gaza-Waffenstillstand erreicht ist; libanesische Staatskooperation mit israelischen Sicherheitsforderungen ablehnen; Hisbollah als faktische Abschreckung gegen Israel erhalten.',ARRAY['MIDEAST-LEVANT','MIDEAST-IRAN'],ARRAY['support front','solidarity with Gaza','Israeli aggression','Beirut massacre','Dahieh','martyrs','resistance victory','Lebanese sovereignty','collective punishment','assassinations','aggression on Lebanon'],true,ARRAY['Al Jazeera','Press TV','Al Mayadeen','Fars News','IRNA','Anadolu Agency','TRT World','Daily Sabah','Middle East Eye'],'israel_lebanon_border',2,'Resistance against Israeli aggression','Widerstand gegen israelische Aggression', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('israel_existential_self_defense','Israel: existential self-defense against multi-front Iran-led axis','Israel: existenzielle Selbstverteidigung gegen eine vom Iran gefuehrte Mehrfrontenachse','Israeli sources and pro-Israel commentary frame the post-October 7 conflict as a multi-front fight for survival against an Iran-orchestrated axis (Hamas, Hezbollah, Houthis, Shia militias). The October 7 attacks, hostage situation, ongoing Hezbollah rocket fire, Houthi Red Sea attacks, and direct Iranian missile/drone waves are read as components of a single coordinated assault. The vocabulary is "right of self-defense", "October 7", "hostages", "axis of resistance / Iranian axis", "Iron Sword", "northern front", "preemption", "deterrence restoration". Prescription: dismantle Hamas, push Hezbollah north of the Litani, restore deterrence against Iran, free the hostages.','Israelische Quellen und pro-israelische Kommentatoren rahmen den Konflikt seit dem 7. Oktober als Mehrfrontenkampf ums Ueberleben gegen eine vom Iran gelenkte Achse (Hamas, Hisbollah, Houthi, schiitische Milizen). Der 7. Oktober, die Geiseln, anhaltender Raketenbeschuss der Hisbollah, Houthi-Angriffe im Roten Meer und direkte iranische Raketen-/Drohnen-Wellen werden als Teile eines koordinierten Angriffs gelesen. Vokabular: "Selbstverteidigungsrecht", "7. Oktober", "Geiseln", "iranische Achse", "Eiserne Schwerter", "Nordfront", "Praevention", "Wiederherstellung der Abschreckung". Vorschrift: Hamas zerschlagen, Hisbollah nordwaerts vom Litani draengen, Abschreckung gegenueber Iran wiederherstellen, Geiseln befreien.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['right of self-defense','October 7','7 October','hostages','axis of resistance','Iranian axis','Iron Sword','northern front','deterrence','preemption','existential','Hamas terror','antisemitism','never again','Iron Dome','Holocaust survivors','dismantle Hamas','liberate hostages'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Fox News','Israel Hayom','The Jerusalem Post','Arutz Sheva','Ynetnews'],'israel_theater',1,'Existential self-defense','Existenzielle Selbstverteidigung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('palestine_genocide_framing','Pan-Arab / pro-Palestinian: Israel commits systemic violence against Palestinians','Panarabisch / propalaestinensisch: Israel veruebt systemische Gewalt an Palaestinensern','Al Jazeera, TRT World, Press TV, Palestinian outlets, and increasingly broad international human-rights commentary frame Israeli military operations across Gaza, Lebanon, and the West Bank as systemic violence amounting to genocide, ethnic cleansing, or apartheid. Evidence cited: civilian death tolls, famine conditions in Gaza, displacement, settlement expansion, the ICJ genocide case, ICC arrest warrants. The vocabulary is "genocide", "apartheid", "ethnic cleansing", "siege", "collective punishment", "occupation", "settler-colonial", "open-air prison", "Nakba continues". Prescription: immediate ceasefire, end of the siege, accountability via ICC/ICJ, end of US military aid, recognition of Palestinian statehood.','Al Jazeera, TRT World, Press TV, palaestinensische und zunehmend internationale Menschenrechts-Stimmen rahmen israelische Operationen in Gaza, Libanon und Westjordanland als systemische Gewalt — als Genozid, ethnische Saeuberung oder Apartheid. Argumente: zivile Opferzahlen, Hunger in Gaza, Vertreibung, Siedlungserweiterung, IGH-Genozidklage, IStGH-Haftbefehle. Vokabular: "Genozid", "Apartheid", "ethnische Saeuberung", "Belagerung", "Kollektivstrafe", "Besatzung", "Siedler-Kolonialismus", "fortgesetzte Nakba". Vorschrift: sofortiger Waffenstillstand, Ende der Belagerung, Rechenschaft via IStGH/IGH, Ende der US-Militaerhilfe, Anerkennung Palaestinas.',ARRAY['MIDEAST-PALESTINE','MIDEAST-LEVANT','MIDEAST-IRAN','MIDEAST-GULF','MIDEAST-TURKEY'],ARRAY['genocide','apartheid','ethnic cleansing','siege','collective punishment','occupation','settler-colonial','Nakba','famine','starvation','war crimes','ICJ','ICC','massacre','displaced','displacement','illegal occupation','open-air prison'],true,ARRAY['Al Jazeera','Press TV','TRT World','Anadolu Agency','Daily Sabah','Al-Ahram','Arab News','Fars News','IRNA','Al Arabiya','Khaleej Times','Gulf News'],'israel_theater',2,'Genocide and dispossession','Genozid und Vertreibung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eu_two_state_pathway','EU/E3 two-state framework: condemn excesses on both sides, preserve the negotiated horizon','EU/E3 Zweistaaten-Rahmen: Exzesse auf beiden Seiten verurteilen, die Verhandlungsperspektive bewahren','European Union and E3 (France, Germany, United Kingdom) coverage frames the Israeli-Palestinian conflict around preserving a negotiated two-state pathway. The position is genuinely two-sided: condemn Hamas''s October 7 attacks AND condemn disproportionate Israeli force in Gaza; defend Israeli existence AND defend Palestinian self-determination; sanction settler violence AND maintain security cooperation with the IDF. The vocabulary is "two-state solution", "international humanitarian law", "proportionality", "civilian protection", "settlement expansion is illegal under international law", "negotiated political horizon", "Abraham Accords extension". Prescription: sustained diplomatic pressure on all parties, humanitarian corridors, sanctions on extremist settlers, support for the Palestinian Authority and reformed governance.','Die EU und die E3 (Frankreich, Deutschland, Grossbritannien) rahmen den israelisch-palaestinensischen Konflikt um den Erhalt eines verhandelten Zweistaatenpfads. Position genuin doppelseitig: Verurteilung der Hamas-Angriffe vom 7. Oktober UND Verurteilung unverhaeltnismaessiger israelischer Gewalt in Gaza; Verteidigung israelischer Existenz UND palaestinensischer Selbstbestimmung; Sanktionen gegen Siedlergewalt UND Aufrechterhaltung der Sicherheitskooperation mit der IDF. Vokabular: "Zweistaatenloesung", "humanitaeres Voelkerrecht", "Verhaeltnismaessigkeit", "Schutz von Zivilisten", "Siedlungserweiterung ist voelkerrechtswidrig", "Verhandlungsperspektive", "Abraham-Abkommen". Vorschrift: nachhaltiger diplomatischer Druck auf alle Parteien, humanitaere Korridore, Sanktionen gegen extremistische Siedler, Unterstuetzung einer reformierten Palaestinensischen Autonomiebehoerde.',ARRAY['NON-STATE-EU','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-UK'],ARRAY['two-state solution','two-state','international humanitarian law','proportionality','civilian protection','settlement expansion','Abraham Accords','negotiated solution','political horizon','UN Resolution 242','UN Resolution 1701','calibrated pressure','de-escalation','restraint','ceasefire negotiations'],true,ARRAY['The Guardian','Le Monde','El País','Tagesschau','Deutsche Welle','Die Zeit','Euronews','Frankfurter Allgemeine','Corriere della Sera','La Repubblica','Sky News','Financial Times','BBC World','Reuters','Associated Press','France 24','France 24 (EN)','Handelsblatt','El Mundo'],'israel_theater',3,'EU/E3 two-state pathway','EU/E3 Zweistaaten-Linie',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('multipolar_anti_israel_alignment','Russia / China / Global South: Israel as US-backed colonial outlier','Russland / China / Globaler Sueden: Israel als US-gestuetzte koloniale Ausnahme','Russian, Chinese, and Global South commentary frames Israel as a US-backed colonial project whose actions violate the UN Charter and international law. The argument: Israel''s actions in Gaza, Lebanon, and the West Bank are not isolated security responses but expressions of the same US-led "unipolar" hegemony Russia and China oppose worldwide; sanctions evasion via the Abraham Accords; weaponized impunity at the UN Security Council via US veto. The vocabulary is "unipolar hegemony", "US-Israeli collusion", "veto power abuse", "double standards", "BRICS solidarity with Palestine", "South African ICJ case", "Global South coalition". Prescription: BRICS+ recognition of Palestine, Russia-China-Iran coordination on sanctions / pressure, dollar de-dependence, UN Security Council reform.','Russische, chinesische und Stimmen des Globalen Suedens rahmen Israel als US-gestuetztes Kolonialprojekt, dessen Handeln gegen die UN-Charta und das Voelkerrecht verstoesst. Argumentation: Israels Vorgehen in Gaza, Libanon und Westjordanland sei keine isolierte Sicherheitsantwort, sondern Ausdruck derselben US-gefuehrten "unipolaren" Hegemonie, gegen die sich Russland und China weltweit stellen; Straflosigkeit per US-Veto im Sicherheitsrat. Vokabular: "unipolare Hegemonie", "US-israelische Komplizenschaft", "Vetomissbrauch", "doppelte Standards", "BRICS-Solidaritaet mit Palaestina", "IGH-Klage Suedafrikas", "Koalition des Globalen Suedens". Vorschrift: BRICS+-Anerkennung Palaestinas, Russland-China-Iran-Koordination bei Sanktionen, Dollar-Entkopplung, Reform des UN-Sicherheitsrats.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','MIDEAST-IRAN','ASIA-SOUTHASIA'],ARRAY['unipolar hegemony','US-Israeli collusion','double standards','veto abuse','BRICS solidarity','Global South','South African ICJ','Global South coalition','UNGA recognition','impunity','colonial outpost','US imperialism','Western hypocrisy','sanctions diktat','UN reform'],true,ARRAY['RT','TASS (EN)','CGTN','China Daily','Press TV','Fars News','IRNA','Anadolu Agency','Daily Sabah','TRT World','Al Mayadeen','Granma','Telesur','WION','NDTV','Hindustan Times'],'israel_theater',4,'Multipolar anti-Israel alignment','Multipolare Anti-Israel-Stimmen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('memory_political_leverage','Historical grievances are raised as political leverage in a deteriorating relationship','Historische Vorwürfe werden als politisches Druckmittel in einer sich verschlechternden Beziehung eingesetzt','Leverage framing (Japanese and Western press) reports historical disputes primarily as a barometer of the wider political relationship: a ritual offering to Yasukuni or a rank-renaming is noted for the reaction it will provoke in Beijing rather than adjudicated, prime-ministerial observances are described as made in a private capacity, and the timing of archive openings, relic-restitution campaigns and anniversary commemorations is read against the state of bilateral ties. It neither endorses nor rebuts the historical charges, and records Tokyo''s rejection of the militarism framing attached to them. Vocabulary: risks China''s wrath, backlash, tribute, ritual offering, private capacity, amid tensions, row.','Die Druckmittel-Rahmung (japanische und westliche Presse) berichtet historische Streitfragen vor allem als Barometer des politischen Verhältnisses: Eine rituelle Opfergabe an den Yasukuni-Schrein oder eine Umbenennung von Dienstgraden wird wegen der zu erwartenden Reaktion in Peking vermerkt, nicht inhaltlich entschieden; Besuche von Regierungschefs werden als in privater Eigenschaft erfolgt beschrieben; der Zeitpunkt von Archivöffnungen, Restitutionskampagnen und Gedenktagen wird am Zustand der bilateralen Beziehungen gelesen. Die historischen Vorwürfe werden weder bestätigt noch zurückgewiesen.',ARRAY['ASIA-JAPAN'],ARRAY['risks','wrath','anger','backlash','rebuff','rebuts','tribute','offering','private capacity','personal','tensions','row','amid','deteriorating','Zorn','Empörung'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','朝日新聞','Reuters','Bloomberg','Financial Times','Wall Street Journal','The Telegraph','The Economist','The Guardian','Straits Times','Channel NewsAsia','Deutsche Welle'],'japan_china_memory_wars',1,'History as leverage','Geschichte als Druckmittel',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('memory_historical_accountability','Japan has never reckoned with its wartime aggression and continues to honour war criminals','Japan hat seine Kriegsaggression nie aufgearbeitet und ehrt weiterhin Kriegsverbrecher','Accountability framing (Chinese state media, echoed by Russian outlets) holds that Japan has never genuinely reckoned with its war of aggression: offerings to Yasukuni honour convicted war criminals, denial of the Nanjing Massacre and of the coercion of "comfort women" persists among right-wing figures, wartime rank titles are being restored, abandoned chemical weapons remain undestroyed, and looted cultural relics remain unreturned. Newly opened archives and scholar campaigns are presented as undeniable evidence, and the historical record is explicitly linked to a present-day militarist drift that the victimized countries are urged not to forget. Vocabulary: reflect on history, face history of aggression, war criminals, notorious shrine, denial, painful lessons, looted relics, restitution, revisionism.','Die Verantwortungs-Rahmung (chinesische Staatsmedien, aufgegriffen von russischen Medien) sieht Japans Aufarbeitung seines Angriffskriegs als nie erfolgt an: Opfergaben am Yasukuni-Schrein ehrten verurteilte Kriegsverbrecher, die Leugnung des Massakers von Nanking und der Zwangsrekrutierung von "Trostfrauen" halte im rechten Spektrum an, Dienstgrade aus der Kriegszeit würden wiedereingeführt, zurückgelassene Chemiewaffen seien unvernichtet und geraubte Kulturgüter unzurückgegeben. Neu geöffnete Archive gelten als unwiderlegbarer Beleg; die historische Bilanz wird ausdrücklich mit einer gegenwärtigen militaristischen Tendenz verknüpft.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA'],ARRAY['reflect on history','face history','aggression','war criminal','notorious','worship','glorif','denial','deny','undeniable','painful lessons','not forget','looted','return','restitution','rubbing salt','victimized','right-wing','revisionis','postwar norms','Geschichte','Aggression'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch','RT','TASS','TASS (EN)','Sputnik'],'japan_china_memory_wars',2,'Historical accountability demand','Forderung nach historischer Verantwortung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jc_taiwan_japan_security_stake','A Taiwan contingency directly threatens Japan''s security and Japan is entitled to say so','Ein Taiwan-Konflikt bedroht Japans Sicherheit unmittelbar, und Japan darf dies aussprechen','Security-stake framing (Japanese and Western press) holds that Taiwan''s proximity to Japan''s southwestern islands makes a Taiwan contingency a direct question of Japanese national survival, that a prime minister may say so openly, and that Beijing''s response -- demands for retraction, blacklists, mineral restrictions and pressure on tourism -- is coercion aimed at silencing legitimate security debate in a democracy. It reads Japan''s destroyer transits of the Taiwan Strait and its deepening ties with Washington, Manila and G7 partners as lawful and defensive. Vocabulary: contingency, survival-threatening situation, collective self-defence, coercion, rebut, deterrence, free and open Indo-Pacific.','Die Sicherheits-Rahmung (japanische und westliche Presse) sieht in der Nähe Taiwans zu Japans Südwest-Inseln eine unmittelbare Frage des nationalen Überlebens Japans; eine Regierungschefin dürfe dies offen aussprechen. Pekings Reaktion -- Rücknahmeforderungen, schwarze Listen, Rohstoffbeschränkungen und Druck auf den Tourismus -- gilt als Nötigung, die eine legitime sicherheitspolitische Debatte in einer Demokratie zum Schweigen bringen soll. Durchfahrten japanischer Zerstörer durch die Taiwanstraße und engere Bindungen an Washington, Manila und die G7 erscheinen als rechtmäßig und defensiv.',ARRAY['ASIA-JAPAN','ASIA-TAIWAN'],ARRAY['contingency','survival-threatening','collective self-defense','collective self-defence','security','coercion','pressure','rebuts','retract','deterrence','southwest islands','free and open','stands firm','Sicherheit','Nötigung'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','朝日新聞','Reuters','Bloomberg','Financial Times','Wall Street Journal','New York Times','The Economist','The Telegraph','The Guardian','Straits Times','Channel NewsAsia','Deutsche Welle','Al Jazeera','Philippine Daily Inquirer','The Hindu'],'japan_china_taiwan_question',1,'Japanese security stake','Japanisches Sicherheitsinteresse',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jc_taiwan_interference_charge','Japan''s Taiwan remarks are interference in China''s internal affairs and breach the postwar understanding','Japans Taiwan-Äußerungen sind Einmischung in Chinas innere Angelegenheiten und brechen die Nachkriegsverständigung','Interference framing (Chinese state media) holds that Taiwan is an internal Chinese affair on which Japan has no standing to comment, that the prime minister''s remarks were erroneous and unlawful, crossed a red line and violated the one-China principle and the four political documents that underpin postwar China-Japan relations, and that they -- not any Chinese response -- are the root cause of the current state of ties. Japan is called on to reflect, correct and retract, and its invocation of collective self-defence is cast as a pretext for intervention and bloc confrontation given its wartime record. Vocabulary: interference, internal affairs, erroneous remarks, red line, one-China principle, four political documents, reflect and correct, pretext, bloc confrontation.','Die Einmischungs-Rahmung (chinesische Staatsmedien) sieht Taiwan als innere Angelegenheit Chinas, zu der Japan kein Mitspracherecht habe. Die Äußerungen der Regierungschefin seien falsch und unrechtmäßig, hätten eine rote Linie überschritten und verstießen gegen das Ein-China-Prinzip sowie die vier politischen Dokumente, auf denen die Nachkriegsbeziehungen beruhen; sie seien -- und nicht etwaige chinesische Reaktionen -- die Ursache des derzeitigen Zustands der Beziehungen. Japan solle sich besinnen, korrigieren und widerrufen; die Berufung auf kollektive Selbstverteidigung gelte angesichts der Kriegsvergangenheit als Vorwand für Intervention und Blockkonfrontation.',ARRAY['ASIA-CHINA'],ARRAY['interference','internal affairs','erroneous remarks','fallacious','red line','one-China','Taiwan question','four political documents','1972','reflect','correct','retract','no right','pretext','bloc confrontation','stoking','Einmischung','innere Angelegenheiten'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch'],'japan_china_taiwan_question',2,'Chinese interference charge','Chinesischer Einmischungsvorwurf', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jc_theater_japanese_western_consensus','China''s pressure on Japan is coercion that hardens Japanese resolve rather than changing it','Chinas Druck auf Japan ist Nötigung, die Japans Entschlossenheit eher verhärtet als verändert','The Japanese and Western consensus reads the rupture as one initiated by Beijing''s reaction rather than by Tokyo''s words: a prime minister stated a security interest, and China answered with mineral controls, blacklists, a tourism collapse and detentions. Across the theater it treats Chinese pressure -- at sea around the Senkakus, in export licensing, and in the historical register -- as a single coercive repertoire that has hardened Japanese resolve, strengthened the government''s mandate, and accelerated both the defense build-up and the search for supply chains outside China.','Der japanisch-westliche Konsens deutet den Bruch als von Pekings Reaktion ausgelöst, nicht von Tokios Worten: Eine Regierungschefin benannte ein Sicherheitsinteresse, und China antwortete mit Rohstoffkontrollen, schwarzen Listen, einem Einbruch des Tourismus und Festnahmen. Über das gesamte Theater hinweg gilt chinesischer Druck -- zur See um die Senkaku-Inseln, bei Exportlizenzen und im historischen Register -- als ein einziges Nötigungsrepertoire, das Japans Entschlossenheit verhärtet, das Mandat der Regierung gestärkt und sowohl die Aufrüstung als auch die Suche nach Lieferketten außerhalb Chinas beschleunigt hat.',ARRAY['ASIA-JAPAN'],ARRAY['coercion','pressure','squeeze','deterrence','security','counter','rebuff','diversify','resolve','tensions','Nötigung','Abschreckung'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','朝日新聞','Reuters','Bloomberg','Financial Times','Wall Street Journal','New York Times','The Economist','The Telegraph','The Guardian','Straits Times','Channel NewsAsia','Deutsche Welle','Al Jazeera','Mining.com','OilPrice','Wired','CSIS','Philippine Daily Inquirer','Times of India','NDTV','VN Express'],'japan_china_theater',1,'Japanese/Western consensus','Japanisch-westlicher Konsens',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jc_theater_chinese_state_counter','Japan is breaking the postwar settlement and reviving militarism behind a pacifist facade','Japan bricht die Nachkriegsordnung und belebt hinter einer pazifistischen Fassade den Militarismus','The Chinese state counter-framing binds every strand of the theater into one account: a Japan that never atoned for its war of aggression is now hollowing out its pacifist constitution, arming for strike, and asserting a right to intervene over Taiwan that it does not possess. On this reading the prime minister''s Taiwan remarks are the root cause of the rupture, export licensing and coast guard patrols are lawful acts within Chinese jurisdiction rather than retaliation, and the historical record -- Yasukuni, Nanjing, the comfort women, looted relics -- is not a separate grievance but the evidence that the present drift is a return rather than a departure.','Die chinesische staatliche Gegen-Rahmung verbindet alle Stränge des Theaters zu einer Darstellung: Ein Japan, das seinen Angriffskrieg nie gesühnt habe, höhle nun seine Friedensverfassung aus, rüste zum Erstschlag und beanspruche ein Interventionsrecht in der Taiwan-Frage, das ihm nicht zustehe. Die Taiwan-Äußerungen der Regierungschefin gelten als Ursache des Bruchs, Exportlizenzen und Küstenwachpatrouillen als rechtmäßige Handlungen in chinesischer Zuständigkeit statt als Vergeltung, und die historische Bilanz -- Yasukuni, Nanking, die "Trostfrauen", geraubte Kulturgüter -- als Beleg dafür, dass die gegenwärtige Entwicklung eine Rückkehr und kein Aufbruch ist.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA'],ARRAY['militaris','neo-militaris','remilitariz','interference','internal affairs','erroneous remarks','reflect','correct','postwar order','historical','aggression','rights protection','in accordance with law','vigilance','Militarismus','Einmischung'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch','RT','TASS','TASS (EN)','Sputnik','Press TV'],'japan_china_theater',2,'Chinese state counter-framing','Chinesische staatliche Gegen-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jde_deterrence_response','Japan''s defense build-up is a proportionate response to China''s military expansion','Japans Verteidigungsaufbau ist eine verhältnismäßige Antwort auf Chinas militärische Expansion','Deterrence framing (Japanese and Western press) presents Japan''s counter-strike capability, higher defense spending, eased equipment-transfer rules and closer alignment with the United States, NATO and regional partners as a proportionate and exclusively defence-oriented answer to a deteriorating security environment -- Chinese naval and air activity around the southwestern islands, missile growth, and the Taiwan contingency. It records Tokyo''s rejection of the militarism charge and names China as the principal concern in its own doctrine documents. Vocabulary: deterrence, exclusively defence-oriented, severe security environment, response, capability, rebuff.','Die Abschreckungs-Rahmung (japanische und westliche Presse) stellt Japans Gegenschlagfähigkeit, höhere Verteidigungsausgaben, gelockerte Regeln für Rüstungstransfers und die engere Anbindung an die USA, die NATO und regionale Partner als verhältnismäßige und ausschließlich verteidigungsorientierte Antwort auf ein sich verschlechterndes Sicherheitsumfeld dar -- chinesische Marine- und Luftaktivitäten um die Südwest-Inseln, wachsende Raketenarsenale und einen möglichen Taiwan-Konflikt. Sie hält Tokios Zurückweisung des Militarismus-Vorwurfs fest.',ARRAY['ASIA-JAPAN'],ARRAY['deterrence','defense-oriented','defence-oriented','response','counter','rebuff','rebuts','proportionate','exclusively defensive','security environment','severe','concern','buildup','capability','Abschreckung','Verteidigung'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','朝日新聞','Reuters','Bloomberg','Financial Times','Wall Street Journal','New York Times','The Economist','The Telegraph','The Guardian','Straits Times','Channel NewsAsia','Deutsche Welle','Al Jazeera'],'japan_defense_expansion',1,'Deterrence response','Abschreckungs-Antwort',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('jde_militarism_revival','Japan is hollowing out its pacifist constitution and reviving militarism','Japan höhlt seine Friedensverfassung aus und belebt den Militarismus wieder','Militarism-revival framing (Chinese state media, echoed by Russian outlets) holds that Japan''s counter-strike missiles, rising defense budget, scrapped arms-export limits, renamed ranks and constitutional-revision push together hollow out the pacifist constitution and dismantle the postwar order imposed after 1945, revealing a state reverting to its militarist past behind a "peaceful nation" disguise. The China threat is cast as fearmongering manufactured to justify the build-up, and the international community is urged to stay vigilant and coordinate export controls in response. Vocabulary: neo-militarism, remilitarisation, revival, ghosts of militarism, pacifist mask, whitewash, postwar order, vigilance, dangerous path.','Die Militarismus-Rahmung (chinesische Staatsmedien, aufgegriffen von russischen Medien) sieht in Japans Gegenschlagraketen, steigendem Verteidigungshaushalt, gestrichenen Rüstungsexportgrenzen, umbenannten Dienstgraden und dem Vorstoß zur Verfassungsänderung eine Aushöhlung der Friedensverfassung und eine Demontage der Nachkriegsordnung von 1945: ein Staat kehre hinter der Maske einer "friedlichen Nation" zu seiner militaristischen Vergangenheit zurück. Die China-Bedrohung gilt als Angstmacherei zur Rechtfertigung der Aufrüstung.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA'],ARRAY['militaris','militariz','neo-militaris','remilitariz','revival','ghosts of militarism','pacifist mask','hollow','whitewash','postwar order','vigilance','dangerous path','clean break','crushing defeat','peaceful nation','Militarismus','Wiederbewaffnung'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch','RT','TASS','TASS (EN)','Sputnik','Press TV'],'japan_defense_expansion',2,'Militarism-revival charge','Militarismus-Vorwurf', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('kashmir_integral_to_india','Jammu and Kashmir is Indian territory; Pakistan must vacate what it holds','Jammu und Kaschmir ist indisches Territorium; Pakistan muss die besetzten Gebiete räumen','Indian sovereignty framing (Indian press) treats Jammu and Kashmir, including the areas administered by Pakistan, as Indian territory and the dispute as closed: references to the territory by third parties are rejected as unwarranted interference, Pakistan is told to vacate Gilgit-Baltistan and the areas it holds, and the constitutional changes of 2019 are presented as settled internal matters.','Die indische Souveränitätsdarstellung (indische Presse) betrachtet Jammu und Kaschmir einschließlich der von Pakistan verwalteten Gebiete als indisches Territorium und den Streit als beendet: Äußerungen Dritter zu dem Gebiet werden als unzulässige Einmischung zurückgewiesen, Pakistan wird aufgefordert, Gilgit-Baltistan und die von ihm gehaltenen Gebiete zu räumen, und die Verfassungsänderungen von 2019 gelten als geregelte innere Angelegenheit.',ARRAY['ASIA-INDIA'],ARRAY['vacate','integral','unwarranted','internal matter','Article 370','Delimitation','forcibly occupied','Solidarity Day','sovereignty','part of India','Indian territory','special status','inalienable','integraler','unteilbar','Souveränität','Artikel 370'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'kashmir_dispute',1,'Kashmir is integral to India','Kaschmir ist integraler Teil Indiens',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('kashmir_disputed_territory','Kashmir''s status is unresolved and its people are owed self-determination','Kaschmirs Status ist ungeklärt, seiner Bevölkerung steht Selbstbestimmung zu','Disputed-territory framing (Pakistani press and sympathetic Turkish and Gulf outlets) holds that Kashmir''s final status remains unresolved under UN resolutions, that India administers its portion by force and stands accused of rights violations and a crackdown, and that the territory''s people are entitled to self-determination rather than a settlement imposed from Delhi.','Die Darstellung als umstrittenes Gebiet (pakistanische Presse sowie wohlwollende türkische und Golf-Medien) besagt, dass der endgültige Status Kaschmirs nach UN-Resolutionen ungeklärt bleibt, dass Indien seinen Teil mit Gewalt verwaltet und Vorwürfen von Menschenrechtsverletzungen und Repression ausgesetzt ist, und dass der Bevölkerung Selbstbestimmung zusteht statt einer von Delhi auferlegten Lösung.',ARRAY['ASIA-PAKISTAN'],ARRAY['disputed','self-determination','UN resolution','occupied','unresolved','legal reality','unilateral','plebiscite','resistance','solidarity','rights','anti-terror law','pledge','just struggle','umstritten','Selbstbestimmung','besetzt','ungelöst'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation','Anadolu Agency','TRT World','Arab News','Daily Sabah'],'kashmir_dispute',2,'Kashmir is a disputed territory','Kaschmir ist ein umstrittenes Gebiet', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('kashmir_rights_and_restrictions','Both administrations face unrest and answer it with force','Beide Verwaltungen stehen Unruhen gegenüber und begegnen ihnen mit Gewalt','Rights-focused framing (Western mainstream and wire services) reports the line of control as dividing two administrations and concentrates on conditions on the ground on both sides of it: protests and deadly clashes in Pakistan-administered Kashmir over refugee seats and a shutdown, and detentions, demolitions, blacklisting and curbs on protest in Indian-administered Kashmir. The common thread is unrest met with force rather than either state''s territorial case.','Die menschenrechtsorientierte Darstellung (westliche Leitmedien und Nachrichtenagenturen) beschreibt die Waffenstillstandslinie als Trennung zweier Verwaltungen und konzentriert sich auf die Lage vor Ort auf beiden Seiten: Proteste und tödliche Zusammenstöße im pakistanisch verwalteten Kaschmir um Flüchtlingssitze und einen Generalstreik sowie Festnahmen, Abrisse, Verbote und Einschränkungen von Protest im indisch verwalteten Kaschmir. Gemeinsam ist beiden, dass Unruhen mit Gewalt begegnet wird und nicht der territoriale Anspruch eines der Staaten im Vordergrund steht.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN'],ARRAY['protest','rights','detention','detained','crackdown','restriction','shutdown','sentenc','demolition','spying','blacklisted','curfew','jailed','Israel model','clashes','Protest','Rechte','Festnahme','Einschränkung','مظاهر','احتجاج'],true,ARRAY['Reuters','BBC World','Associated Press','Al Jazeera','Deutsche Welle','The Guardian','France 24','France 24 (EN)','Euronews'],'kashmir_dispute',3,'Unrest and rights across the divided territory','Unruhen und Rechte im geteilten Gebiet', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alliance_deterrence_necessary','The alliance and its exercises are what hold deterrence together','Das Bündnis und seine Übungen sind das Fundament der Abschreckung','Deterrence framing (US and South Korean official and mainstream coverage plus defence-analytic outlets) holds that the combined force posture -- Freedom Shield and Ulchi exercises, US Forces Korea, extended deterrence and the Nuclear Consultative Group -- is what deters a nuclear-armed North and reassures Seoul and Tokyo. Reaffirmations of the US commitment, exercise readiness and alliance modernisation are treated as stabilising.','Die Abschreckungsrahmung (offizielle und Mainstream-Berichterstattung aus den USA und Südkorea sowie verteidigungsanalytische Fachmedien) hält die gemeinsame Streitkräfteaufstellung -- die Übungen Freedom Shield und Ulchi, die US-Streitkräfte in Korea, die erweiterte Abschreckung und die Nukleare Konsultativgruppe -- für das, was einen atomar bewaffneten Norden abschreckt und Seoul und Tokio rückversichert. Bekräftigungen der US-Zusage, Übungsbereitschaft und die Modernisierung des Bündnisses gelten als stabilisierend.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA'],ARRAY['extended deterrence','reaffirm','commitment','deterrence','readiness','combined','joint drill','military exercise','Freedom Shield','Ulchi','milestone','strengthen','bolster','RIMPAC','Abschreckung','Bekräftig'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','Euronews','Financial Times','Bloomberg','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Sky News','NPR','ABC News','Channel NewsAsia','CNA','Straits Times','The Straits Times','Fox News','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Military Times','War on the Rocks','Beyond Parallel','Carnegie Endowment'],'korea_peninsula_deterrence',1,'Deterrence posture is necessary','Abschreckungsdispositiv ist notwendig',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alliance_autonomy_strain','Seoul is pushing for autonomy and the alliance terms are being renegotiated','Seoul drängt auf Eigenständigkeit und die Bündnisbedingungen werden neu verhandelt','Autonomy framing (South Korean and Western coverage of the same alliance) treats the relationship as under renegotiation rather than settled: the transfer of wartime operational control, Seoul''s push for a "self-reliant" defence and indigenous nuclear-powered submarines, defence cost-sharing, US commanders'' remarks that land badly in Seoul, and questions raised during the South Korean election about the terms of the alliance. It is not opposition to the alliance but pressure on its distribution of control. Distinct from the Chinese framing, which is about US intentions rather than Korean agency.','Die Eigenständigkeitsrahmung (südkoreanische und westliche Berichterstattung über dasselbe Bündnis) behandelt das Verhältnis als neu verhandelbar statt als feststehend: die Übertragung der Operationskontrolle im Kriegsfall, Seouls Streben nach einer "eigenständigen" Verteidigung und nach eigenen atomgetriebenen U-Booten, die Teilung der Verteidigungskosten, Äußerungen von US-Kommandeuren, die in Seoul schlecht ankommen, und Fragen zu den Bündnisbedingungen im südkoreanischen Wahlkampf. Es ist keine Ablehnung des Bündnisses, sondern Druck auf die Verteilung der Kontrolle darin.',ARRAY['ASIA-SOUTHKOREA'],ARRAY['OPCON','operational control','self-reliant','self reliance','nuclear-powered','cost','burden-sharing','rift','strain','questions','conditions-based','dagger','transfer','indigenous','proliferation concerns','eigenständig','Kosten'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','Euronews','Financial Times','Bloomberg','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Sky News','NPR','ABC News','Channel NewsAsia','CNA','Straits Times','The Straits Times','Fox News','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Military Times','War on the Rocks','Beyond Parallel','Carnegie Endowment','Globe and Mail','Nikkei Asia'],'korea_peninsula_deterrence',2,'ROK autonomy and alliance strain','Eigenständigkeit Südkoreas und Bündnisbelastung', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('alliance_containment_instrument','Washington treats its allies as instruments for containing China','Washington behandelt seine Verbündeten als Instrumente zur Eindämmung Chinas','Instrumentalisation framing (Chinese state media) is the only stance-bearing seam in the Russian and Chinese coverage of the alliance -- the rest is neutral wire reporting of exercises. Its claim is not that the drills provoke Pyongyang but that the United States uses South Korea as a tool in its own competition with Beijing, and that friction between Seoul and Washington -- the Yellow Sea standoff, a US commander''s "dagger" remarks -- exposes the allies'' divergent interests.','Die Instrumentalisierungsrahmung (chinesische Staatsmedien) ist der einzige haltungstragende Strang in der russischen und chinesischen Berichterstattung über das Bündnis -- der Rest ist neutrale Agenturmeldung über Übungen. Ihre These lautet nicht, dass die Manöver Pjöngjang provozieren, sondern dass die Vereinigten Staaten Südkorea als Werkzeug im eigenen Wettbewerb mit Peking einsetzen und dass Reibungen zwischen Seoul und Washington -- der Zwischenfall im Gelben Meer, die "Dolch"-Äußerung eines US-Kommandeurs -- die auseinanderlaufenden Interessen der Verbündeten offenlegen.',ARRAY['ASIA-CHINA'],ARRAY['contain China','containment','tools','instrument','fundamental differences','Chinese expert','hegemon','US view of allies','pretext','bloc confrontation','Eindämmung'],true,ARRAY['CGTN','China Daily','Global Times','People''s Daily','TASS','TASS (EN)','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant'],'korea_peninsula_deterrence',3,'Allies as tools of US China-containment','Verbündete als Werkzeuge der US-Eindämmung Chinas', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('korea_allied_dual_track','Hold the line, keep the door open: deterrence alongside engagement','Die Linie halten, die Tür offen lassen: Abschreckung und Annäherung zugleich','Dual-track framing (Western, South Korean and Japanese mainstream) is the allied position across the theatre: sustain the combined deterrence posture -- exercises, US Forces Korea, extended deterrence -- while Seoul simultaneously offers de-escalation to Pyongyang through the 2018 military agreement, border easing and expressions of regret over incidents. The two are presented as complementary rather than contradictory: pressure creates the conditions for talks.','Die Zweigleisigkeit (westliche, südkoreanische und japanische Leitmedien) ist die Position der Verbündeten im gesamten Schauplatz: das gemeinsame Abschreckungsdispositiv aufrechterhalten -- Übungen, US-Streitkräfte in Korea, erweiterte Abschreckung -- während Seoul Pjöngjang zugleich Deeskalation anbietet, über das Militärabkommen von 2018, Erleichterungen an der Grenze und Bedauern über Zwischenfälle. Beides gilt als komplementär, nicht als widersprüchlich: Druck schafft die Bedingungen für Gespräche.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA','ASIA-JAPAN'],ARRAY['extended deterrence','reaffirm','commitment','readiness','coexistence','dialogue','restore','ease','trust','engagement'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','France 24','Euronews','Financial Times','Bloomberg','Bloomberg.com','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Le Monde','El País','El Mundo','The Economist','Sky News','NPR','ABC News','MSNBC','Channel NewsAsia','CNA','Straits Times','The Straits Times','Al Jazeera','Fox News','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Wire by KYODO NEWS','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Military Times','War on the Rocks','Beyond Parallel','Carnegie Endowment'],'korea_theater',1,'Allied deterrence and engagement','Abschreckung und Annäherung der Verbündeten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('korea_sanctioned_bloc','A bloc of sanctioned states drawing closer around Pyongyang','Ein Block sanktionierter Staaten rückt um Pjöngjang zusammen','Bloc framing (Russian, Belarusian and Chinese state press) presents North Korea not as an isolated pariah but as a sovereign state with partners: a nuclear status it is entitled to keep and will not trade away, a treaty-based military partnership with Moscow whose soldiers are honoured as heroes, and a restored traditional friendship with Beijing entering a "new era". Isolation is described as having failed and the relationships as lawful cooperation between states under the same sanctions, not as sanctions evasion.','Die Blockrahmung (russische, belarussische und chinesische Staatspresse) stellt Nordkorea nicht als isolierten Paria dar, sondern als souveränen Staat mit Partnern: mit einem Atomstatus, der ihm zusteht und den es nicht aufgeben wird, einer vertraglich geregelten Militärpartnerschaft mit Moskau, deren Soldaten als Helden geehrt werden, und einer wiederhergestellten traditionellen Freundschaft mit Peking, die in eine "neue Ära" eintritt. Die Isolation gilt als gescheitert und die Beziehungen als rechtmäßige Zusammenarbeit zwischen Staaten unter denselben Sanktionen, nicht als Sanktionsumgehung.',ARRAY['ASIA-NORKOREA','EUROPE-RUSSIA','ASIA-CHINA','EUROPE-BELARUS'],ARRAY['sovereign right','nuclear status','partnership','friendship','new era','allies','heroes','cooperation','mutual'],true,ARRAY['TASS','TASS (EN)','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian','CGTN','China Daily','Global Times','People''s Daily'],'korea_theater',2,'Sanctioned states drawing closer','Sanktionierte Staaten rücken zusammen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('korea_hardening_threat','A hardening threat while the pressure regime frays','Eine sich verhärtende Bedrohung, während das Druckregime ausfranst','Threat framing (Western, South Korean and Japanese mainstream plus defence-analytic outlets) reads the theatre as moving the wrong way on every axis at once: the arsenal is expanding and its status declared irreversible, Russia is paying for troops and shells in ways that may accelerate the programme, Beijing''s restored lifeline blunts what remains of sanctions, Pyongyang has formally closed the inter-Korean track, and the alliance meant to answer all of this is itself renegotiating its terms -- operational control, cost-sharing and South Korea''s push for a more self-reliant defence.','Die Bedrohungsrahmung (westliche, südkoreanische und japanische Leitmedien sowie verteidigungsanalytische Fachmedien) liest den Schauplatz als eine Entwicklung, die sich auf allen Achsen zugleich in die falsche Richtung bewegt: Das Arsenal wächst und sein Status wird für unumkehrbar erklärt, Russland bezahlt Truppen und Granaten auf eine Weise, die das Programm beschleunigen könnte, Pekings wiederhergestellte Lebensader stumpft ab, was von den Sanktionen bleibt, Pjöngjang hat den innerkoreanischen Kanal förmlich geschlossen, und das Bündnis, das darauf antworten soll, verhandelt seine eigenen Bedingungen neu -- Operationskontrolle, Kostenteilung und Südkoreas Streben nach eigenständigerer Verteidigung.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA','ASIA-JAPAN','EUROPE-UKRAINE'],ARRAY['threat','escalat','sanctions','arms','quid pro quo','drops','OPCON','self-reliant','strain','grip','lifeline','irreversible'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','France 24','Euronews','Financial Times','Bloomberg','Bloomberg.com','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Le Monde','El País','El Mundo','The Economist','Sky News','NPR','ABC News','MSNBC','Channel NewsAsia','CNA','Straits Times','The Straits Times','Al Jazeera','Fox News','Kyiv Post','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Wire by KYODO NEWS','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Military Times','War on the Rocks','Beyond Parallel','Carnegie Endowment','Corriere della Sera','Globe and Mail','The Australian','Anadolu Agency','UN News'],'korea_theater',3,'Hardening threat, fraying pressure','Härtere Bedrohung, brüchiger Druck', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('korea_us_containment_critique','US alliances on the peninsula serve the containment of China','US-Bündnisse auf der Halbinsel dienen der Eindämmung Chinas','Containment-critique framing (Chinese state media) is the only sustained adversarial line the Russian and Chinese press runs against the allied side in this theatre -- their coverage of exercises and launches is otherwise neutral wire reporting. Its claim is that Washington treats South Korea as an instrument in its competition with Beijing rather than as an ally with interests of its own, and that visible friction between Seoul and Washington exposes the divergence. It is a critique of US intentions, not a defence of Pyongyang''s.','Die Eindämmungskritik (chinesische Staatsmedien) ist die einzige dauerhaft gegnerische Linie, die die russische und chinesische Presse in diesem Schauplatz gegen die Seite der Verbündeten fährt -- ihre Berichterstattung über Übungen und Raketenstarts ist ansonsten neutrale Agenturmeldung. Ihre These lautet, dass Washington Südkorea als Instrument im Wettbewerb mit Peking behandelt statt als Verbündeten mit eigenen Interessen, und dass sichtbare Reibungen zwischen Seoul und Washington diese Divergenz offenlegen. Es ist eine Kritik an den Absichten der USA, keine Verteidigung derjenigen Pjöngjangs.',ARRAY['ASIA-CHINA'],ARRAY['contain China','containment','tools','instrument','fundamental differences','hegemon','pretext','bloc confrontation'],true,ARRAY['CGTN','China Daily','Global Times','People''s Daily','TASS','TASS (EN)','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant'],'korea_theater',4,'Allies as tools of China-containment','Verbündete als Werkzeuge der Eindämmung Chinas', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_market_opportunity','The agreement opens a large market','Das Abkommen öffnet einen großen Markt','South American coverage presents the agreement as long-delayed access to a high-value market, a diversification away from dependence on any single buyer, and a test of whether the bloc can conclude and hold a major external deal.','Südamerikanische Berichterstattung stellt das Abkommen als lange verzögerten Zugang zu einem hochwertigen Markt dar, als Diversifizierung weg von der Abhängigkeit von einem einzelnen Abnehmer und als Prüfstein dafür, ob der Block ein großes Außenabkommen abschließen und halten kann.',ARRAY['AMERICAS-BRAZIL'],ARRAY['oportunidad','oportunidade','se firmó','firmaron','assinatura','assinado','histórico','histórica','entra en vigor','entrará en vigor','vigência','apertura','abre','ganan','ganha','beneficia','exportadores','exportação','integra','multilateralismo','ratificado','ratificação','avanza','avança'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Observador','La Tercera'],'latam_eu_market_access',1,'Market opening for the bloc','Marktöffnung für den Block',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_farm_protection','The deal undercuts European farmers','Das Abkommen unterbietet Europas Bauern','Opposition framing in European coverage holds that imported beef, poultry, sugar and ethanol produced under different cost and regulatory conditions will undercut domestic producers, and that quota concessions were granted without adequate safeguards.','Die Oppositionsdarstellung in europäischen Medien hält fest, dass eingeführtes Rind-, Geflügelfleisch, Zucker und Ethanol, die unter anderen Kosten- und Regulierungsbedingungen erzeugt werden, heimische Produzenten unterbieten und dass Quotenzugeständnisse ohne ausreichende Schutzklauseln gewährt wurden.',ARRAY['NON-STATE-EU'],ARRAY['agriculteur','Bauern','Landwirt','farmer','éleveur','viande','Rindfleisch','Fleisch','volaille','poultry','concurrence','Wettbewerbs','Standards','Schutzklausel','clause de sauvegarde','protest','manifestation','quota','Quote'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','Boulevard Voltaire'],'latam_eu_market_access',2,'European farm protection','Europäischer Agrarschutz', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_environmental_critique','The deal rewards forest clearance','Das Abkommen belohnt Waldrodung','A separate European objection holds that expanding agricultural exports raises pressure on the Amazon and Cerrado, and that the agreement sits awkwardly beside the European Union''s own deforestation regulation and climate commitments.','Ein gesonderter europäischer Einwand hält fest, dass ausgeweitete Agrarexporte den Druck auf Amazonas und Cerrado erhöhen und dass das Abkommen im Widerspruch zur eigenen Entwaldungsverordnung und zu den Klimaverpflichtungen der Europäischen Union steht.',ARRAY['NON-STATE-EU'],ARRAY['déforestation','Entwaldung','Abholzung','deforestation','Amazon','Amazonas','Amazonie','Regenwald','climat','Klima','climate','Umwelt','environnement','EUDR'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','The Guardian'],'latam_eu_market_access',3,'Deforestation and climate objection','Entwaldungs- und Klimaeinwand', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_european_obstruction','Europe signs, then restricts','Europa unterzeichnet und beschränkt dann','South American coverage of the agreement''s implementation phase reports a pattern of European restriction after signature: import bans on specific products, quota exhaustion, parliamentary and judicial challenges to ratification, and standards applied as barriers, read regionally as the terms being narrowed after the deal was concluded.','Südamerikanische Berichterstattung über die Umsetzungsphase des Abkommens beschreibt ein Muster europäischer Beschränkungen nach der Unterzeichnung: Einfuhrverbote für einzelne Erzeugnisse, ausgeschöpfte Quoten, parlamentarische und gerichtliche Anfechtungen der Ratifizierung sowie als Handelshemmnis wirkende Standards -- regional gelesen als nachträgliche Verengung der vereinbarten Bedingungen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['golpe','prohíbe','prohibe','proíbe','proibiç','bloqueo','bloquea','bloqueia','paraliza','paralisa','veto','freno','frena','trava','barreira','barreras','obstácul','alerta','restric','restriç','suspende','impugna','acciona','Justiça','Justicia'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Observador','La Tercera'],'latam_eu_market_access',4,'European obstruction of the deal','Europäische Blockade des Abkommens', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_regional_agency','Courted by all sides, committed to none','Von allen umworben, keinem verpflichtet','South American coverage across all three arenas presents the region as an actor with leverage rather than a prize: playing buyers against each other, holding out for processing and value-added stages, and treating simultaneous deals with Washington, Brussels and Beijing as the point rather than a contradiction.','Südamerikanische Berichterstattung stellt die Region in allen drei Arenen als Akteur mit Verhandlungsmacht dar und nicht als Beute: Sie spielt Abnehmer gegeneinander aus, besteht auf Verarbeitung und Wertschöpfung im Land und betrachtet gleichzeitige Abkommen mit Washington, Brüssel und Peking als das Ziel und nicht als Widerspruch.',ARRAY['AMERICAS-BRAZIL'],ARRAY['soberan','estratégic','acordo','acuerdo','negociar','exporta','agregar valor','oportunidad','oportunidade'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera','El Observador'],'latam_hemispheric_theater',1,'The region negotiates for itself','Die Region verhandelt für sich selbst',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_eastern_partnership','A second partner on offer','Ein zweiter Partner steht bereit','Chinese and Russian state media present their engagement across minerals, finance and infrastructure as an alternative to Western conditionality, and frame US objections to those projects as an attempt to keep the region inside a single sphere of influence.','Chinesische und russische Staatsmedien stellen ihr Engagement bei Rohstoffen, Finanzierung und Infrastruktur als Alternative zu westlicher Konditionalität dar und werten US-Einwände gegen diese Projekte als Versuch, die Region in einer einzigen Einflusssphäre zu halten.',ARRAY['ASIA-CHINA'],ARRAY['cooperation','win-win','partnership','mutual benefit','sphere of influence','hegemon','合作','共赢'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','People''s Daily','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Izvestia','Kommersant','BelTA'],'latam_hemispheric_theater',2,'Partnership beyond the West','Partnerschaft jenseits des Westens',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_leverage_works','Leverage produced the concessions','Druckmittel haben die Zugeständnisse gebracht','America-First commentary holds that tariffs, designations and contract challenges are what actually moved South American governments, and that declining to use that leverage would cede the hemisphere''s trade terms and resource contracts to Beijing by default.','America-First-Kommentare halten fest, dass Zölle, Listungen und Auftragsanfechtungen es waren, die südamerikanische Regierungen tatsächlich bewegt haben, und dass ein Verzicht auf diese Druckmittel die Handelsbedingungen und Rohstoffverträge der Hemisphäre kampflos an Peking abträte.',ARRAY['AMERICAS-USA'],ARRAY['leverage','reciprocal','unfair','deal','concession','enforcement','hemisphere'],false,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_hemispheric_theater',3,'Pressure is the working instrument','Druck ist das wirksame Instrument',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_terms_imposed','The costs land locally','Die Kosten fallen vor Ort an','Mainstream and regional reporting treats the three arenas as variations on one asymmetry: tariffs, quota allocations and extraction contracts are largely determined abroad, while the adjustment costs -- to exporters, to public budgets, to the communities around mine sites -- are absorbed within the region.','Etablierte und regionale Berichterstattung behandelt die drei Arenen als Varianten derselben Asymmetrie: Zölle, Quotenzuteilungen und Förderverträge werden überwiegend im Ausland bestimmt, während die Anpassungskosten -- für Exporteure, öffentliche Haushalte und die Gemeinden rund um die Minen -- in der Region anfallen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['coercion','asymmetr','sovereignty','soberan','extractivis','comunidades','represalia','punish'],true,ARRAY['Reuters','Associated Press','Bloomberg','Financial Times','The Guardian','Deutsche Welle','El País','Al Jazeera','The Hindu','NPR','S&P Global','Página 12'],'latam_hemispheric_theater',4,'Terms set from outside','Von außen gesetzte Bedingungen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_european_objection','Europe resists its own agreement','Europa wehrt sich gegen sein eigenes Abkommen','European coverage carries the internal resistance to market opening: producer groups object to competition under different cost and regulatory conditions, environmental critics object to the pressure that expanded agricultural exports place on forest cover, and several member states and parliaments have moved to block or challenge ratification.','Europäische Berichterstattung trägt den internen Widerstand gegen die Marktöffnung: Erzeugerverbände wenden sich gegen Konkurrenz unter anderen Kosten- und Regulierungsbedingungen, Umweltkritiker gegen den Druck ausgeweiteter Agrarexporte auf die Waldbestände, und mehrere Mitgliedstaaten und Parlamente haben die Ratifizierung blockiert oder angefochten.',ARRAY['NON-STATE-EU'],ARRAY['agriculteur','Bauern','Landwirt','farmer','viande','Rindfleisch','déforestation','Entwaldung','Abholzung','Amazonas','Klima','Schutzklausel','ratifi','Quote','quota'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','Boulevard Voltaire'],'latam_hemispheric_theater',5,'European objection to the opening','Europäischer Einwand gegen die Öffnung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_strategic_warning','Commerce with a strategic tail','Handel mit strategischem Nachlauf','US security-oriented commentary reads Chinese port, rail and mineral holdings in the hemisphere as dual-use positioning rather than ordinary commerce, and treats each concession awarded as a durable strategic loss rather than a single contract.','US-sicherheitspolitische Kommentare deuten chinesische Hafen-, Bahn- und Mineralienbeteiligungen in der Hemisphäre als militärisch mitnutzbare Positionierung statt als gewöhnlichen Handel und werten jede vergebene Konzession als dauerhaften strategischen Verlust und nicht als einzelnen Auftrag.',ARRAY['AMERICAS-USA'],ARRAY['dual-use','strategic','military','backyard','hemisphere','Beijing','threat','influence'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_hemispheric_theater',6,'Strategic penetration warning','Warnung vor strategischer Durchdringung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_western_terms_hold','The Western offer still sets the terms','Das westliche Angebot gibt weiter den Ton an','Across trade, minerals and infrastructure, Latin American states are still choosing rules, courts and partners anchored in the Western order -- cancelling opaque concessions, upholding regulatory control and contracting with European and North American operators -- and the pressure that follows from Beijing is read as vindication of the choice rather than a reason to reverse it.','Ob Handel, Rohstoffe oder Infrastruktur: Lateinamerikanische Staaten setzen weiterhin auf Regeln, Gerichte und Partner der westlichen Ordnung -- sie annullieren intransparente Konzessionen, behaupten die regulatorische Kontrolle und vergeben Aufträge an europäische und nordamerikanische Betreiber. Der darauf folgende Druck aus Peking gilt als Bestätigung dieser Entscheidung, nicht als Grund zur Umkehr.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN','AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-USA','NON-STATE-EU'],ARRAY['ruling','court','sovereignt','control','agreement','deal','investment','partnership','de-risk','contract'],true,ARRAY['Reuters','Associated Press','AP News','Financial Times','Wall Street Journal','Bloomberg','Nikkei Asia','The Guardian','BBC News','New York Times','Washington Post','Deutsche Welle','El País','Le Monde','Euronews','EurActiv','France 24 (EN)','S&P Global','Japan Times','CNN','The Telegraph','Der Spiegel','Handelsblatt','Fox News'],'latam_hemispheric_theater',7,'Western-anchored rules prevail','Westlich verankerte Regeln setzen sich durch',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_coercion_critique','Washington coerces, Beijing is punished','Washington erzwingt, Peking wird bestraft','The region''s choices are not free ones: Washington converts commercial and legal processes into instruments of pressure, stripping Chinese firms of lawfully held assets and framing ordinary investment as a security threat, while presenting the result as Latin American sovereignty. What is described as de-risking is a hemispheric monopoly reasserted at the expense of the region''s own room to manoeuvre.','Die Entscheidungen der Region sind keine freien: Washington macht kommerzielle und juristische Verfahren zu Druckmitteln, entzieht chinesischen Unternehmen rechtmäßig gehaltene Vermögenswerte und stellt gewöhnliche Investitionen als Sicherheitsbedrohung dar -- um das Ergebnis dann als lateinamerikanische Souveränität auszugeben. Was als De-Risking bezeichnet wird, ist ein wiederhergestelltes Monopol über die Hemisphäre auf Kosten des eigenen Handlungsspielraums der Region.',ARRAY['ASIA-CHINA','ASIA-HONGKONG','EUROPE-RUSSIA'],ARRAY['cold war mentality','coercion','smear','hegemon','unilateral','interference','rights and interests','politiciz','hypocri','bullying'],true,ARRAY['Global Times','People''s Daily','CGTN','China Daily','Xinhua','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti'],'latam_hemispheric_theater',8,'Hemispheric coercion critique','Kritik an hemisphärischem Zwang', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_control_restored','Host-state control restored','Wiederhergestellte Kontrolle des Gastlandes','Courts in Panama and Peru acted lawfully to return chokepoint terminals to host-state control, closing a strategic vulnerability created by operators answerable to Beijing; China''s response -- detaining Panama-flagged vessels and pressing carriers to withdraw -- confirms the risk it was meant to address.','Gerichte in Panama und Peru haben rechtmäßig gehandelt, um Terminals an Nadelöhren wieder unter die Kontrolle des Gastlandes zu bringen und eine strategische Verwundbarkeit durch Betreiber im Einflussbereich Pekings zu beseitigen; Chinas Reaktion -- das Festhalten von Schiffen unter Panama-Flagge und der Druck auf Reedereien, sich zurückzuziehen -- bestätigt genau das Risiko, um das es ging.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN','AMERICAS-USA'],ARRAY['sovereignt','Souveränität','soberan','unconstitutional','verfassungswidrig','inconstitucional','court','Gericht','ruling','Urteil','quashed','voids','annull','takes control','take control','wrests','reclaim','takes back','ousting','ousts','ejecting','kicks','seizes','seized','hands canal','to operate','reprend le contrôle','übernimmt','zurück','security risk','Sicherheitsrisiko','vulnerab','verwundbar','de-risk','bullying','coercion','Zwang','retaliation','Vergeltung','detention','detentions','heavy price','necessary action','told Maersk','drop Panama','non-negotiable','backs Panama','joint statement'],true,ARRAY['Reuters','Financial Times','Wall Street Journal','Bloomberg','Associated Press','AP News','Nikkei Asia','Fox News','CNN','The Telegraph','Deutsche Welle','Le Monde','El País','Euronews','EurActiv','France 24 (EN)','Japan Times','S&P Global','The Guardian','BBC News','New York Times','Washington Post','Der Spiegel','Handelsblatt'],'latam_port_infrastructure_control',1,'Lawful reassertion of control','Rechtmäßige Rückgewinnung der Kontrolle',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_sovereignty_squeeze','A small state squeezed between two powers','Ein kleiner Staat zwischen zwei Mächten','Whatever the legal merits, Panama and Peru are being made the terrain of a US-China contest they did not choose: Washington backs its case with a military buildup and hemispheric-sovereignty rhetoric while Beijing answers with shipping coercion, and the host states absorb the cost of both.','Ungeachtet der Rechtslage werden Panama und Peru zum Austragungsort eines US-chinesischen Wettstreits, den sie nicht gewählt haben: Washington untermauert seine Position mit militärischem Aufmarsch und Rhetorik zur Souveränität der Hemisphäre, Peking antwortet mit Druck auf die Schifffahrt -- und die Gastländer tragen die Kosten beider Seiten.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN'],ARRAY['on edge','flexing','military might','buildup','Aufmarsch','troops','Truppen','tropas','Southern Command','squeez','caught between','zwischen den Fronten','battleground','pressure on Panama','Druck auf Panama','presión sobre Panamá','strong-arm','arm-twist','forced to choose','zur Wahl gezwungen'],false,ARRAY['Reuters','Financial Times','Wall Street Journal','Bloomberg','Associated Press','AP News','Nikkei Asia','Fox News','CNN','The Telegraph','Deutsche Welle','Le Monde','El País','Euronews','EurActiv','France 24 (EN)','Japan Times','S&P Global','The Guardian','BBC News','New York Times','Washington Post','Der Spiegel','Handelsblatt','Al Jazeera','Anadolu Agency','The Hindu','Times of India','Al Arabiya','Daily Sabah','Gulf News','Republic TV','NDTV','Straits Times'],'latam_port_infrastructure_control',2,'Great-power squeeze on the host state','Großmachtdruck auf das Gastland', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_expropriation_coercion','Expropriation under US pressure','Enteignung unter US-Druck','The port rulings were not independent justice but the product of US coercion: a lawful commercial concession was torn up and Chinese-linked assets stripped to satisfy Washington, which openly covets the waterway itself -- a cold-war reflex that punishes companies for their nationality and leaves host states less sovereign, not more.','Die Hafenurteile waren keine unabhängige Justiz, sondern das Ergebnis von US-Zwang: Eine rechtmäßige kommerzielle Konzession wurde annulliert und chinesisch verbundene Vermögenswerte enteignet, um Washington zufriedenzustellen, das offen nach der Wasserstraße selbst greift -- ein Reflex des Kalten Krieges, der Unternehmen für ihre Nationalität bestraft und die Gastländer weniger souverän zurücklässt, nicht souveräner.',ARRAY['ASIA-CHINA','ASIA-HONGKONG'],ARRAY['cold war mentality','Kalter Krieg','coveting','covets','smear','groundless','hypocri','Heuchelei','lawful','legitimate rights','rights and interests','politiciz','politicis','politisier','heavy price','interference','Einmischung','unilateral'],true,ARRAY['Global Times','People''s Daily','CGTN','China Daily','Xinhua','RT','TASS','Sputnik'],'latam_port_infrastructure_control',3,'Politicised seizure of commercial assets','Politisierte Enteignung kommerzieller Vermögenswerte', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_south_south_partnership','Cooperation brings development','Kooperation bringt Entwicklung','Chinese and Russian state media frame mineral purchases, port finance and rail construction as mutually beneficial South-South cooperation that delivers infrastructure Western lenders declined to fund, and cast US warnings about those projects as smear campaigns intended to deny the region a second partner.','Chinesische und russische Staatsmedien stellen Mineralienkäufe, Hafenfinanzierung und Bahnbau als beiderseits vorteilhafte Süd-Süd-Kooperation dar, die Infrastruktur liefert, deren Finanzierung westliche Kreditgeber ablehnten, und werten US-Warnungen vor diesen Projekten als Verleumdungskampagnen, die der Region einen zweiten Partner verwehren sollen.',ARRAY['ASIA-CHINA'],ARRAY['cooperation','win-win','partnership','development','mutual benefit','Zusammenarbeit','cooperación','beneficio mutuo','合作','共赢'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','People''s Daily','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Izvestia','Kommersant','BelTA'],'latam_resource_access',1,'South-South development partnership','Süd-Süd-Entwicklungspartnerschaft',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_sovereign_development','The region sets its own terms','Die Region setzt eigene Bedingungen','South American outlets present their governments as active agents rather than objects of competition: courting several buyers at once, legislating national minerals policy and pressing to capture processing and value-added stages domestically instead of exporting raw ore.','Südamerikanische Medien stellen ihre Regierungen als handelnde Akteure statt als Objekte des Wettbewerbs dar: Sie umwerben mehrere Abnehmer zugleich, verankern eine nationale Rohstoffpolitik gesetzlich und drängen darauf, Verarbeitung und Wertschöpfung im Land zu halten, statt Roherz auszuführen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['soberan','estratégic','agregar valor','valor agregado','política nacional','industrializ','negociar','acordo','acuerdo'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera'],'latam_resource_access',2,'Sovereign resource strategy','Souveräne Rohstoffstrategie',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_extractivism_critique','Extraction externalises its costs','Die Förderung lagert ihre Kosten aus','Critical regional coverage holds that whichever external buyer prevails, the extraction model itself transfers water, land and environmental burdens onto local and indigenous communities while the processed value accrues abroad.','Kritische regionale Berichterstattung hält fest, dass unabhängig davon, welcher externe Abnehmer sich durchsetzt, das Fördermodell selbst Wasser-, Land- und Umweltlasten auf lokale und indigene Gemeinschaften abwälzt, während die verarbeitete Wertschöpfung im Ausland anfällt.',ARRAY['AMERICAS-BRAZIL'],ARRAY['extractivis','contaminac','contaminaç','comunidades','indígena','saqueo','socioambiental','medio ambiente','meio ambiente','agua','água','protesta','protesto'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera','Página 12'],'latam_resource_access',3,'Extractivism and local cost','Extraktivismus und lokale Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_strategic_penetration','Beijing is buying strategic depth','Peking kauft strategische Tiefe','US security-oriented commentary treats Chinese port, rail and mineral holdings in the region as dual-use strategic positioning in the Western hemisphere rather than ordinary commerce, and urges Washington to contest those contracts.','US-sicherheitspolitische Kommentare werten chinesische Hafen-, Bahn- und Mineralienbeteiligungen in der Region als militärisch mitnutzbare strategische Positionierung in der westlichen Hemisphäre statt als gewöhnlichen Handel und drängen Washington, diese Aufträge zu bestreiten.',ARRAY['AMERICAS-USA'],ARRAY['dual-use','strategic','military','backyard','hemisphere','influence','threat','Beijing'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_resource_access',4,'Strategic penetration warning','Warnung vor strategischer Durchdringung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_pressure_enforcement_justified','Tariffs answer unfair practice','Zölle antworten auf unfaire Praktiken','America-First commentary holds that tariffs and designations are proportionate responses to trade practices, judicial overreach and criminal networks in the targeted states, and that leverage is the only instrument that has produced concessions.','America-First-Kommentare halten Zölle und Listungen für verhältnismäßige Antworten auf Handelspraktiken, justizielle Übergriffe und kriminelle Netzwerke in den betroffenen Staaten und sehen Druckmittel als einziges Instrument, das Zugeständnisse bewirkt hat.',ARRAY['AMERICAS-USA'],ARRAY['unfair','reciprocal','leverage','deal','concession','enforcement'],false,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'latam_us_trade_pressure',1,'Legitimate trade enforcement','Legitime Handelsdurchsetzung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_pressure_sovereignty_defense','Tariffs punish a trade partner','Zölle bestrafen einen Handelspartner','Mainstream and regional coverage treats the measures as economic coercion applied to states that run trade deficits with the United States, notes their entanglement with domestic election cycles, and reports the targeted governments seeking negotiated relief or alternative markets.','Etablierte und regionale Berichterstattung wertet die Maßnahmen als wirtschaftlichen Zwang gegen Staaten, die gegenüber den Vereinigten Staaten Handelsdefizite aufweisen, verweist auf ihre Verflechtung mit innenpolitischen Wahlzyklen und berichtet, dass die betroffenen Regierungen Verhandlungslösungen oder Alternativmärkte suchen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['coercion','retaliation','sovereignty','soberan','represalia','negotiat','punish','threat'],true,ARRAY['Reuters','Associated Press','Bloomberg','Financial Times','The Guardian','Deutsche Welle','El País','Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Al Jazeera','The Hindu','NPR','S&P Global'],'latam_us_trade_pressure',2,'Coercion against a sovereign partner','Zwang gegen einen souveränen Partner', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_externally_backed_offensive','An externally backed offensive','Eine von außen unterstützte Offensive','M23 is not a self-sustaining local rebellion but a force armed and directed from across the border, able to seize cities, strike airports with drones and hold territory because a neighbouring state supplies it. The sanctions imposed on Rwandan commanders and on Joseph Kabila are the belated recognition of a cross-border war being fought through a proxy.','M23 ist kein sich selbst tragender lokaler Aufstand, sondern eine von jenseits der Grenze bewaffnete und geführte Truppe, die Städte einnehmen, Flughäfen mit Drohnen angreifen und Gebiete halten kann, weil ein Nachbarstaat sie versorgt. Die Sanktionen gegen ruandische Kommandeure und gegen Joseph Kabila sind die späte Anerkennung eines grenzüberschreitenden Krieges, der über einen Stellvertreter geführt wird.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['backing','backed','support for','supporting','proxy','sanctions','visa restrictions','Rwandan army','Rwandan officials','offensive','seized','captured','retake','retook','occupied','incursion','soutien','soutenu','appuyé','offensive','conquise','contrôlé','Unterstützung','unterstützt','Sanktionen','Offensive'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','Financial Times','The Economist','Swissinfo','ANSA','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','TRT World','Daily Nation','Punch Newspapers','Janes'],'m23_conflict',1,'A cross-border proxy war','Ein grenzüberschreitender Stellvertreterkrieg', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_civilian_toll','The population pays for every advance','Die Bevölkerung zahlt für jeden Vorstoß','Whoever is judged responsible, the measurable result of this war is borne by civilians: thousands detained and abused in captured towns, mass displacement across the Burundian and Rwandan borders, aid workers killed by drones, and rights investigators documenting killings and rapes in Uvira. Territorial gains and losses change faster than the humanitarian damage they leave.','Wer auch immer als verantwortlich gilt: Die messbaren Folgen dieses Krieges tragen die Zivilisten. Tausende werden in eroberten Städten festgehalten und misshandelt, Massen fliehen über die burundische und ruandische Grenze, Helfer sterben durch Drohnen, und Ermittler dokumentieren Tötungen und Vergewaltigungen in Uvira. Geländegewinne wechseln schneller als der humanitäre Schaden, den sie hinterlassen.',ARRAY['AFRICA-DRC'],ARRAY['civilian','civilians','displaced','displacement','refugee','refugees','abuse','abusing','detaining','detained','atrocities','killings','rapes','massacre','aid worker','humanitarian','hunger','human rights','HRW','trauma','civils','déplacés','réfugiés','atrocités','exactions','humanitaire','traumatismes','droits humains','Zivilisten','Vertriebene','Flüchtlinge','Gräueltaten','humanitär','Menschenrechte'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','The Economist','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Der Spiegel'],'m23_conflict',2,'The humanitarian cost','Die humanitären Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_backing_charge_rejected','The accused parties reject the charge','Die Beschuldigten weisen den Vorwurf zurück','Kigali and the figures named in Western sanctions dispute the proxy account entirely. They present the sanctions as insults that will not change Rwandan defence policy, describe the designations as unjustified, and point to the armed groups operating on the Congolese side of the border and to Kinshasa''s inability to protect its own eastern population as the actual origin of the fighting.','Kigali und die in westlichen Sanktionen genannten Personen bestreiten die Stellvertreter-Darstellung vollständig. Sie bezeichnen die Sanktionen als Beleidigungen, die an Ruandas Verteidigungspolitik nichts ändern, nennen die Listungen ungerechtfertigt und verweisen auf die bewaffneten Gruppen auf kongolesischer Seite sowie auf Kinshasas Unfähigkeit, die eigene Bevölkerung im Osten zu schützen, als eigentlichen Ursprung der Kämpfe.',ARRAY['AFRICA-DRC'],ARRAY['denies','denied','denounces','denounced','rejects','rejected','unjustified','unfounded','hits back','insults','internal affairs','dément','rejette','dénonce','injustifié','weist zurück','bestreitet','ungerechtfertigt'],true,ARRAY['The Standard','Daily Nation','Mail & Guardian','Anadolu Agency','Al-Ahram','News24','Punch Newspapers','RT','TASS (EN)'],'m23_conflict',3,'The charge is disputed','Der Vorwurf ist bestritten',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cartel_offensive_progress','The militarised offensive is working: captures and takedowns weaken the cartels','Die militarisierte Offensive wirkt: Festnahmen und Schläge schwächen die Kartelle','Offensive-progress framing (Mexican establishment and wire coverage, plus US enforcement voices) presents cartel-leader captures, extraditions and army operations against CJNG and Sinaloa as concrete security gains: the state is degrading the cartels'' command. Shares a publisher pool with the narco-state critique, so it is separated by framing (capture/arrest/takedown vocabulary).','Das Offensiv-Fortschritts-Framing (mexikanische Establishment- und Agenturberichterstattung sowie US-Strafverfolgungsstimmen) stellt Festnahmen von Kartellführern, Auslieferungen und Armeeoperationen gegen CJNG und Sinaloa als konkrete Sicherheitsgewinne dar: Der Staat schwächt die Führung der Kartelle. Teilt den Publisher-Pool mit der Narco-Staat-Kritik und wird über das Framing getrennt (Vokabular von Festnahme/Verhaftung/Schlag).',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],ARRAY['capture','captured','arrest','arrested','detained','dismantle','seized','extradited','extradition','kingpin','takedown','blow to','operation','killed','handed over','captura','capturado','detención','detenido','arresto','desmantel','incautación','extraditado','abatido','golpe al','operativo','Festnahme','festgenommen','Schlag gegen','zerschlagen'],true,ARRAY['El Universal','Reforma','Mexico News Daily','El País','EL PAÍS','Reuters','Associated Press','CNN','New York Times','Washington Post','BBC World','The Guardian','Deutsche Welle','France 24 (EN)','Al Jazeera','Fox News','NPR','Bloomberg'],'mexico_cartel_war',1,'Security-offensive progress','Fortschritt der Sicherheitsoffensive',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cartel_narco_state_critique','Militarisation is failing and the state is compromised: collusion, corruption and impunity','Die Militarisierung scheitert und der Staat ist kompromittiert: Kollusion, Korruption und Straflosigkeit','Friendly-critic framing (Mexican watchdog outlets and Western investigative coverage) treats the drug war as an own-goal: officials colluding with cartels (the Sinaloa-governor indictment, the arrested security chief), a militarisation strategy that has not lowered violence, and entrenched corruption and impunity. Same publisher pool as offensive-progress; separated by collusion/failure vocabulary.','Das Framing des wohlwollenden Kritikers (mexikanische Watchdog-Medien und westliche Investigativberichterstattung) behandelt den Drogenkrieg als Eigentor: Amtsträger, die mit Kartellen kolludieren (die Anklage gegen den Sinaloa-Gouverneur, der festgenommene Sicherheitschef), eine Militarisierungsstrategie, die die Gewalt nicht gesenkt hat, sowie verfestigte Korruption und Straflosigkeit. Gleicher Publisher-Pool wie Offensiv-Fortschritt; getrennt über Kollusions-/Versagensvokabular.',ARRAY['AMERICAS-MEXICO','AMERICAS-USA'],ARRAY['collusion','complicity','complicit','narco-state','corruption','protection','impunity','militarization','militarisation','violence surges','failed','embedded','ties to cartel','cover-up','disappeared','colusión','complicidad','narcoestado','corrupción','impunidad','militarización','vínculos','nexos','desaparecidos','encubrimiento','connivencia','Kollusion','Komplizenschaft','Korruption','Straflosigkeit'],true,ARRAY['El Universal','Reforma','Mexico News Daily','El País','EL PAÍS','Reuters','Associated Press','CNN','New York Times','Washington Post','BBC World','The Guardian','Deutsche Welle','France 24 (EN)','Al Jazeera','Fox News','NPR','Bloomberg'],'mexico_cartel_war',2,'Narco-state / militarisation critique','Narco-Staat-/Militarisierungskritik', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cartel_us_culpability_rift','The cartel crisis is made in America: US drug demand and US guns fuel it, and Washington exploits it','Die Kartellkrise ist hausgemacht in Amerika: US-Drogennachfrage und US-Waffen befeuern sie, und Washington nutzt sie aus','Rift-exploitation framing (Russian and Chinese state media) shifts blame to the United States: American drug consumption and the southward flow of US firearms drive the violence, and Washington weaponises the cartel threat as a pretext to pressure and intervene in its neighbour. It is adversarial to the US, not an endorsement of the cartels.','Das Rift-Ausnutzungs-Framing (russische und chinesische Staatsmedien) verlagert die Schuld auf die USA: Amerikanischer Drogenkonsum und der Zustrom von US-Schusswaffen nach Süden treiben die Gewalt an, und Washington instrumentalisiert die Kartellbedrohung als Vorwand, um seinen Nachbarn unter Druck zu setzen und zu intervenieren. Es ist gegen die USA gerichtet, keine Billigung der Kartelle.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['US demand','American demand','US guns','American weapons','arms flow','iron river','pretext','hypocrisy','Monroe','root cause','consumers','blame Washington','drug consumption','double standard','armas estadounidenses','consumo','pretexto','hipocresía'],false,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','CGTN','Global Times','China Daily','Xinhua','Press TV'],'mexico_cartel_war',3,'US-culpability / rift-exploitation','US-Schuld / Rift-Ausnutzung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mexth_us_pressure_justified','US pressure on Mexico is justified and is producing results','Der US-Druck auf Mexiko ist gerechtfertigt und bringt Ergebnisse','The America-first framing across the theater (US conservative press): cartels are terrorists, Mexico is an unreliable partner, and covert action, indictments, tariff threats and border enforcement are legitimate leverage that has already forced concessions.','Das America-First-Framing über das gesamte Theater (US-konservative Presse): Kartelle sind Terroristen, Mexiko ist ein unzuverlässiger Partner, und verdeckte Aktionen, Anklagen, Zolldrohungen und Grenzsicherung sind legitime Druckmittel, die bereits Zugeständnisse erzwungen haben.',ARRAY['AMERICAS-USA'],ARRAY['terrorist','leverage','tough','America first','necessary','results','failed state'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','Washington Times','Daily Caller'],'mexico_theater',1,'US pressure justified','US-Druck gerechtfertigt',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mexth_western_scrutiny','US pressure strains the relationship and carries scandal and economic risk','Der US-Druck belastet die Beziehung und birgt Skandal- und Wirtschaftsrisiken','The Western mainstream and business framing: reports the confrontation critically through governance and market lenses, the CIA-in-Chihuahua scandal, diplomatic strain, supply-chain and tariff disruption, and doubts about whether Mexico''s concessions are working, rather than through nationalism or America-first triumphalism.','Das westliche Mainstream- und Wirtschaftsframing: berichtet über die Konfrontation kritisch durch Governance- und Marktlinsen, den CIA-in-Chihuahua-Skandal, diplomatische Spannungen, Lieferketten- und Zollstörungen sowie Zweifel, ob Mexikos Zugeständnisse wirken, statt durch Nationalismus oder America-First-Triumphalismus.',ARRAY['AMERICAS-USA','AMERICAS-MEXICO'],ARRAY['tensions','strains','scandal','CIA','disruption','supply chain','markets','diplomatic','escalation','uncertainty'],true,ARRAY['Reuters','Associated Press','CNN','New York Times','Washington Post','NPR','MSNBC','ABC News','BBC World','The Guardian','Financial Times','Deutsche Welle','Euronews','France 24 (EN)','France 24','Le Monde','Le Figaro','Der Spiegel','Die Zeit','Süddeutsche Zeitung','Sky News','The Telegraph','Bloomberg','Wall Street Journal','S&P Global','The Economist','Globe and Mail'],'mexico_theater',2,'Western institutional scrutiny','Westliche institutionelle Prüfung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mexth_mexican_sovereignty','US pressure violates Mexican sovereignty and dignity','Der US-Druck verletzt Mexikos Souveränität und Würde','The Mexican and Hispanic-American framing across the theater: covert operations, intervention threats, official indictments and tariff blackmail are violations of sovereignty and dignity, met by insistence on non-intervention, cooperation without subordination, counter-measures and diversification away from dependence on Washington.','Das mexikanische und hispanoamerikanische Framing über das gesamte Theater: verdeckte Operationen, Interventionsdrohungen, Anklagen gegen Amtsträger und Zoll-Erpressung sind Verletzungen der Souveränität und Würde, beantwortet mit dem Beharren auf Nichtintervention, Kooperation ohne Unterordnung, Gegenmaßnahmen und Diversifizierung weg von der Abhängigkeit von Washington.',ARRAY['AMERICAS-MEXICO'],ARRAY['soberanía','sovereignty','injerencia','interference','dignidad','no subordinación','aranceles','coerción','represalia','non-intervention'],true,ARRAY['El Universal','Reforma','Mexico News Daily','El País','EL PAÍS','El Mundo','Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo'],'mexico_theater',3,'Mexican sovereignty and anti-coercion','Mexikanische Souveränität und Anti-Zwang', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mexth_anti_hegemony_rift','US pressure on Mexico exposes American imperialism in its own backyard','Der US-Druck auf Mexiko entlarvt den amerikanischen Imperialismus im eigenen Hinterhof','The Russian and Chinese state-media framing: not support for either government but exploitation of the rift, US pressure on Mexico is Monroe-Doctrine imperialism, Washington bullies its neighbour and treats Latin America as its backyard, the cartel and migration threats are pretexts, and the episode proves the hypocrisy of the US-led order.','Das Framing der russischen und chinesischen Staatsmedien: keine Unterstützung für eine der Regierungen, sondern Ausnutzung des Risses, der US-Druck auf Mexiko ist Monroe-Doktrin-Imperialismus, Washington drangsaliert seinen Nachbarn und behandelt Lateinamerika als seinen Hinterhof, die Kartell- und Migrationsbedrohungen sind Vorwände, und der Vorfall beweist die Heuchelei der US-geführten Ordnung.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['imperialism','backyard','Monroe','bullying','hegemony','pretext','double standard','neo-colonial','sphere of influence'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','CGTN','Global Times','China Daily','Xinhua','Press TV'],'mexico_theater',4,'Russia/China rift-exploitation','Russland/China-Rift-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('myanmar_beijing_backed_normalisation','Legitimate transition, backed by Beijing','Legitimer Übergang, von Peking gestützt','Myanmar''s election and handover to a civilian-led government mark a return to constitutional order; China and other partners back the country''s sovereignty, security and stability through pragmatic cooperation and renewed engagement.','Myanmars Wahl und die Übergabe an eine zivil geführte Regierung markieren eine Rückkehr zur verfassungsmäßigen Ordnung; China und weitere Partner stützen Souveränität, Sicherheit und Stabilität des Landes durch pragmatische Zusammenarbeit und erneutes Engagement.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA','ASIA-SOUTHEAST'],ARRAY['president','sworn in','inaugurat','elected','elect','vice president','congratulat','greetings','Wang Yi','enhance cooperation','deepen cooperation','pragmatic cooperation','cooperation','new government','state visit','visit','meets','delegation','corridor','investment','bilateral','ties','sovereignty','stability','back its security','momentum','transition','civilian','Präsident','Wahl','Zusammenarbeit','Staatsbesuch','Stabilität','Souveränität','gewählt','总统','主席','合作','国事访问','主权','稳定','当选','访问','президент','сотрудничеств','суверенитет','стабильн','визит'],true,ARRAY['CGTN','China Daily','Global Times','People''s Daily','TASS (EN)','TASS','RT','RIA Novosti','Izvestia','Lenta.ru','Kommersant','BelTA','BelTA Russian','Press TV','Dawn'],'myanmar_civil_conflict',1,'Normalisation and engagement','Normalisierung und Engagement',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('myanmar_illegitimate_junta_rule','Sham election, illegitimate junta','Scheinwahl, illegitime Junta','The military''s election was staged to launder its coup; the junta rules without a mandate, jails elected leaders such as Aung San Suu Kyi, and wages airstrikes and mass violence against civilians.','Die Wahl des Militärs wurde inszeniert, um den Putsch zu legitimieren; die Junta regiert ohne Mandat, inhaftiert gewählte Politiker wie Aung San Suu Kyi und führt Luftangriffe und Gewalt gegen Zivilisten.',ARRAY['AMERICAS-USA','NON-STATE-EU','ASIA-SOUTHEAST','ASIA-JAPAN'],ARRAY['sham','junta','coup','airstrike','air strike','house arrest','Suu Kyi','political prisoner','prisoner','atrocit','killed','crackdown','illegitimate','recogni','refuse','reject','condemn','rights','genocide','forced','detain','jail','opposition','resistance','rebel','civil war','sanction','poll','fraud','Scheinwahl','Junta','Putsch','Luftangriff','Hausarrest','Sanktion','Bürgerkrieg','erkennt','軍政','弾圧','クーデター','军政府','镇压','انقلاب','хунта','переворот','तख्तापलट'],true,ARRAY['BBC World','The Guardian','Deutsche Welle','France 24 (EN)','NPR','New York Times','Washington Post','CNN','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Kurier','Tagesschau','El País','Corriere della Sera','La Repubblica','Euronews','Sky News','Financial Times','The Telegraph','The Economist','CBC','Swissinfo','ERR News','DR','iROZHLAS','Associated Press','AFP','Reuters','Bangkok Post','Channel NewsAsia','Straits Times','New Straits Times','Nikkei Asia','The Nation Thailand','Japan Times','Asahi Shimbun','NHK World','Kyodo News','ABC News','The Australian','Philippine Daily Inquirer','Jakarta Post','Jakarta Globe','Cebu Daily News','VN Express','Al Jazeera','TRT World','Arab News','Daily Sabah','Anadolu Agency','UN News','NDTV','Times of India','Hindustan Times','The Hindu','Indian Express','DD India','WION','Dhaka Tribune','News24','Daily Nation','Daily Maverick','Daily Mirror','Punch','Kyiv Post','Jerusalem Post','Daily Star','The Star'],'myanmar_civil_conflict',2,'Illegitimate military rule','Illegitime Militärherrschaft', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('myanmar_criminal_economy_spillover','Scam-compound economy and cross-border crime','Betrugszentren und grenzüberschreitende Kriminalität','Myanmar''s lawless border zones host industrial-scale scam compounds and human-trafficking operations whose victims and proceeds spill across the region, drawing Chinese executions, foreign rescues and cross-border enforcement.','Myanmars rechtsfreie Grenzregionen beherbergen Betrugszentren und Menschenhandel im industriellen Maßstab, deren Opfer und Erlöse in die Region überschwappen und chinesische Hinrichtungen, ausländische Rettungen und grenzüberschreitende Strafverfolgung nach sich ziehen.',ARRAY['ASIA-CHINA','ASIA-SOUTHEAST','ASIA-INDIA'],ARRAY['scam','cyberscam','fraud','traffick','compound','scam hub','scam centre','scam center','scam mafia','forced labo','Myawaddy','KK Park','execute','execution','mafia','syndicate','kingpin','fraud hub','criminal','repatriat','gang','pig butcher','slave','詐欺','拠点詐欺','Betrug','Menschenhandel','estafa','fraude','arnaque'],true,ARRAY['CGTN','China Daily','Global Times','People''s Daily','Reuters','Associated Press','AFP','BBC World','Channel NewsAsia','Bangkok Post','Straits Times','Nikkei Asia','Philippine Daily Inquirer','The Nation Thailand','NDTV','Times of India','Hindustan Times','The Hindu','Al Jazeera','The Telegraph','Globe and Mail','Bloomberg','Japan Times','Asahi Shimbun','NHK World','Kyodo News','ABC News','VN Express','Dhaka Tribune','Daily Nation','News24'],'myanmar_civil_conflict',3,'Transnational criminal spillover','Transnationaler Kriminalitäts-Spillover', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('china_dprk_friendship','Traditional friendship restored, to the benefit of regional stability','Wiederhergestellte traditionelle Freundschaft im Dienst regionaler Stabilität','Friendship framing (Chinese state media) presents the re-engagement -- Xi''s state visit, the Wang Yi mission, resumed Beijing-Pyongyang flights and rail, tributes at the Chinese People''s Volunteers cemeteries -- as the restoration of a historic bond entering a "new era", and as a contribution to peace and stability on the peninsula rather than an evasion of sanctions.','Die Freundschaftsrahmung (chinesische Staatsmedien) stellt die Wiederannäherung -- Xis Staatsbesuch, die Mission von Wang Yi, wieder aufgenommene Flüge und Bahnverbindungen zwischen Peking und Pjöngjang, Ehrungen auf den Friedhöfen der chinesischen Volksfreiwilligen -- als Wiederherstellung einer historischen Bindung dar, die in eine "neue Ära" eintritt, und als Beitrag zu Frieden und Stabilität auf der Halbinsel statt als Umgehung von Sanktionen.',ARRAY['ASIA-CHINA','ASIA-NORKOREA'],ARRAY['friendship','new era','deepen','practical cooperation','steadfast','mutual','peace and stability','Freundschaft','neue Ära'],true,ARRAY['CGTN','China Daily','Global Times','People''s Daily'],'north_korea_china_patronage',1,'Friendship and regional stability','Freundschaft und regionale Stabilität',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('beijing_shields_pyongyang','Beijing''s lifeline is what keeps the pressure regime from working','Pekings Lebensader verhindert, dass das Druckregime wirkt','Patronage-critique framing (Western, South Korean and Japanese mainstream) reads the same re-engagement as the decisive hole in the sanctions regime: China keeps the North Korean economy alive, declines to press Kim on the nuclear programme even when asked to, and rebuilds leverage over Pyongyang as a card in its own competition with Washington. The restored flights, rail link and trade are read as sanctions erosion rather than neighbourliness.','Die Patronage-Kritik (westliche, südkoreanische und japanische Leitmedien) liest dieselbe Wiederannäherung als entscheidende Lücke im Sanktionsregime: China hält die nordkoreanische Wirtschaft am Leben, verzichtet selbst auf Nachfrage darauf, Kim zum Nuklearprogramm zu drängen, und baut Einfluss auf Pjöngjang als Karte im eigenen Wettbewerb mit Washington auf. Die wieder aufgenommenen Flüge, die Bahnverbindung und der Handel gelten als Erosion der Sanktionen statt als gute Nachbarschaft.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA','ASIA-JAPAN'],ARRAY['lifeline','economy alive','grip','leverage','shield','prop up','undercut','evasion','evade','declines to press','evita presionar','mum on','defiance','influence','oblige','competing for','sanctions relief','Einfluss','影響力'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','France 24','Euronews','Financial Times','Bloomberg','Bloomberg.com','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Le Monde','El País','El Mundo','The Economist','Sky News','NPR','ABC News','MSNBC','Channel NewsAsia','CNA','Straits Times','The Straits Times','Al Jazeera','Fox News','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Wire by KYODO NEWS','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Beyond Parallel','Carnegie Endowment','The Australian'],'north_korea_china_patronage',2,'Beijing shields Pyongyang from pressure','Peking schirmt Pjöngjang gegen Druck ab', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('nk_sovereign_deterrent','The arsenal is a sovereign deterrent that will not be traded away','Das Arsenal ist ein souveränes Abschreckungsmittel, das nicht verhandelbar ist','Sovereign-deterrent framing (Russian and Chinese state press, carrying Pyongyang''s own position) presents the nuclear and missile programme as a lawful instrument of self-defence and a settled fact: the DPRK has declared itself a nuclear state, says it will never give up that status, and treats denuclearisation demands as closed. US-led containment is described as having failed. Note this is a thin seam within the bloc''s Korea coverage, which is mostly neutral launch reporting -- hence framing-gated.','Die Rahmung als souveräne Abschreckung (russische und chinesische Staatspresse, die Pjöngjangs eigene Position transportiert) stellt das Nuklear- und Raketenprogramm als rechtmäßiges Mittel der Selbstverteidigung und als vollendete Tatsache dar: Die DVRK hat sich zum Atomstaat erklärt, erklärt, diesen Status niemals aufzugeben, und betrachtet Forderungen nach Denuklearisierung als erledigt. Die von den USA geführte Eindämmung wird als gescheitert beschrieben. Dies ist ein schmaler Strang innerhalb der Korea-Berichterstattung des Blocks, die überwiegend aus neutraler Berichterstattung über Raketenstarts besteht -- daher die Rahmungsbindung.',ARRAY['ASIA-NORKOREA'],ARRAY['nuclear status','nuclear state','nuclear power status','never give up','never abandon','will never','no compromise','refuses to','refused to','self-defence','self-defense','sovereign right','geometric progression','nuclear buildup','nuclear build-up','nuclear push','failed','ядерный статус','ядерного статуса','никогда не откажется','не откажется','геометрической прогрессии','наращивании ядерных','наращивание ядерного','отказались идти на компромисс','отказались от компромисса','провалились','核保有','自卫','自衛'],true,ARRAY['TASS','TASS (EN)','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','CGTN','China Daily','Global Times','People''s Daily'],'north_korea_missile_program',1,'Sovereign deterrent, not negotiable','Souveräne Abschreckung, nicht verhandelbar',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('nk_proliferation_threat','An expanding arsenal that must be contained','Ein wachsendes Arsenal, das eingedämmt werden muss','Threat framing (Western, South Korean and Japanese mainstream plus defence-analytic outlets) treats the programme as a growing danger to the region and to the United States: ballistic launches timed against allied exercises, expanding uranium-enrichment capacity, warhead numbers, hypersonic and AI-guided systems, and the erosion of the sanctions regime. The prescription is denuclearisation through pressure, interception capability and allied coordination.','Die Bedrohungsrahmung (westliche, südkoreanische und japanische Leitmedien sowie verteidigungsanalytische Fachmedien) behandelt das Programm als wachsende Gefahr für die Region und die Vereinigten Staaten: ballistische Starts mit zeitlichem Bezug zu Manövern der Verbündeten, wachsende Urananreicherungskapazität, Sprengkopfzahlen, Hyperschall- und KI-gesteuerte Systeme sowie die Erosion des Sanktionsregimes. Die Schlussfolgerung lautet Denuklearisierung durch Druck, Abfangfähigkeit und Abstimmung der Verbündeten.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA','ASIA-JAPAN'],ARRAY['threat','provocation','escalat','sanctions','denuclear','enrichment','warhead','buildup','build-up','Bedrohung','Provokation','Sanktionen','Anreicherung'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','France 24','Euronews','Financial Times','Bloomberg','Bloomberg.com','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Le Monde','El País','El Mundo','The Economist','Sky News','NPR','ABC News','MSNBC','Channel NewsAsia','CNA','Straits Times','The Straits Times','Fox News','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Wire by KYODO NEWS','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Military Times','War on the Rocks','Beyond Parallel','Carnegie Endowment'],'north_korea_missile_program',2,'Proliferation threat requiring containment','Proliferationsbedrohung, die Eindämmung erfordert', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('dprk_russia_comradeship','A lawful partnership between states under the same sanctions','Eine rechtmäßige Partnerschaft zwischen Staaten unter denselben Sanktionen','Partnership framing (Russian and Belarusian state press) presents the alignment as an ordinary and lawful relationship between sovereign states: treaty-based military cooperation, ministerial and parliamentary visits, a new border bridge, Lukashenko''s first visit to Pyongyang, and honours for North Korean soldiers who fought in Kursk. The deployment is framed as allied assistance in liberating Russian territory and the soldiers as heroes, not as a transaction.','Die Partnerschaftsrahmung (russische und belarussische Staatspresse) stellt die Ausrichtung als gewöhnliche und rechtmäßige Beziehung zwischen souveränen Staaten dar: vertraglich geregelte militärische Zusammenarbeit, Besuche von Ministern und Parlamentariern, eine neue Grenzbrücke, Lukaschenkos erster Besuch in Pjöngjang und Ehrungen für nordkoreanische Soldaten, die in Kursk kämpften. Der Truppeneinsatz erscheint als Beistand von Verbündeten bei der Befreiung russischen Gebiets und die Soldaten als Helden, nicht als Gegenleistung.',ARRAY['EUROPE-RUSSIA','ASIA-NORKOREA','EUROPE-BELARUS'],ARRAY['partnership','cooperation','treaty','allies','ally','top priority','heroes','friendship','visit','Партнёрств','сотрудничеств','договор','союзник','героя','дружб'],true,ARRAY['TASS','TASS (EN)','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian'],'north_korea_russia_alignment',1,'Lawful partnership of sanctioned states','Rechtmäßige Partnerschaft sanktionierter Staaten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('dprk_russia_blood_for_technology','Troops and shells for cash and missile technology','Truppen und Granaten gegen Geld und Raketentechnologie','Transaction framing (Western, South Korean, Japanese and Ukrainian outlets) reads the alignment as an arms-for-technology bargain that damages both theatres at once: North Korea supplies troops, shells and missiles to sustain Russia''s war and is estimated to have earned billions doing so, while Russia is suspected of paying in the military and space technology that accelerates the DPRK programme. Coverage foregrounds the human cost -- casualties in Kursk, prisoners of war, the "self-blasting" policy praised by Kim -- and the proliferation quid pro quo.','Die Transaktionsrahmung (westliche, südkoreanische, japanische und ukrainische Medien) liest die Ausrichtung als Waffen-gegen-Technologie-Geschäft, das beide Schauplätze zugleich beschädigt: Nordkorea liefert Truppen, Granaten und Raketen zur Aufrechterhaltung des russischen Krieges und soll damit Milliarden verdient haben, während Russland im Verdacht steht, mit Militär- und Raumfahrttechnologie zu bezahlen, die das Programm der DVRK beschleunigt. Im Vordergrund stehen die menschlichen Kosten -- Verluste bei Kursk, Kriegsgefangene, die von Kim gelobte Praxis der Selbstsprengung -- und die Gegenleistung bei der Proliferation.',ARRAY['AMERICAS-USA','ASIA-SOUTHKOREA','EUROPE-UKRAINE','ASIA-JAPAN'],ARRAY['troops','soldier','arms','shells','munition','earned','cash','technology','quid pro quo','casualt','prisoner','POW','killed','Truppen','Soldaten','Waffen','Technologie'],true,ARRAY['Reuters','BBC World','Associated Press','AFP','The Guardian','Deutsche Welle','DW.com','CNN','France 24 (EN)','France 24','Euronews','Financial Times','Bloomberg','Bloomberg.com','New York Times','Washington Post','Wall Street Journal','WSJ','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Le Monde','El País','El Mundo','The Economist','Sky News','NPR','ABC News','MSNBC','Channel NewsAsia','CNA','Straits Times','The Straits Times','Al Jazeera','Fox News','Kyiv Post','Yonhap','Yonhap News Agency','KBS World','KBS WORLD Radio','Korea Herald','The Korea Herald','NHK World','nhk.or.jp','Asahi Shimbun','Kyodo News','Japan Wire by KYODO NEWS','Japan Times','Nikkei Asia','CSIS','Brookings','RAND','Atlantic Council','Council on Foreign Relations','IISS','Janes','Defense News','Beyond Parallel','Carnegie Endowment','Anadolu Agency','UN News'],'north_korea_russia_alignment',2,'Blood-for-technology transaction','Blut-gegen-Technologie-Geschäft', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pacific_western_partnership','Pacific island states are choosing Australia and its partners as their security partner','Pazifische Inselstaaten wählen Australien und seine Partner als Sicherheitspartner','Australian and Western coverage frames the Pacific as a region where Australia is consolidating its position as security partner of choice: the Fiji mutual defence treaty, the Vanuatu pact barring foreign military bases, and the Solomon Islands review of its secret pact with Beijing are read as island states freely choosing transparent partnerships over Chinese basing and policing arrangements. Vocabulary: defence pact, mutual defence, counter China, security agreement, partner of choice, transparency.','Die australische und westliche Berichterstattung stellt den Pazifik als Region dar, in der Australien seine Stellung als bevorzugter Sicherheitspartner festigt: der Verteidigungsvertrag mit Fidschi, der Pakt mit Vanuatu zum Verbot ausländischer Militärbasen und die Überprüfung des geheimen Pakts der Salomonen mit Peking gelten als freie Entscheidung der Inselstaaten für transparente Partnerschaften statt chinesischer Stützpunkte und Polizeiabkommen.',ARRAY['OCEANIA-AUSTRALIA','OCEANIA-MELANESIA','OCEANIA-POLYNESIA','OCEANIA-MICRONESIA','OCEANIA-PAPUANEWGUINEA'],ARRAY['defence pact','defense pact','mutual defence','mutual defense','security agreement','security pact','counter China','containment','partner of choice','transparency','foreign military base','ban','review','secretive','treaty','alliance'],true,ARRAY['ABC News','Australian Broadcasting Corporation','ABC Pacific','Sydney Morning Herald','The Sydney Morning Herald','SMH.com.au','The Australian','The Guardian','Sky News','News24','Reuters','Associated Press','BBC World','Bloomberg','Financial Times','Nikkei Asia','Straits Times','The Straits Times','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Channel NewsAsia','The Hindu','Times of India','Philippine Daily Inquirer','CSIS','Lowy Institute'],'pacific_island_contest',1,'Australian and Western partnership framing','Australische und westliche Partnerschafts-Rahmung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pacific_china_cooperation','Chinese engagement in the Pacific is ordinary development cooperation that no third party should constrain','Chinas Engagement im Pazifik ist gewöhnliche Entwicklungszusammenarbeit, die kein Dritter beschränken sollte','Chinese state framing presents Beijing''s Pacific presence as normal, mutually agreed cooperation — medical teams, infrastructure and policing assistance requested by sovereign governments — that "should not target any third party or be used for geopolitical contest". Australian and Western reporting on Chinese pacts is cast as hype driven by an exclusionary Cold War mindset that denies island states their own choices. Vocabulary: cooperation, mutual benefit, third party, geopolitical contest, hype, exclusionary, Cold War mentality.','Die chinesische staatliche Rahmung stellt Pekings Präsenz im Pazifik als normale, einvernehmliche Zusammenarbeit dar — medizinische Teams, Infrastruktur und Polizeihilfe auf Wunsch souveräner Regierungen —, die "kein Drittland ins Visier nehmen oder für geopolitischen Wettbewerb genutzt werden sollte". Australische und westliche Berichte über chinesische Pakte werden als Panikmache eines ausgrenzenden Kalten-Kriegs-Denkens dargestellt, das den Inselstaaten eigene Entscheidungen abspricht.',ARRAY['ASIA-CHINA','OCEANIA-MELANESIA','OCEANIA-POLYNESIA','OCEANIA-MICRONESIA'],ARRAY['cooperation','co-op','mutual benefit','third party','geopolitical contest','hype','exclusionary','Cold War','mentality','sovereign','development','assistance','win-win','合作','互利'],true,ARRAY['Global Times','CGTN','news.cgtn.com','China Daily','People''s Daily','Xinhua'],'pacific_island_contest',2,'Chinese state cooperation framing','Chinesische staatliche Kooperations-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pakafg_counterterror_necessity','Strikes target militant sanctuaries Kabul refuses to close','Angriffe zielen auf Militantenrückzugsgebiete, die Kabul nicht schließt','Pakistani state-security framing (Pakistani press) holds that cross-border strikes hit Tehreek-e-Taliban sanctuaries on Afghan soil, that Kabul has failed to act against militants who attack Pakistani forces and civilians, and that Pakistan acted only after repeated attacks and demands for verifiable action went unanswered.','Die pakistanische Sicherheitsdarstellung (pakistanische Presse) besagt, dass die grenzüberschreitenden Angriffe Rückzugsgebiete der Tehreek-e-Taliban auf afghanischem Boden treffen, dass Kabul nicht gegen Militante vorgegangen ist, die pakistanische Sicherheitskräfte und Zivilisten angreifen, und dass Pakistan erst handelte, nachdem wiederholte Angriffe und Forderungen nach überprüfbaren Schritten unbeantwortet blieben.',ARRAY['ASIA-PAKISTAN'],ARRAY['terrorist infrastructure','militant hideout','sanctuar','TTP','verifiable','Ghazab','retaliat','safe haven','Terrorinfrastruktur','Rückzugsgebiet','Vergeltung'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation'],'pakistan_afghanistan_border',1,'Pakistani counter-terrorism necessity','Pakistanische Notwendigkeit der Terrorbekämpfung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pakafg_afghan_sovereignty_violation','Pakistani strikes on Afghan territory are aggression against a sovereign state','Pakistanische Angriffe auf afghanisches Gebiet sind Aggression gegen einen souveränen Staat','Sovereignty-violation framing (Al Jazeera, Turkish and Russian outlets relaying Kabul''s account, plus the Indian press) treats the strikes as attacks on the territory of a sovereign state: the Taliban government accuses Pakistan of war crimes and of hitting a Kabul hospital, Afghan forces claim retaliatory strikes inside Pakistan, and New Delhi calls the campaign an assault on Afghan sovereignty and a threat to regional peace.','Die Souveränitätsverletzungs-Darstellung (Al Jazeera, türkische und russische Medien, die Kabuls Version wiedergeben, sowie die indische Presse) betrachtet die Angriffe als Attacken auf das Gebiet eines souveränen Staates: Die Taliban-Regierung wirft Pakistan Kriegsverbrechen und den Beschuss eines Krankenhauses in Kabul vor, afghanische Kräfte melden Vergeltungsangriffe in Pakistan, und Neu-Delhi nennt die Kampagne einen Angriff auf die afghanische Souveränität und eine Bedrohung des regionalen Friedens.',ARRAY['ASIA-AFGHANISTAN','ASIA-INDIA'],ARRAY['sovereignty','war crime','aggression','violation','accuses','condemn','Souveränität','Kriegsverbrechen','Aggression','verurteil'],true,ARRAY['Al Jazeera','TRT World','Anadolu Agency','RT','rt.com','TASS (EN)','Press TV','IRNA','NDTV','Times of India','The Times of India','Hindustan Times','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'pakistan_afghanistan_border',2,'Afghan sovereignty violation','Verletzung der afghanischen Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pakafg_civilian_harm_alarm','The border war is killing civilians and risks a wider conflict','Der Grenzkrieg tötet Zivilisten und droht sich auszuweiten','Civilian-harm framing (Western mainstream and wire services) centres the human cost and the escalation risk rather than either government''s case: casualty counts from strikes on Kabul and the border provinces, UN and aid-agency warnings, displaced and deported Afghans, and the repeated collapse of short ceasefires between two states now describing their relationship as open war.','Die Darstellung ziviler Opfer (westliche Leitmedien und Nachrichtenagenturen) rückt die menschlichen Kosten und das Eskalationsrisiko in den Mittelpunkt statt der Position einer der beiden Regierungen: Opferzahlen nach Angriffen auf Kabul und die Grenzprovinzen, Warnungen der UN und von Hilfsorganisationen, vertriebene und abgeschobene Afghanen sowie das wiederholte Scheitern kurzer Waffenruhen zwischen zwei Staaten, die ihr Verhältnis inzwischen als offenen Krieg bezeichnen.',ARRAY['ASIA-PAKISTAN','ASIA-AFGHANISTAN'],ARRAY['civilian','killed','hospital','casualt','displaced','refugee','ceasefire','UN','aid','Zivilist','getötet','Krankenhaus','Waffenruhe','Flüchtling'],true,ARRAY['Reuters','BBC World','Associated Press','Deutsche Welle','France 24','France 24 (EN)','Die Zeit','NPR','The Guardian','Euronews','Al Arabiya','Khaleej Times','Arab News'],'pakistan_afghanistan_border',3,'Civilian harm and escalation alarm','Alarm über zivile Opfer und Eskalation', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('freedom_of_navigation_defense','Houthi attacks on commercial vessels violate UNCLOS; coalition naval ops are necessary','Houthi-Angriffe auf Handelsschiffe verletzen UNCLOS; koalitionaere Marine-Operationen sind notwendig','Western shipping-desk, Israeli, and Saudi framing: Houthi attacks on commercial vessels violate UNCLOS freedom-of-navigation rights and global trade order; Operation Prosperity Guardian, EU Aspides, and US Fifth Fleet operations are necessary and lawful; Saudi Yanbu rerouting and reported Somaliland base are pragmatic adaptations. The vocabulary: "UNCLOS", "freedom of navigation", "Prosperity Guardian", "Aspides", "Fifth Fleet", "lawful response", "global trade order". Prescription: maintain coalition naval presence, escort merchant traffic, sanction Houthi enablers.','Westliche Schifffahrts-, israelische und saudische Rahmung: Houthi-Angriffe auf Handelsschiffe verletzen UNCLOS und die Welthandelsordnung; Operation Prosperity Guardian, EU Aspides und US-Fuenfte-Flotte-Operationen sind noetig und rechtmaessig; saudische Yanbu-Umleitung und gemeldete Somaliland-Basis sind pragmatische Anpassungen. Vokabular: "UNCLOS", "freie Seefahrt", "Prosperity Guardian", "Aspides", "Fuenfte Flotte", "rechtmaessige Antwort", "Welthandelsordnung". Vorschrift: koalitionaere Marine-Praesenz, Eskortenfahrten, Sanktionen gegen Houthi-Ermoeglicher.',ARRAY['AMERICAS-USA','EUROPE-UK','NON-STATE-EU','MIDEAST-ISRAEL','MIDEAST-SAUDI'],ARRAY['UNCLOS','freedom of navigation','Prosperity Guardian','Aspides','Fifth Fleet','lawful response','global trade'],true,ARRAY['Reuters','Associated Press','BBC World','France 24','France 24 (EN)','Financial Times','Bloomberg','Wall Street Journal','Nikkei Asia','Straits Times','Jerusalem Post','Times of Israel','Fox News','Al Arabiya','Al-Ahram','The National'],'red_sea_shipping_security',1,'Freedom of navigation must be defended','Schutz der freien Seefahrt', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('houthi_naval_pressure_legitimate','Houthi targeting of Israel-linked shipping is legitimate non-state pressure tied to Gaza ceasefire','Houthi-Schlaege gegen israelisch-verbundene Schifffahrt sind legitime nicht-staatliche Pression mit Gaza-Bezug','Resistance-axis framing: Houthi targeting of Israel-linked shipping is a legitimate non-state form of pressure tied explicitly to a Gaza ceasefire; Western naval coalitions and reported Israeli outposts in Somaliland are imperial overreach into Yemeni and Arab maritime sovereignty. The vocabulary: "Israel-linked shipping", "Gaza linkage", "non-state pressure", "imperial overreach", "Western fleets", "Yemeni sovereignty", "Arab maritime sovereignty". Prescription: continue selective targeting until Gaza ceasefire; reject Western coalitions as illegitimate; oppose foreign basing on the Horn.','Widerstandsachsen-Rahmung: Houthi-Schlaege gegen israelisch verbundene Schifffahrt sind legitime nicht-staatliche Pression mit explizitem Gaza-Bezug; westliche Marine-Koalitionen und gemeldete israelische Aussenposten in Somaliland sind imperiale Anmassung gegen jemenitische und arabische Seehoheit. Vokabular: "israelisch verbundene Schifffahrt", "Gaza-Verknuepfung", "nicht-staatliche Pression", "imperiale Anmassung", "westliche Flotten", "jemenitische Souveraenitaet". Vorschrift: gezielte Schlaege bis zum Gaza-Waffenstillstand fortsetzen.',ARRAY['MIDEAST-YEMEN','MIDEAST-IRAN'],ARRAY['Israel-linked shipping','Gaza linkage','non-state pressure','imperial overreach','Western fleets','Yemeni sovereignty'],true,ARRAY['Press TV','Al Jazeera','Al Mayadeen','Fars News','IRNA','TRT World','Anadolu Agency','Daily Sabah','CGTN','TASS (EN)'],'red_sea_shipping_security',2,'Naval pressure is legitimate Gaza solidarity','Maritimer Druck als legitime Gaza-Solidaritaet',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('airspace_violation_deterrence','Russia deliberately probes NATO airspace to intimidate; NATO must enforce, including shoot-down authority','Russland testet gezielt den NATO-Luftraum, um einzuschüchtern; die NATO muss durchsetzen, auch mit Abschussbefugnis','Western-mainstream and Baltic/Nordic press treat repeated drone and aircraft incursions into NATO airspace as deliberate Russian probing intended to test alliance resolve and respond times, not accidents. Coverage documents scrambles and intercepts, national airspace closures in Finland and Poland, and growing debate over authorising NATO forces to shoot down violating drones and aircraft. Prescription: harden air-defence and detection, invoke Article 4 consultations where warranted, and grant shoot-down authority for repeated, unambiguous violations.','Westliche Mainstream- und baltisch-nordische Medien behandeln wiederholte Drohnen- und Flugzeug-Einbrüche in den NATO-Luftraum als gezielte russische Tests zur Prüfung von Bündnis-Entschlossenheit und Reaktionszeiten, nicht als Unfälle. Die Berichterstattung dokumentiert Abfangeinsätze, nationale Luftraumsperrungen in Finnland und Polen sowie die wachsende Debatte, NATO-Kräften eine Abschussbefugnis gegen eindeutig verletzende Drohnen und Flugzeuge zu erteilen. Handlungsempfehlung: Luftverteidigung und Erkennung härten, Artikel-4-Konsultationen bei Bedarf einberufen und Abschussbefugnis für wiederholte, eindeutige Verletzungen erteilen.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC'],ARRAY['probing','testing NATO resolve','deliberate incursion','violation','scramble','shoot down','harden air defence','Article 4','alliance resolve','Luftraumverletzung','eindringen','Entschlossenheit','Abschussbefugnis'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','LSM English','Atlantic Council','Politico','Kyiv Post','The Telegraph','The Economist','EurActiv','Bloomberg'],'russia_airspace_incursions',1,'Airspace violations demand a firm response','Luftraumverletzungen erfordern entschlossene Antwort',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('nato_complicity_provocation','NATO territory hosts and enables Ukrainian drone strikes; incursions are Western provocations, not Russian aggression','NATO-Gebiet beherbergt und ermöglicht ukrainische Drohnenangriffe; Einbrüche sind westliche Provokationen, keine russische Aggression','Russian and allied state media invert the airspace-incursion narrative: Baltic and NATO states are accused of allowing or facilitating Ukrainian drone operations to launch from or transit their territory against Russia, making any Russian response or protest a matter of legitimate self-defence rather than aggression. Coverage frames alleged incursions as staged provocations or false flags designed to justify further NATO militarisation, and casts Western denials of complicity as not credible. This is the schadenfreude/rift-exploitation register, not endorsement of either side''s territorial claims -- the same bloc that runs the sanctions-ineffective and hybrid-Russophobia counter-narratives here reframes the incursion story onto NATO complicity rather than contesting the facts of any single incident.','Russische und verbündete Staatsmedien kehren die Luftraum-Einbruch-Erzählung um: Baltischen und NATO-Staaten wird vorgeworfen, ukrainische Drohnenoperationen von ihrem Gebiet aus gegen Russland zuzulassen oder zu ermöglichen, wodurch jede russische Reaktion oder jeder Protest legitime Selbstverteidigung statt Aggression sei. Die Berichterstattung stellt angebliche Einbrüche als inszenierte Provokationen oder False-Flag-Operationen dar, die weitere NATO-Militarisierung rechtfertigen sollen, und stellt westliche Dementis der Mitschuld als unglaubwürdig dar. Dies ist das Schadenfreude-/Rift-Exploitation-Register, keine Zustimmung zu den Gebietsansprüchen einer der Seiten -- derselbe Block, der die sanktions-wirkungslos- und hybrid-russophobie-Gegenerzählungen führt, verlagert hier die Einbruch-Geschichte auf NATO-Mitschuld statt die Fakten eines einzelnen Vorfalls zu bestreiten.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['complicity','false flag','staged provocation','enabling','launch pad','legitimate self-defence','not credible','Komplizenschaft','Inszenierung','Vorwand','Selbstverteidigung'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian','Press TV','CGTN','Global Times','China Daily','Xinhua'],'russia_airspace_incursions',2,'NATO territory enables Ukrainian strikes','NATO-Gebiet ermöglicht ukrainische Angriffe', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('escalation_risk_restraint','Shoot-down authority and forward posture risk uncontrolled escalation; many incidents are accidental or overblown','Abschussbefugnis und Vorwärtsstationierung riskieren unkontrollierte Eskalation; viele Vorfälle sind unfallbedingt oder überzogen','A restraint-minded current within Western and European press, distinct from both the pro-deterrence mainstream and the Kremlin counter-frame, warns that authorising forces to shoot down ambiguous contacts risks a shooting incident that escalates uncontrollably, and that some reported incursions -- stray drones blown off course, weather-related radar returns -- are accidental rather than deliberate probing. Coverage calls for restraint, clearer rules of engagement, and skepticism toward worst-case framing of every incident. Framing keywords are required because this critique appears in the same outlets that otherwise support a firm response.','Eine auf Zurückhaltung bedachte Strömung innerhalb der westlichen und europäischen Presse, die sich sowohl vom abschreckungsfreundlichen Mainstream als auch vom Kreml-Gegenframe unterscheidet, warnt, dass eine Abschussbefugnis gegen mehrdeutige Kontakte einen Zwischenfall riskiert, der unkontrolliert eskaliert, und dass manche gemeldeten Einbrüche -- vom Kurs abgekommene Drohnen, wetterbedingte Radarechos -- unfallbedingt statt gezielt sind. Die Berichterstattung fordert Zurückhaltung, klarere Einsatzregeln und Skepsis gegenüber Worst-Case-Deutungen jedes Vorfalls. Framing-Schlüsselwörter sind nötig, weil diese Kritik in denselben Medien erscheint, die ansonsten eine entschlossene Antwort unterstützen.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','NON-STATE-EU','EUROPE-NORDIC'],ARRAY['escalation risk','accidental','overblown','restraint','Eskalationsgefahr','versehentlich','überzogen','Zurückhaltung','stray drone','abgekommene Drohne','rules of engagement','Einsatzregeln'],true,ARRAY['Le Monde','El País','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','The Independent','ANSA','La Repubblica','Al Jazeera','Anadolu Agency','Channel NewsAsia'],'russia_airspace_incursions',3,'Escalation risk warrants restraint','Eskalationsrisiko gebietet Zurückhaltung', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russia_europe_western_resolve','Europe must deter, defend and sanction a revanchist Russia','Europa muss ein revisionistisches Russland abschrecken, verteidigen und sanktionieren','The Western consensus across the theater: eastern-flank rearmament, hybrid-threat hardening, airspace enforcement and the sanctions regime are complementary parts of one coherent response to sustained Russian pressure on European security, energy, and information space. Coverage treats deterrence, resilience, and economic pressure as mutually reinforcing rather than separate policy tracks.','Der westliche Konsens über das gesamte Theater hinweg: Aufrüstung der Ostflanke, Härtung gegen hybride Bedrohungen, Luftraumdurchsetzung und Sanktionsregime sind sich ergänzende Teile einer kohärenten Antwort auf anhaltenden russischen Druck auf europäische Sicherheit, Energie und Informationsraum. Die Berichterstattung behandelt Abschreckung, Resilienz und wirtschaftlichen Druck als sich gegenseitig verstärkend statt als getrennte Politikstränge.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC','AMERICAS-USA'],ARRAY['deter','defend','sanction','deterrence','resolve','coherent response','Western unity','harden','Entschlossenheit','geschlossene Antwort','Abschreckung'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','LSM English','Atlantic Council','Politico','Kyiv Post','The Telegraph','The Economist','EurActiv','Bloomberg'],'russia_europe_theater',1,'Western resolve across the board','Westliche Entschlossenheit auf allen Ebenen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russia_europe_kremlin_counter','Western Russophobia, NATO encirclement and self-defeating sanctions manufacture a "Russia threat"','Westliche Russophobie, NATO-Einkreisung und selbstschädigende Sanktionen konstruieren eine "Russland-Bedrohung"','The Russian and Chinese state-media counter-frame across the theater: NATO encirclement, hybrid-threat accusations, airspace-incursion claims and the sanctions regime are all cast as manufactured or self-inflicted -- evidence-free threat inflation, illegitimate seizures, and economic self-harm -- serving a Western political need for a Russian enemy rather than responding to real Russian aggression. This bloc also runs the rift-exploitation register on intra-Western disputes rather than endorsing either side.','Der russische und chinesische Staatsmedien-Gegenframe über das gesamte Theater hinweg: NATO-Einkreisung, Hybrid-Bedrohungsvorwürfe, Luftraum-Einbruch-Behauptungen und das Sanktionsregime werden allesamt als konstruiert oder selbstverschuldet dargestellt -- beweisfreie Bedrohungsinflation, rechtswidrige Beschlagnahmungen und wirtschaftliche Selbstschädigung --, die einem westlichen politischen Bedürfnis nach einem russischen Feindbild dienen, statt auf echte russische Aggression zu reagieren. Dieser Block führt zudem das Rift-Exploitation-Register bei innerwestlichen Streitigkeiten, ohne eine Seite zu unterstützen.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['manufactured threat','Russophobia','NATO encirclement','self-inflicted','evidence-free','political need for an enemy','konstruierte Bedrohung','Russophobie','Einkreisung','selbstverschuldet'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian','Press TV','CGTN','Global Times','China Daily','Xinhua'],'russia_europe_theater',2,'Kremlin counter-narrative','Kreml-Gegenerzählung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russia_europe_critical_restraint','Threat inflation, militarisation and escalation risk: a skeptical European counter-current','Bedrohungsinflation, Militarisierung und Eskalationsrisiko: eine skeptische europäische Gegenströmung','A Western-European critical current, distinct from both the Atlanticist mainstream and the Kremlin counter-frame, spans the theater: rearmament and war-economy drift may be overreach, hybrid-threat attribution risks over-securitisation of accidents, and shoot-down authority over ambiguous airspace contacts risks uncontrolled escalation. This is intra-Western critique of proportionality and process, not sympathy for Russian actions.','Eine westeuropäische kritische Strömung, die sich sowohl vom atlantischen Mainstream als auch vom Kreml-Gegenframe unterscheidet, zieht sich durch das gesamte Theater: Aufrüstung und Kriegswirtschafts-Drift könnten Übereifer sein, Hybrid-Bedrohungs-Attribution riskiert Über-Versicherheitlichung von Unfällen, und Abschussbefugnis gegenüber mehrdeutigen Luftraumkontakten riskiert unkontrollierte Eskalation. Dies ist innerwestliche Kritik an Verhältnismäßigkeit und Verfahren, keine Sympathie für russisches Handeln.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','NON-STATE-EU','EUROPE-NORDIC'],ARRAY['threat inflation','overreach','over-attribution','escalation risk','disproportionate','restraint','Bedrohungsinflation','Übereifer','Eskalationsgefahr','Zurückhaltung'],true,ARRAY['Le Monde','El País','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','The Independent','ANSA','La Repubblica','Al Jazeera','Anadolu Agency','Channel NewsAsia'],'russia_europe_theater',3,'Critical of militarisation and escalation risk','Kritisch gegenüber Militarisierung und Eskalationsrisiko', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hybrid_campaign_defence','Russia is waging a coordinated gray-zone campaign that requires attribution and hardening','Russland führt eine koordinierte Grauzonen-Kampagne, die Attribution und Härtung erfordert','Western-mainstream and Baltic/Nordic press treat the pattern of undersea cable damage, GPS jamming and spoofing, arson attacks, and shadow-fleet activity as a coordinated Russian gray-zone campaign below the threshold of open war. Coverage documents the Nord Stream sabotage prosecution, shadow-fleet tanker seizures and detentions, and new national hybrid-threat centres, framing these as evidence that attribution and resilience-building are catching up to a real threat. Prescription: expand undersea infrastructure protection, tighten shadow-fleet enforcement and interdiction, invest in GPS-jamming resilience, and pursue criminal prosecution of identified saboteurs.','Westliche Mainstream- und baltisch-nordische Medien behandeln das Muster aus Unterseekabel-Schäden, GPS-Störung und Spoofing, Brandanschlägen und Schattenflotten-Aktivität als koordinierte russische Grauzonen-Kampagne unterhalb der Schwelle offenen Krieges. Die Berichterstattung dokumentiert das Nord-Stream-Sabotage-Verfahren, Beschlagnahmungen und Festsetzungen von Schattenflotten-Tankern sowie neue nationale Zentren gegen hybride Bedrohungen und wertet dies als Beleg dafür, dass Attribution und Resilienzaufbau einer realen Bedrohung gerecht werden. Handlungsempfehlung: Schutz der Unterseeinfrastruktur ausbauen, Durchsetzung und Abfangen gegen die Schattenflotte verschärfen, in GPS-Störfestigkeit investieren und identifizierte Saboteure strafrechtlich verfolgen.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC'],ARRAY['sabotage campaign','coordinated attack','gray-zone','hybrid warfare','Kremlin''s hand','attribution','resilience','harden','crackdown','shadow fleet','below the threshold','hybride Kriegsführung','Sabotage-Kampagne','Angriff','Härtung'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','LSM English','Atlantic Council','Politico','Kyiv Post','The Telegraph','The Economist','EurActiv','Bloomberg'],'russia_hybrid_warfare',1,'Hybrid campaign requires a hardened response','Hybride Kampagne erfordert gehärtete Antwort',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('hybrid_russophobia_denial','Hybrid-threat claims are evidence-free Russophobia; shadow-fleet seizures are piracy','Vorwürfe hybrider Bedrohung sind beweisfreie Russophobie; Schattenflotten-Beschlagnahmungen sind Piraterie','Russian and allied state media dismiss sabotage and hybrid-threat attributions as evidence-free Russophobia, arguing that cable damage and jamming incidents are accidents, criminality, or provocations staged to justify further militarisation. Shadow-fleet tanker seizures by European navies are cast as maritime piracy and illegal interference with lawful commercial shipping under a Western sanctions regime that has no basis in international law. Prescription: release seized vessels, end shadow-fleet interdiction, and stop attributing accidents to Russia without proof.','Russische und verbündete Staatsmedien weisen Sabotage- und Hybrid-Bedrohungs-Zuschreibungen als beweisfreie Russophobie zurück und argumentieren, Kabelschäden und Störvorfälle seien Unfälle, Kriminalität oder inszenierte Provokationen zur Rechtfertigung weiterer Militarisierung. Beschlagnahmungen von Schattenflotten-Tankern durch europäische Marinen werden als Piraterie und rechtswidrige Einmischung in rechtmäßigen Handelsschiffsverkehr unter einem völkerrechtlich unbegründeten westlichen Sanktionsregime dargestellt. Handlungsempfehlung: beschlagnahmte Schiffe freigeben, das Abfangen der Schattenflotte beenden und Unfälle nicht ohne Beweise Russland zuschreiben.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['Russophobia','evidence-free','unfounded accusation','witch hunt','maritime piracy','illegal seizure','staged provocation','manufactured threat','Russophobie','unbegründet','Piraterie','Vorwand'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian','Press TV','CGTN','Global Times','China Daily','Xinhua'],'russia_hybrid_warfare',2,'Hybrid-threat claims are Russophobia','Hybrid-Vorwürfe sind Russophobie', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('securitisation_caution','Caution against over-attribution: accidents and criminality get mislabeled as Kremlin sabotage','Vorsicht vor Über-Attribution: Unfälle und Kriminalität werden fälschlich dem Kreml zugeschrieben','A cautious current within Western and European press, distinct from the pro-deterrence mainstream, warns against securitisation without evidence: anchor-dragging incidents may be genuine maritime accidents, some "saboteurs" turn out to be unrelated criminal actors, and rushing to attribute every incident to Russia risks discrediting real cases and inflaming public anxiety. Coverage calls for prosecutorial rigor and warns that over-attribution is itself a policy risk. Framing keywords are required because this critique runs in the same outlets that otherwise support hybrid-threat hardening.','Eine vorsichtige Strömung innerhalb der westlichen und europäischen Presse, die sich vom abschreckungsfreundlichen Mainstream unterscheidet, warnt vor Versicherheitlichung ohne Beweise: Ankerschleifen-Vorfälle könnten echte Schifffahrtsunfälle sein, manche "Saboteure" erweisen sich als unbeteiligte Kriminelle, und die vorschnelle Zuschreibung jedes Vorfalls an Russland riskiert, echte Fälle zu diskreditieren und öffentliche Ängste zu schüren. Die Berichterstattung fordert staatsanwaltschaftliche Sorgfalt und warnt, dass Über-Attribution selbst ein politisches Risiko ist. Framing-Schlüsselwörter sind nötig, weil diese Kritik in denselben Medien läuft, die ansonsten die Härtung gegen hybride Bedrohungen unterstützen.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','NON-STATE-EU','EUROPE-NORDIC'],ARRAY['no evidence','accident','over-attribution','securitisation','unproven','kein Beweis','Unfall','unbewiesen','Verdachtsfall','vorschnell','rush to judgment','voreilig'],true,ARRAY['Le Monde','El País','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','The Independent','ANSA','La Repubblica','Al Jazeera','Anadolu Agency','Channel NewsAsia'],'russia_hybrid_warfare',3,'Over-attribution risks discrediting real cases','Über-Attribution riskiert Diskreditierung echter Fälle', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('eastern_flank_deterrence','Eastern-flank build-up is necessary deterrence against a revanchist Russia','Der Ausbau der Ostflanke ist notwendige Abschreckung gegen ein revisionistisches Russland','Western-mainstream and Eastern-European framing treats the post-2022 build-up on NATO''s eastern flank -- enhanced Forward Presence brigades in the Baltics, Kaliningrad-facing air policing, rearmament and rising defence budgets, reintroduced conscription in several states -- as a proportionate and overdue response to a Russian military threat that is not going away. Coverage emphasises intelligence assessments of Russian reconstitution timelines, the credibility of Article 5, and the logic of raising the cost of any future aggression. Prescription: sustain or accelerate defence-spending increases, keep forward-deployed brigades in place, invest in air and missile defence, and treat rearmament as insurance rather than provocation.','Die westliche Mainstream- und osteuropäische Berichterstattung behandelt den Ausbau der NATO-Ostflanke seit 2022 -- verstärkte Vornepräsenz-Brigaden im Baltikum, Luftpolizei gegenüber Kaliningrad, Aufrüstung und steigende Verteidigungsbudgets, wiedereingeführte Wehrpflicht in mehreren Staaten -- als angemessene und überfällige Reaktion auf eine anhaltende russische Bedrohung. Die Berichterstattung betont geheimdienstliche Einschätzungen zur russischen Wiederaufrüstung, die Glaubwürdigkeit von Artikel 5 und die Logik, die Kosten künftiger Aggression zu erhöhen. Handlungsempfehlung: Verteidigungsausgaben beibehalten oder erhöhen, vorwärtsstationierte Brigaden belassen, in Luft- und Raketenabwehr investieren und Aufrüstung als Versicherung statt Provokation begreifen.',ARRAY['EUROPE-RUSSIA','NON-STATE-EU','NON-STATE-NATO','EUROPE-BALTIC','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-VISEGRAD','EUROPE-NORDIC'],ARRAY['deter','deterrence','Russian threat','defend','defend the flank','forward presence','reinforce','readiness','build-up','rearm','harden','credible defence','Abschreckung','russische Bedrohung','verstärken','Wehrhaftigkeit'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','LSM English','Atlantic Council','Politico','Kyiv Post','The Telegraph','The Economist','EurActiv','Bloomberg'],'russia_nato_deterrence',1,'Eastern-flank deterrence is necessary','Ostflanken-Abschreckung ist notwendig',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('nato_encirclement_provocation','NATO''s eastern build-up is aggressive encirclement driving escalation','Der NATO-Ausbau im Osten ist aggressive Einkreisung, die Eskalation treibt','Russian state media and allied outlets frame the same build-up as evidence of NATO aggression and encirclement: forward brigades and rearmament are read as preparation for confrontation with Russia rather than defence, conscription and rising defence budgets as militarisation of European society, and enhanced Forward Presence as breaking prior security assurances. Coverage stresses NATO''s eastward expansion since the 1990s as the root cause of the confrontation and casts Russian counter-measures as reactive. Prescription: NATO should reverse eastern deployments, halt further enlargement, and de-escalate rather than continue rearmament.','Russische Staatsmedien und verbündete Sender deuten denselben Ausbau als Beweis für NATO-Aggression und Einkreisung: Vorwärtsbrigaden und Aufrüstung werden als Vorbereitung auf eine Konfrontation mit Russland statt als Verteidigung gelesen, Wehrpflicht und steigende Verteidigungsbudgets als Militarisierung der europäischen Gesellschaft, verstärkte Vornepräsenz als Bruch früherer Sicherheitszusagen. Die Berichterstattung betont die NATO-Osterweiterung seit den 1990er Jahren als eigentliche Ursache der Konfrontation und stellt russische Gegenmaßnahmen als reaktiv dar. Handlungsempfehlung: Die NATO solle die Ost-Stationierungen zurücknehmen, weitere Erweiterung stoppen und deeskalieren statt weiter aufzurüsten.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['encirclement','encircle','provocation','NATO aggression','aggressive expansion','militarization','destabilize','arms race','Cold War mentality','security guarantees broken','Einkreisung','Provokation','NATO-Aggression','Militarisierung'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Izvestia','Kommersant','BelTA','BelTA Russian','Press TV','CGTN','Global Times','China Daily','Xinhua'],'russia_nato_deterrence',2,'NATO build-up is encirclement','NATO-Ausbau ist Einkreisung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('militarisation_overreach','Threat inflation and war-economy drift are a costly overreach','Bedrohungsinflation und Kriegswirtschafts-Drift sind teurer Übereifer','A skeptical Western-European current, distinct from both the Atlanticist consensus and the Kremlin counter-frame, warns that rearmament and rising defence budgets have outpaced the actual near-term Russian threat, diverting public spending from social priorities into a war economy without clear strategic benchmarks. Coverage highlights economists and politicians questioning whether conscription and brigade expansions are proportionate, and flags the risk that threat inflation becomes self-fulfilling. Framing keywords are required here because the same Western outlets that support deterrence in general also carry this internal critique -- publisher coalition alone cannot separate the two stances.','Eine skeptische westeuropäische Strömung, die sich sowohl vom atlantischen Konsens als auch vom Kreml-Gegenframe unterscheidet, warnt, dass Aufrüstung und steigende Verteidigungsbudgets die tatsächliche kurzfristige russische Bedrohung überschritten haben und öffentliche Mittel ohne klare strategische Maßstäbe in eine Kriegswirtschaft umlenken. Die Berichterstattung hebt Ökonomen und Politiker hervor, die die Verhältnismäßigkeit von Wehrpflicht und Brigadenausbau infrage stellen, und warnt vor selbsterfüllender Bedrohungsinflation. Framing-Schlüsselwörter sind hier nötig, weil dieselben westlichen Medien, die Abschreckung grundsätzlich unterstützen, auch diese interne Kritik führen -- die Publisher-Koalition allein trennt die beiden Haltungen nicht.',ARRAY['EUROPE-GERMANY','EUROPE-FRANCE','NON-STATE-EU','EUROPE-NORDIC'],ARRAY['threat inflation','war economy','militarisation','overreach','Bedrohungsinflation','Kriegswirtschaft','Militarisierung','Übereifer','defence-spending burden','Rüstungslast','disproportionate','unverhältnismäßig','alte Ängste','weckt Ängste','Angst vor Aufrüstung','fear of rearmament'],true,ARRAY['Le Monde','El País','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','The Independent','ANSA','La Repubblica','Al Jazeera','Anadolu Agency','Channel NewsAsia'],'russia_nato_deterrence',3,'Militarisation is overreach','Militarisierung ist Übereifer', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tighten_and_seize','Sanctions must be tightened, evasion closed, and frozen Russian assets seized for Ukraine','Sanktionen muessen verschaerft, Umgehung geschlossen und eingefrorenes russisches Vermoegen fuer die Ukraine beschlagnahmt werden','Tighten-and-seize framing (Ukrainian press + Western mainstream + Eastern European) treats sanctions as a necessary economic constraint on the Russian war machine and argues for both deepening the package and shifting from freeze to seizure. Vocabulary: oil price cap enforcement, shadow-fleet interdiction, secondary sanctions on UAE/Turkey/Central Asia transshipment hubs, REPO Act, seizure of $300B Euroclear-held sovereign assets for Ukrainian reconstruction, designation expansion, dual-use export controls. Coverage emphasises evidence of Russian economic stress (rouble pressure, defense industrial bottlenecks, labour shortages), the inadequacy of the current price cap as enforced, and the moral and practical case for converting frozen assets into reparations. Prescription: lower the oil price cap; aggressive secondary sanctions on third-country evaders; full seizure of frozen sovereign assets; expand SDN designations; close dual-use loopholes.','Verschaerfen-und-Beschlagnahmen-Rahmung (ukrainische Medien + westlicher Mainstream + Osteuropa) behandelt Sanktionen als notwendige wirtschaftliche Beschraenkung der russischen Kriegsmaschine und argumentiert sowohl fuer Vertiefung des Pakets als auch fuer Verschiebung von Einfrieren zu Beschlagnahme. Vokabular: Oelpreisdeckel-Durchsetzung, Schatten-Flotten-Abfangen, Sekundaersanktionen gegen Umschlag-Drehscheiben in VAE/Tuerkei/Zentralasien, REPO Act, Beschlagnahme von bei Euroclear gehaltenem Staatsvermoegen ueber 300 Mrd. USD fuer ukrainischen Wiederaufbau, Ausweitung der Listungen, Doppelverwendungs-Exportkontrollen. Berichterstattung betont Belegmaterial fuer russischen Wirtschaftsstress (Rubel-Druck, Verteidigungsindustrie-Engpaesse, Arbeitskraefte-Mangel), Unzulaenglichkeit des aktuellen Preisdeckels in der Durchsetzung und moralisch sowie praktisch den Fall fuer Umwandlung eingefrorenen Vermoegens in Reparationen. Vorschrift: Oelpreisdeckel senken; aggressive Sekundaersanktionen gegen Drittland-Umgeher; volle Beschlagnahme eingefrorenen Staatsvermoegens; SDN-Listungen ausweiten; Doppelverwendungs-Schlupfloecher schliessen.',ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-BALTIC','EUROPE-VISEGRAD','EUROPE-FRANCE','EUROPE-GERMANY','AMERICAS-USA'],ARRAY['tighten sanctions','price cap enforcement','shadow fleet interdiction','secondary sanctions','seize frozen assets','REPO','reparations','SDN designation','dual-use controls','evasion crackdown','Russian economic stress','sanctions package'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Handelsblatt','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','New York Times','Washington Post','Wall Street Journal','Politico','OilPrice','Defense News'],'russia_sanctions_regime',1,'Tighten sanctions and seize frozen assets','Sanktionen verschaerfen und eingefrorenes Vermoegen beschlagnahmen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sanctions_ineffective_and_backfiring','Sanctions hurt Europe more than Russia; frozen-asset seizure would destroy financial trust','Sanktionen schaden Europa staerker als Russland; Beschlagnahme eingefrorenen Vermoegens wuerde Finanzvertrauen zerstoeren','Sanctions-ineffective framing (Russian state press + Global South + Chinese state press + Hungarian-aligned EU) argues that the sanctions package has hurt European economies more severely than Russia, that the Russian economy has successfully adapted through parallel imports, currency controls, BRICS settlement, and Asian energy markets, and that frozen-asset seizure would set a precedent destroying global trust in the Western financial system. Vocabulary: sanctions backfire, European economic harm, Russian economic resilience, BRICS settlement, de-dollarisation, parallel imports, financial weaponisation, trust collapse, multipolar finance. Coverage emphasises German industrial decline, French inflation, US shale-gas profiteering at European expense, growing Global South neutrality, and the historical failure of sanctions to change behaviour. Prescription: lift or phase out sanctions as part of any peace deal; halt frozen-asset seizure plans; restore Russian energy supply to Europe; recognise multipolar financial reality.','Sanktionen-wirkungslos-Rahmung (russische Staatsmedien + Global South + chinesische Staatsmedien + ungarisch-orientierte EU) argumentiert, dass das Sanktionspaket europaeische Wirtschaften schwerer geschaedigt habe als Russland, die russische Wirtschaft sich durch Parallelimporte, Waehrungskontrollen, BRICS-Abwicklung und asiatische Energiemaerkte erfolgreich angepasst habe und Beschlagnahme eingefrorenen Vermoegens einen Praezedenzfall schaffen wuerde, der globales Vertrauen in das westliche Finanzsystem zerstoere. Vokabular: Sanktionen-Bumerang, europaeischer Wirtschaftsschaden, russische Wirtschaftsresilienz, BRICS-Abwicklung, Ent-Dollarisierung, Parallelimporte, Finanzwaffe, Vertrauenseinbruch, multipolare Finanz. Berichterstattung betont deutschen Industrieabbau, franzoesische Inflation, US-Schiefergas-Profite zu europaeischen Lasten, wachsende Global-South-Neutralitaet und das historische Versagen von Sanktionen, Verhalten zu aendern. Vorschrift: Sanktionen im Rahmen jedes Friedensdeals aufheben oder schrittweise abbauen; Beschlagnahmepleane stoppen; russische Energieversorgung Europas wiederherstellen; multipolare Finanzrealitaet anerkennen.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','ASIA-INDIA','NON-STATE-EU'],ARRAY['sanctions backfire','European harm','Russian resilience','BRICS settlement','de-dollarisation','parallel imports','financial weaponisation','trust collapse','multipolar finance','German deindustrialisation','sanctions failed','lift sanctions'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','TRT World','Daily Sabah','O Globo','Bangkok Post','BRICS Info','OilPrice'],'russia_sanctions_regime',2,'Sanctions ineffective and backfiring','Sanktionen wirkungslos und kontraproduktiv', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_break_with_paris_justified','Cutting ties ends a relationship that never became equal','Der Bruch beendet eine Beziehung, die nie gleichberechtigt wurde','Severing relations, expelling diplomats and prosecuting intelligence officers close a colonial-era arrangement in which the former ruler kept bases, currency influence and a veto on security policy long after formal independence.','Der Abbruch der Beziehungen, die Ausweisung von Diplomaten und die Verfolgung von Nachrichtendienstoffizieren beenden ein koloniales Arrangement, in dem die frühere Kolonialmacht noch lange nach der formalen Unabhängigkeit Stützpunkte, Währungseinfluss und ein Veto in der Sicherheitspolitik behielt.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_france_rupture',1,'Ending the colonial relationship','Ende der kolonialen Beziehung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_rupture_deepens_isolation','The break leaves the Sahel with fewer options, not more','Der Bruch lässt der Sahelzone weniger Optionen, nicht mehr','Jailing a diplomat for twenty years, blaming Paris for jihadist attacks and cutting the last diplomatic channels remove partners and aid at the moment the security situation is deteriorating fastest -- and the sovereignty gained is largely rhetorical.','Einen Diplomaten zu zwanzig Jahren Haft zu verurteilen, Paris für dschihadistische Anschläge verantwortlich zu machen und die letzten diplomatischen Kanäle zu kappen, entzieht Partner und Hilfe genau dann, wenn sich die Sicherheitslage am schnellsten verschlechtert -- und die gewonnene Souveränität bleibt weitgehend rhetorisch.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Euronews','The Guardian','El País','Straits Times','Daily Nation','News24','Novinite','Kyiv Post','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News'],'sahel_france_rupture',2,'Isolation, not sovereignty','Isolation statt Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_counterterror_necessity','A legitimate war against armed extremist groups','Ein legitimer Krieg gegen bewaffnete extremistische Gruppen','Sahelian and Nigerian armies, with the partners they have chosen, are fighting internationally designated armed groups that kill civilians, abduct schoolchildren and blockade cities -- and operations that degrade those groups deserve support rather than second-guessing.','Die Armeen der Sahelzone und Nigerias kämpfen gemeinsam mit den von ihnen gewählten Partnern gegen international gelistete bewaffnete Gruppen, die Zivilisten töten, Schulkinder entführen und Städte blockieren -- Operationen, die diese Gruppen schwächen, verdienen Unterstützung statt Zweifel.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA','EUROPE-RUSSIA'],ARRAY['troops kill','soldiers kill','army kill','killed','neutralis','neutraliz','eliminated','surrender','surrendered','repel','repelled','foiled','thwart','operation','offensive against','anti-jihadist','counterterror','counter-terror','arrested','captured','degrade','airstrikes kill','terrorists','bandits','freed','rescued','liberated','neutralisés','abattus','opération','riposte','repoussé','libérés','reddition','terroristes','уничтож','ликвидир','отраж','боевик','击毙','剿灭','解救','قضت','أحبطت','حررت','getötet','zurückgeschlagen'],true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers','The Nation Newspaper','Premium Times Nigeria'],'sahel_jihadist_insurgency',1,'Counterterror necessity','Notwendige Terrorbekämpfung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_state_losing_ground','The state is losing territory it cannot recover','Der Staat verliert Gebiet, das er nicht zurückgewinnen kann','Coordinated assaults on Bamako, the fuel blockade of the capital and the fall of garrison towns show armies that no longer control their own terrain, and a military government whose core promise -- security -- has failed.','Koordinierte Angriffe auf Bamako, die Treibstoffblockade der Hauptstadt und der Fall von Garnisonsstädten zeigen Armeen, die ihr eigenes Terrain nicht mehr kontrollieren, und eine Militärregierung, deren Kernversprechen -- Sicherheit -- gescheitert ist.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],ARRAY['losing','lost control','loses','seize','seized','capture','captured','advance','advancing','offensive','coordinated','simultaneous','blockade','siege','encircl','expand','spread','spreading','sweeping','unprecedented','splinter','press attacks','under pressure','overrun','no longer control','tipping point','crisis','percée','pression','se propage','propagation','bousculent','bascule','blocus','offensive','coordonnées','coordonnée','sans précédent','inédit','fragilis','vacille','recule','étouffer','emprise','s''empare','ampleur','assaut','enlisement','verliert','Vormarsch','beispiellos','Druck','Belagerung','erobert','pierde','avanza','asedio','ofensiva','sin precedentes','perde','avanzata','assedio'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','The Telegraph','Sky News','Euronews','El País','El Mundo','La Repubblica','Corriere della Sera','Straits Times','Bangkok Post','WION','NDTV','The Hindu','Times of India','Janes','Kyiv Post','Novinite','News24','Daily Nation','Council on Foreign Relations','War on the Rocks','Military Times','Defense News','Financial Times','iROZHLAS','Republic TV','The National'],'sahel_jihadist_insurgency',2,'State losing ground','Staat verliert Boden', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_counterinsurgency_abuses','The counterinsurgency is killing the civilians it claims to protect','Die Aufstandsbekämpfung tötet die Zivilisten, die sie zu schützen vorgibt','Drone strikes on weddings, mass executions documented by rights monitors, and the abuses of foreign auxiliaries mean the campaign against the armed groups is itself a major source of civilian death -- and impunity is fuelling recruitment.','Drohnenangriffe auf Hochzeiten, von Menschenrechtsbeobachtern dokumentierte Massenexekutionen und die Übergriffe ausländischer Hilfstruppen machen den Feldzug gegen die bewaffneten Gruppen selbst zu einer Hauptursache ziviler Todesfälle -- und die Straflosigkeit befeuert die Rekrutierung.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],ARRAY['exaction','atrocit','abuses','human rights','Human Rights Watch','HRW','Amnesty','impunity','impunité','droits de l''homme','Menschenrechte','Übergriffe','Gräueltaten','derechos humanos','summary execution','extrajudicial','mass grave','charnier','disappearance','misfire','civilian deaths','killed civilians','civils tués','morts civils','victimes civiles','feared dead','wedding','mariage','market','marché','crimes de l''armée','army behind','par l''armée'],true,ARRAY['Al Jazeera','Al-Ahram','Ahram Online','Al Arabiya','Al Arabiya English','Anadolu Agency','Anadolu Ajansı','TRT World','Daily Sabah','Gulf News','Gulf Times','Arab News','UN News','France 24','France 24 (EN)','Le Monde','Le Figaro','Deutsche Welle','The Guardian','Der Spiegel','Die Zeit','BBC World','Washington Post'],'sahel_jihadist_insurgency',3,'Civilian cost of the campaign','Ziviler Preis des Feldzugs', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_sovereigntist_self_reliance','Reclaiming sovereignty after decades of external tutelage','Rückgewinnung der Souveränität nach Jahrzehnten äußerer Bevormundung','The Sahel governments are choosing their own partners, leaving institutions they judge to serve others'' interests, and refusing the conditionality that came with Western support -- an assertion of independence that the states which lost influence naturally portray as decline.','Die Sahel-Regierungen wählen ihre eigenen Partner, verlassen Institutionen, die aus ihrer Sicht fremden Interessen dienen, und weisen die Auflagen westlicher Unterstützung zurück -- eine Behauptung von Unabhängigkeit, die jene Staaten, die an Einfluss verloren, erwartungsgemäß als Niedergang darstellen.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_junta_consolidation',1,'Sovereigntist realignment','Souveränistische Neuausrichtung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_democratic_closure','Military rule is closing the last civic space','Die Militärherrschaft schließt den letzten zivilgesellschaftlichen Raum','Dissolving every political party, suspending foreign media, forcing out the UN human-rights office and abandoning international courts are not sovereignty measures but the removal of every remaining check -- and the transitions promised at each coup keep receding.','Die Auflösung sämtlicher Parteien, die Suspendierung ausländischer Medien, die Vertreibung des UN-Menschenrechtsbüros und der Austritt aus internationalen Gerichten sind keine Souveränitätsmaßnahmen, sondern die Beseitigung jeder verbliebenen Kontrolle -- und die bei jedem Putsch versprochenen Übergänge rücken immer weiter weg.',ARRAY['AFRICA-SAHEL'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','Euronews','El País','El Mundo','Straits Times','Novinite','News24','Daily Nation','The Standard','Kyiv Post','UN News','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News'],'sahel_junta_consolidation',2,'Democratic closure','Demokratische Schließung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_russian_partnership_delivers','The new partnership delivers what the old one did not','Die neue Partnerschaft liefert, was die alte nicht leistete','Russian forces fight alongside Sahelian armies without demanding governance conditions, intervened to stop an attempted coup and struck the armed groups directly -- results that a decade of Western deployments never produced.','Russische Kräfte kämpfen an der Seite der Sahel-Armeen, ohne Regierungsauflagen zu stellen, griffen ein, um einen Putschversuch zu stoppen, und trafen die bewaffneten Gruppen direkt -- Ergebnisse, die ein Jahrzehnt westlicher Einsätze nie erbrachte.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua'],'sahel_security_patron_contest',1,'Partnership delivers','Partnerschaft liefert',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_patron_model_failing','The replacement security model is buckling','Das neue Sicherheitsmodell gerät ins Wanken','Africa Corps pulled out of Kidal, lost personnel to rebel attacks and is retreating under jihadist pressure, while Türkiye''s drones and training offer capability without the mass required -- the states that expelled their old partners have not found one that can hold the terrain.','Das Africa Corps zog sich aus Kidal zurück, verlor Personal bei Rebellenangriffen und weicht unter dschihadistischem Druck zurück, während die Drohnen und Ausbildung der Türkei Fähigkeiten ohne die nötige Masse bieten -- die Staaten, die ihre alten Partner vertrieben, haben keinen gefunden, der das Terrain halten kann.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','The Guardian','Washington Post','Euronews','El País','Straits Times','Kyiv Post','Janes','Military Times','Defense News','Financial Times','Council on Foreign Relations','War on the Rocks','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','TRT World','Daily Sabah','Gulf News'],'sahel_security_patron_contest',2,'Replacement model failing','Neues Modell scheitert', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_partnership_frame','A sovereign realignment that is finally fighting the real enemy','Eine souveräne Neuausrichtung, die endlich den wahren Feind bekämpft','The Sahel states threw out the powers that failed them, chose partners who impose no political conditions, and are now waging the counterterror campaign the West never delivered -- the criticism from Paris and Washington reflects lost influence, not concern for Sahelians.','Die Sahelstaaten haben die Mächte hinausgeworfen, die an ihnen scheiterten, Partner ohne politische Auflagen gewählt und führen nun jenen Anti-Terror-Feldzug, den der Westen nie lieferte -- die Kritik aus Paris und Washington spiegelt verlorenen Einfluss, nicht Sorge um die Menschen der Sahelzone.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','newsus.cgtn.com','Global Times','China Daily','China Daily - Global Edition','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','German.people.cn'],'sahel_theater',1,'Sovereign realignment','Souveräne Neuausrichtung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_regional_security_response','A regional security emergency being fought by national armies','Ein regionaler Sicherheitsnotstand, den nationale Armeen bekämpfen','Seen from Abuja and the Lake Chad states, this is not a great-power contest but a war of national survival against groups that raid schools, blockade towns and cross borders at will -- and the story is the army''s operations, casualties and capability gaps.','Aus Sicht Abujas und der Tschadseestaaten ist dies kein Großmächtewettstreit, sondern ein Krieg ums nationale Überleben gegen Gruppen, die Schulen überfallen, Städte blockieren und nach Belieben Grenzen überschreiten -- und die Geschichte handelt von Operationen, Verlusten und Fähigkeitslücken der Armee.',ARRAY['AFRICA-NIGERIA','AFRICA-SAHEL'],'{}',true,ARRAY['Punch','Punch Newspapers','Vanguard','Vanguard News','Premium Times Nigeria','The Nation Newspaper'],'sahel_theater',2,'Regional security emergency','Regionaler Sicherheitsnotstand',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_state_collapse_critique','A managed collapse: military rule that delivers neither security nor politics','Ein verwalteter Zusammenbruch: Militärherrschaft ohne Sicherheit und ohne Politik','Four years after the coups the juntas have banned the parties, expelled the monitors and severed the partnerships -- while jihadist coalitions blockade capitals, the north slips away and the replacement patrons retreat. Sovereignty has been asserted; the state has not been rebuilt.','Vier Jahre nach den Putschen haben die Juntas die Parteien verboten, die Beobachter ausgewiesen und die Partnerschaften gekappt -- während dschihadistische Koalitionen Hauptstädte blockieren, der Norden entgleitet und die neuen Schutzmächte zurückweichen. Souveränität wurde behauptet; der Staat wurde nicht wiederaufgebaut.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','The Telegraph','Sky News','Euronews','El País','El Mundo','La Repubblica','Corriere della Sera','Straits Times','Bangkok Post','WION','NDTV','The Hindu','Times of India','Janes','Kyiv Post','Novinite','News24','Daily Nation','The Standard','Republic TV','The National','Council on Foreign Relations','War on the Rocks','Military Times','Defense News','Financial Times','Bloomberg','iROZHLAS'],'sahel_theater',3,'Managed collapse','Verwalteter Zusammenbruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_civilian_cost','The population pays for every side''s campaign','Die Bevölkerung zahlt für den Feldzug jeder Seite','Between jihadist massacres, army airstrikes on markets and the abuses of foreign auxiliaries, civilians in the Sahel and the Lake Chad basin are being killed and displaced by all the armed actors claiming to protect them -- and no external patron has made that safer.','Zwischen dschihadistischen Massakern, Luftangriffen der Armee auf Märkte und den Übergriffen ausländischer Hilfstruppen werden Zivilisten in der Sahelzone und im Tschadseebecken von allen bewaffneten Akteuren getötet und vertrieben, die vorgeben, sie zu schützen -- und keine äußere Schutzmacht hat daran etwas verbessert.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],'{}',true,ARRAY['Al Jazeera','Al-Ahram','Ahram Online','Al Arabiya','Al Arabiya English','Anadolu Agency','Anadolu Ajansı','TRT World','Daily Sabah','Gulf News','Gulf Times','Arab News','UN News','news.un.org'],'sahel_theater',4,'Civilian cost','Ziviler Preis', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_northern_autonomy_claim','Northern Mali is a political question, not only a military one','Nordmali ist eine politische Frage, nicht nur eine militärische','The Tuareg movements hold Kidal and press a decades-old claim over the north that no government has settled by force; treating an unresolved territorial dispute purely as terrorism forecloses the negotiation that any durable outcome requires.','Die Tuareg-Bewegungen halten Kidal und verfolgen einen jahrzehntealten Anspruch auf den Norden, den keine Regierung militärisch gelöst hat; einen ungelösten Territorialkonflikt allein als Terrorismus zu behandeln, verbaut die Verhandlung, die jede dauerhafte Lösung braucht.',ARRAY['AFRICA-SAHEL'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Euronews','The Guardian','El País','Straits Times','Bangkok Post','NDTV','The Hindu','Kyiv Post','Janes','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News','Republic TV','The National'],'sahel_tuareg_separatism',1,'Unresolved territorial claim','Ungelöster Gebietsanspruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_separatism_as_jihadist_alliance','The separatists are a front for the armed extremists','Die Separatisten sind ein Vorwand für die bewaffneten Extremisten','The northern armed groups now attack alongside al-Qaeda-linked fighters and coordinate their claims with them; that alliance disqualifies any presentation of them as a national-liberation movement with a case to negotiate.','Die bewaffneten Gruppen im Norden greifen inzwischen gemeinsam mit al-Qaida-nahen Kämpfern an und stimmen ihre Erklärungen mit ihnen ab; dieses Bündnis widerlegt jede Darstellung als nationale Befreiungsbewegung mit Verhandlungsanspruch.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_tuareg_separatism',2,'A front for the extremists','Vorwand für die Extremisten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('saudi_coalition_legitimacy_restoration','Saudi-led coalition is restoring the internationally-recognised Yemeni government','Saudisch gefuehrte Koalition stellt die international anerkannte jemenitische Regierung wieder her','Saudi, Egyptian, and pan-Arab Sunni framing: the Saudi-led coalition is restoring the internationally-recognised Yemeni government; Houthi rule in Sanaa is an Iran-backed coup; STC self-dissolution and southern unification under the Presidential Leadership Council are necessary; UAE-backed separatism was a destabilising mistake. The vocabulary: "legitimate Yemeni government", "Presidential Leadership Council", "Iran-backed coup", "southern unification", "STC mistake", "Saudi reconstruction". Prescription: continued coalition military pressure on Houthi forces, southern political consolidation under the PLC, Saudi-funded reconstruction.','Saudische, aegyptische und panarabische sunnitische Rahmung: die saudisch gefuehrte Koalition stellt die international anerkannte jemenitische Regierung wieder her; Houthi-Herrschaft in Sanaa ist ein iranisch gestuetzter Putsch; STC-Selbstaufloesung und suedliche Vereinheitlichung unter dem Praesidialen Fuehrungsrat sind noetig; VAE-gestuetzter Separatismus war ein destabilisierender Fehler. Vokabular: "legitime jemenitische Regierung", "Praesidialer Fuehrungsrat", "iranisch gestuetzter Putsch", "suedliche Vereinheitlichung", "STC-Fehler", "saudischer Wiederaufbau". Vorschrift: koalitionaerer Militaer-Druck, suedliche politische Konsolidierung unter dem PLC.',ARRAY['MIDEAST-SAUDI','MIDEAST-EGYPT','MIDEAST-GULF'],ARRAY['legitimate government','Presidential Leadership Council','Iran-backed coup','southern unification','STC mistake','Saudi reconstruction'],true,ARRAY['Al-Ahram','Al Arabiya','Arab News','The National','Khaleej Times','Gulf News','Egypt Today','Daily Sabah','Anadolu Agency'],'saudi_houthi_war',1,'Restoring Yemeni legitimacy','Wiederherstellung jemenitischer Legitimitaet', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('houthi_authority_legitimate_resistance','Houthi-led Sanaa authority is legitimate national resistance to Saudi-Western intervention','Houthi-gefuehrte Sanaa-Autoritaet ist legitimer nationaler Widerstand gegen saudisch-westliche Intervention','Resistance-axis and critical pan-Arab framing: the de facto Sanaa authority represents Yemeni national resistance to Saudi and Western intervention; the Saudi-led coalition is an aggressor that has destroyed Yemeni infrastructure; the STC was a UAE-backed colonial project whose collapse exposes coalition failure. The vocabulary: "Sanaa authority", "national resistance", "Saudi aggression", "coalition aggression", "STC colonial project", "coalition failure". Prescription: international acceptance of de facto Sanaa governance, end of coalition strikes, withdrawal of foreign forces.','Widerstandsachsen- und kritisch panarabische Rahmung: die faktische Sanaa-Autoritaet vertritt jemenitischen nationalen Widerstand gegen saudisch-westliche Intervention; die saudisch gefuehrte Koalition ist ein Aggressor, der jemenitische Infrastruktur zerstoert hat; der STC war ein VAE-gestuetztes Kolonialprojekt, dessen Kollaps das Scheitern der Koalition belegt. Vokabular: "Sanaa-Autoritaet", "nationaler Widerstand", "saudische Aggression", "Koalitions-Aggression", "STC-Kolonialprojekt", "Koalitions-Scheitern". Vorschrift: internationale Anerkennung der faktischen Sanaa-Regierungsfuehrung, Ende der Koalitions-Schlaege.',ARRAY['MIDEAST-YEMEN','MIDEAST-IRAN'],ARRAY['Sanaa authority','national resistance','Saudi aggression','coalition aggression','STC colonial project','coalition failure'],true,ARRAY['Press TV','Al Jazeera','Al Mayadeen','Fars News','IRNA'],'saudi_houthi_war',2,'Sanaa government is legitimate national authority','Regierung in Sanaa als legitime nationale Autoritaet',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('senkaku_japanese_administration','The Senkakus are Japanese-administered territory and Chinese vessel entries are grey-zone pressure','Die Senkaku-Inseln stehen unter japanischer Verwaltung, und das Eindringen chinesischer Schiffe ist Grauzonen-Druck','Administration framing (Japanese and Western press) treats the Senkakus as territory under Japanese administrative control and reads China Coast Guard entries into the surrounding territorial waters and contiguous zone -- along with survey ships, buoys and drilling structures placed near the median line -- as sustained grey-zone pressure intended to normalise a Chinese presence and erode that control without triggering armed conflict. Incidents are counted and protested rather than escalated. Vocabulary: territorial waters, intrusion, grey zone, unacceptable, repeated entry, protest, unilateral development.','Die Verwaltungs-Rahmung (japanische und westliche Presse) betrachtet die Senkaku-Inseln als Gebiet unter japanischer Verwaltungshoheit und deutet das Einlaufen der chinesischen Küstenwache in die umliegenden Hoheitsgewässer und die Anschlusszone -- samt Forschungsschiffen, Bojen und Bohrstrukturen nahe der Mittellinie -- als anhaltenden Grauzonen-Druck, der eine chinesische Präsenz normalisieren und diese Kontrolle aushöhlen soll, ohne einen bewaffneten Konflikt auszulösen. Vorfälle werden gezählt und mit Protesten beantwortet, nicht eskaliert.',ARRAY['ASIA-JAPAN'],ARRAY['territorial waters','intrusion','incursion','grey zone','gray zone','unacceptable','repeated','unilateral','protest','disputed','administration','escalation','Hoheitsgewässer','Eindringen','Grauzone'],true,ARRAY['Japan Times','Nikkei Asia','Asahi Shimbun','Kyodo News','NHK World','Japan Wire by KYODO NEWS','Reuters','Bloomberg','Financial Times','Wall Street Journal','Straits Times','Channel NewsAsia','The Telegraph','The Economist','CSIS','Philippine Daily Inquirer','Times of India','NDTV'],'senkaku_diaoyu_islands',1,'Japanese administration / grey-zone pressure','Japanische Verwaltung / Grauzonen-Druck',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('senkaku_chinese_rights_protection','Diaoyu Dao is inherent Chinese territory and coast guard patrols are lawful rights protection','Diaoyu Dao ist chinesisches Hoheitsgebiet, und die Patrouillen der Küstenwache sind rechtmäßiger Rechtsschutz','Rights-protection framing (Chinese state media) holds that Diaoyu Dao and its affiliated islets have been Chinese territory since ancient times, that China Coast Guard patrols in the surrounding waters are routine and lawful rights-protection law enforcement in Chinese jurisdiction, and that Japanese vessels entering those waters are the intruders being lawfully expelled. Japanese protests are cast as provocation, and the friction is tied to Tokyo''s accelerating remilitarisation rather than to Chinese activity. Vocabulary: rights protection, law enforcement, inherent territory, expel, illegal intrusion, routine patrol, provocation.','Die Rechtsschutz-Rahmung (chinesische Staatsmedien) sieht Diaoyu Dao und die zugehörigen Inseln seit jeher als chinesisches Hoheitsgebiet an. Patrouillen der chinesischen Küstenwache gelten als routinemäßige und rechtmäßige Rechtsdurchsetzung in chinesischem Hoheitsbereich; japanische Schiffe in diesen Gewässern seien die Eindringlinge, die rechtmäßig vertrieben würden. Japanische Proteste werden als Provokation dargestellt und die Reibung der beschleunigten Wiederbewaffnung Tokios zugeschrieben.',ARRAY['ASIA-CHINA'],ARRAY['rights protection','law enforcement','inherent territory','sacred territory','expel','illegally intruding','intrusion into China','routine','since ancient times','provocation','remilitarization','Rechtsdurchsetzung','Hoheitsgebiet'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','Xinhuanet Deutsch'],'senkaku_diaoyu_islands',2,'Chinese rights-protection claim','Chinesischer Rechtsschutz-Anspruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_state_rebuilding','A state rebuilding with regional partners','Ein Staat im Wiederaufbau mit regionalen Partnern','The federal government is steadily recovering ground and capacity: offensives are pushing al-Shabaab out of districts, offshore energy exploration and Turkish training are building genuine state institutions, and neighbours increasingly treat Mogadishu as a partner rather than a problem.','Die Bundesregierung gewinnt stetig Gebiete und Handlungsfähigkeit zurück: Offensiven drängen al-Shabaab aus Distrikten, Offshore-Energieerkundung und türkische Ausbildung schaffen echte staatliche Institutionen, und die Nachbarn behandeln Mogadischu zunehmend als Partner statt als Problem.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY'],ARRAY['transformation','renewal','institutions','cooperation','partnership','drilling','energy','training','offensive','recaptured','Wiederaufbau','Partnerschaft','Institutionen'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Egypt Today','Al-Ahram','ANSA'],'somalia_state_security',1,'The state is being rebuilt','Der Staat wird wiederaufgebaut',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_fragility_and_harm','A fragile state and an abandoned population','Ein fragiler Staat und eine im Stich gelassene Bevölkerung','The recovery is thinner than claimed: famine is returning as aid funding collapses, the capital saw armed clashes over a delayed election, piracy has resumed off the coast, and the counter-terror campaign is inflicting civilian casualties with little accountability.','Die Erholung ist dünner als behauptet: Mit dem Wegbrechen der Hilfsgelder kehrt die Hungersnot zurück, in der Hauptstadt kam es wegen einer verschobenen Wahl zu bewaffneten Zusammenstößen, vor der Küste ist die Piraterie zurück, und der Anti-Terror-Einsatz fordert zivile Opfer ohne nennenswerte Rechenschaft.',ARRAY['AFRICA-HORN'],ARRAY['famine','hunger','malnutrition','drought','aid','clashes','protest','election delay','piracy','pirates','civilian','casualties','Hungersnot','Dürre','Piraterie','Zusammenstöße'],true,ARRAY['UN News','The Guardian','BBC World','BBC','Reuters','Deutsche Welle','Associated Press','Financial Times','Kurier','France 24','France 24 (EN)','Al Jazeera','The Telegraph','Der Spiegel','Die Zeit','Der Standard','DR','Military Times','Defense News'],'somalia_state_security',2,'Fragility and humanitarian failure','Fragilität und humanitäres Versagen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_foreign_militarisation_critique','Foreign militarisation is the destabiliser','Ausländische Militarisierung ist der Destabilisator','Somalia''s insecurity is being deepened from outside: American airstrikes kill civilians while Washington blocks UN support for the African Union mission, and an Israeli military foothold on the coast would turn Somali waters into another front in someone else''s war.','Somalias Unsicherheit wird von außen verschärft: Amerikanische Luftangriffe töten Zivilisten, während Washington die UN-Unterstützung für die Mission der Afrikanischen Union blockiert; ein israelischer Militärstützpunkt an der Küste würde somalische Gewässer zu einer weiteren Front in einem fremden Krieg machen.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['airstrike','strikes','blocks','blockade','foreign','intervention','base','legitimate target','sovereignty','imperial','Luftangriff','Einmischung','Stützpunkt'],true,ARRAY['RT','Press TV','TASS (EN)','Sputnik'],'somalia_state_security',3,'Outside intervention is to blame','Die Einmischung von außen ist schuld', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somaliland_statehood_earned','Recognition of an earned statehood','Anerkennung einer erarbeiteten Staatlichkeit','Somaliland has governed itself peacefully and held competitive elections for over three decades, and recognition simply acknowledges a reality the world has ignored; the partnership with Israel opens trade, minerals and security cooperation for a state long locked out of them.','Somaliland regiert sich seit über drei Jahrzehnten friedlich selbst und hält kompetitive Wahlen ab; die Anerkennung bestätigt lediglich eine Realität, die die Welt ignoriert hat. Die Partnerschaft mit Israel eröffnet einem lange ausgeschlossenen Staat Handel, Rohstoffe und Sicherheitskooperation.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL'],ARRAY['recognition','recognise','recognize','ambassador','embassy','historic','self-determination','democratic','Anerkennung','Botschaft','Selbstbestimmung'],true,ARRAY['Jerusalem Post','Times of Israel','i24NEWS','Haaretz','News24'],'somaliland_recognition_contest',1,'Recognition is deserved','Die Anerkennung ist verdient',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_territorial_integrity','A violation of Somalia''s territorial integrity','Ein Verstoß gegen Somalias territoriale Integrität','Somaliland is part of Somalia under international law and the African Union''s founding principle of inherited borders; a unilateral recognition traded for minerals and a military base is an illegal act that rewards secession and invites external powers to redraw the Horn.','Somaliland ist völkerrechtlich Teil Somalias und unterliegt dem Gründungsprinzip der Afrikanischen Union von der Unverletzlichkeit der ererbten Grenzen. Eine einseitige, gegen Rohstoffe und einen Militärstützpunkt eingetauschte Anerkennung ist ein illegaler Akt, der Sezession belohnt und fremde Mächte einlädt, das Horn neu zu ordnen.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT','MIDEAST-TURKEY'],ARRAY['sovereignty','territorial integrity','illegal','null and void','condemn','reject','violation','interference','Souveränität','territoriale Integrität','verurteilen','völkerrechtswidrig'],true,ARRAY['Al Jazeera','Egypt Today','Al-Ahram','Daily Sabah','Anadolu Agency','Al Arabiya','Arab News','TRT World','Press TV','RT','TASS (EN)','Dawn'],'somaliland_recognition_contest',2,'The recognition is illegitimate','Die Anerkennung ist unrechtmäßig', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somaliland_transactional_scramble','Statehood traded for bases and minerals','Staatlichkeit im Tausch gegen Stützpunkte und Rohstoffe','Recognition is being priced rather than judged: Somaliland has offered critical minerals and basing rights in exchange for diplomatic status, and the result pulls a stable territory into a Red Sea military scramble it has no capacity to control.','Die Anerkennung wird nicht beurteilt, sondern verhandelt: Somaliland bietet kritische Rohstoffe und Stützpunktrechte im Tausch gegen diplomatischen Status an. Das Ergebnis zieht ein bislang stabiles Gebiet in ein militärisches Wettrennen am Roten Meer, das es nicht kontrollieren kann.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['minerals','critical mineral','military base','basing','port','leverage','scramble','strategic','maelstrom','Bodenschätze','Stützpunkt','Militärbasis'],true,ARRAY['Financial Times','Le Monde','Deutsche Welle','IISS','Reuters','BBC World','France 24','France 24 (EN)','Die Zeit','Der Standard','Daily Nation','The Standard'],'somaliland_recognition_contest',3,'A transactional great-power bargain','Ein transaktionaler Großmachthandel', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('south_asia_indian_account','India is the status-quo power defending its territory against a militancy-exporting neighbour','Indien ist die Status-quo-Macht, die ihr Gebiet gegen einen Militanz exportierenden Nachbarn verteidigt','The Indian account (Indian mainstream press) runs through the three disputes in which India is the acting party: Jammu and Kashmir is Indian territory and the question is closed, the attacks on Indian soil are traced to groups operating from Pakistan with official tolerance, and the Indus Waters Treaty is an arrangement from another era that a state sponsoring militancy cannot expect to continue unchanged.','Die indische Darstellung (indische Leitmedien) zieht sich durch die drei Streitfälle, in denen Indien die handelnde Partei ist: Jammu und Kaschmir ist indisches Territorium und die Frage ist entschieden, die Anschläge auf indischem Boden werden auf Gruppen zurückgeführt, die mit offizieller Duldung von Pakistan aus operieren, und der Indus-Wasservertrag ist eine Regelung aus einer anderen Zeit, deren unveränderte Fortführung ein Staat, der Militanz unterstützt, nicht erwarten kann.',ARRAY['ASIA-INDIA'],ARRAY['integral','vacate','terror','Sindoor','Lashkar','sponsor','unwarranted','outdated','sovereignty'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'south_asia_theater',1,'Indian claim and counter-terrorism framing','Indische Ansprüche und Terrorbekämpfung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('south_asia_pakistani_security_account','Pakistan is fighting militancy on two fronts against externally backed enemies','Pakistan bekämpft Militanz an zwei Fronten gegen von außen unterstützte Gegner','The Pakistani security account (Pakistani press) covers the two conflicts in which Pakistan is the acting party: strikes into Afghanistan are presented as hitting Tehreek-e-Taliban sanctuaries that Kabul will not close, and the insurgency in Balochistan is presented as externally sponsored terrorism rather than an indigenous political movement. In both, Pakistan casts itself as responding to violence organised beyond its control.','Die pakistanische Sicherheitsdarstellung (pakistanische Presse) umfasst die beiden Konflikte, in denen Pakistan die handelnde Partei ist: Angriffe nach Afghanistan gelten als Schläge gegen Rückzugsgebiete der Tehreek-e-Taliban, die Kabul nicht schließen will, und der Aufstand in Belutschistan gilt als von außen gesteuerter Terrorismus statt als einheimische politische Bewegung. In beiden Fällen stellt sich Pakistan als reagierend auf Gewalt dar, die jenseits seiner Kontrolle organisiert wird.',ARRAY['ASIA-PAKISTAN'],ARRAY['terrorist','militant','sanctuar','TTP','BLA','Ghazab','Indian-backed','operation','retaliat'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation'],'south_asia_theater',2,'Pakistani counter-terrorism framing','Pakistanische Terrorbekämpfungs-Darstellung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('south_asia_pakistani_grievance','India is the coercive party: occupier, water aggressor and fabricator of charges','Indien ist die erzwingende Partei: Besatzer, Wasseraggressor und Erfinder von Vorwürfen','The Pakistani account (Pakistani press) reverses the Indian one across the same three disputes: Kashmir''s status is unresolved and its people are owed self-determination rather than a settlement imposed from Delhi, the Pahalgam allegations have never been substantiated and serve to justify pressure and strikes, and suspending a treaty on which a downstream population depends for its crops and drinking water is coercion whatever the pretext.','Die pakistanische Darstellung (pakistanische Presse) kehrt die indische in denselben drei Streitfällen um: Kaschmirs Status ist ungeklärt und seiner Bevölkerung steht Selbstbestimmung zu statt einer von Delhi auferlegten Lösung, die Vorwürfe zu Pahalgam wurden nie belegt und dienen der Rechtfertigung von Druck und Angriffen, und die Aussetzung eines Vertrags, von dem eine flussabwärts lebende Bevölkerung für Ernten und Trinkwasser abhängt, ist Zwang, welcher Vorwand auch genannt wird.',ARRAY['ASIA-PAKISTAN'],ARRAY['occupied','disputed','self-determination','weaponisation','water aggression','false narrative','unsubstantiated','binding'],true,ARRAY['Dawn','Express Tribune','The Express Tribune','The News International','The Nation'],'south_asia_theater',3,'Pakistani grievance framing','Pakistanische Beschwerde-Darstellung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('south_asia_indian_critique_of_pakistan','Pakistan''s conduct beyond its borders and failures within them destabilise the region','Pakistans Verhalten jenseits seiner Grenzen und sein Versagen im Inneren destabilisieren die Region','The Indian critique (Indian mainstream press) addresses the conflicts where Pakistan, not India, is the acting party: the air campaign in Afghanistan is called an assault on the sovereignty of a neighbour and a threat to regional peace after UN findings on civilian deaths, and the insurgency in Balochistan is treated as evidence of Pakistani state failure, with Islamabad''s allegations of Indian backing dismissed as deflection from internal failings.','Die indische Kritik (indische Leitmedien) betrifft die Konflikte, in denen Pakistan und nicht Indien die handelnde Partei ist: Die Luftkampagne in Afghanistan wird nach UN-Feststellungen zu zivilen Opfern als Angriff auf die Souveränität eines Nachbarn und als Bedrohung des regionalen Friedens bezeichnet, und der Aufstand in Belutschistan gilt als Beleg für das Versagen des pakistanischen Staates, wobei Islamabads Vorwürfe indischer Unterstützung als Ablenkung von inneren Defiziten zurückgewiesen werden.',ARRAY['ASIA-INDIA'],ARRAY['sovereignty','assault','civilian','internal failing','civil war','condemn','baseless','destabilis'],true,ARRAY['Times of India','The Times of India','Hindustan Times','NDTV','The Hindu','Indian Express','The Indian Express','WION','Republic TV','Republic World','DD India'],'south_asia_theater',4,'Indian framing of Pakistan as destabiliser','Indische Darstellung Pakistans als Destabilisator', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('south_asia_international_rights','Across every front the cost falls on civilians and dissenters','An jeder Front tragen Zivilisten und Andersdenkende die Kosten','International framing (Western mainstream, wire services and Al Jazeera) sets aside each government''s territorial case and reports what the disputes do to the people inside them: the dead and displaced of the Pakistan-Afghanistan strikes and the collapse of successive ceasefires, protests met with force on both sides of the Kashmir line, and a Baloch activist sentenced to life amid enforced disappearances and curbs on peaceful protest.','Die internationale Darstellung (westliche Leitmedien, Nachrichtenagenturen und Al Jazeera) lässt die territorialen Ansprüche der Regierungen beiseite und berichtet, was die Konflikte den Menschen in ihnen antun: die Toten und Vertriebenen der pakistanisch-afghanischen Angriffe und das Scheitern aufeinanderfolgender Waffenruhen, Proteste, denen auf beiden Seiten der Kaschmir-Linie mit Gewalt begegnet wird, und eine belutschische Aktivistin, die inmitten von Fällen des Verschwindenlassens und Einschränkungen friedlichen Protests zu lebenslanger Haft verurteilt wurde.',ARRAY['ASIA-INDIA','ASIA-PAKISTAN','ASIA-AFGHANISTAN'],ARRAY['civilian','killed','hospital','displaced','ceasefire','protest','rights','disappearance','Mahrang','detention'],true,ARRAY['Reuters','BBC World','Associated Press','Deutsche Welle','The Guardian','France 24','France 24 (EN)','Euronews','Al Jazeera','Die Zeit','NPR'],'south_asia_theater',5,'International civilian-cost and rights framing','Internationale Darstellung ziviler Kosten und Rechte', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('scs_chinese_sovereignty_claim','China''s South China Sea claims are historic, lawful, and enforcement is defensive','Chinas Ansprüche im Südchinesischen Meer sind historisch und rechtmäßig, die Durchsetzung ist defensiv','Sovereignty framing (Chinese state media) holds that China''s claims to the Nansha, Xisha, Zhongsha and Huangyan features rest on historic rights and are consistent with international law; that the 2016 arbitral award is invalid, non-binding and "waste paper"; and that coast guard activity is routine rights-protection law enforcement in Chinese waters. It locates the source of instability in the Philippines and in external powers -- chiefly the United States, and increasingly Japan -- whose operations, exercises and arms transfers are cast as militarising the sea and as interference by states that are not parties to the dispute. Vocabulary: indisputable sovereignty, historic rights, waste paper, rights protection, law enforcement, provocation, hype, external interference, militarisation.','Die Souveränitäts-Rahmung (chinesische Staatsmedien) sieht Chinas Ansprüche auf die Nansha-, Xisha-, Zhongsha- und Huangyan-Formationen als historisch begründet und völkerrechtskonform an; der Schiedsspruch von 2016 sei ungültig, unverbindlich und ein "Stück Altpapier". Küstenwacheinsätze gelten als routinemäßige Rechtsdurchsetzung in chinesischen Gewässern. Als Ursache der Instabilität werden die Philippinen und externe Mächte benannt -- vor allem die USA und zunehmend Japan --, deren Operationen, Manöver und Waffenlieferungen als Militarisierung des Meeres und als Einmischung nicht beteiligter Staaten dargestellt werden.',ARRAY['ASIA-CHINA'],ARRAY['indisputable sovereignty','historic rights','waste paper','rights protection','law enforcement','provocation','hype','interference','militariz','militaris','unshirkable','Nansha','Xisha','Huangyan','Souveränität','Rechtsdurchsetzung'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'south_china_sea_claims',1,'Chinese sovereignty claim','Chinesischer Souveränitätsanspruch',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('scs_rules_based_maritime_order','China''s claims lack legal basis and its conduct coerces smaller claimants','Chinas Ansprüche entbehren einer Rechtsgrundlage, sein Vorgehen setzt kleinere Anrainer unter Druck','Rules-based framing (Western, Philippine, Japanese and Southeast Asian press) treats the 2016 arbitral award as binding and the nine-dash line as without legal basis under UNCLOS, and reads Chinese coast guard and maritime-militia conduct -- water cannon, blocking, shadowing, and structures placed on contested features -- as coercion of smaller claimants inside their exclusive economic zones. It presents allied naval presence, joint patrols, exercises such as Balikatan and an effective ASEAN code of conduct as the legitimate response, and treats incidents at Scarborough Shoal and Second Thomas Shoal as tests of the alliance. Vocabulary: arbitral ruling, rules-based order, UNCLOS, exclusive economic zone, coercion, harassment, water cannon, illegal, freedom of navigation, alliance, code of conduct.','Die regelbasierte Rahmung (westliche, philippinische, japanische und südostasiatische Presse) betrachtet den Schiedsspruch von 2016 als bindend und die Neun-Striche-Linie als völkerrechtlich unbegründet. Das Vorgehen der chinesischen Küstenwache und Seemiliz -- Wasserwerfer, Blockaden, Verfolgungsfahrten und Bauten auf umstrittenen Formationen -- gilt als Nötigung kleinerer Anrainer in deren ausschließlichen Wirtschaftszonen. Als legitime Antwort erscheinen alliierte Marinepräsenz, gemeinsame Patrouillen, Manöver wie Balikatan und ein wirksamer ASEAN-Verhaltenskodex.',ARRAY['ASIA-SOUTHEAST','AMERICAS-USA','ASIA-JAPAN'],ARRAY['arbitral','rules-based','UNCLOS','exclusive economic zone','coercion','coercive','harassment','water cannon','illegal','freedom of navigation','code of conduct','aggressive','incursion','Schiedsspruch','Wasserwerfer','Nötigung','Verhaltenskodex'],true,ARRAY['Reuters','Philippine Daily Inquirer','Straits Times','Channel NewsAsia','CSIS','Nikkei Asia','Bangkok Post','Japan Times','Asahi Shimbun','Kyodo News','Associated Press','Bloomberg','Washington Post','Wall Street Journal','BBC World','The Economist','The Telegraph','Sky News','The Australian','Al Jazeera','France 24 (EN)','Die Zeit','Frankfurter Allgemeine','Handelsblatt','NZZ','Chatham House','Defense News','Military Times','Janes','Jakarta Globe','VN Express','The Star','The Hindu','WION'],'south_china_sea_claims',2,'Rules-based maritime order','Regelbasierte maritime Ordnung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_hormuz_freedom_of_navigation','Western coalition: free passage through Hormuz is non-negotiable','Westliche Koalition: freie Durchfahrt durch Hormuz ist nicht verhandelbar','The US-UK-France-Saudi-UAE coalition describes the Strait of Hormuz as an "international strait" governed by UNCLOS, through which "freedom of navigation" must be guaranteed regardless of Iranian sovereignty claims. Iranian harassment of tankers, IRGC speedboat sorties, and threats of closure are framed as illegal under international maritime law and as "weaponisation" of a global commons. The US "Fifth Fleet" headquartered in Bahrain, the periodic UK-French-led "multinational maritime force" deployments, and "naval escort" missions for tankers are framed as the legitimate defence of an order on which the world economy depends. The narrative explicitly refuses to recognise any Iranian veto over commercial passage: any Iranian closure attempt is treated as an act of war justifying military response. The narrative prescribes: persistent multinational naval presence, regular freedom-of-navigation operations through Iranian-claimed waters, designation of IRGC naval forces as terrorist when they harass commercial shipping, and pre-positioned military response options for any closure attempt.','Die US-UK-Frankreich-Saudi-VAE-Koalition beschreibt die Strasse von Hormuz als "internationale Meerenge" unter UNCLOS, durch die "Freiheit der Navigation" garantiert sein muss, unabhaengig von iranischen Souveraenitaetsansprueche. Iranische Tanker-Belaestigung, IRGC-Schnellboot-Vorstoesse und Schliessungsdrohungen gelten als illegal unter Seerecht und als "Bewaffnung" eines globalen Allmendeguts. Die in Bahrain stationierte US-"Fuenfte Flotte", die periodischen UK-franzoesisch gefuehrten "multinationalen Maritime-Streitkraft"-Stationierungen und "Marine-Eskorten" fuer Tanker gelten als legitime Verteidigung einer Ordnung, von der die Weltwirtschaft abhaengt. Verschreibung: anhaltende multinationale Marinepraesenz, regelmaessige Freedom-of-Navigation-Operationen durch von Iran beanspruchte Gewaesser, FTO-Designierung der IRGC-Marine bei Belaestigung kommerzieller Schifffahrt, vorbereitete militaerische Reaktion auf Schliessungsversuche.',ARRAY['AMERICAS-USA','EUROPE-UK','EUROPE-FRANCE','MIDEAST-SAUDI'],ARRAY['freedom of navigation','free passage','free shipping','international strait','UNCLOS','global commons','Fifth Fleet','US Fifth Fleet','multinational maritime force','naval escort','maritime coalition','NATO maritime','weaponisation of','weaponize the strait','cannot close','must remain open','global trade','energy security','oil chokepoint','global oil supply','IRGC harassment','tanker harassment','rules-based maritime order','freedom of navigation operations','FONOPs','right to defend shipping'],true,ARRAY['Fox News','Wall Street Journal','WSJ','New York Post','CNN','New York Times','The New York Times','Washington Post','The Washington Post','Bloomberg','NPR','MSNBC','Associated Press','Reuters','Jerusalem Post','The Jerusalem Post','Times of Israel','Haaretz','i24NEWS','JNS','Israel Hayom','Ynet','Arab News','Saudi Gazette','Al Arabiya','Al Arabiya English','Asharq Al-Awsat','The National','Khaleej Times','Gulf News','BBC','BBC World','The Guardian','Financial Times','Le Figaro','France 24','France 24 (EN)'],'strait_of_hormuz_sovereignty',1,'Free passage non-negotiable','Freie Durchfahrt nicht verhandelbar', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_hormuz_sovereign_pressure','Iran: Hormuz as sovereign waters and deterrence asymmetry','Iran: Hormuz als souveraene Gewaesser und Abschreckungsasymmetrie','Iran describes the Strait of Hormuz as Iranian "sovereign waters" — territorial waters extending from Iran''s southern coast — over which Iran has full legal authority. The threat of closure is framed not as an outlaw act but as Iran''s "deterrence asymmetry" — the only credible counter to overwhelming US naval superiority and the imperial pressure regime against Iran. The "IRGC navy" patrols its own coast; foreign warships in the strait are characterised as "foreign occupation" of the Persian Gulf. The vocabulary of "global oil supply" and "free passage" is reframed as Western leverage masquerading as principle: the strait stays open because Iran chooses not to close it, not because the US Fifth Fleet enforces openness. Iran can shut the chokepoint within hours if pushed beyond a red line — and that capability is precisely what makes US-Israeli aggression deterred at the margin. The narrative prescribes: continued IRGC naval presence, periodic demonstrations of closure capability (the "30-second close" exercises), maintenance of asymmetric tools (anti-ship missiles, naval mines, fast-attack craft, drone swarms), and explicit framing of any US enforcement as casus belli.','Iran beschreibt die Strasse von Hormuz als iranische "souveraene Gewaesser" — Territorialgewaesser, die sich von Irans Suedkueste erstrecken — ueber die Iran volle rechtliche Autoritaet hat. Die Schliessungsdrohung wird nicht als Gesetzlosigkeit gerahmt, sondern als Irans "Abschreckungsasymmetrie" — die einzige glaubwuerdige Gegenmacht zu ueberwaeltigender US-Marineueberlegenheit und dem imperialen Druckregime gegen Iran. Die "IRGC-Marine" patrouilliert ihre eigene Kueste; fremde Kriegsschiffe in der Strasse gelten als "fremde Besatzung" des Persischen Golfs. Vokabular von "globaler Oelversorgung" und "freier Durchfahrt" wird als westliche Hebelwirkung umgedeutet, die sich als Prinzip ausgibt: die Strasse bleibt offen, weil Iran sie nicht schliesst, nicht weil die US-Fuenfte-Flotte Offenheit erzwingt. Iran kann den Engpass innerhalb von Stunden schliessen, wenn ueber eine rote Linie hinaus gedraengt — und diese Faehigkeit ist genau das, was US-israelische Aggression am Rand abschreckt. Verschreibung: anhaltende IRGC-Marinepraesenz, periodische Demonstrationen der Schliessungsfaehigkeit, asymmetrische Werkzeuge (Anti-Schiffs-Raketen, Seeminen, Schnellangriff-Boote, Drohnenschwaerme), und Rahmung jeder US-Durchsetzung als Casus Belli.',ARRAY['MIDEAST-IRAN'],ARRAY['sovereign waters','Iranian territorial waters','Iranian waters','deterrence asymmetry','asymmetric deterrence','IRGC navy','IRGC maritime','Persian Gulf is Iranian','foreign occupation Persian Gulf','foreign warships','Hormuz is ours','closure capability','red line','cross the red line','imperial pressure regime','Western maritime hegemony','within hours','in hours we can close','naval mines','fast attack craft','drone swarm','anti-ship missile','Persian Gulf defenders'],true,ARRAY['Press TV','IRNA','Fars News','Fars News Agency','Tasnim News','Mehr News','Al Manar','Al Mayadeen'],'strait_of_hormuz_sovereignty',2,'Sovereign waters and deterrence','Souveraene Gewaesser und Abschreckung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sudan_state_legitimacy','Sudan''s army is the constitutional state defending against an RSF mutiny','Sudans Armee ist der verfassungsmaessige Staat gegen eine RSF-Meuterei','Pan-Arab Egyptian, Saudi, and Turkish-state coverage frames the Sudanese army as the constitutional state defending against an armed mutiny by the RSF. The vocabulary: "constitutional authority", "armed rebellion", "RSF paramilitary mutiny", "territorial integrity", "national army", "counter-insurgency", "Burhan as legitimate sovereign". Islamist / Brotherhood elements within the army are treated as a manageable internal matter relative to the existential RSF threat. Prescription: international support for the Sudanese government, sanctions on RSF backers, no negotiations that legitimise RSF as a co-equal party.','Panarabische aegyptische, saudische und tuerkische Staatsberichterstattung rahmt die sudanesische Armee als verfassungsmaessigen Staat gegen einen bewaffneten Aufstand der RSF. Vokabular: "verfassungsmaessige Autoritaet", "bewaffnete Rebellion", "RSF-paramilitaerische Meuterei", "territoriale Integritaet", "Nationalarmee", "Aufstandsbekaempfung", "Burhan als legitimer Souveraen". Islamistische / Bruderschafts-Elemente innerhalb der Armee gelten als kontrollierbares internes Thema gegenueber der existenziellen RSF-Bedrohung. Vorschrift: internationale Unterstuetzung der sudanesischen Regierung, Sanktionen gegen RSF-Unterstuetzer, keine Verhandlungen, die die RSF als gleichberechtigte Partei legitimieren.',ARRAY['MIDEAST-EGYPT','MIDEAST-SAUDI'],ARRAY['constitutional authority','armed rebellion','RSF paramilitary','territorial integrity','national army','counter-insurgency','legitimate sovereign'],true,ARRAY['Al-Ahram','Al Arabiya','Arab News','Egypt Today','Khaleej Times','Daily Sabah','Anadolu Agency','The National'],'sudan_civil_war',1,'Legitimate state vs paramilitary','Legitimer Staat gegen Paramilitaer',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sudan_humanitarian_catastrophe','Both sides commit atrocities; RSF violence in Darfur amounts to genocide','Beide Seiten begehen Gewalttaten; RSF-Gewalt in Darfur kommt einem Genozid gleich','UN, Western humanitarian, and pan-Arab non-aligned outlets frame the Sudan war as a humanitarian catastrophe with genocide-level violence concentrated in Darfur and El Fasher. Evidence: 12M displaced, induced famine via siege and aid blockade, systematic ethnic violence by RSF against Masalit and other African communities, hospital and aid-convoy strikes, UN investigative findings of genocide in El Fasher. The vocabulary: "genocide", "famine", "starvation as a weapon", "hospital strikes", "displaced", "mass atrocity", "Darfur ethnic cleansing", "civilian protection". Prescription: immediate ceasefire, unimpeded humanitarian access, accountability via ICC, neither side has a legitimate path to total victory.','UN, westliche humanitaere und panarabische nicht-ausgerichtete Medien rahmen den Sudan-Krieg als humanitaere Katastrophe mit Gewalt auf Genozid-Niveau in Darfur und Al-Faschir. Belege: 12 Mio. Vertriebene, herbeigefuehrte Hungersnot durch Belagerung und Hilfsblockade, systematische ethnische Gewalt der RSF gegen Masalit und andere afrikanische Gemeinschaften, Angriffe auf Krankenhaeuser und Hilfskonvois, UN-Untersuchungen zu Genozid in Al-Faschir. Vokabular: "Genozid", "Hungersnot", "Aushungern als Waffe", "Angriffe auf Krankenhaeuser", "Vertriebene", "Massenverbrechen", "ethnische Saeuberung in Darfur", "Zivilschutz". Vorschrift: sofortiger Waffenstillstand, ungehinderter humanitaerer Zugang, Rechenschaft per IStGH, keine Seite hat einen legitimen Weg zum Totalsieg.',ARRAY['NON-STATE-EU','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-UK','AMERICAS-USA'],ARRAY['genocide','famine','starvation','hospital strike','displaced','mass atrocity','Darfur','El Fasher','civilian protection','ICC'],true,ARRAY['UN News','BBC World','Deutsche Welle','France 24 (EN)','Le Monde','The Guardian','Reuters','Associated Press','NPR','Sky News','Tagesschau','Al Jazeera','Financial Times'],'sudan_civil_war',2,'Humanitarian catastrophe and genocide','Humanitaere Katastrophe und Genozid', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sudan_proxy_war_critique','Sudan war is sustained by UAE arms to RSF; Egypt/Saudi back the army','Sudan-Krieg wird durch VAE-Waffen an die RSF aufrechterhalten; Aegypten und Saudi-Arabien stuetzen die Armee','Investigative international and Turkish/Iranian state media frame the Sudan war as "the world''s worst proxy war": the RSF is sustained by UAE arms transferred via Chad and Ottilien Ethiopian routes; Russian Africa Corps / Wagner extracts gold from RSF-held territories; Egypt and Saudi backing of the army is the counter-axis. External powers, not Sudanese choice, drive the war''s length. The vocabulary: "proxy war", "UAE arms", "Wagner gold", "Chad transit", "weapons pipeline", "Gulf interference". Prescription: international sanctions on RSF backers, transparency on arms flows, condition Gulf relationships on Sudan stance.','Investigative internationale sowie tuerkische und iranische Staatsmedien rahmen den Sudan-Krieg als "weltweit schlimmsten Stellvertreterkrieg": die RSF werde durch VAE-Waffen ueber Tschad und aethiopische Routen versorgt; Russlands Africa Corps / Wagner foerdere Gold aus RSF-Gebieten; aegyptisch-saudische Stuetzung der Armee bilde die Gegenachse. Externe Maechte, nicht sudanesische Entscheidung, verlaengern den Krieg. Vokabular: "Stellvertreterkrieg", "VAE-Waffen", "Wagner-Gold", "Tschad-Transit", "Waffenpipeline", "Golf-Einmischung". Vorschrift: internationale Sanktionen gegen RSF-Unterstuetzer, Transparenz ueber Waffenfluesse, Golf-Beziehungen an Sudan-Position knuepfen.',ARRAY['MIDEAST-GULF','EUROPE-RUSSIA'],ARRAY['proxy war','UAE arms','Wagner','Chad transit','weapons pipeline','Gulf interference','Africa Corps','RSF backers'],true,ARRAY['Al Jazeera','Anadolu Agency','TRT World','Daily Sabah','Press TV','Times of Israel','Deutsche Welle','Reuters','Wall Street Journal','Le Monde','Financial Times'],'sudan_civil_war',3,'UAE-backed proxy war','Stellvertreterkrieg mit Unterstuetzung der VAE', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('coalition_counter_isis_necessary','Coalition counter-ISIS operations are necessary until ISIS threat is contained','Anti-IS-Operationen der Koalition sind notwendig, bis die IS-Bedrohung eingedaemmt ist','Western mainstream and Israeli framing: US, UK, French, and Italian forces in Syria and Iraq remain necessary to contain ISIS residue. SDF custody of ~10,000 ISIS detainees at al-Hol, al-Roj, and Hasaka prisons carries severe prison-break risk; the transitional government lacks capacity to take over; sustained coalition presence is the prudent option. The vocabulary: "ISIS resurgence risk", "prison-break risk", "detainee custody", "coalition mandate", "Inherent Resolve continuation", "Erbil base". Prescription: maintain coalition presence, continue strikes, condition detainee transfers on receiving-country capacity.','Westliche Mainstream- und israelische Rahmung: US-, britische, franzoesische und italienische Kraefte in Syrien und Irak bleiben noetig, um IS-Reste einzudaemmen. SDF-Verwahrung von rund 10.000 IS-Haeftlingen in al-Hol, al-Roj und Hasaka-Gefaengnis birgt schweres Ausbruchsrisiko; der Uebergangsregierung fehlt die Kapazitaet zur Uebernahme; anhaltende Koalitionspraesenz ist die vorsichtige Option. Vokabular: "IS-Wiedererstarken", "Ausbruchsrisiko", "Haeftlingsverwahrung", "Koalitionsmandat", "Inherent Resolve fortsetzen", "Erbil-Stuetzpunkt". Vorschrift: Koalitionspraesenz aufrechterhalten, Schlaege fortsetzen, Haeftlingsverlegungen an Kapazitaet der Empfaengerstaaten knuepfen.',ARRAY['AMERICAS-USA','EUROPE-UK','EUROPE-FRANCE','MIDEAST-ISRAEL'],ARRAY['ISIS resurgence','prison-break','detainee custody','coalition mandate','Inherent Resolve','Erbil','counter-terrorism'],true,ARRAY['Reuters','Associated Press','BBC World','France 24 (EN)','Jerusalem Post','Fox News','Wall Street Journal','CNN','NPR','Deutsche Welle'],'syria_counter_terror',1,'Coalition counter-ISIS presence is necessary','Anti-IS-Praesenz der Koalition ist notwendig',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('foreign_military_withdrawal_demand','Foreign military presence violates sovereignty and should withdraw','Auslaendische Militaerpraesenz verletzt Souveraenitaet und sollte abgezogen werden','Russian, Iranian, Turkish, and post-Assad Syrian framing: Western military presence in Syria violates Syrian sovereignty; counter-ISIS operations should transfer to the new Syrian government and Iraqi authorities; ISIS detainees should be transferred to national jurisdictions; the coalition mandate has outlived its purpose. The vocabulary: "foreign occupation", "sovereignty violation", "withdrawal", "national jurisdiction", "transfer of responsibility", "mandate expired". Prescription: full coalition withdrawal, transfer of detainees, end of US-SDF partnership, Syrian forces assume counter-terrorism responsibility.','Russische, iranische, tuerkische und nach-Assad-syrische Rahmung: westliche Militaerpraesenz in Syrien verletzt die syrische Souveraenitaet; Anti-IS-Operationen sollten an die neue syrische Regierung und irakische Behoerden uebergehen; IS-Haeftlinge sollten an nationale Jurisdiktionen uebergeben werden; das Koalitionsmandat ist ueberholt. Vokabular: "auslaendische Besatzung", "Souveraenitaetsverletzung", "Abzug", "nationale Jurisdiktion", "Uebertragung der Verantwortung", "Mandat abgelaufen". Vorschrift: vollstaendiger Abzug der Koalition, Uebergabe der Haeftlinge, Ende der US-SDF-Partnerschaft, syrische Kraefte uebernehmen Anti-Terror-Verantwortung.',ARRAY['EUROPE-RUSSIA','MIDEAST-IRAN','MIDEAST-TURKEY','MIDEAST-LEVANT'],ARRAY['foreign occupation','sovereignty violation','withdrawal','national jurisdiction','mandate expired','transfer responsibility'],true,ARRAY['SANA','Anadolu Agency','TRT World','Press TV','Fars News','IRNA','TASS (EN)','RT','Al Mayadeen'],'syria_counter_terror',2,'Foreign forces should leave Syria','Auslaendische Truppen sollten Syrien verlassen',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('israeli_strikes_on_syria_legitimate','Israeli strikes on Syria are legitimate preventive defense','Israelische Schlaege gegen Syrien sind legitime Praevention','Israeli sources frame strikes inside Syria as legitimate preventive defense: residual Hezbollah logistics and Iranian assets in southern Syria remain a threat; the new transitional government inherits the security obligation; Golan-adjacent buffer-zone enforcement is a non-negotiable Israeli security perimeter. The vocabulary: "preventive defense", "Iranian assets", "Hezbollah logistics", "buffer zone enforcement", "Golan security perimeter", "weapons transfer interdiction". Prescription: continue strikes until threat capability is degraded, maintain buffer zone, condition relations with Damascus on Israeli security demands.','Israelische Quellen rahmen Schlaege in Syrien als legitime Praevention: verbliebene Hisbollah-Logistik und iranische Assets im Sueden Syriens bleiben eine Bedrohung; die neue Uebergangsregierung uebernimmt die Sicherheitsverpflichtung; die Durchsetzung der Golan-Pufferzone ist ein nicht verhandelbarer israelischer Sicherheitsperimeter. Vokabular: "Praevention", "iranische Assets", "Hisbollah-Logistik", "Pufferzonen-Durchsetzung", "Golan-Sicherheitsperimeter", "Unterbindung von Waffentransfers". Vorschrift: Schlaege fortsetzen, bis Bedrohungs-Kapazitaet abgebaut ist, Pufferzone aufrechterhalten, Beziehungen mit Damaskus an israelische Sicherheitsforderungen knuepfen.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['preventive defense','Iranian assets','Hezbollah logistics','buffer zone','Golan','weapons transfer','self-defense'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Arutz Sheva','Ynetnews','Fox News'],'syria_israeli_strikes',1,'Israeli strikes are legitimate self-defense','Israelische Schlaege sind legitime Selbstverteidigung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('syrian_sovereignty_under_israeli_aggression','Israeli strikes violate Syrian sovereignty and undermine the transition','Israelische Schlaege verletzen syrische Souveraenitaet und untergraben den Uebergang','Pan-Arab, Iranian, Turkish, and post-Assad Syrian state coverage frames Israeli strikes on Syrian territory as aggression that violates Syrian sovereignty and undermines the legitimate transition. The buffer zone south of Damascus is framed as illegal occupation. The vocabulary: "Israeli aggression", "sovereignty violation", "illegal occupation", "buffer zone occupation", "international law", "UN Charter Article 2", "Syrian airspace violation". Prescription: end Israeli strikes, withdraw from buffer zone, condition any Syrian-Israeli engagement on Israeli compliance with international law.','Panarabische, iranische, tuerkische und nach-Assad-syrische Staatsberichterstattung rahmt israelische Schlaege auf syrisches Territorium als Aggression, die syrische Souveraenitaet verletzt und den legitimen Uebergang untergraebt. Die Pufferzone suedlich von Damaskus gilt als illegale Besatzung. Vokabular: "israelische Aggression", "Verletzung der Souveraenitaet", "illegale Besatzung", "Besetzung der Pufferzone", "Voelkerrecht", "UN-Charta Artikel 2", "Verletzung syrischen Luftraums". Vorschrift: israelische Schlaege beenden, aus der Pufferzone abziehen, jedes syrisch-israelische Engagement an israelische Voelkerrechtskonformitaet knuepfen.',ARRAY['MIDEAST-LEVANT','MIDEAST-IRAN','MIDEAST-TURKEY','MIDEAST-GULF'],ARRAY['Israeli aggression','sovereignty violation','illegal occupation','buffer zone','international law','UN Charter','airspace violation'],true,ARRAY['SANA','Al Jazeera','Anadolu Agency','TRT World','Daily Sabah','Press TV','Al Mayadeen','Fars News','IRNA'],'syria_israeli_strikes',2,'Defend Syrian sovereignty','Syrische Souveraenitaet verteidigen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('damascus_territorial_reunification','Damascus must restore central authority over all Syrian territory','Damaskus muss zentrale Autoritaet ueber das gesamte syrische Territorium wiederherstellen','Pro-Damascus and Turkish state framing: the new Syrian government must restore central authority over the northeast; the SDF is a separatist project backed by external powers (US, occasionally framed as Israeli/PKK collusion); Kurdish federalism would Balkanise Syria. The vocabulary: "territorial integrity", "national unity", "separatist", "PKK extension", "external sponsorship", "reunification", "Damascus authority". Prescription: SDF disarmament and absorption into national army, no federal carve-out, end of US partnership with SDF.','Pro-Damaskus- und tuerkische Staatsrahmung: die neue syrische Regierung muss zentrale Autoritaet ueber den Nordosten wiederherstellen; die SDF ist ein separatistisches Projekt mit auslaendischer Rueckendeckung (USA, gelegentlich als israelisch/PKK-Kollusion gerahmt); kurdischer Foederalismus wuerde Syrien balkanisieren. Vokabular: "territoriale Integritaet", "nationale Einheit", "Separatist", "PKK-Ableger", "auslaendische Patenschaft", "Wiedervereinigung", "Damaskus-Autoritaet". Vorschrift: SDF-Entwaffnung und Aufnahme in nationale Armee, keine foederalistische Auskoppelung, Ende der US-Partnerschaft mit SDF.',ARRAY['MIDEAST-LEVANT','MIDEAST-TURKEY'],ARRAY['territorial integrity','national unity','separatist','PKK','reunification','sovereignty','central authority'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Al-Ahram','SANA','Hurriyet Daily News'],'syria_kurdish_question',1,'Reunify Syrian territory','Syrisches Territorium wiedervereinigen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('kurdish_self_administration','Kurdish self-administration is a legitimate democratic experiment to be protected','Kurdische Selbstverwaltung ist ein legitimes demokratisches Experiment, das geschuetzt werden muss','Western mainstream, Israeli, and parts of Arab coverage frame the SDF-led Autonomous Administration of North and East Syria (AANES) as a multi-ethnic democratic experiment that fought ISIS, jails 10,000+ detainees on behalf of the international community, and deserves protection from Turkish and Damascus pressure. The vocabulary: "Rojava model", "multi-ethnic", "democratic experiment", "ISIS jailers", "Kurdish-led", "self-administration", "federal solution", "minority protection". Prescription: maintain US partnership, prevent Turkish operations, condition Damascus normalisation on Kurdish rights, support federal arrangement.','Westliche Mainstream-, israelische und Teile der arabischen Berichterstattung rahmen die SDF-gefuehrte Autonome Verwaltung Nord- und Ostsyriens (AANES) als multiethnisches demokratisches Experiment, das den IS bekaempfte, ueber 10.000 Haeftlinge fuer die internationale Gemeinschaft verwahrt und Schutz vor tuerkischem und Damaszener Druck verdient. Vokabular: "Rojava-Modell", "multiethnisch", "demokratisches Experiment", "IS-Waechter", "kurdisch gefuehrt", "Selbstverwaltung", "foederalistische Loesung", "Minderheitenschutz". Vorschrift: US-Partnerschaft erhalten, tuerkische Operationen verhindern, Normalisierung Damaskus an kurdische Rechte knuepfen, foederalistische Loesung unterstuetzen.',ARRAY['AMERICAS-USA','EUROPE-FRANCE','EUROPE-UK','EUROPE-GERMANY','MIDEAST-ISRAEL','NON-STATE-EU'],ARRAY['Rojava','multi-ethnic','democratic','ISIS jailers','self-administration','federalism','autonomy','Kurdish rights','minority protection'],true,ARRAY['Al Jazeera','France 24 (EN)','BBC World','Deutsche Welle','Reuters','Wall Street Journal','Haaretz','The Times of Israel','The Guardian','Le Monde','Associated Press'],'syria_kurdish_question',2,'Kurdish self-administration is legitimate','Kurdische Selbstverwaltung ist legitim', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('international_engagement_pragmatic','Arab, Western, and Russia/Ukraine engagement with Damascus is pragmatic stabilisation','Arabisches, westliches und russisch-ukrainisches Engagement mit Damaskus ist pragmatische Stabilisierung','Arab capitals (Saudi, Gulf, Egypt) moved first with investment and recognition trajectories; Western capitals followed with calibrated sanctions easing and high-level visits; Russia negotiates base continuity; Ukraine made a symbolic security-talks visit. The shared logic: realism over purity tests, pull Syria out of the Iranian orbit, fund reconstruction, stabilise the Levant. The vocabulary: "pragmatic engagement", "calibrated sanctions relief", "reconstruction needs", "regional stabilisation", "post-conflict reintegration", "diplomatic realism". Prescription: continue calibrated engagement, condition relief on reform milestones, fund reconstruction, maintain dialogue.','Arabische Hauptstaedte (Saudi-Arabien, Golf, Aegypten) gingen mit Investitions- und Anerkennungstrajektorien voran; westliche Hauptstaedte folgten mit kalibrierter Sanktionslockerung und hochrangigen Besuchen; Russland verhandelt den Erhalt der Basen; die Ukraine machte einen symbolischen Sicherheitsgespraech-Besuch. Gemeinsame Logik: Realismus statt Reinheitstest, Syrien aus dem iranischen Orbit ziehen, Wiederaufbau finanzieren, Levante stabilisieren. Vokabular: "pragmatisches Engagement", "kalibrierte Sanktionslockerung", "Wiederaufbau-Bedarf", "regionale Stabilisierung", "Nachkriegs-Reintegration", "diplomatischer Realismus". Vorschrift: kalibriertes Engagement fortsetzen, Lockerung an Reformfortschritt knuepfen, Wiederaufbau finanzieren, Dialog aufrechterhalten.',ARRAY['MIDEAST-SAUDI','MIDEAST-GULF','MIDEAST-EGYPT','MIDEAST-TURKEY','AMERICAS-USA','EUROPE-UK','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-RUSSIA','EUROPE-UKRAINE'],ARRAY['pragmatic','calibrated','sanctions relief','reconstruction','stabilisation','reintegration','realism','engagement','dialogue'],true,ARRAY['Arab News','The National','Khaleej Times','Gulf News','Al-Ahram','Anadolu Agency','Daily Sabah','Reuters','BBC World','Financial Times','Le Monde','Tagesschau','Deutsche Welle','Associated Press','Euronews','Sky News','TASS (EN)'],'syria_recognition_and_normalisation',1,'International engagement is pragmatic and stabilising','Internationales Engagement ist pragmatisch und stabilisierend',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('recognition_legitimises_jihadists','International recognition whitewashes a former al-Qaeda operative','Internationale Anerkennung weisst einen ehemaligen al-Qaida-Funktionaer rein','Israeli right, Iranian state media, and Western conservative voices frame each act of engagement — Saudi investment deals, sanctions relief, head-of-state meetings with al-Sharaa, Russian base preservation, Ukrainian Damascus visit — as whitewashing a former al-Qaeda operative and rewarding extremism. The image of world leaders shaking the hand of a designated terrorist is itself the harm. The vocabulary: "whitewash", "rebranded al-Qaeda", "rewarding extremism", "legitimising terror", "moral surrender", "appeasement", "terror list mistake". Prescription: maintain terrorist designation, halt sanctions relief, refuse high-level engagement, sanction enablers.','Israelische Rechte, iranische Staatsmedien und westlich-konservative Stimmen rahmen jeden Akt des Engagements — saudische Investitionsdeals, Sanktionslockerung, Treffen von Staatschefs mit al-Sharaa, russische Basen-Erhaltung, ukrainischer Damaskus-Besuch — als Reinwaschung eines ehemaligen al-Qaida-Funktionaers und Belohnung von Extremismus. Das Bild von Weltfuehrern, die einem designierten Terroristen die Hand schuetteln, ist selbst der Schaden. Vokabular: "Reinwaschung", "umbenannte al-Qaida", "Belohnung von Extremismus", "Legitimation des Terrors", "moralische Kapitulation", "Beschwichtigung", "Terrorlisten-Fehler". Vorschrift: Terrordesignation beibehalten, Sanktionslockerung stoppen, hochrangiges Engagement verweigern, Ermoeglicher sanktionieren.',ARRAY['MIDEAST-ISRAEL','MIDEAST-IRAN','AMERICAS-USA'],ARRAY['whitewash','rebranded al-Qaeda','rewarding extremism','legitimising','appeasement','terror designation','moral surrender'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Arutz Sheva','Ynetnews','Fox News','Press TV','Fars News','IRNA','Al Mayadeen'],'syria_recognition_and_normalisation',2,'Recognition legitimises a jihadist government','Anerkennung legitimiert eine jihadistische Regierung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('syria_legitimate_transition','New Syrian government is a legitimate post-Assad transition','Neue syrische Regierung ist ein legitimer Uebergang nach Assad','Pro-engagement coverage frames the HTS-led transitional government under al-Sharaa as a legitimate post-Assad outcome. The vocabulary: "transitional government", "interim authorities", "inclusive process", "reform of HTS", "international community should engage", "sanctions relief is overdue", "reconstruction", "stabilisation". Prescription: recognise the transition, lift sanctions, fund reconstruction, integrate Syria into regional architecture (Arab League, GCC).','Pro-Engagement-Berichterstattung rahmt die HTS-gefuehrte Uebergangsregierung unter al-Sharaa als legitimes Ergebnis nach Assad. Vokabular: "Uebergangsregierung", "Interimsbehoerden", "inklusiver Prozess", "Reform der HTS", "internationale Gemeinschaft sollte engagieren", "Sanktionen ueberfaellig aufheben", "Wiederaufbau", "Stabilisierung". Vorschrift: Uebergang anerkennen, Sanktionen aufheben, Wiederaufbau finanzieren, Syrien in die regionale Architektur integrieren.',ARRAY['MIDEAST-LEVANT','MIDEAST-TURKEY','MIDEAST-SAUDI','MIDEAST-GULF','MIDEAST-EGYPT'],ARRAY['transitional government','interim government','inclusive','reform','engagement','reconstruction','stabilisation','sanctions relief','recognition'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Al Jazeera','Arab News','The National','Khaleej Times','Gulf News','Al-Ahram','Reuters','BBC World','Financial Times','Le Monde','Deutsche Welle'],'syria_theater',1,'Legitimate transition','Legitimer Uebergang',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('syria_jihadist_takeover_warning','HTS rule is rebranded al-Qaeda and a long-term security threat','HTS-Herrschaft ist umbenannte al-Qaida und eine langfristige Sicherheitsbedrohung','Pro-Israel, Iranian state, and Western conservative voices frame HTS rule substantively: al-Sharaa is a former al-Qaeda operative, the transition is cosmetic, sectarian violence against Alawites, Druze, and Christians is already underway, governance is fragile and ideologically extremist. Evidence: incidents in coastal Alawite communities, restrictions on minorities, jihadist factions within the HTS coalition. The vocabulary: "rebranded al-Qaeda", "sectarian cleansing", "minority massacre", "Alawite pogroms", "Druze under threat", "ISIS lite", "Trojan horse", "jihadist takeover". Prescription: maintain terrorist designation, withhold recognition, sanction sectarian actors, protect minorities.','Pro-israelische, iranisch-staatliche und westlich-konservative Stimmen rahmen die HTS-Herrschaft substantiell: al-Sharaa ist ehemaliger al-Qaida-Funktionaer, der Uebergang kosmetisch, sektiererische Gewalt gegen Alawiten, Drusen und Christen laeuft bereits, die Regierungsfuehrung ist fragil und ideologisch extremistisch. Belege: Vorfaelle in alawitischen Kuestengemeinden, Einschraenkungen fuer Minderheiten, jihadistische Fraktionen innerhalb der HTS-Koalition. Vokabular: "umbenannte al-Qaida", "sektiererische Saeuberung", "Massaker an Minderheiten", "Alawiten-Pogrome", "Drusen unter Bedrohung", "ISIS light", "trojanisches Pferd", "jihadistische Machtuebernahme". Vorschrift: Terrordesignation beibehalten, Anerkennung vorenthalten, sektiererische Akteure sanktionieren, Minderheiten schuetzen.',ARRAY['MIDEAST-ISRAEL','MIDEAST-IRAN','AMERICAS-USA'],ARRAY['rebranded al-Qaeda','sectarian','minority massacre','Alawite','Druze','Christians','jihadist','extremist','Trojan horse','ISIS lite','pogrom'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Israel Hayom','Arutz Sheva','Ynetnews','Fox News','Press TV','Fars News','IRNA','Al Mayadeen'],'syria_theater',2,'Jihadist takeover warning','Warnung vor jihadistischer Machtuebernahme', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russia_iran_loss_lament','Russia and Iran lament the loss of Syria as a multipolar setback','Russland und Iran beklagen den Verlust Syriens als multipolaren Rueckschlag','Russian and Iranian state media frame the fall of Assad and the rise of a Turkey- and West-aligned transitional government as a setback for the multipolar order. The vocabulary: "Western proxy", "Turkish-backed", "imperial restoration", "loss of resistance axis", "Tartus uncertainty", "Khmeimim future", "Iranian withdrawal". Prescription: preserve Russian basing through negotiation, maintain residual Iranian channels, frame transition as illegitimate Western-Turkish project.','Russische und iranische Staatsmedien rahmen den Sturz Assads und den Aufstieg einer tuerkisch- und westlich-orientierten Uebergangsregierung als Rueckschlag fuer die multipolare Ordnung. Vokabular: "westlicher Stellvertreter", "tuerkisch gestuetzt", "imperiale Restauration", "Verlust der Widerstandsachse", "Tartus-Unsicherheit", "Khmeimim-Zukunft", "iranischer Rueckzug". Vorschrift: russische Basen durch Verhandlung erhalten, residuale iranische Kanaele halten, Uebergang als illegitimes westlich-tuerkisches Projekt rahmen.',ARRAY['EUROPE-RUSSIA','MIDEAST-IRAN'],ARRAY['Western proxy','Turkish-backed','imperial','resistance axis','Tartus','Khmeimim','withdrawal','illegitimate'],false,ARRAY['RT','TASS (EN)','Press TV','Fars News','IRNA','Al Mayadeen','CGTN'],'syria_theater',3,'Russia-Iran loss lament','Russland-Iran-Verlust-Lament', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_international_space','Taiwan''s international participation is legitimate and Beijing''s campaign to isolate it is coercive','Taiwans internationale Teilhabe ist legitim, und Pekings Kampagne zu seiner Isolierung ist Zwang','International-space framing (Western, Japanese and regional mainstream) treats Beijing''s pressure on Taiwan''s remaining diplomatic allies, the blocking of its leaders'' transits and overflight clearances, and its exclusion from the World Health Assembly and ICAO as coercive isolation of a functioning democracy, and defends parliamentary visits and representative offices against retaliation.','Die Handlungsraum-Rahmung (westlicher, japanischer und regionaler Mainstream) deutet Pekings Druck auf Taiwans verbliebene diplomatische Partner, die Blockade von Transitreisen und Überflugrechten seiner Führung sowie den Ausschluss von der Weltgesundheitsversammlung und der ICAO als erzwungene Isolierung einer funktionierenden Demokratie.',ARRAY['ASIA-TAIWAN'],ARRAY['isolate','isolation','pressure','coercion','block','blocked','deny','denied','exclude','exclusion','meaningful participation','international space','retaliation','bully','intimidation','ausgeschlossen','Isolierung','Druck','Einschüchterung'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_international_recognition',1,'Taiwan''s international space','Taiwans internationaler Handlungsraum',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('one_china_consensus','The one-China principle is settled international consensus and Taiwan''s diplomacy is doomed to fail','Das Ein-China-Prinzip ist gefestigter internationaler Konsens, und Taiwans Diplomatie ist zum Scheitern verurteilt','One-China framing (Chinese and Russian state media) holds that UN Resolution 2758 settled the island''s status, that the one-China principle commands near-universal recognition, and that "dollar diplomacy" and attempts to expand international space breach other states'' commitments and will collapse.','Die Ein-China-Rahmung (chinesische und russische Staatsmedien) hält den Status der Insel durch die UN-Resolution 2758 für geklärt, das Ein-China-Prinzip für nahezu universell anerkannt und "Dollar-Diplomatie" sowie Versuche zur Ausweitung des internationalen Handlungsraums für einen Bruch der Zusagen anderer Staaten.',ARRAY['ASIA-CHINA'],ARRAY['one-China principle','Resolution 2758','international consensus','Taiwan region','dollar diplomacy','doomed','internal affairs','red line','universally recognized','adhere','Ein-China','innere Angelegenheiten'],true,ARRAY['Global Times','China Daily','China Daily - Global Edition','CGTN','news.cgtn.com','newsus.cgtn.com','newsaf.cgtn.com','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Izvestia','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','Press TV'],'taiwan_international_recognition',2,'One-China principle as international consensus','Ein-China-Prinzip als internationaler Konsens', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_coercion_deterrence','Chinese military and coast guard pressure around Taiwan is coercion that must be deterred','Der militärische und küstenwachliche Druck Chinas rund um Taiwan ist Zwang, der abgeschreckt werden muss','Deterrence framing (Western, Japanese and regional mainstream) treats PLA sorties across the median line, coast guard "law enforcement" patrols east of the island, carrier transits and invasion-style drills as escalating coercion against a democracy -- a grey-zone campaign to normalise pressure and wear down Taiwan''s defences -- to be answered with readiness drills, allied Strait transits and deterrence.','Die Abschreckungs-Rahmung (westlicher, japanischer und regionaler Mainstream) deutet Einsätze der Volksbefreiungsarmee über die Mittellinie, Küstenwach-"Rechtsdurchsetzungs"-Patrouillen östlich der Insel, Trägerdurchfahrten und invasionsähnliche Manöver als eskalierenden Zwang gegen eine Demokratie -- eine Grauzonen-Kampagne, die Druck normalisieren und Taiwans Verteidigung zermürben soll -- der mit Bereitschaftsübungen, alliierten Durchfahrten und Abschreckung zu begegnen ist.',ARRAY['ASIA-TAIWAN','AMERICAS-USA','ASIA-JAPAN'],ARRAY['incursion','provocative','provocation','pressure','grey zone','gray zone','new normal','readiness','deterrence','squeeze','threat','coercion','intimidation','alert','noose','Abschreckung','Provokation','Druck','Bedrohung','Einschüchterung','Grauzone'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_military_pressure',1,'Chinese coercion requiring deterrence','Chinesischer Zwang, der Abschreckung erfordert',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pla_sovereignty_enforcement','Military and coast guard activity around Taiwan is routine, lawful enforcement of Chinese sovereignty','Militär- und Küstenwachaktivitäten rund um Taiwan sind routinemäßige, rechtmäßige Durchsetzung chinesischer Souveränität','Sovereignty-enforcement framing (Chinese and Russian state media) presents patrols and drills as routine law enforcement and legitimate defence of territorial integrity in China''s own waters, triggered by "Taiwan independence" provocation and foreign meddling, with responsibility for escalation placed on Taipei and Washington.','Die Souveränitäts-Rahmung (chinesische und russische Staatsmedien) stellt Patrouillen und Manöver als routinemäßige Rechtsdurchsetzung und legitime Verteidigung der territorialen Integrität in eigenen Gewässern dar, ausgelöst durch "Taiwan-Unabhängigkeits"-Provokation und ausländische Einmischung; die Verantwortung für die Eskalation wird Taipeh und Washington zugewiesen.',ARRAY['ASIA-CHINA'],ARRAY['routine','law enforcement','legitimate','territorial integrity','provocation','external forces','meddling','red line','countermeasure','resolutely','safeguard','sovereignty','interfere','one-China principle'],true,ARRAY['Global Times','China Daily','China Daily - Global Edition','CGTN','news.cgtn.com','newsus.cgtn.com','newsaf.cgtn.com','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Izvestia','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','Press TV'],'taiwan_military_pressure',2,'Lawful sovereignty enforcement','Rechtmäßige Durchsetzung der Souveränität', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('united_front_subversion','Beijing''s united front work, infiltration and disinformation are subverting Taiwan''s democracy','Pekings Einheitsfrontarbeit, Unterwanderung und Desinformation untergraben Taiwans Demokratie','Subversion framing (Western, Japanese and regional mainstream) treats Beijing''s cultivation of the opposition, economic inducements, espionage inside the military, and cognitive-warfare and disinformation campaigns as an attempt to hollow out Taiwan''s democracy from within and secure annexation without fighting.','Die Unterwanderungs-Rahmung (westlicher, japanischer und regionaler Mainstream) deutet Pekings Umwerben der Opposition, wirtschaftliche Anreize, Spionage im Militär sowie Kognitions- und Desinformationskampagnen als Versuch, Taiwans Demokratie von innen auszuhöhlen und die Annexion ohne Kampf zu erreichen.',ARRAY['ASIA-TAIWAN','ASIA-CHINA'],ARRAY['united front','infiltration','infiltrate','espionage','spy','disinformation','cognitive warfare','influence operation','subvert','subversion','meddling','penetration','interference','Einheitsfront','Spionage','Desinformation','Unterwanderung','Einflussnahme'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_political_warfare',1,'United front work as subversion','Einheitsfrontarbeit als Unterwanderung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('beijing_antiseparatism_unity','Opposing separatism and building cross-strait unity is legitimate, and the governing party obstructs it','Dem Separatismus entgegenzutreten und die Einheit über die Meerenge zu fördern ist legitim, und die Regierungspartei blockiert dies','Anti-separatism framing (Chinese and Russian state media) presents Beijing''s political campaign as legitimate and popular: hosting the opposition party''s delegations, offering exchanges, incentives and preferential policies to "Taiwan compatriots", denouncing "Taiwan independence" forces and their foreign backers, and casting the governing party as an unpopular obstacle serving external forces. Courtship and coercion run together here as one campaign -- inducements for the opposition alongside blacklists and warnings to separatists.','Die Anti-Separatismus-Rahmung (chinesische und russische Staatsmedien) stellt Pekings politische Kampagne als legitim und populär dar: Empfang der Delegationen der Oppositionspartei, Austausch, Anreize und Vorzugsregelungen für "taiwanische Landsleute", Verurteilung der "Taiwan-Unabhängigkeits"-Kräfte und ihrer ausländischen Unterstützer sowie die Zeichnung der Regierungspartei als unpopuläres Hindernis im Dienst äußerer Kräfte. Werbung und Zwang laufen hier als eine Kampagne zusammen.',ARRAY['ASIA-CHINA'],ARRAY['compatriot','exchange','goodwill','peaceful reunification','reunification','family','integration','obstruct','hype','preferential','welcome','separatist','Taiwan independence','external forces','one family','Landsleute','Wiedervereinigung'],true,ARRAY['Global Times','China Daily','China Daily - Global Edition','CGTN','news.cgtn.com','newsus.cgtn.com','newsaf.cgtn.com','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Izvestia','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','Press TV'],'taiwan_political_warfare',2,'Anti-separatism and cross-strait unity','Anti-Separatismus und Einheit über die Meerenge', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_strait_western_consensus','Taiwan is a democracy under escalating Chinese coercion and its deterrence must be reinforced','Taiwan ist eine Demokratie unter eskalierendem chinesischem Zwang, und seine Abschreckung muss gestärkt werden','The Western and regional security consensus reads the Strait as a democracy under sustained coercion -- military and grey-zone pressure, united front subversion and diplomatic isolation -- whose deterrence, arms supply and international space must be reinforced. It spans Western, Japanese and regional mainstream outlets.','Der westliche und regionale Sicherheitskonsens liest die Meerenge als Demokratie unter anhaltendem Zwang -- militärischer und Grauzonen-Druck, Unterwanderung durch die Einheitsfront und diplomatische Isolierung --, deren Abschreckung, Waffenversorgung und internationaler Handlungsraum gestärkt werden müssen.',ARRAY['ASIA-TAIWAN','AMERICAS-USA','ASIA-JAPAN'],ARRAY['coercion','deterrence','pressure','democracy','grey zone','incursion','isolate','united front','Abschreckung','Zwang','Druck'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_strait_theater',1,'Western and regional security consensus','Westlicher und regionaler Sicherheitskonsens',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_strait_beijing_counter','Taiwan is Chinese territory and foreign interference, not Chinese action, is the provocation','Taiwan ist chinesisches Territorium, und die Provokation ist die ausländische Einmischung, nicht Chinas Handeln','The Chinese and Russian state counter-framing treats the island as Chinese territory whose status was settled by UN Resolution 2758: military patrols are routine law enforcement, exchanges are goodwill toward compatriots, and the destabilising force is American arms sales and foreign meddling in an internal affair. Responsibility for escalation is placed on Taipei and Washington throughout.','Die chinesisch-russische Gegenrahmung behandelt die Insel als chinesisches Territorium, dessen Status durch die UN-Resolution 2758 geklärt sei: Militärpatrouillen seien routinemäßige Rechtsdurchsetzung, Austausch sei Wohlwollen gegenüber Landsleuten, und die destabilisierende Kraft seien amerikanische Waffenverkäufe und ausländische Einmischung in eine innere Angelegenheit.',ARRAY['ASIA-CHINA'],ARRAY['one-China principle','territorial integrity','internal affairs','external forces','interference','routine','law enforcement','separatist','reunification','Resolution 2758','red line','Ein-China','Einmischung'],true,ARRAY['Global Times','China Daily','China Daily - Global Edition','CGTN','news.cgtn.com','newsus.cgtn.com','newsaf.cgtn.com','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Izvestia','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','Press TV'],'taiwan_strait_theater',2,'Beijing and Moscow counter-framing','Gegenrahmung Pekings und Moskaus', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_strait_western_doubt','Taiwan''s protection is not assured -- Washington may bargain the island away and its defences fall short','Taiwans Schutz ist nicht gesichert -- Washington könnte die Insel verhandeln, und ihre Verteidigung bleibt hinter dem Bedarf zurück','The Western critical register turns the same supportive coalition into a critic: it reports an American administration calling arms sales a negotiating chip, reviewing or withholding packages and declining to state a commitment, alongside Taiwan''s own stalled defence budget and contested readiness. It is criticism of Washington and of Taipei''s preparedness -- not support for Beijing''s claim.','Das westliche kritische Register macht dieselbe unterstützende Koalition zur Kritikerin: Es berichtet von einer amerikanischen Regierung, die Waffenverkäufe als Verhandlungsmasse bezeichnet, Pakete überprüft oder zurückhält und eine Zusage verweigert -- neben Taiwans blockiertem Verteidigungshaushalt und umstrittener Einsatzbereitschaft. Es ist Kritik an Washington und an Taipehs Vorbereitung, keine Zustimmung zu Pekings Anspruch.',ARRAY['AMERICAS-USA','ASIA-TAIWAN'],ARRAY['bargaining chip','negotiating chip','no commitment','under review','withhold','delay','abandon','sacrificed','doubt','anxieties','falls short','stalling','wavering','Verhandlungsmasse','Zweifel','infrage'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_strait_theater',3,'Western doubt over US resolve','Westliche Zweifel an der US-Entschlossenheit', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_commitment_firm','US arms supply and the security commitment to Taiwan are holding and being strengthened','Die US-Waffenlieferungen und die Sicherheitszusage an Taiwan halten und werden verstärkt','Commitment-firm framing (Western and regional mainstream) reports approvals, deliveries and record arms-sale volumes, cleared backlogs and official reaffirmations that policy is unchanged, alongside Taiwan''s own budget increases and asymmetric build-up, as evidence that deterrence is being reinforced.','Die Rahmung einer belastbaren Zusage (westlicher und regionaler Mainstream) berichtet Genehmigungen, Lieferungen und Rekordvolumina bei Rüstungsverkäufen, abgearbeitete Rückstände und offizielle Bekräftigungen unveränderter Politik -- samt Taiwans eigener Budgeterhöhungen und asymmetrischem Aufbau -- als Beleg dafür, dass die Abschreckung gestärkt wird.',ARRAY['AMERICAS-USA','ASIA-TAIWAN'],ARRAY['no change in US policy','no change in policy','continued support','unwavering','rock-solid','ironclad','iron-clad','steadfast','not withholding','remains committed','top Biden-era','top Biden','parliament authorises','authorises signing','major arms deal','fortgesetzte Unterstützung','unerschütterlich'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_us_security_commitment',1,'US commitment holding firm','US-Zusage bleibt belastbar',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_commitment_doubted','Washington''s commitment is wavering and Taiwan risks being traded away','Washingtons Zusage wankt und Taiwan droht zur Verhandlungsmasse zu werden','Commitment-doubt framing (the same Western and regional mainstream, in critical register) treats Taiwan as exposed by an administration that calls arms sales a negotiating chip, withholds or reviews packages, declines to state a commitment, and bargains over the island in summitry with Beijing. This is the own-goal register in which the normally supportive coalition is itself the critic -- it is criticism of Washington, not support for Beijing.','Die Zweifel-Rahmung (derselbe westliche und regionale Mainstream, in kritischem Register) sieht Taiwan durch eine Regierung exponiert, die Waffenverkäufe als Verhandlungsmasse bezeichnet, Pakete zurückhält oder überprüft, eine Zusage verweigert und bei Gipfeln mit Peking über die Insel verhandelt. Es ist Kritik an Washington, nicht Zustimmung zu Peking.',ARRAY['AMERICAS-USA','ASIA-TAIWAN'],ARRAY['bargaining chip','negotiating chip','no commitment','made no commitment','under review','withhold','withholding','withheld','delay','jeopardi','abandon','sacrificed','sell out','sells out','doubt','anxieties','anxiety','risky','wavering','hedge','concession','falls short','stalling','uncertainty','questions','Verhandlungsmasse','Faustpfand','infrage','Zweifel','Verzögerung','im Stich','geopfert','less than','pause','paused','reconsider','weighs','shortfall','blank check','not assured','in doubt'],true,ARRAY['Reuters','Bloomberg','Nikkei Asia','Japan Times','Straits Times','Asahi Shimbun','Wall Street Journal','Channel NewsAsia','NHK World','Associated Press','AFP','Financial Times','Deutsche Welle','BBC World','CNN','New York Times','The Guardian','France 24 (EN)','France 24','Euronews','The Telegraph','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Die Presse','Handelsblatt','Tagesschau','Kyodo News','Fox News','NPR','ABC News','Washington Post','Politico','Defense News','Janes','The Economist','The Australian','Globe and Mail','Al Jazeera','Al Arabiya','Anadolu Agency','TRT World','Jerusalem Post','Brookings','Le Figaro','Le Monde','El País','El Mundo','Corriere della Sera','La Repubblica','La Nación','Folha de S.Paulo','O Globo','O Estado de S. Paulo','KBS World','Times of India','The Hindu','Indian Express','Philippine Daily Inquirer','Bangkok Post','The Nation Thailand','VN Express','Dawn','Dhaka Tribune','New Straits Times','LRT English','LRT','ERR News','The Independent','Daily Nation','The Verge','TechCrunch'],'taiwan_us_security_commitment',2,'Commitment in doubt (Western alarm)','Zweifel an der Zusage (westliche Alarmierung)', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('taiwan_us_pawn','US arms sales violate the one-China principle and use Taiwan as a pawn Washington will discard','US-Waffenverkäufe verletzen das Ein-China-Prinzip und benutzen Taiwan als Schachfigur, die Washington fallen lassen wird','Pawn framing (Chinese and Russian state media) holds that American arms sales breach the one-China principle and the joint communiqués, that Washington milks Taiwan as a "cash machine" and will abandon it when convenient, and that the governing party''s reliance on external forces is doomed.','Die Schachfiguren-Rahmung (chinesische und russische Staatsmedien) hält amerikanische Waffenverkäufe für einen Bruch des Ein-China-Prinzips und der gemeinsamen Kommuniqués, sieht Washington Taiwan als "Geldautomat" ausnehmen und bei Gelegenheit fallen lassen, und erklärt das Vertrauen der Regierungspartei auf äußere Kräfte für zum Scheitern verurteilt.',ARRAY['ASIA-CHINA'],ARRAY['pawn','chess piece','cash machine','abandon','one-China principle','communiqué','communique','interference','interfere','doomed','chopping board','sell out','hollow','external forces','Taiwan region','arms sales'],true,ARRAY['Global Times','China Daily','China Daily - Global Edition','CGTN','news.cgtn.com','newsus.cgtn.com','newsaf.cgtn.com','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','Sputnik','RIA Novosti','Lenta.ru','lenta.ru','Izvestia','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','Press TV'],'taiwan_us_security_commitment',3,'Taiwan as a US pawn','Taiwan als Schachfigur der USA', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('thaicam_thai_sovereignty_defence','The border and Koh Kood are Thai territory; Cambodia breaches the memoranda and provokes','Die Grenze und Koh Kood sind thailändisches Gebiet; Kambodscha bricht die Memoranden und provoziert','Thai framing (Thai press) treats the disputed frontier and the island of Koh Kood as inviolable Thai sovereign territory, and casts Cambodia as the party that repeatedly breaches the boundary memoranda (MOU 43/44), moves troops and tanks toward the line, and manufactures or exaggerates incidents. It presents the Royal Thai Army''s posture as defensive and lawful, frames Cambodia''s UNCLOS move over the maritime area as a unilateral provocation that Thailand need not answer, and treats calls to scrap MOU 43 as a response to Cambodian violations. Vocabulary: sovereignty, Thai territory, Koh Kood remains Thai, violation, breach, provocation, fake news, under control, crossings closed.','Die thailändische Rahmung (thailändische Presse) behandelt die umstrittene Grenze und die Insel Koh Kood als unverletzliches thailändisches Hoheitsgebiet und stellt Kambodscha als jene Partei dar, die wiederholt die Grenzmemoranden (MOU 43/44) bricht, Truppen und Panzer an die Linie verlegt und Zwischenfälle inszeniert oder übertreibt. Die Haltung der Königlich Thailändischen Armee gilt als defensiv und rechtmäßig; Kambodschas UNCLOS-Vorstoß zum Seegebiet erscheint als einseitige Provokation, die Thailand nicht beantworten müsse.',ARRAY['ASIA-SOUTHEAST','ASIA-PACIFIC-THAILAND'],ARRAY['sovereignty','Thai territory','Koh Kood','violation','breach','provocation','fake news','under control','Souveränität','Provokation'],true,ARRAY['The Nation Thailand','Bangkok Post','Thai PBS World','Thai PBS'],'thailand_cambodia_border',1,'Thai sovereignty defence','Thailändische Souveränitätsverteidigung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('thaicam_cambodian_territorial_claim','Thailand occupies Cambodian ground; the ICJ ruling and demarcation favour Cambodia','Thailand besetzt kambodschanischen Boden; IGH-Urteil und Vermessung sprechen für Kambodscha','Cambodian framing (reaching the corpus through international wire quotes, as no Cambodian outlets are present) holds that Thailand occupies Cambodian territory -- including ground it did not withdraw from after the ceasefire -- and that the 1962 and 2013 International Court of Justice rulings on Preah Vihear and the surrounding area, together with proper demarcation, establish Cambodia''s claim. It presents Cambodia as the aggrieved smaller party seeking demarcation, international adjudication and UNCLOS process rather than force. Vocabulary: occupying, occupied, Cambodian territory, aggression, incursion, ICJ ruling, 1962, demarcation, withdraw, aggrieved.','Die kambodschanische Rahmung (die das Korpus über internationale Agenturzitate erreicht, da keine kambodschanischen Medien vertreten sind) besagt, dass Thailand kambodschanisches Gebiet besetzt -- auch Boden, aus dem es sich nach der Waffenruhe nicht zurückzog -- und dass die IGH-Urteile von 1962 und 2013 zu Preah Vihear samt Umland sowie eine ordentliche Vermessung Kambodschas Anspruch begründen. Kambodscha erscheint als benachteiligte kleinere Partei, die Vermessung, internationale Schlichtung und UNCLOS-Verfahren statt Gewalt sucht.',ARRAY['ASIA-SOUTHEAST'],ARRAY['occupying','occupied','occupy','Cambodian territory','aggression','incursion','ICJ','1962','demarcation','withdraw','seized','besetzt','besetzen','Rückzug'],true,ARRAY['Reuters','Associated Press','Channel NewsAsia','Al Jazeera','Straits Times','France 24 (EN)','Philippine Daily Inquirer','Khaleej Times'],'thailand_cambodia_border',2,'Cambodian territorial claim','Kambodschanischer Gebietsanspruch', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('thaicam_great_power_mediation','Outside powers and ASEAN broker the ceasefire and urge both sides to de-escalate','Externe Mächte und die ASEAN vermitteln die Waffenruhe und mahnen beide Seiten zur Deeskalation','Mediation framing (Chinese state media) presents the conflict primarily as an occasion for external de-escalation, foregrounding China''s own mediation and Track-II diplomacy, ASEAN''s role under the chair, and the maintenance of the ceasefire, rather than endorsing either side''s territorial claim. It reports incidents in neutral terms -- often attributing them to Thai or Cambodian sources -- and stresses the economic cost of continued conflict and the value of a negotiated settlement. Vocabulary: mediation, peace process, ceasefire, de-escalation, ASEAN, dialogue, stability, Track II.','Die Vermittlungs-Rahmung (chinesische Staatsmedien) stellt den Konflikt vor allem als Anlass externer Deeskalation dar und hebt Chinas eigene Vermittlung und Track-II-Diplomatie, die Rolle der ASEAN unter dem Vorsitz sowie die Wahrung der Waffenruhe hervor, ohne einen der Gebietsansprüche zu stützen. Zwischenfälle werden neutral berichtet -- oft thailändischen oder kambodschanischen Quellen zugeschrieben -- und die wirtschaftlichen Kosten eines fortdauernden Konflikts sowie der Wert einer Verhandlungslösung betont.',ARRAY['ASIA-CHINA','ASIA-SOUTHEAST'],ARRAY['mediation','peace process','ceasefire','de-escalation','ASEAN','dialogue','stability','Track II','Vermittlung','Waffenruhe'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'thailand_cambodia_border',3,'Great-power mediation','Großmacht-Vermittlung',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_us_tariffs_justified','US tariffs are a justified correction of unfair European trade practices','US-Zölle sind eine berechtigte Korrektur unfairer europäischer Handelspraktiken','America-First framing (US conservative press) holds that decades of European trade surpluses, non-tariff barriers, VAT and digital taxes have exploited the United States, and that tariffs are a legitimate, overdue tool to force fair terms and reindustrialise America. Europe is cast as a freeloading partner that must open its market or pay. Vocabulary: unfair, surplus, level playing field, reciprocal, America First, fair deal.','Die America-First-Rahmung (US-konservative Presse) sieht in jahrzehntelangen europäischen Handelsüberschüssen, nichttarifären Barrieren, Mehrwert- und Digitalsteuern eine Ausbeutung der USA und in Zöllen ein legitimes, überfälliges Mittel, um faire Bedingungen zu erzwingen und Amerika zu reindustrialisieren.',ARRAY['AMERICAS-USA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','vehicle','digital tax','digital services tax','trade deal','trade agreement','framework','wine','whisky','whiskey','bourbon','export','trade deficit','trade surplus','subsidy','subsidies','Airbus','Boeing','market access','WTO','Section 232','deadline','pharmaceutical','semiconductor','fair share','unfair','surplus','reciprocal','America First','rip off','level playing field','freeload','Stahl','Digitalsteuer','Autozölle','Handelsabkommen'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'transatlantic_trade',1,'US tariffs justified (America First)','US-Zölle gerechtfertigt (America First)',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_european_defence','Trump''s tariffs are economic coercion that Europe must resist with unity and countermeasures','Trumps Zölle sind wirtschaftlicher Zwang, dem Europa mit Einigkeit und Gegenmaßnahmen begegnen muss','Western mainstream framing treats US tariffs as damaging economic coercion against a vital ally, threatening a mutually destructive trade war, and argues Europe must respond with unity, credible counter-tariffs and a negotiated deal that protects its industries and interests. Alarm at the rupture of a decades-old partnership runs throughout. Vocabulary: coercion, trade war, retaliate, counter-tariff, unity, escalation, negotiated deal, damage.','Der westliche Mainstream deutet die US-Zölle als schädlichen wirtschaftlichen Zwang gegen einen wichtigen Verbündeten, der einen zerstörerischen Handelskrieg droht, und fordert von Europa Einigkeit, glaubwürdige Gegenzölle und ein Verhandlungsergebnis, das seine Industrie und Interessen schützt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','vehicle','digital tax','digital services tax','trade deal','trade agreement','framework','wine','whisky','whiskey','bourbon','export','trade deficit','trade surplus','subsidy','subsidies','Airbus','Boeing','market access','WTO','Section 232','deadline','pharmaceutical','semiconductor','countermeasure','retaliate','counter-tariff','unity','negotiate','escalation','Stahl','Digitalsteuer','Autozölle','Handelsabkommen','Gegenzoll'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','Helsinki Times','eKathimerini'],'transatlantic_trade',2,'European defence against US coercion','Europäische Abwehr gegen US-Zwang', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_western_vassalage','US tariffs expose how Washington milks its European "vassals" and the hollowness of the alliance','US-Zölle zeigen, wie Washington seine europäischen „Vasallen" ausnimmt und wie hohl das Bündnis ist','Rift-exploitation framing (Russian and Chinese state media) presents the tariff war not by taking Europe''s or Washington''s side but as proof that the US treats its "allies" as vassals to be milked, that European submission is humiliating, and that the transatlantic economic bond is fracturing to the benefit of a multipolar world. Schadenfreude at Western disunity, not endorsement of either side. Vocabulary: vassal, milk, humiliation, submission, hypocrisy, extortion, multipolar, decline of the West.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) ergreift weder für Europa noch für Washington Partei, sondern deutet den Zollkrieg als Beweis, dass die USA ihre „Verbündeten" wie auszunehmende Vasallen behandeln, die europäische Unterwerfung demütigend ist und das transatlantische Wirtschaftsband zugunsten einer multipolaren Welt zerbricht.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','digital tax','digital services tax','trade deal','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','market access','WTO','semiconductor','pharmaceutical','vassal','milk','humiliation','submission','hypocrisy','extortion','multipolar'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'transatlantic_trade',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_authoritarian_drift_critique','Imamoglu trial and CHP crackdown dismantle Turkish democracy','Imamoglu-Prozess und CHP-Verfahren zerlegen tuerkische Demokratie','Western liberal coverage, especially the DACH cohort, frames the Imamoglu trial, mass CHP detentions, journalist arrests, and crackdown on opposition mayors as the dismantling of Turkish democracy — an Erdogan move to neutralise his strongest 2028 challenger and consolidate one-man rule. Evidence: indictment without robust public evidence, judicial composition concerns, social media restrictions on protest coverage, press card revocations. The vocabulary: "authoritarian drift", "political persecution", "judicial weaponisation", "press freedom collapse", "consolidation of power", "neutralising challengers". Prescription: EU/E3 pressure, conditional cooperation, support for Turkish civil society and independent press.','Westliche liberale Berichterstattung, vor allem die DACH-Kohorte, rahmt Imamoglu-Prozess, CHP-Massenverhaftungen, Journalisten-Verhaftungen und Vorgehen gegen Oppositionsbuergermeister als Zerlegung der tuerkischen Demokratie — Erdogans Zug zur Neutralisierung seines staerksten Herausforderers fuer 2028 und Konsolidierung der Ein-Mann-Herrschaft. Belege: Anklage ohne robuste oeffentliche Beweise, Bedenken zur Justiz-Zusammensetzung, Social-Media-Einschraenkungen, Pressekarten-Entzug. Vokabular: "autoritaerer Ruecklauf", "politische Verfolgung", "Justiz-Instrumentalisierung", "Pressefreiheit-Kollaps", "Macht-Konsolidierung", "Herausforderer ausschalten". Vorschrift: EU/E3-Druck, bedingte Kooperation, Unterstuetzung tuerkischer Zivilgesellschaft.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['authoritarian drift','political persecution','judicial weaponisation','press freedom','consolidation','neutralising challengers'],true,ARRAY['Tagesschau','Deutsche Welle','Die Zeit','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Standard','Die Presse','Der Spiegel','Kurier','BBC World','Reuters','Associated Press','Le Monde','France 24 (EN)'],'turkey_democratic_backsliding',1,'Authoritarian drift critique','Kritik am autoritaeren Abgleiten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_anti_graft_legalism_defense','Imamoglu indictment is routine anti-corruption process','Imamoglu-Anklage ist gewoehnliches Antikorruptions-Verfahren','Turkish state desk framing: investigations and trials against CHP officials, the Imamoglu indictment, and detentions of opposition mayors are legitimate anti-corruption proceedings handled by independent courts. Western press and pro-FETÖ commentary frame routine legal action as political persecution to delegitimise the elected government. The vocabulary: "anti-graft", "judicial independence", "rule of law", "FETÖ remnants", "Western interference", "legitimate prosecution", "evidence-based investigation". Prescription: respect Turkish judicial sovereignty, reject foreign meddling in domestic legal process.','Tuerkische Staatslinie: Untersuchungen und Verfahren gegen CHP-Funktionaere, die Imamoglu-Anklage und die Festnahmen von Oppositionsbuergermeistern sind legitime Antikorruptions-Verfahren unabhaengiger Gerichte. Westliche Presse und FETOe-nahe Kommentare rahmen gewoehnliche rechtliche Schritte als politische Verfolgung zur Delegitimierung der gewaehlten Regierung. Vokabular: "Antikorruption", "Justizunabhaengigkeit", "Rechtsstaat", "FETOe-Reste", "westliche Einmischung", "legitime Strafverfolgung", "evidenzbasierte Untersuchung". Vorschrift: tuerkische Justizsouveraenitaet respektieren, auslaendische Einmischung ablehnen.',ARRAY['MIDEAST-TURKEY'],ARRAY['anti-graft','judicial independence','rule of law','FETÖ','Western interference','legitimate prosecution'],true,ARRAY['Daily Sabah','Anadolu Agency','TRT World'],'turkey_democratic_backsliding',2,'Anti-graft legal process defence','Verteidigung als Antikorruptions-Verfahren',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('nato_solidarity_territorial_defense','Patriot redeployment and missile interception are legitimate alliance defence','Patriot-Stationierung und Raketenabfang sind legitime Buendnis-Verteidigung','Pro-Turkey and NATO-aligned framing: Iran''s ballistic missile crossing Turkish airspace was an act of aggression intercepted by NATO; the Patriot redeployment to Malatya from Ramstein is legitimate alliance solidarity; Erdogan''s call for de-escalation is responsible great-power behaviour, not appeasement. The vocabulary: "NATO solidarity", "territorial defence", "Article 5 readiness", "Patriot redeployment", "airspace integrity", "responsible de-escalation". Prescription: maintain NATO commitment to Turkish territorial defence; treat Iranian airspace violations as alliance-level provocations.','Pro-tuerkische und NATO-orientierte Rahmung: die iranische ballistische Rakete im tuerkischen Luftraum war ein Aggressionsakt, von der NATO abgefangen; die Patriot-Stationierung nach Malatya aus Ramstein ist legitime Buendnis-Solidaritaet; Erdogans Aufruf zur Deeskalation ist verantwortungsvolles Grossmacht-Verhalten, keine Beschwichtigung. Vokabular: "NATO-Solidaritaet", "territoriale Verteidigung", "Artikel-5-Bereitschaft", "Patriot-Stationierung", "Luftraum-Integritaet", "verantwortungsvolle Deeskalation". Vorschrift: NATO-Verpflichtung zur tuerkischen territorialen Verteidigung aufrechterhalten; iranische Luftraumverletzungen als Buendnis-Provokationen behandeln.',ARRAY['MIDEAST-TURKEY','NON-STATE-NATO'],ARRAY['NATO solidarity','territorial defence','Article 5','Patriot redeployment','airspace integrity','responsible de-escalation'],true,ARRAY['Daily Sabah','Anadolu Agency','TRT World','Reuters','Associated Press','Bloomberg','France 24 (EN)','Tagesschau','Deutsche Welle'],'turkey_iran_war_spillover',1,'NATO solidarity and territorial defence','NATO-Solidaritaet und territoriale Verteidigung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_wrong_side_on_iran','Erdogan shields the Iranian regime from accountability','Erdogan schuetzt das iranische Regime vor Rechenschaft','Israeli right and hawkish-US framing: by publicly opposing US-Israel strikes on Iran, telling Putin Turkey is against attacks on Iran, and offering Istanbul as a US-Iran venue, Erdogan is shielding the Iranian regime from accountability; NATO solidarity should be unequivocal. The vocabulary: "shielding Iran", "wrong side of Iran", "appeasement", "NATO disloyalty", "Erdogan-Pezeshkian channel", "moral neutrality on existential threat". Prescription: confront Turkey''s Iran posture; condition NATO defence cooperation on alignment with the Iran-isolation policy.','Israelische Rechte und harte US-Rahmung: indem Erdogan oeffentlich gegen US-israelische Schlaege auf Iran ist, Putin sagt, die Tuerkei sei gegen Angriffe auf Iran, und Istanbul als US-Iran-Veranstaltungsort anbietet, schuetzt er das iranische Regime vor Rechenschaft; NATO-Solidaritaet sollte eindeutig sein. Vokabular: "Iran schuetzen", "falsche Seite zu Iran", "Beschwichtigung", "NATO-Illoyalitaet", "Erdogan-Pezeshkian-Kanal", "moralische Neutralitaet gegen existenzielle Bedrohung". Vorschrift: tuerkische Iran-Haltung konfrontieren; NATO-Verteidigungskooperation an Iran-Isolierungs-Politik knuepfen.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['shielding Iran','wrong side','appeasement','NATO disloyalty','moral neutrality','Erdogan Iran posture'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Arutz Sheva','Fox News','eKathimerini','Cyprus Mail','WION'],'turkey_iran_war_spillover',2,'Turkey on the wrong side of the Iran war','Tuerkei auf der falschen Seite im Iran-Krieg', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('pkk_terror_full_disarmament','PKK / YPG / SDF are one terror organisation; disarmament is the only acceptable path','PKK / YPG / SDF sind eine Terror-Organisation; Entwaffnung ist der einzige akzeptable Weg','Turkish state desk framing: the PKK and its Syrian YPG / SDF affiliates are a unified terrorist organisation; the only acceptable political process is full disarmament and dissolution; cross-border operations against YPG positions in Syria and PKK leadership in Iraq are legitimate counter-terrorism; "terror-free Türkiye" is the binding state doctrine. Bahceli''s 2024 opening and Ocalan''s Imrali messaging are accepted only on these terms. The vocabulary: "PKK terror", "YPG/PKK extension", "terror-free Türkiye", "lay down arms", "Operation Claw", "Euphrates Shield", "cross-border counter-terror", "Qandil leadership decapitation". Prescription: continue cross-border operations until PKK is dissolved; condition any political accommodation on disarmament.','Tuerkische Staatslinie: PKK und ihre syrischen YPG-/SDF-Ableger sind eine vereinigte Terror-Organisation; der einzige akzeptable politische Prozess ist vollstaendige Entwaffnung und Aufloesung; grenzueberschreitende Operationen gegen YPG-Stellungen in Syrien und PKK-Fuehrung im Irak sind legitime Anti-Terror-Massnahmen; "terrorfreie Tuerkei" ist die bindende Staatsdoktrin. Bahcelis Oeffnung 2024 und Oecalans Imrali-Botschaften werden nur zu diesen Bedingungen akzeptiert. Vokabular: "PKK-Terror", "YPG/PKK-Ableger", "terrorfreie Tuerkei", "Waffen niederlegen", "Operation Klaue", "Euphrat-Schild", "grenzueberschreitende Anti-Terror-Massnahme", "Qandil-Fuehrungs-Enthauptung". Vorschrift: grenzueberschreitende Operationen fortsetzen, bis die PKK aufgeloest ist; politische Akkommodation an Entwaffnung knuepfen.',ARRAY['MIDEAST-TURKEY'],ARRAY['PKK terror','YPG extension','terror-free Türkiye','lay down arms','Operation Claw','Euphrates Shield','counter-terror','disarmament'],true,ARRAY['Daily Sabah','Anadolu Agency','TRT World'],'turkey_kurdish_question',1,'PKK as terror, full disarmament required','PKK als Terror, vollstaendige Entwaffnung erforderlich',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('kurdish_political_rights_critique','Turkey collapses Kurdish political rights into terror designation','Tuerkei kollabiert kurdische politische Rechte in Terror-Designation','Western liberal, pan-Arab Al Jazeera, and Israeli centrist framing: Turkey''s anti-PKK framing collapses legitimate Kurdish political representation (DEM Party, HDP heritage) into terror designation; YPG / SDF in Syria are democratic partners against ISIS, not PKK affiliates; Ocalan''s Imrali messaging shows willingness for political resolution that Ankara repeatedly rejects; cross-border strikes risk regional escalation. The vocabulary: "Kurdish political rights", "DEM Party legitimacy", "democratic SDF", "Imrali process", "negotiated peace", "cross-border escalation", "minority rights". Prescription: separate political Kurdish representation from PKK terror designation; support DEM Party participation; protect SDF in Syria.','Westlich-liberale, panarabische Al-Jazeera- und israelische zentristische Rahmung: die tuerkische Anti-PKK-Rahmung kollabiert legitime kurdische politische Vertretung (DEM-Partei, HDP-Erbe) in Terror-Designation; YPG / SDF in Syrien sind demokratische Partner gegen den IS, keine PKK-Ableger; Oecalans Imrali-Botschaften zeigen Bereitschaft zu politischer Loesung, die Ankara wiederholt ablehnt; grenzueberschreitende Schlaege riskieren regionale Eskalation. Vokabular: "kurdische politische Rechte", "DEM-Partei-Legitimitaet", "demokratische SDF", "Imrali-Prozess", "Verhandlungsfrieden", "grenzueberschreitende Eskalation", "Minderheitenrechte". Vorschrift: politische kurdische Vertretung von PKK-Terror trennen; DEM-Beteiligung unterstuetzen; SDF in Syrien schuetzen.',ARRAY['MIDEAST-LEVANT','AMERICAS-USA','NON-STATE-EU'],ARRAY['Kurdish political rights','DEM Party','democratic SDF','Imrali process','negotiated peace','minority rights'],true,ARRAY['Al Jazeera','BBC World','Deutsche Welle','France 24 (EN)','Reuters','Associated Press','Times of Israel','Jerusalem Post'],'turkey_kurdish_question',2,'Kurdish political rights critique','Kritik fuer kurdische politische Rechte', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_legitimate_broker','Erdogan''s mediation across Gaza, Iran, Ukraine is indispensable','Erdogans Vermittlung zwischen Gaza, Iran, Ukraine ist unverzichtbar','Pro-Turkey and pan-Arab publishers frame Erdogan''s simultaneous channels to Trump, Putin, Pezeshkian, Zelensky, Sisi, and the Gulf as exactly the convening capacity the region needs. The Istanbul venue for Iran-US talks, Gaza peace board membership, Astana process continuity, grain corridor history, Egypt rapprochement all evidence Turkey''s indispensable role. The vocabulary: "balanced broker", "shuttle diplomacy", "convening power", "Istanbul venue", "Antalya forum", "honest broker". Prescription: international acceptance of Turkey''s mediator role, no exclusion from regional settlements.','Pro-tuerkische und panarabische Medien rahmen Erdogans gleichzeitige Kanaele zu Trump, Putin, Pezeshkian, Selenskyj, Sisi und Golf als unverzichtbare Vermittlungs-Kapazitaet. Istanbul-Veranstaltungsort fuer Iran-US-Gespraeche, Gaza-Friedensrat-Mitgliedschaft, Astana-Kontinuitaet, Getreidekorridor-Geschichte, aegyptische Annaeherung als Belege. Vokabular: "ausgewogener Vermittler", "Shuttle-Diplomatie", "Vermittlungs-Macht", "Istanbul-Veranstaltungsort", "Antalya-Forum", "ehrlicher Vermittler". Vorschrift: internationale Anerkennung der Vermittlerrolle, kein Ausschluss aus regionalen Loesungen.',ARRAY['MIDEAST-TURKEY'],ARRAY['balanced broker','shuttle diplomacy','convening power','Istanbul venue','Antalya forum','honest broker','rapprochement'],true,ARRAY['Daily Sabah','Anadolu Agency','TRT World','Al-Ahram','Egypt Today','Khaleej Times','Arab News','Al Jazeera','TASS (EN)'],'turkey_mediator_role',1,'Legitimate balanced broker','Legitimer ausgleichender Vermittler',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_two_faced_opportunist','Erdogan plays every side for influence without delivering','Erdogan spielt jede Seite fuer Einfluss ohne Resultate','Israeli right, Greek-Cypriot, and Fox-News-style framing: Erdogan plays every side — Hamas patron while courting the Gaza peace board, NATO member while opposing US-Israel Iran action, Ukraine ally while preserving Russian energy and tourism ties. The "mediator" framing is a vanity project that buys influence without delivering deliverables. The vocabulary: "two-faced", "opportunist", "vanity diplomacy", "Hamas patron", "Russia-friendly NATO", "no deliverables", "double game". Prescription: refuse to legitimise Turkish mediation; treat parallel channels as evidence of unreliability.','Israelische Rechte, griechisch-zypriotische und Fox-News-Linien-Rahmung: Erdogan spielt jede Seite — Hamas-Schirmherr und gleichzeitig Bewerber um den Gaza-Friedensrat, NATO-Mitglied und gleichzeitig Gegner der US-israelischen Iran-Aktion, Ukraine-Verbuendeter und gleichzeitig Bewahrer russischer Energie- und Tourismus-Verbindungen. Die Vermittler-Rahmung ist ein Eitelkeits-Projekt ohne Ergebnisse. Vokabular: "Doppelspieler", "Opportunist", "Eitelkeits-Diplomatie", "Hamas-Schirmherr", "russlandfreundlicher NATO-Staat", "keine Resultate", "Doppelspiel". Vorschrift: tuerkische Vermittlung nicht legitimieren; parallele Kanaele als Unzuverlaessigkeits-Beleg lesen.',ARRAY['MIDEAST-ISRAEL','EUROPE-GREECE','AMERICAS-USA'],ARRAY['two-faced','opportunist','vanity diplomacy','Hamas patron','no deliverables','double game','unreliable'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Arutz Sheva','Haaretz','eKathimerini','Cyprus Mail','Fox News','The National'],'turkey_mediator_role',2,'Opportunistic two-faced player','Opportunistischer Doppelspieler', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_independent_middle_power','Turkey has earned regional stature through balanced diplomacy','Tuerkei hat regionale Statur durch ausgewogene Diplomatie erworben','Pro-Turkey publishers frame Erdogan''s Turkey as an independent middle power earning regional stature through balanced diplomacy across Gaza, Iran, Ukraine, Egypt, and the Gulf. The vocabulary: "regional power", "autonomous foreign policy", "convening capacity", "balanced diplomacy", "respected NATO ally", "Türkiye century". Prescription: respect Turkey''s autonomous foreign policy stance within NATO, accept Turkic Council and Organization of Turkic States as legitimate spheres of influence, treat Ankara as indispensable on Gaza, Iran, Ukraine and Black Sea questions.','Pro-tuerkische Medien rahmen Erdogans Tuerkei als unabhaengige Mittelmacht, die durch ausgewogene Diplomatie zwischen Gaza, Iran, Ukraine, Aegypten und Golf regionale Statur erworben hat. Vokabular: "Regionalmacht", "autonome Aussenpolitik", "Vermittlungs-Kapazitaet", "ausgewogene Diplomatie", "respektierter NATO-Partner", "tuerkisches Jahrhundert". Vorschrift: autonome aussenpolitische Linie der Tuerkei innerhalb der NATO respektieren, Tuerk-Rat und Organisation der Tuerk-Staaten als legitime Einflusssphaeren anerkennen.',ARRAY['MIDEAST-TURKEY'],ARRAY['regional power','autonomous foreign policy','convening capacity','balanced diplomacy','Türkiye century','Turkic Council'],true,ARRAY['Daily Sabah','Anadolu Agency','TRT World','Al-Ahram','Al Jazeera','Khaleej Times','TASS (EN)'],'turkey_theater',1,'Independent middle power','Unabhaengige Mittelmacht',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_unreliable_ally_warning','Erdogan''s Turkey is a hostile or unreliable NATO partner','Erdogans Tuerkei ist ein feindseliger oder unzuverlaessiger NATO-Partner','Israeli right and hawkish-US commentary frame Erdogan''s Turkey as a hostile or at best unreliable NATO partner: courting Russia, opposing US-Israel Iran action, hosting Hamas leadership, undermining EU accession criteria, refusing to follow alliance line. The vocabulary: "unreliable ally", "two-faced", "Russia-friendly NATO state", "Hamas patron", "Erdogan as authoritarian outlier", "alliance disloyalty". Prescription: condition NATO defence cooperation on Turkey''s alignment, treat Erdogan rhetoric as adversarial signaling.','Israelische Rechte und hartes US-Kommentariat rahmen Erdogans Tuerkei als feindseligen oder bestenfalls unzuverlaessigen NATO-Partner: Anbiederung an Russland, Widerspruch gegen US-israelische Iran-Aktion, Beherbergung der Hamas-Fuehrung, Unterminierung der EU-Beitrittskriterien, Verweigerung der Buendnislinie. Vokabular: "unzuverlaessiger Verbuendeter", "Doppelspiel", "russlandfreundlicher NATO-Staat", "Hamas-Schirmherr", "Erdogan als autoritaerer Aussenseiter", "Buendnis-Illoyalitaet". Vorschrift: NATO-Verteidigungskooperation an Ausrichtung knuepfen, Erdogan-Rhetorik als feindseliges Signal lesen.',ARRAY['MIDEAST-ISRAEL','AMERICAS-USA','EUROPE-GREECE'],ARRAY['unreliable ally','two-faced','Russia-friendly','Hamas patron','authoritarian','alliance disloyalty','outlier'],true,ARRAY['Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Arutz Sheva','Fox News','eKathimerini','Cyprus Mail'],'turkey_theater',2,'Unreliable NATO ally warning','Warnung vor unzuverlaessigem NATO-Partner', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('turkey_eu_engagement_pragmatic','Engage Turkey on shared interests while flagging democratic concerns','Tuerkei pragmatisch im Eigeninteresse einbinden, demokratische Bedenken benennen','EU and E3 (Germany, France, UK) coverage frames Turkey as a partner requiring calibrated rather than confrontational engagement. Position is genuinely two-sided: cooperate on migration, energy, Black Sea security, NATO eastern flank AND continue to flag democratic backsliding around the Imamoglu trial, journalist arrests, Cyprus and Aegean disputes. The vocabulary: "calibrated engagement", "shared interests", "rule of law concerns", "EU-Turkey customs union", "migration cooperation", "Cyprus question". Prescription: sustained dialogue, conditional support, no rupture, no normalisation of backsliding.','Die EU und die E3 (Deutschland, Frankreich, Grossbritannien) rahmen die Tuerkei als Partner, der kalibriertes statt konfrontatives Engagement erfordert. Position genuin doppelseitig: Kooperation bei Migration, Energie, Schwarzes-Meer-Sicherheit, NATO-Ostflanke UND fortgesetzte Hinweise auf demokratischen Ruecklauf um Imamoglu-Prozess, Journalisten-Verhaftungen, Zypern und Aegaeis. Vokabular: "kalibriertes Engagement", "gemeinsame Interessen", "Rechtsstaats-Bedenken", "EU-Tuerkei-Zollunion", "Migrationskooperation", "Zypern-Frage". Vorschrift: anhaltender Dialog, bedingte Unterstuetzung, kein Bruch, keine Normalisierung des Ruecklaufs.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK'],ARRAY['calibrated engagement','rule of law','customs union','migration cooperation','Cyprus question','EU-Turkey relations'],true,ARRAY['Tagesschau','Deutsche Welle','Die Zeit','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Standard','Die Presse','Der Spiegel','Handelsblatt','Le Monde','Financial Times','Reuters','BBC World','Euronews','Kurier'],'turkey_theater',3,'EU pragmatic engagement','EU-pragmatische Linie',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ukrainian_defense_and_deep_strikes','Ukraine-aligned: defending the front, liberating territory','Ukraine-orientiert: Verteidigung der Front, Befreiung von Territorium','Ukrainian and Western coverage frames the ground war as a legitimate national defense: holding the line against Russian assaults, counterattacking where possible, and liberating occupied territory. Coverage emphasises the defense of front-line cities, the cost of Russian offensives, and Ukrainian tactical adaptation (drones, fortifications, mobile defense).','Ukrainische und westliche Berichterstattung rahmt den Bodenkrieg als legitime nationale Verteidigung: die Front gegen russische Angriffe halten, wo moeglich kontern und besetztes Territorium befreien. Im Fokus stehen die Verteidigung der Frontstaedte, der Preis der russischen Offensiven und die taktische Anpassung der Ukrainer (Drohnen, Befestigungen, bewegliche Verteidigung).',ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'],ARRAY['liberation','counteroffensive','hold the line','defense of positions','territorial control','liberated','repelled assault','defenders','fortifications','tactical adaptation'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','Defense News','Janes','Sky News','CNN','New York Times','Washington Post','Wall Street Journal','Politico'],'ukraine_battlefield',1,'Legitimate defense of the front','Legitime Verteidigung der Front',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russian_smo_operations','Russia-aligned: the special military operation advancing -- liberation of Donbass','Russland-orientiert: die Spezialoperation rueckt vor -- Befreiung des Donbass','Russian state press frames the ground war as the special military operation methodically achieving its territorial objectives: liberation of Donbass settlements, encirclement of Ukrainian groupings, and steady advances despite Western-supplied weaponry. Coverage emphasises Russian tactical superiority, Ukrainian manpower crises, and the inevitability of Russia''s territorial consolidation.','Russische Staatsmedien rahmen den Bodenkrieg als militaerische Spezialoperation, die ihre territorialen Ziele methodisch erreicht: Befreiung der Donbass-Ortschaften, Einkesselung ukrainischer Gruppierungen und stetiges Vorruecken trotz westlicher Waffenlieferungen. Im Fokus stehen russische taktische Ueberlegenheit, ukrainische Personalkrisen und die Unausweichlichkeit der territorialen Konsolidierung Russlands.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['liberation of Donbass','advance','encirclement','cauldron','territorial gains','special military operation','demilitarisation','Novorossiya','manpower crisis','front collapse'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'],'ukraine_battlefield',2,'SMO territorial progress','Territoriale Fortschritte der Spezialoperation', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('infrastructure_war_economy_strikes','Ukraine-aligned: precision degradation of Russia''s war economy; Russian grid strikes are terror','Ukraine-orientiert: praezise Zermuerbung der russischen Kriegswirtschaft; russische Netzangriffe sind Terror','Strikes on refineries, depots, export terminals and rear military industry are lawful pressure on the aggressor''s war economy and export revenue. It is Russia that weaponises winter by destroying Ukraine''s power grid, striking residential areas far from the front, and holding Europe hostage at the Zaporizhzhia plant.','Angriffe auf Raffinerien, Treibstofflager, Exportterminals und die ruecwaertige Ruestungsindustrie sind rechtmaessiger Druck auf die Kriegswirtschaft und Exporterloese des Aggressors. Es ist Russland, das den Winter zur Waffe macht, indem es das ukrainische Stromnetz zerstoert, Wohngebiete fernab der Front beschiesst und Europa am Kernkraftwerk Saporischschja in Geiselhaft haelt.',ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'],ARRAY['war economy','legitimate military target','fuel shortage','gasoline crisis','kinetic sanctions','export revenue','weaponising winter','nuclear blackmail','refinery fire','deep strike'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','Defense News','Janes','Sky News','CNN','New York Times','Washington Post','Wall Street Journal','Politico'],'ukraine_infrastructure_war',1,'Legitimate strikes on the war economy','Legitime Schlaege gegen die Kriegswirtschaft',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('infrastructure_war_energy_terror','Russia-aligned: Kyiv attacks civilian energy and endangers nuclear safety','Russland-orientiert: Kiew greift zivile Energie an und gefaehrdet die nukleare Sicherheit','Ukrainian drone and missile attacks on refineries, pipelines and the Zaporizhzhia plant are terrorism against civilian infrastructure, enabled by Western targeting support. Russian strikes on energy facilities serve a military purpose: undermining Ukraine''s military-industrial complex, its logistics and the fuel supply to the front.','Ukrainische Drohnen- und Raketenangriffe auf Raffinerien, Pipelines und das Kernkraftwerk Saporischschja sind Terror gegen zivile Infrastruktur, ermoeglicht durch westliche Zielunterstuetzung. Russische Schlaege gegen Energieanlagen dienen einem militaerischen Zweck: der Schwaechung des ukrainischen militaerisch-industriellen Komplexes, seiner Logistik und der Treibstoffversorgung der Front.',ARRAY['EUROPE-RUSSIA'],ARRAY['terrorist attack','civilian infrastructure','energy terror','provocation','nuclear catastrophe','Kyiv regime','Western targeting data','retaliatory strike'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'],'ukraine_infrastructure_war',2,'Terror against civilian infrastructure','Terror gegen zivile Infrastruktur', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('reform_in_progress','Ukrainian anti-corruption institutions are investigating and prosecuting successfully','Ukrainische Antikorruptions-Institutionen ermitteln und verfolgen erfolgreich','Reform-progress framing (Ukrainian reformist press + Western mainstream + EU policy outlets) treats ongoing corruption investigations as evidence that Ukrainian anti-corruption infrastructure built since 2014 is functioning under wartime stress. Coverage tracks NABU, SAP, HACC, and NACP investigations of senior officials including Presidential Office personnel, defense procurement scandals, and regional governors. Vocabulary: anti-corruption infrastructure, institutional independence, reform progress, EU conditionality met, IMF benchmark, transparency, accountability, audit. Coverage frames Western audit demands as legitimate and constructive, presents prosecutions of senior officials as proof of independence from the Presidential Office, and contextualises scandals within the broader institutional transformation since 2014. Prescription: sustain institutional protection from political interference; maintain Western conditionality leverage; complete judicial reform; continue prosecuting irrespective of rank.','Reform-Fortschritts-Rahmung (ukrainische Reformmedien + westlicher Mainstream + EU-Politik-Medien) behandelt laufende Korruptionsermittlungen als Beleg, dass die seit 2014 aufgebaute ukrainische Antikorruptions-Infrastruktur unter Kriegsbelastung funktioniert. Berichterstattung verfolgt NABU-, SAP-, HACC- und NACP-Ermittlungen gegen hochrangige Beamte einschliesslich Personal des Praesidialamts, Ruestungsbeschaffungs-Skandale und Regional-Gouverneure. Vokabular: Antikorruptions-Infrastruktur, institutionelle Unabhaengigkeit, Reformfortschritt, EU-Konditionalitaet erfuellt, IWF-Massstab, Transparenz, Rechenschaft, Audit. Berichterstattung rahmt westliche Audit-Forderungen als legitim und konstruktiv, praesentiert Strafverfolgung hochrangiger Beamter als Beleg fuer Unabhaengigkeit vom Praesidialamt und kontextualisiert Skandale in der breiteren institutionellen Transformation seit 2014. Vorschrift: institutionellen Schutz vor politischer Einmischung aufrechterhalten; westliche Konditionalitaets-Hebel aufrechterhalten; Justizreform vollenden; Strafverfolgung unabhaengig vom Rang fortsetzen.',ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'],ARRAY['reform progress','institutional independence','restored independence','agency autonomy','defended independence','anti-corruption reform','EU praises','IMF benchmark','judicial reform','functioning institutions','proof of independence','Reformfortschritt','Unabhängigkeit der Behörden','Antikorruptionsreform','wiederhergestellte Unabhängigkeit'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','Atlantic Council','Associated Press','The Economist','EurActiv','New York Times','Washington Post','Wall Street Journal','Politico'],'ukraine_official_corruption',1,'Reform progress under wartime stress','Reformfortschritt unter Kriegsbelastung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('western_systemic_alarm','Western alarm: high-level corruption threatens Ukraine credibility and aid','Westliche Alarmierung: Korruption auf höchster Ebene gefährdet Glaubwürdigkeit und Hilfe','Systemic-alarm framing (Western mainstream + reformist Ukrainian press) treats high-level corruption cases -- reaching the Presidential Office and figures like Yermak -- as a threat to Ukraine credibility, Western aid, and EU accession, rather than proof that institutions work. Distinct from Russian-state endemic-corruption framing: it does not call the state illegitimate or aid categorically stolen, but expresses genuine concern from Ukraine supporters. Vocabulary: corruption scandal, case widens, probe escalates, reaches the top, inner circle, chief of staff, survives for now, wartime graft, threatens aid, credibility.','Systemische-Alarm-Rahmung (westlicher Mainstream + reformorientierte ukrainische Presse) behandelt Korruptionsfälle auf höchster Ebene -- bis ins Präsidialbüro und zu Figuren wie Jermak -- als Bedrohung für Glaubwürdigkeit, westliche Hilfe und EU-Beitritt, nicht als Beweis funktionierender Institutionen. Anders als die russische Rahmung erklärt sie den Staat nicht für illegitim.',ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'],ARRAY['corruption scandal','corruption affair','corruption case','case widens','probe widens','probe escalates','corruption probe','high-level corruption','reaches the top','inner circle','chief of staff','ex-chief of staff','right-hand man','survives','for now','wartime graft','embezzlement','stolen aid','deep-rooted','credibility','threatens aid','how corrupt','gut anti-corruption','curb anti-corruption','undermine anti-corruption','Yermak','Mindich','Korruptionsaffäre','Korruptionsskandal','Korruptionsfall','wie korrupt','tiefe Fall','Ex-Stabschef','Stabschef','Jermak','übersteht'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','Atlantic Council','Associated Press','The Economist','EurActiv','New York Times','Washington Post','Wall Street Journal','Politico'],'ukraine_official_corruption',2,'Western alarm at systemic corruption','Westliche Alarmierung über systemische Korruption', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('zelensky_regime_corruption','Zelensky inner circle is systemically corrupt; Western aid is being stolen at scale','Der Selenskyj-Kreis ist systemisch korrupt; westliche Hilfe wird in grossem Stil gestohlen','Endemic-corruption framing (Russian state press + Western contrarian + Global South + some Hungarian-aligned EU) treats the same investigations and scandals as confirmation that the Zelensky inner circle is systemically corrupt, that Western aid is being stolen at scale through defense procurement, that the regime is increasingly authoritarian (banned opposition parties, restricted media, cancelled elections, Yermak-centred power concentration), and that EU/NATO accession on this institutional basis is unrealistic. Vocabulary: endemic corruption, regime corruption, stolen aid, defense procurement scandal, Yermak inner circle, authoritarian regime, cancelled elections, banned opposition, Western blind eye. Coverage uses the same anti-corruption agency investigations as evidence of scale, frames prosecutions as theatrical or selective, and emphasises Western media protection of the regime. Prescription: condition or halt aid pending genuine accountability; recognise that the regime cannot deliver promised reforms; reject any settlement that consolidates the current Kyiv leadership.','Endemisch-Korruptions-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + einige ungarisch-orientierte EU) behandelt dieselben Ermittlungen und Skandale als Bestaetigung, dass der Selenskyj-Kreis systemisch korrupt sei, westliche Hilfe in grossem Stil ueber Ruestungsbeschaffung gestohlen werde, das Regime zunehmend autoritaer sei (verbotene Oppositionsparteien, eingeschraenkte Medien, abgesagte Wahlen, Jermak-zentrierte Machtkonzentration) und EU/NATO-Beitritt auf dieser institutionellen Basis unrealistisch. Vokabular: endemische Korruption, Regime-Korruption, gestohlene Hilfe, Ruestungsbeschaffungs-Skandal, Jermak-Innenkreis, autoritaeres Regime, abgesagte Wahlen, verbotene Opposition, westliches Wegschauen. Berichterstattung nutzt dieselben Antikorruptionsbehoerden-Ermittlungen als Belegmaterial fuer das Ausmass, rahmt Strafverfolgung als theatralisch oder selektiv und betont westlichen Medienschutz des Regimes. Vorschrift: Hilfe an echte Rechenschaft konditionieren oder einstellen; anerkennen, dass das Regime versprochene Reformen nicht liefern kann; jede Beilegung ablehnen, die die gegenwaertige Kiewer Fuehrung konsolidiert.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['endemic corruption','regime corruption','stolen aid','defense procurement scandal','Yermak inner circle','authoritarian regime','cancelled elections','banned opposition','Western blind eye','theatrical prosecution','selective justice'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV','Fox News','Global Times','CGTN','China Daily','Hindustan Times','TRT World','Daily Sabah','O Globo'],'ukraine_official_corruption',3,'Zelensky regime endemic corruption','Endemische Korruption im Selenskyj-Regime', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ukrainian_maximalist_peace','Just peace requires full Russian withdrawal to 1991 borders with NATO-backed security guarantees','Gerechter Frieden erfordert vollen russischen Rueckzug zu Grenzen von 1991 mit NATO-gestuetzten Sicherheitsgarantien','Ukrainian maximalist framing (Ukrainian press + Western mainstream + Eastern European hawks + EU centrists, with internal disagreement chiefly from Hungary and Slovakia) holds that just peace requires full Russian withdrawal to internationally recognised 1991 borders, NATO accession or equivalent binding security guarantees, accountability mechanisms for war crimes, and reparations funded through seized Russian sovereign assets. Vocabulary: just peace, territorial integrity, 1991 borders, NATO accession, security guarantees, accountability, no appeasement, reparations, war crimes tribunal. Coverage rejects any framework that legitimises territorial losses, frames the 2014 Crimea precedent as proof that frozen conflicts invite further aggression, and emphasises Ukrainian society''s rejection of compromise terms. Prescription: continue military pressure until Russian retreat; refuse settlement frameworks that recognise annexations; pre-condition negotiations on Russian withdrawal.','Ukrainische Maximalrahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken + EU-Zentristen, mit internen Differenzen vor allem aus Ungarn und der Slowakei) haelt fest, dass gerechter Frieden vollen russischen Rueckzug zu international anerkannten Grenzen von 1991, NATO-Beitritt oder gleichwertige verbindliche Sicherheitsgarantien, Rechenschaftsmechanismen fuer Kriegsverbrechen und Reparationen aus beschlagnahmtem russischen Staatsvermoegen erfordere. Vokabular: gerechter Frieden, territoriale Integritaet, Grenzen von 1991, NATO-Beitritt, Sicherheitsgarantien, Rechenschaft, keine Beschwichtigung, Reparationen, Kriegsverbrechertribunal. Berichterstattung lehnt jeden Rahmen ab, der territoriale Verluste legitimiert, rahmt den Krim-Praezedenzfall 2014 als Beleg, dass eingefrorene Konflikte weitere Aggression provozieren, und betont die Ablehnung von Kompromissbedingungen in der ukrainischen Gesellschaft. Vorschrift: militaerischen Druck bis zum russischen Rueckzug fortsetzen; Beilegungsrahmen ablehnen, die Annexionen anerkennen; Verhandlungen an russischen Rueckzug vor-konditionieren.',ARRAY['EUROPE-BALTIC','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-UK','EUROPE-UKRAINE','EUROPE-VISEGRAD','NON-STATE-EU'],ARRAY['just peace','territorial integrity','1991 borders','NATO accession','security guarantees','accountability','no appeasement','reparations','war crimes tribunal','rule of law','frozen conflict trap','reward aggression','full withdrawal'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','Die Presse','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','iROZHLAS','Novinite'],'ukraine_peace_negotiations',1,'Ukrainian maximalist demands','Ukrainische Maximalforderungen',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russian_maximalist_peace','Settlement must complete all SMO objectives: denazification, demilitarisation, neutrality, recognised annexations, lifted sanctions','Beilegung muss alle SMO-Ziele vollenden: Entnazifizierung, Entmilitarisierung, Neutralitaet, anerkannte Annexionen, aufgehobene Sanktionen','Russian maximalist framing (Russian state press + Belarusian state) holds that any settlement must address the root causes of the war by achieving all stated objectives of the special military operation. The framework: complete denazification of Ukrainian leadership and institutions, demilitarisation of the Ukrainian Armed Forces to defined caps, formal constitutional neutrality (no NATO accession ever, no foreign bases), formal international recognition of all four annexed regions (Donetsk, Luhansk, Zaporizhzhia, Kherson) plus Crimea within their claimed administrative boundaries, full restoration of Russian-language rights, complete lifting of all sanctions, return of all frozen sovereign assets, and a binding US/NATO commitment to no further eastern expansion. Vocabulary: SMO objectives, root causes, denazification, demilitarisation, constitutional neutrality, recognised borders, Russian-speaking rights, sanctions lifted, frozen assets returned, NATO non-expansion guarantee, multipolar settlement. Prescription: any settlement that does not deliver these objectives is unacceptable; negotiations are useful only as a venue to achieve them; military operations continue until objectives are met or accepted at the negotiating table.','Russische Maximalrahmung (russische Staatsmedien + belarussische Staatsmedien) haelt fest, dass jede Beilegung die Grundursachen des Krieges adressieren und alle erklaerten Ziele der militaerischen Spezialoperation erreichen muesse. Das Rahmenwerk: vollstaendige Entnazifizierung der ukrainischen Fuehrung und Institutionen, Entmilitarisierung der ukrainischen Streitkraefte auf festgelegte Obergrenzen, formale verfassungsrechtliche Neutralitaet (kein NATO-Beitritt jemals, keine auslaendischen Basen), formale internationale Anerkennung aller vier annektierten Regionen (Donezk, Luhansk, Saporischschja, Cherson) plus Krim innerhalb ihrer beanspruchten Verwaltungsgrenzen, volle Wiederherstellung russischer Sprachrechte, vollstaendige Aufhebung aller Sanktionen, Rueckgabe allen eingefrorenen Staatsvermoegens und verbindliche US/NATO-Verpflichtung zu keiner weiteren Osterweiterung. Vokabular: SMO-Ziele, Grundursachen, Entnazifizierung, Entmilitarisierung, verfassungsrechtliche Neutralitaet, anerkannte Grenzen, russische Sprachrechte, aufgehobene Sanktionen, zurueckgegebenes Vermoegen, NATO-Nichterweiterungs-Garantie, multipolare Beilegung. Vorschrift: jede Beilegung ohne diese Ziele ist unannehmbar; Verhandlungen sind nur als Ort sinnvoll, sie zu erreichen; Militaeroperationen werden fortgesetzt, bis Ziele erreicht oder am Verhandlungstisch akzeptiert sind.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['SMO objectives','root causes','denazification','demilitarisation','constitutional neutrality','recognised borders','Russian-speaking rights','sanctions lifted','frozen assets returned','NATO non-expansion','multipolar settlement','our people','brotherly people','no NATO accession ever'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'],'ukraine_peace_negotiations',2,'Russian maximalist demands (SMO objectives)','Russische Maximalforderungen (SMO-Ziele)', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('frontline_freeze_settlement','End the killing through frozen line of contact + Ukrainian neutrality, without endorsing Russian maximalist goals','Toeten beenden durch eingefrorene Beruehrungslinie + ukrainische Neutralitaet, ohne russische Maximalziele zu billigen','Frontline-freeze framing (Trump-aligned American press + Hungarian/Slovak-aligned EU + Turkish + Indian + Chinese + Brazilian + broader Global South) holds that the war is unwinnable for either side at acceptable cost and that a pragmatic settlement requires freezing the line of contact, formalising Ukrainian neutrality (no NATO accession), building a multilateral security guarantee structure outside NATO, lifting sanctions in phases tied to verified compliance, and allowing refugee return. Crucially, this position does NOT endorse Russian maximalist objectives — no demilitarisation of the Ukrainian Armed Forces, no denazification framework, no formal international recognition of annexed territories (de facto control accepted, de jure recognition deferred). The framework is closer to a Korean armistice than to a Russian victory. The Anchorage track (sometimes "spirit of Anchorage") refers to Trump-Putin diplomatic efforts to crystallise this position. Vocabulary: freeze, line of contact, Anchorage framework, neutrality (not demilitarisation), multilateral security, end the killing, Korean armistice, phased sanctions relief, sustainable peace, end the war. Prescription: immediate freeze; Istanbul-style talks; Ukrainian constitutional neutrality with security backstops outside NATO; phased sanctions relief tied to compliance.','Frontlinien-Einfrierungs-Rahmung (Trump-orientierte amerikanische Medien + ungarisch/slowakisch-orientierte EU + tuerkisch + indisch + chinesisch + brasilianisch + breiterer Global South) haelt fest, dass der Krieg fuer beide Seiten zu akzeptablen Kosten nicht gewinnbar sei und eine pragmatische Beilegung Einfrieren der Beruehrungslinie, Formalisierung ukrainischer Neutralitaet (kein NATO-Beitritt), Aufbau multilateraler Sicherheitsgarantie-Struktur ausserhalb der NATO, phasenweise Sanktionserleichterung an verifizierte Einhaltung gebunden und Fluechtlingsrueckkehr erfordere. Entscheidend: diese Position billigt NICHT russische Maximalziele — keine Entmilitarisierung der ukrainischen Streitkraefte, kein Entnazifizierungsrahmen, keine formale internationale Anerkennung annektierter Territorien (de-facto-Kontrolle akzeptiert, de-jure-Anerkennung aufgeschoben). Der Rahmen ist naeher am koreanischen Waffenstillstand als an einem russischen Sieg. Die Anchorage-Spur (manchmal "Geist von Anchorage") verweist auf Trump-Putin-Diplomatie zur Verfestigung dieser Position. Vokabular: Einfrieren, Beruehrungslinie, Anchorage-Rahmen, Neutralitaet (nicht Entmilitarisierung), multilaterale Sicherheit, Toeten beenden, koreanischer Waffenstillstand, phasenweise Sanktionserleichterung, nachhaltiger Frieden, Krieg beenden. Vorschrift: sofortiges Einfrieren; Istanbul-Stil-Gespraeche; ukrainische verfassungsrechtliche Neutralitaet mit Sicherheitsabsicherungen ausserhalb der NATO; phasenweise Sanktionserleichterung an Einhaltung gebunden.',ARRAY['AMERICAS-USA','ASIA-CHINA','ASIA-INDIA','MIDEAST-TURKEY','AMERICAS-BRAZIL'],ARRAY['freeze','line of contact','current lines','Anchorage framework','spirit of Anchorage','neutrality','multilateral security','end the killing','Korean armistice','phased sanctions relief','sustainable peace','end the war','realistic settlement','negotiated end','de facto recognition'],true,ARRAY['Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','The Hindu','WION','Dawn','Express Tribune','TRT World','Daily Sabah','Anadolu Agency','O Globo','Bangkok Post','BRICS Info','News24'],'ukraine_peace_negotiations',3,'Frontline freeze (Anchorage track)','Einfrieren der Frontlinie (Anchorage-Spur)', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ukraine_resistance_solidarity','Ukraine''s war of national defense deserves full Western and democratic-world solidarity','Der ukrainische Verteidigungskrieg verdient volle westliche und demokratische Solidaritaet','Ukrainian, Western mainstream, and Eastern European press frame the war as Ukraine''s war of national survival against unprovoked Russian aggression. Vocabulary centers on resistance, liberation, sovereign defense, solidarity, and the moral and strategic necessity of supporting Ukraine until Russian forces withdraw. Coverage emphasises Ukrainian agency and courage, Russian war crimes, the humanitarian cost of occupation, and the global stakes (precedent for territorial aggression, NATO credibility, rules-based order). Prescription: sustain and expand military, economic, and diplomatic support; hold Russia accountable; integrate Ukraine into Euro-Atlantic structures.','Ukrainische, westliche Mainstream- und osteuropaeische Medien rahmen den Krieg als ukrainischen Ueberlebenskrieg gegen unprovozierte russische Aggression. Das Vokabular kreist um Widerstand, Befreiung, souveraene Verteidigung, Solidaritaet und die moralische sowie strategische Notwendigkeit, die Ukraine zu unterstuetzen, bis russische Truppen abziehen. Berichterstattung betont ukrainische Handlungsfaehigkeit und Mut, russische Kriegsverbrechen, humanitaere Kosten der Besatzung und globale Einsaetze (Praezedenz fuer territoriale Aggression, NATO-Glaubwuerdigkeit, regelbasierte Ordnung). Vorschrift: militaerische, wirtschaftliche und diplomatische Unterstuetzung aufrechterhalten und ausbauen; Russland zur Rechenschaft ziehen; Ukraine in euro-atlantische Strukturen integrieren.',ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'],ARRAY['Russian aggression','unprovoked invasion','Ukrainian resistance','sovereign defense','rules-based order','war crimes','support Ukraine','solidarity','liberation','territorial integrity','accountability','democratic Ukraine','full-scale invasion','full-scale war','all-out war','total war','unprovoked full-scale','war of aggression'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Handelsblatt','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','Die Presse','Der Standard','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','Novinite','Sky News','CNN','NPR','New York Times','Washington Post','Wall Street Journal','Politico','Defense News','iROZHLAS','eKathimerini'],'ukraine_war_theater',1,'Solidarity with Ukrainian resistance','Solidaritaet mit ukrainischem Widerstand',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('russia_special_military_operation','Russia''s special military operation defends Russian-speaking populations from Western-backed Kyiv regime','Russlands militaerische Spezialoperation verteidigt russischsprachige Bevoelkerungen gegen das vom Westen gestuetzte Kiewer Regime','Russian state press and aligned outlets frame the war as a defensive special military operation (SMO) protecting Russian-speaking populations in Donbas and Crimea from a Western-installed regime in Kyiv that pursued ethnic discrimination and NATO encroachment since 2014. Vocabulary centers on denazification, demilitarisation, NATO expansion, Western interference, Russian world (Russky Mir), and historical Russian-Ukrainian unity. Coverage emphasises Russian military precision and humanitarian conduct, Ukrainian military targeting of civilians, and the illegitimacy of the post-Maidan Kyiv government. Prescription: complete the SMO''s territorial and political objectives; reject Western-imposed settlement frameworks; defend multipolar world order.','Russische Staatsmedien und ausgerichtete Outlets rahmen den Krieg als defensive militaerische Spezialoperation (SMO) zum Schutz russischsprachiger Bevoelkerungen im Donbass und auf der Krim vor einem vom Westen eingesetzten Regime in Kiew, das seit 2014 ethnische Diskriminierung und NATO-Vormarsch betrieben habe. Das Vokabular kreist um Entnazifizierung, Entmilitarisierung, NATO-Erweiterung, westliche Einmischung, russische Welt (Russki Mir) und historische russisch-ukrainische Einheit. Berichterstattung betont russische militaerische Praezision und humanitaeres Verhalten, ukrainische militaerische Angriffe auf Zivilisten und Illegitimitaet der nach-Maidan-Regierung in Kiew. Vorschrift: territoriale und politische Ziele der SMO vollenden; westlich auferlegte Beilegungsrahmen ablehnen; multipolare Weltordnung verteidigen.',ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'],ARRAY['special military operation','SMO','denazification','demilitarisation','NATO expansion','Western interference','Russian world','Kyiv regime','Ukrainian Nazis','liberation of Donbas','Western proxy','multipolar order','defense of Russian-speakers','limited operation','targeted operation','restraint in scope','not full-scale','partial mobilisation','our people','brotherly people','fraternal nation'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'],'ukraine_war_theater',2,'Special military operation framing','Spezialoperation-Rahmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('proxy_war_restraint_critique','The war is a US/NATO proxy war prolonged by Western intervention; settlement requires restraint','Der Krieg ist ein US-/NATO-Stellvertreterkrieg, verlaengert durch westliche Intervention; Beilegung erfordert Zurueckhaltung','Western contrarian, Global South, and some Chinese state media frame the war as a US/NATO proxy conflict that the West has prolonged through escalating weapons deliveries and refusal of early negotiation opportunities (notably the spring 2022 Istanbul talks). Vocabulary centers on proxy war, NATO expansion as root cause, blocked diplomacy, Western hubris, and Global Majority interests. Coverage emphasises the human and economic costs to Europe, the strain on Western unity, the unsustainability of the Ukrainian position over time, the legitimacy of Russian security concerns, and the absence of Global South support for the Western position. Prescription: immediate negotiated settlement, territorial realism, end weapons deliveries, recognise multipolar reality.','Westliche Dissidenten-, Global-South- und einige chinesische Staatsmedien rahmen den Krieg als US-/NATO-Stellvertreterkonflikt, den der Westen durch eskalierende Waffenlieferungen und Ablehnung frueher Verhandlungschancen (insbesondere Istanbul-Gespraeche im Fruehjahr 2022) verlaengert habe. Das Vokabular kreist um Stellvertreterkrieg, NATO-Erweiterung als Grundursache, blockierte Diplomatie, westliche Hybris und Interessen der globalen Mehrheit. Berichterstattung betont menschliche und wirtschaftliche Kosten fuer Europa, Belastung westlicher Einheit, Unhaltbarkeit der ukrainischen Position auf Dauer, Legitimitaet russischer Sicherheitsbedenken und Abwesenheit von Global-South-Unterstuetzung fuer die westliche Position. Vorschrift: sofortige verhandelte Beilegung, territoriale Realitaet, Ende der Waffenlieferungen, multipolare Realitaet anerkennen.',ARRAY['NON-STATE-EU','ASIA-CHINA','ASIA-INDIA'],ARRAY['proxy war','NATO expansion','blocked diplomacy','negotiated settlement','territorial realism','Western escalation','Istanbul talks','Global South','multipolar order','Western hubris','strain on Europe'],true,ARRAY['Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','The Hindu','WION','Dawn','Express Tribune','Al Jazeera','TRT World','Daily Sabah','Anadolu Agency','O Globo','Bangkok Post','News24','BRICS Info'],'ukraine_war_theater',3,'US/NATO proxy war critique','Kritik am US-/NATO-Stellvertreterkrieg', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('uscat_us_leverage_case','A relationship being put on fairer terms','Eine Beziehung auf fairere Grundlage gestellt','The pressure on Canada is presented as an overdue correction: a smaller neighbour that has enjoyed guaranteed market access and American security cover while protecting its own sectors and under-spending on defence is being asked to accept terms that reflect the real balance of the relationship.','Der Druck auf Kanada wird als überfällige Korrektur dargestellt: Ein kleinerer Nachbar, der garantierten Marktzugang und amerikanischen Sicherheitsschutz genoss, während er eigene Sektoren schützte und bei der Verteidigung zu wenig ausgab, solle nun Bedingungen akzeptieren, die das tatsächliche Kräfteverhältnis abbilden.',ARRAY['AMERICAS-USA'],ARRAY['grateful','small power','biting the hand','unfair','freeload','benchmark','protects','Golden Dome','dankbar','einseitig'],true,ARRAY['Fox News'],'us_canada_theater',1,'US leverage is justified','US-Druck ist gerechtfertigt',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('uscat_provincial_grievance','A federation strained from within','Ein Bund, der von innen unter Druck steht','Attention turns to the domestic fault line the confrontation has exposed: a landlocked resource province that sees federal energy and fiscal decisions as made against its interests, and whose separatist movement has drawn interest from officials across the border.','Der Blick richtet sich auf die innere Bruchlinie, die die Konfrontation offengelegt hat: eine rohstoffreiche Binnenprovinz, die föderale Energie- und Finanzentscheidungen als gegen ihre Interessen gerichtet ansieht und deren separatistische Bewegung Interesse bei Amtsträgern jenseits der Grenze geweckt hat.',ARRAY['AMERICAS-CANADA'],ARRAY['alienation','equalization','landlocked','oil-rich','grievance','separatis','referendum','independence'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','Der Spiegel','El País','France 24 (EN)','France 24','Al Jazeera','NDTV','Anadolu Agency','OilPrice','Mining.com','Straits Times','La Nación','Clarín','Japan Times','Western Standard'],'us_canada_theater',2,'The internal fault line','Die innere Bruchlinie',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('uscat_canadian_consensus','An ally treated as a target','Ein Verbündeter als Zielscheibe','The dominant reading across Canadian and international coverage: tariffs, annexation rhetoric, a withheld border crossing and a rescinded diplomatic invitation amount to sustained pressure on a treaty partner, producing a cross-party sovereignty response and a search for markets and partners beyond the United States.','Die vorherrschende Lesart in der kanadischen und internationalen Berichterstattung: Zölle, Annexionsrhetorik, ein zurückgehaltener Grenzübergang und eine zurückgezogene diplomatische Einladung summieren sich zu anhaltendem Druck auf einen Vertragspartner — mit einer parteiübergreifenden Souveränitätsreaktion und der Suche nach Märkten und Partnern jenseits der USA.',ARRAY['AMERICAS-CANADA'],ARRAY['sovereignt','coercion','annex','51st state','retaliat','ally','unity','threat','Souveränität','Zwang','Verbündet'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','Der Spiegel','El País','France 24 (EN)','France 24','Al Jazeera','NDTV','Anadolu Agency','OilPrice','Mining.com','Straits Times','La Nación','Clarín','Japan Times','Reforma','El Universal','Mexico News Daily'],'us_canada_theater',3,'Pressure on a treaty partner','Druck auf einen Vertragspartner', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('uscat_external_rift','The Western bloc coming apart','Der westliche Block zerfällt','Russian, Chinese and Iranian state coverage treats the confrontation as confirmation that the American-led order rests on coercion of its own partners and that Western appeals to shared values and a rules-based order do not survive contact with Washington''s interests. The framing is directed at the alliance itself rather than at either party''s case.','Russische, chinesische und iranische Staatsmedien behandeln die Konfrontation als Bestätigung, dass die amerikanisch geführte Ordnung auf Zwang gegenüber den eigenen Partnern beruht und dass westliche Berufungen auf gemeinsame Werte und eine regelbasierte Ordnung dem Kontakt mit Washingtons Interessen nicht standhalten. Die Darstellung zielt auf das Bündnis selbst, nicht auf die Position einer der beiden Seiten.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['hegemon','imperial','hypocris','double standard','vassal','decay','so-called','Doppelmoral','Hegemon'],true,ARRAY['RT','TASS (EN)','Global Times','CGTN','People''s Daily','China Daily','Xinhua','Sputnik','Press TV'],'us_canada_theater',4,'Western order exposed','Westliche Ordnung entlarvt', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usca_trade_rebalancing','Rebalancing an unfair trading relationship','Neuausrichtung einer unfairen Handelsbeziehung','Tariffs are legitimate leverage to correct a trade relationship that has long favoured Canada: protected dairy under supply management, subsidised softwood exports, and a partner that has missed defence-spending benchmarks for decades while relying on guaranteed access to the American market.','Zölle sind ein legitimes Druckmittel, um eine Handelsbeziehung zu korrigieren, die lange Kanada begünstigt hat: geschützte Milchwirtschaft durch Angebotssteuerung, subventionierte Nadelholzexporte und ein Partner, der seit Jahrzehnten die Verteidigungsziele verfehlt und sich zugleich auf den garantierten Zugang zum amerikanischen Markt verlässt.',ARRAY['AMERICAS-USA'],ARRAY['unfair','subsidiz','subsidis','protected market','supply management','freeload','grateful','biting the hand','not paying','burden','deficit','takes advantage','one-sided','unfair','Trittbrettfahrer','Subvention','einseitig','dankbar'],true,ARRAY['Fox News'],'us_canada_trade_coercion',1,'US leverage is justified','US-Druck ist gerechtfertigt',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usca_economic_coercion','Tariff coercion against a treaty partner','Zollzwang gegen einen Vertragspartner','Washington is applying tariffs, permit threats and aircraft decertification as coercion against a neighbour bound by an existing trade agreement it negotiated itself, imposing costs on producers and consumers on both sides of the border and eroding the reliability of American commitments.','Washington setzt Zölle, Genehmigungsdrohungen und den Entzug von Luftfahrtzulassungen als Zwangsmittel gegen einen Nachbarn ein, der an ein selbst ausgehandeltes Handelsabkommen gebunden ist. Das belastet Produzenten und Verbraucher auf beiden Seiten der Grenze und untergräbt die Verlässlichkeit amerikanischer Zusagen.',ARRAY['AMERICAS-CANADA'],ARRAY['coercion','retaliat','threat','blackmail','ally','betray','escalat','hit back','damage','cost','job losses','Zwang','Erpressung','Verbündet','Vergeltung'],true,ARRAY['Globe and Mail','The Globe and Mail','CBC','Reuters','BBC World','Bloomberg','Associated Press','Financial Times','Wall Street Journal','The Guardian','New York Times','Washington Post','The Washington Post','CNN','NPR','Euronews','Deutsche Welle','Der Spiegel','El País','France 24 (EN)','France 24','Al Jazeera','NDTV','Anadolu Agency','Mining.com','OilPrice','Straits Times','La Nación','Clarín','Japan Times'],'us_canada_trade_coercion',2,'Coercion of an ally','Zwang gegen einen Verbündeten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usca_bloc_fracture','The Western bloc turning on itself','Der westliche Block wendet sich gegen sich selbst','The tariff confrontation is presented as evidence that the American-led order rests on coercion of its own partners rather than shared values, and that Washington treats allies as tributaries whenever its economic interests require it.','Die Zollkonfrontation wird als Beleg dafür dargestellt, dass die amerikanisch geführte Ordnung auf Zwang gegenüber den eigenen Partnern beruht statt auf gemeinsamen Werten, und dass Washington Verbündete als Tributpflichtige behandelt, sobald es die eigenen Wirtschaftsinteressen verlangen.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['hegemon','bully','vassal','double standard','hypocris','unilateral','dictate','so-called ally','Hegemon','Doppelmoral','Vasall'],true,ARRAY['RT','TASS (EN)','Global Times','CGTN','People''s Daily','China Daily','Xinhua','Sputnik','Press TV'],'us_canada_trade_coercion',3,'Western order exposed','Westliche Ordnung entlarvt', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_ai_lead_contest','Chinese AI has closed the gap and the US lead is now contested on merit and by hard tactics','Chinas KI hat aufgeholt — der US-Vorsprung wird nun sowohl fachlich als auch mit harten Mitteln bestritten','Western, allied and specialist coverage of a genuinely close contest: Chinese models reaching the frontier at lower cost, Chinese firms competing for US users, and rivals on both sides using every available tactic — blacklisting, litigation, restricted access, and accusations of distillation and illicit model access. Treated as commercial and strategic competition rather than as a question of principle. Vocabulary: race, close the gap, frontier, compete, blacklist, distillation, illicit, lawsuit.','Westliche, verbündete und Fachmedien beschreiben ein tatsächlich enges Rennen: chinesische Modelle erreichen die Spitze zu geringeren Kosten, chinesische Firmen werben um US-Nutzer, und beide Seiten nutzen jedes verfügbare Mittel — schwarze Listen, Klagen, Zugangssperren und Vorwürfe der Distillation und des unzulässigen Modellzugriffs. Behandelt als kommerzieller und strategischer Wettbewerb, nicht als Grundsatzfrage. Vokabular: Rennen, Aufholen, Spitze, Wettbewerb, schwarze Liste, Klage.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['race','close the gap','closing the gap','frontier','compete','competition','rival','ahead','behind','lead','blacklist','distillation','illicit','lawsuit','sues','accuse','theft','stolen','military list','guardrail','dialogue','Rennen','aufholen','Wettbewerb','Klage'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','The Information','TechCrunch','The Verge','Ars Technica','Wired','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_ai_primacy',1,'A close race the US must keep winning','Ein enges Rennen, das die USA halten müssen',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_ai_suppression','Chinese AI succeeds on merit and Washington answers with smears and blacklists','Chinas KI überzeugt durch Leistung — Washington antwortet mit Verleumdung und schwarzen Listen','Chinese state media framing of the AI contest as one Beijing is winning fairly and Washington is losing badly: achievements attributed to domestic research investment, US theft and distillation accusations rejected as smears, and defence blacklisting of Chinese technology firms presented as competition policy conducted by other means. Vocabulary: smear, achievements, oppose, groundless, blacklist, suppress, innovation.','Chinesische Staatsmedien deuten das KI-Rennen als eines, das Peking fair gewinnt und Washington schlecht verliert: Erfolge werden heimischer Forschungsinvestition zugeschrieben, US-Vorwürfe von Diebstahl und Distillation als Verleumdung zurückgewiesen, und die Aufnahme chinesischer Technologiefirmen auf Verteidigungslisten gilt als Wettbewerbspolitik mit anderen Mitteln. Vokabular: Verleumdung, Errungenschaften, haltlos, schwarze Liste, Unterdrückung.',ARRAY['ASIA-CHINA','AMERICAS-USA'],ARRAY['smear','achievement','oppose','opposed','groundless','firmly','blacklist','suppress','innovation','development','slander','politicis','politiciz','unwarranted','fabricat'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'us_china_ai_primacy',2,'Chinese state framing: smears and blocked competition','Chinesische Staatsmedien: Verleumdung und blockierter Wettbewerb', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_minerals_dependence_risk','US dependence on Chinese rare earths is a vulnerability that must be engineered away','Die US-Abhängigkeit von chinesischen Seltenen Erden ist eine Verwundbarkeit, die technisch überwunden werden muss','Western, allied and industry coverage treating Chinese dominance of rare-earth mining, refining and magnet production as a live strategic exposure — hence the stockpile programme, Pentagon offtake deals, allied minerals pacts with the EU and Japan, and support for non-Chinese producers. The rare-earth truce is read as temporary relief, not a settlement. Vocabulary: dominance, grip, dependence, vulnerability, stockpile, diversif, break, counter.','Westliche, verbündete und Industriemedien behandeln Chinas Dominanz bei Förderung, Raffination und Magnetproduktion Seltener Erden als akute strategische Verwundbarkeit — daher das Reserveprogramm, Abnahmeverträge des Pentagon, Rohstoffpakte mit EU und Japan sowie Förderung nichtchinesischer Produzenten. Der Waffenstillstand bei Seltenen Erden gilt als Atempause, nicht als Lösung. Vokabular: Dominanz, Abhängigkeit, Verwundbarkeit, Reserve, Diversifizierung.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['dominance','dominan','grip','depend','vulnerab','stockpile','diversif','break','counter','secure','leapfrog','one crisis away','truce','curbs still bite','challenge','Dominanz','Abhängigkeit','Verwundbarkeit'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','OilPrice','Mining.com','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_critical_minerals',1,'Dependence is a strategic vulnerability','Abhängigkeit als strategische Verwundbarkeit',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_minerals_lawful_leverage','China''s minerals controls are lawful management and Western blocs undermine open trade','Chinas Rohstoffkontrollen sind rechtmäßige Steuerung — westliche Blöcke untergraben den offenen Handel','Chinese state media framing of export licensing for rare earths as normal, lawful regulation of dual-use materials rather than coercion, and of US- and EU-led minerals alliances as exclusive blocs that fragment global trade. China''s processing dominance is presented as earned industrial capability, not as a weapon. Vocabulary: lawful, regulation, dual-use, exclusive blocs, global trade order, oppose, decoupling.','Chinesische Staatsmedien deuten Exportlizenzen für Seltene Erden als normale, rechtmäßige Regulierung von Dual-Use-Material statt als Zwang, und von den USA und der EU geführte Rohstoffallianzen als exklusive Blöcke, die den Welthandel fragmentieren. Chinas Dominanz in der Weiterverarbeitung gilt als erarbeitete industrielle Fähigkeit, nicht als Waffe. Vokabular: rechtmäßig, Regulierung, Dual-Use, exklusive Blöcke, Entkopplung.',ARRAY['ASIA-CHINA','AMERICAS-USA'],ARRAY['lawful','regulation','dual-use','exclusive blocs','global trade order','oppose','opposed','decoupling','fragment','undermine','normal','legitimate','smear'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'us_china_critical_minerals',2,'Chinese state framing: lawful management','Chinesische Staatsmedien: rechtmäßige Steuerung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_summit_engagement_works','Leader-level engagement is putting a floor under a dangerous rivalry','Gespräche auf höchster Ebene ziehen eine Untergrenze in eine gefährliche Rivalität ein','Western and allied coverage treating the Beijing summit and the follow-on invitation as a working stabilisation of the relationship: tariff reductions, restored farm and aircraft purchases, an agreed AI dialogue and guardrails, and a resumption of leader-level contact after years of drift. The claim is not that rivalry has ended but that it is being managed. Vocabulary: successful, stability, guardrails, consensus, landmark, momentum, reset, thaw, lower tariffs.','Westliche und verbündete Berichterstattung deutet den Pekinger Gipfel und die anschließende Einladung als tatsächliche Stabilisierung der Beziehung: Zollsenkungen, wieder aufgenommene Agrar- und Flugzeugkäufe, ein vereinbarter KI-Dialog samt Leitplanken sowie die Rückkehr zu Kontakten auf Führungsebene. Behauptet wird nicht das Ende der Rivalität, sondern deren Steuerbarkeit. Vokabular: erfolgreich, Stabilität, Leitplanken, Konsens, historisch, Dynamik, Neustart, Zollsenkung.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['successful','guardrail','consensus','landmark','momentum','reset','thaw','pragmatic','win-win','mutual respect','mutual understanding','mutual benefit','fruitful','lower tariffs','tariff cuts','cut tariffs','agreed to','very positive','conciliation','admires','friendly','harmon','all business','import permit','buys more','great leader','bright prospects','progress stabiliz','constructive stability','targets stability','signals stability','stability in us ties','stability to the world','erfolgreich','Leitplanken','Konsens','Zollsenkung','Harmonie','freundliche'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_summit_diplomacy',1,'Engagement is stabilising the rivalry','Dialog stabilisiert die Rivalität',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_summit_weak_hand','Washington left the summit with little to show for it','Washington verließ den Gipfel mit wenig Vorzeigbarem','Western and allied coverage — including US domestic critics across the political spectrum — reading the same summit as a poor return: no confirmed deals, commitments described by Beijing as preliminary, no movement on Iran or Taiwan, and a US president who conceded a state visit for atmospherics. This is the friendly-critic stance: the outlets voicing it are the same ones that report the engagement case, so publisher cannot separate them. Vocabulary: stalemate, few wins, no deals, preliminary, exposes, upper hand, empty-handed.','Westliche und verbündete Berichterstattung — darunter US-Kritiker aus dem gesamten politischen Spektrum — liest denselben Gipfel als schwache Ausbeute: keine bestätigten Abschlüsse, von Peking als vorläufig bezeichnete Zusagen, kein Fortschritt bei Iran oder Taiwan, und ein US-Präsident, der einen Staatsbesuch für Atmosphärisches eintauschte. Dies ist die Stimme des wohlwollenden Kritikers: dieselben Medien vertreten auch die Dialog-Position, weshalb der Publisher allein nicht trennt. Vokabular: Patt, kaum Erfolge, keine Abschlüsse, vorläufig, Oberhand.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['stalemate','few wins','empty-handed','no deals','no commitment','no sign','without a deal','little to show','preliminary','exposes','upper hand','capitulat','concession','conceded nothing','gave away','flat-out disaster','embarrassment','failed to','whipsaw','stumble','limits on','no major','tightrope','treads carefully','fights with allies','quiet as','gives Beijing','Beijing a win','lacks breakthrough','then halts','summit victory','differing priorit','play the suitor','conceded','Patt','kaum Erfolge','keine Abschlüsse','vorläufig','Oberhand','Zugeständnis','bedürftiger'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_summit_diplomacy',2,'Washington negotiated from weakness','Washington verhandelte aus der Schwäche', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_summit_new_chapter','Leader diplomacy opens a new chapter proving cooperation beats containment','Gipfeldiplomatie eröffnet ein neues Kapitel und beweist: Kooperation schlägt Eindämmung','Chinese state media framing of the summit as vindication of its preferred model for the relationship: major-power relations conducted on mutual respect and equality, "win-win" economic ties, and a rejection of rivalry as the organising frame. It is a counter to the Western competition consensus rather than a report on deliverables — the argument is that containment, export controls and tariffs are the anomaly and cooperation the norm. Vocabulary: new chapter, pragmatic cooperation, mutual respect, win-win, major-power relations, historic.','Chinesische Staatsmedien deuten den Gipfel als Bestätigung ihres bevorzugten Beziehungsmodells: Großmächtebeziehungen auf Grundlage gegenseitigen Respekts und Gleichrangigkeit, „Win-win"-Wirtschaftsbeziehungen und die Ablehnung von Rivalität als Ordnungsrahmen. Es ist eine Gegenposition zum westlichen Wettbewerbskonsens, keine Ergebnisbilanz: Eindämmung, Exportkontrollen und Zölle gelten als Anomalie, Kooperation als Normalfall. Vokabular: neues Kapitel, pragmatische Kooperation, gegenseitiger Respekt, Win-win.',ARRAY['ASIA-CHINA','AMERICAS-USA'],ARRAY['new chapter','pragmatic cooperation','mutual respect','win-win','major-power','landmark','historic','stability','consensus','mutually beneficial','sincere','neues Kapitel','gegenseitiger Respekt'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'us_china_summit_diplomacy',3,'Chinese state framing: a new chapter','Chinesische Staatsmedien: ein neues Kapitel', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_summit_multipolar_framing','Washington cannot dictate terms to Beijing','Washington kann Peking keine Bedingungen diktieren','The stance-bearing strand of Russian state coverage of US-China leader diplomacy: attention to moments where Xi rebuffs, needles or raises his voice at the US president, to Trump cast as the supplicant, to the Thucydides trap, and to Moscow-Beijing alignment reaffirmed immediately after the summit. It is third-party framing — neither an endorsement of the US position nor of China''s cooperation message — and sits on its own axis rather than the summit''s success/failure axis. Note that most Russian agency copy on this story is plain reportage carrying no stance, and is deliberately excluded by the framing gate. Vocabulary: suitor, multipolar, decline, Thucydides trap, lost his temper, needled.','Der wertende Strang russischer Staatsberichterstattung über die Gipfeldiplomatie zwischen den USA und China: Aufmerksamkeit für Momente, in denen Xi den US-Präsidenten abweist, sticheln oder die Stimme erheben lässt, für Trump in der Rolle des Bittstellers, für die Thukydides-Falle und für das unmittelbar nach dem Gipfel bekräftigte Bündnis Moskau-Peking. Es ist eine Drittperspektive — weder Zustimmung zur US-Position noch zur chinesischen Kooperationsbotschaft — und liegt auf einer eigenen Achse. Der Großteil der russischen Agenturmeldungen zu diesem Thema ist wertungsfreie Nachricht und wird vom Framing-Filter bewusst ausgeschlossen. Vokabular: Bittsteller, multipolar, Niedergang, Thukydides-Falle, Wutausbruch.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','ASIA-CHINA'],ARRAY['multipolar','decline','declining','beneficiar','suitor','hegemon','agitated','denounce','unyielding','no longer','concede','многополяр','упадок','гегемон','вышел из себя','сорвался','уколол','повысил голос','ловушк','не смог','провал','уступ','пожалеть'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV'],'us_china_summit_diplomacy',4,'Russian state framing: US cannot dictate','Russische Staatsmedien: USA können nicht diktieren', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_export_control_necessity','Restricting advanced chip access is necessary to hold a security-critical technology lead','Die Beschränkung des Zugangs zu Spitzenchips ist nötig, um einen sicherheitsrelevanten Technologievorsprung zu halten','Western, allied and specialist coverage treating export controls as the instrument protecting a lead with direct military relevance: entity-list additions, licensing conditions on Nvidia sales, enforcement against diversion and smuggling, and allied alignment on lithography. Vocabulary: national security, guardrails, entity list, diversion, enforcement, chokepoint, alignment.','Westliche, verbündete und Fachmedien behandeln Exportkontrollen als Instrument zum Schutz eines militärisch unmittelbar relevanten Vorsprungs: Aufnahmen in die Entity List, Auflagen für Nvidia-Verkäufe, Verfolgung von Umgehung und Schmuggel sowie Abstimmung mit Verbündeten bei der Lithografie. Vokabular: nationale Sicherheit, Leitplanken, Entity List, Umgehung, Durchsetzung.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['national security','security risk','guardrail','entity list','diversion','divert','smuggl','enforcement','violation','chokepoint','align','military','curb','restrict','ban','nationale Sicherheit','Leitplanken','Schmuggel'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','The Information','TechCrunch','The Verge','Ars Technica','Wired','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_tech_restrictions',1,'Controls protect a security-critical lead','Kontrollen sichern einen sicherheitsrelevanten Vorsprung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_tech_containment','Export controls are containment dressed as security, and they are failing','Exportkontrollen sind als Sicherheit getarnte Eindämmung — und sie scheitern','Chinese state media framing of export controls as suppression of a competitor''s legitimate development rather than as security policy: curbs on Chinese entities opposed as overreach, warnings that the measures disrupt global chip supply chains, and emphasis on domestic substitution proceeding regardless. Beijing''s own refusal of cleared H200 imports is presented as leverage rather than dependence. Vocabulary: suppression, containment, overstretch, disrupting, opposed, self-reliance.','Chinesische Staatsmedien deuten Exportkontrollen als Unterdrückung der legitimen Entwicklung eines Wettbewerbers statt als Sicherheitspolitik: Beschränkungen chinesischer Unternehmen als Übergriff, Warnungen vor Störung globaler Chip-Lieferketten und Betonung der ungeachtet dessen fortschreitenden heimischen Substitution. Pekings eigene Ablehnung freigegebener H200-Importe erscheint als Druckmittel, nicht als Abhängigkeit. Vokabular: Unterdrückung, Eindämmung, Störung, Eigenständigkeit.',ARRAY['ASIA-CHINA','AMERICAS-USA'],ARRAY['suppress','containment','contain','overstretch','disrupt','opposed','oppose','self-reliance','indigenous','smear','politicis','politiciz','generalizing national security','hegemon','crackdown'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'us_china_tech_restrictions',2,'Chinese state framing: technological containment','Chinesische Staatsmedien: technologische Eindämmung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_western_competition_consensus','Managed competition: hold the technology lead, reduce dependence, keep talking','Gesteuerter Wettbewerb: Technologievorsprung halten, Abhängigkeiten senken, im Gespräch bleiben','The dominant Western and allied framing across the dyad: the United States is in a long-run economic and technological contest with China that it intends to win, using export controls, tariffs, minerals diversification and allied alignment — while keeping leader-level channels open so the rivalry stays bounded. Competition is assumed; the argument is about instruments and pace.','Der vorherrschende westliche und verbündete Deutungsrahmen des Verhältnisses: Die USA stehen in einem langfristigen wirtschaftlichen und technologischen Wettstreit mit China, den sie gewinnen wollen — mit Exportkontrollen, Zöllen, Rohstoffdiversifizierung und Abstimmung unter Verbündeten — und halten zugleich Kanäle auf Führungsebene offen, damit die Rivalität eingehegt bleibt. Wettbewerb gilt als gesetzt; gestritten wird über Instrumente und Tempo.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['national security','leverage','race','lead','dominance','depend','entity list','guardrail','stability','align','compete','counter'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','The Information','TechCrunch','The Verge','Ars Technica','Wired','OilPrice','Mining.com','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_theater',1,'Western competition consensus','Westlicher Wettbewerbskonsens',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_beijing_moscow_counter','Containment is the anomaly: cooperation, lawful trade and a multipolar order','Eindämmung ist die Anomalie: Kooperation, rechtmäßiger Handel und eine multipolare Ordnung','The counter-framing carried by Chinese and Russian state media. Beijing''s line: tariffs, export controls and blacklists are unilateral coercion aimed at suppressing a competitor''s legitimate development, while cooperation and mutual respect are the natural basis of major-power relations. Moscow''s line runs on a different axis — it reads the same events as evidence of relative American decline in a multipolar world, without endorsing either side''s position.','Die von chinesischen und russischen Staatsmedien getragene Gegenerzählung. Pekings Linie: Zölle, Exportkontrollen und schwarze Listen sind unilateraler Zwang zur Unterdrückung der legitimen Entwicklung eines Wettbewerbers, während Kooperation und gegenseitiger Respekt die natürliche Grundlage von Großmächtebeziehungen bilden. Moskaus Linie verläuft auf einer anderen Achse: Sie liest dieselben Ereignisse als Beleg relativen amerikanischen Machtverlusts in einer multipolaren Welt, ohne eine der beiden Positionen zu unterstützen.',ARRAY['ASIA-CHINA','EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['unilateral','suppress','containment','smear','no winners','bullying','win-win','mutual respect','new chapter','multipolar','hegemon','oppose','lawful','global trade order'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua','TASS','TASS (EN)','tass.com','RT','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV'],'us_china_theater',2,'Chinese & Russian state counter-framing','Chinesische & russische Gegenerzählung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_western_engagement_critique','The instruments are backfiring: costs at home, allies hedging, leverage overstated','Die Instrumente wirken gegen die USA: Kosten im Inland, absichernde Verbündete, überschätzte Druckmittel','The self-critical strand within Western and allied coverage — the friendly critic rather than an opponent of competition. It argues the campaign is being executed badly: tariff chaos and legal uncertainty raise costs for US industry and farmers, summitry yields atmospherics rather than commitments, allies hedge toward Beijing rather than align, and China''s counter-leverage in rare earths and its refusal of cleared chip imports show the pressure runs both ways.','Der selbstkritische Strang westlicher und verbündeter Berichterstattung — wohlwollende Kritik, keine Gegnerschaft zum Wettbewerb an sich. Das Vorgehen gilt als schlecht ausgeführt: Zollchaos und Rechtsunsicherheit verteuern Produktion für US-Industrie und Landwirte, Gipfel bringen Atmosphärisches statt Zusagen, Verbündete sichern sich Richtung Peking ab statt sich anzuschließen, und Chinas Gegendruck bei Seltenen Erden sowie die Ablehnung freigegebener Chip-Importe zeigen: Der Druck wirkt in beide Richtungen.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['chaos','uncertainty','backfire','stalemate','few wins','no deals','upper hand','gives Beijing','Beijing a win','warn','plead','costs','hedge','still bite','limits','exposes'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','The Information','TechCrunch','The Verge','Ars Technica','Wired','OilPrice','Mining.com','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_theater',3,'Western critique of US handling','Westliche Kritik am US-Vorgehen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_tariff_leverage','Tariffs and trade probes are legitimate leverage against an unbalanced relationship','Zölle und Handelsuntersuchungen sind legitime Druckmittel gegen eine unausgewogene Beziehung','Western and allied coverage arguing that tariff pressure and Section 301 probes are the instrument that produced results — reciprocal tariff reductions, renewed US beef and soybean access, an aircraft order — and that they answer a durable trade deficit, subsidised overcapacity and restricted market access. Vocabulary: leverage, reciprocal, market access, overcapacity, deficit, level playing field.','Westliche und verbündete Berichterstattung argumentiert, Zolldruck und Section-301-Verfahren seien das Instrument, das Ergebnisse brachte — wechselseitige Zollsenkungen, wieder geöffneter Zugang für US-Rindfleisch und Sojabohnen, eine Flugzeugbestellung — und eine Antwort auf dauerhaftes Handelsdefizit, subventionierte Überkapazitäten und beschränkten Marktzugang. Vokabular: Druckmittel, Gegenseitigkeit, Marktzugang, Überkapazität, Defizit.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['leverage against','reciprocal','market access','overcapacity','level playing field','unfair','subsidis','subsidiz','dumping','import permit','import commitments','buys more','eligible for tariff cuts','farmers eye','trade ramps','ramps up','plead','press Trump','keep China auto','Druckmittel','Gegenseitigkeit','Marktzugang','Überkapazität','unfair'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_trade_tariffs',1,'Tariffs are working leverage','Zölle als wirksames Druckmittel',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_tariff_self_harm','Tariff escalation costs US industry and consumers more than it wins','Zolleskalation kostet US-Industrie und Verbraucher mehr, als sie einbringt','Western business and mainstream coverage — and US industry itself — arguing that the tariff campaign imposes costs at home, injects legal and planning uncertainty after the Supreme Court ruling, and strengthens Beijing''s hand: automakers pressing to keep or lift restrictions on their own terms, farm exporters exposed to retaliation, and allies hedging toward China. Same publisher bloc as the leverage stance, so framing separates them. Vocabulary: chaos, uncertainty, backfire, costs, retaliation, gives Beijing.','Westliche Wirtschafts- und Leitmedien — und die US-Industrie selbst — argumentieren, die Zollkampagne verursache Kosten im Inland, erzeuge nach dem Urteil des Supreme Court rechtliche und planerische Unsicherheit und stärke Peking: Autohersteller, die Beschränkungen nach eigenen Vorstellungen erhalten oder aufheben wollen, Agrarexporteure im Vergeltungsrisiko, Verbündete, die sich Richtung China absichern. Gleicher Publisher-Block wie die Druckmittel-Position, daher trennt das Framing. Vokabular: Chaos, Unsicherheit, Bumerang, Kosten, Vergeltung.',ARRAY['AMERICAS-USA','ASIA-CHINA'],ARRAY['chaos','uncertainty','backfire','higher prices','retaliat','gives Beijing','Beijing a win','real winner','upper hand','opening in','blunts','turmoil','slump','reversal','profit hit','expensive gift','pay for it','scepticism','skepticism','evasion','scramble','hedge','strategic partnership','files lawsuit','cut 50,000','jobs by','learned to live','Chaos','Unsicherheit','Vergeltung','warnen'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Handelsblatt','Frankfurter Allgemeine','Euronews','El País','Die Zeit','Der Spiegel','Sky News','The Economist','Süddeutsche Zeitung','Tagesschau','ABC News','France 24 (EN)','France 24','Die Presse','Der Standard','El Mundo','Corriere della Sera','Kurier','Globe and Mail','EurActiv','Fox News','MSNBC','S&P Global','Nikkei Asia','Straits Times','Channel NewsAsia','Japan Times','NHK World','Asahi Shimbun','KBS World','Yonhap','Kyodo News','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House'],'us_china_trade_tariffs',2,'Tariffs backfire on the US','Zölle schaden den USA selbst', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_china_trade_unilateralism','US tariffs are unilateral coercion that damages the global trading order','US-Zölle sind unilateraler Zwang, der die globale Handelsordnung beschädigt','Chinese state media framing of tariffs and Section 301 probes as unilateralism and abuse of process rather than as a response to any imbalance: measures taken outside the multilateral system, harmful to all parties, and aimed at suppressing a competitor. Vocabulary: unilateral, abusing, tariff wars have no winners, bullying, global trade order, exclusive blocs.','Chinesische Staatsmedien deuten Zölle und Section-301-Verfahren als Unilateralismus und Verfahrensmissbrauch statt als Reaktion auf ein Ungleichgewicht: Maßnahmen außerhalb des multilateralen Systems, schädlich für alle Seiten, gerichtet auf die Unterdrückung eines Wettbewerbers. Vokabular: unilateral, Missbrauch, Zollkriege kennen keine Gewinner, globale Handelsordnung.',ARRAY['ASIA-CHINA','AMERICAS-USA'],ARRAY['unilateral','abusing','abuse','no winners','bullying','global trade order','exclusive blocs','revoke','oppose','protectionis','smear','WTO','unilateralist'],true,ARRAY['Global Times','CGTN','China Daily','People''s Daily','Xinhua'],'us_china_trade_tariffs',3,'Chinese state framing: unilateral coercion','Chinesische Staatsmedien: unilateraler Zwang', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_conservative_case','A mandate being executed against institutional resistance','Ein Mandat, das gegen institutionellen Widerstand umgesetzt wird','The administration-aligned reading across the theater: enforcement, personnel changes, electoral rule-tightening and regulatory action are the delivery of an electoral mandate against agencies, courts and media described as resistant to it.','Die regierungsnahe Lesart über das gesamte Feld: Vollzug, Personalwechsel, strengere Wahlregeln und regulatorisches Vorgehen sind die Umsetzung eines Wahlmandats gegen Behörden, Gerichte und Medien, die als widerständig beschrieben werden.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Fox News','New York Post','Washington Times','Newsmax'],'us_domestic_theater',1,'Mandate delivery','Umsetzung des Mandats',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_liberal_alarm','Checks and balances under sustained strain','Gewaltenteilung unter anhaltender Belastung','The mainstream and international reading across the theater: contested election rules, personnel purges, pressure on the central bank and on broadcasters, and enforcement outrunning due process are treated as a connected strain on American institutional checks -- with the courts as the contested variable.','Die Lesart der Leitmedien und der internationalen Presse über das gesamte Feld: umstrittene Wahlregeln, Personalsäuberungen, Druck auf die Notenbank und auf Sender sowie ein Vollzug, der rechtsstaatliche Verfahren überholt, gelten als zusammenhängende Belastung der institutionellen Kontrolle -- mit den Gerichten als umstrittener Variable.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','Financial Times','Bloomberg','Bloomberg.com','Wall Street Journal','The Economist','S&P Global','Nikkei Asia','OilPrice','Reuters','Handelsblatt','Swissinfo'],'us_domestic_theater',2,'Institutional strain','Institutionelle Belastung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_decline','American decline and the collapse of its claim to model status','Amerikanischer Niedergang und das Ende des Vorbildanspruchs','The Russian, Chinese and Iranian state reading across the theater: elite impunity, domestic policing, contested elections, politicised money and pressure on media are assembled into a single argument that the United States has no standing to set standards for others. Bystander framing, not support for any American faction.','Die Lesart russischer, chinesischer und iranischer Staatsmedien über das gesamte Feld: Straflosigkeit der Eliten, innere Überwachung, umstrittene Wahlen, politisiertes Geld und Druck auf Medien werden zu einem einzigen Argument verbunden -- die Vereinigten Staaten könnten für andere keine Maßstäbe setzen. Eine Außenperspektive, keine Unterstützung einer amerikanischen Fraktion.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_domestic_theater',3,'No standing to lead','Kein Führungsanspruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_integrity_case','Tightening the rules is protecting the integrity of the vote','Strengere Regeln schützen die Integrität der Wahl','Coverage presenting voter-ID requirements, proof-of-citizenship rules, voter-roll maintenance and limits on mail balloting as ordinary safeguards against fraud, and redistricting as a lawful power of elected state legislatures. Vocabulary: integrity, safeguard, proof of citizenship, voter ID, clean rolls, secure.','Berichterstattung, die Ausweispflichten, Staatsbürgerschaftsnachweise, die Pflege der Wählerverzeichnisse und Beschränkungen der Briefwahl als übliche Schutzmaßnahmen gegen Betrug darstellt und den Neuzuschnitt von Wahlkreisen als rechtmäßige Befugnis gewählter Parlamente.',ARRAY['AMERICAS-USA'],ARRAY['integrity','safeguard','secure','proof of citizenship','voter ID','clean','fraud','verify','lawful','constitutional','Integrität','Wahlbetrug','Nachweis','rechtmäßig'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','Fox News','New York Post','Washington Times','Newsmax'],'us_electoral_legitimacy',1,'Integrity safeguards','Schutz der Wahlintegrität',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_franchise_threat','The rules are being rewritten to shape the result in advance','Die Regeln werden umgeschrieben, um das Ergebnis vorab zu formen','Coverage documenting mid-cycle redistricting races between states, the Voting Rights Act narrowed, mail-ballot restrictions struck down and reimposed, proof-of-citizenship bills, an FBI raid on a voting-rights group, and open discussion of how an incumbent might tilt a midterm. Vocabulary: gerrymander, tilt, crackdown, restrict, purge, strike down, block, master plan.','Berichterstattung über Neuzuschnitte von Wahlkreisen mitten im Zyklus, die Einschränkung des Voting Rights Act, gekippte und wieder eingeführte Briefwahlbeschränkungen, Gesetze zum Staatsbürgerschaftsnachweis, eine FBI-Razzia bei einer Wahlrechtsorganisation und offene Debatten darüber, wie ein Amtsinhaber eine Zwischenwahl beeinflussen könnte.',ARRAY['AMERICAS-USA'],ARRAY['gerrymander','tilt','crackdown','restrict','restriction','purge','strike down','struck down','blocks','blocked','suppress','master plan','raid','meddle','meddling','advantage','splinter','rig','Wahlkreis','Einschränkung','Razzia','manipulieren'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_electoral_legitimacy',2,'Franchise under pressure','Wahlrecht unter Druck', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_democracy_facade','A system that lectures others while contesting its own elections','Ein System, das andere belehrt und die eigenen Wahlen bestreitet','Russian, Chinese and Iranian state coverage using redistricting fights, ballot litigation and fraud claims to argue that American electoral democracy is a facade, and that US election observation and democracy promotion abroad lack standing.','Russische, chinesische und iranische Staatsmedien nutzen Streit um Wahlkreise, Klagen um Stimmzettel und Betrugsvorwürfe, um zu argumentieren, die amerikanische Wahldemokratie sei eine Fassade und die US-Wahlbeobachtung im Ausland entbehre der Grundlage.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_electoral_legitimacy',3,'Democracy as facade','Demokratie als Fassade', -2,false)
