INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_transition_democracy_betrayed','Chavismo survives; the opposition is frozen out','Der Chavismo überlebt; die Opposition bleibt ausgeschlossen','A chavista clique simply swapped faces: Machado and the opposition are sidelined, promised elections never come, and the "transition" entrenches the old regime under a new manager.','Eine chavistische Clique hat nur die Gesichter getauscht: Machado und die Opposition werden ausgebootet, versprochene Wahlen bleiben aus, und der "Übergang" zementiert das alte Regime unter neuer Führung.',ARRAY['NON-STATE-EU','AMERICAS-VENEZUELA','AMERICAS-USA'],ARRAY['frozen out','sidelined','no elections','without elections','snap elections','sham','illegitim','betray','authoritarian','entrench','power grab','kidnap','arrest','detention','detain','politically motivated','crackdown','repress','urges elections','demands elections','keine Wahlen','Schein','ausgeschlossen','festgenommen','entführt','sin elecciones','fraude','ilegítim','represión','detenc','secuestr','exige elecciones'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Frankfurter Allgemeine','Le Monde','Le Figaro','El País','El Mundo','Corriere della Sera','La Repubblica','Der Standard','Die Presse','The Telegraph','ABC News','Sky News','Clarín','La Nación','Reforma','O Estado de S. Paulo'],'venezuela_political_transition',2,'Stolen transition','Gestohlener Übergang', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_transition_imperial_puppet','The transition is a US-installed puppet regime','Der Übergang ist ein von den USA eingesetztes Marionettenregime','Washington abducted a president and hand-picked his successor -- the "transition" is illegal regime change and a foreign-imposed government with no legitimacy.','Washington entführte einen Präsidenten und wählte seinen Nachfolger aus -- der "Übergang" ist illegaler Regimewechsel und eine von außen eingesetzte Regierung ohne Legitimität.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','MIDEAST-IRAN'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency'],'venezuela_political_transition',3,'US-installed puppet','Von den USA eingesetzte Marionette', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_oil_restart_opportunity','Sanctions relief reopens Venezuela''s oil to the world','Sanktionslockerung öffnet Venezuelas Öl wieder für die Welt','Lifting sanctions and welcoming the majors back is a pragmatic win -- Venezuelan crude eases global supply, funds recovery and pulls the economy off the floor.','Die Aufhebung der Sanktionen und die Rückkehr der Ölkonzerne sind ein pragmatischer Gewinn -- venezolanisches Rohöl entlastet den Weltmarkt, finanziert den Wiederaufbau und richtet die Wirtschaft wieder auf.',ARRAY['AMERICAS-USA','NON-STATE-EU','AMERICAS-VENEZUELA'],ARRAY['restart','rebound','return','comeback','opportunity','recovery','invest','deal','exports','production','output','billions','rush','energy security','supply','black gold','Neustart','Erholung','Investition','Ölgeschäft','Rückkehr','recuperación','inversión','oportunidad','exportaciones','reactivación','producción'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Frankfurter Allgemeine','Le Monde','Le Figaro','El País','El Mundo','Corriere della Sera','La Repubblica','Der Standard','Die Presse','The Telegraph','ABC News','Sky News','Bloomberg','Wall Street Journal','Financial Times','OilPrice','S&P Global','Mining.com','Times of India','NDTV','The Hindu','Hindustan Times','WION','Folha de S.Paulo','O Globo','El Universal','Clarín','La Nación'],'venezuela_sanctions_oil',1,'Pragmatic restart & recovery','Pragmatischer Neustart & Erholung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_oil_deals_opacity','The oil restart is opaque and serves Trump, not Venezuelans','Der Öl-Neustart ist undurchsichtig und dient Trump, nicht den Venezolanern','Behind the comeback are secret contracts and a president boasting he "made a fortune" -- the opacity, cronyism and unanswered question of who benefits are the real story.','Hinter dem Comeback stehen Geheimverträge und ein Präsident, der prahlt, er habe "ein Vermögen gemacht" -- die Intransparenz, Vetternwirtschaft und die offene Frage, wer profitiert, sind die eigentliche Geschichte.',ARRAY['AMERICAS-USA','NON-STATE-EU','AMERICAS-VENEZUELA'],ARRAY['secret','opaque','opacity','transparency','made a fortune','fortune','who benefits','cronies','crony','linger','murky','plunder','looting','kickback','no accountability','Geheim','undurchsichtig','Intransparenz','Vermögen gemacht','wer profitiert','secreto','opaco','opacidad','transparencia','saqueo','a quién beneficia'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Frankfurter Allgemeine','Le Monde','Le Figaro','El País','El Mundo','Corriere della Sera','La Repubblica','Der Standard','Die Presse','The Telegraph','ABC News','Sky News','Bloomberg','Wall Street Journal','Financial Times'],'venezuela_sanctions_oil',2,'Opaque deals & who profits','Undurchsichtige Deals & Profiteure', -1,true)
