INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_oil_imperial_plunder','Washington is looting Venezuela''s oil wealth','Washington plündert Venezuelas Ölreichtum','The whole operation was about seizing the world''s largest reserves -- the US toppled a government to take the oil, a textbook imperial resource grab dressed up as sanctions relief.','Bei der ganzen Operation ging es darum, sich die größten Reserven der Welt zu sichern -- die USA stürzten eine Regierung, um das Öl zu nehmen: eine imperiale Ressourcenplünderung im Gewand der Sanktionslockerung.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','MIDEAST-IRAN'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency'],'venezuela_sanctions_oil',3,'Imperial resource grab','Imperiale Ressourcenplünderung', -2,false)
