INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_theater_western_consensus','Removing Maduro opened a stabilising, pragmatic path for Venezuela','Maduros Absetzung öffnete einen stabilisierenden, pragmatischen Weg für Venezuela','With the narco-state gone, an interim government is restoring order and the oil sector is reopening -- a fragile but genuine chance for Venezuelan recovery and for global energy supply.','Mit dem Ende des Narco-Staats stellt eine Übergangsregierung die Ordnung wieder her und der Ölsektor öffnet sich erneut -- eine fragile, aber echte Chance für Venezuelas Erholung und die globale Energieversorgung.',ARRAY['AMERICAS-USA','NON-STATE-EU','AMERICAS-VENEZUELA'],ARRAY['stabil','reform','recovery','restart','opportunity','transition','invest','estabil','reforma','recuperación','Stabil','Erholung'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Frankfurter Allgemeine','Le Monde','Le Figaro','El País','El Mundo','Corriere della Sera','La Repubblica','Der Standard','Die Presse','The Telegraph','ABC News','Sky News','Bloomberg','Wall Street Journal','Financial Times','OilPrice','S&P Global','Mining.com','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo','El Universal','Times of India','NDTV','The Hindu','Hindustan Times','WION','Fox News','The Australian','Jerusalem Post','Times of Israel','i24NEWS'],'venezuela_theater',1,'Pragmatic Western consensus','Pragmatischer westlicher Konsens',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_theater_western_critical','The means were lawless and the transition is hollow','Die Mittel waren rechtlos und der Übergang ist hohl','Even sympathetic Western coverage sees a head of state abducted without legal mandate, an opposition frozen out of the settlement, and oil deals struck behind closed doors.','Selbst wohlwollende westliche Berichterstattung sieht einen ohne Rechtsgrundlage entführten Staatschef, eine von der Einigung ausgeschlossene Opposition und hinter verschlossenen Türen geschlossene Ölgeschäfte.',ARRAY['NON-STATE-EU','AMERICAS-USA','AMERICAS-VENEZUELA'],ARRAY['illegal','unlawful','war powers','frozen out','no elections','secret','opaque','abduct','overreach','sin elecciones','ilegal','rechtswidrig','Entführung','ausgeschlossen'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Frankfurter Allgemeine','Le Monde','Le Figaro','El País','El Mundo','Corriere della Sera','La Repubblica','Der Standard','Die Presse','The Telegraph','ABC News','Sky News','Bloomberg','Wall Street Journal','Financial Times','OilPrice','S&P Global','Mining.com','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo','El Universal','Straits Times'],'venezuela_theater',2,'Lawless means, hollow transition','Rechtlose Mittel, hohler Übergang', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ven_theater_anti_imperial','A US imperial operation to seize a sovereign nation''s oil','Eine imperiale US-Operation zur Aneignung des Öls einer souveränen Nation','Washington abducted a president, installed a compliant government and took the world''s largest oil reserves -- gunboat imperialism that shreds international law and puts all of Latin America on notice.','Washington entführte einen Präsidenten, setzte eine gefügige Regierung ein und nahm sich die größten Ölreserven der Welt -- Kanonenbootimperialismus, der das Völkerrecht zerreißt und ganz Lateinamerika warnt.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','MIDEAST-IRAN'],ARRAY['imperial','sovereignty','regime change','plunder','puppet','soberanía','imperialismo','Souveränität','Regimewechsel'],true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency'],'venezuela_theater',3,'Anti-imperial counter-framing','Anti-imperiale Gegenerzählung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('judea_samaria_sovereignty','Israeli right: Jewish sovereignty over biblical Judea-Samaria','Israelische Rechte: juedische Souveraenitaet ueber das biblische Judaea-Samaria','Israeli right-wing outlets and settlement-movement commentary frame the West Bank as biblical Judea-Samaria — historically and legally part of the Jewish national home rather than "occupied territory". Settler communities are presented as the natural population restoration; IDF operations in Jenin and Nablus are counter-terrorism against Hamas/Islamic Jihad infrastructure; settler-Palestinian friction is reduced to extremist outliers or framed as defensive against Palestinian terror. The vocabulary is "Judea and Samaria", "biblical heartland", "Jewish indigeneity", "counter-terror raid", "Hamas in the West Bank", "PA failed state", "applied sovereignty", "Levin reform", "Smotrich plan". Prescription: extend Israeli civil law over Area C, expand settlement construction, abandon the two-state framework, treat the PA as a security risk to be replaced.','Israelische rechte Medien und siedlungsnahe Kommentatoren rahmen das Westjordanland als biblisches Judaea-und-Samaria — historisch und rechtlich Teil der juedischen Heimstaette, nicht "besetztes Gebiet". Siedlungen gelten als natuerliche Wiederbesiedlung; IDF-Operationen in Dschenin und Nablus als Anti-Terror gegen Hamas/Islamischen Dschihad; Siedler-Palaestinenser-Reibungen werden auf Einzelne reduziert oder als Verteidigung gegen palaestinensischen Terror gerahmt. Vokabular: "Judaea und Samaria", "biblisches Kernland", "juedische Indigenitaet", "Anti-Terror-Razzia", "Hamas im Westjordanland", "PA als gescheiterter Staat", "angewandte Souveraenitaet", "Levin-Reform", "Smotrich-Plan". Vorschrift: israelisches Zivilrecht auf Gebiet C ausdehnen, Siedlungsbau erweitern, Zweistaaten-Rahmen verlassen, die PA als Sicherheitsrisiko behandeln.',ARRAY['MIDEAST-ISRAEL'],ARRAY['Judea and Samaria','biblical heartland','Jewish indigeneity','counter-terror raid','Hamas in West Bank','PA failed state','applied sovereignty','Smotrich plan','Ben Gvir','outpost legalization','settler communities','Hamas Jenin','Hamas Nablus'],true,ARRAY['Jerusalem Post','Israel Hayom','Arutz Sheva','i24NEWS','Times of Israel','The Times of Israel'],'west_bank_settlements',1,'Judea-Samaria sovereignty','Souveraenitaet ueber Judaea und Samaria',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('west_bank_apartheid_framing','Palestinian / international human rights: occupation, settler impunity, apartheid system','Palaestinensisch / internationale Menschenrechte: Besatzung, Straflosigkeit von Siedlern, Apartheid-System','Palestinian outlets, Al Jazeera, and increasingly international human rights commentary (Amnesty, HRW, B''Tselem) frame Israeli control of the West Bank as an illegal occupation now operating as an apartheid system. Settler violence is presented as systemic and state-enabled; IDF raids on Jenin and Nablus as collective punishment of Palestinian civilian populations; settlement expansion as land theft prohibited under the Fourth Geneva Convention. The vocabulary is "occupation", "apartheid", "settler-colonial", "ethnic cleansing", "illegal under international law", "settler pogrom", "annexation by stealth", "Area C land theft", "ICJ advisory opinion on occupation". Prescription: end the occupation, dismantle settlements, accountability for settler violence, recognition of Palestinian statehood within 1967 borders.','Palaestinensische Medien, Al Jazeera und zunehmend internationale Menschenrechts-Stimmen (Amnesty, HRW, B''Tselem) rahmen die israelische Kontrolle ueber das Westjordanland als illegale Besatzung, die als Apartheid-System operiert. Siedlergewalt gilt als systemisch und staatlich ermoeglicht; IDF-Razzien in Dschenin und Nablus als Kollektivstrafe gegen Zivilbevoelkerung; Siedlungserweiterung als Landraub im Sinne der Vierten Genfer Konvention. Vokabular: "Besatzung", "Apartheid", "Siedler-Kolonialismus", "ethnische Saeuberung", "voelkerrechtswidrig", "Siedler-Pogrom", "schleichende Annexion", "Landraub in Gebiet C", "IGH-Gutachten zur Besatzung". Vorschrift: Besatzung beenden, Siedlungen aufloesen, Rechenschaft fuer Siedlergewalt, Anerkennung Palaestinas in den Grenzen von 1967.',ARRAY['MIDEAST-PALESTINE','MIDEAST-LEVANT','MIDEAST-GULF','NON-STATE-EU'],ARRAY['occupation','apartheid','settler-colonial','ethnic cleansing','illegal under international law','settler pogrom','annexation by stealth','Area C','land theft','ICJ advisory','settler violence','PA','collective punishment','Geneva Convention'],true,ARRAY['Al Jazeera','Press TV','TRT World','Anadolu Agency','Daily Sabah','Al-Ahram','Arab News','The Guardian','Middle East Eye','Al Mayadeen'],'west_bank_settlements',2,'Occupation, settler violence, apartheid','Besatzung, Siedlergewalt, Apartheid', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aid_sustains_defense','Western military, economic, and industrial aid is sustaining and must be scaled','Westliche militaerische, wirtschaftliche und industrielle Hilfe traegt und muss skaliert werden','Pro-aid framing (Ukrainian press + Western mainstream + Eastern European hawks) treats Western military, economic, and financial assistance as both moral imperative and strategic necessity. Coverage tracks weapons deliveries (HIMARS, ATACMS, Storm Shadow, Taurus debates, F-16 deployment, Patriot replenishment), financial mechanisms (ERA loan from windfall profits on frozen Russian assets, Ukraine Facility, REPO Act seizure provisions, European Peace Facility), and the growing defense-industrial partnership (Rheinmetall-Ukraine joint ventures, Czech ammunition initiative, BAE local production). Vocabulary: aid package, security assistance, defense industrial base, joint production, ammunition supply, frozen-asset windfall, sustained commitment. Prescription: scale all three channels; remove restrictions on Western weapons use; seize frozen sovereign assets for Ukrainian reconstruction; build long-term defense-industrial capacity in Ukraine.','Pro-Hilfe-Rahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken) behandelt westliche militaerische, wirtschaftliche und finanzielle Unterstuetzung als moralische Pflicht und strategische Notwendigkeit. Berichterstattung verfolgt Waffenlieferungen (HIMARS, ATACMS, Storm Shadow, Taurus-Debatten, F-16-Stationierung, Patriot-Nachschub), Finanzmechanismen (ERA-Darlehen aus Sondervermoegens-Gewinnen eingefrorenen russischen Vermoegens, Ukraine-Fazilitaet, REPO-Act-Beschlagnahmebestimmungen, Europaeische Friedensfazilitaet) und die wachsende verteidigungsindustrielle Partnerschaft (Rheinmetall-Ukraine-Joint-Ventures, tschechische Munitions-Initiative, BAE-Lokalproduktion). Vokabular: Hilfspaket, Sicherheitsunterstuetzung, Verteidigungsindustrie-Basis, gemeinsame Produktion, Munitionsversorgung, Sondervermoegens-Windfall, anhaltendes Engagement. Vorschrift: alle drei Kanaele skalieren; Beschraenkungen westlichen Waffeneinsatzes aufheben; eingefrorenes Staatsvermoegen fuer ukrainischen Wiederaufbau beschlagnahmen; langfristige Verteidigungsindustrie-Kapazitaet in der Ukraine aufbauen.',ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'],ARRAY['military aid','aid package','security assistance','weapons delivery','training mission','defence production','joint production','ammunition supply','frozen-asset windfall','ERA loan','seize frozen assets','sustained commitment','long-term partnership'],true,ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Handelsblatt','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','Defense News','Janes','CNN','New York Times','Washington Post','Wall Street Journal','Politico','iROZHLAS'],'western_aid_to_ukraine',1,'Aid sustains Ukrainian defense','Hilfe sichert ukrainische Verteidigung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aid_as_escalation_and_proxy','Western aid prolongs proxy war, wastes taxpayer money, escalates direct NATO-Russia risk','Westliche Hilfe verlaengert Stellvertreterkrieg, verschwendet Steuergeld, eskaliert direktes NATO-Russland-Risiko','Restraint framing (Russian state press + Western contrarian + Global South + Hungarian-aligned EU) treats Western aid as proxy-war escalation that delays inevitable settlement, wastes taxpayer money increasingly diverted from domestic priorities, and risks direct NATO-Russia confrontation by supplying longer-range weapons and authorising their use inside Russia. Vocabulary: proxy war, escalation, taxpayer waste, weapons graveyard, diversion of aid, NATO involvement, red line. Coverage emphasises the corruption risk in aid pipelines, the ineffectiveness of escalating weapons categories in changing the battlefield, Ukrainian losses and recruitment shortages, growing European public fatigue, and the strain on US bipartisan support. Prescription: pause and reassess aid, condition it on negotiated outcomes, prevent direct NATO-Russia escalation, redirect funds to domestic priorities.','Zurueckhaltungs-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + ungarisch-orientierte EU) behandelt westliche Hilfe als Stellvertreterkriegs-Eskalation, die unvermeidliche Beilegung verzoegert, Steuergeld zunehmend von inlaendischen Prioritaeten umlenkt und direkte NATO-Russland-Konfrontation durch Lieferung weitreichenderer Waffen und deren Autorisierung in Russland riskiert. Vokabular: Stellvertreterkrieg, Eskalation, Steuerverschwendung, Waffenfriedhof, Umlenkung von Hilfe, NATO-Beteiligung, rote Linie. Berichterstattung betont Korruptionsrisiko in Hilfspipelines, Wirkungslosigkeit eskalierender Waffenkategorien fuer den Schlachtfeld-Wandel, ukrainische Verluste und Rekrutierungsmaengel, wachsende europaeische Erschoepfung der Oeffentlichkeit und Belastung ueberparteilicher US-Unterstuetzung. Vorschrift: Hilfe pausieren und neu bewerten, sie an verhandelten Ergebnissen konditionieren, direkte NATO-Russland-Eskalation verhindern, Mittel auf inlaendische Prioritaeten umleiten.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','ASIA-INDIA'],ARRAY['proxy war','escalation','taxpayer waste','weapons graveyard','aid diversion','NATO involvement','red line','red lines','corruption risk','aid fatigue','bipartisan strain','Western recklessness'],true,ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV','Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','TRT World','Daily Sabah'],'western_aid_to_ukraine',2,'Aid as escalation and proxy waste','Hilfe als Eskalation und Stellvertreter-Verschwendung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('houthis_fourth_front_solidarity','Houthi attacks on Israel and Red Sea shipping are legitimate Gaza solidarity','Houthi-Angriffe auf Israel und Schifffahrt im Roten Meer sind legitime Gaza-Solidaritaet','Resistance / Iran-aligned framing: Houthi attacks on Israel and Red Sea shipping are legitimate solidarity-with-Gaza pressure under a unified axis-of-resistance command; the Yemeni movement has the right to extend the war until Gaza ceasefire holds. The vocabulary: "fourth front", "support front", "axis solidarity", "Gaza pressure", "joint operation", "resistance command". Prescription: maintain pressure until Gaza ceasefire; integrate Houthi operations into unified resistance posture.','Widerstand / Iran-orientierte Rahmung: Houthi-Angriffe auf Israel und Schifffahrt im Roten Meer sind legitime Solidaritaets-Druck mit Gaza unter einem einheitlichen Widerstandsachsen-Kommando; die jemenitische Bewegung hat das Recht, den Krieg auszuweiten, bis ein Gaza-Waffenstillstand haelt. Vokabular: "vierte Front", "Unterstuetzungsfront", "Achsen-Solidaritaet", "Gaza-Druck", "gemeinsame Operation". Vorschrift: Druck bis zum Gaza-Waffenstillstand aufrechterhalten.',ARRAY['MIDEAST-IRAN','MIDEAST-YEMEN'],ARRAY['fourth front','support front','axis solidarity','Gaza pressure','joint operation','resistance command'],true,ARRAY['Press TV','Al Jazeera','Al Mayadeen','Fars News','IRNA','TRT World','Anadolu Agency','Daily Sabah','CGTN','TASS (EN)','RT'],'yemen_red_sea_theater',1,'Fourth-front solidarity','Vierte Front: Solidaritaet',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('iran_proxy_destabilisation','Houthis are an Iranian proxy that has hijacked the Yemeni state','Houthi sind ein iranischer Stellvertreter, der den jemenitischen Staat gekapert hat','Saudi / Egyptian state, Israeli, and pro-Western framing: Houthis are an Iranian-armed proxy that has hijacked the Yemeni state, threatens Arab order, and must be militarily defeated; STC fracture is one symptom of the broader Iran-axis destabilisation. The vocabulary: "Iranian proxy", "Iran-armed", "axis aggression", "hijacked state", "Arab order", "destabilisation". Prescription: military defeat of Houthi capability, restoration of legitimate Yemeni government, interdiction of Iranian weapons pipelines.','Saudisch-aegyptisch, israelisch und prowestlich: Houthi sind ein iranisch bewaffneter Stellvertreter, der den jemenitischen Staat gekapert hat, die arabische Ordnung bedroht und militaerisch besiegt werden muss; STC-Bruch ist ein Symptom der breiteren Iran-Achsen-Destabilisierung. Vokabular: "iranischer Stellvertreter", "iranisch bewaffnet", "Achsen-Aggression", "gekaperter Staat", "arabische Ordnung", "Destabilisierung". Vorschrift: militaerische Niederlage der Houthi-Kapazitaet, Wiederherstellung der legitimen Regierung, Unterbindung iranischer Waffenlieferungen.',ARRAY['MIDEAST-SAUDI','MIDEAST-GULF','MIDEAST-EGYPT','MIDEAST-ISRAEL','AMERICAS-USA'],ARRAY['Iranian proxy','Iran-armed','axis aggression','hijacked state','Arab order','destabilisation','weapons pipeline'],true,ARRAY['Al-Ahram','Al Arabiya','Arab News','The National','Khaleej Times','Gulf News','Egypt Today','Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS','Fox News','Haaretz'],'yemen_red_sea_theater',2,'Iranian proxy destabilising the region','Iranischer Stellvertreter destabilisiert die Region', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('western_pragmatic_navigation','Houthi problem is a freedom-of-navigation problem; Gaza ceasefire removes the casus belli','Houthi-Problem ist eine Frage der freien Seefahrt; Gaza-Waffenstillstand entfernt den Casus belli','EU / E3 / US shipping-desk mainstream: the Houthi problem is primarily a freedom-of-navigation problem requiring coalition naval pressure (Prosperity Guardian, Aspides) and a Gaza ceasefire that removes the Houthis'' stated casus belli; humanitarian impact in Yemen is a parallel concern, not the primary frame. The vocabulary: "freedom of navigation", "Prosperity Guardian", "Aspides", "global trade", "coalition naval pressure", "Gaza ceasefire linkage", "humanitarian concern". Prescription: sustained coalition naval pressure, Gaza ceasefire diplomacy, humanitarian access; reject both kinetic escalation and unilateral concession.','EU / E3 / US-Schifffahrts-Mainstream: das Houthi-Problem ist primaer eine Frage der freien Seefahrt, die koalitionaeren Marine-Druck erfordert (Prosperity Guardian, Aspides) und einen Gaza-Waffenstillstand, der den Houthi-Casus-belli entfernt; humanitaere Auswirkungen im Jemen sind eine parallele Sorge, nicht der primaere Rahmen. Vokabular: "freie Seefahrt", "Prosperity Guardian", "Aspides", "Welthandel", "Marine-Druck", "Gaza-Waffenstillstand-Verknuepfung". Vorschrift: anhaltender Marine-Druck, Gaza-Waffenstillstands-Diplomatie, humanitaerer Zugang.',ARRAY['NON-STATE-EU','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','AMERICAS-USA'],ARRAY['freedom of navigation','Prosperity Guardian','Aspides','global trade','coalition pressure','Gaza ceasefire linkage','humanitarian concern'],true,ARRAY['Reuters','Associated Press','BBC World','France 24','France 24 (EN)','Deutsche Welle','Tagesschau','Financial Times','Bloomberg','Wall Street Journal','The Guardian','Le Monde','Nikkei Asia','Straits Times'],'yemen_red_sea_theater',3,'Western pragmatic navigation framing','Westliche pragmatische Schifffahrts-Rahmung',0,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('zc_connectivity_prosperity','The corridor unlocks connectivity, trade and a regional peace dividend','Der Korridor erschließt Konnektivität, Handel und eine regionale Friedensdividende','Western, Turkish and Azerbaijani framing presents the Zangezur route -- rebranded the US-backed "Trump Route"/TRIPP -- as a transformative connectivity project unlocking east-west trade, jobs and a peace dividend for the whole region.','Die westliche, türkische und aserbaidschanische Deutung präsentiert die Sangesur-Route -- neu benannt als US-gestützte "Trump-Route"/TRIPP -- als transformatives Konnektivitätsprojekt, das Ost-West-Handel, Arbeitsplätze und eine Friedensdividende für die ganze Region erschließt.',ARRAY['ASIA-CAUCASUS'],ARRAY['connectivity','trade route','prosperity','peace dividend','unlock','transit hub','east-west','Trump Route','TRIPP','Konnektivität','Handelsroute','Wohlstand','Trump-Route','коридор','торговый маршрут'],true,ARRAY['Reuters','Euronews','Euronews.com','Associated Press','Bloomberg','Financial Times','OilPrice','Daily Sabah','Anadolu Agency','TRT World','The Astana Times','Tengrinews','ANSA'],'zangezur_corridor',1,'Connectivity and prosperity','Konnektivität und Wohlstand',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('zc_sovereignty_threat','The corridor is an extraterritorial threat to Armenian sovereignty and Iran''s border','Der Korridor ist eine extraterritoriale Bedrohung für Armeniens Souveränität und Irans Grenze','An Iranian and Russian framing warns the corridor is a strategic threat: an extraterritorial route carving through Armenian sovereign territory, severing Iran''s land border with Armenia and inserting US/NATO influence -- a red line to be blocked, not a peace project.','Eine iranische und russische Deutung warnt, der Korridor sei eine strategische Bedrohung: eine extraterritoriale Route mitten durch armenisches Hoheitsgebiet, die Irans Landgrenze zu Armenien durchtrenne und US-/NATO-Einfluss einschleuse -- eine rote Linie, die zu blockieren sei, kein Friedensprojekt.',ARRAY['ASIA-CAUCASUS'],ARRAY['extraterritorial','sovereignty','red line','sever','border','security risk','US influence','NATO','block','threat','extraterritorial','Souveränität','rote Linie','Grenze','экстерриториальн','суверенитет','красная линия','угроза'],true,ARRAY['IRNA','Press TV','TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia'],'zangezur_corridor',2,'Sovereignty and red-line threat','Souveränitäts- und Grenzbedrohung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();

